INSERT INTO `rfq_system_schema_history` VALUES (1,'f_clean_names','FUNCTION','BEGIN\n    DECLARE v_clean VARCHAR(255);\n    \n    IF p_name IS NULL OR p_name = \'\' THEN\n        RETURN \'\';\n    END IF;\n\n    -- Step 1: Force Lowercase to normalize casing issues\n    SET v_clean = LOWER(TRIM(p_name));\n\n    -- Step 2: Strip common legal entity suffixes/keywords\n    SET v_clean = REPLACE(v_clean, \'pvt.ltd.\', \'\');\n    SET v_clean = REPLACE(v_clean, \'pvt ltd\', \'\');\n    SET v_clean = REPLACE(v_clean, \'pvt.\', \'\');\n    SET v_clean = REPLACE(v_clean, \'pvt\', \'\');\n    SET v_clean = REPLACE(v_clean, \'ltd.\', \'\');\n    SET v_clean = REPLACE(v_clean, \'ltd\', \'\');\n    SET v_clean = REPLACE(v_clean, \'limited\', \'\');\n    SET v_clean = REPLACE(v_clean, \'llp\', \'\');\n    SET v_clean = REPLACE(v_clean, \'inc.\', \'\');\n    SET v_clean = REPLACE(v_clean, \'inc\', \'\');\n    SET v_clean = REPLACE(v_clean, \'brokers\', \'\'); -- Handles \'broker\' variation variations\n    SET v_clean = REPLACE(v_clean, \'broker\', \'\');\n\n    -- Step 3: Strip Punctuation, Dots, Hyphens, and Spaces\n    SET v_clean = REPLACE(v_clean, \'.\', \'\');\n    SET v_clean = REPLACE(v_clean, \',\', \'\');\n    SET v_clean = REPLACE(v_clean, \'-\', \'\');\n    SET v_clean = REPLACE(v_clean, \'/\', \'\');\n    SET v_clean = REPLACE(v_clean, \' \', \'\'); -- Removes all blank spaces\n\n    RETURN TRIM(v_clean);\nEND','System Baseline Init','2026-07-03 05:28:00'),(2,'f_crypto_value','FUNCTION','BEGIN\n    DECLARE v_secret_key VARCHAR(64);\n    SET v_secret_key = \'sandeep!\'; \n\n    -- 1. Tight Guard Clause: Handle NULL, Empty Strings, or Whitespaces instantly\n    IF p_input_value IS NULL OR TRIM(p_input_value) = \'\' THEN\n        RETURN p_input_value;\n    END IF;\n\n    -- =========================================================================\n    -- ROUTE 1: ENCRYPTION\n    -- =========================================================================\n    IF p_action = 1 THEN\n        RETURN HEX(AES_ENCRYPT(p_input_value, v_secret_key));\n\n    -- =========================================================================\n    -- ROUTE 2: DECRYPTION\n    -- =========================================================================\n    ELSEIF p_action = 2 THEN\n        -- Verify string is an even length AND contains ONLY hex characters\n        IF LENGTH(TRIM(p_input_value)) % 2 = 0 AND TRIM(p_input_value) REGEXP \'^[0-9a-fA-F]+$\' THEN\n            RETURN CAST(AES_DECRYPT(UNHEX(TRIM(p_input_value)), v_secret_key) AS CHAR);\n        ELSE\n            -- Plain text string fallback (keeps legacy test phone numbers safe)\n            RETURN p_input_value;\n        END IF;\n    \n    ELSE\n        RETURN NULL;\n    END IF;\nEND','System Baseline Init','2026-07-03 05:28:00'),(3,'f_generate_sequential_uuid','FUNCTION','BEGIN\n    -- CONCAT implicitly converts the random number to a string, saving CPU cycles\n    RETURN CONCAT(\n        FLOOR(100000 + (RAND() * 899999)), \n        REPLACE(UUID(), \'-\', \'Q\')\n    );\nEND','System Baseline Init','2026-07-03 05:28:00'),(4,'sp_approval_client','PROCEDURE','proc_main: BEGIN\n    -- Extracted Parameters\n    DECLARE v_userid BIGINT;\n    DECLARE v_client_id BIGINT UNSIGNED;\n    DECLARE v_owner_id BIGINT UNSIGNED; -- The user being assigned as owner\n    DECLARE v_owner_type_code VARCHAR(30); -- \'cooo\' (Owner) or \'cooc\' (Co-Owner)\n    DECLARE v_remarks VARCHAR(500);\n\n    -- System Error Capture Variables\n    DECLARE v_sql_state VARCHAR(5) DEFAULT \'00000\';\n    DECLARE v_error_msg TEXT;\n\n    -- Global Exception Trap Handler (Auto-Rollback enabled)\n    DECLARE EXIT HANDLER FOR SQLEXCEPTION\n    BEGIN\n        ROLLBACK;\n        GET DIAGNOSTICS CONDITION 1 \n            v_sql_state = RETURNED_SQLSTATE, \n            v_error_msg = MESSAGE_TEXT;\n\n        SET p_response = JSON_OBJECT(\n            \'status\', 500,\n            \'message\', CONCAT(\'Ownership Transaction Failed: \', v_error_msg),\n            \'payload\', NULL\n        );\n    END;\n\n    -- 1. Extract Mapping Elements from JSON\n    SET v_userid = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.userid\')) AS UNSIGNED);\n    SET v_client_id = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.payload.client_id\')) AS UNSIGNED);\n    SET v_owner_id = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.payload.owner_id\')) AS UNSIGNED);\n    SET v_owner_type_code = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.payload.owner_type_code\'));\n    SET v_remarks = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.payload.remarks\'));\n\n    -- Guard Clause: Validate correct ownership context rules\n    IF v_owner_type_code NOT IN (\'cooo\', \'cooc\') THEN\n        SET p_response = JSON_OBJECT(\n            \'status\', 400,\n            \'message\', \'Validation Failed: Invalid owner_type_code supplied. Must be cooo or cooc.\',\n            \'payload\', NULL\n        );\n        LEAVE proc_main;\n    END IF;\n\n    -- Start Transaction Block\n    START TRANSACTION;\n\n    -- 2. BUSINESS RULE ROUTING\n    IF v_owner_type_code = \'cooo\' THEN\n        -- Rule: A client can have only ONE primary owner active at a time.\n        -- Deactivate any previous primary owner entries for this client.\n        UPDATE client_owners \n        SET active = FALSE \n        WHERE client_id = v_client_id \n          AND owner_type_code = \'cooo\' \n          AND active = TRUE;\n\n    ELSEIF v_owner_type_code = \'cooc\' THEN\n        -- Rule: Multiples allowed, but let\'s avoid duplicating the exact same active co-owner.\n        UPDATE client_owners\n        SET active = FALSE \n        WHERE client_id = v_client_id\n          AND owner_id = v_owner_id\n          AND owner_type_code = \'cooc\'\n          AND active = TRUE;\n    END IF;\n\n    -- 3. INSERT THE NEW OWNER ASSIGNMENT\n    -- Assumes table structures match your corporate baseline conventions\n    INSERT INTO client_owners (\n        client_id,\n        user_id,\n        owner_type_code,\n        -- status_remarks,\n        active,\n        created_id\n    ) \n    VALUES (\n        v_client_id,\n        v_owner_id,\n        v_owner_type_code,\n        -- COALESCE(v_remarks, \'Ownership assignment mapped successfully.\'),\n        TRUE, -- Marked as active\n        v_userid\n    );\n\n    COMMIT;\n\n    -- 4. Construct Success Packet\n    SET p_response = JSON_OBJECT(\n        \'status\', 200,\n        \'message\', \'Ownership matrix updated and archived successfully.\',\n        \'payload\', JSON_OBJECT(\n            \'client_id\', v_client_id,\n            \'active_owner_type\', v_owner_type_code\n        )\n    );\n\nEND','System Baseline Init','2026-07-03 05:28:00'),(5,'sp_backup_and_deploy_object','PROCEDURE','proc_main: BEGIN\n    DECLARE v_current_body LONGTEXT DEFAULT NULL;\n\n    -- Global Exception Catch Block\n    DECLARE EXIT HANDLER FOR SQLEXCEPTION\n    BEGIN\n        SELECT JSON_OBJECT(\'status\', 500, \'message\', \'Deployment execution block failed.\') AS response;\n    END;\n\n    -- 1. EXTRACT EXISTING ARCHITECTURE FROM MYSQL SYSTEM DICTIONARIES\n    IF p_object_type = \'PROCEDURE\' THEN\n        SELECT ROUTINE_DEFINITION INTO v_current_body \n        FROM information_schema.ROUTINES \n        WHERE ROUTINE_SCHEMA = \'corporateqms\' AND ROUTINE_NAME = p_object_name AND ROUTINE_TYPE = \'PROCEDURE\';\n        \n    ELSEIF p_object_type = \'FUNCTION\' THEN\n        SELECT ROUTINE_DEFINITION INTO v_current_body \n        FROM information_schema.ROUTINES \n        WHERE ROUTINE_SCHEMA = \'corporateqms\' AND ROUTINE_NAME = p_object_name AND ROUTINE_TYPE = \'FUNCTION\';\n        \n    ELSEIF p_object_type = \'VIEW\' THEN\n        SELECT VIEW_DEFINITION INTO v_current_body \n        FROM information_schema.VIEWS \n        WHERE TABLE_SCHEMA = \'corporateqms\' AND TABLE_NAME = p_object_name;\n    END IF;\n\n    -- 2. IF PREVIOUS SPECIFICATION EXISTS, MOVE IT TO HISTORICAL LEDGER\n    IF v_current_body IS NOT NULL THEN\n        INSERT INTO system_schema_history (object_name, object_type, definition_body, changed_by)\n        VALUES (p_object_name, p_object_type, v_current_body, p_developer_name);\n    END IF;\n\n	-- 3. EXECUTE THE NEW DDL DEFINITION STREAM\n	-- Note: Dynamic DDL execution must use Prepared Statements\n	--  SET @ddl_query = p_new_definition;\n	--     PREPARE stmt FROM @ddl_query;\n	--     EXECUTE stmt;\n	--     DEALLOCATE PREPARE stmt;\n\n    SELECT JSON_OBJECT(\n        \'status\', 200, \n        \'message\', CONCAT(p_object_type, \' \', p_object_name, \' backup compiled and deployed successfully.\')\n    ) AS response;\n\nEND','System Baseline Init','2026-07-03 05:28:00'),(6,'sp_check_client','PROCEDURE','BEGIN\n    -- Control Variables\n    DECLARE v_incoming_name VARCHAR(255);\n    DECLARE v_cleaned_incoming VARCHAR(255);\n    DECLARE v_match_count INT DEFAULT 0;\n    DECLARE v_matched_payload JSON;\n\n    -- System Error Capture Variables\n    DECLARE v_sql_state VARCHAR(5) DEFAULT \'00000\';\n    DECLARE v_error_msg TEXT;\n\n    -- Global Exception Handler\n    DECLARE EXIT HANDLER FOR SQLEXCEPTION\n    BEGIN\n        GET DIAGNOSTICS CONDITION 1 \n            v_sql_state = RETURNED_SQLSTATE, \n            v_error_msg = MESSAGE_TEXT;\n\n        SET p_response = JSON_OBJECT(\n            \'status\', 500,\n            \'message\', CONCAT(\'Duplicate Check Engine Error: \', v_error_msg),\n            \'payload\', NULL\n        );\n    END;\n\n    -- 1. Extract the proposed client name from your standard API payload structure\n    SET v_incoming_name = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.payload.client.client_name\'));\n    \n    -- 2. Process incoming name through cleaning machine\n    SET v_cleaned_incoming = f_clean_names(v_incoming_name);\n\n    -- 3. Query the database checking for matching normalized baselines\n    SELECT COUNT(1), \n           JSON_ARRAYAGG(\n               JSON_OBJECT(\n                   \'client_UUID\', client_UUID,\n                   \'client_name\', client_name\n               )\n           )\n    INTO v_match_count, v_matched_payload\n    FROM client\n    -- Clean database value dynamically inline and compare with optimized collation standard\n    WHERE f_clean_names(client_name) = v_cleaned_incoming; -- COLLATE utf8mb4_unicode_ci;\n\n    -- 4. Construct JSON warning response block if matched\n    IF v_match_count > 0 THEN\n        SET p_response = JSON_OBJECT(\n            \'status\', 409, -- 409 Conflict status code standard\n            \'message\', \'Duplicate warning: A similar client configuration already exists.\',\n            \'payload\', v_matched_payload\n        );\n    ELSE\n        -- No duplicate found. Safe to proceed!\n        SET p_response = JSON_OBJECT(\n            \'status\', 200,\n            \'message\', \'Validation passed. Name is unique.\',\n            \'payload\', NULL\n        );\n    END IF;\n\nEND','System Baseline Init','2026-07-03 05:28:00'),(7,'sp_get_client','PROCEDURE','proc_main: BEGIN\n    -- Internal Control Tracker Variables\n    DECLARE v_client_id BIGINT UNSIGNED DEFAULT NULL;\n    DECLARE v_client_UUID VARCHAR(50);\n    \n    -- System Exception State Catch Containers\n    DECLARE v_sql_state VARCHAR(5) DEFAULT \'00000\';\n    DECLARE v_error_msg TEXT;\n\n    -- =========================================================================\n    -- THE \"CATCH\" BLOCK (Global Exception Handler)\n    -- =========================================================================\n    DECLARE EXIT HANDLER FOR SQLEXCEPTION\n    BEGIN\n        GET DIAGNOSTICS CONDITION 1 \n            v_sql_state = RETURNED_SQLSTATE, \n            v_error_msg = MESSAGE_TEXT;\n\n        SET p_response = JSON_OBJECT(\n            \'status\', 500,\n            \'message\', CONCAT(\'Database Fetch Error: \', v_error_msg),\n            \'payload\', NULL\n        );\n    END;\n\n    -- =========================================================================\n    -- THE \"TRY\" BLOCK (Core Fetch Logic)\n    -- =========================================================================\n\n    -- 1. Safely extract target identification keys out of input document paths\n    SET v_client_UUID = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.payload.client_ID\'));\n    -- 2. Resolve internal master sequential primary auto-increment identifier \n    SELECT client_id INTO v_client_id  \n    FROM client  \n    WHERE client_UUID = v_client_UUID -- COLLATE utf8mb4_unicode_ci\n    LIMIT 1;\n\n    -- 3. Guard Clause: Route to structured error state mapping if target asset is missing\n    IF v_client_id IS NULL THEN\n        SET p_response = JSON_OBJECT(\n            \'status\', 4001,\n            \'message\', \'Client not found\',\n            \'payload\', NULL\n        );\n        LEAVE proc_main;\n    END IF;\n	-- Select v_client_id, v_client_UUID;\n    -- 4. Aggregate nested profiles into one final unified out JSON object\n    SELECT JSON_OBJECT(\n        \'status\', 200,\n        \'message\', \'Client record found\',\n        \'payload\', JSON_OBJECT(\n            \'client\', JSON_OBJECT(\n                \'client_id\', main.client_id,\n                \'client_name\', main.client_name,\n                \'client_type_code\', main.client_type_code\n            ),\n            \'client_data\', main.client_payload,\n            \'contacts\', COALESCE(main.contacts_array, JSON_ARRAY())\n        )\n    ) INTO p_response\n    FROM (\n        SELECT \n            c.client_id,\n            c.client_name,\n            c.client_type_code,\n            -- Pull down latest configurations mapping active versions\n            (SELECT cd.client_payload \n             FROM client_data cd \n             WHERE cd.client_id = c.client_id AND cd.active = TRUE \n             ORDER BY cd.client_data_id DESC LIMIT 1) AS client_payload,\n            -- Assemble nested stakeholders array while decrypting hidden text strings\n            (SELECT JSON_ARRAYAGG(\n                        JSON_OBJECT(\n                            \'name\', ct.name,\n                            \'email\', ct.email,\n                            \'mobile\', ct.mobile -- Decrypts inline safely\n                        )\n                    )\n             FROM contact ct\n             WHERE ct.table_name = \'client\'\n               AND ct.pk_id = c.client_id\n               AND ct.active = TRUE) AS contacts_array\n        FROM client c\n        WHERE c.client_id = v_client_id\n    ) main;\n\nEND','System Baseline Init','2026-07-03 05:28:00'),(8,'sp_get_client_list','PROCEDURE','proc_main: BEGIN\n    -- Control Variables\n    DECLARE v_userid BIGINT;\n    DECLARE v_offset INT DEFAULT 0;\n    DECLARE v_limit INT DEFAULT 20;\n    DECLARE v_total_records INT DEFAULT 0;\n    \n    -- Filter Strings\n    DECLARE v_filter_name VARCHAR(255) DEFAULT NULL;\n    DECLARE v_filter_type VARCHAR(30) DEFAULT NULL;\n    DECLARE v_final_array JSON;\n\n    -- System Error Capture Variables\n    DECLARE v_sql_state VARCHAR(5) DEFAULT \'00000\';\n    DECLARE v_error_msg TEXT;\n\n    -- =========================================================================\n    -- THE \"CATCH\" BLOCK (Global Exception Handler)\n    -- =========================================================================\n    DECLARE EXIT HANDLER FOR SQLEXCEPTION\n    BEGIN\n        GET DIAGNOSTICS CONDITION 1 \n            v_sql_state = RETURNED_SQLSTATE, \n            v_error_msg = MESSAGE_TEXT;\n\n        SET p_response = JSON_OBJECT(\n            \'status\', 500,\n            \'message\', CONCAT(\'Database Fetch Error: \', v_error_msg),\n            \'payload\', JSON_OBJECT(\'sql_state\', v_sql_state)\n        );\n    END;\n\n    -- =========================================================================\n    -- THE \"TRY\" BLOCK (Core Business Logic)\n    -- =========================================================================\n    \n    -- 1. Extract structural routing parameters from JSON input\n    SET v_userid = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.userid\')) AS UNSIGNED);\n    \n    -- Extract pagination parameters if supplied safely\n    IF JSON_CONTAINS_PATH(p_input_json, \'one\', \'$.offset\') = 1 THEN\n        SET v_offset = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.offset\')) AS UNSIGNED);\n    END IF;\n    IF JSON_CONTAINS_PATH(p_input_json, \'one\', \'$.limit\') = 1 THEN\n        SET v_limit = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.limit\')) AS UNSIGNED);\n    END IF;\n\n    -- 2. Extract searching filter criteria blocks\n    IF JSON_CONTAINS_PATH(p_input_json, \'one\', \'$.filters.client_name\') = 1 THEN\n        SET v_filter_name = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.filters.client_name\'));\n        IF v_filter_name = \'\' THEN \n            SET v_filter_name = NULL; \n        ELSE \n            SET v_filter_name = CONCAT(\'%\', v_filter_name, \'%\'); \n        END IF;\n    END IF;\n\n    IF JSON_CONTAINS_PATH(p_input_json, \'one\', \'$.filters.client_type_code\') = 1 THEN\n        SET v_filter_type = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.filters.client_type_code\'));\n        IF v_filter_type = \'\' THEN SET v_filter_type = NULL; END IF;\n    END IF;\n\n	-- 3. Optimization Step: Fetch Total Matching Count first (Bypassing LIMIT/OFFSET)\n    SELECT COUNT(1) INTO v_total_records\n    FROM client c\n    WHERE (v_filter_name IS NULL OR c.client_name LIKE v_filter_name)\n      AND (v_filter_type IS NULL OR c.client_type_code = v_filter_type);\n\n	-- 4. User Filter\n\n    -- 5. Execute Core Paginated Aggregation Query\n    SELECT JSON_ARRAYAGG(\n                JSON_OBJECT(\n                    \'client_id\', main.client_id,\n                    \'client_UUID\', main.client_UUID,\n                    \'client_name\', main.client_name,\n                    \'client_type_code\', main.client_type_code\n                    -- ,\'client_data\', main.client_payload\n                )\n           ) INTO v_final_array\n    FROM (\n        SELECT \n            c.client_id,\n            c.client_UUID,\n            c.client_name,\n            c.client_type_code,\n            (SELECT cd.client_payload \n             FROM client_data cd \n             WHERE cd.client_id = c.client_id AND cd.active = TRUE \n             ORDER BY cd.client_data_id DESC LIMIT 1) AS client_payload\n        FROM client c\n        WHERE (v_filter_name IS NULL OR c.client_name LIKE v_filter_name)\n         AND (v_filter_type IS NULL OR c.client_type_code = v_filter_type)\n        ORDER BY c.client_id DESC\n        LIMIT v_limit OFFSET v_offset\n    ) main;\n\n    -- 4. Construct response wrapper structure \n    SET p_response = JSON_OBJECT(\n        \'status\', 200,\n        \'message\', \'Client Record Found\',\n        \'payload\', JSON_OBJECT(\n            \'total_records\', v_total_records,\n            \'clients\', COALESCE(v_final_array, JSON_ARRAY())\n        )\n    );\n\nEND','System Baseline Init','2026-07-03 05:28:00'),(9,'sp_save_client','PROCEDURE','proc_main: BEGIN\n    -- Declare tracking variables\n    DECLARE v_userid BIGINT;\n    DECLARE v_client_id BIGINT UNSIGNED DEFAULT NULL;\n    DECLARE v_client_UUID VARCHAR(50); \n    DECLARE v_client_name VARCHAR(255);\n    DECLARE v_client_type_code VARCHAR(30);\n    DECLARE v_client_vertical_code VARCHAR(30) DEFAULT \'cvva\';\n    DECLARE v_client_data_payload JSON;\n    \n    -- Loop / Array context variables for Contacts parsing\n    DECLARE v_contact_count INT DEFAULT 0;\n    DECLARE v_idx INT DEFAULT 0;\n    DECLARE v_contact_name VARCHAR(255);\n    DECLARE v_contact_email VARCHAR(255);\n    DECLARE v_contact_mobile VARCHAR(20);\n\n    -- Variables to capture system error states\n    DECLARE v_sql_state VARCHAR(5) DEFAULT \'00000\';\n    DECLARE v_error_msg TEXT;\n\n    -- =========================================================================\n    -- THE \"CATCH\" BLOCK (Global Exception Handler)\n    -- =========================================================================\n    DECLARE EXIT HANDLER FOR SQLEXCEPTION\n    BEGIN\n        -- Capture the exact error details from the MySQL diagnostics engine\n        GET DIAGNOSTICS CONDITION 1 \n            v_sql_state = RETURNED_SQLSTATE, \n            v_error_msg = MESSAGE_TEXT;\n            \n        -- Explicitly rollback any uncommitted modifications\n        ROLLBACK;\n        \n        -- Return a clean, standardized error response object to Java\n        SET p_response = JSON_OBJECT(\n            \'status\', 500,\n            \'message\', CONCAT(\'Database Transaction Failed: \', v_error_msg),\n            \'payload\', JSON_OBJECT(\'sql_state\', v_sql_state)\n        );\n    END;\n\n    -- =========================================================================\n    -- THE \"TRY\" BLOCK (Transaction Logic Zone)\n    -- =========================================================================\n    START TRANSACTION;\n\n    -- 1. Extract foundational control structures out of the JSON root\n    SET v_userid = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.userid\')) AS UNSIGNED);\n    \n    -- 2. Extract client payload blocks\n    SET v_client_name = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.payload.client.client_name\'));\n    SET v_client_type_code = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.payload.client.client_type_code\'));\n    SET v_client_vertical_code = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.payload.client.v_client_vertical_code\'));\n    SET v_client_data_payload = JSON_EXTRACT(p_input_json, \'$.payload.client_data\');\n	-- SET v_client_UUID = JSON_EXTRACT(p_input_json, \'$.payload.client_UUID\');\n    \n    -- 3. Determine Route: Is it an Update or a New Entry?\n    IF JSON_CONTAINS_PATH(p_input_json, \'one\', \'$.payload.client.client_UUID\') = 1 AND \n       JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.payload.client.client_UUID\')) IS NOT NULL AND\n       JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.payload.client.client_UUID\')) != \'\' THEN\n       \n        SET v_client_UUID = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, \'$.payload.client.client_UUID\'));\n    END IF;\n\n    -- =========================================================================\n    -- BRANCH A: UPDATE EXISTENT RECORD (client_id is provided)\n    -- =========================================================================\n    IF v_client_UUID IS NOT NULL THEN\n        \n        -- Fetch the existing UUID so we can return it in the payload\n        SELECT client_id INTO v_client_id \n        FROM client \n        WHERE client_UUID = v_client_UUID;\n\n        -- Quick validation check: If client does not exist, throw custom escape notice\n        IF v_client_id IS NULL THEN\n            SET p_response = JSON_OBJECT(\n                \'status\', 4001,\n                \'message\', \'Client record matching provided client_id not found.\',\n                \'payload\', NULL\n            );\n            ROLLBACK;\n            LEAVE proc_main;\n        END IF;\n\n        -- Update Master Record Details\n        UPDATE client \n        SET client_name = v_client_name,\n            client_type_code = v_client_type_code\n        WHERE client_id = v_client_id;\n\n        -- Deactivate older matching rows in client_data\n        UPDATE client_data \n        SET active = FALSE \n        WHERE client_id = v_client_id;\n\n        -- Insert updated nested metadata block\n        INSERT INTO client_data (client_id, client_payload, updated_id, version)\n        VALUES (v_client_id, v_client_data_payload, v_userid, 2);\n\n        -- Clear out preceding dynamic structural associations for contacts\n        -- DELETE FROM contact \n        UPDATE contact \n        SET active = FALSE \n        WHERE table_name = \'client\' AND pk_id = v_client_id;\n\n        -- Format response with UUID payload\n        SET p_response = JSON_OBJECT(\n            \'status\', 200,\n            \'message\', \'client record updated\',\n            \'payload\', JSON_OBJECT(\'client_UUID\', v_client_UUID)\n        );\n\n    -- =========================================================================\n    -- BRANCH B: PROVISION NEW RECORD (client_id is NULL)\n    -- =========================================================================\n    ELSE\n        -- Generate the new UUID here first so we can reuse it\n        SET v_client_UUID =  f_generate_sequential_uuid() ;\n\n        -- Insert new client baseline registration profile\n        INSERT INTO client (client_UUID, client_name, client_type_code, client_vertical_code, created_id)\n        VALUES (v_client_UUID, v_client_name, v_client_type_code, v_client_vertical_code, v_userid);\n        \n        -- Pull down auto-increment key context identifier generated\n        SET v_client_id = LAST_INSERT_ID();\n\n        -- Save metadata payload block tracking context linked directly\n        INSERT INTO client_data (client_id, client_payload, updated_id, version)\n        VALUES (v_client_id, v_client_data_payload, v_userid, 1);\n\n        -- Format response with UUID payload\n        SET p_response = JSON_OBJECT(\n            \'status\', 200,\n            \'message\', \'client created\',\n            \'payload\', JSON_OBJECT(\'client_UUID\', v_client_UUID)\n        );\n    END IF;\n\n    -- =========================================================================\n    -- SHARED LAYER: PARSE AND POPULATE DYNAMIC MULTI-ROW CONTACT ARRAYS\n    -- =========================================================================\n    SET v_contact_count = JSON_LENGTH(JSON_EXTRACT(p_input_json, \'$.payload.contacts\'));\n    \n    WHILE v_idx < v_contact_count DO\n        SET v_contact_name  = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, CONCAT(\'$.payload.contacts[\', v_idx, \'].name\')));\n        SET v_contact_email = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, CONCAT(\'$.payload.contacts[\', v_idx, \'].email\')));\n        SET v_contact_mobile = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, CONCAT(\'$.payload.contacts[\', v_idx, \'].mobile\')));\n\n        INSERT INTO contact (table_name, pk_id, title, name, mobile, email, active)\n        VALUES (\'client\', v_client_id, \'Contact Member Mapping\', v_contact_name, v_contact_mobile, v_contact_email, TRUE);\n\n        SET v_idx = v_idx + 1;\n    END WHILE;\n\n    -- If all operations succeed, commit everything together safely\n    COMMIT;\nEND','System Baseline Init','2026-07-03 05:28:00'),(10,'sp_sync_all_schema_history','PROCEDURE','BEGIN\n    -- Cursor Loop tracking indicators\n    DECLARE v_done INT DEFAULT FALSE;\n    DECLARE v_obj_name VARCHAR(100);\n    DECLARE v_obj_type VARCHAR(20);\n    DECLARE v_obj_body LONGTEXT;\n    DECLARE v_count INT DEFAULT 0;\n\n    -- 1. Declare Cursor for Stored Procedures & Functions\n    DECLARE cursor_routines CURSOR FOR \n        SELECT ROUTINE_NAME, ROUTINE_TYPE, ROUTINE_DEFINITION\n        FROM information_schema.ROUTINES \n        WHERE ROUTINE_SCHEMA = \'corporateqms\';\n\n    -- 2. Declare Cursor for Views\n    DECLARE cursor_views CURSOR FOR \n        SELECT TABLE_NAME, \'VIEW\', VIEW_DEFINITION\n        FROM information_schema.VIEWS \n        WHERE TABLE_SCHEMA = \'corporateqms\';\n\n    -- Loop termination condition loop handler\n    DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_done = TRUE;\n\n    -- Global Exception Trap Block\n    DECLARE EXIT HANDLER FOR SQLEXCEPTION\n    BEGIN\n        SET p_response = JSON_OBJECT(\n            \'status\', 500,\n            \'message\', \'Mass schema synchronization execution failed mid-process.\',\n            \'payload\', NULL\n        );\n    END;\n\n    -- =========================================================================\n    -- STEP 1: PROCESSING PROCEDURES & FUNCTIONS\n    -- =========================================================================\n    OPEN cursor_routines;\n    \n    routine_loop: LOOP\n        FETCH cursor_routines INTO v_obj_name, v_obj_type, v_obj_body;\n        IF v_done THEN\n            LEAVE routine_loop;\n        END IF;\n\n        -- Log definitions to history only if a code body actually exists\n        IF v_obj_body IS NOT NULL AND v_obj_body <> \'\' THEN\n            INSERT INTO system_schema_history (object_name, object_type, definition_body, changed_by)\n            VALUES (v_obj_name, v_obj_type, v_obj_body, p_developer_name);\n            SET v_count = v_count + 1;\n        END IF;\n    END LOOP;\n    \n    CLOSE cursor_routines;\n\n    -- Reset termination flag for next cursor loop sequence\n    SET v_done = FALSE;\n\n    -- =========================================================================\n    -- STEP 2: PROCESSING DATABASE VIEWS\n    -- =========================================================================\n    OPEN cursor_views;\n    \n    view_loop: LOOP\n        FETCH cursor_views INTO v_obj_name, v_obj_type, v_obj_body;\n        IF v_done THEN\n            LEAVE view_loop;\n        END IF;\n\n        IF v_obj_body IS NOT NULL AND v_obj_body <> \'\' THEN\n            INSERT INTO system_schema_history (object_name, object_type, definition_body, changed_by)\n            VALUES (v_obj_name, v_obj_type, v_obj_body, p_developer_name);\n            SET v_count = v_count + 1;\n        END IF;\n    END LOOP;\n    \n    CLOSE cursor_views;\n\n    -- Return full transaction summary confirmation report\n    SET p_response = JSON_OBJECT(\n        \'status\', 200,\n        \'message\', \'Database schema historical snapshot complete.\',\n        \'payload\', JSON_OBJECT(\n            \'total_objects_archived\', v_count\n        )\n    );\n\nEND','System Baseline Init','2026-07-03 05:28:00'),(11,'ZPopulateDummyClients','PROCEDURE','BEGIN\n    DECLARE i INT DEFAULT 1;\n    DECLARE current_user_id INT;\n    DECLARE random_uuid VARCHAR(36);\n    DECLARE random_pan VARCHAR(10);\n    DECLARE random_gstin VARCHAR(15);\n    DECLARE client_type VARCHAR(4);\n    DECLARE vertical VARCHAR(4);\n    DECLARE biz_type VARCHAR(30);\n\n    WHILE i <= 500 DO\n        SET current_user_id = IF(i % 2 = 0, 2, 1);\n        SET random_uuid = REPLACE(REPLACE(UUID(),\'-\', \'Q\') , \'f\',\'1\'); -- REPLACE(text, \'-\', \'Q\'):\n        SET random_pan = CONCAT(\'ABCDE\', FLOOR(1000 + (RAND() * 8999)), \'F\');\n        SET random_gstin = CONCAT(\'27\', random_pan, \'1Z\', FLOOR(RAND() * 9));\n        \n        SET client_type = ELT((i % 2) + 1, \'cttc\', \'cttd\');\n        SET vertical = ELT((i % 3) + 1, \'cvva\', \'coos\', \'cooi\');\n        SET biz_type = ELT((i % 4) + 1, \'Manufacturing\', \'Retail Logistics\', \'Pharmaceuticals\', \'IT Services\');\n\n        INSERT INTO `client` \n        (`client_UUID`, `client_name`, `client_type_code`, `client_vertical_code`, `created_id`)\n        VALUES \n        (\n            f_generate_sequential_uuid(),  -- INSERT(client_UUID, 1, 3, \'999\')\n            CONCAT(\'Test Enterprise Hub \', i), \n            client_type, \n            vertical, \n            current_user_id\n        );\n\n        INSERT INTO `client_data` \n        (`client_id`, `client_payload`, `version`, `updated_id`)\n        VALUES\n        (\n            LAST_INSERT_ID(),\n            CONCAT(\'{\n                \"client\": {\n                    \"pancard\": \"\', random_pan, \'\",\n                    \"cin_number\": \"L\', FLOOR(10000 + (RAND() * 89999)), \'MH2026PLC\', FLOOR(100000 + (RAND() * 899999)), \'\",\n                    \"tin_number\": \"9876543\', FLOOR(1000 + (RAND() * 8999)), \'\",\n                    \"gstin\": \"\', random_gstin, \'\",\n                    \"biz_type\": \"\', biz_type, \'\"\n                },\n                \"address\": {\n                    \"address_line1\": \"Building \', FLOOR(1 + (RAND() * 500)), \', Industrial Zone\",\n                    \"address_line2\": \"Phase \', ELT((i % 3) + 1, \'I\', \'II\', \'III\'), \'\",\n                    \"cityid\": \', FLOOR(400000 + (RAND() * 99999)), \',\n                    \"stateid\": \', FLOOR(1 + (RAND() * 36)), \',\n                    \"pincode\": \"4000\', FLOOR(10 + (RAND() * 89)), \'\"\n                },\n                \"portfolio\": {\n                    \"biz_type\": \"\', ELT((i % 3) + 1, \'Property\', \'Motor\', \'Marine\'), \'\",\n                    \"lob\": \"\', ELT((i % 3) + 1, \'Fire & Engineering\', \'Commercial Vehicles\', \'Cargo Transit\'), \'\",\n                    \"product\": \"Product Package Option \', ELT((i % 2) + 1, \'A\', \'B\'), \'\",\n                    \"sub_product\": \"Standard Subcategory Plan\",\n                    \"sum_insured\": \', ROUND(5000000 + (RAND() * 45000000), 0), \',\n                    \"expected_premium\": \', ROUND(20000 + (RAND() * 180000), 0), \',\n                    \"brokerage\": \', ROUND(5.0 + (RAND() * 10.0), 2), \',\n                    \"renewal_date\": \"\', DATE_ADD(CURRENT_DATE, INTERVAL FLOOR(RAND() * 365) DAY), \'\"\n                }\n            }\'),\n            1,\n            current_user_id\n        );\n\n        SET i = i + 1;\n    END WHILE;\nEND','System Baseline Init','2026-07-03 05:28:00'),(12,'ZPopulateDummyContacts','PROCEDURE','BEGIN\n    DECLARE done INT DEFAULT FALSE;\n    DECLARE current_client_id BIGINT UNSIGNED;\n    DECLARE i INT DEFAULT 1;\n    \n    -- Cursor to iterate through all existing clients\n    DECLARE client_cursor CURSOR FOR SELECT client_id FROM `client`;\n    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;\n\n    OPEN client_cursor;\n\n    read_loop: LOOP\n        FETCH client_cursor INTO current_client_id;\n        IF done THEN\n            LEAVE read_loop;\n        END IF;\n\n        -- 1. Insert Primary Contact for this client\n        INSERT INTO `contact` (`table_name`, `pk_id`, `title`, `name`, `mobile`, `email`, `active`)\n        VALUES (\n            \'client\',\n            current_client_id,\n            \'Primary Contact\',\n            CONCAT(\'Executive Director \', i),\n            CONCAT(\'+1-555-01\', LPAD(i, 3, \'0\')),\n            CONCAT(\'primary.exec\', i, \'@testqmsdomain.com\'),\n            TRUE\n        );\n\n        -- 2. Insert Secondary Contact for this client\n        INSERT INTO `contact` (`table_name`, `pk_id`, `title`, `name`, `mobile`, `email`, `active`)\n        VALUES (\n            \'client\',\n            current_client_id,\n            \'Operations Lead\',\n            CONCAT(\'Manager Specialist \', i),\n            CONCAT(\'9999000000\'+         FLOOR(100000 + (RAND() * 899999))),\n            CONCAT(\'ops.lead\', i, \'@testqmsdomain.com\'),\n            TRUE\n        );\n\n        SET i = i + 1;\n    END LOOP;\n\n    CLOSE client_cursor;\nEND','System Baseline Init','2026-07-03 05:28:00');
