CREATE DEFINER=`root`@`localhost` FUNCTION `rfq_f_generate_sequential_uuid`() RETURNS varchar(50) CHARSET utf8mb4
    DETERMINISTIC
BEGIN
    -- CONCAT implicitly converts the random number to a string, saving CPU cycles
    RETURN CONCAT(
        FLOOR(100000 + (RAND() * 899999)), 
        REPLACE(UUID(), '-', 'Q')
    );
END ;;
DELIMITER ;
