CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_getmispoutletpagedetails`(
    IN Json_data JSON,
    IN type VARCHAR(45),
    OUT SP_STATUS VARCHAR(500),
    OUT MESSAGE VARCHAR(500)
)
BEGIN
    DECLARE pageId VARCHAR(45);
    DECLARE roleId VARCHAR(45);
    DECLARE searchName VARCHAR(100); 
    DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 0;
    DECLARE calculated INT DEFAULT 0;
    DECLARE dealerId VARCHAR(100);
    DECLARE crossAllocation VARCHAR (45);
    DECLARE columnindex INT DEFAULT 0;
    DECLARE crossIndex INT DEFAULT 0;
    DECLARE map VARCHAR(45);
    DECLARE dealerLoc VARCHAR(45);
    DECLARE dbTableName VARCHAR(45);
    DECLARE dbColName VARCHAR(45);
    DECLARE excelColName VARCHAR(45);
    DECLARE parentId VARCHAR(100);
    DECLARE i INT DEFAULT 0;
    DECLARE hasError BOOLEAN DEFAULT false;
	DECLARE customId INT DEFAULT 0;
	DECLARE dealerName VARCHAR(255);
    DECLARE ebmCode VARCHAR(45);
    DECLARE v_mappingDealerCode VARCHAR(45);
    DECLARE v_customType VARCHAR(45);
    DECLARE v_dealerName VARCHAR(225);
    DECLARE v_excelBlob LONGBLOB;
	DECLARE old_upload_data JSON;
	DECLARE new_upload_data JSON;
    DECLARE v_dealerId VARCHAR(45);
    DECLARE v_map VARCHAR(45);
    DECLARE	v_parentId varchar(45);
    DECLARE	v_crossAllocation varchar(45);
    DECLARE	v_flag varchar(45);
    DECLARE	v_dealerLocName varchar(45);
    DECLARE	v_dealerLocCode varchar(45);
    DECLARE	v_state varchar(45);
    DECLARE	v_userId varchar(45);
    DECLARE v_ebmCode VARCHAR(45);
    DECLARE sortField VARCHAR(45);
    DECLARE sortOrder VARCHAR(45);
    
	
    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        GET DIAGNOSTICS CONDITION 1 
            @sqlstate = RETURNED_SQLSTATE,errno = MYSQL_ERRNO,errmsg = MESSAGE_TEXT;

		   SET SP_STATUS = 407;
		   SET MESSAGE = 'Something Went Worng';
		ROLLBACK;

		INSERT INTO mmi_mast_procedure_error (error_code,error_message,procedure_name,procedure_type,ERROR_TIMING,created_by,created_date) 
		VALUES (errno,CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg),'mmi_getmispoutletpagedetails',type,CURRENT_TIMESTAMP(),'SYSTEM',NOW());

END;
    -- getdealerdetails
    IF type = 'getdealerdetails' THEN
        SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.limit')) AS UNSIGNED), 10);
        SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.offset')) AS UNSIGNED), 0);
        SET searchName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.searchName'));
        SET calculated = (offsetVal - 1) * limitVal;
        
        SET sortField = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.sortField'));
		SET sortOrder = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.sortOrder'));

		-- Set default sort field
		IF sortField IS NULL OR sortField = '' THEN
			SET sortField = 'Name';
		END IF;

		-- Set default sort order
		IF sortOrder IS NULL OR sortOrder = '' THEN
			SET sortOrder = 'asc';
		END IF;


        IF limitVal IS NULL  OR offsetVal IS NULL OR limitVal='' OR offsetVal='' THEN
            SET SP_STATUS = "400";
            SET MESSAGE = 'limit or offset cannot be empty or NULL';
        ELSE
			SELECT 
				dealer_ebmcode as ebmCode,dealer_parent_code as parentId,dealer_id as dealerId,
				dealer_name as dealerName,mobile_no as dealerMobileNo,dealer_loc_name as dealerLocName,dealer_address as dealerAddress
				FROM getdealerdetails
				WHERE 
				LOWER(dealer_name) LIKE LOWER(CONCAT('%', searchName, '%')) 
                OR LOWER(dealer_loc_name) LIKE LOWER(CONCAT('%', searchName, '%'))
				OR LOWER(dealer_address) LIKE LOWER(CONCAT('%', searchName, '%')) 
                OR LOWER(dealer_ebmcode) LIKE LOWER(CONCAT('%', searchName, '%'))
				OR LOWER(dealer_id) LIKE LOWER(CONCAT('%', searchName, '%'))
				OR LOWER(mobile_no) LIKE LOWER(CONCAT('%', searchName, '%'))
                ORDER BY
					CASE WHEN sortField = 'Location' AND sortOrder = 'asc' THEN dealer_loc_name END ASC,
					CASE WHEN sortField = 'Location' AND sortOrder = 'desc' THEN dealer_loc_name END DESC,
					CASE WHEN sortField = 'Dealer Code' AND sortOrder = 'asc' THEN dealer_id END ASC,
					CASE WHEN sortField = 'Dealer Code' AND sortOrder = 'desc' THEN dealer_id END DESC,
					CASE WHEN sortField = 'Mobile No' AND sortOrder = 'asc' THEN mobile_no END ASC,
					CASE WHEN sortField = 'Mobile No' AND sortOrder = 'desc' THEN mobile_no END DESC,
					CASE WHEN sortField = 'Name' AND sortOrder = 'asc' THEN dealer_name END ASC,
					CASE WHEN sortField = 'Name' AND sortOrder = 'desc' THEN dealer_name END DESC,
					CASE WHEN sortField = 'Address' AND sortOrder = 'asc' THEN dealer_address END ASC,
					CASE WHEN sortField = 'Address' AND sortOrder = 'desc' THEN dealer_address END DESC
				LIMIT limitVal OFFSET calculated;
            
			SELECT COUNT(*) AS totalcount FROM getdealerdetails WHERE LOWER(dealer_name) LIKE LOWER(CONCAT('%', searchName, '%')) OR 
			LOWER(dealer_loc_name) LIKE LOWER(CONCAT('%', searchName, '%')) OR LOWER(dealer_address) LIKE LOWER(CONCAT('%', searchName, '%')) OR 
			LOWER(dealer_ebmcode) LIKE LOWER(CONCAT('%', searchName, '%')) OR LOWER(dealer_id) LIKE LOWER(CONCAT('%', searchName, '%'));
                
             SELECT distinct loc_code as dealerLocCode,customtype FROM mmi_excel_column_mapping where parent_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'));   
            
            SET SP_STATUS = "200";
            SET MESSAGE = 'Fetched all dealer list successfully.';
	END IF;

    -- gettablecolumnsname
    ELSEIF type='countdealerdetails' then 

		SET searchName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.searchName'));
			
		SELECT COUNT(*) AS totalcount FROM getdealerdetails WHERE LOWER(dealer_name) LIKE LOWER(CONCAT('%', searchName, '%')) 
		OR LOWER(dealer_loc_name) LIKE LOWER(CONCAT('%', searchName, '%'));

            SET SP_STATUS = "200";
            SET MESSAGE = 'Success';
            
    ELSEIF type = 'fetchDealerDetails' THEN
        SET dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'));
        SET parentId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'));

        -- IF dealerId IS NULL OR dealerId = '' OR 
        IF parentId IS NULL OR parentId = '' THEN
            SET SP_STATUS = "400";
            SET MESSAGE = CASE
				-- WHEN dealerId IS NULL OR dealerId = '' THEN 'dealerId is missing'
				WHEN parentId IS NULL OR parentId = '' THEN 'parent code is missing'
				END;
        ELSE
			
			SELECT * FROM (
			 SELECT 'policy' AS result_type, columns_name AS columns, mandatory AS required, NULL AS column3 
			 FROM mmi_mast_columns_mandatory 
			 WHERE db_table_name = 'mmi_ebm_policy_data'

			 UNION ALL

			 SELECT 'claim', columns_name, mandatory, NULL 
			 FROM mmi_mast_columns_mandatory 
			 WHERE db_table_name = 'mmi_ebm_claim_data'

			 UNION ALL

			 SELECT 'sales', columns_name, mandatory, NULL 
			 FROM mmi_mast_columns_mandatory 
			 WHERE db_table_name = 'mmi_ebm_sales_data'

			 UNION ALL

			 SELECT 'service', columns_name, mandatory, NULL 
			 FROM mmi_mast_columns_mandatory 
			 WHERE db_table_name = 'mmi_ebm_service_data'

			 UNION ALL

			 SELECT 'addon', columns_name, mandatory, NULL 
			 FROM mmi_mast_columns_mandatory 
			 WHERE db_table_name = 'mmi_poladdon_data'

		) AS unified_result;

-- Dealer Code and Mapping Dealer code same list fetching for Map and Corss Allocation
            
		SELECT DISTINCT 
		mdlm.location_code AS dealerLocCode,
		md.loc_name AS dealerLocName,
		mdlm.dealer_code AS dealerId,
		md.comm_address as dealerAddress,
		dd.lead_assignment as leadAssignment,
		dd.cross_allocation as crossAllocation,
		dd.communication as communication,
		dd.otp_flag as otpFlag,
        dd.policy_flag as policyFlag,dd.claim_flag as claimFlag, dd.service_flag as serviceFlag,
        dd.sales_flag as salesFlag,dd.addon_flag as addOnFlag
		FROM mmi_dealer_location_mapping mdlm
		left join mmi_mast_dealer_location md ON mdlm.location_code = md.loc_code
		left join mmi_dealer_details dd on dd.dealer_id = mdlm.mapping_dealer_code and dd.dealer_id = mdlm.dealer_code
		WHERE mdlm.mapping_dealer_code = mdlm.dealer_code and mdlm.parent_code = parentId;


			--  Dealer Code and Mapping Dealer code same list fetching for created Tempalte Dropdown
			select distinct ecm.dealer_id AS dealerId,ecm.loc_code AS dealerLocCode
            ,md.loc_name AS dealerLocName,ecm.customtype
            from mmi_excel_column_mapping ecm left join mmi_dealer_location_mapping mdlm 
			on mdlm.parent_code = ecm.parent_id  and mdlm.dealer_code = ecm.dealer_id 
			left JOIN mmi_mast_dealer_location md ON mdlm.location_code = md.loc_code
            WHERE ecm.mapping_dealer_code = ecm.dealer_id and ecm.parent_id = parentId;

    
		SET SP_STATUS = '200';
		SET MESSAGE = 'Fetching Dealer Details Successfully';
	END IF;

    -- saveoutletsetup
     ELSEIF type = 'saveoutletsetup' THEN
     
        SET v_dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'));
        SET v_map = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.map'));
		SET crossAllocation = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.crossAllocation'));
		SET v_ebmCode = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.ebmCode'));
        SET v_flag = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.flag'));
        SET v_dealerLocName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerLocName'));
        SET v_parentId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'));
        SET v_dealerLocCode = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerLocCode'));
        SET v_userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
        SET v_state = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.state'));
		
		IF (v_flag IS  NULL OR v_flag = '') AND (v_dealerId IS NULL OR v_dealerId = '' 
		OR v_parentId IS NULL OR v_parentId = '' 
		) 
		THEN
			SET SP_STATUS = '400';
			SET MESSAGE = CASE
				WHEN v_dealerId IS NULL OR v_dealerId = '' THEN 'DealerId is missing'
				WHEN v_parentId IS NULL OR v_parentId = '' THEN 'Parent Code is missing'
				END;
			ELSE
        START TRANSACTION;
        
		IF v_flag = 'addNewDealer' THEN
		
        SET v_dealerName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerName'));						
		
        IF v_parentId IS NULL OR v_parentId = '' THEN
		
			SET @v_parentPrefix = UPPER(LEFT(REPLACE(v_dealerName, ' ', ''), 4));

			-- SELECT LPAD(COALESCE(MAX(CAST(SUBSTRING(parent_code, 5) AS UNSIGNED)) + 1, 1 ), 4, '0') 
			-- INTO @nextNum FROM mmi_mast_dealer WHERE parent_code LIKE CONCAT(@v_parentPrefix, '%');
			    /*SELECT LPAD(COALESCE(MAX(CAST(NULLIF(SUBSTRING(parent_code, 5), '') AS UNSIGNED)) + 1, 1),4, '0')
				INTO @nextNum FROM mmi_mast_dealer WHERE parent_code LIKE CONCAT(@v_parentPrefix, '%') 
                AND SUBSTRING(parent_code, 5) REGEXP '^[0-9]+$';*/
                
                SELECT LPAD(COALESCE(MAX(CAST(NULLIF(SUBSTRING(parent_code, 5), '') AS UNSIGNED)) + 1, 1),4, '0')
				INTO @nextNum FROM mmi_dealer_location_mapping WHERE parent_code LIKE CONCAT(@v_parentPrefix, '%') 
                AND SUBSTRING(parent_code, 5) REGEXP '^[0-9]+$';


			SET v_parentId = CONCAT(@v_parentPrefix, @nextNum);

         -- Parent not exist then insert   
		INSERT INTO mmi_mast_dealer(dealer_name, parent_code, is_active ,status ,created_by, created_date)
		VALUES (v_dealerName, v_parentId, '1', '1', v_userId, now());

		END IF;
                    
	-- Get the max dealer_Id under this parent Code
	SELECT MAX(dealer_code) INTO v_dealerId FROM mmi_dealer_location_mapping 
    WHERE parent_code = v_parentId;

		IF v_dealerId IS NULL OR v_dealerId = '' THEN
			select   Concat(UPPER(LEFT(v_dealerName, 3)),
			LPAD(FLOOR(100 + RAND() * 900), 3, '0'),
			UPPER(RIGHT(v_dealerName, 3)),'0001') into v_dealerId;
            
            set v_map = v_dealerId;
            
		ELSE   
			-- Increment the numeric sequence (last 4 digits)
			-- SET v_dealerId = CONCAT(LEFT(v_dealerId, 9), 
			-- LPAD(RIGHT(v_dealerId, 4) + 1, 4, '0')
			-- );
			SET @last4 = RIGHT(v_dealerId, 4);

			IF @last4 REGEXP '^[0-9]+$' THEN
				SET v_dealerId = CONCAT(LEFT(v_dealerId, 9), LPAD(@last4 + 1, 4, '0'));
			ELSE
				SET v_dealerId = CONCAT(LEFT(v_dealerId, 9), '0001');  -- fallback if last4 is non-numeric
			END IF;
				set v_map = v_dealerId;
		END IF;
        
        IF v_dealerLocCode is null or v_dealerLocCode =  '' then
                
        select concat(UPPER(LEFT(REPLACE(v_dealerLocName, ' ', ''), 3))
        , v_parentId,UPPER(right(REPLACE(v_dealerId, ' ', ''), 3))) into v_dealerLocCode;
        
        INSERT INTO mmi_mast_dealer_location ( loc_code, loc_name, comm_address, state, locality, location_status, created_by,created_date)
		VALUES (
		v_dealerLocCode,v_dealerLocName, 
		JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerAddress')),
		v_state,
		JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerAddress')),
		'1',v_userId,now());
			
        END IF;
        
		INSERT INTO mmi_dealer_location_mapping
		(dealer_name,location_code, parent_code, dealer_code, -- mapping_dealer_code,
        mobile_no,zone,status, is_active, created_by, created_date) 
		VALUES (v_dealerName, v_dealerLocCode, v_parentId, v_dealerId, -- v_map ,
        JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.mobileNo')),JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.zone')),'1', '1', v_userId, now());

		
        			
	END IF;
        
		-- Step 1: Check if record exists
		SELECT COUNT(*) INTO @recordExists FROM mmi_dealer_details WHERE  dealer_id = v_dealerId AND parent_code = v_parentId;
 
		if v_dealerName is null or v_dealerName = '' then 

		SET v_dealerName = (SELECT dealer_name FROM mmi_dealer_location_mapping WHERE parent_code = v_parentId and dealer_code = v_dealerId);-- (SELECT dealer_name FROM mmi_mast_dealer WHERE parent_code = v_parentId);

		END IF;
        
        IF @recordExists = 0 THEN
           
				INSERT INTO mmi_dealer_details (dealer_id,dealer_name,parent_code,ebm_code,map,
                lead_assignment,communication,policy_flag,claim_flag,service_flag,sales_flag,
                addon_flag,cross_allocation,created_by,otp_flag
				) VALUES (
					v_dealerId,
					v_dealerName,
					v_parentId,
					v_ebmCode,
					v_map,
					JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.leadAssignment')),
					JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.communication')),
					JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.policyFlag')),
					JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.claimFlag')),
					JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.serviceFlag')),
					JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.salesFlag')),
					JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.addOnFlag')),
					crossAllocation,
                    JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
                    JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.otpFlag'))
				);

ELSE

			UPDATE mmi_dealer_details
			SET 
				map             = v_map,
				lead_assignment = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.leadAssignment')),
				communication   = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.communication')),
				policy_flag     = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.policyFlag')),
				claim_flag      = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.claimFlag')),
				service_flag    = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.serviceFlag')),
				sales_flag      = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.salesFlag')),
				addon_flag      = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.addOnFlag')),
				cross_allocation = crossAllocation,
				modified_by = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
				modified_date = NOW(),
                otp_flag = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.otpFlag'))
			WHERE dealer_id = v_dealerId and parent_code = v_parentId 
            ;



-- this updating for who mapped to dealer code also updating
UPDATE mmi_dealer_details
			SET 
				map             = v_map,
				lead_assignment = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.leadAssignment')),
				communication   = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.communication')),
				policy_flag     = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.policyFlag')),
				claim_flag      = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.claimFlag')),
				service_flag    = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.serviceFlag')),
				sales_flag      = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.salesFlag')),
