            );

         UPDATE mmi_dealer_location_mapping  SET status = '0' ,  mapping_dealer_code = v_map
         WHERE parent_code =  v_parentId AND dealer_code = v_dealerId;
         
   
   -- If dealerId and Mapping dealerId Differnet Then Mapping DealerId ColumnsMapping map to DealerId
   
   IF v_dealerId <> v_map then 
DELETE FROM mmi_excel_column_mapping
WHERE dealer_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'))
AND parent_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'))
-- AND customtype = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype'))
;
    
   INSERT INTO mmi_excel_column_mapping (
    custom_id,
    dealer_id,
    parent_id,
    loc_code,
    customtype,
    column_mapping_excel,
    created_by,
    mapping_dealer_code,
    column_mapping_file_name
)
SELECT *
FROM (
		SELECT
		custom_id,
		JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId')) AS dealer_id,
		parent_id,
		loc_code,
		customtype,
		column_mapping_excel,
		JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')) as created_by,
