		column_mapping_file_name
    FROM mmi_excel_column_mapping
    WHERE
        parent_id = parentId AND dealer_id = map ORDER BY custom_id
) AS sub;  
	END IF;

SELECT JSON_ARRAYAGG(
    JSON_OBJECT(
        'id', IFNULL(id, ''),
        'custom_id', IFNULL(custom_id, ''),
        'dealer_id', IFNULL(dealer_id, ''),
        'parent_id', IFNULL(parent_id, ''),
        'loc_code', IFNULL(loc_code, ''),
        'mapping_dealer_code', IFNULL(mapping_dealer_code, ''),
        'customtype', IFNULL(customtype, ''),
        'created_by', IFNULL(created_by, ''),
        'created_date', IFNULL(created_date, ''),
        'modified_by', IFNULL(modified_by, ''),
        'modified_date', IFNULL(modified_date, '')
    )
)
INTO  old_upload_data FROM mmi_excel_column_mapping;
         
         
 DELETE ecm
FROM mmi_excel_column_mapping ecm
JOIN mmi_dealer_details dd 
    ON ecm.parent_id = dd.parent_code  
   AND dd.dealer_id = ecm.dealer_id
WHERE dd.parent_code = v_parentId
  AND ecm.dealer_id =  v_dealerId
  AND (
      (ecm.customtype = 'sales'   AND dd.sales_flag = 'sales_system') OR
      (ecm.customtype = 'policy'  AND dd.policy_flag = 'policy_system') OR
      (ecm.customtype = 'claim'   AND dd.claim_flag = 'claim_system') OR
      (ecm.customtype = 'service' AND dd.service_flag = 'service_system') OR
      (ecm.customtype = 'addon'   AND dd.addon_flag = 'addon_system')
  );
  
  SELECT JSON_ARRAYAGG(
    JSON_OBJECT(
        'id', IFNULL(id, ''),
        'custom_id', IFNULL(custom_id, ''),
        'dealer_id', IFNULL(dealer_id, ''),
        'parent_id', IFNULL(parent_id, ''),
        'loc_code', IFNULL(loc_code, ''),
        'mapping_dealer_code', IFNULL(mapping_dealer_code, ''),
        'customtype', IFNULL(customtype, ''),
        'created_by', IFNULL(created_by, ''),
        'created_date', IFNULL(created_date, ''),
        'modified_by', IFNULL(modified_by, ''),
        'modified_date', IFNULL(modified_date, '')
    )
)
INTO new_upload_data FROM mmi_excel_column_mapping;

 INSERT INTO mmi_maintain_overwrite_logs (
    upload_type,name,
    old_upload_data, new_upload_data,
    created_by, created_date
    ) VALUES 
(
    'save Outlet', 'mmi_excel_column_mapping',
    old_upload_data, new_upload_data,
    JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')), NOW()
);

        Commit; 
		SET SP_STATUS = '200';
		SET MESSAGE = 'Outlet details saved successfully.';
	END IF;
    
    -- Fetch dealer List 
    ELSEIF type = 'editDealerDetails' THEN
    
		SET dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'));
        SET ebmCode = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.ebmCode'));
		SET parentId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'));
       
   IF dealerId IS NULL OR dealerId = '' 
		-- OR ebmCode IS NULL OR ebmCode = '' 
		OR parentId IS NULL OR parentId = '' 
		THEN
		SET SP_STATUS = '400';

		SET MESSAGE = CASE
		WHEN dealerId IS NULL OR dealerId = '' THEN 'dealerId is missing'
		-- WHEN ebmCode IS NULL OR ebmCode = '' THEN 'EBM Code is missing'
		WHEN parentId IS NULL OR parentId = '' THEN 'parent id is missing'
		END;
   ELSE
        
-- Fetching Dealer Details based on Dealer Id and Ebm Code    
 select distinct 
		dd.dealer_id as dealerId,
        dd.map,
        dd.lead_assignment as leadAssignment,
        dd.cross_allocation as crossAllocation
		,dd.communication,
        dd.policy_flag as policyFlag,
        dd.claim_flag as claimFlag,
        dd.service_flag as serviceFlag
        ,dd.sales_flag as salesFlag ,
        dd.addon_flag as addOnFlag,
        dd.otp_flag as otpFlag
		from mmi_dealer_details dd 
		left join mmi_dealer_location_mapping dlp on dd.parent_code = dlp.parent_code and
		dd.dealer_id = dlp.dealer_code 
        where dd.dealer_id = dealerId -- AND dd.ebm_code = ebmCode
		AND dd.parent_code = parentId;

		-- Fetching Dealer Excel Column Mapping
	SELECT DISTINCT
    t.dealerId,
    -- t.custom_id,
    t.dbTableName,
    t.dbColumnName,
    t.excelColumnName,
    t.column_mapping_file_name,
    IF(t.rn = 1, t.column_mapping_excel, null) AS column_mapping_excel
FROM (
    SELECT DISTINCT
        ecm.dealer_id AS dealerId,
        ecm.custom_id,
        mec.db_table_name AS dbTableName,
        mec.db_column_name AS dbColumnName,
        mec.excel_column_name AS excelColumnName,
        ecm.column_mapping_excel,
        ecm.column_mapping_file_name,
        ROW_NUMBER() OVER (PARTITION BY ecm.custom_id ORDER BY mec.id) AS rn
    FROM mmi_mast_excel_column_mapping mec
    JOIN mmi_excel_column_mapping ecm ON ecm.custom_id = mec.custom_id
    JOIN mmi_dealer_details dd ON dd.dealer_id = ecm.dealer_id
    WHERE ecm.dealer_id = dealerId
      AND (
            (mec.db_table_name = 'mmi_ebm_policy_data'   AND dd.policy_flag = 'policy_custom') OR
            (mec.db_table_name = 'mmi_ebm_claim_data'    AND dd.claim_flag  = 'claim_custom') OR
            (mec.db_table_name = 'mmi_ebm_service_data'  AND dd.service_flag = 'service_custom') OR
            (mec.db_table_name = 'mmi_ebm_sales_data'    AND dd.sales_flag = 'sales_custom') OR
            (mec.db_table_name = 'mmi_poladdon_data'     AND dd.addon_flag = 'addon_custom')
          )
      AND mec.status = 1
) t;
    -- Dealer Code and Mapping Dealer code same list fetching for Map and Corss Allocation
            
	SELECT DISTINCT 
		mdlm.location_code AS dealerLocCode,
		md.loc_name AS dealerLocName,
		mdlm.dealer_code AS dealerId,
		md.comm_address as dealerAddress,
		dd.lead_assignment as leadAssignment,
		dd.cross_allocation as crossAllocation,
		dd.communication as communication,
		dd.otp_flag as otpFlag,
        dd.policy_flag as policyFlag,dd.claim_flag as claimFlag, dd.service_flag as serviceFlag,
        dd.sales_flag as salesFlag,dd.addon_flag as addOnFlag
		FROM mmi_dealer_location_mapping mdlm
		left join mmi_mast_dealer_location md ON mdlm.location_code = md.loc_code
		left join mmi_dealer_details dd on dd.dealer_id = mdlm.mapping_dealer_code and dd.dealer_id = mdlm.dealer_code
		WHERE mdlm.mapping_dealer_code = mdlm.dealer_code
		and mdlm.parent_code = parentId;
    
    SELECT * FROM (
     SELECT 'policy' AS result_type, columns_name AS columns, mandatory AS required, NULL AS column3 
     FROM mmi_mast_columns_mandatory 
     WHERE db_table_name = 'mmi_ebm_policy_data'

     UNION ALL

     SELECT 'claim', columns_name, mandatory, NULL 
     FROM mmi_mast_columns_mandatory 
     WHERE db_table_name = 'mmi_ebm_claim_data'

     UNION ALL

     SELECT 'sales', columns_name, mandatory, NULL 
     FROM mmi_mast_columns_mandatory 
     WHERE db_table_name = 'mmi_ebm_sales_data'

     UNION ALL

     SELECT 'service', columns_name, mandatory, NULL 
     FROM mmi_mast_columns_mandatory 
     WHERE db_table_name = 'mmi_ebm_service_data'

     UNION ALL

     SELECT 'addon', columns_name, mandatory, NULL 
     FROM mmi_mast_columns_mandatory 
     WHERE db_table_name = 'mmi_poladdon_data'

) AS unified_result;

    select distinct
            ecm.dealer_id AS dealerId,
            ecm.loc_code AS dealerLocCode,
            md.loc_name AS dealerLocName,
            ecm.customtype
            from mmi_excel_column_mapping ecm  
			left join mmi_dealer_location_mapping mdlm 
			on mdlm.parent_code = ecm.parent_id  and mdlm.dealer_code = ecm.dealer_id 
			left JOIN mmi_mast_dealer_location md ON
			mdlm.location_code = md.loc_code WHERE ecm.mapping_dealer_code = ecm.dealer_id   
			and ecm.parent_id = parentId;
    
 
-- ************  selected delaer template code	


SELECT DISTINCT
     ecm.mapping_dealer_code AS dealerId,
    ecm.loc_code AS dealerLocCode,
    md.loc_name AS dealerLocName,
    ecm.customtype
FROM  mmi_excel_column_mapping ecm  
LEFT JOIN mmi_dealer_location_mapping mdlm 
     ON mdlm.parent_code = ecm.parent_id  AND mdlm.dealer_code = ecm.mapping_dealer_code 
LEFT JOIN mmi_mast_dealer_location md 
    ON mdlm.location_code = md.loc_code
LEFT JOIN mmi_dealer_details dd 
    ON dd.dealer_id = ecm.dealer_id AND dd.parent_code = ecm.parent_id
WHERE 
--    ecm.mapping_dealer_code = ecm.dealer_id AND 
    ecm.parent_id = parentId
    AND ecm.dealer_id = dealerId
    -- Filter for only those with *_created_custom dynamically
    AND (
        (ecm.customtype = 'sales'   AND dd.sales_flag   = 'sales_created_custom') OR
        (ecm.customtype = 'claim'   AND dd.claim_flag   = 'claim_created_custom') OR
        (ecm.customtype = 'policy'  AND dd.policy_flag  = 'policy_created_custom') OR
        (ecm.customtype = 'service' AND dd.service_flag = 'service_created_custom') OR
        (ecm.customtype = 'addon'   AND dd.addon_flag   = 'addon_created_custom')
    );

    SET SP_STATUS = '200';
	SET MESSAGE = 'Fetching the dealer details.';
    
    End if; -- END editDealerDetails
    
    ELSEIF TYPE =  'editDealerList' THEN
    
		SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.limit')) AS UNSIGNED), 10);
        SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.offset')) AS UNSIGNED), 0);
        SET searchName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.searchName'));
        SET calculated = (offsetVal - 1) * limitVal;
        
        SET sortField = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.sortField'));
		SET sortOrder = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.sortOrder'));

		-- Set default sort field
		IF sortField IS NULL OR sortField = '' THEN
			SET sortField = 'Name';
		END IF;

		-- Set default sort order
		IF sortOrder IS NULL OR sortOrder = '' THEN
			SET sortOrder = 'asc';
		END IF;

        IF limitVal IS NULL  OR offsetVal IS NULL OR limitVal='' OR offsetVal='' THEN
            SET SP_STATUS = "400";
            SET MESSAGE = 'limit or offset cannot be empty';
        ELSE
		-- -- Edit Dealer List
			SELECT dealer_id as dealerId,
			dealer_parent_code as parentId,
			dealer_ebmcode as ebmCode,
			dealer_name as dealerName,
            mobile_no as dealerMobileNo,
			dealer_loc_name as dealerLocName,
			dealer_address as dealerAddress
			FROM getalleditdealerdetails  
		WHERE 
			LOWER(dealer_name) LIKE LOWER(CONCAT('%', searchName, '%'))
			OR LOWER(dealer_loc_name) LIKE LOWER(CONCAT('%', searchName, '%'))
			OR LOWER(dealer_id) LIKE LOWER(CONCAT('%', searchName, '%'))
			OR LOWER(dealer_address) LIKE LOWER(CONCAT('%', searchName, '%'))
            OR LOWER(dealer_ebmcode) LIKE LOWER(CONCAT('%', searchName, '%'))
            OR LOWER(mobile_no) LIKE LOWER(CONCAT('%', searchName, '%'))
			ORDER BY
					CASE WHEN sortField = 'Location' AND sortOrder = 'asc' THEN dealer_loc_name END ASC,
					CASE WHEN sortField = 'Location' AND sortOrder = 'desc' THEN dealer_loc_name END DESC,
					CASE WHEN sortField = 'Dealer Code' AND sortOrder = 'asc' THEN dealer_id END ASC,
					CASE WHEN sortField = 'Dealer Code' AND sortOrder = 'desc' THEN dealer_id END DESC,
					CASE WHEN sortField = 'Mobile No' AND sortOrder = 'asc' THEN mobile_no END ASC,
					CASE WHEN sortField = 'Mobile No' AND sortOrder = 'desc' THEN mobile_no END DESC,
					CASE WHEN sortField = 'Name' AND sortOrder = 'asc' THEN dealer_name END ASC,
					CASE WHEN sortField = 'Name' AND sortOrder = 'desc' THEN dealer_name END DESC,
					CASE WHEN sortField = 'Address' AND sortOrder = 'asc' THEN dealer_address END ASC,
					CASE WHEN sortField = 'Address' AND sortOrder = 'desc' THEN dealer_address END DESC
			LIMIT limitVal OFFSET calculated;

		-- Edit Dealer List Count
		SELECT COUNT(*) AS totalcount
			FROM getalleditdealerdetails  
		WHERE 
			LOWER(dealer_name) LIKE LOWER(CONCAT('%', searchName, '%'))
			OR LOWER(dealer_loc_name) LIKE LOWER(CONCAT('%', searchName, '%'))
			OR LOWER(dealer_id) LIKE LOWER(CONCAT('%', searchName, '%'))
			OR LOWER(dealer_address) LIKE LOWER(CONCAT('%', searchName, '%'))
            OR LOWER(dealer_ebmcode) LIKE LOWER(CONCAT('%', searchName, '%'))
            OR LOWER(mobile_no) LIKE LOWER(CONCAT('%', searchName, '%'));
    
	SET SP_STATUS = '200';
	SET MESSAGE = 'Fetching  dealer Details.';
END IF;  -- Edit Dealer List END 

ELSEIF TYPE = 'getExcelBlob' THEN

		SET parentId =   JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'));
        SET dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'));
        SET v_customType = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype'));
         SET v_mappingDealerCode = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.mapping_dealer_code'));
        
     IF  dealerId IS NULL OR dealerId = '' 
		OR v_customType IS NULL OR v_customType = '' 
		OR parentId IS NULL OR parentId = ''
        OR v_mappingDealerCode IS NULL OR v_mappingDealerCode = ''
		THEN
		SET SP_STATUS = '400';

		SET MESSAGE = CASE
		WHEN dealerId IS NULL OR dealerId = '' THEN 'dealerId is missing'
		WHEN v_customType IS NULL OR v_customType = '' THEN 'Custom Type is missing'
		WHEN parentId IS NULL OR parentId = '' THEN 'parent id is missing'
        WHEN v_mappingDealerCode IS NULL OR v_mappingDealerCode = '' THEN 'Mapping Dealer Code is missing'
		END;
 ELSE
SELECT column_mapping_excel,column_mapping_file_name
FROM mmi_excel_column_mapping
WHERE parent_id = parentId
AND customtype = v_customType  
-- AND dealer_id =  dealerId
AND mapping_dealer_code = v_mappingDealerCode
and column_mapping_excel is not null
LIMIT 1;
END IF;
  
  SET SP_STATUS = '200';
  SET MESSAGE = 'Blob fetched successfully';

ELSEIF TYPE = 'checkDealerExists' THEN

	SET v_dealerName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerName'));       
     IF  v_dealerName IS NULL OR v_dealerName = '' THEN
	
     SET SP_STATUS = '200';
     SET MESSAGE = 'Dealer name is missing';
 ELSE

SELECT distinct dealer_name as dealerName,parent_code as parentId FROM mmi_dealer_location_mapping 
WHERE dealer_name LIKE CONCAT('%', v_dealerName, '%');

SET SP_STATUS = '200';
SET MESSAGE = 'Existing Dealers fetched successfully';

END IF;


ELSEIF TYPE = 'checkLocationExists' THEN
		SET v_state = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.state'));
		SET v_parentId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'));
		SET v_dealerLocName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerLocName'));       
	IF  v_dealerLocName IS NULL OR v_dealerLocName = '' THEN
		SET SP_STATUS = '200';
		SET MESSAGE = '';
	ELSE
		/*SELECT loc_code as dealerLocCode ,loc_name as dealerLocName ,comm_address as dealerAddress,state 
		FROM mmi_mast_dealer_location WHERE loc_name LIKE CONCAT('%',v_dealerLocName , '%');*/
        
	SELECT mmd.loc_code as dealerLocCode ,mmd.loc_name as dealerLocName ,mmd.comm_address as dealerAddress,mmd.state,
	dlp.parent_code as parentId FROM mmi_mast_dealer_location mmd left join mmi_dealer_location_mapping dlp 
	on mmd.loc_code = dlp.location_code WHERE dlp.parent_code = v_parentId AND mmd.state = v_state  
	AND loc_name LIKE CONCAT('%',v_dealerLocName , '%');
        
		SET SP_STATUS = '200';
		SET MESSAGE = 'Existing Locations fetched successfully';
	END IF;
    
  ELSEIF type = 'newDealerSetUp' THEN   
	select distinct zone from mmi_dealer_location_mapping;
    select state_name as state from mmi_mast_location;
    select distinct dealer_name as dealerName from mmi_dealer_location_mapping where status =1 and is_active = 1;
    
		SET SP_STATUS = '200';
		SET MESSAGE = 'fetched successfully';

ELSEIF type = 'checkLocationDetails' THEN   
		SET v_parentId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'));
        
		select dealer_Id as dealerId,dl.loc_name as dealerLocName,dl.comm_address as dealerAddress from mmi_dealer_details mdl
		left join mmi_dealer_location_mapping dlm on mdl.dealer_id = dlm.mapping_dealer_code
		left join mmi_mast_dealer_location dl on dl.loc_code = dlm.location_code
		where dlm.status = 0 and dlm.is_active = 1 and location_status = 1 and mdl.parent_code = v_parentId;
    
		SET SP_STATUS = '200';
		SET MESSAGE = 'fetched successfully';

ELSE
	SET SP_STATUS = "400";
	SET MESSAGE = CONCAT('Invalid type: ', type);
END IF;

-- END ;
END ;;
DELIMITER ;
