CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_activatedeactive_role_by_id`(
    IN Json_data JSON,
    OUT p_status_code INT,
    OUT p_status_message VARCHAR(255)
)
BEGIN
proc_block: BEGIN

    DECLARE p_role_id VARCHAR(200);
    DECLARE p_status VARCHAR(45);
    DECLARE p_modified_by VARCHAR(45);
    DECLARE p_remark VARCHAR(255);
    DECLARE p_check_user_exist INT;

    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
            
            SET p_status_code = 500;
			SET p_status_message = 'An error occurred. Please try again.';
			ROLLBACK;
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_activatedeactive_role_by_id', 'DEACTIVATE_ROLE', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;

    SET p_role_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleId'));
    SET p_status = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleStatus'));
    SET p_modified_by = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
    SET p_remark = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.remark'));
	
    IF p_role_id IS NULL THEN
		SET p_status_code = 404;
        SET p_status_message = 'Required field cannot be null';
        ROLLBACK;
        LEAVE proc_block;
    END IF;
    
		SELECT count(urm.user_id) INTO p_check_user_exist 
		FROM mmi_mast_role r
        LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
        LEFT JOIN mmi_user_role_mapping urm on r.role_id = urm.role_id
		WHERE r.status = '1' AND m.role_id IS NOT NULL AND m.role_type_id IS NOT NULL
        and urm.role_id = p_role_id;
    
    IF p_check_user_exist > 0 THEN
		SET p_status_code = 404;
        SET p_status_message = 'Cannot Deactivate Role User Mapped to this role';
        ROLLBACK;
        LEAVE proc_block;
    END IF;
	
    START TRANSACTION;
    
    IF EXISTS (
        SELECT 1 FROM mmi_mast_role
        WHERE role_id = p_role_id
    ) THEN
        UPDATE mmi_mast_role
        SET
            status = p_status,
            -- remarks = p_remark,
            modified_by = p_modified_by,
            modified_date = NOW()
			WHERE role_id = p_role_id;

       SET p_status_code = 200;

	IF p_status = '1' THEN
		SET p_status_message = 'Role account activated successfully';
	ELSE
		SET p_status_message = 'Role account deactivated successfully';
	END IF;

        COMMIT;
    ELSE
        SET p_status_code = 404;
        SET p_status_message = 'Role not found or inactive';
        ROLLBACK;
    END IF;
    END proc_block;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
