CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_add_customer_contact_details`(
    IN p_json_data JSON,
    OUT SP_STATUS VARCHAR(500),
    OUT SP_MESSAGE VARCHAR(500)
)
BEGIN
	proc_end: BEGIN
    -- Declare local variables
    DECLARE v_type VARCHAR(50);
    DECLARE v_dealerCode VARCHAR(50);
    DECLARE v_clusterId VARCHAR(50);
    DECLARE v_customer_name VARCHAR(300);
    DECLARE v_customer_address VARCHAR(500);
    DECLARE v_customer_state VARCHAR(50);
    DECLARE v_customer_city VARCHAR(50);
    DECLARE v_customer_pincode VARCHAR(50);
    DECLARE v_vehicle_reg_no VARCHAR(50);
    DECLARE v_engine_no VARCHAR(50);
    DECLARE v_chassis_no VARCHAR(50);
    DECLARE v_color VARCHAR(50);
    DECLARE v_mobile VARCHAR(50);
    DECLARE v_email VARCHAR(50);
	DECLARE v_created_user_id VARCHAR(50);
    
    -- Error handling variables
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    -- Declare EXIT HANDLER for SQL errors
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        -- Capture the error details
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		SET SP_STATUS = '500';
        SET SP_MESSAGE = 'An error occurred. Please try again.';
        
        ROLLBACK;
        -- Insert the error details into the mmi_mast_procedure_error table
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_add_customer_contact_details', 'ADD_CUSTOMER_CONTACT', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
        
    END;

    -- Start the transaction
    START TRANSACTION;

    -- Extract data from the input JSON
    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.type'));
    SET v_dealerCode = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerCode'));
    SET v_clusterId = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.clusterId'));
    SET v_created_user_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.userId'));
    
      -- by mobile / email 
    -- SET v_mobile = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.mobile'));
    -- SET v_email = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.email'));
 /*
    IF v_clusterId IS NULL OR v_clusterId = '' THEN

		
        SELECT cluster_id
        INTO v_clusterId
        FROM mmi_mast_customer_details
        WHERE customer_phone = v_mobile
           OR customer_email = v_email
        ORDER BY created_date DESC
        LIMIT 1;

        IF v_clusterId IS NULL OR v_clusterId = '' THEN

            SET SP_STATUS = '201';
            SET SP_MESSAGE = 'Cannot Add Mobile No. Or Email New User';

            ROLLBACK;
            LEAVE proc_end;

        END IF;

    END IF;  */
    

    -- Validate input parameters
    IF v_type IS NULL OR v_type = '' OR v_dealerCode IS NULL OR v_dealerCode = '' THEN
        SET SP_STATUS = "300";
        SET SP_MESSAGE = 'DealerCode and Type cannot be empty or null';
        ROLLBACK;
        LEAVE proc_end;
    ELSE
        -- Fetch customer details based on cluster_id
        SELECT customer_name, customer_address, customer_state, customer_city, customer_pincode,
               vehicle_reg_no, engine_no, chassis_no, color
        INTO v_customer_name, v_customer_address, v_customer_state, v_customer_city, v_customer_pincode,
             v_vehicle_reg_no, v_engine_no, v_chassis_no, v_color
        FROM mmi_mast_customer_details
        WHERE cluster_id = v_clusterId
        ORDER BY created_date DESC LIMIT 1;

        -- Handle cases where customer details are not found
        IF v_customer_name IS NULL THEN
            SET SP_STATUS = "201";
            SET SP_MESSAGE = 'Customer not found for the given clusterId';
            ROLLBACK;
            LEAVE proc_end;
        END IF;

        -- Handling mobile number update
        /*IF v_type = 'mobile' THEN
            SET v_mobile = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.mobile'));

            IF v_mobile IS NULL OR v_mobile = '' THEN
                SET SP_STATUS = "300";
                SET SP_MESSAGE = 'Mobile Number cannot be empty or null';
                ROLLBACK;
                LEAVE proc_end;
            ELSE
                -- Insert the new mobile number
                INSERT INTO mmi_mast_customer_details 
                    (cluster_id, customer_name, customer_address, customer_state, customer_city, customer_pincode, 
                     vehicle_reg_no, engine_no, chassis_no, color, customer_phone)
                VALUES 
                    (v_clusterId, v_customer_name, v_customer_address, v_customer_state, v_customer_city,
                     v_customer_pincode, v_vehicle_reg_no, v_engine_no, v_chassis_no, v_color, v_mobile);
            END IF;

        -- Handling email update
        ELSEIF v_type = 'email' THEN
            SET v_email = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.email'));

            IF v_email IS NULL OR v_email = '' THEN
                SET SP_STATUS = "300";
                SET SP_MESSAGE = 'Email ID cannot be empty or null';
                ROLLBACK;
                LEAVE proc_end;
            ELSE
                -- Insert the new email address
                INSERT INTO mmi_mast_customer_details 
                    (cluster_id, customer_name, customer_address, customer_state, customer_city, customer_pincode, 
                     vehicle_reg_no, engine_no, chassis_no, color, customer_email)
                VALUES 
                    (v_clusterId, v_customer_name, v_customer_address, v_customer_state, v_customer_city,
                     v_customer_pincode, v_vehicle_reg_no, v_engine_no, v_chassis_no, v_color, v_email);
            END IF;
        END IF;*/
        
        -- Handling mobile number update
		IF v_type = 'mobile' THEN
			SET v_mobile = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.mobile'));

			IF v_mobile IS NULL OR v_mobile = '' THEN
				SET SP_STATUS = "300";
				SET SP_MESSAGE = 'Mobile Number cannot be empty or null';
				ROLLBACK;
				LEAVE proc_end;
			ELSE
				-- Check if the mobile number already exists
				IF EXISTS (
					SELECT 1 FROM mmi_mast_customer_details 
					WHERE customer_phone = v_mobile AND cluster_id = v_clusterId
				) THEN
					SET SP_STATUS = '409';
					SET SP_MESSAGE = 'Mobile number already exists';
					ROLLBACK;
					LEAVE proc_end;
				END IF;

				-- Insert the new mobile number
				INSERT INTO mmi_mast_customer_details 
					(cluster_id, customer_name, customer_address, customer_state, customer_city, customer_pincode, 
					 vehicle_reg_no, engine_no, chassis_no, color, customer_phone, created_by)
				VALUES 
					(v_clusterId, v_customer_name, v_customer_address, v_customer_state, v_customer_city,
					 v_customer_pincode, v_vehicle_reg_no, v_engine_no, v_chassis_no, v_color, v_mobile, v_created_user_id);
			END IF;

		-- Handling email update
		ELSEIF v_type = 'email' THEN
			SET v_email = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.email'));

			IF v_email IS NULL OR v_email = '' THEN
				SET SP_STATUS = "300";
				SET SP_MESSAGE = 'Email ID cannot be empty or null';
				ROLLBACK;
				LEAVE proc_end;
			ELSE
				-- Check if the email already exists
				IF EXISTS (
					SELECT 1 FROM mmi_mast_customer_details 
					WHERE customer_email = v_email AND cluster_id = v_clusterId
				) THEN
					SET SP_STATUS = '409';
					SET SP_MESSAGE = 'Email already exists';
					ROLLBACK;
					LEAVE proc_end;
				END IF;

        INSERT INTO mmi_mast_customer_details 
            (cluster_id, customer_name, customer_address, customer_state, customer_city, customer_pincode, 
             vehicle_reg_no, engine_no, chassis_no, color, customer_email, created_by)
        VALUES 
            (v_clusterId, v_customer_name, v_customer_address, v_customer_state, v_customer_city,
             v_customer_pincode, v_vehicle_reg_no, v_engine_no, v_chassis_no, v_color, v_email, v_created_user_id);
    END IF;
END IF;

			INSERT INTO mmi_insert_log_details (service_name,user_id,log_payload,
            service_type,created_by,created_date) 
            VALUES ('mmi_proc_add_customer_contact_details',v_created_user_id,
                p_json_data,'INSERT',v_created_user_id,CURRENT_TIMESTAMP(3));
                
        -- Set success status and message
        SET SP_STATUS = '200';
        SET SP_MESSAGE = 'Record Inserted Successfully';
    END IF;

    COMMIT;

    -- Exit the procedure cleanly
    END proc_end; 
END ;;
DELIMITER ;
