CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_archive_expired_leads`()
proc_end: BEGIN
    DECLARE v_interval_days INT;
    DECLARE v_rollover_archive_days INT;
    DECLARE v_archived_count INT DEFAULT 0;
    DECLARE v_deleted_count INT DEFAULT 0;
    DECLARE v_archived_rollover_count INT DEFAULT 0;
    DECLARE v_deleted_rollover_count INT DEFAULT 0;
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    -- Error handler
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_archive_expired_leads', 'ARCHIVE_EXPIRED_LEADS', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    START TRANSACTION;

    -- Get threshold for Non-Rollover leads
    SELECT CAST(services_value AS SIGNED)
    INTO v_interval_days
    FROM mmi_services_config
    WHERE services_property = 'lost_bucket_threshold_days'
    LIMIT 1;

    -- Get threshold for Rollover leads
    SELECT CAST(services_value AS SIGNED)
    INTO v_rollover_archive_days
    FROM mmi_services_config
    WHERE services_property = 'rollover_archive_threshold_days'
    LIMIT 1;

    -- Validate config values
    IF v_interval_days IS NULL OR v_interval_days <= 0 OR v_rollover_archive_days IS NULL OR v_rollover_archive_days <= 0 THEN
        ROLLBACK;
        LEAVE proc_end;
    END IF;

    -- Archive Non-Rollover Leads with last_disp_status
    INSERT INTO mmi_lead_archive_details (
        lead_id, policy_id, dealer_code, dealer, insurance_company, policy_no, policy_tenure, policy_type,
        insured_name, yom, ncb_percentage, vehicle_class, vehicle_sub_class, carrier_type, policy_effective_date,
        policy_expiry_date, make, model, vehicle_body_type, fuel_type, variant, vin, engine_no, payment_mode,
        od_discount_percentage, total_idv, addon_premium_amount, net_od_premium_amount, third_party_liability,
        pa_cover, legal_liability, net_liability, net_premium, imt_23, gross_premium, group_product, rto_display_name, previous_policy_no,
        previous_insurance_company, podc_start, podc_end, plc_start, plc_end, third_party_liability_bifuel_kit,
        trailer_imt30, imt_34tp, pa_cover_unnamed_persons_imt16, geographical_areas_extention_imt1,
        tpgeographical_areas_extention_imt1, legal_liability_nfpp_imt37, pa_cover_owner_driver, oem_code, proposal_no,
        plan_type, ebm_calls, zd, bundle_product, invoice_date, cancellation_flag, reg_no, i_date, m_date,
        cluster_id, registration_date, assigned_agent, lead_source, lead_status, lead_source_type, expiry_days, renewal_category,
        lead_type,lead_type_score, reason_for_archiving, customer_landline, customer_type, m_user, service_tax, sub_oem_name, version,
        lead_assignment_type, lead_assignment_date_time, lead_created_date, created_by, rollover_count, last_disp_status
    )
    SELECT
        ld.lead_id, ld.policy_id, ld.dealer_code, ld.dealer, ld.insurance_company, ld.policy_no, ld.policy_tenure, ld.policy_type,
        ld.insured_name, ld.yom, ld.ncb_percentage, ld.vehicle_class, ld.vehicle_sub_class, ld.carrier_type, ld.policy_effective_date,
        ld.policy_expiry_date, ld.make, ld.model, ld.vehicle_body_type, ld.fuel_type, ld.variant, ld.vin, ld.engine_no, ld.payment_mode,
        ld.od_discount_percentage, ld.total_idv, ld.addon_premium_amount, ld.net_od_premium_amount, ld.third_party_liability,
        ld.pa_cover, ld.legal_liability, ld.net_liability, ld.net_premium, ld.imt_23, ld.gross_premium, ld.group_product, ld.rto_display_name, ld.previous_policy_no,
        ld.previous_insurance_company, ld.podc_start, ld.podc_end, ld.plc_start, ld.plc_end, ld.third_party_liability_bifuel_kit,
        ld.trailer_imt30, ld.imt_34tp, ld.pa_cover_unnamed_persons_imt16, ld.geographical_areas_extention_imt1,
        ld.tpgeographical_areas_extention_imt1, ld.legal_liability_nfpp_imt37, ld.pa_cover_owner_driver, ld.oem_code, ld.proposal_no,
        ld.plan_type, ld.ebm_calls, ld.zd, ld.bundle_product, ld.invoice_date, ld.cancellation_flag, ld.reg_no, ld.i_date, ld.m_date,
        ld.cluster_id, ld.registration_date, ld.assigned_agent, ld.lead_source, 'Lost', ld.lead_source_type, ld.expiry_days,
        ld.renewal_category, ld.lead_type, ld.lead_type_score, 'Leads lost due to overdue', ld.customer_landline, ld.customer_type, ld.m_user, ld.service_tax, ld.sub_oem_name, ld.version,
        ld.lead_assignment_type, ld.lead_assignment_date_time, ld.created_date, ld.created_by, ld.rollover_count,
        cd.call_status
    FROM mmi_lead_details ld
    LEFT JOIN (
        SELECT c1.lead_id, c1.call_status
        FROM mmi_call_disposition_history c1
        JOIN (
            SELECT lead_id, MAX(created_date) AS max_date
            FROM mmi_call_disposition_history
            GROUP BY lead_id
        ) c2 ON c1.lead_id = c2.lead_id AND c1.created_date = c2.max_date
    ) cd ON ld.lead_id = cd.lead_id
    WHERE ld.expiry_days <= -v_interval_days
      AND ld.lead_source_type <> 'Rollover';

    SET v_archived_count = ROW_COUNT();

    DELETE FROM mmi_lead_details
    WHERE expiry_days <= -v_interval_days
      AND lead_source_type <> 'Rollover';

    SET v_deleted_count = ROW_COUNT();

    -- Archive Rollover Leads with last_disp_status
    INSERT INTO mmi_lead_archive_details (
        lead_id, policy_id, dealer_code, dealer, insurance_company, policy_no, policy_tenure, policy_type,
        insured_name, yom, ncb_percentage, vehicle_class, vehicle_sub_class, carrier_type, policy_effective_date,
        policy_expiry_date, make, model, vehicle_body_type, fuel_type, variant, vin, engine_no, payment_mode,
        od_discount_percentage, total_idv, addon_premium_amount, net_od_premium_amount, third_party_liability,
        pa_cover, legal_liability, net_liability, net_premium, imt_23, gross_premium, group_product, rto_display_name, previous_policy_no,
        previous_insurance_company, podc_start, podc_end, plc_start, plc_end, third_party_liability_bifuel_kit,
        trailer_imt30, imt_34tp, pa_cover_unnamed_persons_imt16, geographical_areas_extention_imt1,
        tpgeographical_areas_extention_imt1, legal_liability_nfpp_imt37, pa_cover_owner_driver, oem_code, proposal_no,
        plan_type, ebm_calls, zd, bundle_product, invoice_date, cancellation_flag, reg_no, i_date, m_date,
        cluster_id, registration_date, assigned_agent, lead_source, lead_status, lead_source_type, expiry_days, renewal_category,
        lead_type, lead_type_score, reason_for_archiving, customer_landline, customer_type, m_user, service_tax, sub_oem_name, version,
        lead_assignment_type, lead_assignment_date_time, lead_created_date, created_by, rollover_count, last_disp_status
    )
    SELECT
        ld.lead_id, ld.policy_id, ld.dealer_code, ld.dealer, ld.insurance_company, ld.policy_no, ld.policy_tenure, ld.policy_type,
        ld.insured_name, ld.yom, ld.ncb_percentage, ld.vehicle_class, ld.vehicle_sub_class, ld.carrier_type, ld.policy_effective_date,
        ld.policy_expiry_date, ld.make, ld.model, ld.vehicle_body_type, ld.fuel_type, ld.variant, ld.vin, ld.engine_no, ld.payment_mode,
        ld.od_discount_percentage, ld.total_idv, ld.addon_premium_amount, ld.net_od_premium_amount, ld.third_party_liability,
        ld.pa_cover, ld.legal_liability, ld.net_liability, ld.net_premium, ld.imt_23, ld.gross_premium, ld.group_product, ld.rto_display_name, ld.previous_policy_no,
        ld.previous_insurance_company, ld.podc_start, ld.podc_end, ld.plc_start, ld.plc_end, ld.third_party_liability_bifuel_kit,
        ld.trailer_imt30, ld.imt_34tp, ld.pa_cover_unnamed_persons_imt16, ld.geographical_areas_extention_imt1,
        ld.tpgeographical_areas_extention_imt1, ld.legal_liability_nfpp_imt37, ld.pa_cover_owner_driver, ld.oem_code, ld.proposal_no,
        ld.plan_type, ld.ebm_calls, ld.zd, ld.bundle_product, ld.invoice_date, ld.cancellation_flag, ld.reg_no, ld.i_date, ld.m_date,
        ld.cluster_id, ld.registration_date, ld.assigned_agent, ld.lead_source, 'Lost', ld.lead_source_type, ld.expiry_days,
        ld.renewal_category, ld.lead_type, ld.lead_type_score, 'Rollover leads lost due to overdue', ld.customer_landline, ld.customer_type, ld.m_user, ld.service_tax, ld.sub_oem_name, ld.version,
        ld.lead_assignment_type, ld.lead_assignment_date_time, ld.created_date, ld.created_by, ld.rollover_count,
        cd.call_status
    FROM mmi_lead_details ld
    LEFT JOIN (
        SELECT c1.lead_id, c1.call_status
        FROM mmi_call_disposition_history c1
        JOIN (
            SELECT lead_id, MAX(created_date) AS max_date
            FROM mmi_call_disposition_history
            GROUP BY lead_id
        ) c2 ON c1.lead_id = c2.lead_id AND c1.created_date = c2.max_date
    ) cd ON ld.lead_id = cd.lead_id
    WHERE ld.lead_source_type = 'Rollover'
      AND DATEDIFF(CURDATE(), ld.created_date) >= v_rollover_archive_days;

    SET v_archived_rollover_count = ROW_COUNT();

    DELETE FROM mmi_lead_details
    WHERE lead_source_type = 'Rollover'
      AND DATEDIFF(CURDATE(), created_date) >= v_rollover_archive_days;

    SET v_deleted_rollover_count = ROW_COUNT();

    COMMIT;

    -- Log procedure execution
    INSERT INTO mmi_mast_procedure_error (
        error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
    ) VALUES (
        0, CONCAT('Non-Rollover Archived: ', v_archived_count, ', Deleted: ', v_deleted_count,
                 '; Rollover Archived: ', v_archived_rollover_count, ', Deleted: ', v_deleted_rollover_count),
        'mmi_proc_archive_expired_leads', 'ARCHIVE_EXPIRED_LEADS', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
    );

END ;;
DELIMITER ;
