CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_archive_won_leads`()
proc_end: BEGIN
    DECLARE err_code INT;
    DECLARE err_msg TEXT;
    DECLARE v_updated_count INT DEFAULT 0;
    DECLARE v_inserted_count INT DEFAULT 0;
    DECLARE v_deleted_count INT DEFAULT 0;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_archive_won_leads', 'ARCHIVING_WON_LEAD', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    START TRANSACTION;

    -- Update lead_status to 'Won' for matching records
    UPDATE mmi_lead_details l
    JOIN mmi_ebm_policy_data p ON l.policy_no = p.previous_policy_no
    SET l.lead_status = 'Won'
    WHERE l.policy_expiry_date <> DATE(p.policy_expiry_date)
      AND p.policy_expiry_date IS NOT NULL;

    SET v_updated_count = ROW_COUNT();

    -- Insert the updated 'Won' leads into archive table with latest disposition status
    INSERT INTO mmi_lead_archive_details (
        lead_id, policy_id, dealer_code, dealer, insurance_company, policy_no, policy_tenure, policy_type,
        insured_name, yom, ncb_percentage, vehicle_class, vehicle_sub_class, carrier_type, policy_effective_date,
        policy_expiry_date, make, model, vehicle_body_type, fuel_type, variant, vin, engine_no, payment_mode,
        od_discount_percentage, total_idv, addon_premium_amount, net_od_premium_amount, third_party_liability,
        pa_cover, legal_liability, net_liability, net_premium, imt_23, gross_premium, group_product, rto_display_name, previous_policy_no,
        previous_insurance_company, podc_start, podc_end, plc_start, plc_end, third_party_liability_bifuel_kit,
        trailer_imt30, imt_34tp, pa_cover_unnamed_persons_imt16, geographical_areas_extention_imt1,
        tpgeographical_areas_extention_imt1, legal_liability_nfpp_imt37, pa_cover_owner_driver, oem_code, proposal_no,
        plan_type, ebm_calls, zd, bundle_product, invoice_date, cancellation_flag, reg_no, i_date, m_date,
        cluster_id, registration_date, assigned_agent, lead_source, lead_status, expiry_days, renewal_category, lead_type,
        lead_type_score, lead_source_type, reason_for_archiving,
        customer_landline, customer_type, m_user, service_tax, sub_oem_name, version,
        lead_assignment_type, lead_assignment_date_time, lead_created_date, created_by, rollover_count, last_disp_status, converted_flag
    )
    SELECT
        l.lead_id, l.policy_id, l.dealer_code, l.dealer, l.insurance_company, l.policy_no, l.policy_tenure, l.policy_type,
        l.insured_name, l.yom, l.ncb_percentage, l.vehicle_class, l.vehicle_sub_class, l.carrier_type, l.policy_effective_date,
        l.policy_expiry_date, l.make, l.model, l.vehicle_body_type, l.fuel_type, l.variant, l.vin, l.engine_no, l.payment_mode,
        l.od_discount_percentage, l.total_idv, l.addon_premium_amount, l.net_od_premium_amount, l.third_party_liability,
        l.pa_cover, l.legal_liability, l.net_liability, l.net_premium, l.imt_23, l.gross_premium, l.group_product, l.rto_display_name, l.previous_policy_no,
        l.previous_insurance_company, l.podc_start, l.podc_end, l.plc_start, l.plc_end, l.third_party_liability_bifuel_kit,
        l.trailer_imt30, l.imt_34tp, l.pa_cover_unnamed_persons_imt16, l.geographical_areas_extention_imt1,
        l.tpgeographical_areas_extention_imt1, l.legal_liability_nfpp_imt37, l.pa_cover_owner_driver, l.oem_code, l.proposal_no,
        l.plan_type, l.ebm_calls, l.zd, l.bundle_product, l.invoice_date, l.cancellation_flag, l.reg_no, l.i_date, l.m_date,
        l.cluster_id, l.registration_date, l.assigned_agent, l.lead_source, l.lead_status, l.expiry_days, l.renewal_category, l.lead_type,
        l.lead_type_score, l.lead_source_type, 'Lead Won',
        l.customer_landline, l.customer_type, l.m_user, l.service_tax, l.sub_oem_name, l.version,
        l.lead_assignment_type, l.lead_assignment_date_time, l.created_date, l.created_by, l.rollover_count,
		MAX(cd.call_status) AS call_status, -- cd.call_status
           CASE 
             WHEN MAX(cd.call_status) IS NOT NULL AND MAX(cd.call_status) <> '' THEN 'CRM Renewal'
             ELSE 'Direct Renewal'
         END AS converted_flag
    FROM mmi_lead_details l
    JOIN mmi_ebm_policy_data p ON l.policy_no = p.previous_policy_no
    LEFT JOIN (
        SELECT c1.lead_id, c1.call_status
        FROM mmi_call_disposition_history c1
        JOIN (
            SELECT lead_id, MAX(created_date) AS max_date
            FROM mmi_call_disposition_history
            GROUP BY lead_id
        ) c2 ON c1.lead_id = c2.lead_id AND c1.created_date = c2.max_date
    ) cd ON l.lead_id = cd.lead_id
    WHERE l.policy_expiry_date <> DATE(p.policy_expiry_date)
      AND p.policy_expiry_date IS NOT NULL
      AND l.lead_status = 'Won'
    GROUP BY l.lead_id, cd.call_status;

    SET v_inserted_count = ROW_COUNT();

    -- Delete archived rows from lead details
    DELETE l
    FROM mmi_lead_details l
    JOIN mmi_ebm_policy_data p ON l.policy_no = p.previous_policy_no
    WHERE l.policy_expiry_date <> DATE(p.policy_expiry_date)
      AND p.policy_expiry_date IS NOT NULL
      AND l.lead_status = 'Won';

    SET v_deleted_count = ROW_COUNT();

    COMMIT;

    -- Log the counts
    INSERT INTO mmi_mast_procedure_error (
        error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
    ) VALUES (
        0, CONCAT('Updated: ', v_updated_count, ', Inserted: ', v_inserted_count, ', Deleted: ', v_deleted_count),
        'mmi_proc_archive_won_leads', 'ARCHIVING_WON_LEAD', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
    );
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_assign_leads` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_assign_leads`()
BEGIN
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_assign_leads', 'ASSIGN_LEADS', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    START TRANSACTION;


    DELETE FROM mmi_lead_assignment_staging;


    DROP TEMPORARY TABLE IF EXISTS tmp_deduped_leads;
    CREATE TEMPORARY TABLE tmp_deduped_leads AS
    SELECT DISTINCT lead_id, bucket_id
    FROM mmi_vw_get_leads_with_bucket
    WHERE bucket_id IS NOT NULL;


    DROP TEMPORARY TABLE IF EXISTS tmp_bucket_users;
    CREATE TEMPORARY TABLE tmp_bucket_users AS
    SELECT
        bucket_id,
        user_id,
        ROW_NUMBER() OVER (
            PARTITION BY bucket_id
            ORDER BY assigned_lead_count ASC, user_id
        ) AS user_rn
    FROM (
        SELECT
            mbum.bucket_id,
            mbum.user_id,
            COALESCE(ld.assigned_count, 0) AS assigned_lead_count
        FROM mmi_bucket_user_mapping mbum
        LEFT JOIN (
            SELECT
                assigned_agent AS user_id,
                COUNT(*) AS assigned_count
            FROM mmi_lead_details
            WHERE assigned_agent IS NOT NULL
            GROUP BY assigned_agent
        ) ld ON mbum.user_id = ld.user_id
    ) AS sorted_users;


    DROP TEMPORARY TABLE IF EXISTS tmp_user_counts;
    CREATE TEMPORARY TABLE tmp_user_counts AS
    SELECT bucket_id, COUNT(*) AS total_users
    FROM tmp_bucket_users
    GROUP BY bucket_id;


    INSERT INTO mmi_lead_assignment_staging (lead_id, user_id, bucket_id)
    SELECT
        dl.lead_id,
        bu.user_id,
        dl.bucket_id
    FROM (
        SELECT lead_id, bucket_id,
               ROW_NUMBER() OVER (PARTITION BY bucket_id ORDER BY lead_id) AS lead_rn
        FROM tmp_deduped_leads
    ) dl
    JOIN tmp_user_counts uc ON dl.bucket_id = uc.bucket_id
    JOIN tmp_bucket_users bu ON dl.bucket_id = bu.bucket_id
    WHERE uc.total_users > 0
      AND ((dl.lead_rn - 1) % uc.total_users + 1) = bu.user_rn;


    INSERT INTO mmi_lead_assignment_staging (lead_id, user_id, bucket_id)
    SELECT
        dl.lead_id,
        MIN(bu.user_id),
        dl.bucket_id
    FROM tmp_deduped_leads dl
    LEFT JOIN mmi_lead_assignment_staging ta ON ta.lead_id = dl.lead_id
    JOIN tmp_bucket_users bu ON dl.bucket_id = bu.bucket_id
    WHERE ta.lead_id IS NULL
    GROUP BY dl.lead_id, dl.bucket_id;


    UPDATE mmi_lead_details ld
    JOIN mmi_lead_assignment_staging assign ON ld.lead_id = assign.lead_id
    SET ld.assigned_agent = assign.user_id,
      ld.lead_assignment_type = 'AUTO',
    ld.lead_assignment_date_time = NOW();


    DROP TEMPORARY TABLE IF EXISTS tmp_deduped_leads;
    DROP TEMPORARY TABLE IF EXISTS tmp_bucket_users;
    DROP TEMPORARY TABLE IF EXISTS tmp_user_counts;

    COMMIT;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_assign_reassign_lead_details` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_assign_reassign_lead_details`(
IN Json_data JSON,
IN type VARCHAR(45),
OUT SP_STATUS VARCHAR(500),
OUT MESSAGE VARCHAR(500)
)
proc_main: BEGIN

    DECLARE limitVal INT DEFAULT 10;   
    DECLARE offsetVal INT DEFAULT 0; 
    DECLARE calculated INT DEFAULT 0;
    DECLARE flagVal VARCHAR(50);
    DECLARE leadIndex INT DEFAULT 0; 
    DECLARE leadCount INT DEFAULT 0;
    DECLARE agentIdVal INT DEFAULT 0;
    DECLARE leadIdVal INT;
    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;
    DECLARE totalUpdates INT DEFAULT 0;
    DECLARE old_upload_data JSON;
    DECLARE new_upload_data JSON;
    DECLARE dealerId VARCHAR(45);
    DECLARE parentId VARCHAR(45);
    DECLARE userId VARCHAR(45);




    DECLARE EXIT HANDLER FOR SQLEXCEPTION
        BEGIN

            GET DIAGNOSTICS CONDITION 1
            @sqlstate = RETURNED_SQLSTATE,errno = MYSQL_ERRNO,errmsg = MESSAGE_TEXT;
            SET SP_STATUS = 407;
            SET MESSAGE = 'Something went wrong.';

            ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (error_code, error_message, procedure_name,procedure_type,ERROR_TIMING,created_by,created_date)
        VALUES (errno, CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg), 'mmi_proc_assign_reassign_lead_details', type ,CURRENT_TIMESTAMP(),'SYSTEM',NOW());

    END;

    IF type IS NULL OR TRIM(type) = '' THEN
            SET SP_STATUS = '400';
            SET MESSAGE = 'Type not provided or empty.';
            LEAVE proc_main;
    END IF;

    -- Extract pagination and flag safely
    SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.limit')) AS UNSIGNED), 10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.offset')) AS UNSIGNED), 0);
    SET calculated = (offsetVal - 1) * limitVal;
    IF calculated < 0 THEN
    SET calculated = 0; 
    END IF;

    SET flagVal = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.flag'));

    IF flagVal = '' THEN
    SET SP_STATUS = '400';
    SET MESSAGE = 'Flag not provided or empty.';
    LEAVE proc_main;
    END IF;


    IF type = 'leadList' THEN

    SET dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
    SET userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));

    IF dealerId IS NULL OR dealerId = ''
        OR userId IS NULL OR userId = ''
        THEN
        SET SP_STATUS = '400';
        SET MESSAGE = CONCAT(
        CASE
        WHEN dealerId IS NULL OR dealerId = '' THEN 'dealerId is missing'
        WHEN userId IS NULL OR userId = '' THEN 'userId is missing'
        END
        );
ELSE
        -- counts: assigned, unassigned, myLeads
        -- Unassigned Leads
        -- SELECT (SELECT COUNT(ml.lead_id) FROM mmi_lead_details  ml
        -- WHERE ml.dealer_code = dealerId AND ml.assigned_agent IS NULL) AS unassignedCount,
        
        SELECT (SELECT COUNT(DISTINCT ml.lead_id) FROM mmi_lead_details  ml
        left join mmi_mast_customer_details mc on ml.vin = mc.chassis_no and ml.engine_no = mc.engine_no-- on ml.cluster_id = mc.cluster_id
		left join mmi_dealer_location_mapping dlm on ml.dealer_code = dlm.dealer_code
        WHERE dlm.mapping_dealer_code  = dealerId AND ml.assigned_agent IS NULL) AS unassignedCount,

        -- Leads assigned to subordinates (using recursive CTE)
        (
        SELECT COUNT(DISTINCT ml.lead_id) FROM mmi_lead_details ml
        INNER JOIN (
        WITH RECURSIVE subordinates AS (
        SELECT ur.user_id FROM mmi_user_reporting ur where ur.supervisor_id = userId

        UNION ALL

        SELECT ur.user_id FROM mmi_user_reporting ur
        INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
        )
        SELECT * FROM subordinates
        ) AS s ON ml.assigned_agent = s.user_id
        LEFT JOIN mmi_user_dealer_mapping udm on s.user_id = udm.user_id and udm.dealer_id = ml.dealer_code
        LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = udm.dealer_id
        left join mmi_dealer_location_mapping dlm on ml.dealer_code = dlm.dealer_code
        AND udm.user_id = ml.assigned_agent
        WHERE dlm.mapping_dealer_code =  dealerId
        AND ml.assigned_agent IS NOT NULL
        AND ml.assigned_agent <> userId
        ) AS assignedCount,

        -- My Leads
        (
        /*SELECT COUNT(ml.lead_id)
        FROM mmi_lead_details ml
        LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = ml.dealer_code
        WHERE ml.dealer_code = dealerId
        AND ml.assigned_agent =  userId
        AND ml.assigned_agent IS NOT NULL*/
        SELECT COUNT(DISTINCT ml.lead_id)
        FROM mmi_mast_customer_details mc
        LEFT JOIN mmi_lead_details ml on ml.vin = mc.chassis_no and ml.engine_no = mc.engine_no-- ON mc.cluster_id = ml.cluster_id
        LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent
        LEFT JOIN mmi_user_dealer_mapping udm on ml.assigned_agent = udm.user_id and udm.dealer_id = ml.dealer_code
        LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = udm.dealer_id
        left join mmi_dealer_location_mapping dlm on ml.dealer_code = dlm.dealer_code
        WHERE
        dlm.mapping_dealer_code = dealerId
        AND urd.id  = userId
        ORDER BY ml.policy_expiry_date
        ) AS myLeadCount,
		
        
        (
        select count(DISTINCT lad.lead_id) as leadId
		from mmi_lead_archive_details lad
		LEFT JOIN mmi_mast_customer_details mcd on lad.vin = mcd.chassis_no and lad.engine_no = mcd.engine_no-- on lad.cluster_id=mcd.cluster_id
		LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = lad.assigned_agent
		LEFT JOIN mmi_user_dealer_mapping udm on lad.assigned_agent = udm.user_id and udm.dealer_id = lad.dealer_code
		LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = udm.dealer_id
        left join mmi_dealer_location_mapping dlm on lad.dealer_code = dlm.dealer_code
        WHERE dlm.mapping_dealer_code = dealerId and lad.lead_status = 'Lost'
        ) AS lostLeadCount;
        -- Master Renewel List
        select renewal_year as renewalCategory from mmi_mast_renewal_category where status =1;


    -- *****************  Assign to Agent Master Lit Fetching ***************
    IF flagVal = 'assigned' || flagVal = 'unassigned' THEN

        (select DISTINCT CONCAT(urd.first_name, ' ', urd.last_name) AS agentName,
        urd.id AS agentId from mmi_mast_user_registration_detail urd
        left join mmi_user_dealer_mapping urm on urd.id = urm.user_id 
        LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = urm.dealer_id
        LEFT JOIN mmi_mast_user mu on urd.id = mu.user_id
        left join mmi_dealer_location_mapping dlm on mdl.dealer_id = dlm.dealer_code
		Where mu.calling_flag = 'Y' and dlm.mapping_dealer_code =dealerId and urd.id=userId)

            union all

           (WITH RECURSIVE subordinates AS
            (
            SELECT ur.user_id
            FROM mmi_user_reporting ur where ur.supervisor_id = userId
            UNION ALL
            SELECT ur.user_id
            FROM mmi_user_reporting ur
            INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
            )

            SELECT DISTINCT

            CONCAT(urd.first_name, ' ', urd.last_name) AS agentName,
            urd.id AS agentId
            FROM subordinates s
            LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = s.user_id
            LEFT JOIN mmi_user_dealer_mapping urm on s.user_id = urm.user_id
            LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = urm.dealer_id
			LEFT JOIN mmi_mast_user mu on urd.id = mu.user_id
            left join mmi_dealer_location_mapping dlm on mdl.dealer_id = dlm.dealer_code
			Where mu.calling_flag = 'Y' and urd.id is not null AND dlm.mapping_dealer_code = dealerId)
            ;

    ELSEIF flagVal = 'myLeads' THEN

            WITH RECURSIVE subordinates AS
            (
            SELECT ur.user_id
            FROM mmi_user_reporting ur where ur.supervisor_id = userId
            UNION ALL
            SELECT ur.user_id
            FROM mmi_user_reporting ur
            INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
            )

            SELECT DISTINCT

            CONCAT(urd.first_name, ' ', urd.last_name) AS agentName,
            urd.id AS agentId
            FROM subordinates s
            LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = s.user_id
            LEFT JOIN mmi_user_dealer_mapping urm on s.user_id = urm.user_id
            LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = urm.dealer_id
            LEFT JOIN mmi_mast_user mu on urd.id = mu.user_id
            left join mmi_dealer_location_mapping dlm on mdl.dealer_id = dlm.dealer_code
			Where mu.calling_flag = 'Y' and urd.id is not null AND dlm.mapping_dealer_code = dealerId
            and urd.id <> userId
            ;
            
	ELSEIF flagVal = 'lostLeads' THEN
		select DISTINCT mcd.customer_name as customerName,
		lad.lead_id as leadId,lad.model,
		lad.renewal_category as renewalCategory,
		DATE_FORMAT(lad.policy_expiry_date, '%d %b %Y') AS policy_expiry_date,
        mcd.cluster_id as customerId,
        lad.lead_type as leadType
		from mmi_lead_archive_details lad
		LEFT JOIN mmi_mast_customer_details mcd on lad.vin = mcd.chassis_no and lad.engine_no = mcd.engine_no-- on lad.cluster_id=mcd.cluster_id
		LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = lad.assigned_agent
		LEFT JOIN mmi_user_dealer_mapping udm on lad.assigned_agent = udm.user_id and udm.dealer_id = lad.dealer_code
		LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = udm.dealer_id
        left join mmi_dealer_location_mapping dlm on lad.dealer_code = dlm.dealer_code
        WHERE dlm.mapping_dealer_code = dealerId and lad.lead_status = 'Lost'
		order BY FIELD(leadType ,'Hot', 'Warm', 'Cold');
        
   END IF; -- END Lead List


   IF flagVal = 'assigned' THEN

            WITH RECURSIVE subordinates AS
            (
            SELECT ur.user_id FROM mmi_user_reporting ur where ur.supervisor_id = userId
            UNION ALL
            SELECT ur.user_id FROM mmi_user_reporting ur
            INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
            )
            SELECT DISTINCT
            mc.customer_name as customerName,
            ml.lead_id as leadId,
            ml.model,
            CONCAT(urd.first_name, ' ', urd.last_name) AS agentName,
            ml.renewal_category as renewalCategory,
            DATE_FORMAT(ml.policy_expiry_date, '%d %b %Y') AS policy_expiry_date,
            ml.expiry_days as expiry_days,
