ELSEIF type = 'assignLeads' THEN

    SET leadCount = JSON_LENGTH(JSON_EXTRACT(Json_data, '$.leadIds'));
    SET agentIdVal = CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.agentId')) AS UNSIGNED);
    SET dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
    SET userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));

    IF dealerId IS NULL OR dealerId = ''
        OR userId IS NULL OR userId = ''
        OR agentIdVal IS NULL OR agentIdVal = ''
        OR leadCount = 0
    THEN
        SET SP_STATUS = '400';
        SET MESSAGE = CONCAT(
            CASE
                WHEN dealerId IS NULL OR dealerId = '' THEN 'dealerId is missing'
                WHEN userId IS NULL OR userId = '' THEN 'userId is missing'
                WHEN agentIdVal IS NULL OR agentIdVal = '' THEN 'agentId is missing'
                WHEN leadCount IS NULL OR leadCount = 0 THEN 'Lead IDs are missing'
            END
        );
    ELSE
        START TRANSACTION;

        -- Get old upload data
        SELECT JSON_ARRAYAGG(
