        -- Update leads in one query using the JSON array
        /*UPDATE mmi_lead_details
        SET assigned_agent = agentIdVal,
            modified_by = userId,
            modified_date = NOW()
        WHERE dealer_code = dealerId
          AND lead_id IN (
