		  FROM (SELECT 0 AS n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL 
				SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9) n
		  WHERE n.n < JSON_LENGTH(JSON_EXTRACT(Json_data, '$.leadIds'))
	  );


        -- Get total updates
        SET totalUpdates = ROW_COUNT();

        -- Get new upload data
        SELECT JSON_ARRAYAGG(
