ELSEIF type = 'leadFilterData' THEN

    SET dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
    SET userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));

    IF dealerId IS NULL OR dealerId = ''
        OR userId IS NULL OR userId = ''
        THEN
        SET SP_STATUS = '400';
        SET MESSAGE = CONCAT(
        CASE
        WHEN dealerId IS NULL OR dealerId = '' THEN 'dealerId is missing'
        WHEN userId IS NULL OR userId = '' THEN 'userId is missing'
        END
        );
ELSE

    IF flagVal = 'assigned' THEN

                WITH RECURSIVE subordinates AS
                (
                SELECT ur.user_id
                FROM mmi_user_reporting ur where ur.supervisor_id = userId

                UNION ALL

                SELECT ur.user_id
                FROM mmi_user_reporting ur
                INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
                )

                SELECT *
                FROM (
                SELECT DISTINCT
                mc.customer_name as customerName,
                ml.lead_id as leadId,
                ml.model,
                CONCAT(urd.first_name, ' ', urd.last_name) AS agentName,
                ml.renewal_category as renewalCategory,
                 DATE_FORMAT(ml.policy_expiry_date, '%d %b %Y') AS policy_expiry_date,
                ml.expiry_days,
                urd.id AS agentId,
                ml.lead_type as leadType
                FROM mmi_lead_details ml
                INNER JOIN subordinates s ON ml.assigned_agent = s.user_id
				LEFT JOIN LATERAL (
						SELECT cluster_id, MIN(customer_name) AS customer_name, MIN(vehicle_reg_no) AS vehicle_reg_no
						FROM mmi_mast_customer_details cd WHERE ml.vin = cd.chassis_no and ml.engine_no = cd.engine_no-- cd.cluster_id = ml.cluster_id
						GROUP BY cluster_id LIMIT 1
				) mc ON TRUE
				-- LEFT JOIN mmi_mast_customer_details mc ON mc.cluster_id = ml.cluster_id
                LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent
                LEFT JOIN mmi_user_dealer_mapping udm on s.user_id = udm.user_id and udm.dealer_id = ml.dealer_code
                LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = udm.dealer_id
                left join mmi_dealer_location_mapping dlm on ml.dealer_code = dlm.dealer_code
                WHERE
                dlm.mapping_dealer_code = dealerId
                and ml.assigned_agent <> userId
                -- Agent Id (multiple values)
                AND (
                JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.agentId'))  IS NULL
                OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.agentId'))  = ''
                OR FIND_IN_SET(CAST(ml.assigned_agent AS CHAR), JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.agentId')))
                )

                -- Renewal Category (multiple values)
                AND (
                JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalCategory')) IS NULL
                OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalCategory')) = ''
                OR FIND_IN_SET(TRIM(ml.renewal_category), TRIM(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalCategory'))))
                )

                -- Expiry Days
                AND (
                JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.expiry_days'))  IS NULL
                OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.expiry_days'))  = ''
                OR ml.expiry_days <= CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.expiry_days')) AS UNSIGNED)

                )
                ) AS filtered_data
                order BY FIELD(leadType ,'Hot', 'Warm', 'Cold')
                LIMIT limitVal OFFSET calculated;


                -- Assign Filter List Count *********************************

                WITH RECURSIVE subordinates AS
                (
                SELECT ur.user_id
                FROM mmi_user_reporting ur where ur.supervisor_id = userId

                UNION ALL

                SELECT ur.user_id
                FROM mmi_user_reporting ur
                INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
                )

                SELECT *
                FROM (
                SELECT DISTINCT COUNT(DISTINCT ml.lead_id) AS listCount
                FROM mmi_lead_details ml
                INNER JOIN subordinates s ON ml.assigned_agent = s.user_id
                -- LEFT JOIN mmi_mast_customer_details mc ON mc.cluster_id = ml.cluster_id
				LEFT JOIN LATERAL (
						SELECT cluster_id, MIN(customer_name) AS customer_name, MIN(vehicle_reg_no) AS vehicle_reg_no
						FROM mmi_mast_customer_details cd WHERE ml.vin = cd.chassis_no and ml.engine_no = cd.engine_no-- cd.cluster_id = ml.cluster_id
						GROUP BY cluster_id LIMIT 1
				) mc ON TRUE
				LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent
                LEFT JOIN mmi_user_dealer_mapping udm on s.user_id = udm.user_id and udm.dealer_id = ml.dealer_code
                LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = udm.dealer_id
                left join mmi_dealer_location_mapping dlm on ml.dealer_code = dlm.dealer_code
                WHERE
                dlm.mapping_dealer_code = dealerId
                and ml.assigned_agent <> userId

                -- Agent Id (multiple values)
                AND (
                JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.agentId'))  IS NULL
                OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.agentId'))  = ''
                OR FIND_IN_SET(CAST(ml.assigned_agent AS CHAR), JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.agentId')))
                )

                -- Renewal Category (multiple values)
                AND (
                JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalCategory')) IS NULL
                OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalCategory')) = ''
                OR FIND_IN_SET(TRIM(ml.renewal_category), TRIM(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalCategory'))))
                )

                -- Expiry Days
                AND (
                JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.expiry_days'))  IS NULL
                OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.expiry_days'))  = ''
                OR ml.expiry_days <= CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.expiry_days')) AS UNSIGNED)
                )
                ) AS filtered_data;

                ELSEIF flagVal = 'myLeads' THEN

                SELECT DISTINCT
                mc.customer_name as customerName,
                ml.lead_id as leadId,
                ml.model,
                -- CONCAT(urd.first_name, ' ', urd.last_name) AS agentName,
                ml.renewal_category as renewalCategory,
                 DATE_FORMAT(ml.policy_expiry_date, '%d %b %Y') AS policy_expiry_date,
                ml.expiry_days,
                urd.id AS agentId,
				ml.lead_type as leadType
                -- FROM mmi_mast_customer_details mc
                -- LEFT JOIN mmi_lead_details ml ON mc.cluster_id = ml.cluster_id
				FROM mmi_lead_details ml
				LEFT JOIN LATERAL (
						SELECT cluster_id, MIN(customer_name) AS customer_name, MIN(vehicle_reg_no) AS vehicle_reg_no,
                        MIN(customer_phone) AS customer_phone,MIN(chassis_no) AS chassis_no
						FROM mmi_mast_customer_details cd WHERE ml.vin = cd.chassis_no and ml.engine_no = cd.engine_no-- cd.cluster_id = ml.cluster_id
						GROUP BY cluster_id LIMIT 1
				) mc ON TRUE
                LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent
                LEFT JOIN mmi_user_dealer_mapping udm on ml.assigned_agent = udm.user_id and udm.dealer_id = ml.dealer_code
                LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = udm.dealer_id
                left join mmi_dealer_location_mapping dlm on ml.dealer_code = dlm.dealer_code
                WHERE
                dlm.mapping_dealer_code =  dealerId
                AND urd.id  =  userId
                -- Dealer Code
                AND (
                JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode')) IS NULL
