ELSEIF type = 'validateassignLeads' THEN
BEGIN
    -- Create a temporary table for validation results
    CREATE TEMPORARY TABLE IF NOT EXISTS temp_validation_result (
        leadId VARCHAR(20),
        agentId VARCHAR(20),
        message VARCHAR(500)
    );

    -- Use JSON_TABLE to parse the input array into rows
    INSERT INTO temp_validation_result (leadId, agentId, message)
    SELECT 
        jt.leadId,
        jt.agentId,
        TRIM(BOTH ', ' FROM CONCAT(
            -- Validate Lead ID and Dealer Code
            CASE
                WHEN jt.leadId IS NULL THEN 'Lead ID is NULL'
                WHEN jt.leadId = '' THEN 'Lead ID is EMPTY'
                WHEN jt.leadId = '0' THEN 'Lead ID is Zero'
                WHEN NOT EXISTS (
                    SELECT 1 
                    FROM mmi_lead_details mld
                    left join mmi_dealer_location_mapping dlm on mld.dealer_code = dlm.dealer_code
                    WHERE mld.lead_id = CAST(jt.leadId AS UNSIGNED)
                      AND dlm.mapping_dealer_code = jt.dealerCode  -- Make sure lead's dealer code matches
                ) THEN CONCAT('Lead ID ', jt.leadId, ' does not exist or does not belong to dealer ', jt.dealerCode, '.')
                ELSE ''
            END,
            -- Validate Agent ID
            CASE
                WHEN jt.agentId IS NULL THEN ', Agent ID is NULL'
                WHEN jt.agentId = '' THEN ', Agent ID is EMPTY'
                WHEN jt.agentId = '0' THEN ', Agent ID is ZERO'
                WHEN NOT EXISTS (
                    SELECT 1 
                    FROM mmi_mast_user_registration_detail mur
                    WHERE mur.id = CAST(jt.agentId AS UNSIGNED)
                ) THEN CONCAT(', Agent ID ', jt.agentId, ' does not exist.')
                ELSE ''
            END,
            -- Validate if Lead's Dealer Code matches the Agent's Dealer Code
            CASE
				WHEN jt.agentId IS NULL THEN ''
                WHEN jt.agentId = '' THEN ''
                WHEN jt.agentId = '0' THEN ''
                WHEN NOT EXISTS (
                    SELECT 1 
                    -- FROM mmi_mast_user_registration_detail mur
                    FROM mmi_user_dealer_mapping udm
                    JOIN mmi_dealer_details mdi ON udm.dealer_id = mdi.dealer_id
                    left join mmi_dealer_location_mapping dlm on dlm.dealer_code =  mdi.dealer_id
                    WHERE udm.user_id = CAST(jt.agentId AS UNSIGNED)
                      AND dlm.mapping_dealer_code != jt.dealerCode
                ) THEN CONCAT(', Agent ID ', jt.agentId, ' does not belong to the same dealer as the lead.')
                ELSE ''
            END
        ))
    FROM JSON_TABLE(
        Json_data,
        '$[*]' COLUMNS (
            leadId VARCHAR(20) PATH '$.leadId',
            agentId VARCHAR(20) PATH '$.agentId',
            dealerCode VARCHAR(100) PATH '$.dealerCode'
        )
    ) AS jt
    -- Only insert rows with actual validation errors
    WHERE 
        jt.leadId IS NULL OR jt.leadId = '' OR jt.leadId = '0'
        OR NOT EXISTS (
            SELECT 1 
            FROM mmi_lead_details mld
            left join mmi_dealer_location_mapping dlm on mld.dealer_code = dlm.dealer_code
            WHERE mld.lead_id = CAST(jt.leadId AS UNSIGNED)
              AND dlm.mapping_dealer_code = jt.dealerCode
        )
        OR jt.agentId IS NULL OR jt.agentId = '' OR jt.agentId = '0'
        OR NOT EXISTS (
            SELECT 1 
            FROM mmi_mast_user_registration_detail mur
            WHERE mur.id = CAST(jt.agentId AS UNSIGNED)
        );

    -- Return validation errors
    SELECT * FROM temp_validation_result;

    DROP TEMPORARY TABLE IF EXISTS temp_validation_result;

    SET SP_STATUS = '200';
    SET MESSAGE = 'Excel data fetched and validated successfully.';
END;

