BEGIN
  DECLARE userId VARCHAR(50);
  DECLARE validCount INT;

  SET userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$[0].userId'));

  START TRANSACTION;

  -- Extract valid assignments from JSON
  /*CREATE TEMPORARY TABLE temp_valid_assignment AS
  SELECT
    CAST(jt.leadId AS UNSIGNED) AS leadId,
    CAST(jt.agentId AS UNSIGNED) AS agentId
  FROM JSON_TABLE(
    Json_data,
    '$[*]' COLUMNS (
      leadId VARCHAR(50) PATH '$.leadId',
      agentId VARCHAR(50) PATH '$.agentId'
    )
  ) AS jt
  WHERE
    jt.leadId IS NOT NULL AND jt.leadId <> '' AND jt.leadId <> '0'
    AND jt.agentId IS NOT NULL AND jt.agentId <> '' AND jt.agentId <> '0'
    AND EXISTS (
      SELECT 1 FROM mmi_lead_details mld
      WHERE mld.lead_id = CAST(jt.leadId AS UNSIGNED)
    )
    AND EXISTS (
      SELECT 1 FROM mmi_mast_user_registration_detail mur
      WHERE mur.id = CAST(jt.agentId AS UNSIGNED)
    );*/
    
    CREATE TEMPORARY TABLE temp_valid_assignment AS
SELECT DISTINCT 
  CAST(jt.leadId AS UNSIGNED) AS leadId,
  CAST(jt.agentId AS UNSIGNED) AS agentId
FROM JSON_TABLE(
  Json_data,
  '$[*]' COLUMNS (
    leadId VARCHAR(50) PATH '$.leadId',
    agentId VARCHAR(50) PATH '$.agentId'
  )
) AS jt
JOIN mmi_lead_details mld
  ON mld.lead_id = CAST(jt.leadId AS UNSIGNED)
JOIN mmi_mast_user_registration_detail mur
  ON mur.id = CAST(jt.agentId AS UNSIGNED)
JOIN mmi_user_dealer_mapping udm
  ON udm.user_id = mur.id
JOIN mmi_dealer_details mdi
  ON mdi.dealer_id = udm.dealer_id
left join mmi_dealer_location_mapping dlm on mld.dealer_code = dlm.dealer_code  
WHERE
  dlm.mapping_dealer_code = mdi.dealer_id
    AND jt.leadId IS NOT NULL AND jt.leadId <> '' AND jt.leadId <> '0' -- Ensure leadId is not null, empty, or '0'
  AND jt.agentId IS NOT NULL AND jt.agentId <> '' AND jt.agentId <> '0'; -- Ensure agentId is not null, empty, or '0'

    
  -- Store old data before update
  SELECT JSON_ARRAYAGG(
    JSON_OBJECT(
      'lead_id', IFNULL(lead_id, ''),
'policy_id', IFNULL(policy_id, ''),
'dealer_code', IFNULL(dealer_code, ''),
'dealer', IFNULL(dealer, ''),
'insurance_company', IFNULL(insurance_company, ''),
'policy_no', IFNULL(policy_no, ''),
'policy_tenure', IFNULL(policy_tenure, ''),
'policy_type', IFNULL(policy_type, ''),
'insured_name', IFNULL(insured_name, ''),
'yom', IFNULL(yom, ''),
'ncb_percentage', IFNULL(ncb_percentage, ''),
'vehicle_class', IFNULL(vehicle_class, ''),
