'insured_name', IFNULL(insured_name, ''),
'yom', IFNULL(yom, ''),
'ncb_percentage', IFNULL(ncb_percentage, ''),
'vehicle_class', IFNULL(vehicle_class, ''),
'vehicle_sub_class', IFNULL(vehicle_sub_class, ''),
'carrier_type', IFNULL(carrier_type, ''),
'policy_effective_date', IFNULL(policy_effective_date, ''),
'policy_expiry_date', IFNULL(policy_expiry_date, ''),
'make', IFNULL(make, ''),
'model', IFNULL(model, ''),
'vehicle_body_type', IFNULL(vehicle_body_type, ''),
'fuel_type', IFNULL(fuel_type, ''),
'variant', IFNULL(variant, ''),
'vin', IFNULL(vin, ''),
'engine_no', IFNULL(engine_no, ''),
'payment_mode', IFNULL(payment_mode, ''),
'od_discount_percentage', IFNULL(od_discount_percentage, ''),
'total_idv', IFNULL(total_idv, ''),
'addon_premium_amount', IFNULL(addon_premium_amount, ''),
'net_od_premium_amount', IFNULL(net_od_premium_amount, ''),
'third_party_liability', IFNULL(third_party_liability, ''),
'pa_cover', IFNULL(pa_cover, ''),
'legal_liability', IFNULL(legal_liability, ''),
'net_liability', IFNULL(net_liability, ''),
'net_premium', IFNULL(net_premium, ''),
'imt_23', IFNULL(imt_23, ''),
'gross_premium', IFNULL(gross_premium, ''),
'rto_display_name', IFNULL(rto_display_name, ''),
'previous_policy_no', IFNULL(previous_policy_no, ''),
'previous_insurance_company', IFNULL(previous_insurance_company, ''),
'podc_start', IFNULL(podc_start, ''),
'podc_end', IFNULL(podc_end, ''),
'plc_start', IFNULL(plc_start, ''),
'plc_end', IFNULL(plc_end, ''),
'third_party_liability_bifuel_kit', IFNULL(third_party_liability_bifuel_kit, ''),
'trailer_imt30', IFNULL(trailer_imt30, ''),
'imt_34tp', IFNULL(imt_34tp, ''),
'pa_cover_unnamed_persons_imt16', IFNULL(pa_cover_unnamed_persons_imt16, ''),
'geographical_areas_extention_imt1', IFNULL(geographical_areas_extention_imt1, ''),
'tpgeographical_areas_extention_imt1', IFNULL(tpgeographical_areas_extention_imt1, ''),
'legal_liability_nfpp_imt37', IFNULL(legal_liability_nfpp_imt37, ''),
'pa_cover_owner_driver', IFNULL(pa_cover_owner_driver, ''),
'oem_code', IFNULL(oem_code, ''),
'proposal_no', IFNULL(proposal_no, ''),
'plan_type', IFNULL(plan_type, ''),
'ebm_calls', IFNULL(ebm_calls, ''),
'zd', IFNULL(zd, ''),
'bundle_product', IFNULL(bundle_product, ''),
'invoice_date', IFNULL(invoice_date, ''),
'cancellation_flag', IFNULL(cancellation_flag, ''),
'reg_no', IFNULL(reg_no, ''),
'i_date', IFNULL(i_date, ''),
'm_date', IFNULL(m_date, ''),
'm_user', IFNULL(m_user, ''),
'version', IFNULL(version, ''),
'cluster_id', IFNULL(cluster_id, ''),
'assigned_agent', IFNULL(assigned_agent, ''),
'lead_source', IFNULL(lead_source, ''),
'lead_status', IFNULL(lead_status, ''),
'expiry_days', IFNULL(expiry_days, ''),
'renewal_category', IFNULL(renewal_category, ''),
'created_by', IFNULL(created_by, ''),
'created_date', IFNULL(created_date, ''),
'modified_by', IFNULL(modified_by, ''),
'modified_date', IFNULL(modified_date, '')
    )
  )
  INTO new_upload_data
  FROM mmi_lead_details
  WHERE lead_id IN (SELECT leadId FROM temp_valid_assignment);

  -- Insert into overwrite logs
  INSERT INTO mmi_maintain_overwrite_logs (
    upload_type, name,
    old_upload_data, new_upload_data,
    created_by, created_date
  )
  VALUES (
    'bulkAssign', 'mmi_lead_details',
    old_upload_data, new_upload_data,
    CAST(userId AS UNSIGNED), NOW()
  );

  -- Show updated leads
  SELECT * FROM temp_valid_assignment;

  -- Drop temp table
  DROP TEMPORARY TABLE IF EXISTS temp_valid_assignment;

  -- Set output message
  IF validCount = 0 THEN
    SET SP_STATUS = '2222';
    SET MESSAGE = 'Failed: All entries are invalid.';
  ELSE
    SET SP_STATUS = '200';
    SET MESSAGE = CONCAT('Success: ', validCount, ' entries updated.');
  END IF;

  COMMIT;
END;




    ELSE
        -- This handles unknown `type` directly
        SET SP_STATUS = '1004';
        SET MESSAGE = CONCAT('Invalid type: ', type);
        LEAVE proc_main;
    END IF;

END ;;
