DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_capture_policy_lead`()
BEGIN
    DECLARE v_interval_days INT;
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_capture_policy_lead', 'POLICY_LEAD_INSERT', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    START TRANSACTION;

    -- Fetch interval days
    SELECT CAST(services_value AS UNSIGNED)
    INTO v_interval_days
    FROM mmi_services_config
    WHERE services_property = 'lead_capture_interval_days'
      AND status = '1'
    LIMIT 1;


    /* -----------------------------------------------------
       STEP 1: UPDATE RECORDS WHERE policy_no + engine_no + vin MATCH
       ----------------------------------------------------- */
    UPDATE mmi_lead_details AS ld
    JOIN mmi_ebm_policy_data AS epd 
        ON ld.policy_no = epd.policy_no
       AND ld.engine_no = epd.engine_no
       AND ld.vin = epd.vin
    JOIN mmi_dealer_details AS mdl
        ON mdl.dealer_id = epd.dealer_code
    SET
        ld.addon_premium_amount = epd.addon_premium_amount,
        ld.bundle_product = epd.bundle_product,
        ld.cancellation_flag = epd.cancellation_flag,
        ld.carrier_type = epd.carrier_type,
        ld.cluster_id = epd.cluster_id,
        ld.customer_landline = epd.customer_landline,
        ld.customer_type = epd.customer_type,
        ld.dealer = epd.dealer,
        ld.dealer_code = epd.dealer_code,
        ld.ebm_calls = epd.ebm_calls,
        ld.engine_no = epd.engine_no,
        ld.fuel_type = epd.fuel_type,
        ld.geographical_areas_extention_imt1 = epd.geographical_areas_extention_imt1,
        ld.gross_premium = epd.gross_premium,
        ld.group_product = epd.group_product,
        ld.i_date = epd.i_date,
        ld.imt_23 = epd.imt_23,
        ld.imt_34tp = epd.imt_34tp,
        ld.insurance_company = epd.insurance_company,
        ld.insured_name = epd.insured_name,
        ld.invoice_date = epd.invoice_date,
        ld.legal_liability = epd.legal_liability,
        ld.legal_liability_nfpp_imt37 = epd.legal_liability_nfpp_imt37,
        ld.m_user = epd.m_user,
        ld.make = epd.make,
        ld.model = epd.model,
        ld.ncb_percentage = epd.ncb_percentage,
        ld.net_liability = epd.net_liability,
        ld.net_od_premium_amount = epd.net_od_premium_amount,
        ld.net_premium = epd.net_premium,
        ld.od_discount_percentage = epd.od_discount_percentage,
        ld.oem_code = epd.oem_code,
        ld.pa_cover = epd.pa_cover,
        ld.pa_cover_owner_driver = epd.pa_cover_owner_driver,
        ld.pa_cover_unnamed_persons_imt16 = epd.pa_cover_unnamed_persons_imt16,
        ld.payment_mode = epd.payment_mode,
        ld.plan_type = epd.plan_type,
        ld.plc_end = epd.plc_end,
        ld.plc_start = epd.plc_start,
        ld.podc_end = epd.podc_end,
        ld.podc_start = epd.podc_start,
        ld.policy_effective_date = epd.policy_effective_date,
        ld.policy_expiry_date = DATE(SUBSTRING(epd.policy_expiry_date, 1, 10)),
        ld.policy_id = epd.policy_id,
        ld.policy_tenure = epd.policy_tenure,
        ld.policy_type = epd.policy_type,
        ld.previous_insurance_company = epd.previous_insurance_company,
        ld.previous_policy_no = epd.previous_policy_no,
        ld.proposal_no = epd.proposal_no,
        ld.reg_no = epd.reg_no,
        ld.registration_date = epd.registration_date,
        ld.rto_display_name = epd.rto_display_name,
        ld.service_tax = epd.service_tax,
        ld.sub_oem_name = epd.sub_oem_name,
        ld.third_party_liability = epd.third_party_liability,
        ld.third_party_liability_bifuel_kit = epd.third_party_liability_bifuel_kit,
        ld.total_idv = epd.total_idv,
        ld.tpgeographical_areas_extention_imt1 = epd.tpgeographical_areas_extention_imt1,
        ld.trailer_imt30 = epd.trailer_imt30,
        ld.variant = epd.variant,
        ld.vehicle_body_type = epd.vehicle_body_type,
        ld.vehicle_class = epd.vehicle_class,
        ld.vehicle_sub_class = epd.vehicle_sub_class,
        ld.version = epd.version,
        ld.yom = epd.yom,
        ld.zd = epd.zd,
        ld.lead_source = epd.source,
        ld.lead_source_type = 'Renewal'
    WHERE epd.policy_expiry_date REGEXP '^[0-9]{4}-[0-9]{2}-[0-9]{2}'
      AND DATE(SUBSTRING(epd.policy_expiry_date, 1, 10))
         BETWEEN CURDATE() AND DATE_ADD(CURDATE(), INTERVAL v_interval_days DAY);


    /* -----------------------------------------------------
       STEP 2: INSERT RECORDS THAT DID NOT MATCH
       ----------------------------------------------------- */
    INSERT INTO mmi_lead_details (
        addon_premium_amount, bundle_product, cancellation_flag, carrier_type, cluster_id,
        customer_landline, customer_type, dealer, dealer_code, ebm_calls,
        engine_no, fuel_type, geographical_areas_extention_imt1, gross_premium, group_product,
        i_date, imt_23, imt_34tp, insurance_company, insured_name,
        invoice_date, legal_liability, legal_liability_nfpp_imt37, m_user, make,
        model, ncb_percentage, net_liability, net_od_premium_amount, net_premium,
        od_discount_percentage, oem_code, pa_cover, pa_cover_owner_driver, pa_cover_unnamed_persons_imt16,
        payment_mode, plan_type, plc_end, plc_start, podc_end,
        podc_start, policy_effective_date, policy_expiry_date, policy_id, policy_no,
        policy_tenure, policy_type, previous_insurance_company, previous_policy_no, proposal_no,
        reg_no, registration_date, rto_display_name, service_tax, sub_oem_name,
        third_party_liability, third_party_liability_bifuel_kit, total_idv, tpgeographical_areas_extention_imt1, trailer_imt30,
        variant, vehicle_body_type, vehicle_class, vehicle_sub_class, version,
        vin, yom, zd, lead_source, lead_source_type, created_by, created_date
    )
    SELECT
        epd.addon_premium_amount, epd.bundle_product, epd.cancellation_flag, epd.carrier_type, epd.cluster_id,
        epd.customer_landline, epd.customer_type, epd.dealer, epd.dealer_code, epd.ebm_calls,
        epd.engine_no, epd.fuel_type, epd.geographical_areas_extention_imt1, epd.gross_premium, epd.group_product,
        epd.i_date, epd.imt_23, epd.imt_34tp, epd.insurance_company, epd.insured_name,
        epd.invoice_date, epd.legal_liability, epd.legal_liability_nfpp_imt37, epd.m_user, epd.make,
        epd.model, epd.ncb_percentage, epd.net_liability, epd.net_od_premium_amount, epd.net_premium,
        epd.od_discount_percentage, epd.oem_code, epd.pa_cover, epd.pa_cover_owner_driver, epd.pa_cover_unnamed_persons_imt16,
        epd.payment_mode, epd.plan_type, epd.plc_end, epd.plc_start, epd.podc_end,
        epd.podc_start, epd.policy_effective_date,
        DATE(SUBSTRING(epd.policy_expiry_date, 1, 10)),
        epd.policy_id, epd.policy_no,
        epd.policy_tenure, epd.policy_type, epd.previous_insurance_company, epd.previous_policy_no, epd.proposal_no,
        epd.reg_no, epd.registration_date,
        epd.rto_display_name, epd.service_tax, epd.sub_oem_name,
        epd.third_party_liability, epd.third_party_liability_bifuel_kit, epd.total_idv, epd.tpgeographical_areas_extention_imt1, epd.trailer_imt30,
        epd.variant, epd.vehicle_body_type, epd.vehicle_class, epd.vehicle_sub_class, epd.version,
        epd.vin, epd.yom, epd.zd, epd.source, 'Renewal', 'SYSTEM', NOW()
    FROM mmi_ebm_policy_data epd
    INNER JOIN mmi_dealer_details mdl ON mdl.dealer_id = epd.dealer_code
    LEFT JOIN mmi_lead_details ld
           ON ld.policy_no = epd.policy_no
          AND ld.engine_no = epd.engine_no
          AND ld.vin = epd.vin
    WHERE ld.policy_no IS NULL
     AND NOT EXISTS (
        SELECT 1
        FROM mmi_lead_archive_details lad
        WHERE lad.policy_no = epd.policy_no
          AND lad.engine_no = epd.engine_no
          AND lad.vin = epd.vin
  )
 AND epd.policy_expiry_date REGEXP '^[0-9]{4}-[0-9]{2}-[0-9]{2}'
   AND DATE(SUBSTRING(epd.policy_expiry_date, 1, 10))
        BETWEEN CURDATE() AND DATE_ADD(CURDATE(), INTERVAL v_interval_days DAY);

 CALL mmi_proc_insert_customer_details();
    COMMIT;

    SELECT ROW_COUNT() AS affected_rows;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_capture_rollover_expired_policy_lead` */;
