CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_delete_bucket`(
    IN p_json_data JSON, 
    OUT p_status_code VARCHAR(50), 
    OUT p_status_message VARCHAR(255)
)
BEGIN
	DECLARE p_bucket_id INT; 
    DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
            
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_delete_bucket', 'DELETE_BUCKET', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    
    START TRANSACTION;
	SET p_bucket_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.bucketId'));
    
    IF p_bucket_id = 0 OR p_bucket_id IS NULL THEN
		SET p_status_code = '300';
        SET p_status_message = 'Bucket ID cannot empty or null.';
        ROLLBACK;
    ELSE
		DELETE FROM mmi_call_user_preference_addon WHERE bucket_id = p_bucket_id;
		DELETE FROM mmi_call_user_preference_datapull WHERE bucket_id = p_bucket_id;
		DELETE FROM mmi_call_user_preference_insurance WHERE bucket_id = p_bucket_id;
		DELETE FROM mmi_call_user_preference_renewal WHERE bucket_id = p_bucket_id;
		DELETE FROM mmi_call_user_preference_segment WHERE bucket_id = p_bucket_id;

		DELETE FROM mmi_mast_bucket WHERE id = p_bucket_id;
		COMMIT;

		SET p_status_code = '200';
		SET p_status_message = CONCAT('Bucket successfully deleted for bucketId: ', p_bucket_id);
	END IF;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_download_error_record` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_download_error_record`(
    IN Json_data JSON,
    IN type VARCHAR(45),
    OUT SP_STATUS VARCHAR(500), 
    OUT MESSAGE VARCHAR(500)
)
BEGIN
proc_block: BEGIN

    DECLARE dealerId VARCHAR(45);
    DECLARE parentId VARCHAR(45);
    DECLARE custom_type VARCHAR(45);
    DECLARE userId VARCHAR(100);
    DECLARE v_case_id VARCHAR(20);
    DECLARE table_name VARCHAR(100);
    DECLARE db_table_name VARCHAR(100);
    -- DECLARE v_sql TEXT;

    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;

    -- Error handler
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        GET DIAGNOSTICS CONDITION 1 
            @sqlstate = RETURNED_SQLSTATE,
            errno = MYSQL_ERRNO,
            errmsg = MESSAGE_TEXT;
        SET SP_STATUS = 407;
        SET MESSAGE = 'Something Went Wrong.';
        
        ROLLBACK;
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, ERROR_TIMING, created_by, created_date
        ) VALUES (
            errno, CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg), 'mmi_proc_download_error_record', type, CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    -- Extract JSON values
    SET dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'));
    SET parentId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'));
    SET custom_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype'));
    SET userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
    SET v_case_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.caseId'));

    IF custom_type IS NULL OR userId IS NULL THEN
        SET SP_STATUS = 400;
        SET MESSAGE = 'Missing required fields';
        LEAVE proc_block;
    END IF;

    -- Map custom_type to table names
    CASE custom_type
        WHEN 'sales' THEN SET table_name = 'mmi_ebm_sales_data_error'; SET db_table_name='mmi_ebm_sales_data';
        WHEN 'policy' THEN SET table_name = 'mmi_ebm_policy_data_error_log'; SET db_table_name='mmi_ebm_policy_data';
        WHEN 'claim' THEN SET table_name = 'mmi_ebm_claim_data_error'; SET db_table_name='mmi_ebm_claim_data';
        WHEN 'service' THEN SET table_name = 'mmi_ebm_service_data_error'; SET db_table_name='mmi_ebm_service_data';
        WHEN 'addon' THEN SET table_name = 'mmi_poladdon_data_error'; SET db_table_name='mmi_poladdon_data';
        ELSE 
            SET SP_STATUS = 300;
            SET MESSAGE = 'Invalid custom_type';
            LEAVE proc_block;
    END CASE;

    SET SESSION group_concat_max_len = 1000000;

    -- Try fetching columns from mmi_mast_excel_column_mapping
    SELECT GROUP_CONCAT(DISTINCT CONCAT('sde.', ecm.db_column_name, ' AS `', REPLACE(ecm.excel_column_name,'`',''), '`') 
                        ORDER BY ecm.id SEPARATOR ', ')
           INTO @v_sql
    FROM mmi_mast_excel_column_mapping ecm
    JOIN INFORMATION_SCHEMA.COLUMNS c
        ON c.TABLE_NAME = table_name
        AND c.COLUMN_NAME = ecm.db_column_name
        AND c.TABLE_SCHEMA = DATABASE()
    WHERE ecm.db_table_name = db_table_name
      AND ecm.status = 1;

    -- If no mapping found, fallback to mmi_mast_columns_mandatory
    IF @v_sql IS NULL THEN
        SELECT GROUP_CONCAT(DISTINCT CONCAT('sde.', cm.columns_name, ' AS `', REPLACE(cm.excel_column_name,'`',''), '`') 
                            ORDER BY cm.id SEPARATOR ', ')
               INTO @v_sql
        FROM mmi_mast_columns_mandatory cm
        JOIN INFORMATION_SCHEMA.COLUMNS c
            ON c.TABLE_NAME = table_name
            AND c.COLUMN_NAME = cm.columns_name
            AND c.TABLE_SCHEMA = DATABASE()
        WHERE cm.db_table_name = db_table_name;
          -- AND cm.status = 1;
    END IF;

    -- Add validation_errors
    SET @v_sql = CONCAT('SELECT ', @v_sql, IF(@v_sql IS NOT NULL, ',', ''), ' sde.validation_errors FROM ', table_name, ' sde ',
                       'WHERE sde.user_id = ', QUOTE(userId),
                       IF(type='Dealer', CONCAT(' AND sde.dealer_id = ', QUOTE(dealerId)), ''),
                       ' AND sde.case_reference_id = ', QUOTE(v_case_id), ';');

    -- Execute dynamic SQL
    PREPARE stmt FROM @v_sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

    SET SP_STATUS = 200;
    SET MESSAGE = CONCAT('Download Success for ', custom_type);

END proc_block;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_ebm_init_crm_transaction` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_ebm_init_crm_transaction`(
    IN p_policy_no VARCHAR(200),
    IN p_crm_txn_token VARCHAR(100),
    IN p_ebm_user_id VARCHAR(50)
)
proc_end: BEGIN
    DECLARE v_lead_id INT;
    DECLARE v_count INT DEFAULT 0;

    SELECT lead_id
    INTO v_lead_id
    FROM mmi_lead_details
    WHERE policy_no = p_policy_no
    ORDER BY created_date DESC
    LIMIT 1;

    IF v_lead_id IS NULL THEN
        LEAVE proc_end;
    END IF;

    SELECT COUNT(1)
    INTO v_count
    FROM mmi_crm_ebm_transaction_details
    WHERE crm_transaction_token_no = p_crm_txn_token;

    IF v_count = 0 THEN
        INSERT INTO mmi_crm_ebm_transaction_details (
            lead_id,
            policy_no,
            crm_transaction_token_no,
            ebm_user_id,
            created_by,
            created_date
        ) VALUES (
            v_lead_id,
            p_policy_no,
            p_crm_txn_token,
            p_ebm_user_id,
            'SYSTEM',
            NOW()
        );
    END IF;

END proc_end ;;
DELIMITER ;
