CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_ebm_insert_addon_data`(
    IN p_policy_id VARCHAR(45),
    IN p_policy_no VARCHAR(45),
    IN p_description VARCHAR(45),
    IN p_premium VARCHAR(45)
)
BEGIN
    DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code,
            error_message,
            procedure_name,
