            error_timing,
            created_by,
            created_date
        ) VALUES (
            err_code,
            err_msg,
            'mmi_proc_ebm_insert_addon_data',
            'EBM_ADDON_INSERT',
            CURRENT_TIMESTAMP(),
            'SYSTEM',
            NOW()
        );
    END;

    START TRANSACTION;

    -- Check if a record with the same policy_no and description exists
    IF EXISTS (
        SELECT 1 FROM mmi_poladdon_data
        WHERE policy_no = p_policy_no
          AND add_on_name = p_description
    ) THEN
        -- Update the record
        UPDATE mmi_poladdon_data
        SET
            policy_id = p_policy_id,
            premium = p_premium,
            modified_by = 'SYSTEM',
            modified_date = NOW()
        WHERE policy_no = p_policy_no
          AND add_on_name = p_description;
    ELSE
        -- Insert new record
        INSERT INTO mmi_poladdon_data (
            policy_id,
            policy_no,
            add_on_name,
            premium,
            created_by,
            created_date
        ) VALUES (
            p_policy_id,
            p_policy_no,
            p_description,
            p_premium,
            'SYSTEM',
            NOW()
        );
    END IF;

    COMMIT;
END ;;
