CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_ebm_insert_reminder_data`(
    IN p_policy_no VARCHAR(200),
    IN p_reminder_frequency VARCHAR(45),
    IN p_renewal_link VARCHAR(1000),
    IN p_mode VARCHAR(100),
    IN p_contact_detail VARCHAR(1000),
    IN p_sent_date DATE  -- Adding the sent_date parameter
)
BEGIN
    DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code,
            error_message,
            procedure_name,
            procedure_type,
            error_timing,
            created_by,
            created_date
        ) VALUES (
            err_code,
            err_msg,
            'mmi_proc_ebm_insert_reminder_data',
            'EBM_REMINDER_INSERT',
            CURRENT_TIMESTAMP(),
            'SYSTEM',
            NOW()
        );
    END;

    START TRANSACTION;

    -- Check if a record already exists with the same combination
    IF EXISTS (
        SELECT 1
        FROM mmi_renewalreminder_data
        WHERE policy_no = p_policy_no
          AND reminder_frequency = p_reminder_frequency
          -- AND renewal_link = p_renewal_link
          AND mode = p_mode
          -- AND contact_detail = p_contact_detail
    ) THEN
        -- If it exists, update the record, including the sent_date
        UPDATE mmi_renewalreminder_data
        SET
            reminder_frequency = p_reminder_frequency,
            renewal_link = p_renewal_link,
            mode = p_mode,
            contact_detail = p_contact_detail,
            sent_date = p_sent_date,   -- Including sent_date in the update
            modified_by = 'SYSTEM',
            modified_date = NOW()
        WHERE policy_no = p_policy_no
          AND reminder_frequency = p_reminder_frequency
          AND mode = p_mode;
    ELSE
        -- If it does not exist, insert a new record, including the sent_date
        INSERT INTO mmi_renewalreminder_data (
            policy_no,
            reminder_frequency,
            contact_detail,
            renewal_link,
            mode,
            sent_date,  -- Inserting sent_date
            created_by,
            created_date
        ) VALUES (
            p_policy_no,
            p_reminder_frequency,
            p_contact_detail,
            p_renewal_link,
            p_mode,
            p_sent_date,  -- Use sent_date parameter
            'SYSTEM',
            NOW()
        );
    END IF;

    COMMIT;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
