            NOW(),
            'SYSTEM',
            NOW()
        );
    END;

    START TRANSACTION;

    -- Fetch lead_id
    SELECT lead_id
    INTO v_lead_id
    FROM mmi_lead_details
    WHERE policy_no = p_policy_no
      AND vin = p_chassis_no
      AND policy_expiry_date = DATE(SUBSTRING(p_policy_expiry_date, 1, 10))
    LIMIT 1;

    IF v_lead_id IS NOT NULL AND v_lead_id <> 0 THEN

        -- Generate unique token
        SET v_token = CONCAT(
            'CRM_TRN_',
            DATE_FORMAT(NOW(3), '%d%m%Y%H%i%s'),
            LPAD(MICROSECOND(NOW(3)) DIV 1000, 3, '0')
        );

        -- Check if record already exists
        SELECT COUNT(1)
        INTO v_count
        FROM mmi_crm_ebm_transaction_details
        WHERE lead_id = v_lead_id
          AND policy_no = p_policy_no;

        IF v_count > 0 THEN
            -- UPDATE
            UPDATE mmi_crm_ebm_transaction_details
            SET
                proposal_no = p_proposal_no,
                crm_transaction_token_no = v_token,
                modified_by = 'SYSTEM',
                modified_date = NOW()
            WHERE lead_id = v_lead_id
              AND policy_no = p_policy_no;

        ELSE
            -- INSERT
            INSERT INTO mmi_crm_ebm_transaction_details (
                lead_id,
                policy_no,
                proposal_no,
                crm_transaction_token_no,
                created_date,
                created_by
            ) VALUES (
                v_lead_id,
                p_policy_no,
                p_proposal_no,
                v_token,
                NOW(),
                'SYSTEM'
            );
        END IF;

    END IF;

    COMMIT;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_ebm_update_proposal_status` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_ebm_update_proposal_status`(
    IN  p_json_data JSON,
    OUT p_status_code VARCHAR(50),
    OUT p_status_message VARCHAR(255)
)
proc_end: BEGIN

    DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;

    DECLARE v_policy_no VARCHAR(100);
    DECLARE v_proposal_no VARCHAR(100);
    DECLARE v_proposal_status VARCHAR(100);
    DECLARE v_renewal_link_modify TEXT;
    DECLARE v_renewal_link_readOnly TEXT(500);
    DECLARE v_proposalTimestamp DATETIME;
    DECLARE v_ebm_action_userId VARCHAR(100);
    DECLARE v_crm_authToken VARCHAR(100);
    DECLARE v_remarks TEXT;
    DECLARE v_additional_param2 TEXT;
    
    DECLARE v_token_policy_no VARCHAR(100);
    DECLARE v_expiry_time DATETIME;

    DECLARE v_latest_id BIGINT;
    DECLARE v_check_leadId INT;

    DECLARE v_mandatory_error VARCHAR(500) DEFAULT '';

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg  = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name,
            procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg,
            'mmi_proc_ebm_update_proposal_status',
            'EBM_UPDATE_PROPOSAL',
            CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

        SET p_status_code = '500';
        SET p_status_message = 'Something went wrong';
    END;

    START TRANSACTION;

    -- JSON extraction
    SET v_policy_no             = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.policyNo'));
    SET v_proposal_status       = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.proposalStatus'));
    SET v_crm_authToken         = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.crmAuthToken'));
    SET v_remarks               = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.additionalParameter1'));
	SET v_additional_param2     = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.additionalParameter2'));


    -- Opt fields
    SET v_proposal_no           = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.proposalNo'));
    SET v_renewal_link_modify   = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.renewalLinkModify'));
    SET v_renewal_link_readOnly = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.renewalLinkReadOnly'));
    SET v_proposalTimestamp     = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.proposalTimestamp'));
    SET v_ebm_action_userId     = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.ebmActionUserId'));

    -- Mandatory fields validation
    IF v_policy_no IS NULL OR v_policy_no = '' THEN
        SET v_mandatory_error = CONCAT(v_mandatory_error, 'policyNo is required; ');
    END IF;
    IF v_proposal_status IS NULL OR v_proposal_status = '' THEN
        SET v_mandatory_error = CONCAT(v_mandatory_error, 'proposalStatus is required; ');
    END IF;
    IF v_crm_authToken IS NULL OR v_crm_authToken = '' THEN
        SET v_mandatory_error = CONCAT(v_mandatory_error, 'crmAuthToken is required; ');
    END IF;
    IF v_remarks IS NULL OR v_remarks = '' THEN
        SET v_mandatory_error = CONCAT(v_mandatory_error, 'additionalParameter1 is required; ');
    END IF;

    IF v_mandatory_error != '' THEN
        SET p_status_code = '400';
        SET p_status_message = v_mandatory_error;
        ROLLBACK;
        LEAVE proc_end;
    END IF;

    -- Token validation
    IF NOT EXISTS (
        SELECT 1
        FROM mmi_crm_ebm_tokens
        WHERE token_value = v_crm_authToken
          AND token_type = 'CRM_AUTH'
    ) THEN
        SET p_status_code = '401';
        SET p_status_message = 'Invalid CRM Auth Token';
        ROLLBACK;
        LEAVE proc_end;
    END IF;

    SELECT policy_no, expiry_time
    INTO v_token_policy_no, v_expiry_time
    FROM mmi_crm_ebm_tokens
    WHERE token_value = v_crm_authToken
      AND token_type = 'CRM_AUTH'
    LIMIT 1;

    IF v_policy_no <> v_token_policy_no THEN
        SET p_status_code = '401';
        SET p_status_message = 'Policy mismatch for CRM Auth Token';
        ROLLBACK;
        LEAVE proc_end;
    END IF;

    IF v_expiry_time < NOW() THEN
        SET p_status_code = '401';
        SET p_status_message = 'CRM Auth Token expired';
        ROLLBACK;
        LEAVE proc_end;
    END IF;

    -- Fetching latest txn row 
    SELECT id, lead_id
    INTO v_latest_id, v_check_leadId
    FROM mmi_crm_ebm_transaction_details
    WHERE policy_no = v_policy_no
    ORDER BY id DESC
    LIMIT 1;

    IF v_latest_id IS NULL THEN
        SET p_status_code = '404';
        SET p_status_message = 'No record found';
        ROLLBACK;
        LEAVE proc_end;
    END IF;

    -- Update latest row - only update provided fields, keep existing if null 
    UPDATE mmi_crm_ebm_transaction_details
    SET
        -- proposal_no            = v_proposal_no,
        proposal_status        = v_proposal_status,
        renewal_link_modify    = v_renewal_link_modify,
        renewal_link_read_only = v_renewal_link_readOnly,
        proposal_timestamp     = v_proposalTimestamp,
        ebm_user_id            = v_ebm_action_userId,
        crm_token              = v_crm_authToken,
        modified_by            = v_ebm_action_userId,
        modified_date          = NOW(),
		remarks 	           = v_remarks
        -- additional_param_2     = v_additional_param2
        
    WHERE id = v_latest_id;

    -- History insert
    IF v_check_leadId IS NOT NULL AND v_check_leadId > 0 THEN
        INSERT INTO mmi_proposal_status_history (
            lead_id, policy_no, proposal_no, proposal_status,
            renewal_link_modify, renewal_link_read_only,
            proposal_timestamp, remarks, additional_param_2, ebm_action_user_id,
            created_by, source_system
        ) VALUES (
            /* v_check_leadId, v_policy_no, 
            IFNULL(v_proposal_no, (SELECT proposal_no FROM mmi_crm_ebm_transaction_details WHERE id = v_latest_id)),
            v_proposal_status,
            IFNULL(v_renewal_link_modify, (SELECT renewal_link_modify FROM mmi_crm_ebm_transaction_details WHERE id = v_latest_id)),
            IFNULL(v_renewal_link_readOnly, (SELECT renewal_link_read_only FROM mmi_crm_ebm_transaction_details WHERE id = v_latest_id)),
            IFNULL(v_proposalTimestamp, NOW()),
            v_remarks,
            IFNULL(v_ebm_action_userId, 'SYSTEM'),
            IFNULL(v_ebm_action_userId, 'SYSTEM'),
            'EBM' */ 
	    
	    v_check_leadId, v_policy_no, v_proposal_no, v_proposal_status,
            v_renewal_link_modify, v_renewal_link_readOnly,
            v_proposalTimestamp, v_remarks, v_additional_param2, v_ebm_action_userId,
            v_ebm_action_userId, 'EBM'

        );
    END IF;

    COMMIT;

    SET p_status_code = '200';
    SET p_status_message = 'Latest record updated successfully';

END proc_end ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_fetch_all_faq_details` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_all_faq_details`(
    OUT status_code VARCHAR(10),
    OUT status_message VARCHAR(255)
)
BEGIN
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        INSERT INTO mmi_mast_procedure_error (
            error_code,
            error_message,
            procedure_name,
            procedure_type,
            error_timing,
            created_by,
            created_date
        ) VALUES (
            err_code,
            err_msg,
            'mmi_proc_fetch_all_faq_details',
            'FETCH_FAQ',
            CURRENT_TIMESTAMP(),
            'SYSTEM',
            NOW()
        );

        SET status_code = '300';
        SET status_message = CONCAT('Something Went Wrong');
    END;

     SELECT
        faq_id,
        topic,
        question,
        answer,
        status
    FROM mmi_faq_master
    WHERE status = 1
    ORDER BY faq_id;

    SET status_code = '200';
    SET status_message = 'Fetched all FAQ successfully';

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_fetch_callqueuedetails` */;
