/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_callqueuedetails`(
    IN Json_data JSON,
    OUT SP_STATUS VARCHAR(500),
    OUT MESSAGE VARCHAR(500)
)
BEGIN
    proc_end: BEGIN
     
    DECLARE userid VARCHAR(45); 
    DECLARE calculated INT DEFAULT 0;
    DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 0;
    DECLARE statustype VARCHAR(45) DEFAULT "";
    DECLARE roleId VARCHAR(45); 
    DECLARE type VARCHAR(45);
    DECLARE v_total_count VARCHAR(45);
    DECLARE v_current_count VARCHAR(45);
    DECLARE sortField VARCHAR(45);
    DECLARE sortOrder VARCHAR(45);
    DECLARE v_dealer_code VARCHAR(200);
    DECLARE v_parent_dealer VARCHAR(200);   --

    
    DECLARE v_sort_col INT DEFAULT 1;
	DECLARE v_sort_dir INT DEFAULT 1;

    DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
            
            SET SP_STATUS = '500';
            SET MESSAGE = 'An error occurred. Please try again.';
            
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_fetch_callqueuedetails', 'FETCH_CALL_QUEUE', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;

    SET statustype = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.callQueType'));
    SET userid = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
    SET type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.type'));
    
    SET sortField = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.sortField'));
    SET sortOrder = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.sortOrder'));
	SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
    
SELECT COALESCE(
    (
        SELECT mapping_dealer_code
        FROM mmi_dealer_location_mapping
        WHERE dealer_code = v_dealer_code
        LIMIT 1
    ),
    v_dealer_code
)
INTO v_parent_dealer;
    
    
    -- Set default sort field
    IF sortField IS NULL OR sortField = '' THEN
        SET sortField = 'expiryDays';
    END IF;

    -- Set default sort order
    IF sortOrder IS NULL OR sortOrder = '' THEN
        SET sortOrder = 'asc'; 
    END IF;
    
    SET v_sort_col =
    CASE sortField
        WHEN 'Expiry Date'       THEN 1
        WHEN 'customerName'      THEN 2
        WHEN 'status'            THEN 3
        WHEN 'Vehicle Name'      THEN 4
        WHEN 'Renewal Category'  THEN 5
        -- EBM herek
		WHEN 'EBM Status'        THEN 6
        ELSE 1
    END;

	SET v_sort_dir = IF(LOWER(sortOrder) = 'desc', -1, 1);

    IF userid IS NULL OR userid = '' OR type IS NULL OR type = '' THEN
        SET SP_STATUS = '1101';
        SET MESSAGE = 'UserId and Type cannot be empty';
        ROLLBACK;
        LEAVE proc_end;
    END IF;

    SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.limit')) AS UNSIGNED), 10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.offset')) AS UNSIGNED), 0);
    SET calculated = (offsetVal - 1) * limitVal;

	IF type = 'getcallqueuedetails' THEN

		-- Use CTE output in your queries below
		IF statustype = 'current' THEN
		WITH dealer_scope AS (
    SELECT dealer_code
    FROM mmi_dealer_location_mapping
    WHERE mapping_dealer_code = v_parent_dealer

    UNION

    SELECT v_parent_dealer
), 
		dispo_counts AS (
			SELECT lead_id, COUNT(*) AS dispo_count
			FROM mmi_call_disposition_history
			GROUP BY lead_id
		),
		latest_dispositions AS (
			SELECT h1.*
			FROM mmi_call_disposition_history h1
			LEFT JOIN mmi_call_disposition_history h2 
				ON h1.lead_id = h2.lead_id AND h1.created_date < h2.created_date
			WHERE h2.id IS NULL
		),
        /*customer_unique AS (
			SELECT cluster_id, MIN(customer_name) AS customer_name, MIN(vehicle_reg_no) AS vehicle_reg_no
			FROM mmi_mast_customer_details
			GROUP BY cluster_id
		),*/
        -- EBM herek - Modified to use proper status-color mapping
        latest_ebm_status AS (

    SELECT 
        e.lead_id,

        COALESCE(
            NULLIF(e.proposal_status,'N/A'),

            (
                SELECT psh.proposal_status
                FROM mmi_proposal_status_history psh
                WHERE psh.lead_id = e.lead_id
                AND psh.proposal_status IS NOT NULL
                AND psh.proposal_status <> 'N/A'
                ORDER BY psh.created_date DESC
                LIMIT 1
            ),

            'N/A'
        ) AS proposal_status,

        COALESCE(ems.ebm_status_color,'#000000') AS ebm_status_color

    FROM (
        SELECT *
        FROM (
            SELECT *,
                   ROW_NUMBER() OVER (
                       PARTITION BY lead_id 
                       ORDER BY created_date DESC
                   ) AS rn
            FROM mmi_crm_ebm_transaction_details
        ) t
        WHERE rn = 1
    ) e

    LEFT JOIN mmi_mast_ebm_status ems
        ON ems.sub_ebm_status = e.proposal_status
),
        --
		caller_data AS (
			SELECT DISTINCT
				customer.customer_name AS customerName,
				lead_details.lead_id AS leadId,
				lead_details.lead_type AS leadType,
				lead_details.model AS model,
                customer.vehicle_reg_no AS vehicleRegNo,
				lead_details.renewal_category AS renewal_category,
				DATE_FORMAT(lead_details.policy_expiry_date, '%Y-%m-%d') AS expiry_date,
				lead_details.expiry_days AS expiryDays,
				customer.cluster_id AS clusterId,
				lead_details.assigned_agent,
				user.id AS agent_id,
				userreporting.supervisor_id,
				-- sh.user_id AS top_supervisor_id,
				CONCAT(user.first_name, ' ', user.last_name) AS agentName,
				-- recentupdates
				CONCAT(
					latest_dispo.call_status, ' | ',
					DATE_FORMAT(latest_dispo.call_date, '%Y-%m-%d %H:%i:%s'), ' \n ',
					IFNULL(adfr.field_value, ''), ' | ',
					IFNULL(latest_dispo.next_call_datetime, '')
				) AS recentupdates,
				-- next_status
				CONCAT(
					IFNULL(adfr.field_value, ''),
					CASE 
						WHEN dispo_counts.dispo_count > 0 
						THEN CONCAT('(', dispo_counts.dispo_count, ')')
						ELSE ''
					END
				) AS next_status,
				latest_dispo.next_call_datetime AS call_date_time,
                
                -- EBM herek - Modified to include proper color mapping
                COALESCE(ebm_status.proposal_status, 'N/A') AS ebm_status,
				COALESCE(ebm_status.ebm_status_color, '#000000') AS ebm_status_color,
                lead_details.vin as vin
                --
			FROM mmi_lead_details lead_details
            INNER JOIN dealer_scope ds ON ds.dealer_code = lead_details.dealer_code
			LEFT JOIN latest_dispositions latest_dispo ON latest_dispo.lead_id = lead_details.lead_id
			LEFT JOIN dispo_counts ON dispo_counts.lead_id = lead_details.lead_id
			LEFT JOIN mmi_agent_disposition_field_response adfr 
				ON adfr.response_id = latest_dispo.id AND adfr.field_label = 'Sub Disposition'
			-- LEFT JOIN customer_unique customer ON customer.cluster_id = lead_details.cluster_id
			LEFT JOIN LATERAL (
				SELECT cluster_id, MIN(customer_name) AS customer_name, MIN(vehicle_reg_no) AS vehicle_reg_no
				FROM mmi_mast_customer_details cd WHERE lead_details.vin = cd.chassis_no and lead_details.engine_no = cd.engine_no -- cd.cluster_id = lead_details.cluster_id
				GROUP BY cluster_id LIMIT 1
			) customer ON TRUE
            LEFT JOIN mmi_mast_user_registration_detail user ON user.id = lead_details.assigned_agent
			LEFT JOIN mmi_user_reporting userreporting ON userreporting.user_id = user.id
            -- EBM herek
			LEFT JOIN latest_ebm_status ebm_status ON ebm_status.lead_id = lead_details.lead_id
			--
            
			-- INNER JOIN subordinates sh ON sh.user_id = user.id
			-- WHERE lead_details.dealer_code = 'K010801KBS1'
		)
            -- EBM herek
			SELECT DISTINCT customerName, leadId, leadType, model AS vehicleName,vehicleRegNo, renewal_category AS renewalCategory,
						   expiry_date AS expiryDate, recentupdates AS recentUpdates, next_status AS status, 
						   clusterId, expiryDays, ebm_status AS ebmStatus, ebm_status_color AS ebmStatusColor, vin as chassisNo
			--
            
			FROM caller_data
			WHERE assigned_agent = userid
			  AND (DATE(call_date_time) = CURRENT_DATE() OR DATE(expiry_date) = CURRENT_DATE())
			/*ORDER BY
				 CASE leadType
					 WHEN 'hot' THEN 1
					 WHEN 'warm' THEN 2
					 WHEN 'cold' THEN 3
				 END,
                 expiryDays ASC,
				 leadId ASC, 
				-- CASE WHEN sortField = 'Expiry Date' AND sortOrder = 'asc' THEN CAST(expiryDays as UNSIGNED) END ASC,
				-- CASE WHEN sortField = 'Expiry Date' AND sortOrder = 'desc' THEN CAST(expiryDays as UNSIGNED) END DESC,
				CASE WHEN sortField = 'Expiry Date' AND sortOrder = 'asc' THEN expiryDays END ASC,
                CASE WHEN sortField = 'Expiry Date' AND sortOrder = 'desc' THEN expiryDays END DESC,
                CASE WHEN sortField = 'customerName' AND sortOrder = 'asc' THEN customerName END ASC,
				CASE WHEN sortField = 'customerName' AND sortOrder = 'desc' THEN customerName END DESC,
				CASE WHEN sortField = 'status' AND sortOrder = 'asc' THEN next_status END ASC,
				CASE WHEN sortField = 'status' AND sortOrder = 'desc' THEN next_status END DESC,
				CASE WHEN sortField = 'Vehicle Name' AND sortOrder = 'asc' THEN model END ASC,
				CASE WHEN sortField = 'Vehicle Name' AND sortOrder = 'desc' THEN model END DESC,
				CASE WHEN sortField = 'Renewal Category' AND sortOrder = 'asc' THEN renewal_category END ASC,
				CASE WHEN sortField = 'Renewal Category' AND sortOrder = 'desc' THEN renewal_category END DESC
			LIMIT limitVal OFFSET calculated;*/
			ORDER BY
				CASE leadType
					WHEN 'hot'  THEN 1
					WHEN 'warm' THEN 2
					WHEN 'cold' THEN 3
					ELSE 4
				END,

				CASE v_sort_col
					WHEN 1 THEN expiryDays
					WHEN 2 THEN customerName
					WHEN 3 THEN next_status
					WHEN 4 THEN model
					WHEN 5 THEN renewal_category
                    -- EBM herek
                    WHEN 6 THEN ebm_status
                    --
				END * v_sort_dir

				-- leadId
			LIMIT limitVal OFFSET calculated;


 -- MIBL Call Centre
		ELSEIF statustype = 'callCenter' THEN
		WITH dealer_scope AS (
    SELECT dealer_code
    FROM mmi_dealer_location_mapping
    WHERE mapping_dealer_code = v_parent_dealer

    UNION

    SELECT v_parent_dealer
), 
		dispo_counts AS (
			SELECT lead_id, COUNT(*) AS dispo_count
			FROM mmi_call_disposition_history
			GROUP BY lead_id
		),
		latest_dispositions AS (
		SELECT *
			FROM (
				SELECT *,
               ROW_NUMBER() OVER (PARTITION BY lead_id ORDER BY created_date DESC) rn
