				FROM mmi_mast_customer_details cd WHERE lead_details.vin = cd.chassis_no and lead_details.engine_no = cd.engine_no-- cd.cluster_id = lead_details.cluster_id
				GROUP BY cluster_id LIMIT 1
			) customer ON TRUE
			LEFT JOIN mmi_mast_user_registration_detail user ON user.id = lead_details.assigned_agent
			LEFT JOIN mmi_user_reporting userreporting ON userreporting.user_id = user.id
			INNER JOIN subordinates sh ON sh.user_id = user.id
			-- WHERE lead_details.dealer_code = 'K010801KBS1'
            -- EBM herek
            LEFT JOIN latest_ebm_status ebm_status ON ebm_status.lead_id = lead_details.lead_id
			--
		)
			SELECT COUNT(DISTINCT leadId) AS totalCallQueue 
			FROM caller_data 
			WHERE assigned_agent <> userid;
		ELSE
			WITH
            dealer_scope AS (
    SELECT dealer_code
    FROM mmi_dealer_location_mapping
    WHERE mapping_dealer_code = v_parent_dealer

    UNION

    SELECT v_parent_dealer
), 
		dispo_counts AS (
			SELECT lead_id, COUNT(*) AS dispo_count
			FROM mmi_call_disposition_history
			GROUP BY lead_id
		),
		latest_dispositions AS (
			SELECT h1.*
			FROM mmi_call_disposition_history h1
			LEFT JOIN mmi_call_disposition_history h2 
				ON h1.lead_id = h2.lead_id AND h1.created_date < h2.created_date
			WHERE h2.id IS NULL
		),
        -- EBM herek - Modified to use proper status-color mapping
       latest_ebm_status AS (

    SELECT 
        e.lead_id,

        COALESCE(
            NULLIF(e.proposal_status,'N/A'),

            (
                SELECT psh.proposal_status
                FROM mmi_proposal_status_history psh
                WHERE psh.lead_id = e.lead_id
                AND psh.proposal_status IS NOT NULL
                AND psh.proposal_status <> 'N/A'
                ORDER BY psh.created_date DESC
                LIMIT 1
            ),

            'N/A'
        ) AS proposal_status,

        COALESCE(ems.ebm_status_color,'#000000') AS ebm_status_color

    FROM (
        SELECT *
        FROM (
            SELECT *,
                   ROW_NUMBER() OVER (
                       PARTITION BY lead_id 
                       ORDER BY created_date DESC
                   ) AS rn
            FROM mmi_crm_ebm_transaction_details
        ) t
        WHERE rn = 1
    ) e

    LEFT JOIN mmi_mast_ebm_status ems
        ON ems.sub_ebm_status = e.proposal_status
),
        --
        
		caller_data AS (
			SELECT DISTINCT
				customer.customer_name AS customerName,
				lead_details.lead_id AS leadId,
				lead_details.lead_type AS leadType,
				lead_details.model AS model,
                customer.vehicle_reg_no AS vehicleRegNo,
				lead_details.renewal_category AS renewal_category,
				DATE_FORMAT(lead_details.policy_expiry_date, '%Y-%m-%d') AS expiry_date,
				lead_details.expiry_days AS expiryDays,
				customer.cluster_id AS clusterId,
				lead_details.assigned_agent,
				user.id AS agent_id,
				CONCAT(user.first_name, ' ', user.last_name) AS agentName,
				-- recentupdates
				CONCAT(
					latest_dispo.call_status, ' | ',
					DATE_FORMAT(latest_dispo.call_date, '%Y-%m-%d %H:%i:%s'), ' \n ',
					IFNULL(adfr.field_value, ''), ' | ',
					IFNULL(latest_dispo.next_call_datetime, '')
				) AS recentupdates,
				-- next_status
				CONCAT(
					IFNULL(adfr.field_value, ''),
					CASE 
						WHEN dispo_counts.dispo_count > 0 
						THEN CONCAT('(', dispo_counts.dispo_count, ')')
						ELSE ''
					END
				) AS next_status,
				latest_dispo.next_call_datetime AS call_date_time,
                -- EBM herek - Modified to include proper color mapping
				COALESCE(ebm_status.proposal_status, 'N/A') AS ebm_status,
				COALESCE(ebm_status.ebm_status_color, '#000000') AS ebm_status_color,
                lead_details.vin as vin
                --
                
			FROM mmi_lead_details lead_details
            INNER JOIN dealer_scope ds ON ds.dealer_code = lead_details.dealer_code
			LEFT JOIN latest_dispositions latest_dispo ON latest_dispo.lead_id = lead_details.lead_id
			LEFT JOIN dispo_counts ON dispo_counts.lead_id = lead_details.lead_id
			LEFT JOIN mmi_agent_disposition_field_response adfr 
				ON adfr.response_id = latest_dispo.id AND adfr.field_label = 'Sub Disposition'
			LEFT JOIN LATERAL (
				SELECT cluster_id, MIN(customer_name) AS customer_name, MIN(vehicle_reg_no) AS vehicle_reg_no
				FROM mmi_mast_customer_details cd WHERE lead_details.vin = cd.chassis_no and lead_details.engine_no = cd.engine_no-- cd.cluster_id = lead_details.cluster_id
				GROUP BY cluster_id LIMIT 1
			) customer ON TRUE
			LEFT JOIN mmi_mast_user_registration_detail user ON user.id = lead_details.assigned_agent
			LEFT JOIN mmi_user_reporting userreporting ON userreporting.user_id = user.id
			-- WHERE lead_details.dealer_code = 'K010801KBS1'
			-- EBM herek
            LEFT JOIN latest_ebm_status ebm_status ON ebm_status.lead_id = lead_details.lead_id
			--
		)
			SELECT COUNT(DISTINCT leadId) AS totalCallQueue 
			FROM caller_data 
			WHERE assigned_agent = userid;

WITH dealer_scope AS (
