		WHERE disposition_color IS NOT NULL;

		SET SP_STATUS = '200';
		SET MESSAGE = 'Success';

	ELSE
		SET SP_STATUS = '300';
		SET MESSAGE = 'Invalid request type';
	END IF;


    END proc_end;
