CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_customer_details_for_communication`(
    IN p_cluster_id VARCHAR(100),
    IN p_disposition VARCHAR(100),
    IN p_sub_disposition VARCHAR(100),
    IN p_next_call_datetime VARCHAR(100),
    IN p_communication_type VARCHAR(100)
)
BEGIN
    -- Email placeholders
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    -- Declare EXIT HANDLER for SQL errors
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        -- Capture the error details
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
        -- SET SP_STATUS = '500';
        -- SET SP_MESSAGE = 'An error occurred. Please try again.';
        
        ROLLBACK;
        -- Insert the error details into the mmi_mast_procedure_error table
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_fetch_customer_details_for_communication', 'SEND_CUSTOMER_COMMUNICATION', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
        
    END;
    
    IF p_communication_type = 'Email' THEN 
	IF (p_disposition = 'Not Reachable' AND p_sub_disposition = 'Invalid Number') 
		OR (p_disposition = 'Not Reachable' AND p_sub_disposition = 'No Answer') THEN
        SELECT IF(LENGTH(mdl.policy_no) > 4, CONCAT('xxxx', RIGHT(mdl.policy_no, 4)), mdl.policy_no) AS `previous policy number`,
               date_format(mdl.policy_expiry_date,'%Y-%m-%d') AS `Policy Expiry Date`,
               '+91-22-66423800' AS `Contact number`,
               'insurance.care@mahindrainsurancebrokers.com' AS `Email Address`,
               'Email' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;
		
    ELSEIF (p_disposition = 'Callback Scheduled' AND p_sub_disposition = 'Call Tomorrow') 
			OR (p_disposition = 'Callback Scheduled' AND p_sub_disposition = 'Call Later Today') THEN
        SELECT 
               -- mcd.vehicle_reg_no AS `Vehicle Number`,
               IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `Vehicle Number`,
               mdl.insurance_company AS `Previous Insurer`,
               IF(LENGTH(mdl.policy_no) > 4, CONCAT('xxxx', RIGHT(mdl.policy_no, 4)), mdl.policy_no) AS `Previous Policy No`,
               date_format(mdl.policy_expiry_date,'%Y-%m-%d') AS `Policy Expiry Date`,
               'Email' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;
		
	ELSEIF p_disposition = 'Callback Scheduled' AND p_sub_disposition = 'Call on Specific Date' THEN
        SELECT p_next_call_datetime AS `Scheduled Date`,
			   -- mcd.vehicle_reg_no AS `Vehicle Number`,
               IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `Vehicle Number`,
               mdl.insurance_company AS `Previous Insurer`,
               IF(LENGTH(mdl.policy_no) > 4, CONCAT('xxxx', RIGHT(mdl.policy_no, 4)), mdl.policy_no) AS `Previous Policy No`,
               date_format(mdl.policy_expiry_date,'%Y-%m-%d') AS `Policy Expiry Date`,
               'Email' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;
	
    ELSEIF (p_disposition = 'Converted/ Won' AND p_sub_disposition = 'Policy Issued')
			OR (p_disposition = 'Converted/ Won' AND p_sub_disposition = 'Payment Received') THEN
        SELECT -- mcd.vehicle_reg_no AS `Vehicle Number`,
				IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `Vehicle Number`,
			'Email' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;
		
	ELSE
        SELECT 
               -- mcd.vehicle_reg_no AS `Vehicle Number`,
               IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `Vehicle Number`,
               mdl.insurance_company AS `Previous Insurer`,
               IF(LENGTH(mdl.policy_no) > 4, CONCAT('xxxx', RIGHT(mdl.policy_no, 4)), mdl.policy_no) AS `Previous Policy No`,
               date_format(mdl.policy_expiry_date,'%Y-%m-%d') AS `Policy Expiry Date`,
               'Email' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;	
    END IF;
	END IF;
    
    -- SMS placeholders
    IF p_communication_type = 'SMS' THEN
	IF (p_disposition = 'Converted/ Won' AND p_sub_disposition = 'Payment Received')
		OR (p_disposition = 'Converted/ Won' AND p_sub_disposition = 'Policy Issued') THEN
        SELECT 
			-- mcd.vehicle_reg_no AS `Vehicle Number`,
            IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `Vehicle Number`,
			'SMS' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;
		
    ELSEIF p_disposition = 'Callback Scheduled' AND p_sub_disposition = 'Call on Specific Date' THEN
        SELECT p_next_call_datetime AS `Scheduled Date`,
               -- mcd.vehicle_reg_no AS `Vehicle Number`,
               IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `Vehicle Number`,
			   IF(LENGTH(mdl.policy_no) > 4, CONCAT('xxxx', RIGHT(mdl.policy_no, 4)), mdl.policy_no) AS `Previous Policy No`,
			   mdl.insurance_company AS `Previous Insurer`,
			'SMS' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;

	ELSEIF p_disposition = 'Interested' AND p_sub_disposition = 'Ready to Pay' THEN
        SELECT -- mcd.vehicle_reg_no AS `Vehicle Number`,
			   IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `Vehicle Number`,
			   IF(LENGTH(mdl.policy_no) > 4, CONCAT('xxxx', RIGHT(mdl.policy_no, 4)), mdl.policy_no) AS `Previous Policy No`,
			   mdl.insurance_company AS `Previous Insurer`,
			'SMS' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id; 
		
	
	ELSEIF (p_disposition = 'Interested' AND p_sub_disposition = 'Awaiting Documents')
			OR (p_disposition = 'Interested' AND p_sub_disposition = 'Break-in survey') THEN
        SELECT 
			   -- mcd.vehicle_reg_no AS `Vehicle Number`,
			   IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `Vehicle Number`,
               IF(LENGTH(mdl.policy_no) > 4, CONCAT('xxxx', RIGHT(mdl.policy_no, 4)), mdl.policy_no) AS `Previous Policy No`,
			   mdl.insurance_company AS `Previous Insurer`,
			   date_format(mdl.policy_expiry_date,'%Y-%m-%d') AS `Policy Expiry Date`,
			'SMS' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;
	
	
    ELSEIF (p_disposition = 'Callback Scheduled' AND p_sub_disposition = 'Call Later Today')
			OR (p_disposition = 'Callback Scheduled' AND p_sub_disposition = 'Call Tomorrow') THEN
        SELECT 
			   -- mcd.vehicle_reg_no AS `Vehicle Number`,
               IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `Vehicle Number`,
               IF(LENGTH(mdl.policy_no) > 4, CONCAT('xxxx', RIGHT(mdl.policy_no, 4)), mdl.policy_no) AS `Previous Policy No`,
               mdl.insurance_company AS `Previous Insurer`,
               'SMS' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;
		
	ELSE
        SELECT IF(LENGTH(mdl.policy_no) > 4, CONCAT('xxxx', RIGHT(mdl.policy_no, 4)), mdl.policy_no) AS `Previous Policy No`,
			   mdl.insurance_company AS `Previous Insurer`,
               date_format(mdl.policy_expiry_date,'%Y-%m-%d') AS `Policy Expiry Date`,
			   -- mcd.vehicle_reg_no AS `Vehicle Number`,
               IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `Vehicle Number`,
               'SMS' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;
	
    END IF;
	END IF;
    
    -- WhatsApp placeholders
    IF p_communication_type = 'Whatsapp' THEN
	
	IF (p_disposition = 'Converted/ Won' AND p_sub_disposition = 'Policy Issued')
			OR (p_disposition = 'Converted/ Won' AND p_sub_disposition = 'Payment Received') THEN
        SELECT -- mcd.vehicle_reg_no AS `1`
			IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `1`
			-- 'Whatsapp' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;
	
	ELSEIF (p_disposition = 'Callback Scheduled' AND p_sub_disposition = 'Call Tomorrow') 
			OR (p_disposition = 'Callback Scheduled' AND p_sub_disposition = 'Call Later Today') THEN
        SELECT 
			   -- mcd.vehicle_reg_no AS `1`,
               IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `1`,
               mdl.insurance_company AS `2`,
               IF(LENGTH(mdl.policy_no) > 4, CONCAT('xxxx', RIGHT(mdl.policy_no, 4)), mdl.policy_no) AS `3`,
               date_format(mdl.policy_expiry_date,'%Y-%m-%d') AS `4`
               -- 'Whatsapp' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;
		
	ELSEIF p_disposition = 'Callback Scheduled' AND p_sub_disposition = 'Call on Specific Date'  THEN
        SELECT p_next_call_datetime AS `1`,
			   -- mcd.vehicle_reg_no AS `2`,
               IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `2`,
               mdl.insurance_company AS `3`,
               IF(LENGTH(mdl.policy_no) > 4, CONCAT('xxxx', RIGHT(mdl.policy_no, 4)), mdl.policy_no) AS `4`,
               date_format(mdl.policy_expiry_date,'%Y-%m-%d') AS `5`
               -- 'Whatsapp' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;	
	
	ELSEIF (p_disposition = 'Not Reachable' AND p_sub_disposition = 'Invalid Number') 
		OR (p_disposition = 'Not Reachable' AND p_sub_disposition = 'No Answer') THEN
        SELECT IF(LENGTH(mdl.policy_no) > 4, CONCAT('xxxx', RIGHT(mdl.policy_no, 4)), mdl.policy_no) AS `1`,
               date_format(mdl.policy_expiry_date,'%Y-%m-%d') AS `2`,
               '+91-22-66423800' AS `3`,
               'insurance.care@mahindrainsurancebrokers.com' AS `4`
               -- 'Whatsapp' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id;
	
    ELSE
        SELECT -- mcd.vehicle_reg_no AS `1`,
			   IF (mcd.vehicle_reg_no IS NOT NULL AND mcd.vehicle_reg_no != '',
				   CONCAT('Reg No. ',mcd.vehicle_reg_no),
                   CONCAT('Chassis No. ',mcd.chassis_no)
               ) AS `1`,
               mdl.insurance_company AS `2`,
               IF(LENGTH(mdl.policy_no) > 4, CONCAT('xxxx', RIGHT(mdl.policy_no, 4)), mdl.policy_no) AS `3`,
               date_format(mdl.policy_expiry_date,'%Y-%m-%d') AS `4`
               -- 'Whatsapp' AS `Communication Type`
        FROM mmi_lead_details mdl
        LEFT JOIN mmi_mast_customer_details mcd 
               ON mdl.cluster_id = mcd.cluster_id
        WHERE mdl.cluster_id = p_cluster_id; 
    END IF;
    END IF;

END ;;
DELIMITER ;
