CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_customer_details_for_ebm_communication`(
    IN p_cluster_id VARCHAR(100),
    IN p_ebm_status VARCHAR(100),
    IN p_communication_type VARCHAR(100),
    OUT p_status_code VARCHAR(500),
    OUT p_status_message VARCHAR(500)
)
BEGIN
    DECLARE err_code INT;
    DECLARE err_msg TEXT;
    DECLARE v_dealer_code VARCHAR(100);
    DECLARE v_dealer_communication VARCHAR(45);
    DECLARE v_customer_name VARCHAR(255);
    DECLARE v_mobile_no VARCHAR(20);
    DECLARE v_email VARCHAR(255);
    DECLARE v_vehicle_reg_no VARCHAR(100);
    DECLARE v_policy_no VARCHAR(200);
    DECLARE v_insurance_company VARCHAR(300);
    DECLARE v_policy_expiry_date VARCHAR(45);
    DECLARE v_ebm_status_color VARCHAR(45);
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
        
        SET p_status_code = '500';
        SET p_status_message = CONCAT('An error occurred: ', err_msg);
        
        ROLLBACK;
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_fetch_customer_details_for_ebm_communication', 'SEND_EBM_COMMUNICATION', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;
    
    
    -- dealer code and lead_details BY USING cluster_id
    SELECT mld.dealer_code, dd.communication 
    INTO v_dealer_code, v_dealer_communication
    FROM mmi_lead_details mld
    LEFT JOIN mmi_dealer_details dd ON mld.dealer_code = dd.dealer_id
    WHERE mld.cluster_id = p_cluster_id 
    ORDER BY mld.created_date DESC
    LIMIT 1;
    
    -- nullCheck for dealer exists
    IF v_dealer_code IS NULL THEN
        SET p_status_code = '404';
        SET p_status_message = 'Dealer not found for this cluster';
    ELSE
        -- nullCheck for communication type is supported by dealer
        IF (p_communication_type = 'Email' AND FIND_IN_SET('Email', v_dealer_communication) = 0) OR
           (p_communication_type = 'SMS' AND FIND_IN_SET('SMS', v_dealer_communication) = 0) OR
           (p_communication_type = 'WhatsApp' AND FIND_IN_SET('WhatsApp', v_dealer_communication) = 0) THEN
           
            SET p_status_code = '400';
            SET p_status_message = CONCAT('Communication type "', p_communication_type, '" not supported by dealer');
        ELSE
            -- customer and lead details BY USING cluster_id
            SELECT 
                mcd.customer_name,
                COALESCE(
                    (SELECT customer_phone FROM mmi_mast_customer_details 
                     WHERE cluster_id = p_cluster_id AND customer_phone IS NOT NULL 
                     ORDER BY created_date DESC LIMIT 1),
                    mcd.customer_phone
                ) AS customer_phone,
                COALESCE(
                    (SELECT customer_email FROM mmi_mast_customer_details 
                     WHERE cluster_id = p_cluster_id AND customer_email IS NOT NULL 
                     ORDER BY created_date DESC LIMIT 1),
                    mcd.customer_email
                ) AS customer_email,
                mcd.vehicle_reg_no,
                mld.policy_no,
                mld.insurance_company,
                mld.policy_expiry_date,
                mes.ebm_status_color
            INTO 
                v_customer_name,
                v_mobile_no,
                v_email,
                v_vehicle_reg_no,
                v_policy_no,
                v_insurance_company,
                v_policy_expiry_date,
                v_ebm_status_color
            FROM mmi_mast_customer_details mcd
            LEFT JOIN mmi_lead_details mld ON mld.cluster_id = mcd.cluster_id
            LEFT JOIN mmi_mast_ebm_status mes ON mes.sub_ebm_status = p_ebm_status
            WHERE mcd.cluster_id = p_cluster_id
            ORDER BY mld.created_date DESC
            LIMIT 1;
            
            -- customer data nullCheck
            IF v_customer_name IS NULL THEN
                SET p_status_code = '404';
                SET p_status_message = 'Customer details not found';
            ELSE
                -- Email placeholders
                IF p_communication_type = 'Email' THEN 
                    IF p_ebm_status IN ('Quote Shared', 'Insurer Selected', 'Declaration Acknowledged') THEN
                        SELECT 
                            v_customer_name AS `Customer Name`,
                            v_policy_no AS `Policy Number`,
                            v_insurance_company AS `Insurance Company`,
                            DATE_FORMAT(v_policy_expiry_date, '%Y-%m-%d') AS `Policy Expiry Date`,
                            p_ebm_status AS `EBM Status`,
                            'insurance.care@mahindrainsurancebrokers.com' AS `Support Email`,
                            '+91-22-66423800' AS `Support Contact`,
                            'Email' AS `Communication Type`
                        FROM dual;
                        
                    ELSEIF p_ebm_status IN ('CKYC Completed', 'Proposal Confirmed') THEN
                        SELECT 
                            v_customer_name AS `Customer Name`,
                            v_policy_no AS `Policy Number`,
                            IF(v_vehicle_reg_no IS NOT NULL AND v_vehicle_reg_no != '',
                                CONCAT('Reg No. ', v_vehicle_reg_no),
                                CONCAT('Policy No. ', v_policy_no)
                            ) AS `Vehicle Details`,
                            p_ebm_status AS `EBM Status`,
                            DATE_FORMAT(NOW(), '%Y-%m-%d') AS `Current Date`,
                            'Email' AS `Communication Type`
                        FROM dual;
                        
                    ELSEIF p_ebm_status IN ('Payment Completed', 'Policy Issued', 'Policy Booked') THEN
                        SELECT 
                            v_customer_name AS `Customer Name`,
                            IF(v_vehicle_reg_no IS NOT NULL AND v_vehicle_reg_no != '',
                                CONCAT('Reg No. ', v_vehicle_reg_no),
                                CONCAT('Policy No. ', v_policy_no)
                            ) AS `Vehicle/Policy Number`,
                            p_ebm_status AS `EBM Status`,
                            DATE_FORMAT(NOW(), '%Y-%m-%d') AS `Completion Date`,
                            'Email' AS `Communication Type`
                        FROM dual;
                        
                    ELSE
                        -- Default for any other EBM status
                        SELECT 
                            v_customer_name AS `Customer Name`,
                            v_policy_no AS `Policy Number`,
                            v_insurance_company AS `Insurance Company`,
                            p_ebm_status AS `EBM Status`,
                            DATE_FORMAT(NOW(), '%Y-%m-%d') AS `Date`,
                            'Email' AS `Communication Type`
                        FROM dual;
                    END IF;
                END IF;
                
                -- SMS placeholders
                IF p_communication_type = 'SMS' THEN
                    IF p_ebm_status IN ('Quote Shared', 'Insurer Selected') THEN
                        SELECT 
                            v_customer_name AS `Customer Name`,
                            v_policy_no AS `Policy Number`,
                            p_ebm_status AS `Status`,
                            DATE_FORMAT(NOW(), '%d/%m/%Y') AS `Date`,
                            'SMS' AS `Communication Type`
                        FROM dual;
                        
                    ELSEIF p_ebm_status IN ('Declaration Acknowledged', 'CKYC Completed') THEN
                        SELECT 
                            v_customer_name AS `Customer Name`,
                            IF(v_vehicle_reg_no IS NOT NULL AND v_vehicle_reg_no != '',
                                CONCAT('Reg No. ', v_vehicle_reg_no),
                                CONCAT('Policy: ', v_policy_no)
                            ) AS `Vehicle/Policy`,
                            p_ebm_status AS `Status`,
                            DATE_FORMAT(NOW(), '%d/%m/%Y') AS `Date`,
                            'SMS' AS `Communication Type`
                        FROM dual;
                        
                    ELSEIF p_ebm_status IN ('Proposal Confirmed', 'Payment Completed') THEN
                        SELECT 
                            v_customer_name AS `Customer Name`,
                            v_policy_no AS `Policy No`,
                            p_ebm_status AS `Status`,
                            DATE_FORMAT(NOW(), '%d/%m/%Y') AS `Date`,
                            'SMS' AS `Communication Type`
                        FROM dual;
                        
                    ELSEIF p_ebm_status IN ('Policy Issued', 'Policy Booked') THEN
                        SELECT 
                            v_customer_name AS `Customer Name`,
                            IF(v_vehicle_reg_no IS NOT NULL AND v_vehicle_reg_no != '',
                                CONCAT('Reg No. ', v_vehicle_reg_no),
                                CONCAT('Policy: ', v_policy_no)
                            ) AS `Details`,
                            p_ebm_status AS `Status`,
                            DATE_FORMAT(NOW(), '%d/%m/%Y') AS `Date`,
                            'SMS' AS `Communication Type`
                        FROM dual;
                        
                    ELSE
                        -- Default SMS
                        SELECT 
                            v_customer_name AS `Customer Name`,
                            v_policy_no AS `Policy No`,
                            p_ebm_status AS `Status`,
                            DATE_FORMAT(NOW(), '%d/%m/%Y') AS `Date`,
                            'SMS' AS `Communication Type`
                        FROM dual;
                    END IF;
                END IF;
                
                -- WhatsApp placeholders
                IF p_communication_type = 'WhatsApp' THEN
                    IF p_ebm_status IN ('Quote Shared', 'Insurer Selected') THEN
                        SELECT 
                            v_customer_name AS `1`,
                            v_policy_no AS `2`,
                            p_ebm_status AS `3`,
                            DATE_FORMAT(NOW(), '%d/%m/%Y') AS `4`,
                            'WhatsApp' AS `Communication Type`
                        FROM dual;
                        
                    ELSEIF p_ebm_status IN ('Declaration Acknowledged', 'CKYC Completed') THEN
                        SELECT 
                            v_customer_name AS `1`,
                            IF(v_vehicle_reg_no IS NOT NULL AND v_vehicle_reg_no != '',
                                CONCAT('Reg No. ', v_vehicle_reg_no),
                                CONCAT('Policy: ', v_policy_no)
                            ) AS `2`,
                            p_ebm_status AS `3`,
                            DATE_FORMAT(NOW(), '%d/%m/%Y') AS `4`,
                            'WhatsApp' AS `Communication Type`
                        FROM dual;
                        
                    ELSEIF p_ebm_status IN ('Proposal Confirmed', 'Payment Completed') THEN
                        SELECT 
                            v_customer_name AS `1`,
                            v_policy_no AS `2`,
                            p_ebm_status AS `3`,
                            DATE_FORMAT(NOW(), '%d/%m/%Y') AS `4`,
                            'WhatsApp' AS `Communication Type`
                        FROM dual;
                        
                    ELSEIF p_ebm_status IN ('Policy Issued', 'Policy Booked') THEN
                        SELECT 
                            v_customer_name AS `1`,
                            IF(v_vehicle_reg_no IS NOT NULL AND v_vehicle_reg_no != '',
                                CONCAT('Reg No. ', v_vehicle_reg_no),
                                CONCAT('Policy: ', v_policy_no)
                            ) AS `2`,
                            p_ebm_status AS `3`,
                            DATE_FORMAT(NOW(), '%d/%m/%Y') AS `4`,
                            'WhatsApp' AS `Communication Type`
                        FROM dual;
                        
                    ELSE
                        -- Default WhatsApp
                        SELECT 
                            v_customer_name AS `1`,
                            v_policy_no AS `2`,
                            p_ebm_status AS `3`,
                            DATE_FORMAT(NOW(), '%d/%m/%Y') AS `4`,
                            'WhatsApp' AS `Communication Type`
                        FROM dual;
                    END IF;
                END IF;
            END IF;
        END IF;
        
       /* INSERT INTO mmi_insert_log_details (service_name,user_id,log_payload,
		service_type,created_by,created_date) 
		VALUES ('mmi_proc_save_disposition_details',v_created_user_id,
		p_json_data,'INSERT',v_created_user_id,CURRENT_TIMESTAMP(3)); */
    END IF;
END ;;
DELIMITER ;
