DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_ebm_comm_placeholders`(
    IN p_cluster_id VARCHAR(100),
    IN p_communication_type VARCHAR(50)
)
BEGIN
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code,
            error_message,
            procedure_name,
            procedure_type,
            error_timing,
            created_by,
            created_date
        ) VALUES (
            err_code,
            err_msg,
            'mmi_proc_fetch_ebm_comm_placeholders',
            'SEND_EBM_COMMUNICATION',
            CURRENT_TIMESTAMP(),
            'SYSTEM',
            NOW()
        );
    END;

    START TRANSACTION;

    /*
      ONLY required dynamic values:
      DEALER_NAME
      DYNAMIC_URL
    */

    SELECT
        COALESCE(mdl.dealer, '') AS DEALER_NAME,
        COALESCE(tx.dynamic_url, '') AS DYNAMIC_URL
    FROM mmi_lead_details mdl
    LEFT JOIN mmi_crm_ebm_transaction_details tx
           ON tx.lead_id = mdl.lead_id
          AND tx.id = (
                SELECT MAX(id)
                FROM mmi_crm_ebm_transaction_details
                WHERE lead_id = mdl.lead_id
           )
    WHERE mdl.cluster_id = p_cluster_id
    LIMIT 1;

    COMMIT;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_fetch_ebm_comm_template` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_ebm_comm_template`(
    IN p_lead_id INT,
    IN p_ebm_status VARCHAR(100),
    IN p_communication_type VARCHAR(50),
    OUT p_status_code VARCHAR(50),
    OUT p_status_message VARCHAR(255)
)
proc_main: BEGIN

    DECLARE v_cluster_id VARCHAR(100);
    DECLARE v_dealer_code VARCHAR(100);
    DECLARE v_dealer_modes VARCHAR(200);
    DECLARE v_template_body TEXT;
    DECLARE v_template_id VARCHAR(100);
    DECLARE v_template_subject VARCHAR(255);

    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1 err_code = MYSQL_ERRNO, err_msg = MESSAGE_TEXT;
        SET p_status_code = '500';
        SET p_status_message = err_msg;
    END;

    -- Lead → dealer + cluster
    SELECT cluster_id, dealer_code
    INTO v_cluster_id, v_dealer_code
    FROM mmi_lead_details
    WHERE lead_id = p_lead_id
    LIMIT 1;

    IF v_dealer_code IS NULL THEN
        SET p_status_code = '404';
        SET p_status_message = 'Lead not found';
        LEAVE proc_main;
    END IF;

    -- Dealer communication modes
    SELECT communication INTO v_dealer_modes
    FROM mmi_dealer_details
    WHERE dealer_id = v_dealer_code
    LIMIT 1;

    IF FIND_IN_SET(p_communication_type, v_dealer_modes) = 0 THEN
        SET p_status_code = '400';
        SET p_status_message = 'Dealer does not support this communication mode';
        LEAVE proc_main;
    END IF;

    -- Template fetch
    SELECT template_body, template_id, template_subject
    INTO v_template_body, v_template_id, v_template_subject
    FROM mmi_ebm_communication_templates
    WHERE ebm_status = p_ebm_status
      AND communication_type = p_communication_type
      AND is_active = 1
    LIMIT 1;

    IF v_template_body IS NULL THEN
        SET p_status_code = '404';
        SET p_status_message = 'Template not configured';
        LEAVE proc_main;
    END IF;

    -- Placeholder data
    SELECT
        mcd.customer_name,
        mcd.customer_phone,
        mcd.customer_email,
        ld.policy_no,
        ld.vehicle_class,
        v_template_body,
        v_template_subject,
        v_template_id,
        p_communication_type AS communication_type
    FROM mmi_mast_customer_details mcd
    JOIN mmi_lead_details ld ON ld.cluster_id = mcd.cluster_id
    WHERE ld.lead_id = p_lead_id
    LIMIT 1;

    SET p_status_code = '200';
    SET p_status_message = 'Success';

END ;;
