DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_leaderBoard_details`(
    IN p_json JSON,
    OUT p_status_code INT,
    OUT p_status_message VARCHAR(255)
)
BEGIN

    DECLARE v_type VARCHAR(45);
    DECLARE v_from_date VARCHAR(450);
    DECLARE v_to_date VARCHAR(450);
    DECLARE v_segment VARCHAR(100);
    DECLARE v_renewal_category VARCHAR(1000);
    DECLARE v_dealer_code VARCHAR(2000);
    DECLARE v_role_type VARCHAR(45);
    DECLARE v_check_type VARCHAR(45);    
    DECLARE v_zone VARCHAR(45);
    DECLARE v_state VARCHAR(500);
    DECLARE v_dealerLocCode VARCHAR(450);
    DECLARE v_check_ratio VARCHAR(450);
    DECLARE v_rank_filter VARCHAR(450);
	-- DECLARE v_userId VARCHAR(450);     
	-- DECLARE v_dealerCode VARCHAR(450);
    
    DECLARE calculated INT DEFAULT 0;
    DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 0;

    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        -- ROLLBACK;

        SET p_status_code = 500;
        SET p_status_message = 'An error occurred. Please try again.';

        INSERT INTO mmi_mast_procedure_error
        (
            error_code,
            error_message,
            procedure_name,
            procedure_type,
            error_timing,
            created_by,
            created_date
        )
        VALUES
        (
            err_code,
            err_msg,
            'mmi_proc_fetch_leaderBoard_details',
            'FETCH_LEADERBOARD_DETAILS',
            CURRENT_TIMESTAMP(),
            'SYSTEM',
            NOW()
        );
    END;

    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(p_json,'$.type'));
    
    SET v_renewal_category = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.renewalCategory'));
    SET v_zone = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.zone'));
	SET v_state = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.state'));
	SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.dealerCode'));
	SET v_dealerLocCode = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.dealerLocCode'));
    -- SET v_from_date = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_json,'$.fromDate')), '');
	-- SET v_to_date   = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_json,'$.toDate')), '');
    -- SET v_from_date = STR_TO_DATE(JSON_UNQUOTE(JSON_EXTRACT(p_json,'$.fromDate')),'%Y-%m-%d');
    -- SET v_to_date = STR_TO_DATE(JSON_UNQUOTE(JSON_EXTRACT(p_json,'$.toDate')),'%Y-%m-%d');
    SET v_from_date = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.fromDate'));
    SET v_to_date   = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.toDate'));
    SET v_role_type  = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.roleType'));
    -- SET v_userId  = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.loginUserId'));
    SET v_segment = JSON_UNQUOTE(JSON_EXTRACT(p_json,'$.segment'));
    SET v_check_type = JSON_UNQUOTE(JSON_EXTRACT(p_json,'$.checkType'));
    SET v_check_ratio = JSON_UNQUOTE(JSON_EXTRACT(p_json,'$.checkRatio'));
    SET v_rank_filter = JSON_UNQUOTE(JSON_EXTRACT(p_json,'$.rankFilter'));
    
    SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.limit')) AS UNSIGNED), 10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.offset')) AS UNSIGNED), 0);
    -- SET calculated = (offsetVal - 1) * limitVal;
    SET calculated = GREATEST((offsetVal - 1) * limitVal,0);

IF v_role_type = 'MIBL' THEN

IF v_type = 'downloadLeaderBoardFilteredData' THEN

WITH lead_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT mld.lead_id) AS leadsAssigned
    FROM mmi_lead_details mld
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code 	
    WHERE mld.assigned_agent is not null AND
        (v_dealer_code IS NULL OR v_dealer_code = '' OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))

        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))

        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
        AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(dlm.zone, v_zone))
        AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(dloc.state, v_state))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))

    GROUP BY mld.assigned_agent,mld.dealer_code
),
lead_archive_stats AS (
	SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT mld.lead_id) AS leadsAssigned
    FROM mmi_lead_archive_details mld
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    WHERE 
        -- (v_dealer_code IS NULL OR v_dealer_code='' OR mld.dealer_code=v_dealer_code)
        (v_dealer_code IS NULL OR v_dealer_code='' OR FIND_IN_SET(TRIM(mld.dealer_code),v_dealer_code))

        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))

        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
        AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(dlm.zone, v_zone))
        AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(dloc.state, v_state))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
		and assigned_agent is not null
    GROUP BY mld.assigned_agent,mld.dealer_code
),

call_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
        ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_details mld ON mld.lead_id = cdh.lead_id
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    WHERE
        (v_dealer_code IS NULL OR v_dealer_code='' OR FIND_IN_SET(TRIM(mld.dealer_code),v_dealer_code))

        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))

        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
        AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone),v_zone))
        AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state),v_state))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' 
             OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))

    GROUP BY mld.assigned_agent,mld.dealer_code
),

lead_archive_call AS (
	SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
        ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_archive_details mld ON mld.lead_id = cdh.lead_id
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    WHERE
        (v_dealer_code IS NULL OR v_dealer_code='' OR FIND_IN_SET(TRIM(mld.dealer_code),v_dealer_code))

        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))

        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
        AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone),v_zone))
        AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state),v_state))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' 
             OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))

    GROUP BY mld.assigned_agent,mld.dealer_code
),

eligible_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT mld.lead_id) AS eligibleLeads
    FROM mmi_lead_details mld
    JOIN mmi_call_disposition_history cdh 
        ON cdh.lead_id = mld.lead_id
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    WHERE
        (v_dealer_code IS NULL OR v_dealer_code='' OR FIND_IN_SET(TRIM(mld.dealer_code),v_dealer_code))

        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))

        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
        AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone),v_zone))
        AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state),v_state))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' 
             OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))    

    GROUP BY mld.assigned_agent,mld.dealer_code
),

conversion_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT policy_no) AS policiesConverted,
        COUNT(DISTINCT CASE 
            WHEN lead_status='Won' AND converted_flag='CRM Renewal'
            THEN lead_id END) AS conversionCount
    FROM mmi_lead_archive_details mld
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    WHERE
        (v_dealer_code IS NULL OR v_dealer_code='' OR FIND_IN_SET(TRIM(mld.dealer_code),v_dealer_code))

        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))

        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
        AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone),v_zone))
        AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state),v_state))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' 
             OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))

    GROUP BY mld.assigned_agent,mld.dealer_code
),

disposition_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        SUM(CASE WHEN disp.disposition_count >= 2 THEN 1 ELSE 0 END) AS swiftConverter
    FROM (
        SELECT lead_id, dealer_id, COUNT(*) disposition_count
        FROM mmi_call_disposition_history
        GROUP BY lead_id, dealer_id
    ) disp
    JOIN mmi_lead_details mld ON mld.lead_id = disp.lead_id
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    WHERE
        (v_dealer_code IS NULL OR v_dealer_code='' OR FIND_IN_SET(TRIM(mld.dealer_code),v_dealer_code))

        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))

        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
        AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone),v_zone))
        AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state),v_state))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' 
             OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))    
    GROUP BY mld.assigned_agent,mld.dealer_code
),

top_converter_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT mld.lead_id) AS topConverterCount
    FROM mmi_lead_archive_details mld
    JOIN mmi_call_disposition_history cdh
        ON cdh.lead_id = mld.lead_id
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    WHERE mld.lead_status = 'Won'
        AND DATEDIFF(CURDATE(), cdh.created_date) <= 7 AND
        (v_dealer_code IS NULL OR v_dealer_code='' OR FIND_IN_SET(TRIM(mld.dealer_code),v_dealer_code))

        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))

        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
        AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone),v_zone))
        AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state),v_state))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' 
             OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))    
    GROUP BY mld.assigned_agent,mld.dealer_code
),

premium_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        SUM(mmd.net_premium) AS netPremium
    FROM mmi_lead_archive_details mld
    JOIN mmi_ebm_policy_data mmd
        ON mld.policy_no = mmd.previous_policy_no
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    WHERE mld.lead_status = 'Won'
        AND 
        (v_dealer_code IS NULL OR v_dealer_code='' OR FIND_IN_SET(TRIM(mld.dealer_code),v_dealer_code))

        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))

        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
        AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone),v_zone))
        AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state),v_state))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' 
             OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))   
    GROUP BY mld.assigned_agent,mld.dealer_code
),

breach_stats AS (
    SELECT 
        mld.assigned_agent,
        COUNT(DISTINCT lb.lead_id) AS breachedLeads
    FROM mmi_lead_breached lb
    JOIN mmi_lead_details mld 
        ON mld.lead_id = lb.lead_id
	LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    WHERE mld.lead_status = 'Won'
        AND 
        (v_dealer_code IS NULL OR v_dealer_code='' OR FIND_IN_SET(TRIM(mld.dealer_code),v_dealer_code))

        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))

        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
        AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone),v_zone))
        AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state),v_state))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' 
             OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ',''))) 	
    GROUP BY mld.assigned_agent
),

addon_sales AS (
            SELECT ld.assigned_agent AS assigned_agent,
                   COUNT(pad.id) AS AddonSales
            FROM mmi_poladdon_data pad
            JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE (v_dealer_code IS NULL OR v_dealer_code='' OR FIND_IN_SET(ld.dealer_code, REPLACE(v_dealer_code,' ','')))

			AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
			OR
			(v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
			 AND (ld.created_date BETWEEN v_from_date AND v_to_date
				  OR ld.modified_date BETWEEN v_from_date AND v_to_date)))

			AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class),v_segment))
			AND (v_renewal_category IS NULL OR v_renewal_category='' 
				 OR FIND_IN_SET(TRIM(ld.renewal_category),v_renewal_category))
			AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone),v_zone))
			AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state),v_state))
			AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' 
				 OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))
            GROUP BY ld.assigned_agent
)

SELECT
    md.dealer_code as dealerCode,
    md.dealer_name as dealerName,
	urd.id as agentId,
    concat(urd.first_name,' ', urd.last_name) as agentName,
    COALESCE(ls.leadsAssigned, 0) + COALESCE(las.leadsAssigned, 0) as leadsAssigned,
    COALESCE(cs.leadsContacted, 0) + COALESCE(lac.leadsContacted, 0) as leadsContacted,
    IFNULL(conv.policiesConverted,0) policiesConverted,
    IFNULL(ps.netPremium,0) netPremium,
	ROUND(
        NULLIF(bs.breachedLeads, 0)/NULLIF(COALESCE(ls.leadsAssigned, 0) + COALESCE(las.leadsAssigned, 0),0) * 100,
    2) AS followup,

    CASE 
        WHEN v_check_ratio='Conversion Rate'
        THEN ROUND(IFNULL(conv.conversionCount,0) /
             NULLIF(COALESCE(cs.leadsContacted, 0) + COALESCE(lac.leadsContacted, 0),0) * 100 ,2)

        WHEN v_check_ratio='Retention Rate'
        THEN ROUND(IFNULL(conv.policiesConverted,0) /
             NULLIF(COALESCE(ls.leadsAssigned, 0) + COALESCE(las.leadsAssigned, 0),0) * 100 ,2)
    END AS ratio,

    RANK() OVER(
        ORDER BY
        CASE 
            WHEN v_rank_filter = 'Top Converter / Conversion Rate'
            THEN IFNULL(tc.topConverterCount,0)

            WHEN v_rank_filter = 'Swift Converter'
            THEN IFNULL(ds.swiftConverter,0)

            WHEN v_rank_filter='Net Premium Leader'
            THEN IFNULL(ps.netPremium,0)
			
			WHEN v_rank_filter='Follow-up'
			THEN ROUND(NULLIF(bs.breachedLeads, 0)/NULLIF(COALESCE(ls.leadsAssigned, 0) + COALESCE(las.leadsAssigned, 0),0) * 100,2)
			
			WHEN v_rank_filter='Addon Sales'
            THEN IFNULL(ads.addonSales,0)
			
            ELSE IFNULL(conv.policiesConverted,0) /
                 NULLIF(es.eligibleLeads,0)
        END DESC
    ) AS rankPosition

FROM mmi_dealer_location_mapping md
JOIN lead_stats ls ON ls.dealer_code = md.dealer_code
LEFT JOIN mmi_mast_user_registration_detail urd on urd.id = ls.assigned_agent
LEFT JOIN call_stats cs ON cs.assigned_agent = urd.id 
LEFT JOIN eligible_stats es ON es.assigned_agent = urd.id 
LEFT JOIN conversion_stats conv ON conv.assigned_agent = urd.id 
LEFT JOIN premium_stats ps ON ps.assigned_agent = urd.id 
LEFT JOIN top_converter_stats tc ON tc.assigned_agent = urd.id 
LEFT JOIN disposition_stats ds ON ds.assigned_agent = urd.id 
LEFT JOIN lead_archive_stats las ON las.assigned_agent = urd.id 
LEFT JOIN lead_archive_call lac ON lac.assigned_agent = urd.id
LEFT JOIN breach_stats bs ON bs.assigned_agent = urd.id
LEFT JOIN addon_sales ads ON ads.assigned_agent = urd.id;

SET p_status_code = 200;
SET p_status_message = 'LeaderBoard filter details download';


ELSEIF v_type = 'downloadLeaderBoardData' THEN 

WITH lead_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT mld.lead_id) AS leadsAssigned
    FROM mmi_lead_details mld
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
	WHERE mld.assigned_agent is not null	
    GROUP BY mld.dealer_code,mld.assigned_agent
),
lead_archive_stats AS (
	SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT mld.lead_id) AS leadsAssigned
    FROM mmi_lead_archive_details mld
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    WHERE assigned_agent is not null    
    GROUP BY mld.dealer_code,mld.assigned_agent
),
lead_archive_call AS (
	SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
        ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_archive_details mld ON mld.lead_id = cdh.lead_id
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    GROUP BY mld.dealer_code,mld.assigned_agent
),

call_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
        ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_details mld ON mld.lead_id = cdh.lead_id
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    GROUP BY mld.dealer_code,mld.assigned_agent
),

eligible_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT mld.lead_id) AS eligibleLeads
    FROM mmi_lead_details mld
    JOIN mmi_call_disposition_history cdh 
        ON cdh.lead_id = mld.lead_id
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    GROUP BY mld.dealer_code,mld.assigned_agent
),

conversion_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT policy_no) AS policiesConverted,
        COUNT(DISTINCT CASE 
            WHEN lead_status='Won' AND converted_flag='CRM Renewal'
            THEN lead_id END) AS conversionCount
    FROM mmi_lead_archive_details mld
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    GROUP BY mld.dealer_code,mld.assigned_agent
),

disposition_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        SUM(CASE WHEN disp.disposition_count >= 2 THEN 1 ELSE 0 END) AS swiftConverter
    FROM (
        SELECT lead_id, dealer_id, COUNT(*) disposition_count
        FROM mmi_call_disposition_history
        GROUP BY lead_id, dealer_id
    ) disp
    JOIN mmi_lead_details mld ON mld.lead_id = disp.lead_id
    GROUP BY mld.dealer_code,mld.assigned_agent
),

top_converter_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT mld.lead_id) AS topConverterCount
    FROM mmi_lead_archive_details mld
    JOIN mmi_call_disposition_history cdh
        ON cdh.lead_id = mld.lead_id
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    WHERE mld.lead_status = 'Won'
        AND DATEDIFF(CURDATE(), cdh.created_date) <= 7    
    GROUP BY mld.dealer_code,mld.assigned_agent
),

premium_stats AS (
    SELECT
		mld.assigned_agent,
        mld.dealer_code,
        SUM(mmd.net_premium) AS netPremium
    FROM mmi_lead_archive_details mld
    JOIN mmi_ebm_policy_data mmd
        ON mld.policy_no = mmd.previous_policy_no
    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code
    WHERE mld.lead_status = 'Won'
    GROUP BY mld.assigned_agent,mld.dealer_code
),

breach_stats AS (
    SELECT 
        mld.assigned_agent,
        COUNT(DISTINCT lb.lead_id) AS breachedLeads
    FROM mmi_lead_breached lb
    JOIN mmi_lead_details mld 
        ON mld.lead_id = lb.lead_id
	LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.mapping_dealer_code = mld.dealer_code
    LEFT JOIN mmi_mast_dealer_location dloc 
        ON dloc.loc_code = dlm.location_code	
    GROUP BY mld.assigned_agent
),

addon_sales AS (
            SELECT ld.assigned_agent AS assigned_agent,
                   COUNT(pad.id) AS AddonSales
            FROM mmi_poladdon_data pad
            JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            GROUP BY ld.assigned_agent
)

SELECT 
    md.dealer_code as dealerCode,
    md.dealer_name as dealerName,
	urd.id as agentId,
    concat(urd.first_name,' ', urd.last_name) as agentName,
    COALESCE(ls.leadsAssigned, 0) + COALESCE(las.leadsAssigned, 0) as leadsAssigned,
    COALESCE(cs.leadsContacted, 0) + COALESCE(lac.leadsContacted, 0) as leadsContacted,
    IFNULL(conv.policiesConverted,0) policiesConverted,
    IFNULL(ps.netPremium,0) netPremium,
	ROUND(
        NULLIF(bs.breachedLeads, 0)/NULLIF(COALESCE(ls.leadsAssigned, 0) + COALESCE(las.leadsAssigned, 0),0) * 100,
    2) AS followup,

   CASE 
        WHEN v_check_ratio='Conversion Rate'
        THEN ROUND(IFNULL(conv.conversionCount,0) /
             NULLIF(COALESCE(cs.leadsContacted, 0) + COALESCE(lac.leadsContacted, 0),0) * 100 ,2)

        WHEN v_check_ratio='Retention Rate'
        THEN ROUND(IFNULL(conv.policiesConverted,0) /
             NULLIF(COALESCE(ls.leadsAssigned, 0) + COALESCE(las.leadsAssigned, 0),0) * 100 ,2)
    END AS ratio,

    RANK() OVER(
        ORDER BY
        CASE 
            WHEN v_rank_filter = 'Top Converter / Conversion Rate'
            THEN IFNULL(tc.topConverterCount,0)

            WHEN v_rank_filter = 'Swift Converter'
            THEN IFNULL(ds.swiftConverter,0)

            WHEN v_rank_filter='Net Premium Leader'
            THEN IFNULL(ps.netPremium,0)
			
			WHEN v_rank_filter='Follow-up'
			THEN ROUND(NULLIF(bs.breachedLeads, 0)/NULLIF(COALESCE(ls.leadsAssigned, 0) + COALESCE(las.leadsAssigned, 0),0) * 100,2)
			
			WHEN v_rank_filter='Addon Sales'
            THEN IFNULL(ads.addonSales,0)
			
            ELSE IFNULL(conv.policiesConverted,0) /
                 NULLIF(es.eligibleLeads,0)
        END DESC
    ) AS rankPosition

FROM mmi_dealer_location_mapping md
JOIN lead_stats ls ON ls.dealer_code = md.dealer_code
LEFT JOIN mmi_mast_user_registration_detail urd on urd.id = ls.assigned_agent
LEFT JOIN call_stats cs ON cs.assigned_agent = urd.id 
LEFT JOIN eligible_stats es ON es.assigned_agent = urd.id 
LEFT JOIN conversion_stats conv ON conv.assigned_agent = urd.id 
LEFT JOIN premium_stats ps ON ps.assigned_agent = urd.id 
LEFT JOIN top_converter_stats tc ON tc.assigned_agent = urd.id 
LEFT JOIN disposition_stats ds ON ds.assigned_agent = urd.id 
LEFT JOIN lead_archive_stats las ON las.assigned_agent = urd.id 
LEFT JOIN lead_archive_call lac ON lac.assigned_agent = urd.id
LEFT JOIN breach_stats bs ON bs.assigned_agent = urd.id
LEFT JOIN addon_sales ads ON ads.assigned_agent = urd.id;

