WITH disposition_stats AS (
    SELECT 
        lead_id,
        dealer_id,
        COUNT(*) AS disposition_count
    FROM mmi_call_disposition_history
    GROUP BY lead_id, dealer_id
),

total_leads AS (
    SELECT dealer,dealer_code, COUNT(DISTINCT lead_id) AS totalLeads
    FROM (
        SELECT dealer,dealer_code, lead_id FROM mmi_lead_details where assigned_agent is not null
        UNION ALL
        SELECT dealer,dealer_code, lead_id FROM mmi_lead_archive_details where assigned_agent is not null
    ) t
    GROUP BY dealer_code,dealer
),

rank_base AS (
    SELECT
        la.dealer,
        la.dealer_code,

        SUM(epd.net_premium) AS netPremium,
        
        COUNT(DISTINCT CASE 
            WHEN la.lead_status = 'Won'
             AND la.converted_flag = 'CRM Renewal'
            THEN la.lead_id
        END) AS conversionCount,

        COUNT(DISTINCT la.policy_no) AS policiesConverted,

        COUNT(DISTINCT CASE 
            WHEN la.lead_status='Won'
             AND DATEDIFF(CURDATE(), dh.created_date) <= 7
            THEN la.lead_id
        END) AS topConverterCount,

        SUM(CASE 
            WHEN disp.disposition_count >= 2 THEN 1 
            ELSE 0 
        END) AS swiftConverter

    FROM mmi_lead_archive_details la

    LEFT JOIN mmi_ebm_policy_data epd 
        ON epd.previous_policy_no = la.policy_no

    LEFT JOIN mmi_call_disposition_history dh
        ON dh.lead_id = la.lead_id
        AND dh.dealer_id = la.dealer_code

    LEFT JOIN disposition_stats disp
        ON disp.lead_id = la.lead_id
        AND disp.dealer_id = la.dealer_code

    GROUP BY la.dealer, la.dealer_code
)

SELECT
    'Best in India' AS Name,

    ROW_NUMBER() OVER(
        ORDER BY 
            CASE 
                WHEN v_check_ratio = 'Conversion Rate' THEN
                    rb.conversionCount * 100.0 / NULLIF(lc.totalleadContacted, 0)

                WHEN v_check_ratio = 'Retention Rate' THEN
                    rb.policiesConverted * 100.0 / NULLIF(tl.totalLeads, 0)
            END DESC
    ) AS agent_rank,

    rb.dealer,
    rb.dealer_code
FROM rank_base rb
LEFT JOIN total_leads tl 
    ON rb.dealer_code = tl.dealer_code AND rb.dealer = tl.dealer
LEFT JOIN
(
	SELECT
        dealer,
		dealer_code,
		COUNT(DISTINCT lead_id) AS totalleadContacted
    FROM (
    SELECT
        dealer,
		dealer_code,
        cdh.lead_id
    FROM mmi_call_disposition_history cdh left join
    mmi_lead_details mld on mld.lead_id = cdh.lead_id
    WHERE assigned_agent IS NOT NULL    
    UNION
    SELECT
        dealer,
		dealer_code,
        cdh.lead_id
    FROM mmi_call_disposition_history cdh left join
    mmi_lead_archive_details mld on mld.lead_id = cdh.lead_id
    WHERE assigned_agent IS NOT NULL
    ) combined
    Group by dealer_code,dealer
) lc
ON tl.dealer_code = lc.dealer_code
LIMIT 3;


WITH disposition_stats AS (
    SELECT 
        lead_id,
        dealer_id,
        COUNT(*) AS disposition_count
    FROM mmi_call_disposition_history
    GROUP BY lead_id, dealer_id
),

total_leads AS (
    SELECT dealer,dealer_code, COUNT(DISTINCT lead_id) AS totalLeads
    FROM (
        SELECT dealer,dealer_code, lead_id FROM mmi_lead_details where assigned_agent is not null
        UNION ALL
        SELECT dealer,dealer_code, lead_id FROM mmi_lead_archive_details where assigned_agent is not null
    ) t
    GROUP BY dealer_code,dealer
),

rank_base AS (
    SELECT
        la.dealer,
        la.dealer_code,

        SUM(epd.net_premium) AS netPremium,
        
        COUNT(DISTINCT CASE 
            WHEN la.lead_status = 'Won'
             AND la.converted_flag = 'CRM Renewal'
            THEN la.lead_id
        END) AS conversionCount,

        COUNT(DISTINCT la.policy_no) AS policiesConverted,

        COUNT(DISTINCT CASE 
            WHEN la.lead_status='Won'
             AND DATEDIFF(CURDATE(), dh.created_date) <= 7
            THEN la.lead_id
        END) AS topConverterCount,

        SUM(CASE 
            WHEN disp.disposition_count >= 2 THEN 1 
            ELSE 0 
        END) AS swiftConverter

    FROM mmi_lead_archive_details la

    LEFT JOIN mmi_ebm_policy_data epd 
        ON epd.previous_policy_no = la.policy_no

    LEFT JOIN mmi_call_disposition_history dh
        ON dh.lead_id = la.lead_id
        AND dh.dealer_id = la.dealer_code

    LEFT JOIN disposition_stats disp
        ON disp.lead_id = la.lead_id
        AND disp.dealer_id = la.dealer_code
    
    LEFT JOIN mmi_dealer_location_mapping dealLoc
        ON dealLoc.mapping_dealer_code = la.dealer_code

    LEFT JOIN mmi_mast_dealer_location dloc
        ON dloc.loc_code = dealLoc.location_code

    WHERE
        (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
        AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))

    GROUP BY la.dealer, la.dealer_code
)

SELECT
    'Best in Zone' AS Name,

    ROW_NUMBER() OVER(
        ORDER BY 
            CASE 
                WHEN v_check_ratio = 'Conversion Rate' THEN
                    rb.conversionCount * 100.0 / NULLIF(lc.totalleadContacted, 0)

                WHEN v_check_ratio = 'Retention Rate' THEN
                    rb.policiesConverted * 100.0 / NULLIF(tl.totalLeads, 0)
            END DESC
    ) AS agent_rank,

    rb.dealer,
    rb.dealer_code
FROM rank_base rb
LEFT JOIN total_leads tl 
    ON rb.dealer_code = tl.dealer_code AND rb.dealer = tl.dealer
LEFT JOIN
(
	SELECT
        dealer,
		dealer_code,
		COUNT(DISTINCT lead_id) AS totalleadContacted
    FROM (
    SELECT
        mld.dealer,
		mld.dealer_code,
        cdh.lead_id
    FROM mmi_call_disposition_history cdh left join
    mmi_lead_details mld on mld.lead_id = cdh.lead_id
    LEFT JOIN mmi_dealer_location_mapping dealLoc
        ON dealLoc.mapping_dealer_code = mld.dealer_code

    LEFT JOIN mmi_mast_dealer_location dloc
        ON dloc.loc_code = dealLoc.location_code

    WHERE
        (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
        AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND assigned_agent IS NOT NULL    
    UNION
    SELECT
        mld.dealer,
		mld.dealer_code,
        cdh.lead_id
    FROM mmi_call_disposition_history cdh left join
    mmi_lead_archive_details mld on mld.lead_id = cdh.lead_id
    LEFT JOIN mmi_dealer_location_mapping dealLoc
        ON dealLoc.mapping_dealer_code = mld.dealer_code

    LEFT JOIN mmi_mast_dealer_location dloc
        ON dloc.loc_code = dealLoc.location_code

    WHERE
        (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
        AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND assigned_agent IS NOT NULL 
    ) combined
    Group by dealer_code,dealer
) lc
ON tl.dealer_code = lc.dealer_code
LIMIT 3;



SELECT 
    'Best in India' AS Name,
    d.dealer,
	d.dealer_code,

    CASE 
        WHEN v_check_ratio = 'Conversion Rate' THEN
            ROUND(
                d.conversionCount * 100.0 /
                NULLIF(lc.totalleadContacted, 0), 
            2)

        WHEN v_check_ratio = 'Retention Rate' THEN
            ROUND(
                d.policiesConverted * 100.0 /
                NULLIF(l.totalLeads, 0), 
            2)
    END AS penetration_percentage

FROM 
(
    SELECT
        dealer,
		dealer_code,
        COUNT(DISTINCT CASE 
            WHEN lead_status = 'Won'
             AND converted_flag = 'CRM Renewal'
            THEN lead_id 
        END) AS conversionCount,

        COUNT(DISTINCT policy_no) AS policiesConverted

    FROM mmi_lead_archive_details
    GROUP BY dealer_code,dealer
) d

LEFT JOIN
(
    SELECT
        dealer,
		dealer_code,
        COUNT(DISTINCT lead_id) 
        + COUNT(DISTINCT archive_lead_id) AS totalLeads
    FROM
    (
        SELECT dealer,dealer_code, lead_id, NULL AS archive_lead_id
        FROM mmi_lead_details where assigned_agent is not null

        UNION ALL

        SELECT dealer,dealer_code, NULL AS lead_id, lead_id AS archive_lead_id
        FROM mmi_lead_archive_details where assigned_agent is not null
    ) combined
    GROUP BY dealer_code,dealer
) l
ON d.dealer_code = l.dealer_code

LEFT JOIN
(
	SELECT
        dealer,
		dealer_code,
		COUNT(DISTINCT lead_id) AS totalleadContacted
    FROM (
    SELECT
        dealer,
		dealer_code,
        cdh.lead_id
    FROM mmi_call_disposition_history cdh left join
    mmi_lead_details mld on mld.lead_id = cdh.lead_id
    WHERE assigned_agent IS NOT NULL    
    UNION
    SELECT
        dealer,
		dealer_code,
        cdh.lead_id
    FROM mmi_call_disposition_history cdh left join
    mmi_lead_archive_details mld on mld.lead_id = cdh.lead_id
    WHERE assigned_agent IS NOT NULL
    ) combined
    Group by dealer_code,dealer
) lc
ON d.dealer_code = lc.dealer_code

ORDER BY penetration_percentage DESC
LIMIT 3;

SELECT 
    'Best in Zone' AS Name,
    d.dealer,
	d.dealer_code,
    CASE 
        WHEN v_check_ratio = 'Conversion Rate' THEN
            ROUND(
                d.conversionCount * 100.0 /
                NULLIF(lc.totalleadContacted, 0), 
            2)

        WHEN v_check_ratio = 'Retention Rate' THEN
            ROUND(
                d.policiesConverted * 100.0 /
                NULLIF(l.totalLeads, 0), 
            2)
    END AS penetration_percentage

FROM 
(
    SELECT
        dealer,
		la.dealer_code,
        COUNT(DISTINCT CASE 
            WHEN lead_status = 'Won'
             AND converted_flag = 'CRM Renewal'
            THEN lead_id 
        END) AS conversionCount,

        COUNT(DISTINCT policy_no) AS policiesConverted

    FROM mmi_lead_archive_details la
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.mapping_dealer_code = la.dealer_code
	LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code 
	WHERE
			(v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
			AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    GROUP BY dealer_code,dealer
) d

LEFT JOIN
(
    SELECT
        dealer,
		dealer_code,
        COUNT(DISTINCT lead_id) 
        + COUNT(DISTINCT archive_lead_id) AS totalLeads
    FROM
    (
        SELECT dealer,la.dealer_code, lead_id, NULL AS archive_lead_id
        FROM mmi_lead_details la 
        LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.mapping_dealer_code = la.dealer_code
		LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code 
		WHERE assigned_agent is not null AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
				AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))


        UNION ALL

        SELECT dealer,la.dealer_code, NULL AS lead_id, lead_id AS archive_lead_id
        FROM mmi_lead_archive_details la
        LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.mapping_dealer_code = la.dealer_code
		LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code 
		WHERE assigned_agent is not null AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
				AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    ) combined
    GROUP BY dealer_code,dealer
) l
ON d.dealer_code = l.dealer_code

LEFT JOIN
(
	SELECT
        dealer,
		dealer_code,
		COUNT(DISTINCT lead_id) AS totalleadContacted
    FROM (
    SELECT
        dealer,
		mld.dealer_code,
        cdh.lead_id
    FROM mmi_call_disposition_history cdh left join
    mmi_lead_details mld on mld.lead_id = cdh.lead_id
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.mapping_dealer_code = mld.dealer_code
	LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code 
	WHERE
			(v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
			AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND assigned_agent IS NOT NULL     
    UNION
    SELECT
        dealer,
		mld.dealer_code,
        cdh.lead_id
    FROM mmi_call_disposition_history cdh left join
    mmi_lead_archive_details mld on mld.lead_id = cdh.lead_id
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.mapping_dealer_code = mld.dealer_code
	LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code 
	WHERE
			(v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
			AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND assigned_agent IS NOT NULL  
    ) combined
    Group by dealer_code,dealer
) lc
ON d.dealer_code = lc.dealer_code

ORDER BY penetration_percentage DESC
