IF v_check_type = 'FetchDealerAgent' THEN
WITH lead_stats AS (
    SELECT
        assigned_agent,
        COUNT(DISTINCT lead_id) AS leadsAssigned
    FROM mmi_lead_details
    WHERE dealer_code = v_dealer_code and assigned_agent is not null
    GROUP BY assigned_agent
	
),
lead_archive_stats AS (
	
	SELECT
        assigned_agent,
        COUNT(DISTINCT lead_id) AS leadsAssigned
    FROM mmi_lead_archive_details
    WHERE dealer_code = v_dealer_code and assigned_agent is not null
    GROUP BY assigned_agent
),
lead_archive_call AS (
	
	SELECT
        mld.assigned_agent as assigned_agent,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
        ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_archive_details mld ON mld.lead_id = cdh.lead_id
    WHERE dealer_code = v_dealer_code
    GROUP BY mld.assigned_agent 	
	
),

call_stats AS (
    SELECT
        mld.assigned_agent as assigned_agent,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
        ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_details mld ON mld.lead_id = cdh.lead_id
    WHERE dealer_code = v_dealer_code
    GROUP BY mld.assigned_agent 

),

eligible_stats AS (
    SELECT
        mld.assigned_agent,
        COUNT(DISTINCT mld.lead_id) AS eligibleLeads
    FROM mmi_lead_details mld
    JOIN mmi_call_disposition_history cdh 
        ON cdh.lead_id = mld.lead_id
    WHERE mld.dealer_code = v_dealer_code    
    GROUP BY mld.assigned_agent
),

conversion_stats AS (
    SELECT
        assigned_agent,
        COUNT(DISTINCT policy_no) AS policiesConverted,
        COUNT(DISTINCT CASE 
            WHEN lead_status='Won' AND converted_flag='CRM Renewal'
            THEN lead_id END) AS conversionCount
    FROM mmi_lead_archive_details
    WHERE dealer_code = v_dealer_code
    GROUP BY assigned_agent
),
disposition_stats AS (
    SELECT
        mld.assigned_agent,
        SUM(CASE WHEN disp.disposition_count >= 2 THEN 1 ELSE 0 END) AS swiftConverter
    FROM (
        SELECT
            lead_id,
            dealer_id,
            COUNT(*) disposition_count
        FROM mmi_call_disposition_history
        GROUP BY lead_id, dealer_id
    ) disp
    JOIN mmi_lead_details mld
        ON mld.lead_id = disp.lead_id
    WHERE mld.dealer_code = v_dealer_code    
    GROUP BY mld.assigned_agent
),
top_converter_stats AS (
    SELECT
        mld.assigned_agent,
        COUNT(DISTINCT mld.lead_id) AS topConverterCount
    FROM mmi_lead_archive_details mld
    JOIN mmi_call_disposition_history cdh
        ON cdh.lead_id = mld.lead_id
    WHERE
        mld.lead_status = 'Won'
        AND DATEDIFF(CURDATE(), cdh.created_date) <= 7
        AND mld.dealer_code = v_dealer_code
    GROUP BY mld.assigned_agent
),
premium_stats AS (
    SELECT
        mld.assigned_agent,
        SUM(mmd.net_premium) AS netPremium
    FROM mmi_lead_archive_details mld
    JOIN mmi_ebm_policy_data mmd
        ON mld.policy_no = mmd.previous_policy_no
    WHERE mld.lead_status='Won'
    AND mld.dealer_code = v_dealer_code
    GROUP BY mld.assigned_agent
),

breach_stats AS (
    SELECT 
        mld.assigned_agent,
        mld.dealer_code,
        COUNT(DISTINCT lb.lead_id) AS breachedLeads
    FROM mmi_lead_breached lb
    JOIN mmi_lead_details mld 
        ON mld.lead_id = lb.lead_id
	WHERE mld.dealer_code = v_dealer_code	
    GROUP BY mld.assigned_agent, mld.dealer_code
),

addon_sales AS (
            SELECT ld.assigned_agent AS assigned_agent,
                   COUNT(pad.id) AS AddonSales
            FROM mmi_poladdon_data pad
            JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            GROUP BY ld.assigned_agent
)

SELECT
    urd.id AS agent_id,
    CONCAT(urd.first_name,' ',urd.last_name) AS agentName,
    
    COALESCE(ls.leadsAssigned, 0) + COALESCE(las.leadsAssigned, 0) as leadsAssigned,
    COALESCE(cs.leadsContacted, 0) + COALESCE(lac.leadsContacted, 0) as leadsContacted,
    IFNULL(conv.policiesConverted,0) policiesConverted,
    IFNULL(ps.netPremium,0) netPremium,
	ROUND(
        NULLIF(bs.breachedLeads, 0)/NULLIF(COALESCE(ls.leadsAssigned, 0) + COALESCE(las.leadsAssigned, 0),0) * 100,
    2) AS followup,
    
    CASE 
        WHEN v_check_ratio='Conversion Rate'
        THEN ROUND(
            IFNULL(conv.conversionCount,0) /
            NULLIF(COALESCE(cs.leadsContacted, 0) + COALESCE(lac.leadsContacted, 0),0) * 100 ,2
        )

        WHEN v_check_ratio='Retention Rate'
        THEN ROUND(
            IFNULL(conv.policiesConverted,0) /
            NULLIF(COALESCE(ls.leadsAssigned, 0) + COALESCE(las.leadsAssigned, 0),0) * 100 ,2
        )
    END AS conversionRatio,

    RANK() OVER(
        ORDER BY
        CASE 
			WHEN v_rank_filter = 'Top Converter / Conversion Rate'
			THEN IFNULL(tc.topConverterCount,0)

			WHEN v_rank_filter = 'Swift Converter'
			THEN IFNULL(ds.swiftConverter,0)

			WHEN v_rank_filter='Net Premium Leader'
			THEN IFNULL(ps.netPremium,0)
			
			WHEN v_rank_filter='Follow-up'
			THEN ROUND(NULLIF(bs.breachedLeads, 0)/NULLIF(COALESCE(ls.leadsAssigned, 0) + COALESCE(las.leadsAssigned, 0),0) * 100,2)
			
			WHEN v_rank_filter='Addon Sales'
            THEN IFNULL(ads.addonSales,0)
			
            ELSE IFNULL(conv.policiesConverted,0) /
                 NULLIF(es.eligibleLeads,0)
			END DESC
    ) AS rankPosition

FROM mmi_mast_user_registration_detail urd
JOIN lead_stats ls ON ls.assigned_agent = urd.id
LEFT JOIN call_stats cs ON cs.assigned_agent = urd.id
LEFT JOIN eligible_stats es ON es.assigned_agent = urd.id
LEFT JOIN conversion_stats conv ON conv.assigned_agent = urd.id
LEFT JOIN premium_stats ps ON ps.assigned_agent = urd.id
LEFT JOIN top_converter_stats tc ON tc.assigned_agent = urd.id
LEFT JOIN disposition_stats ds ON ds.assigned_agent = urd.id
LEFT JOIN lead_archive_stats las ON las.assigned_agent = urd.id
LEFT JOIN lead_archive_call lac ON lac.assigned_agent = urd.id
LEFT JOIN breach_stats bs ON bs.assigned_agent = urd.id
LEFT JOIN addon_sales ads ON ads.assigned_agent = urd.id
Where ls.assigned_agent is not null
LIMIT limitVal OFFSET calculated;

