WITH disposition_stats AS (
    SELECT 
        lead_id,
        dealer_id,
        COUNT(*) AS disposition_count
    FROM mmi_call_disposition_history
    GROUP BY lead_id, dealer_id
),

total_leads AS (
    SELECT dealer,dealer_code, COUNT(DISTINCT lead_id) AS totalLeads
    FROM (
        SELECT dealer,dealer_code, lead_id FROM mmi_lead_details where assigned_agent is not null
        UNION ALL
        SELECT dealer,dealer_code, lead_id FROM mmi_lead_archive_details where assigned_agent is not null
    ) t
    GROUP BY dealer,dealer_code
),

rank_base AS (
    SELECT
        la.dealer,
        la.dealer_code,

        SUM(epd.net_premium) AS netPremium,
        
        COUNT(DISTINCT CASE 
            WHEN la.lead_status = 'Won'
             AND la.converted_flag = 'CRM Renewal'
            THEN la.lead_id
        END) AS conversionCount,

        COUNT(DISTINCT la.policy_no) AS policiesConverted,

        COUNT(DISTINCT CASE 
            WHEN la.lead_status='Won'
             AND DATEDIFF(CURDATE(), dh.created_date) <= 7
            THEN la.lead_id
        END) AS topConverterCount,

        SUM(CASE 
            WHEN disp.disposition_count >= 2 THEN 1 
            ELSE 0 
        END) AS swiftConverter

    FROM mmi_lead_archive_details la

    LEFT JOIN mmi_ebm_policy_data epd 
        ON epd.previous_policy_no = la.policy_no

    LEFT JOIN mmi_call_disposition_history dh
        ON dh.lead_id = la.lead_id
        AND dh.dealer_id = la.dealer_code

    LEFT JOIN disposition_stats disp
        ON disp.lead_id = la.lead_id
        AND disp.dealer_id = la.dealer_code

    GROUP BY la.dealer, la.dealer_code
)

SELECT
    'Best in India' AS Name,

    ROW_NUMBER() OVER(
        ORDER BY 
            CASE 
                WHEN v_check_ratio = 'Conversion Rate' THEN
                    rb.conversionCount * 100.0 / NULLIF(lc.totalleadContacted, 0)

                WHEN v_check_ratio = 'Retention Rate' THEN
                    rb.policiesConverted * 100.0 / NULLIF(tl.totalLeads, 0)
            END DESC
    ) AS agent_rank,

    rb.dealer,
    rb.dealer_code
FROM rank_base rb
LEFT JOIN total_leads tl 
    ON rb.dealer_code = tl.dealer_code AND rb.dealer = tl.dealer
LEFT JOIN
(
	SELECT
        dealer,
		dealer_code,
		COUNT(DISTINCT lead_id) AS totalleadContacted
    FROM (
    SELECT
        dealer,
		dealer_code,
        cdh.lead_id
    FROM mmi_call_disposition_history cdh left join
    mmi_lead_details mld on mld.lead_id = cdh.lead_id
    WHERE assigned_agent IS NOT NULL    
    UNION
    SELECT
        dealer,
		dealer_code,
        cdh.lead_id
    FROM mmi_call_disposition_history cdh left join
    mmi_lead_archive_details mld on mld.lead_id = cdh.lead_id
    WHERE assigned_agent IS NOT NULL
    ) combined
    Group by dealer_code,dealer
) lc
ON tl.dealer_code = lc.dealer_code
LIMIT 4;


