-- penetration level ----

SELECT 
    'Best in India' AS Name,
    d.dealer,
	d.dealer_code,

    CASE 
        WHEN v_check_ratio = 'Conversion Rate' THEN
            ROUND(
                d.conversionCount * 100.0 /
                NULLIF(lc.totalleadContacted, 0), 
            2)

        WHEN v_check_ratio = 'Retention Rate' THEN
            ROUND(
                d.policiesConverted * 100.0 /
                NULLIF(l.totalLeads, 0), 
            2)
    END AS penetration_percentage

FROM 
(
    SELECT
        dealer,
		dealer_code,
        COUNT(DISTINCT CASE 
            WHEN lead_status = 'Won'
             AND converted_flag = 'CRM Renewal'
            THEN lead_id 
        END) AS conversionCount,

        COUNT(DISTINCT policy_no) AS policiesConverted

    FROM mmi_lead_archive_details
    GROUP BY dealer_code,dealer
) d

LEFT JOIN
(
    SELECT
        dealer,
		dealer_code,
        COUNT(DISTINCT lead_id) 
        + COUNT(DISTINCT archive_lead_id) AS totalLeads
    FROM
    (
        SELECT dealer,dealer_code, lead_id, NULL AS archive_lead_id
        FROM mmi_lead_details where assigned_agent is not null

        UNION ALL

        SELECT dealer,dealer_code, NULL AS lead_id, lead_id AS archive_lead_id
        FROM mmi_lead_archive_details where assigned_agent is not null
    ) combined
    GROUP BY dealer_code,dealer
) l
ON d.dealer_code = l.dealer_code

LEFT JOIN
(
	SELECT
        dealer,
		dealer_code,
		COUNT(DISTINCT lead_id) AS totalleadContacted
    FROM (
    SELECT
        dealer,
		dealer_code,
        cdh.lead_id
    FROM mmi_call_disposition_history cdh left join
    mmi_lead_details mld on mld.lead_id = cdh.lead_id
    WHERE assigned_agent IS NOT NULL    
    UNION
    SELECT
        dealer,
		dealer_code,
        cdh.lead_id
    FROM mmi_call_disposition_history cdh left join
    mmi_lead_archive_details mld on mld.lead_id = cdh.lead_id
    WHERE assigned_agent IS NOT NULL
    ) combined
    Group by dealer_code,dealer
) lc
ON d.dealer_code = lc.dealer_code

ORDER BY penetration_percentage DESC
LIMIT 4;


