WITH lead_stats AS (
    SELECT
        assigned_agent,
        COUNT(DISTINCT lead_id) AS leadsAssigned
    FROM mmi_lead_details
    WHERE assigned_agent is not null AND
       (v_dealer_code IS NULL OR v_dealer_code='' OR dealer_code=v_dealer_code)
        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (created_date BETWEEN v_from_date AND v_to_date
              OR modified_date BETWEEN v_from_date AND v_to_date)))
        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(renewal_category),v_renewal_category))
    GROUP BY assigned_agent
),
lead_archive_stats AS (
	
	SELECT
        assigned_agent,
        COUNT(DISTINCT lead_id) AS leadsAssigned
    FROM mmi_lead_archive_details
    WHERE
       (v_dealer_code IS NULL OR v_dealer_code='' OR dealer_code=v_dealer_code)
        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (created_date BETWEEN v_from_date AND v_to_date
              OR modified_date BETWEEN v_from_date AND v_to_date)))
        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(renewal_category),v_renewal_category))
        and assigned_agent is not null     
    GROUP BY assigned_agent
	
),
lead_archive_call AS (
		
	SELECT
        mld.assigned_agent as assigned_agent,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
        ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_archive_details mld ON mld.lead_id = cdh.lead_id
     WHERE (v_dealer_code IS NULL OR v_dealer_code='' OR dealer_code=v_dealer_code)
        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))
        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
    GROUP BY mld.assigned_agent
),

call_stats AS (
    SELECT
        mld.assigned_agent as assigned_agent,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
        ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_details mld ON mld.lead_id = cdh.lead_id
     WHERE (v_dealer_code IS NULL OR v_dealer_code='' OR dealer_code=v_dealer_code)
        AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))
        AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
        AND (v_renewal_category IS NULL OR v_renewal_category='' 
             OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
    GROUP BY mld.assigned_agent
),

eligible_stats AS (
    SELECT
        mld.assigned_agent,
