CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_send_quote_placeholders`(
    IN  p_cluster_id VARCHAR(50),
    IN  p_communication_type VARCHAR(20),
    OUT SP_STATUS VARCHAR(50),
    OUT MESSAGE   VARCHAR(500)
)
BEGIN
    DECLARE err_code INT;
    DECLARE err_msg  TEXT;
    DECLARE v_lead_id INT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg  = MESSAGE_TEXT;

        INSERT INTO mmi_mast_procedure_error (
            error_code,
            error_message,
            procedure_name,
            procedure_type,
            error_timing,
            created_by,
            created_date
        )
        VALUES (
            err_code,
            err_msg,
            'mmi_proc_fetch_send_quote_placeholders',
            'SEND_QUOTE',
            CURRENT_TIMESTAMP(),
            'SYSTEM',
            NOW()
        );

        SET SP_STATUS = 'FAILURE';
        SET MESSAGE   = 'An error occurred. Please try again.';

        SELECT
            '' AS dealer_company_name,
            '' AS broker_company_name,
            '' AS renewal_link;
    END;

    SET SP_STATUS = 'SUCCESS';
    SET MESSAGE   = 'Placeholders fetched successfully';

    -- Fetch latest lead
    SELECT ld.lead_id
    INTO v_lead_id
    FROM mmi_lead_details ld
    WHERE ld.cluster_id = p_cluster_id
    ORDER BY ld.created_date DESC
    LIMIT 1;

    -- No lead found
    IF v_lead_id IS NULL THEN
        SET SP_STATUS = 'FAILURE';
        SET MESSAGE   = 'No lead found for cluster';

        SELECT
            '' AS dealer_company_name,
            '' AS broker_company_name,
            '' AS renewal_link;

    ELSE
        -- Validate communication type
        IF LOWER(p_communication_type) IN ('sms','whatsapp') THEN -- ,'email'

            SELECT
                COALESCE(ld.dealer, 'Our Authorized Dealer') AS dealer_company_name,
                'Mahindra Insurance Brokers Limited'         AS broker_company_name,
                COALESCE(etd.renewal_link_modify, '')        AS renewal_link
            FROM mmi_lead_details ld
            LEFT JOIN mmi_proposal_status_history psh
       ON psh.lead_id = ld.lead_id
      AND psh.id = (
            SELECT MAX(id)
            FROM mmi_proposal_status_history
            WHERE lead_id = ld.lead_id
       )
WHERE ld.lead_id = v_lead_id;

        ELSE
            SET SP_STATUS = 'FAILURE';
            SET MESSAGE   = 'Invalid communication type';

            SELECT
                '' AS dealer_company_name,
                '' AS broker_company_name,
                '' AS renewal_link;
        END IF;
    END IF;
END ;;
DELIMITER ;
