CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_system_configuration`(
	IN p_json_data JSON,
    OUT p_status VARCHAR(20),
    OUT p_message VARCHAR(200)
)
BEGIN
	DECLARE v_type VARCHAR(50);
    DECLARE v_role_id VARCHAR(50);
	DECLARE v_error_code INT DEFAULT 0;
    DECLARE v_error_msg VARCHAR(255);
    DECLARE PROCEDURE_TYPE VARCHAR(20) DEFAULT 'FETCH';
	
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            v_error_code = MYSQL_ERRNO, 
            v_error_msg = MESSAGE_TEXT;

        IF v_error_msg IS NULL THEN
            SET v_error_msg = 'Unexpected SQL Exception occurred.';
        END IF;
        
        SET v_type = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.type'));
        INSERT INTO mmi_mast_procedure_error 
            (error_code, error_message, procedure_name, procedure_type, ERROR_TIMING, created_by, created_date)
        VALUES 
            (v_error_code, v_error_msg, 'mmi_proc_fetch_system_configuration', v_type, CURRENT_TIMESTAMP(), 'SYSTEM', NOW());

        SET p_status = '500';
        SET p_message = 'Something went wrong. Please contact admin.';
    END;
    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.type'));
    SET v_role_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.roleId'));

    IF v_type IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Missing required parameter: type';
    END IF;
	
		select distinct features from mmi_mast_feature mf left join
        mmi_user_feature_access_mapping ufam on mf.id = ufam.feature_id 
        left join mmi_user_role_mapping urm on urm.role_id = ufam.role_id where
        mf.id in (11,12,13) and ufam.role_id = v_role_id;
        
    IF v_type = 'leadCategorize' THEN
        
		SELECT p_name,p_value from mmi_mast_ncb_details where status = 1;
        
        SELECT 
            lch.metric,
            lch.label_key,
            lch.min_value,
            lch.max_value,
            lcw.weight_percent,
            lch.categorize_status as status
        FROM 
            mmi_lead_categorize_thresholds lch
        LEFT JOIN 
            mmi_lead_categorize_labels lcl ON lch.label_key = lcl.label_key
        LEFT JOIN 
            mmi_lead_categorization_weights lcw ON lch.metric = lcw.metric
        ORDER BY 
            lch.metric ASC;
         
         SELECT 
            adm.metric,
            adm.label_key,
            adm.field_value,
            lcw.weight_percent,
            adm.status
        FROM 
            mmi_agent_dispo_mappings adm
        LEFT JOIN 
            mmi_lead_categorize_labels lcl ON adm.label_key = lcl.label_key
        LEFT JOIN 
            mmi_lead_categorization_weights lcw ON adm.metric = lcw.metric
        ORDER BY 
            adm.metric ASC;
            
        SELECT sub_disposition FROM mmi_mast_disposition WHERE disposition_id = 1;    
    -- ELSEIF v_type = 'feature' THEN
       -- SELECT DISTINCT features FROM mmi_mast_feature;

    -- ELSEIF v_type = 'access' THEN
       -- SELECT DISTINCT access_name FROM mmi_mast_access_feature;

    ELSEIF v_type = 'leadpool' THEN
        SELECT ic_code, ic_name FROM mmi_mast_insurancecompany order by ic_code desc;
        SELECT id, renewal_year,renewal_month FROM mmi_mast_renewal_category order by id desc;
        SELECT segment_id, name FROM mmi_mast_segment order by segment_id desc;
        SELECT id, addon_description,premium_amt FROM mmi_mast_addon order by id desc;

    ELSEIF v_type = 'Threshold' THEN
        SELECT DISTINCT services_property, services_value FROM mmi_services_config;

    ELSE
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported type: ';
    END IF;

    SET p_status = '200';
    SET p_message = 'Configuration data fetched successfully';
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
