CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_target_planning`(
    IN p_json_data JSON,
    OUT p_status_code VARCHAR(10),
    OUT p_status_message VARCHAR(255)
)
BEGIN

    DECLARE PROCEDURE_TYPE VARCHAR(20) DEFAULT 'SELECT';
    DECLARE v_dealer_code VARCHAR(50);
    DECLARE v_userId VARCHAR(50);
    DECLARE v_search_name VARCHAR(500);
    DECLARE v_team_id VARCHAR(200); 
    DECLARE v_type VARCHAR(50);
    DECLARE v_period_type_filter VARCHAR(20);
	DECLARE v_year_filter INT;
	DECLARE v_month_filter VARCHAR(20);
    
    DECLARE calculated INT DEFAULT 0;
    DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 0;
    
    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            @sqlstate = RETURNED_SQLSTATE, errno = MYSQL_ERRNO, errmsg = MESSAGE_TEXT;
        SET p_status_code = '500';
        SET p_status_message = 'Internal Server Error';

        INSERT INTO mmi_mast_procedure_error
            (error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date)
        VALUES
            (errno, errmsg, 'mmi_proc_fetch_target_planning', PROCEDURE_TYPE, CURRENT_TIMESTAMP(), 'SYSTEM', NOW());
    END;

    SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerCode'));
    SET v_userId = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.userId'));
    SET v_search_name = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.searchName'));
    SET v_team_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.teamId'));
    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.type'));
    SET v_period_type_filter = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.periodType'));
	SET v_year_filter = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.year'));
	SET v_month_filter = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.month'));
    
    SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.limit')) AS UNSIGNED), 10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.offset')) AS UNSIGNED), 0);
    SET calculated = GREATEST((offsetVal - 1) * limitVal,0);
    
    IF v_dealer_code IS NULL OR v_dealer_code = '' THEN
        SET p_status_code = '300';
        SET p_status_message = 'Dealer code cannot be null or empty';

    ELSEIF v_userId IS NULL OR v_userId = '' THEN
		SET p_status_code = '300';
		SET p_status_message = 'UserId cannot be null or empty';

    ELSE
		-- IF v_type = 'downloadTargetFilter' THEN
		IF v_type IN ('downloadTargetFilter') THEN
        
			WITH RECURSIVE team_hierarchy AS (
				SELECT v_userId AS user_id
				UNION ALL
				SELECT ur.user_id
				FROM mmi_user_reporting ur
				INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
			),
			dealer_team_members AS (
				SELECT th.user_id
				FROM team_hierarchy th
				JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
				WHERE udm.dealer_id = v_dealer_code
			)
			SELECT tp.id, dealer_code, period_type, year, month, concat(urd.first_name ,' ', urd.last_name) as teamMember, segment, kpi,
			target_bucket, target_value, notes, tp.created_by, tp.created_date
			-- FROM mmi_target_planning
            FROM mmi_target_planning tp left join 
            mmi_mast_user_registration_detail urd on urd.id = tp.team_member
			WHERE dealer_code = v_dealer_code and team_member IN (SELECT user_id FROM dealer_team_members)
			AND (v_team_id IS NULL OR v_team_id = '' OR FIND_IN_SET(TRIM(team_member), v_team_id))
			AND (v_search_name IS NULL
			 OR v_search_name = ''
			 OR period_type LIKE CONCAT('%', v_search_name, '%')
			 OR segment LIKE CONCAT('%', v_search_name, '%')
			 OR kpi LIKE CONCAT('%', v_search_name, '%')
			 OR target_bucket LIKE CONCAT('%', v_search_name, '%')
             OR LOWER(TRIM(urd.first_name)) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')
			 OR LOWER(TRIM(urd.last_name)) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')
			 OR LOWER(TRIM(CONCAT(urd.first_name, ' ', urd.last_name))) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%'))
             AND (v_period_type_filter = 'ALL'
					OR (v_period_type_filter = 'YEAR' AND period_type = 'YEAR')
					OR (v_period_type_filter = 'MONTH' AND period_type = 'MONTH')
				);
             -- AND period_type = v_period_type_filter;
			-- AND (v_period_type_filter IS NULL OR v_period_type_filter = '' OR v_period_type_filter = 'ALL'
				-- OR (v_period_type_filter = 'YEAR' AND year = v_year_filter)
				-- OR (v_period_type_filter = 'MONTH' AND year = v_year_filter AND month = v_month_filter));
        
        ELSEIF v_type = 'downloadTarget' THEN
			
			WITH RECURSIVE team_hierarchy AS (
				SELECT v_userId AS user_id
				UNION ALL
				SELECT ur.user_id
				FROM mmi_user_reporting ur
				INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
			),
			dealer_team_members AS (
				SELECT th.user_id
				FROM team_hierarchy th
				JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
				WHERE udm.dealer_id = v_dealer_code
			)
			SELECT tp.id, dealer_code, period_type, year, month, concat(urd.first_name ,' ', urd.last_name) as teamMember, segment, kpi,
			target_bucket, target_value, notes, tp.created_by, tp.created_date
			FROM mmi_target_planning tp left join 
            mmi_mast_user_registration_detail urd on urd.id = tp.team_member
			WHERE dealer_code = v_dealer_code and team_member IN (SELECT user_id FROM dealer_team_members)
			AND (v_search_name IS NULL
			 OR v_search_name = ''
			 OR period_type LIKE CONCAT('%', v_search_name, '%')
			 OR segment LIKE CONCAT('%', v_search_name, '%')
			 OR kpi LIKE CONCAT('%', v_search_name, '%')
			 OR target_bucket LIKE CONCAT('%', v_search_name, '%')
             OR LOWER(TRIM(urd.first_name)) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')
			 OR LOWER(TRIM(urd.last_name)) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')
			 OR LOWER(TRIM(CONCAT(urd.first_name, ' ', urd.last_name))) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%'))
             AND (v_period_type_filter = 'ALL'
					OR (v_period_type_filter = 'YEAR' AND period_type = 'YEAR')
					OR (v_period_type_filter = 'MONTH' AND period_type = 'MONTH')
				);
             -- AND period_type = v_period_type_filter;
			-- AND (v_period_type_filter IS NULL OR v_period_type_filter = '' OR v_period_type_filter = 'ALL'
				-- OR (v_period_type_filter = 'YEAR' AND year = v_year_filter)
				-- OR (v_period_type_filter = 'MONTH' AND year = v_year_filter AND month = v_month_filter));
            
        /*ELSEIF v_type = 'targetFilter' THEN
        
			WITH RECURSIVE team_hierarchy AS (
				SELECT v_userId AS user_id
				UNION ALL
				SELECT ur.user_id
				FROM mmi_user_reporting ur
				INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
			),
			dealer_team_members AS (
				SELECT th.user_id
				FROM team_hierarchy th
				JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
				WHERE udm.dealer_id = v_dealer_code
			)
			SELECT dealer_code, period_type, year, month, team_member, segment, kpi,
			target_bucket, target_value, notes, created_by, created_date
			FROM mmi_target_planning
			WHERE dealer_code = v_dealer_code and team_member IN (SELECT user_id FROM dealer_team_members)
			AND (v_team_id IS NULL OR v_team_id = '' OR FIND_IN_SET(TRIM(team_member), v_team_id))
			AND (v_search_name IS NULL
			 OR v_search_name = ''
			 OR period_type LIKE CONCAT('%', v_search_name, '%')
			 OR segment LIKE CONCAT('%', v_search_name, '%')
			 OR kpi LIKE CONCAT('%', v_search_name, '%')
			 OR target_bucket LIKE CONCAT('%', v_search_name, '%'))
			AND (v_period_type_filter IS NULL OR v_period_type_filter = '' OR v_period_type_filter = 'ALL'
				OR (v_period_type_filter = 'YEAR' AND year = v_year_filter)
				OR (v_period_type_filter = 'MONTH' AND year = v_year_filter AND month = v_month_filter));
         */
        ELSE
			 WITH RECURSIVE team_hierarchy AS (
				SELECT ur.user_id
				FROM mmi_user_reporting ur
				WHERE ur.supervisor_id =v_userId
				UNION ALL
				SELECT ur2.user_id
				FROM mmi_user_reporting ur2
				INNER JOIN team_hierarchy th ON ur2.supervisor_id = th.user_id
			)
			SELECT
				th.user_id as teamMemberId,
				CONCAT(COALESCE(mud.first_name, ''), ' ', COALESCE(mud.last_name, '')) AS teamMemberName
			FROM team_hierarchy th
			JOIN mmi_mast_user mu ON th.user_id = mu.user_id
			JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
			JOIN mmi_mast_user_registration_detail mud ON mu.user_id = mud.id
			WHERE udm.dealer_id = v_dealer_code
			ORDER BY mud.first_name, mud.last_name;
			
			SELECT segment_id,segment FROM mmi_mast_segment WHERE status = '1' and segment is not null;
			SELECT id,kpi_name FROM mmi_mast_kpi WHERE status = '1' and kpi_name is not null;
			SELECT id,target_bucket_name FROM mmi_mast_target_bucket WHERE status = '1' and target_bucket_name is not null;
			
			WITH RECURSIVE team_hierarchy AS (
				SELECT v_userId AS user_id
				UNION ALL
				SELECT ur.user_id
				FROM mmi_user_reporting ur
