CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_target_planning_by_id`(
    IN p_json_data JSON,
    OUT p_status_code VARCHAR(10),
    OUT p_status_message VARCHAR(255)
)
BEGIN

    DECLARE PROCEDURE_TYPE VARCHAR(20) DEFAULT 'SELECT';
	DECLARE v_dealer_code VARCHAR(500);
    DECLARE v_Id INT;
    
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        SET p_status_code = '500';
        SET p_status_message = 'Internal Server Error';

        INSERT INTO mmi_mast_procedure_error
            (error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date)
        VALUES
            (p_status_code, p_status_message, 'mmi_proc_fetch_target_planning_by_id', PROCEDURE_TYPE, CURRENT_TIMESTAMP(), 'SYSTEM', NOW());
    END;

	SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerCode'));
	SET v_Id = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.id')) AS UNSIGNED);
    
    IF v_dealer_code IS NULL OR v_dealer_code = '' THEN
        SET p_status_code = '300';
        SET p_status_message = 'Dealer code cannot be null or empty';
	
    ELSEIF v_Id IS NULL OR v_Id = 0 THEN
        SET p_status_code = '301';
        SET p_status_message = 'Id cannot be null or empty';
    
    ELSE

        SELECT dealer_code, period_type, year, month, team_member as teamMember, segment, kpi,
		target_bucket, target_value, notes FROM mmi_target_planning
        WHERE dealer_code = v_dealer_code and id = v_Id;

        SET p_status_code = '200';
        SET p_status_message = 'Target planning data fetched successfully';

    END IF;
END ;;
DELIMITER ;
