CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_template_by_ebm_status`(
    IN p_lead_id INT,
    IN p_communication_type VARCHAR(50)  -- Email, SMS, WhatsApp
)
BEGIN
    DECLARE v_ebm_status VARCHAR(100);
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg,
            'mmi_proc_fetch_template_by_status',
            'FETCH_TEMPLATE_BY_EBM_STATUS',
            CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    -- latest EBM status
    SELECT et.ebm_status
    INTO v_ebm_status
    FROM ebm_transaction_details et
    WHERE et.lead_id = p_lead_id
    ORDER BY et.created_date DESC
    LIMIT 1;

    -- template body according to that ebmStatus + comType
    SELECT 
        v_ebm_status AS ebm_status,
        etm.communication_type,
        etm.template_subject,
        etm.template_body
    FROM mmi_emb_template_master etm
    WHERE etm.ebm_status = v_ebm_status
      AND etm.communication_type = p_communication_type
      AND etm.is_active = 1
    LIMIT 1;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_fetch_template_by_status` */;
