CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_user_communication_modes`(
    IN Json_data JSON,
    OUT p_status_code VARCHAR(500),
    OUT p_status_message VARCHAR(500)
)
proc_block: BEGIN
    DECLARE err_code INT;
    DECLARE err_msg TEXT;
    DECLARE v_cluster_id VARCHAR(100);
    DECLARE v_dealer_id VARCHAR(100);
    DECLARE v_lead_id VARCHAR(100);
    DECLARE v_dealer_communication VARCHAR(500);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        SET p_status_code = '500';
        SET p_status_message = CONCAT('An error occurred: ', err_msg);

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_fetch_user_communication_modes', 'FETCH_COMM_MODES', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    SET v_cluster_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.cluster_id'));
    SET v_dealer_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealer_id'));
    SET v_lead_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.lead_id'));

    IF v_cluster_id IS NULL OR v_cluster_id = '' OR
       v_dealer_id IS NULL OR v_dealer_id = '' OR
       v_lead_id IS NULL OR v_lead_id = '' THEN
        SET p_status_code = '400';
        SET p_status_message = 'Cluster ID, Dealer ID, and Lead ID are required';
        LEAVE proc_block;
    END IF;

    -- fetching dealer communications using dealer_id, optional join to lead for ordering
    SELECT dd.communication
    INTO v_dealer_communication
    FROM mmi_dealer_details dd
    LEFT JOIN mmi_lead_details ld 
           ON dd.dealer_id = ld.dealer_code
          AND ld.lead_id = v_lead_id
          AND ld.cluster_id = v_cluster_id
    WHERE dd.dealer_id = v_dealer_id
    ORDER BY ld.created_date DESC
    LIMIT 1;

    -- nullCheck for if communication exists
    IF v_dealer_communication IS NULL OR v_dealer_communication = '' THEN
        SET p_status_code = '404';
        SET p_status_message = 'Dealer communication modes not found';
        LEAVE proc_block;
    END IF;

    -- comm modes
    SELECT
        CASE WHEN FIND_IN_SET('Email', v_dealer_communication) > 0 THEN 'Email' END AS communication_mode
    UNION
    SELECT CASE WHEN FIND_IN_SET('SMS', v_dealer_communication) > 0 THEN 'SMS' END
    UNION
    SELECT CASE WHEN FIND_IN_SET('WhatsApp', v_dealer_communication) > 0 THEN 'WhatsApp' END;

    SET p_status_code = '200';
    SET p_status_message = 'Fetched user communication modes successfully';

END ;;
