DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_user_creation_values`(
    IN Json_data VARCHAR(1000),
    OUT p_sp_status VARCHAR(45),
    OUT p_message VARCHAR(500)
)
BEGIN
	proc_end: BEGIN

    DECLARE v_dealer_name VARCHAR(450); 
    DECLARE v_parent_code VARCHAR(45); 
    DECLARE v_roleId VARCHAR(45); 
    DECLARE v_type VARCHAR(45);
    DECLARE v_location VARCHAR(45);
    DECLARE v_role_name VARCHAR(300);
    DECLARE v_role_id VARCHAR(45);
    DECLARE v_role_type VARCHAR(45);
    DECLARE v_dealer_code VARCHAR(45);
    DECLARE user_count INT DEFAULT 0;
    
    DECLARE err_code INT;
    DECLARE err_msg TEXT;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
			
            SET p_sp_status = '500';
			SET p_message = 'An error occurred. Please try again.';
                        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_fetch_user_creation_values', 'FETCH_USER_CREATION', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;

    SET v_roleId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleId'));
    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.type'));
    -- SET v_dealer_name = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerName'));
	SET v_dealer_name = TRIM(SUBSTRING_INDEX(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerName')),'-',-1));
    SET v_location = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.location'));
    SET v_role_name = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleName'));
	SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleType'));
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentCode'));
    SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
    
    IF v_type IS NULL OR v_type = '' THEN
        SET p_sp_status = '400';
        SET p_message = 'Type is required';
        ROLLBACK;
        LEAVE proc_end;
    END IF;
	select id,role_type from mmi_mast_role_type where status = 1;
    
    IF v_parent_code IS NOT NULL AND v_parent_code !='' THEN
    IF v_type = 'dealerName' THEN
        /*SELECT DISTINCT dl.dealer_name -- ,dl.dealer_id  
        FROM mmi_dealer_details dl
        LEFT JOIN mmi_dealer_location_mapping md ON md.dealer_code = dl.dealer_id
        WHERE dl.parent_code = v_parent_code;*/
        SELECT distinct dl.parent_code,concat(dl.dealer_name,' - ',mdl.loc_name,' - ',dl.dealer_id) as dealer_name 
        -- from mmi_mast_dealer md left join
		from mmi_dealer_details dl -- on md.parent_code = dl.parent_code
		left join mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = dl.dealer_id -- on dlm.parent_code = md.parent_code
		left join mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL AND  dl.parent_code = v_parent_code;

    ELSEIF v_type = 'location' THEN
        IF v_dealer_name IS NULL OR v_dealer_name = '' THEN
            SET p_sp_status = '400';
            SET p_message = 'Dealer Name is required for location query';
            ROLLBACK;
            LEAVE proc_end;
        END IF;

        SELECT DISTINCT loc_name
        FROM mmi_mast_dealer_location mdl
        LEFT JOIN mmi_dealer_location_mapping dlm ON mdl.loc_code = dlm.location_code
        -- LEFT JOIN mmi_mast_dealer md ON dlm.parent_code = md.parent_code
        LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = dlm.mapping_dealer_code
        -- WHERE dlm.dealer_name = v_dealer_name and dl.dealer_id = v_dealer_code
        WHERE dl.dealer_id = v_dealer_name
        and loc_name IS NOT NULL and loc_name <> '';

    ELSEIF v_type = 'Role Assignment' THEN
        IF v_dealer_name IS NULL OR v_dealer_name = '' OR v_location IS NULL OR v_location = '' THEN
            SET p_sp_status = '400';
            SET p_message = 'Dealer Name and Location are required for role assignment query';
            ROLLBACK;
            LEAVE proc_end;
        END IF;

        -- SELECT DISTINCT role 
        -- FROM mmi_mast_role 
        -- WHERE role_id IN (1, 2)
        /*SELECT DISTINCT
        mr.role AS role,mr.role_id
		FROM mmi_mast_role r
		JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id AND drm.status = '1'
		LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
		LEFT JOIN mmi_mast_role mr ON drm.reporting_role_id = mr.role_id
		LEFT JOIN mmi_mast_role_type mrt ON mrt.id = m.role_type_id
		WHERE r.status = '1' AND m.role_id IS NOT NULL AND mrt.id = 1 AND m.role_type_id 
        IS NOT NULL AND mr.role is not null
		GROUP BY  mr.role,mr.role_id
        UNION ALL
        SELECT DISTINCT role,mr.role_id 
        FROM mmi_mast_role mr
        LEFT JOIN mmi_mast_dealer_role_mapping drm ON mr.role_id = drm.role_id
        LEFT JOIN mmi_mast_dealer md ON drm.parent_code = md.parent_code
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.parent_code = md.parent_code
        LEFT JOIN mmi_mast_dealer_location dl ON dl.loc_code = dlm.location_code
        LEFT JOIN mmi_dealer_details mdl ON mdl.parent_code = md.parent_code
        WHERE md.dealer_name = v_dealer_name AND dl.loc_name = v_location;*/
        SELECT DISTINCT role,mr.role_id 
        FROM mmi_mast_role mr
        LEFT JOIN mmi_mast_dealer_role_mapping drm ON mr.role_id = drm.role_id
        -- LEFT JOIN mmi_mast_dealer md ON drm.parent_code = md.parent_code
        LEFT JOIN mmi_dealer_details mdl ON mdl.parent_code = drm.parent_code
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mdl.dealer_id
        LEFT JOIN mmi_mast_dealer_location dl ON dl.loc_code = dlm.location_code
        -- WHERE dlm.dealer_name = v_dealer_name AND drm.role_location = v_location
        WHERE mdl.dealer_id = v_dealer_name AND drm.role_location = v_location
        and mr.status = 1;

    ELSEIF v_type = 'Reporting Manager' THEN
        IF v_role_name IS NULL OR v_role_name = '' THEN
            SET p_sp_status = '400';
            SET p_message = 'Role Name is required for Reporting Manager query';
            ROLLBACK;
            LEAVE proc_end;
        END IF;

        SELECT DISTINCT role_id INTO v_role_id
        FROM mmi_mast_role
        WHERE role = v_role_name
        LIMIT 1;
        /*WITH RECURSIVE role_hierarchy AS (
			  SELECT
				rh1.role_id,
				rh1.role,
				rh1.role_level,
				drm.reporting_role_id AS parent_role_id,
				drm.parent_code  -- important to filter on dealer
			  FROM mmi_mast_role rh1
			  JOIN mmi_mast_dealer_role_mapping drm ON rh1.role_id = drm.role_id
			  WHERE rh1.role_id = v_role_id
				AND drm.parent_code = (
				  SELECT parent_code
				  FROM mmi_mast_dealer WHERE dealer_name = v_dealer_name
				)

			  UNION ALL

			  SELECT
				mr.role_id,
				mr.role,
				mr.role_level,
				drm1.reporting_role_id,
				drm1.parent_code
			  FROM mmi_mast_role mr
			  JOIN mmi_mast_dealer_role_mapping drm1 ON mr.role_id = drm1.role_id
			  JOIN role_hierarchy rh ON mr.role_id = rh.parent_role_id
			)*/
            WITH RECURSIVE role_hierarchy (role_id, role, role_level, parent_role_id, parent_code, depth) AS (
    -- Anchor member
    SELECT
        rh1.role_id,
        rh1.role,
        rh1.role_level,
        drm.reporting_role_id,
        drm.parent_code,
        1 AS depth
    FROM mmi_mast_role rh1
    JOIN mmi_mast_dealer_role_mapping drm ON rh1.role_id = drm.role_id
    WHERE rh1.role_id = v_role_id
      AND drm.parent_code = (
          -- SELECT parent_code
          -- FROM mmi_mast_dealer WHERE dealer_name = v_dealer_name
			SELECT distinct md.parent_code 
            -- FROM mmi_mast_dealer md 
			-- LEFT JOIN mmi_dealer_location_mapping dlm ON md.parent_code = dlm.parent_code
            FROM mmi_dealer_location_mapping md
			LEFT JOIN mmi_dealer_details dl on dl.dealer_id = md.mapping_dealer_code
			LEFT JOIN mmi_mast_dealer_location mdl on mdl.loc_code = md.location_code
			-- WHERE md.dealer_name = v_dealer_name and mdl.loc_name = v_location
            WHERE dl.dealer_id = v_dealer_name and mdl.loc_name = v_location
      )

    UNION ALL

    -- Recursive member
    SELECT
        mr.role_id,
        mr.role,
        mr.role_level,
        drm1.reporting_role_id,
        drm1.parent_code,
        rh.depth + 1
    FROM mmi_mast_role mr
    JOIN mmi_mast_dealer_role_mapping drm1 ON mr.role_id = drm1.role_id
    JOIN role_hierarchy rh ON mr.role_id = rh.parent_role_id
    WHERE rh.depth < 50
)
SELECT COUNT(*) INTO user_count
FROM role_hierarchy rh
JOIN mmi_user_role_mapping urm ON urm.role_id = rh.role_id
JOIN mmi_mast_user_registration_detail urd ON urm.user_id = urd.id
JOIN mmi_mast_dealer_role_mapping drm ON rh.role_id = drm.reporting_role_id
-- JOIN mmi_mast_dealer md ON drm.parent_code = md.parent_code
JOIN mmi_dealer_location_mapping dlm ON dlm.parent_code = drm.parent_code
JOIN mmi_mast_dealer_location dl ON dl.loc_code = dlm.location_code
-- WHERE dlm.dealer_name = v_dealer_name
WHERE dlm.mapping_dealer_code = v_dealer_name
  AND dl.loc_name = v_location
  AND rh.role_id <> v_role_id
  AND urd.role_type_id <> 1;

IF user_count > 0 THEN
WITH RECURSIVE role_hierarchy (role_id, role, role_level, parent_role_id, parent_code, depth) AS (
    -- Anchor member
    SELECT
        rh1.role_id,
        rh1.role,
        rh1.role_level,
        drm.reporting_role_id,
        drm.parent_code,
        1 AS depth
    FROM mmi_mast_role rh1
    JOIN mmi_mast_dealer_role_mapping drm ON rh1.role_id = drm.role_id
    WHERE rh1.role_id = v_role_id
      AND drm.parent_code = (
          -- SELECT parent_code
          -- FROM mmi_mast_dealer WHERE dealer_name = v_dealer_name
			SELECT distinct md.parent_code 
            -- FROM mmi_mast_dealer md 
			-- LEFT JOIN mmi_dealer_location_mapping dlm ON md.parent_code = dlm.parent_code
            FROM mmi_dealer_location_mapping md
			LEFT JOIN mmi_dealer_details dl on dl.dealer_id = md.mapping_dealer_code
			LEFT JOIN mmi_mast_dealer_location mdl on mdl.loc_code = md.location_code
			-- WHERE md.dealer_name = v_dealer_name and mdl.loc_name = v_location
            WHERE dl.dealer_id = v_dealer_name and mdl.loc_name = v_location
      )

    UNION ALL

    -- Recursive member
    SELECT
        mr.role_id,
        mr.role,
        mr.role_level,
        drm1.reporting_role_id,
        drm1.parent_code,
        rh.depth + 1
    FROM mmi_mast_role mr
    JOIN mmi_mast_dealer_role_mapping drm1 ON mr.role_id = drm1.role_id
    JOIN role_hierarchy rh ON mr.role_id = rh.parent_role_id
    WHERE rh.depth < 50
)
			SELECT DISTINCT 
			  CONCAT(urd.first_name, ' ', urd.last_name) AS name,
			  rh.role,
			  rh.role_level,
			  rh.role_id
			FROM role_hierarchy rh
			LEFT JOIN mmi_user_role_mapping urm ON urm.role_id = rh.role_id
			LEFT JOIN mmi_mast_user_registration_detail urd ON urm.user_id = urd.id
			LEFT JOIN mmi_mast_dealer_role_mapping drm ON rh.role_id = drm.reporting_role_id
			-- LEFT JOIN mmi_mast_dealer md ON drm.parent_code = md.parent_code
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.parent_code = drm.parent_code
			LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = dlm.mapping_dealer_code
			LEFT JOIN mmi_mast_dealer_location dl ON dl.loc_code = dlm.location_code
			-- WHERE dlm.dealer_name = v_dealer_name
            WHERE mdl.dealer_id = v_dealer_name
			  AND dl.loc_name = v_location
			  AND rh.role_id <> v_role_id
              AND urd.role_type_id <> 1
			ORDER BY rh.role_id DESC;
ELSE
WITH RECURSIVE role_hierarchy (role_id, role, role_level, parent_role_id, parent_code, depth) AS (
    -- Anchor member
    SELECT
        rh1.role_id,
        rh1.role,
        rh1.role_level,
        drm.reporting_role_id,
        drm.parent_code,
        1 AS depth
    FROM mmi_mast_role rh1
    JOIN mmi_mast_dealer_role_mapping drm ON rh1.role_id = drm.role_id
    WHERE rh1.role_id = v_role_id
      AND drm.parent_code = (
          -- SELECT parent_code
          -- FROM mmi_mast_dealer WHERE dealer_name = v_dealer_name
			SELECT distinct md.parent_code 
            -- FROM mmi_mast_dealer md 
			-- LEFT JOIN mmi_dealer_location_mapping dlm ON md.parent_code = dlm.parent_code
			FROM mmi_dealer_location_mapping md
            LEFT JOIN mmi_dealer_details dl on dl.dealer_id = md.mapping_dealer_code
			LEFT JOIN mmi_mast_dealer_location mdl on mdl.loc_code = md.location_code
			-- WHERE md.dealer_name = v_dealer_name and mdl.loc_name = v_location
            WHERE dl.dealer_id = v_dealer_name and mdl.loc_name = v_location
      )

    UNION ALL

    -- Recursive member
    SELECT
        mr.role_id,
        mr.role,
        mr.role_level,
        drm1.reporting_role_id,
        drm1.parent_code,
        rh.depth + 1
    FROM mmi_mast_role mr
    JOIN mmi_mast_dealer_role_mapping drm1 ON mr.role_id = drm1.role_id
    JOIN role_hierarchy rh ON mr.role_id = rh.parent_role_id
    WHERE rh.depth < 50
)
	SELECT DISTINCT 
			  CONCAT(urd.first_name, ' ', urd.last_name) AS name,
			  rh.role,
			  rh.role_level,
			  rh.role_id
			FROM role_hierarchy rh
			LEFT JOIN mmi_user_role_mapping urm ON urm.role_id = rh.role_id
			LEFT JOIN mmi_mast_user_registration_detail urd ON urm.user_id = urd.id
			LEFT JOIN mmi_mast_dealer_role_mapping drm ON rh.role_id = drm.reporting_role_id
			-- LEFT JOIN mmi_mast_dealer md ON drm.parent_code = md.parent_code
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.parent_code = drm.parent_code
			LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = dlm.mapping_dealer_code
			LEFT JOIN mmi_mast_dealer_location dl ON dl.loc_code = dlm.location_code
			-- WHERE dlm.dealer_name = v_dealer_name
            WHERE mdl.dealer_id = v_dealer_name
			  AND dl.loc_name = v_location
			  AND rh.role_id = v_role_id
              AND urd.role_type_id <> 1
			ORDER BY rh.role_id DESC;
END IF;

    ELSEIF v_type = 'Yes' THEN
        SELECT DISTINCT bucket_name 
        FROM mmi_mast_bucket mb
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.dealer_code = mb.dealer_code
        -- LEFT JOIN mmi_mast_dealer md ON md.parent_code = dlm.parent_code
        LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = dlm.mapping_dealer_code
        LEFT JOIN mmi_mast_dealer_location dl ON dl.loc_code = dlm.location_code
        -- WHERE dlm.dealer_name = v_dealer_name AND dl.loc_name = v_location;
        WHERE mdl.dealer_id = v_dealer_name AND dl.loc_name = v_location;

    ELSE
        SET p_sp_status = '400';
        SET p_message = 'Invalid type value';
        ROLLBACK;
        LEAVE proc_end;
    END IF;
    
    ELSEIF v_role_type = 'DEALER' THEN
    IF v_type = 'dealerName' THEN
        /*SELECT DISTINCT dl.dealer_name-- ,dl.dealer_id  
        FROM mmi_dealer_details dl
        LEFT JOIN mmi_dealer_location_mapping md ON md.mapping_dealer_code = dl.dealer_id;*/
        SELECT distinct concat(dl.dealer_name,' - ',mdl.loc_name,' - ',dl.dealer_id) as dealer_name 
        -- from mmi_mast_dealer md left join
		from mmi_dealer_details dl -- on md.parent_code = dl.parent_code
		left join mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = dl.dealer_id -- on dlm.parent_code = md.parent_code
		left join mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL; 
        /*SELECT distinct concat(dl.dealer_name,' ',mdl.loc_name,' ',dl.dealer_id) as dealer_name from mmi_mast_dealer md left join
		mmi_dealer_details dl on md.parent_code = dl.parent_code
		left join mmi_dealer_location_mapping dlm on dlm.parent_code = md.parent_code
		left join mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL; */

    ELSEIF v_type = 'location' THEN
        IF v_dealer_name IS NULL OR v_dealer_name = '' THEN
            SET p_sp_status = '400';
            SET p_message = 'Dealer Name is required for location query';
            ROLLBACK;
            LEAVE proc_end;
        END IF;

        SELECT DISTINCT loc_name
        FROM mmi_mast_dealer_location mdl 
        LEFT JOIN mmi_dealer_location_mapping dlm ON mdl.loc_code = dlm.location_code
        -- LEFT JOIN mmi_mast_dealer md ON dlm.parent_code = md.parent_code
        LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = dlm.mapping_dealer_code
        -- WHERE dlm.dealer_name = v_dealer_name and loc_name IS NOT NULL and loc_name <> ''; -- and dl.dealer_id = v_dealer_code;
		WHERE dl.dealer_id = v_dealer_name and loc_name IS NOT NULL and loc_name <> '';
        
    ELSEIF v_type = 'Role Assignment' THEN
        IF v_dealer_name IS NULL OR v_dealer_name = '' OR v_location IS NULL OR v_location = '' THEN
            SET p_sp_status = '400';
            SET p_message = 'Dealer Name and Location are required for role assignment query';
            ROLLBACK;
            LEAVE proc_end;
        END IF;

        -- SELECT DISTINCT role 
        -- FROM mmi_mast_role 
        -- WHERE role_id IN (1, 2)
        /*SELECT DISTINCT
        mr.role AS role,mr.role_id
		FROM mmi_mast_role r
		JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id AND drm.status = '1'
		LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
		LEFT JOIN mmi_mast_role mr ON drm.reporting_role_id = mr.role_id
		LEFT JOIN mmi_mast_role_type mrt ON mrt.id = m.role_type_id
		WHERE r.status = '1' AND m.role_id IS NOT NULL AND mrt.id = 1 AND m.role_type_id 
        IS NOT NULL AND mr.role is not null
		GROUP BY  mr.role,mr.role_id
        UNION ALL*/
        SELECT DISTINCT role,mr.role_id 
        FROM mmi_mast_role mr
        LEFT JOIN mmi_mast_dealer_role_mapping drm ON mr.role_id = drm.role_id
        -- LEFT JOIN mmi_mast_dealer md ON drm.parent_code = md.parent_code
        LEFT JOIN mmi_dealer_details mdl ON mdl.parent_code = drm.parent_code
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mdl.dealer_id
        LEFT JOIN mmi_mast_dealer_location dl ON dl.loc_code = dlm.location_code
        -- WHERE dlm.dealer_name = v_dealer_name AND drm.role_location = v_location
        WHERE mdl.dealer_id = v_dealer_name AND drm.role_location = v_location
        and mr.status = 1;

    ELSEIF v_type = 'Reporting Manager' THEN
        IF v_role_name IS NULL OR v_role_name = '' THEN
            SET p_sp_status = '400';
            SET p_message = 'Role Name is required for Reporting Manager query';
            ROLLBACK;
            LEAVE proc_end;
        END IF;

        SELECT DISTINCT role_id INTO v_role_id
        FROM mmi_mast_role
        WHERE role = v_role_name
        LIMIT 1;
        
		/*WITH RECURSIVE role_hierarchy AS (
			  SELECT
				rh1.role_id,
				rh1.role,
				rh1.role_level,
				drm.reporting_role_id AS parent_role_id,
				drm.parent_code  -- important to filter on dealer
			  FROM mmi_mast_role rh1
			  JOIN mmi_mast_dealer_role_mapping drm ON rh1.role_id = drm.role_id
			  WHERE rh1.role_id = v_role_id
				AND drm.parent_code = (
				  SELECT parent_code
				  FROM mmi_mast_dealer WHERE dealer_name = v_dealer_name
				)

			  UNION ALL

			  SELECT
				mr.role_id,
				mr.role,
				mr.role_level,
				drm1.reporting_role_id,
				drm1.parent_code
			  FROM mmi_mast_role mr
			  JOIN mmi_mast_dealer_role_mapping drm1 ON mr.role_id = drm1.role_id
			  JOIN role_hierarchy rh ON mr.role_id = rh.parent_role_id
			)*/
            WITH RECURSIVE role_hierarchy (role_id, role, role_level, parent_role_id, parent_code, depth) AS (
    SELECT
        rh1.role_id,
        rh1.role,
        rh1.role_level,
        drm.reporting_role_id,
        drm.parent_code,
        1 AS depth
    FROM mmi_mast_role rh1
    JOIN mmi_mast_dealer_role_mapping drm ON rh1.role_id = drm.role_id
    WHERE rh1.role_id = v_role_id
      AND drm.parent_code = (
          -- SELECT parent_code
          -- FROM mmi_mast_dealer WHERE dealer_name = v_dealer_name
			SELECT distinct md.parent_code 
            -- FROM mmi_mast_dealer md 
			-- LEFT JOIN mmi_dealer_location_mapping dlm ON md.parent_code = dlm.parent_code
            FROM mmi_dealer_location_mapping md
			LEFT JOIN mmi_dealer_details dl on dl.dealer_id = md.mapping_dealer_code
			LEFT JOIN mmi_mast_dealer_location mdl on mdl.loc_code = md.location_code
			-- WHERE md.dealer_name = v_dealer_name and mdl.loc_name = v_location
            WHERE dl.dealer_id = v_dealer_name and mdl.loc_name = v_location
      )

    UNION ALL

    SELECT
        mr.role_id,
        mr.role,
        mr.role_level,
        drm1.reporting_role_id,
        drm1.parent_code,
        rh.depth + 1
    FROM mmi_mast_role mr
    JOIN mmi_mast_dealer_role_mapping drm1 ON mr.role_id = drm1.role_id
    JOIN role_hierarchy rh ON mr.role_id = rh.parent_role_id
    WHERE rh.depth < 50
)
			SELECT DISTINCT 
			  CONCAT(urd.first_name, ' ', urd.last_name) AS name,
			  rh.role,
			  rh.role_level,
			  rh.role_id
			FROM role_hierarchy rh
			LEFT JOIN mmi_user_role_mapping urm ON urm.role_id = rh.role_id
			LEFT JOIN mmi_mast_user_registration_detail urd ON urm.user_id = urd.id
			LEFT JOIN mmi_mast_dealer_role_mapping drm ON rh.role_id = drm.reporting_role_id
			-- LEFT JOIN mmi_mast_dealer md ON drm.parent_code = md.parent_code
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.parent_code = drm.parent_code
			LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = dlm.mapping_dealer_code
			LEFT JOIN mmi_mast_dealer_location dl ON dl.loc_code = dlm.location_code
			-- WHERE dlm.dealer_name = v_dealer_name
            WHERE mdl.dealer_id = v_dealer_name
			  AND dl.loc_name = v_location
			  AND rh.role_id <> v_role_id
              AND urd.role_type_id <> 1
			ORDER BY rh.role_id DESC;

    ELSEIF v_type = 'Yes' THEN
        SELECT DISTINCT bucket_name 
        FROM mmi_mast_bucket mb
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.dealer_code = mb.dealer_code
        -- LEFT JOIN mmi_mast_dealer md ON md.parent_code = dlm.parent_code
        LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = dlm.mapping_dealer_code
        LEFT JOIN mmi_mast_dealer_location dl ON dl.loc_code = dlm.location_code
        -- WHERE dlm.dealer_name = v_dealer_name AND dl.loc_name = v_location;
        WHERE mdl.dealer_id = v_dealer_name AND dl.loc_name = v_location;

    ELSE
        SET p_sp_status = '400';
        SET p_message = 'Invalid type value';
        ROLLBACK;
        LEAVE proc_end;
    END IF;
	ELSEIF v_role_type = 'MIBL' THEN
		IF v_type = 'Role Assignment' THEN
			SELECT DISTINCT
			r.role AS role,r.role_id
			FROM mmi_mast_role r
			JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id AND drm.status = '1'
			LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
			LEFT JOIN mmi_mast_role mr ON drm.reporting_role_id = mr.role_id
			LEFT JOIN mmi_mast_role_type mrt ON mrt.id = m.role_type_id
			WHERE r.status = '1' AND m.role_id IS NOT NULL AND mrt.id = 1 AND m.role_type_id 
			IS NOT NULL AND r.role is not null
			GROUP BY  r.role,r.role_id;
         ELSEIF v_type = 'Reporting Manager' THEN
			IF v_role_name IS NULL OR v_role_name = '' THEN
				SET p_sp_status = '400';
				SET p_message = 'Role Name is required for Reporting Manager query';
				ROLLBACK;
				LEAVE proc_end;
			END IF;
			
            SELECT DISTINCT role_id INTO v_role_id
			FROM mmi_mast_role
			WHERE role = v_role_name
			LIMIT 1;
            
            /*WITH RECURSIVE role_hierarchy AS (
			SELECT mr.role_id,mr.role,mr.role_level,
				drm.reporting_role_id
			FROM mmi_mast_role mr
			LEFT JOIN mmi_mast_dealer_role_mapping drm ON mr.role_id = drm.role_id
			WHERE mr.role_id = v_role_id

			UNION ALL

			SELECT mr.role_id,mr.role,mr.role_level,
				drm.reporting_role_id
			FROM mmi_mast_role mr
			LEFT JOIN mmi_mast_dealer_role_mapping drm ON mr.role_id = drm.role_id
			INNER JOIN role_hierarchy rh ON mr.role_id = rh.reporting_role_id
			WHERE drm.parent_code IS NULL
		)
			SELECT DISTINCT rh.role_id,rh.role,rh.role_level,rh.reporting_role_id
			FROM role_hierarchy rh WHERE rh.role_id <> v_role_id
			ORDER BY rh.role_id DESC;*/
            
           /* WITH RECURSIVE role_hierarchy AS (
				SELECT rh1.role_id,rh1.role,rh1.role_level,
					drm.reporting_role_id AS parent_role_id
				FROM mmi_mast_role rh1
					LEFT JOIN mmi_mast_dealer_role_mapping drm ON rh1.role_id = drm.role_id
				WHERE rh1.role_id = v_role_id and drm.parent_code IS NULL
				UNION ALL
				SELECT mr.role_id,mr.role,mr.role_level,drm1.reporting_role_id
				FROM mmi_mast_role mr
					LEFT JOIN mmi_mast_dealer_role_mapping drm1 ON mr.role_id = drm1.role_id
				INNER JOIN role_hierarchy rh ON mr.role_id = rh.parent_role_id
			)*/
            WITH RECURSIVE role_hierarchy (role_id, role, role_level, parent_role_id, depth) AS (
    SELECT
        rh1.role_id,
        rh1.role,
        rh1.role_level,
        drm.reporting_role_id,
        1 AS depth
    FROM mmi_mast_role rh1
    LEFT JOIN mmi_mast_dealer_role_mapping drm ON rh1.role_id = drm.role_id
    WHERE rh1.role_id = v_role_id AND drm.parent_code IS NULL

    UNION ALL

    SELECT
        mr.role_id,
        mr.role,
        mr.role_level,
        drm1.reporting_role_id,
        rh.depth + 1
    FROM mmi_mast_role mr
    LEFT JOIN mmi_mast_dealer_role_mapping drm1 ON mr.role_id = drm1.role_id
    JOIN role_hierarchy rh ON mr.role_id = rh.parent_role_id
    WHERE rh.depth < 50
)
				SELECT DISTINCT 
					CONCAT(urd.first_name, ' ', urd.last_name) AS name,
					rh.role,
					rh.role_level,
					rh.role_id
				FROM 
					role_hierarchy rh
				LEFT JOIN mmi_user_role_mapping urm ON urm.role_id = rh.role_id
				LEFT JOIN mmi_mast_user_registration_detail urd ON urm.user_id = urd.id
				LEFT JOIN mmi_mast_dealer_role_mapping drm ON rh.role_id = drm.reporting_role_id
				WHERE rh.role_id <> v_role_id and drm.parent_code IS NULL and urd.role_type_id = 1
				ORDER BY rh.role_id DESC;
				
        END IF;
    END IF;
    SET p_sp_status = '200';
    SET p_message = 'Success';

    END proc_end;
END ;;
DELIMITER ;
