CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_user_details_By_Id`(
    IN p_json JSON,
    OUT p_status_code VARCHAR(45),
    OUT p_status_message VARCHAR(255)
)
BEGIN
	procedure_end:BEGIN

    DECLARE v_userId INT;
    DECLARE err_code INT;
    DECLARE err_msg TEXT;
    DECLARE v_parent_code VARCHAR(50);  

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
            
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again later.';
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_fetch_user_details_By_Id', 'FETCH_USER_DETAILS_BY_ID', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;

    SET v_userId = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.userId'));
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.parentCode'));

    IF v_userId IS NULL OR v_userId = 0 THEN
        SET p_status_code = '400';
        SET p_status_message = 'Invalid userId provided';
        LEAVE procedure_end;
    END IF;
	
    IF v_parent_code IS NOT NULl THEN
			SELECT DISTINCT 
				urd.first_name,
				urd.last_name,
				urd.mobile_no,
				urd.email_id,
				urd.status,
				dlm.dealer_name,
				urd.address,
				mr.role,
				mu.calling_flag,
				mb.bucket_name,
				mu.lead_flag,
				urd.team_email_flag,
				CONCAT(murd.first_name, ' ', murd.last_name) AS reportingManager,
				mu.ad_flag AS adFlag,
                urd.role_type_id,
                mrt.role_type,
                urd.is_group as isGroup
			FROM mmi_mast_user_registration_detail urd
			LEFT JOIN mmi_user_dealer_mapping udm ON udm.user_id = urd.id
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.dealer_code = udm.dealer_id
			-- LEFT JOIN mmi_mast_dealer md ON md.parent_code = dlm.parent_code
            LEFT JOIN mmi_dealer_details dl ON dlm.mapping_dealer_code = dl.dealer_id-- md.parent_code = dl.parent_code
			LEFT JOIN mmi_user_reporting ur ON ur.user_id = urd.id
			LEFT JOIN mmi_mast_user mu ON mu.user_id = urd.id
			LEFT JOIN mmi_mast_user_registration_detail murd ON murd.id = ur.supervisor_id
			LEFT JOIN mmi_user_role_mapping urm ON urm.user_id = urd.id
			LEFT JOIN mmi_mast_role mr ON mr.role_id = urm.role_id
			LEFT JOIN mmi_bucket_user_mapping bum ON bum.user_id = urd.id
			LEFT JOIN mmi_mast_bucket mb ON bum.bucket_id = mb.id
            LEFT JOIN mmi_mast_role_type mrt on mrt.id = urd.role_type_id
			WHERE urd.id = v_userId;
            
            SET p_status_code = '200';
			SET p_status_message = 'User details fetched successfully';
	ELSE	
			SELECT DISTINCT 
			urd.first_name,
			urd.last_name,
			urd.mobile_no,
			urd.email_id,
			urd.status,
			mr.role,
			urd.team_email_flag,
			CONCAT(murd.first_name, ' ', murd.last_name) AS reportingManager,
			mu.ad_flag AS adFlag,
            urd.role_type_id,
            mrt.role_type,
            urd.sap_code as sapCode,
            urd.is_group as isGroup
		FROM mmi_mast_user_registration_detail urd
		LEFT JOIN mmi_user_reporting ur ON ur.user_id = urd.id
		LEFT JOIN mmi_mast_user mu ON mu.user_id = urd.id
		LEFT JOIN mmi_mast_user_registration_detail murd ON murd.id = ur.supervisor_id
		LEFT JOIN mmi_user_role_mapping urm ON urm.user_id = urd.id
		LEFT JOIN mmi_mast_role mr ON mr.role_id = urm.role_id
        LEFT JOIN mmi_mast_role_type mrt on mrt.id = urd.role_type_id
		WHERE urd.id = v_userId;
    
			SET p_status_code = '200';
			SET p_status_message = 'User details fetched successfully';
	END IF;
    END procedure_end;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_fetch_user_list` */;
