CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_user_list`(
    IN p_json_data JSON,
    OUT p_sp_status VARCHAR(45),
    OUT p_sp_message VARCHAR(255)
)
BEGIN
	procedure_end: BEGIN
	
    DECLARE v_role_type VARCHAR(50);
    DECLARE v_parent_code VARCHAR(50);
	DECLARE v_search_name VARCHAR(100);
    DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 0; 
    DECLARE calculated INT DEFAULT 0;
    DECLARE err_code INT;
    DECLARE err_msg TEXT;


    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

		SET p_sp_status = '500';
        SET p_sp_message = 'An error occurred while fetching user details. Please try again later.';

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_fetch_user_list', 'FETCH_USER_LIST', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;

    SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.limit')) AS UNSIGNED), 10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.offset')) AS UNSIGNED), 0);
    SET calculated = (offsetVal - 1) * limitVal;
    SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.roleType'));
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode'));
	SET v_search_name = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.searchName'));

    IF limitVal IS NULL OR offsetVal IS NULL OR limitVal = '' OR offsetVal = '' THEN
        SET p_sp_status = '300';
        SET p_sp_message = 'Limit or offset cannot be empty';
        LEAVE procedure_end;
    END IF;
	
    IF v_parent_code IS NOT NULL THEN
		SELECT name,contactInfo,role,dealer,location,ReportingManager,status,lockStatus,id,parentCode
		FROM mmi_vw_get_user_list WHERE parentCode = v_parent_code
        AND (
			v_search_name IS NULL OR v_search_name = ''
			OR (
			name LIKE CONCAT('%', v_search_name, '%') OR contactInfo LIKE CONCAT('%', v_search_name, '%')
			OR role LIKE CONCAT('%', v_search_name, '%') OR dealer LIKE CONCAT('%', v_search_name, '%')
			OR location LIKE CONCAT('%', v_search_name, '%') OR ReportingManager LIKE CONCAT('%', v_search_name, '%')
			OR ((v_search_name = 'active' AND status = 1) OR (v_search_name = 'inactive' AND status = 0)
		))) LIMIT limitVal OFFSET calculated;

		SELECT COUNT(*) AS paginationCount 
		FROM mmi_vw_get_user_list WHERE parentCode = v_parent_code
        AND (
			v_search_name IS NULL OR v_search_name = ''
			OR (
			name LIKE CONCAT('%', v_search_name, '%') OR contactInfo LIKE CONCAT('%', v_search_name, '%')
			OR role LIKE CONCAT('%', v_search_name, '%') OR dealer LIKE CONCAT('%', v_search_name, '%')
			OR location LIKE CONCAT('%', v_search_name, '%') OR ReportingManager LIKE CONCAT('%', v_search_name, '%')
			OR ((v_search_name = 'active' AND status = 1) OR (v_search_name = 'inactive' AND status = 0)
		)));
        
        SET p_sp_status = '200';
		SET p_sp_message = 'Dealer User details fetched successfully';
    
    ELSEIF v_role_type = 'DEALER' THEN
		/*SELECT distinct dl.parent_code,dl.dealer_name from mmi_mast_dealer md left join
		mmi_dealer_details dl on md.parent_code = dl.parent_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL; */
        
        SELECT distinct dl.parent_code,concat(dl.dealer_name,' - ',mdl.loc_name,' - ',dl.dealer_id) as dealer_name 
        -- from mmi_mast_dealer md left join
		from mmi_dealer_details dl
		left join mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = dl.dealer_id -- on dlm.parent_code = md.parent_code
		left join mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL; 
		
		SELECT name,contactInfo,role,dealer,location,ReportingManager,status,lockStatus,id,parentCode
		FROM mmi_vw_get_user_list WHERE roleTypeId = 2
        AND (
			v_search_name IS NULL OR v_search_name = ''
			OR (
			name LIKE CONCAT('%', v_search_name, '%') OR contactInfo LIKE CONCAT('%', v_search_name, '%')
			OR role LIKE CONCAT('%', v_search_name, '%') OR dealer LIKE CONCAT('%', v_search_name, '%')
			OR location LIKE CONCAT('%', v_search_name, '%') OR ReportingManager LIKE CONCAT('%', v_search_name, '%')
			OR ((v_search_name = 'active' AND status = 1) OR (v_search_name = 'inactive' AND status = 0)
		))) LIMIT limitVal OFFSET calculated;

		SELECT COUNT(*) AS paginationCount 
		FROM mmi_vw_get_user_list WHERE roleTypeId = 2
        AND (
			v_search_name IS NULL OR v_search_name = ''
			OR (
			name LIKE CONCAT('%', v_search_name, '%') OR contactInfo LIKE CONCAT('%', v_search_name, '%')
			OR role LIKE CONCAT('%', v_search_name, '%') OR dealer LIKE CONCAT('%', v_search_name, '%')
			OR location LIKE CONCAT('%', v_search_name, '%') OR ReportingManager LIKE CONCAT('%', v_search_name, '%')
			OR ((v_search_name = 'active' AND status = 1) OR (v_search_name = 'inactive' AND status = 0)
		)));
        
			SET p_sp_status = '200';
			SET p_sp_message = 'User details fetched successfully';
    ELSE 
		/*SELECT distinct dl.parent_code,dl.dealer_name from mmi_mast_dealer md left join
		mmi_dealer_details dl on md.parent_code = dl.parent_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL;*/
        
        SELECT distinct dl.parent_code,concat(dl.dealer_name,' - ',mdl.loc_name,' - ',dl.dealer_id) as dealer_name 
        -- from mmi_mast_dealer md left join
		from mmi_dealer_details dl -- on md.parent_code = dl.parent_code
		left join mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = dl.dealer_id -- on dlm.parent_code = md.parent_code
		left join mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL; 
        
		SELECT name,contactInfo,role,dealer,location,ReportingManager,status,lockStatus,id
		FROM mmi_vw_get_user_list WHERE roleTypeId = 1
        AND (
			v_search_name IS NULL OR v_search_name = ''
			OR (
			name LIKE CONCAT('%', v_search_name, '%') OR contactInfo LIKE CONCAT('%', v_search_name, '%')
			OR role LIKE CONCAT('%', v_search_name, '%') OR dealer LIKE CONCAT('%', v_search_name, '%')
			OR location LIKE CONCAT('%', v_search_name, '%') OR ReportingManager LIKE CONCAT('%', v_search_name, '%')
			OR ((v_search_name = 'active' AND status = 1) OR (v_search_name = 'inactive' AND status = 0)
		))) LIMIT limitVal OFFSET calculated;

		SELECT COUNT(*) AS paginationCount 
		FROM mmi_vw_get_user_list WHERE roleTypeId = 1
        AND (
			v_search_name IS NULL OR v_search_name = ''
			OR (
			name LIKE CONCAT('%', v_search_name, '%') OR contactInfo LIKE CONCAT('%', v_search_name, '%')
			OR role LIKE CONCAT('%', v_search_name, '%') OR dealer LIKE CONCAT('%', v_search_name, '%')
			OR location LIKE CONCAT('%', v_search_name, '%') OR ReportingManager LIKE CONCAT('%', v_search_name, '%')
			OR ((v_search_name = 'active' AND status = 1) OR (v_search_name = 'inactive' AND status = 0)
		)));

			SET p_sp_status = '200';
			SET p_sp_message = 'User details fetched successfully';
		END IF;
	END procedure_end;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_fetch_user_list_details` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_user_list_details`(
    IN p_json_data JSON,
    OUT p_sp_status varchar(45),
    OUT p_sp_message varchar(45)
)
BEGIN

    DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 0;
    DECLARE calculated INT DEFAULT 0;

    SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.limit')) AS UNSIGNED), 10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.offset')) AS UNSIGNED), 0);
    SET calculated = (offsetVal - 1) * limitVal;

    IF limitVal IS NULL  OR offsetVal IS NULL OR limitVal='' OR offsetVal='' THEN
        SET p_sp_status = "300";
        SET p_sp_message = 'limit or offset cannot be empty';
    ELSE
        select name,contactInfo,role,dealer,location,ReportingManager,status,id from
        mmi_vw_get_user_list LIMIT limitVal OFFSET calculated;

        select count(*) as paginationCount from mmi_vw_get_user_list;

        SET p_sp_status = '200';
        SET p_sp_message = 'User Details Fetched Successfully';
   END IF;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
