CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_fetch_user_profiledetails`(
    IN p_user_id VARCHAR(50),
    IN p_user_email VARCHAR(500),
    OUT sp_status VARCHAR(10),
    OUT message VARCHAR(255)
)
BEGIN 
	
	DECLARE PROCEDURE_TYPE VARCHAR(20) DEFAULT 'SELECT'; -- example type
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
		SET sp_status = '500';
        SET message = 'Internal Server Error';
        
        INSERT INTO mmi_mast_procedure_error 
            (error_code, error_message, procedure_name, procedure_type, ERROR_TIMING, created_by, created_date)
        VALUES 
            (sp_status, message, 'mmi_proc_fetch_user_profiledetails', PROCEDURE_TYPE, CURRENT_TIMESTAMP(), 'SYSTEM', NOW());
    END;

    IF p_user_id IS NULL OR p_user_id = '' THEN
        SET sp_status = '300';
        SET message = 'User ID cannot be null or empty';
    ELSEIF p_user_id REGEXP '[^a-zA-Z0-9_@.-]' THEN
        SET sp_status = '301';
        SET message = 'User ID contains invalid characters';
    ELSE
        -- Safe SELECT (MySQL parameters are safe from injection)
        SELECT 
            urd.first_name,
            urd.last_name,
            urd.mobile_no,
            urd.email_id,
            dlm.dealer_name,
            urd.address,
            mr.role,
            CONCAT(murd.first_name, ' ', murd.last_name) AS reportingManager
        FROM mmi_mast_user_registration_detail urd 
        LEFT JOIN mmi_mast_user mu ON urd.id = mu.user_id 
        LEFT JOIN mmi_user_dealer_mapping udm ON urd.id = udm.user_id 
        LEFT JOIN mmi_dealer_location_mapping dlm ON udm.dealer_id = dlm.dealer_code 
        -- LEFT JOIN mmi_mast_dealer md ON dlm.parent_code = md.parent_code 
        LEFT JOIN mmi_user_role_mapping urm ON mu.user_id = urm.user_id 
        LEFT JOIN mmi_mast_role mr ON urm.role_id = mr.role_id 
        LEFT JOIN mmi_user_reporting ur ON mu.user_id = ur.user_id 
        LEFT JOIN mmi_mast_user_registration_detail murd ON ur.supervisor_id = murd.id
        WHERE mu.user_id = p_user_id and mu.email_id = p_user_email;

        SET sp_status = '200';
        SET message = 'User Profile fetched successfully';
    END IF;
END ;;
DELIMITER ;
