            err_msg = MESSAGE_TEXT;

        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';

        INSERT INTO mmi_mast_procedure_error (
            error_code,
            error_message,
            procedure_name,
            procedure_type,
            error_timing,
            created_by,
            created_date
        ) VALUES (
            err_code,
            err_msg,
            'mmi_proc_filter_renewal_dashboard_data',
            'FETCH_FILTER_RENEWAL_DASHBOARD',
            CURRENT_TIMESTAMP(),
            'SYSTEM',
            NOW()
        );
    END;

    SET v_roleType = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.type'));
	SET v_parent_codes = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCodes'));
    SET v_user_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.userId'));
    SET v_dealer_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerId'));

--    SET v_parent_codes = JSON_EXTRACT(p_json_data, '$.parentCodes'); 
-- SET v_user_id = JSON_EXTRACT(p_json_data, '$.userId');
   -- SET v_dealer_id = JSON_EXTRACT(p_json_data, '$.dealerId');
    
    IF v_roleType = 'MIBL' THEN
           SELECT segment_id, segment as Segment FROM mmi_mast_segment;
            -- SELECT DISTINCT zone as Zone FROM mmi_dealer_location_mapping Where zone is not null and zone !='';
            -- SELECT DISTINCT state as State FROM mmi_mast_dealer_location Where state is not null and state !='';
            SELECT DISTINCT zone as Zone FROM mmi_dealer_location_mapping dlm
			INNER JOIN mmi_dealer_details dl on dlm.dealer_code = dl.dealer_id Where zone is not null and zone !='';
            SELECT DISTINCT state as State FROM mmi_mast_dealer_location mdl
			INNER JOIN mmi_dealer_location_mapping dlm on dlm.location_code = mdl.loc_code 
			INNER JOIN mmi_dealer_details dl on dlm.dealer_code = dl.dealer_id
			Where state is not null and state !='';

			SELECT DISTINCT 
				dlm.dealer_name ,
				mdd.parent_code AS dealer_id
			FROM mmi_dealer_location_mapping dlm
			LEFT JOIN mmi_mast_dealer_location mdl ON dlm.location_code = mdl.loc_code
			LEFT JOIN mmi_dealer_details mdd on dlm.mapping_dealer_code = mdd.dealer_id
			-- LEFT JOIN mmi_mast_dealer mmd ON mdd.parent_code = mmd.parent_code
			WHERE dlm.dealer_name IS NOT NULL;
        
    
    ELSEIF v_roleType = 'Dealer' THEN
        SELECT segment_id, segment as Segment FROM mmi_mast_segment;
        
        WITH RECURSIVE team_hierarchy AS (
			
			SELECT ur.user_id
			FROM mmi_user_reporting ur
			WHERE ur.supervisor_id =v_user_id

			UNION ALL

			
			SELECT ur2.user_id
			FROM mmi_user_reporting ur2
			INNER JOIN team_hierarchy th ON ur2.supervisor_id = th.user_id
		)
		SELECT
			th.user_id as teamMemberId,
			CONCAT(COALESCE(mud.first_name, ''), ' ', COALESCE(mud.last_name, '')) AS teamMemberName
		FROM team_hierarchy th
		JOIN mmi_mast_user mu ON th.user_id = mu.user_id
		JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
		JOIN mmi_mast_user_registration_detail mud ON mu.user_id = mud.id
		WHERE udm.dealer_id = v_dealer_id
		ORDER BY mud.first_name, mud.last_name; 
        
        -- select DISTINCT zone from mmi_dealer_location_mapping dlm
		-- left join mmi_dealer_details dl on dl.parent_code = dlm.parent_code
		-- where dlm.parent_code = v_parent_codes and is_active = 1 and zone is not null and zone !='';

		-- select DISTINCT state from mmi_mast_dealer_location mdl
		-- LEFT JOIN mmi_dealer_location_mapping dlm ON mdl.loc_code = dlm.location_code
		-- LEFT JOIN mmi_dealer_details dl ON dl.parent_code = dlm.parent_code
		-- where dlm.parent_code = v_parent_codes and is_active = 1 and state is not null and state !='';
	
			-- SELECT DISTINCT 
				-- mdd.dealer_name ,
				-- mdd.parent_code AS parent_code
			-- FROM mmi_dealer_location_mapping dlm
			-- LEFT JOIN mmi_mast_dealer_location mdl ON dlm.location_code = mdl.loc_code
			-- LEFT JOIN mmi_dealer_details mdd on dlm.dealer_code = mdd.dealer_id
			-- LEFT JOIN mmi_mast_dealer mmd ON mdd.parent_code = mmd.parent_code
			-- WHERE mmd.dealer_name IS NOT NULL and mdd.parent_code = v_parent_codes and dlm.is_active = 1 ;
        
    END IF;

    
    SET p_status_code = '200';
    SET p_status_message = 'Data fetched successfully';

END ;;
