CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_generate_report_tracking`(
    -- IN report_type VARCHAR(50)
    IN p_json JSON
    -- OUT p_sp_status VARCHAR(45),
    -- OUT p_message VARCHAR(500)
)
BEGIN
	DECLARE report_type VARCHAR(50);
    DECLARE err_code INT;
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
			
            -- SET p_sp_status = '500';
			-- SET p_message = 'An error occurred. Please try again.';
                        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_generate_report_tracking', report_type, CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END; 
    
	SET report_type = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.type'));
    
    -- Lead Funnel Report
    IF report_type = 'lead_funnel' THEN
        SELECT distinct
            l.lead_id,
            l.lead_type AS hot_warm_cold,
            l.lead_status AS converted_or_lost,
            d.disposition AS disposition_status,
            c.customer_name,
            c.customer_phone
        FROM mmi_lead_details l
        LEFT JOIN mmi_call_disposition_history h ON l.lead_id = h.lead_id
        LEFT JOIN mmi_mast_disposition d ON h.dealer_disposition_id = d.disposition_id
        LEFT JOIN mmi_mast_customer_details c ON l.cluster_id = c.cluster_id;

    -- Due Report
    ELSEIF report_type = 'due_report' THEN
        SELECT distinct
            l.lead_id,
            c.customer_name,
            l.policy_expiry_date AS due_date,
            l.lead_status AS policy_status,
            d.disposition AS disposition_status
        FROM mmi_lead_details l
        LEFT JOIN mmi_call_disposition_history h ON l.lead_id = h.lead_id
        LEFT JOIN mmi_mast_disposition d ON h.dealer_disposition_id = d.disposition_id
        LEFT JOIN mmi_mast_customer_details c ON l.cluster_id = c.cluster_id;

    -- Disposition Summary
    ELSEIF report_type = 'dispo_summary' THEN
        SELECT distinct
            d.disposition AS disposition,
            COUNT(h.lead_id) AS lead_count,
            ROUND((COUNT(h.lead_id) / (SELECT COUNT(*) FROM mmi_call_disposition_history)) * 100, 2) AS percentage
        FROM mmi_call_disposition_history h
        JOIN mmi_mast_disposition d ON h.dealer_disposition_id = d.disposition_id
        GROUP BY d.disposition
        ORDER BY lead_count DESC;

    -- Policy Conversion Report
    ELSEIF report_type = 'policy_conversion' THEN
        WITH total_leads AS (
            SELECT 
                vehicle_class,
                COUNT(*) AS total_leads
            FROM mmi_lead_archive_details
            GROUP BY vehicle_class
        ),
        converted_data AS (
            SELECT 
                vehicle_class,
                COUNT(*) AS converted_leads,
                SUM(addon_premium_amount) AS total_premium
            FROM mmi_lead_archive_details
            WHERE lead_status = 'Converted'
            GROUP BY vehicle_class
        )
        SELECT 
            c.vehicle_class AS segment,
            c.converted_leads,
            ROUND((c.converted_leads / t.total_leads) * 100, 2) AS conversion_ratio,
            c.total_premium
        FROM converted_data c
        JOIN total_leads t ON c.vehicle_class = t.vehicle_class;

    END IF;
END ;;
DELIMITER ;
