  DROP TABLE IF EXISTS mmi_dashboard_staging;

CREATE TABLE mmi_dashboard_staging (
    report_date DATE PRIMARY KEY,
    month_num INT,
    total_leads INT,
    total_converted INT,
    KEY idx_month (month_num)
) ENGINE=InnoDB;

INSERT INTO mmi_dashboard_staging (report_date, month_num, total_leads, total_converted)
SELECT
    DATE(created_date) AS rd,
    MONTH(created_date) AS mn, -- This was the problem column
    COUNT(*) AS daily_leads,
    SUM(CASE WHEN lead_status = 'Won' AND converted_flag = 'CRM Renewal' THEN 1 ELSE 0 END) AS daily_won
FROM (
    SELECT created_date, lead_status, converted_flag FROM mmi_lead_archive_details
    WHERE created_date >= DATE_SUB(DATE_FORMAT(CURDATE(), '%Y-%m-01'), INTERVAL 1 MONTH)
    UNION ALL
    SELECT created_date, NULL AS lead_status, NULL AS converted_flag FROM mmi_lead_details
    WHERE created_date >= DATE_SUB(DATE_FORMAT(CURDATE(), '%Y-%m-01'), INTERVAL 1 MONTH)
) combined
GROUP BY rd, mn -- Added 'mn' here to satisfy ONLY_FULL_GROUP_BY
ON DUPLICATE KEY UPDATE
    total_leads = VALUES(total_leads),
    total_converted = VALUES(total_converted);

/* ------------------------------------------------------------------
   PART B: The Final Report (Runs in < 0.1s)
   ------------------------------------------------------------------ */
WITH params AS (
    SELECT
        DATE_SUB(DATE_FORMAT(CURDATE(), '%Y-%m-01'), INTERVAL 1 MONTH) AS lm_start,
        LAST_DAY(DATE_SUB(DATE_FORMAT(CURDATE(), '%Y-%m-01'), INTERVAL 1 MONTH)) AS lm_end,
        DATE_FORMAT(CURDATE(), '%Y-%m-01') AS cm_start,
        LAST_DAY(CURDATE()) AS cm_end
),
months AS (
    SELECT 1 m_num,'Jan' m_name UNION ALL SELECT 2,'Feb' UNION ALL SELECT 3,'Mar' UNION ALL
    SELECT 4,'Apr' UNION ALL SELECT 5,'May' UNION ALL SELECT 6,'Jun' UNION ALL SELECT 7,'Jul' UNION ALL
    SELECT 8,'Aug' UNION ALL SELECT 9,'Sep' UNION ALL SELECT 10,'Oct' UNION ALL SELECT 11,'Nov' UNION ALL SELECT 12,'Dec'
),
week_ranges AS (
    -- Last Month Weeks
    SELECT lm_start as s, lm_end as e, 'last_month' as t, 0 as seq FROM params
    UNION ALL SELECT DATE_ADD(lm_start, INTERVAL 7 DAY), lm_end, 'last_month', 1 FROM params
    UNION ALL SELECT DATE_ADD(lm_start, INTERVAL 14 DAY), lm_end, 'last_month', 2 FROM params
    UNION ALL SELECT DATE_ADD(lm_start, INTERVAL 21 DAY), lm_end, 'last_month', 3 FROM params
    UNION ALL SELECT DATE_ADD(lm_start, INTERVAL 28 DAY), lm_end, 'last_month', 4 FROM params
    -- Current Month Weeks
    UNION ALL SELECT cm_start, cm_end, 'current_month', 0 FROM params
    UNION ALL SELECT DATE_ADD(cm_start, INTERVAL 7 DAY), cm_end, 'current_month', 1 FROM params
    UNION ALL SELECT DATE_ADD(cm_start, INTERVAL 14 DAY), cm_end, 'current_month', 2 FROM params
    UNION ALL SELECT DATE_ADD(cm_start, INTERVAL 21 DAY), cm_end, 'current_month', 3 FROM params
    UNION ALL SELECT DATE_ADD(cm_start, INTERVAL 28 DAY), cm_end, 'current_month', 4 FROM params
),
weekly_stats AS (
    SELECT
        wr.t as month_type,
        wr.s as week_start,
        LEAST(DATE_ADD(wr.s, INTERVAL 6 DAY), wr.e) as week_end,
        SUM(st.total_leads) as leads,
        SUM(st.total_converted) as converted,
        ROW_NUMBER() OVER (PARTITION BY wr.t ORDER BY wr.s) as week_rank
    FROM week_ranges wr
    LEFT JOIN mmi_dashboard_staging st
        ON st.report_date >= wr.s
        AND st.report_date <= LEAST(DATE_ADD(wr.s, INTERVAL 6 DAY), wr.e)
    WHERE wr.s <= wr.e
    GROUP BY wr.t, wr.s, wr.e
),
month_stats AS (
    SELECT month_num, ROUND(SUM(total_converted)*100/NULLIF(SUM(total_leads),0),2) as m_pct
    FROM mmi_dashboard_staging GROUP BY month_num
)
/* FINAL SELECT */
SELECT m.m_name AS report_label, IFNULL(ms.m_pct,0.00) AS monthly_conversion_percent, 0.00 AS weekly_conversion_percent, m.m_num AS sort_key, NULL AS week_start, NULL AS week_end
FROM months m LEFT JOIN month_stats ms ON m.m_num = ms.month_num
UNION ALL
SELECT CONCAT('Week ', week_rank), 0.00, ROUND(converted*100/NULLIF(leads,0),2), CASE WHEN month_type='last_month' THEN 100+week_rank ELSE 200+week_rank END, week_start, week_end
FROM weekly_stats
UNION ALL
SELECT 'Overall Average', ROUND(AVG(m_pct),2), (SELECT ROUND(AVG(converted*100/NULLIF(leads,0)),2) FROM weekly_stats), 999, NULL, NULL
FROM month_stats
ORDER BY sort_key;





