DROP TEMPORARY TABLE IF EXISTS temp_leads;

CREATE TEMPORARY TABLE temp_leads AS
SELECT 
    al.dealer_code,
    COUNT(DISTINCT al.lead_id) AS TotalLeads,
    COUNT(DISTINCT CASE WHEN al.assigned_agent IS NOT NULL THEN al.lead_id END) AS AssignedLeads,
    COUNT(DISTINCT CASE WHEN cdh.lead_id IS NOT NULL THEN al.lead_id END) AS LeadsContacted,
    COUNT(DISTINCT CASE WHEN cdh.lead_id IS NULL THEN al.lead_id END) AS LeadsNotContacted
FROM (
        SELECT lead_id, dealer_code, assigned_agent
        FROM mmi_lead_details
        
        UNION
        
        SELECT lead_id, dealer_code, assigned_agent
        FROM mmi_lead_archive_details
) al
LEFT JOIN mmi_call_disposition_history cdh 
       ON cdh.lead_id = al.lead_id
GROUP BY al.dealer_code;



-- Pagination Count Query
SELECT COUNT(*) AS paginationCount
FROM (
    SELECT 
        -- dlm.dealer_name,
        -- dl.loc_name,
        mdl.dealer_id
    -- FROM mmi_mast_dealer md
    FROM mmi_dealer_details mdl 
        -- ON mdl.parent_code = md.parent_code
    -- LEFT JOIN mmi_dealer_location_mapping dlm 
       -- ON dlm.dealer_code = mdl.dealer_id
    -- LEFT JOIN mmi_mast_dealer_location dl 
       -- ON dl.loc_code = dlm.location_code
    -- LEFT JOIN temp_leads tl 
        -- ON tl.dealer_code = mdl.dealer_id
    WHERE mdl.dealer_id IS NOT NULL
    GROUP BY 
        -- dlm.dealer_name,
        -- dl.loc_name,
        mdl.dealer_id
) AS count_query;



-- Main Dashboard Query with Pagination
SELECT
    dlm.dealer_name AS DealName,
    IFNULL(dl.loc_name, '') AS DealLocation,
    mdl.dealer_id AS DealCode,
    COALESCE(tl.TotalLeads, 0) AS TotalLeads,
    COALESCE(tl.AssignedLeads, 0) AS AssignedLeads,
    COALESCE(tl.LeadsContacted, 0) AS LeadsContacted,
    COALESCE(tl.LeadsNotContacted, 0) AS LeadsNotContacted,

    IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag = 'CRM Renewal' THEN larc.lead_id END) / NULLIF(tl.LeadsContacted, 0)) * 100,2),0) AS WonLeadsPercentage,

    IFNULL(
        ROUND(
            (tl.LeadsNotContacted / NULLIF(tl.TotalLeads, 0)) * 100
        ,2)
    ,0) AS LeadsNotContactedPercentage,

    /*IFNULL(
        ROUND(
            (COUNT(DISTINCT CASE 
                WHEN larc.converted_flag IN ('CRM Renewal','Direct Renewal')
                THEN larc.lead_id END) 
            / NULLIF(tl.TotalLeads,0)) * 100
        ,2)
    ,0) AS RetentionRatio*/
    
    IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag IN ('CRM Renewal') THEN larc.lead_id END) * 100.0)
        / NULLIF(tl.AssignedLeads,0),2),0) AS RetentionRatio

-- FROM mmi_mast_dealer md
FROM mmi_dealer_details mdl 
      -- ON mdl.parent_code = md.parent_code
LEFT JOIN mmi_dealer_location_mapping dlm 
       ON dlm.dealer_code = mdl.dealer_id
LEFT JOIN mmi_mast_dealer_location dl 
       ON dl.loc_code = dlm.location_code
LEFT JOIN temp_leads tl 
       ON tl.dealer_code = mdl.dealer_id
LEFT JOIN mmi_lead_archive_details larc 
       ON larc.dealer_code = mdl.dealer_id

WHERE mdl.dealer_id IS NOT NULL

GROUP BY 
    dlm.dealer_name, 
    dl.loc_name, 
    mdl.dealer_id,
    tl.TotalLeads, 
    tl.AssignedLeads, 
    tl.LeadsContacted, 
    tl.LeadsNotContacted

-- ORDER BY WonLeadsPercentage DESC
ORDER BY 
CASE WHEN sortField = 'Conversion Ratio' AND sortOrder = 'asc' 
THEN IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag = 'CRM Renewal' THEN larc.lead_id END) / NULLIF(tl.LeadsContacted, 0)) * 100,2),0) END ASC,
CASE WHEN sortField = 'Conversion Ratio' AND sortOrder = 'desc' THEN IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag = 'CRM Renewal' THEN larc.lead_id END) / NULLIF(tl.LeadsContacted, 0)) * 100,2),0) END DESC, 
CASE WHEN sortField = 'Retention Ratio' AND sortOrder = 'asc' THEN 
IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag IN ('CRM Renewal') THEN larc.lead_id END) * 100.0)
        / NULLIF(tl.AssignedLeads,0),2),0) END ASC,
CASE WHEN sortField = 'Retention Ratio' AND sortOrder = 'desc' THEN 
IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag IN ('CRM Renewal') THEN larc.lead_id END) * 100.0)
        / NULLIF(tl.AssignedLeads,0),2),0) END DESC  
LIMIT limitVal OFFSET calculated;

