INNER JOIN mmi_dealer_details dl on dlm.dealer_code = dl.dealer_id Where zone is not null and zone !='';

-- 2
-- SELECT DISTINCT state as State FROM mmi_mast_dealer_location Where state is not null and state !='';  -- Get all states
SELECT DISTINCT state as State FROM mmi_mast_dealer_location mdl
INNER JOIN mmi_dealer_location_mapping dlm on dlm.location_code = mdl.loc_code 
INNER JOIN mmi_dealer_details dl on dlm.dealer_code = dl.dealer_id
Where state is not null and state !='';

-- 3 
select distinct mmr.dealer_name,dlm.dealer_code from  mmi_dealer_details mmr 
left join mmi_dealer_location_mapping dlm on dlm.parent_code = mmr.parent_code ;  -- Get all dealers with their Ids
-- 4
SELECT segment_id, segment as Segment FROM mmi_mast_segment WHERE segment is not null;  -- Get all segments

-- 5
SELECT DISTINCT loc.loc_name,dlm.dealer_code FROM mmi_mast_dealer_location loc
LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.location_code = loc.loc_code
left join mmi_dealer_details mdl on mdl.dealer_id = dlm.dealer_code
WHERE FIND_IN_SET((dlm.dealer_code), (v_dealerId));

-- 6 
select distinct loc.loc_name,dlm.dealer_code from mmi_mast_dealer_location loc 
left join mmi_dealer_location_mapping  dlm on dlm.location_code=loc.loc_code
left join mmi_dealer_details mdl on mdl.dealer_id = dlm.dealer_code;

