mmdl.loc_name AS 'Location',mmd.dealer_name AS 'Dealer',
 mdlm.dealer_code AS 'Dealer Id',mdlm.zone AS 'Zone',
mmdl.state AS 'State', mdlm.parent_code AS 'Parent code'
FROM mmi_mast_dealer_location mmdl 
LEFT JOIN mmi_dealer_location_mapping mdlm 
ON mdlm.location_code = mmdl.loc_code 
LEFT JOIN mmi_dealer_details mmd 
ON mmd.parent_code = mdlm.parent_code
WHERE mmd.dealer_name IS NOT NULL AND FIND_IN_SET((mdlm.dealer_code),(v_dealerId));



