              OR l.modified_date BETWEEN v_startDate AND v_endDate))
    )
         
UNION ALL

SELECT 'Users' as Name, IFNULL(COUNT(DISTINCT user.user_id), 0) as Count
FROM mmi_mast_user user
LEFT JOIN mmi_user_dealer_mapping udm ON udm.user_id = user.user_id
LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.dealer_code = udm.dealer_id 
LEFT JOIN mmi_mast_dealer mas ON mas.parent_code = dealLoc.parent_code
LEFT JOIN mmi_dealer_details mdl on mdl.parent_code = mas.parent_code  
LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
LEFT JOIN mmi_lead_details l ON dealLoc.dealer_code = l.dealer_code
where user.status = 1 AND
     (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone) )
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state) )
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId) )
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode) )
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment) )
    AND (
        (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
        OR
        (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
         AND (l.created_date BETWEEN v_startDate AND v_endDate
              OR l.modified_date BETWEEN v_startDate AND v_endDate))
    )
    
UNION ALL

SELECT 'Agents' as Name, IFNULL(COUNT(DISTINCT mu.user_id), 0) as Count
FROM mmi_mast_user mu 
LEFT JOIN mmi_lead_details l ON mu.user_id = l.assigned_agent
LEFT JOIN mmi_user_dealer_mapping udm ON udm.user_id = mu.user_id
LEFT JOIN mmi_dealer_location_mapping map ON map.dealer_code = udm.dealer_id
LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = map.dealer_code
LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = map.location_code
WHERE calling_flag = 'Y' and mu.status=1
    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(map.zone), v_zone) )
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state) )
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId) )
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode) )
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment) )
    AND (
        (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
        OR
        (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
         AND (l.created_date BETWEEN v_startDate AND v_endDate
              OR l.modified_date BETWEEN v_startDate AND v_endDate))
    )
    
UNION ALL

SELECT 'Total Leads' AS Name, IFNULL(COUNT(DISTINCT l.lead_id), 0) AS Count
FROM mmi_lead_details l
LEFT JOIN mmi_dealer_location_mapping loc ON loc.dealer_code = l.dealer_code
LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = loc.dealer_code
LEFT JOIN mmi_mast_dealer mas ON mas.parent_code = mdl.parent_code
LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = loc.location_code
WHERE l.lead_type IN ('Hot', 'Warm', 'Cold')
    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(loc.zone), v_zone) )
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state) )
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId) )
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode) )
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment) )
    AND (
        (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
        OR
        (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
         AND (l.created_date BETWEEN v_startDate AND v_endDate
              OR l.modified_date BETWEEN v_startDate AND v_endDate))
    )

UNION ALL

SELECT 'Hot Leads' AS Name, IFNULL(COUNT(distinct lead_id), 0) as count 
FROM mmi_lead_details l 
LEFT JOIN mmi_dealer_location_mapping loc ON loc.dealer_code = l.dealer_code
LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = loc.dealer_code
LEFT JOIN mmi_mast_dealer mas ON mas.parent_code = mdl.parent_code
LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = loc.location_code
WHERE l.lead_type = 'Hot'
    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(loc.zone), v_zone) )
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state) )
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId) )
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode) )
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment) )
    AND (
        (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
        OR
        (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
         AND (l.created_date BETWEEN v_startDate AND v_endDate
              OR l.modified_date BETWEEN v_startDate AND v_endDate))
    )
         
UNION ALL

