              OR l.modified_date BETWEEN v_startDate AND v_endDate))
    );  */
  
WITH lead_counts AS (
    SELECT
        l.dealer_code,
        COUNT(*) AS total_leads,
        SUM(l.lead_type = 'Hot') AS hot_leads,
        SUM(l.lead_type = 'Warm') AS warm_leads,
        SUM(l.lead_type = 'Cold') AS cold_leads
    FROM mmi_lead_details l
    INNER JOIN mmi_dealer_location_mapping loc ON loc.dealer_code = l.dealer_code
	INNER JOIN mmi_dealer_details mdl on mdl.dealer_id = loc.dealer_code
	INNER JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = loc.location_code
	WHERE l.lead_type IN ('Hot','Warm','Cold')
		AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(loc.zone), v_zone) )
		AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state) )
		AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId) )
		AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode) )
		AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment) )
		AND (
			(v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
			OR
			(v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
			 AND (l.created_date BETWEEN v_startDate AND v_endDate
				  OR l.modified_date BETWEEN v_startDate AND v_endDate))
		) 
    GROUP BY l.dealer_code
),

dealer_counts AS (
    SELECT COUNT(DISTINCT mdl.parent_code) AS dealer_count
    FROM mmi_dealer_details mdl
    INNER JOIN mmi_dealer_location_mapping dlm ON dlm.parent_code = mdl.parent_code
    INNER JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
    LEFT JOIN mmi_lead_details l ON l.dealer_code = dlm.dealer_code
    WHERE 
        (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
        AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
        AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
        AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
        AND (
            ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
            OR
            (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
             AND (l.created_date BETWEEN v_startDate AND v_endDate
                  OR l.modified_date BETWEEN v_startDate AND v_endDate))
        )
),

branch_counts AS (
    SELECT COUNT(DISTINCT dloc.loc_code) AS branch_count
    FROM mmi_mast_dealer_location dloc
    INNER JOIN mmi_dealer_location_mapping dlm ON dlm.location_code = dloc.loc_code
    INNER JOIN mmi_dealer_details mdl ON mdl.dealer_id = dlm.dealer_code
    LEFT JOIN mmi_lead_details l ON l.dealer_code = dlm.dealer_code
    WHERE dlm.status = 0 AND dlm.is_active = 1
    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
    AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR
        (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
         AND (l.created_date BETWEEN v_startDate AND v_endDate
              OR l.modified_date BETWEEN v_startDate AND v_endDate))
    )
),

user_counts AS (
    SELECT IFNULL(COUNT(DISTINCT u.user_id), 0) AS user_count
    FROM mmi_mast_user u
    LEFT JOIN mmi_user_dealer_mapping udm ON udm.user_id = u.user_id
    LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.dealer_code = udm.dealer_id
    LEFT JOIN mmi_dealer_details mdl ON mdl.parent_code = dlm.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
    LEFT JOIN mmi_lead_details l ON l.dealer_code = dlm.dealer_code
    WHERE u.status = 1
    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
    AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR
        (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
         AND (l.created_date BETWEEN v_startDate AND v_endDate
              OR l.modified_date BETWEEN v_startDate AND v_endDate))
    )
),

agent_counts AS (
    SELECT COUNT(DISTINCT u.user_id) AS agent_count
    FROM mmi_mast_user u
    INNER JOIN mmi_user_dealer_mapping udm ON udm.user_id = u.user_id
    INNER JOIN mmi_dealer_location_mapping dlm ON dlm.dealer_code = udm.dealer_id
    INNER JOIN mmi_dealer_details mdl ON mdl.dealer_id = dlm.dealer_code
    INNER JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
    LEFT JOIN mmi_lead_details l ON l.dealer_code = dlm.dealer_code
    WHERE u.calling_flag = 'Y' AND u.status = 1
    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
    AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR
        (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
         AND (l.created_date BETWEEN v_startDate AND v_endDate
              OR l.modified_date BETWEEN v_startDate AND v_endDate))
    )
)

SELECT 'Dealers' AS Name, dealer_count AS Count FROM dealer_counts
UNION ALL
SELECT 'Branch', branch_count FROM branch_counts
UNION ALL
SELECT 'Users', user_count FROM user_counts
UNION ALL
SELECT 'Agents', agent_count FROM agent_counts
UNION ALL
SELECT 'Total Leads', SUM(total_leads) FROM lead_counts
UNION ALL
SELECT 'Hot Leads', SUM(hot_leads) FROM lead_counts
UNION ALL
SELECT 'Warm Leads', SUM(warm_leads) FROM lead_counts
UNION ALL
SELECT 'Cold Leads', SUM(cold_leads) FROM lead_counts;

/*DROP TEMPORARY TABLE IF EXISTS tmp_lead_counts;
DROP TEMPORARY TABLE IF EXISTS tmp_dealer_counts;
DROP TEMPORARY TABLE IF EXISTS tmp_branch_counts;
DROP TEMPORARY TABLE IF EXISTS tmp_user_counts;
DROP TEMPORARY TABLE IF EXISTS tmp_agent_counts;
DROP TEMPORARY TABLE IF EXISTS tmp_lead_summary;


-- Step 1: Lead counts
CREATE TEMPORARY TABLE tmp_lead_counts AS
SELECT
    l.dealer_code,
    COUNT(*) AS total_leads,
    SUM(l.lead_type = 'Hot') AS hot_leads,
    SUM(l.lead_type = 'Warm') AS warm_leads,
    SUM(l.lead_type = 'Cold') AS cold_leads
FROM mmi_lead_details l
INNER JOIN mmi_dealer_location_mapping loc ON loc.dealer_code = l.dealer_code
INNER JOIN mmi_dealer_details mdl ON mdl.dealer_id = loc.dealer_code
INNER JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = loc.location_code
LEFT JOIN tmp_zone z ON z.zone = loc.zone
LEFT JOIN tmp_state s ON s.state = dloc.state
LEFT JOIN tmp_dealer d ON d.parent_code = mdl.parent_code
LEFT JOIN tmp_dealer_loc l2 ON l2.loc_code = dloc.loc_code
LEFT JOIN tmp_segment sg ON sg.segment = l.vehicle_class
WHERE l.lead_type IN ('Hot','Warm','Cold')
  AND (v_zone IS NULL OR v_zone = '' OR z.zone IS NOT NULL)
  AND (v_state IS NULL OR v_state = '' OR s.state IS NOT NULL)
  AND (v_dealerId IS NULL OR v_dealerId = '' OR d.parent_code IS NOT NULL)
  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR l2.loc_code IS NOT NULL)
  AND (v_segment IS NULL OR v_segment = '' OR sg.segment IS NOT NULL)
  AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR l.created_date BETWEEN v_startDate AND v_endDate
        OR l.modified_date BETWEEN v_startDate AND v_endDate
  )
GROUP BY l.dealer_code;

-- Step 2: Dealer counts
CREATE TEMPORARY TABLE tmp_dealer_counts AS
SELECT COUNT(DISTINCT mdl.parent_code) AS dealer_count
FROM mmi_dealer_details mdl
INNER JOIN mmi_dealer_location_mapping dlm ON dlm.parent_code = mdl.parent_code
INNER JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
LEFT JOIN mmi_lead_details l ON l.dealer_code = dlm.dealer_code
LEFT JOIN tmp_zone z ON z.zone = dlm.zone
LEFT JOIN tmp_state s ON s.state = dloc.state
LEFT JOIN tmp_dealer d ON d.parent_code = mdl.parent_code
LEFT JOIN tmp_dealer_loc l2 ON l2.loc_code = dloc.loc_code
LEFT JOIN tmp_segment sg ON sg.segment = l.vehicle_class
WHERE (v_zone IS NULL OR v_zone = '' OR z.zone IS NOT NULL)
  AND (v_state IS NULL OR v_state = '' OR s.state IS NOT NULL)
  AND (v_dealerId IS NULL OR v_dealerId = '' OR d.parent_code IS NOT NULL)
  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR l2.loc_code IS NOT NULL)
  AND (v_segment IS NULL OR v_segment = '' OR sg.segment IS NOT NULL)
  AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR l.created_date BETWEEN v_startDate AND v_endDate
        OR l.modified_date BETWEEN v_startDate AND v_endDate
  );

-- Step 3: Branch counts
CREATE TEMPORARY TABLE tmp_branch_counts AS
SELECT COUNT(DISTINCT dloc.loc_code) AS branch_count
FROM mmi_mast_dealer_location dloc
INNER JOIN mmi_dealer_location_mapping dlm ON dlm.location_code = dloc.loc_code
INNER JOIN mmi_dealer_details mdl ON mdl.dealer_id = dlm.dealer_code
LEFT JOIN mmi_lead_details l ON l.dealer_code = dlm.dealer_code
LEFT JOIN tmp_zone z ON z.zone = dlm.zone
LEFT JOIN tmp_state s ON s.state = dloc.state
LEFT JOIN tmp_dealer d ON d.parent_code = mdl.parent_code
LEFT JOIN tmp_dealer_loc l2 ON l2.loc_code = dloc.loc_code
LEFT JOIN tmp_segment sg ON sg.segment = l.vehicle_class
WHERE dlm.status = 0 AND dlm.is_active = 1
  AND (v_zone IS NULL OR v_zone = '' OR z.zone IS NOT NULL)
  AND (v_state IS NULL OR v_state = '' OR s.state IS NOT NULL)
  AND (v_dealerId IS NULL OR v_dealerId = '' OR d.parent_code IS NOT NULL)
  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR l2.loc_code IS NOT NULL)
  AND (v_segment IS NULL OR v_segment = '' OR sg.segment IS NOT NULL)
  AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR l.created_date BETWEEN v_startDate AND v_endDate
        OR l.modified_date BETWEEN v_startDate AND v_endDate
  );

-- Step 4: User counts
CREATE TEMPORARY TABLE tmp_user_counts AS
SELECT IFNULL(COUNT(DISTINCT u.user_id), 0) AS user_count
FROM mmi_mast_user u
LEFT JOIN mmi_user_dealer_mapping udm ON udm.user_id = u.user_id
LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.dealer_code = udm.dealer_id
LEFT JOIN mmi_dealer_details mdl ON mdl.parent_code = dlm.parent_code
LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
LEFT JOIN mmi_lead_details l ON l.dealer_code = dlm.dealer_code
LEFT JOIN tmp_zone z ON z.zone = dlm.zone
LEFT JOIN tmp_state s ON s.state = dloc.state
LEFT JOIN tmp_dealer d ON d.parent_code = mdl.parent_code
LEFT JOIN tmp_dealer_loc l2 ON l2.loc_code = dloc.loc_code
LEFT JOIN tmp_segment sg ON sg.segment = l.vehicle_class
WHERE u.status = 1
  AND (v_zone IS NULL OR v_zone = '' OR z.zone IS NOT NULL)
  AND (v_state IS NULL OR v_state = '' OR s.state IS NOT NULL)
  AND (v_dealerId IS NULL OR v_dealerId = '' OR d.parent_code IS NOT NULL)
  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR l2.loc_code IS NOT NULL)
  AND (v_segment IS NULL OR v_segment = '' OR sg.segment IS NOT NULL)
  AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR l.created_date BETWEEN v_startDate AND v_endDate
        OR l.modified_date BETWEEN v_startDate AND v_endDate
  );

-- Step 5: Agent counts
CREATE TEMPORARY TABLE tmp_agent_counts AS
SELECT COUNT(DISTINCT u.user_id) AS agent_count
FROM mmi_mast_user u
INNER JOIN mmi_user_dealer_mapping udm ON udm.user_id = u.user_id
INNER JOIN mmi_dealer_location_mapping dlm ON dlm.dealer_code = udm.dealer_id
INNER JOIN mmi_dealer_details mdl ON mdl.dealer_id = dlm.dealer_code
INNER JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
LEFT JOIN mmi_lead_details l ON l.dealer_code = dlm.dealer_code
LEFT JOIN tmp_zone z ON z.zone = dlm.zone
LEFT JOIN tmp_state s ON s.state = dloc.state
LEFT JOIN tmp_dealer d ON d.parent_code = mdl.parent_code
LEFT JOIN tmp_dealer_loc l2 ON l2.loc_code = dloc.loc_code
LEFT JOIN tmp_segment sg ON sg.segment = l.vehicle_class
WHERE u.calling_flag = 'Y' AND u.status = 1
  AND (v_zone IS NULL OR v_zone = '' OR z.zone IS NOT NULL)
  AND (v_state IS NULL OR v_state = '' OR s.state IS NOT NULL)
  AND (v_dealerId IS NULL OR v_dealerId = '' OR d.parent_code IS NOT NULL)
  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR l2.loc_code IS NOT NULL)
  AND (v_segment IS NULL OR v_segment = '' OR sg.segment IS NOT NULL)
  AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR l.created_date BETWEEN v_startDate AND v_endDate
        OR l.modified_date BETWEEN v_startDate AND v_endDate
  );

