WITH total_leads AS (
    SELECT 
        (SELECT COUNT(*) FROM mmi_lead_archive_details l
        INNER JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.dealer_code = l.dealer_code
		INNER JOIN mmi_mast_dealer_location abc ON abc.loc_code = dealLoc.location_code
		INNER JOIN mmi_dealer_details mdl ON mdl.dealer_id = dealLoc.dealer_code
        WHERE -- lead_type IN ('Hot','Warm','Cold')
          (COALESCE(NULLIF(v_zone, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone) > 0)
		  AND (COALESCE(NULLIF(v_state, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(abc.state), v_state) > 0)
		  AND (COALESCE(NULLIF(v_dealerId, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId) > 0)
		  AND (COALESCE(NULLIF(v_dealerLocCode, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(dealLoc.location_code), v_dealerLocCode) > 0)
		  AND (COALESCE(NULLIF(v_segment, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment) > 0)
		  AND (COALESCE(NULLIF(v_startDate, ''), NULL) IS NULL OR l.created_date >= v_startDate)
		  AND (COALESCE(NULLIF(v_endDate, ''), NULL) IS NULL OR l.created_date <= v_endDate)
        ) +
        (SELECT COUNT(*) FROM mmi_lead_details l
        INNER JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.dealer_code = l.dealer_code
		INNER JOIN mmi_mast_dealer_location abc ON abc.loc_code = dealLoc.location_code
		INNER JOIN mmi_dealer_details mdl ON mdl.dealer_id = dealLoc.dealer_code
        WHERE -- lead_type IN ('Hot','Warm','Cold')
          (COALESCE(NULLIF(v_zone, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone) > 0)
		  AND (COALESCE(NULLIF(v_state, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(abc.state), v_state) > 0)
		  AND (COALESCE(NULLIF(v_dealerId, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId) > 0)
		  AND (COALESCE(NULLIF(v_dealerLocCode, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(dealLoc.location_code), v_dealerLocCode) > 0)
		  AND (COALESCE(NULLIF(v_segment, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment) > 0)
		  AND (COALESCE(NULLIF(v_startDate, ''), NULL) IS NULL OR l.created_date >= v_startDate)
		  AND (COALESCE(NULLIF(v_endDate, ''), NULL) IS NULL OR l.created_date <= v_endDate)
        ) AS total_cnt
),

latest_cdh AS (
    SELECT
        cdh.id,
        cdh.lead_id,
        ROW_NUMBER() OVER (PARTITION BY cdh.lead_id ORDER BY cdh.created_date DESC) AS rn
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_lead_details l ON cdh.lead_id = l.lead_id
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.dealer_code = l.dealer_code
    LEFT JOIN mmi_mast_dealer_location abc ON abc.loc_code = dealLoc.location_code
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = dealLoc.dealer_code
    WHERE (COALESCE(NULLIF(v_zone, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone) > 0)
      AND (COALESCE(NULLIF(v_state, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(abc.state), v_state) > 0)
      AND (COALESCE(NULLIF(v_dealerId, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId) > 0)
      AND (COALESCE(NULLIF(v_dealerLocCode, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(dealLoc.location_code), v_dealerLocCode) > 0)
      AND (COALESCE(NULLIF(v_segment, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment) > 0)
      AND (COALESCE(NULLIF(v_startDate, ''), NULL) IS NULL OR cdh.created_date >= v_startDate)
      AND (COALESCE(NULLIF(v_endDate, ''), NULL) IS NULL OR cdh.created_date <= v_endDate)
)

SELECT 
    x.leadStatus,
    x.count_val AS count,
    ROUND(x.count_val * 100.0 / tl.total_cnt, 2) AS percentage
FROM (
    -- Converted Leads
    SELECT 'Converted' AS leadStatus, COUNT(DISTINCT lead_id) AS count_val
    FROM mmi_lead_archive_details l
    INNER JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.dealer_code = l.dealer_code
	INNER JOIN mmi_mast_dealer_location abc ON abc.loc_code = dealLoc.location_code
	INNER JOIN mmi_dealer_details mdl ON mdl.dealer_id = dealLoc.dealer_code
	WHERE lead_status = 'Won' AND lead_type IN ('Hot','Warm','Cold') 
	  AND converted_flag = 'CRM Renewal'
	  AND (COALESCE(NULLIF(v_zone, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone) > 0)
	  AND (COALESCE(NULLIF(v_state, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(abc.state), v_state) > 0)
	  AND (COALESCE(NULLIF(v_dealerId, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId) > 0)
	  AND (COALESCE(NULLIF(v_dealerLocCode, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(dealLoc.location_code), v_dealerLocCode) > 0)
	  AND (COALESCE(NULLIF(v_segment, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment) > 0)
	  AND (COALESCE(NULLIF(v_startDate, ''), NULL) IS NULL OR l.created_date >= v_startDate)
	  AND (COALESCE(NULLIF(v_endDate, ''), NULL) IS NULL OR l.created_date <= v_endDate)

    UNION ALL
    
    -- Contacted Leads (latest call per lead)
    SELECT 'Contacted', COUNT(DISTINCT lead_id)
    FROM latest_cdh
    WHERE rn = 1

    UNION ALL

    -- Quote Shared
    SELECT 'Quote Shared', COUNT(DISTINCT c.lead_id)
    FROM mmi_call_disposition_history c
    JOIN mmi_agent_disposition_field_response a
         ON a.response_id = c.id
        AND a.field_label = 'Sub Disposition'
        AND a.field_value = 'Shared Quotes'
	LEFT JOIN mmi_lead_details l ON c.lead_id = l.lead_id
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.dealer_code = l.dealer_code
    LEFT JOIN mmi_mast_dealer_location abc ON abc.loc_code = dealLoc.location_code
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = dealLoc.dealer_code
    WHERE (COALESCE(NULLIF(v_zone, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone) > 0)
      AND (COALESCE(NULLIF(v_state, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(abc.state), v_state) > 0)
      AND (COALESCE(NULLIF(v_dealerId, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId) > 0)
      AND (COALESCE(NULLIF(v_dealerLocCode, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(dealLoc.location_code), v_dealerLocCode) > 0)
      AND (COALESCE(NULLIF(v_segment, ''), NULL) IS NULL OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment) > 0)
      AND (COALESCE(NULLIF(v_startDate, ''), NULL) IS NULL OR c.created_date >= v_startDate)
      AND (COALESCE(NULLIF(v_endDate, ''), NULL) IS NULL OR c.created_date <= v_endDate)   

    UNION ALL

    -- Total Leads
    SELECT 'Total Leads', total_cnt
    FROM total_leads
) AS x
CROSS JOIN total_leads tl
ORDER BY FIELD(x.leadStatus,'Converted','Contacted','Quote Shared','Total Leads');

