    LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = dealLoc.dealer_code
    LEFT JOIN mmi_mast_dealer mas ON mas.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location abc ON abc.loc_code = dealLoc.location_code
    WHERE l.created_date BETWEEN (SELECT last_month_start FROM params)
      AND (SELECT current_month_end FROM params) AND
    (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(IFNULL(dealLoc.zone, ''), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(IFNULL(abc.state, ''), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(IFNULL(mdl.parent_code, ''), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(IFNULL(abc.loc_code, ''), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(IFNULL(l.vehicle_class, ''), v_segment))
    AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR
        (l.created_date BETWEEN v_startDate AND v_endDate) 
        OR
        (l.modified_date BETWEEN v_startDate AND v_endDate)
    )
       -- WHERE created_date BETWEEN (SELECT last_month_start FROM params)
           -- AND (SELECT current_month_end FROM params)
    ) combined
),

week_ranges AS (
    SELECT
        tm.last_month_year AS yr,
        tm.last_month_num AS mon,
        DATE_ADD(tm.last_month_start, INTERVAL w.seq * 7 DAY) AS week_start,
        LEAST(
            DATE_ADD(tm.last_month_start, INTERVAL (w.seq * 7 + 6) DAY),
            tm.last_month_end
        ) AS week_end,
        'last_month' AS month_type
    FROM target_months tm
    JOIN (
        SELECT 0 AS seq UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4
            UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7
    ) w
    WHERE DATE_ADD(tm.last_month_start, INTERVAL w.seq * 7 DAY) <= tm.last_month_end

    UNION ALL

    SELECT
        tm.current_month_year AS yr,
        tm.current_month_num AS mon,
        DATE_ADD(tm.current_month_start, INTERVAL w.seq * 7 DAY) AS week_start,
        LEAST(
            DATE_ADD(tm.current_month_start, INTERVAL (w.seq * 7 + 6) DAY),
            tm.current_month_end
        ) AS week_end,
        'current_month' AS month_type
    FROM target_months tm
    JOIN (
        SELECT 0 AS seq UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4
            UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7
    ) w
    WHERE DATE_ADD(tm.current_month_start, INTERVAL w.seq * 7 DAY) <= tm.current_month_end
),

weekly_data AS (
    SELECT
        wr.month_type,
        wr.week_start,
        wr.week_end,
        COUNT(b.lead_id) AS lead_cnt,
        SUM(COALESCE(b.is_converted, 0)) AS converted_cnt,
        IFNULL(
            ROUND(SUM(COALESCE(b.is_converted, 0)) * 100.0 / NULLIF(COUNT(b.lead_id), 0), 2),
            0.00
        ) AS weekly_conversion_percent,
        ROW_NUMBER() OVER (PARTITION BY wr.month_type ORDER BY wr.week_start) AS week_rank
    FROM week_ranges wr
    LEFT JOIN base_data b
      ON b.created_date BETWEEN wr.week_start AND wr.week_end
    GROUP BY wr.month_type, wr.week_start, wr.week_end
),

month_conversion_data AS (
    SELECT
        month_num,
        SUM(is_converted) AS total_converted,
        COUNT(*) AS total_leads,
        IFNULL( ROUND( SUM(is_converted) * 100.0 / NULLIF(COUNT(*), 0 ), 2 ), 0.00 ) AS monthly_conversion_percent
    FROM base_data
    GROUP BY month_num
),

all_12_month_values AS (
    SELECT 
        COALESCE(mcd.monthly_conversion_percent, 0.00) AS monthly_conversion_percent
    FROM months m
    LEFT JOIN month_conversion_data mcd ON m.month_num = mcd.month_num
),

overall_weekly_avg AS (
    SELECT
        COUNT(*) AS total_weeks,
        SUM(weekly_conversion_percent) AS sum_weekly_pct,
        ROUND(SUM(weekly_conversion_percent) / NULLIF(COUNT(*), 0), 2) AS avg_weekly_conversion
    FROM weekly_data
)

-- Final combined result
SELECT
    m.month_name AS report_label,
    COALESCE(mcd.monthly_conversion_percent, 0.00) AS monthly_conversion_percent,
    0.00 AS weekly_conversion_percent,
    m.month_num AS sort_key,
    NULL AS week_start,
    NULL AS week_end
FROM months m
LEFT JOIN month_conversion_data mcd ON m.month_num = mcd.month_num

UNION ALL

SELECT
    CONCAT('Week ', wd.week_rank) AS report_label,
    0.00 AS monthly_conversion_percent,
    wd.weekly_conversion_percent AS weekly_conversion_percent,
    CASE WHEN wd.month_type = 'last_month' THEN 100 + wd.week_rank ELSE 200 + wd.week_rank END AS sort_key,
    wd.week_start,
    wd.week_end
FROM weekly_data wd 

UNION ALL 

SELECT
    'Overall Average' AS report_label,
    (SELECT ROUND(AVG(monthly_conversion_percent), 2) FROM all_12_month_values) AS monthly_conversion_percent,
    (SELECT avg_weekly_conversion FROM overall_weekly_avg) AS weekly_conversion_percent,
    999 AS sort_key,
    NULL, NULL
FROM month_conversion_data mcd

ORDER BY sort_key;*/

