WITH params AS (
    SELECT
        DATE_SUB(DATE_FORMAT(CURDATE(), '%Y-%m-01'), INTERVAL 1 MONTH) AS last_month_start,
        LAST_DAY(DATE_SUB(DATE_FORMAT(CURDATE(), '%Y-%m-01'), INTERVAL 1 MONTH)) AS last_month_end,
        DATE_FORMAT(CURDATE(), '%Y-%m-01') AS current_month_start,
        LAST_DAY(CURDATE()) AS current_month_end
),

target_months AS (
    SELECT
        MONTH(last_month_start) AS last_month_num,
        YEAR(last_month_start) AS last_month_year,
        MONTH(current_month_start) AS current_month_num,
        YEAR(current_month_start) AS current_month_year,
        last_month_start, last_month_end, current_month_start, current_month_end
    FROM params
),

months AS (
    SELECT 1 AS month_num, 'Jan' AS month_name UNION ALL
    SELECT 2, 'Feb' UNION ALL
    SELECT 3, 'Mar' UNION ALL
    SELECT 4, 'Apr' UNION ALL
    SELECT 5, 'May' UNION ALL
    SELECT 6, 'Jun' UNION ALL
    SELECT 7, 'Jul' UNION ALL
    SELECT 8, 'Aug' UNION ALL
    SELECT 9, 'Sep' UNION ALL
    SELECT 10, 'Oct' UNION ALL
    SELECT 11, 'Nov' UNION ALL
    SELECT 12, 'Dec'
),

