    LEFT JOIN mmi_user_dealer_mapping udm ON udm.user_id = l.assigned_agent
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.dealer_code = l.dealer_code
    LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = dealLoc.dealer_code
    LEFT JOIN mmi_mast_dealer mas ON mas.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location abc ON abc.loc_code = dealLoc.location_code
    WHERE l.created_date BETWEEN (SELECT last_month_start FROM params)
      AND (SELECT current_month_end FROM params) AND
    (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(IFNULL(dealLoc.zone, ''), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(IFNULL(abc.state, ''), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(IFNULL(mdl.parent_code, ''), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(IFNULL(abc.loc_code, ''), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(IFNULL(l.vehicle_class, ''), v_segment))
    AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR
        (l.created_date BETWEEN v_startDate AND v_endDate) 
        OR
        (l.modified_date BETWEEN v_startDate AND v_endDate)
    )
),*/

base_data AS (
    SELECT
        lead_id,
        DATE(created_date) AS created_date,
        MONTH(created_date) AS month_num,
        YEAR(created_date) AS year,
        CASE WHEN lead_status = 'Won' AND converted_flag = 'CRM Renewal' THEN 1 ELSE 0 END AS is_converted
    FROM (
        SELECT l.lead_id, l.created_date, l.lead_status, l.converted_flag FROM mmi_lead_archive_details l
        -- WHERE created_date BETWEEN (SELECT last_month_start FROM params)
           -- AND (SELECT current_month_end FROM params)
        LEFT JOIN mmi_user_dealer_mapping udm ON udm.user_id = l.assigned_agent
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.dealer_code = l.dealer_code
    LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = dealLoc.dealer_code
    LEFT JOIN mmi_mast_dealer mas ON mas.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location abc ON abc.loc_code = dealLoc.location_code
    WHERE l.created_date BETWEEN (SELECT last_month_start FROM params)
      AND (SELECT current_month_end FROM params) AND
    (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(IFNULL(dealLoc.zone, ''), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(IFNULL(abc.state, ''), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(IFNULL(mdl.parent_code, ''), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(IFNULL(abc.loc_code, ''), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(IFNULL(l.vehicle_class, ''), v_segment))
    AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR
        (l.created_date BETWEEN v_startDate AND v_endDate) 
        OR
        (l.modified_date BETWEEN v_startDate AND v_endDate)
    )
        UNION
        SELECT l.lead_id, l.created_date, l.lead_status, NULL FROM mmi_lead_details l
        LEFT JOIN mmi_user_dealer_mapping udm ON udm.user_id = l.assigned_agent
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.dealer_code = l.dealer_code
    LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = dealLoc.dealer_code
    LEFT JOIN mmi_mast_dealer mas ON mas.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location abc ON abc.loc_code = dealLoc.location_code
    WHERE l.created_date BETWEEN (SELECT last_month_start FROM params)
      AND (SELECT current_month_end FROM params) AND
    (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(IFNULL(dealLoc.zone, ''), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(IFNULL(abc.state, ''), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(IFNULL(mdl.parent_code, ''), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(IFNULL(abc.loc_code, ''), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(IFNULL(l.vehicle_class, ''), v_segment))
    AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR
        (l.created_date BETWEEN v_startDate AND v_endDate) 
        OR
        (l.modified_date BETWEEN v_startDate AND v_endDate)
    )
       -- WHERE created_date BETWEEN (SELECT last_month_start FROM params)
           -- AND (SELECT current_month_end FROM params)
    ) combined
),

week_ranges AS (
    SELECT
        tm.last_month_year AS yr,
        tm.last_month_num AS mon,
        DATE_ADD(tm.last_month_start, INTERVAL w.seq * 7 DAY) AS week_start,
        LEAST(
            DATE_ADD(tm.last_month_start, INTERVAL (w.seq * 7 + 6) DAY),
            tm.last_month_end
        ) AS week_end,
        'last_month' AS month_type
    FROM target_months tm
    JOIN (
        SELECT 0 AS seq UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4
            UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7
    ) w
    WHERE DATE_ADD(tm.last_month_start, INTERVAL w.seq * 7 DAY) <= tm.last_month_end

    UNION ALL

    SELECT
        tm.current_month_year AS yr,
        tm.current_month_num AS mon,
        DATE_ADD(tm.current_month_start, INTERVAL w.seq * 7 DAY) AS week_start,
        LEAST(
            DATE_ADD(tm.current_month_start, INTERVAL (w.seq * 7 + 6) DAY),
            tm.current_month_end
        ) AS week_end,
        'current_month' AS month_type
    FROM target_months tm
    JOIN (
        SELECT 0 AS seq UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4
            UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7
    ) w
    WHERE DATE_ADD(tm.current_month_start, INTERVAL w.seq * 7 DAY) <= tm.current_month_end
),

weekly_data AS (
    SELECT
        wr.month_type,
        wr.week_start,
        wr.week_end,
        COUNT(b.lead_id) AS lead_cnt,
        SUM(COALESCE(b.is_converted, 0)) AS converted_cnt,
        IFNULL(
            ROUND(SUM(COALESCE(b.is_converted, 0)) * 100.0 / NULLIF(COUNT(b.lead_id), 0), 2),
            0.00
        ) AS weekly_conversion_percent,
        ROW_NUMBER() OVER (PARTITION BY wr.month_type ORDER BY wr.week_start) AS week_rank
    FROM week_ranges wr
    LEFT JOIN base_data b
      ON b.created_date BETWEEN wr.week_start AND wr.week_end
    GROUP BY wr.month_type, wr.week_start, wr.week_end
),

month_conversion_data AS (
    SELECT
        month_num,
        SUM(is_converted) AS total_converted,
        COUNT(*) AS total_leads,
        IFNULL( ROUND( SUM(is_converted) * 100.0 / NULLIF(COUNT(*), 0 ), 2 ), 0.00 ) AS monthly_conversion_percent
    FROM base_data
    GROUP BY month_num
),

all_12_month_values AS (
    SELECT 
        COALESCE(mcd.monthly_conversion_percent, 0.00) AS monthly_conversion_percent
    FROM months m
    LEFT JOIN month_conversion_data mcd ON m.month_num = mcd.month_num
),

overall_weekly_avg AS (
    SELECT
        COUNT(*) AS total_weeks,
        SUM(weekly_conversion_percent) AS sum_weekly_pct,
        ROUND(SUM(weekly_conversion_percent) / NULLIF(COUNT(*), 0), 2) AS avg_weekly_conversion
    FROM weekly_data
)

-- Final combined result
SELECT
    m.month_name AS report_label,
    COALESCE(mcd.monthly_conversion_percent, 0.00) AS monthly_conversion_percent,
    0.00 AS weekly_conversion_percent,
    m.month_num AS sort_key,
    NULL AS week_start,
    NULL AS week_end
FROM months m
LEFT JOIN month_conversion_data mcd ON m.month_num = mcd.month_num

UNION ALL

SELECT
    CONCAT('Week ', wd.week_rank) AS report_label,
    0.00 AS monthly_conversion_percent,
    wd.weekly_conversion_percent AS weekly_conversion_percent,
    CASE WHEN wd.month_type = 'last_month' THEN 100 + wd.week_rank ELSE 200 + wd.week_rank END AS sort_key,
    wd.week_start,
    wd.week_end
FROM weekly_data wd 

UNION ALL 

SELECT
    'Overall Average' AS report_label,
    (SELECT ROUND(AVG(monthly_conversion_percent), 2) FROM all_12_month_values) AS monthly_conversion_percent,
    (SELECT avg_weekly_conversion FROM overall_weekly_avg) AS weekly_conversion_percent,
    999 AS sort_key,
    NULL, NULL
FROM month_conversion_data mcd

ORDER BY sort_key;

            SET SP_STATUS = '200';
            SET MESSAGE = 'Filtered admin dashboard data fetched successfully.';
            
	ELSEIF type = 'downloadInactiveLeadExcel' AND v_role_type = 'MIBL' THEN

			SET v_zone = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.zone'));
            SET v_dealerName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerName'));
            SET v_branch = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.location'));
            SET v_segment = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.segment'));
            SET v_startDate = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.startDate'));
            SET v_endDate = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.endDate'));
            SET v_leadType = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.leadType'));
            SET v_dealerCode = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
            SET v_dealerLocCode = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerLocCode'));
            SET v_parentCode = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentCode'));
            SET v_state = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.state'));
            SET v_dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'));
            SET v_modifiedEndDate = v_endDate;--  same as end date 

DROP TEMPORARY TABLE IF EXISTS temp_leads;
DROP TEMPORARY TABLE IF EXISTS temp_contacted;
DROP TEMPORARY TABLE IF EXISTS temp_won;
DROP TEMPORARY TABLE IF EXISTS temp_retention;

DROP TEMPORARY TABLE IF EXISTS tmp_zone;
DROP TEMPORARY TABLE IF EXISTS tmp_state;
DROP TEMPORARY TABLE IF EXISTS tmp_dealer;
DROP TEMPORARY TABLE IF EXISTS tmp_dealer_loc;
DROP TEMPORARY TABLE IF EXISTS tmp_segment;
    -- Drop temporary tables if exist
  /*  DROP TEMPORARY TABLE IF EXISTS temp_leads;
    DROP TEMPORARY TABLE IF EXISTS temp_contacted;
    DROP TEMPORARY TABLE IF EXISTS temp_won;
    DROP TEMPORARY TABLE IF EXISTS temp_retention;
    
    DROP TEMPORARY TABLE IF EXISTS tmp_zone;
DROP TEMPORARY TABLE IF EXISTS tmp_state;
DROP TEMPORARY TABLE IF EXISTS tmp_dealer;
DROP TEMPORARY TABLE IF EXISTS tmp_dealer_loc;
DROP TEMPORARY TABLE IF EXISTS tmp_segment;

CREATE TEMPORARY TABLE tmp_zone (zone VARCHAR(50));
CREATE TEMPORARY TABLE tmp_state (state VARCHAR(50));
CREATE TEMPORARY TABLE tmp_dealer (parent_code VARCHAR(50));
CREATE TEMPORARY TABLE tmp_dealer_loc (loc_code VARCHAR(50));
CREATE TEMPORARY TABLE tmp_segment (segment VARCHAR(50));*/

DROP TEMPORARY TABLE IF EXISTS tmp_zone;
CREATE TEMPORARY TABLE tmp_zone (
    zone VARCHAR(50) PRIMARY KEY
);

IF v_zone IS NOT NULL AND v_zone <> '' THEN
    INSERT INTO tmp_zone
    SELECT DISTINCT TRIM(value)
    FROM JSON_TABLE(
        CONCAT('["', REPLACE(v_zone, ',', '","'), '"]'),
        '$[*]' COLUMNS(value VARCHAR(50) PATH '$')
    ) jt;
END IF;


DROP TEMPORARY TABLE IF EXISTS tmp_state;
CREATE TEMPORARY TABLE tmp_state (
    state VARCHAR(50) PRIMARY KEY
);

IF v_state IS NOT NULL AND v_state <> '' THEN
    INSERT INTO tmp_state
    SELECT DISTINCT TRIM(value)
    FROM JSON_TABLE(
        CONCAT('["', REPLACE(v_state, ',', '","'), '"]'),
        '$[*]' COLUMNS(value VARCHAR(50) PATH '$')
    ) jt;
END IF;


DROP TEMPORARY TABLE IF EXISTS tmp_dealer;
CREATE TEMPORARY TABLE tmp_dealer (
    parent_code VARCHAR(50) PRIMARY KEY
);

IF v_dealerId IS NOT NULL AND v_dealerId <> '' THEN
    INSERT INTO tmp_dealer
    SELECT DISTINCT TRIM(value)
    FROM JSON_TABLE(
        CONCAT('["', REPLACE(v_dealerId, ',', '","'), '"]'),
        '$[*]' COLUMNS(value VARCHAR(50) PATH '$')
    ) jt;
END IF;


DROP TEMPORARY TABLE IF EXISTS tmp_dealer_loc;
CREATE TEMPORARY TABLE tmp_dealer_loc (
    loc_code VARCHAR(50) PRIMARY KEY
);

IF v_dealerLocCode IS NOT NULL AND v_dealerLocCode <> '' THEN
    INSERT INTO tmp_dealer_loc
    SELECT DISTINCT TRIM(value)
    FROM JSON_TABLE(
        CONCAT('["', REPLACE(v_dealerLocCode, ',', '","'), '"]'),
        '$[*]' COLUMNS(value VARCHAR(50) PATH '$')
    ) jt;
END IF;


DROP TEMPORARY TABLE IF EXISTS tmp_segment;
CREATE TEMPORARY TABLE tmp_segment (
    segment VARCHAR(50) PRIMARY KEY
);

IF v_segment IS NOT NULL AND v_segment <> '' THEN
    INSERT INTO tmp_segment
    SELECT DISTINCT TRIM(value)
    FROM JSON_TABLE(
        CONCAT('["', REPLACE(v_segment, ',', '","'), '"]'),
        '$[*]' COLUMNS(value VARCHAR(50) PATH '$')
    ) jt;
END IF;


/*DROP TEMPORARY TABLE IF EXISTS tmp_dealer_code;
CREATE TEMPORARY TABLE tmp_dealer_code (
    dealer_code VARCHAR(50) PRIMARY KEY
);

IF v_dealerCode IS NOT NULL AND v_dealerCode <> '' THEN
    INSERT INTO tmp_dealer_code
    SELECT DISTINCT TRIM(value)
    FROM JSON_TABLE(
        CONCAT('["', REPLACE(v_dealerCode, ',', '","'), '"]'),
        '$[*]' COLUMNS(value VARCHAR(50) PATH '$')
    ) jt;
END IF;*/

    -- =========================
    -- TEMP LEADS (ACTIVE + ARCHIVE)
    -- =========================
    DROP TEMPORARY TABLE IF EXISTS temp_leads;
    CREATE TEMPORARY TABLE temp_leads
    SELECT
        lead_id,
        dealer_code,
        vehicle_class,
        created_date,
        modified_date,
        assigned_agent
    FROM mmi_lead_details

    UNION ALL

    SELECT
        lead_id,
        dealer_code,
        vehicle_class,
        created_date,
        modified_date,
        assigned_agent
    FROM mmi_lead_archive_details;


    -- =========================
    -- CONTACTED LEADS
    -- =========================
    DROP TEMPORARY TABLE IF EXISTS temp_contacted;
    CREATE TEMPORARY TABLE temp_contacted AS
    SELECT DISTINCT lead_id
    FROM mmi_call_disposition_history;


    -- =========================
    -- WON LEADS
    -- =========================
    DROP TEMPORARY TABLE IF EXISTS temp_won;
    CREATE TEMPORARY TABLE temp_won AS
    SELECT DISTINCT lead_id
    FROM mmi_lead_archive_details
    WHERE lead_status = 'Won'
      AND converted_flag = 'CRM Renewal';


    -- =========================
    -- RETENTION LEADS
    -- =========================
    DROP TEMPORARY TABLE IF EXISTS temp_retention;
    CREATE TEMPORARY TABLE temp_retention AS
    SELECT DISTINCT lead_id
	FROM mmi_lead_archive_details
    WHERE lead_status = 'Won'
     AND converted_flag = 'CRM Renewal';
    -- AND lead_source_type = 'Renewal';


    -- =========================
    -- MAIN EXCEL QUERY (NO LIMIT)
    -- =========================

    SELECT
        dlm.dealer_name AS DealName,
        IFNULL(dl.loc_name, '') AS DealLocation,
        mdl.dealer_id AS DealCode,

        COUNT(DISTINCT tl.lead_id) AS TotalLeads,

        COUNT(DISTINCT CASE 
            WHEN tl.assigned_agent IS NOT NULL 
            THEN tl.lead_id 
        END) AS AssignedLeads,

        COUNT(DISTINCT cl.lead_id) AS LeadsContacted,

        COUNT(DISTINCT CASE 
            WHEN cl.lead_id IS NULL 
            THEN tl.lead_id 
        END) AS LeadsNotContacted,

        ROUND(
            IFNULL(
                COUNT(DISTINCT wl.lead_id) 
                / NULLIF(COUNT(DISTINCT cl.lead_id),0) * 100
            ,0),
        2) AS WonLeadsPercentage,

        ROUND(
            IFNULL(
                COUNT(DISTINCT CASE 
                    WHEN cl.lead_id IS NULL 
                    THEN tl.lead_id 
                END) 
                / NULLIF(COUNT(DISTINCT tl.lead_id),0) * 100
            ,0),
        2) AS LeadsNotContactedPercentage,

       /* ROUND(
            IFNULL(
                COUNT(DISTINCT tr.lead_id) 
                / NULLIF(COUNT(DISTINCT tl.lead_id),0) * 100
            ,0),
        2) AS RetentionRatio */
        
        ROUND(
    IFNULL(
        COUNT(DISTINCT tr.lead_id) 
        /
        NULLIF(COUNT(DISTINCT CASE WHEN tl.assigned_agent IS NOT NULL THEN tl.lead_id END),0) * 100
      ,0),
      2) AS RetentionRatio

    -- FROM mmi_mast_dealer md
    FROM mmi_dealer_details mdl 
        -- ON mdl.parent_code = md.parent_code

    LEFT JOIN mmi_dealer_location_mapping dlm 
        ON dlm.dealer_code = mdl.dealer_id

    LEFT JOIN mmi_mast_dealer_location dl 
        ON dl.loc_code = dlm.location_code

    LEFT JOIN temp_leads tl 
        ON tl.dealer_code = mdl.dealer_id

    LEFT JOIN temp_contacted cl 
        ON cl.lead_id = tl.lead_id

    LEFT JOIN temp_won wl 
        ON wl.lead_id = tl.lead_id

    LEFT JOIN temp_retention tr 
        ON tr.lead_id = tl.lead_id

    WHERE mdl.dealer_id IS NOT NULL

      /*AND (v_zone IS NULL OR v_zone = '' 
           OR EXISTS (SELECT 1 FROM tmp_zone z WHERE z.zone = dlm.zone))

      AND (v_state IS NULL OR v_state = '' 
           OR EXISTS (SELECT 1 FROM tmp_state s WHERE s.state = dl.state))

      AND (v_dealerId IS NULL OR v_dealerId = '' 
           OR EXISTS (SELECT 1 FROM tmp_dealer d WHERE d.parent_code = mdl.parent_code))

      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' 
           OR EXISTS (SELECT 1 FROM tmp_dealer_loc l WHERE l.loc_code = dl.loc_code))

      AND (v_segment IS NULL OR v_segment = '' 
           OR EXISTS (SELECT 1 FROM tmp_segment sg WHERE sg.segment = tl.vehicle_class))*/
      AND (v_zone IS NULL OR v_zone = '' OR dlm.zone IN (SELECT zone FROM tmp_zone))
	  AND (v_state IS NULL OR v_state = '' OR dl.state IN (SELECT state FROM tmp_state))
	  AND (v_dealerId IS NULL OR v_dealerId = '' OR mdl.parent_code IN (SELECT parent_code FROM tmp_dealer))
	  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR dl.loc_code IN (SELECT loc_code FROM tmp_dealer_loc))
	  AND (v_segment IS NULL OR v_segment = '' OR tl.vehicle_class IN (SELECT segment FROM tmp_segment))      

      AND (
            ((v_startDate IS NULL OR v_startDate = '') 
             AND (v_endDate IS NULL OR v_endDate = ''))
            OR tl.created_date BETWEEN v_startDate AND v_endDate
            OR tl.modified_date BETWEEN v_startDate AND v_endDate
          )

    GROUP BY 
        dlm.dealer_name,
        dl.loc_name,
        mdl.dealer_id;

    -- ORDER BY WonLeadsPercentage DESC;


    -- =========================
    -- DROP TEMP TABLES
    -- =========================
    DROP TEMPORARY TABLE IF EXISTS temp_leads;
    DROP TEMPORARY TABLE IF EXISTS temp_contacted;
    DROP TEMPORARY TABLE IF EXISTS temp_won;
    DROP TEMPORARY TABLE IF EXISTS temp_retention;
    
    DROP TEMPORARY TABLE IF EXISTS tmp_zone;
DROP TEMPORARY TABLE IF EXISTS tmp_state;
DROP TEMPORARY TABLE IF EXISTS tmp_dealer;
DROP TEMPORARY TABLE IF EXISTS tmp_dealer_loc;
DROP TEMPORARY TABLE IF EXISTS tmp_segment;

    SET SP_STATUS = '200';
    SET MESSAGE = 'Excel data fetched successfully.';
        ELSE
            SET SP_STATUS = '400';
            SET MESSAGE = CONCAT('Invalid type: ', type);
        END IF;
    END IF;
END ;;
