DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_admin_inactiveAging_dashboardDetails`(
   IN Json_data JSON,
    IN type VARCHAR(45),
    OUT SP_STATUS VARCHAR(500),
    OUT MESSAGE VARCHAR(500))
BEGIN
    DECLARE v_roleId VARCHAR(45); 
    DECLARE v_userId VARCHAR(45);
    DECLARE v_zone VARCHAR(45);
    DECLARE v_segment VARCHAR(45);
    DECLARE v_startDate VARCHAR(20);
    DECLARE v_endDate VARCHAR(20);
    DECLARE v_leadType VARCHAR(45);
     DECLARE v_dealerCode VARCHAR(450);
    DECLARE v_dealerId TEXT;
    DECLARE v_dealerLocCode VARCHAR(450);
    DECLARE v_parentCode VARCHAR(100);
    DECLARE v_dealerName VARCHAR(500);
	DECLARE v_branch VARCHAR(500);
	DECLARE v_location VARCHAR(500);
	DECLARE v_state VARCHAR(500);
    DECLARE v_role_type VARCHAR(500);
    DECLARE v_modifiedEndDate VARCHAR(20);
    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;
    
    DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 1;
    DECLARE calculated INT DEFAULT 0;
    DECLARE sortField VARCHAR(45);
    DECLARE sortOrder VARCHAR(45);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
        @sqlstate = RETURNED_SQLSTATE, errno = MYSQL_ERRNO, errmsg = MESSAGE_TEXT;
        SET SP_STATUS = 407;
        SET MESSAGE = CONCAT('Something went wrong. Error: ', errno, ' - ', errmsg);

        INSERT INTO mmi_mast_procedure_error (error_code, error_message, procedure_name, procedure_type, ERROR_TIMING, created_by, created_date)
        VALUES (errno, CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg), 'mmi_proc_get_admin_inactiveAging_dashboardDetails', type, CURRENT_TIMESTAMP(), 'SYSTEM', NOW());
    END;

    SET v_roleId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleId'));
    SET v_userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
    SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleType'));
    
    SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data,'$.limit')) AS UNSIGNED),10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data,'$.offset')) AS UNSIGNED),1);
    SET sortField = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.sortField'));
    SET sortOrder = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.sortOrder'));
    
    IF sortField IS NULL OR sortField = '' THEN
        SET sortField = 'Conversion Ratio';
    END IF;

    -- Set default sort order
    IF sortOrder IS NULL OR sortOrder = '' THEN
        SET sortOrder = 'desc'; 
    END IF;
    
    IF offsetVal < 1 THEN
       SET offsetVal = 1;
    END IF;
    
    IF limitVal < 1 THEN
       SET limitVal = 10;
    END IF;
    
    SET calculated = (offsetVal - 1) * limitVal;

    IF v_roleId IS NULL OR v_roleId = '' OR v_roleId = 0
        OR v_userId IS NULL OR v_userId = '' OR v_userId = 0
        OR v_role_type IS NULL OR v_role_type = '' 
    THEN
        SET SP_STATUS = '400';
        SET MESSAGE = CONCAT(
            CASE
                WHEN v_roleId IS NULL OR v_roleId = '' THEN 'roleId is missing'
                WHEN v_roleId = 0 THEN 'roleId is Invalid'
                WHEN v_userId IS NULL OR v_userId = '' THEN 'userId is missing'
                WHEN v_userId = 0 THEN 'userId is Invalid'
                WHEN v_role_type IS NULL OR v_role_type = '' THEN 'Role Type is missing'
                ELSE ''
            END
        );
