-- Main query with all your WHERE filters
SELECT
    dlm.dealer_name AS DealName,
    IFNULL(dl.loc_name, '') AS DealLocation,
    mdl.dealer_id AS DealCode,
    COUNT(DISTINCT tl.lead_id) AS TotalLeads,
    COUNT(DISTINCT CASE WHEN tl.assigned_agent IS NOT NULL THEN tl.lead_id END) AS AssignedLeads,
    COUNT(DISTINCT cl.lead_id) AS LeadsContacted,
    COUNT(DISTINCT CASE WHEN cl.lead_id IS NULL THEN tl.lead_id END) AS LeadsNotContacted,
    ROUND(
        IFNULL(COUNT(DISTINCT wl.lead_id) / NULLIF(COUNT(DISTINCT cl.lead_id),0) * 100, 0),
        2
    ) AS WonLeadsPercentage,
    ROUND(
        IFNULL(COUNT(DISTINCT CASE WHEN cl.lead_id IS NULL THEN tl.lead_id END) / NULLIF(COUNT(DISTINCT tl.lead_id),0) * 100, 0),
        2
    ) AS LeadsNotContactedPercentage,
    ROUND(
    IFNULL(
        COUNT(DISTINCT tr.lead_id) 
        /
        NULLIF(COUNT(DISTINCT CASE WHEN tl.assigned_agent IS NOT NULL THEN tl.lead_id END),0) * 100
      ,0),
      2) AS RetentionRatio
-- FROM mmi_mast_dealer md
FROM mmi_dealer_details mdl -- ON mdl.parent_code = md.parent_code
LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.dealer_code = mdl.dealer_id
LEFT JOIN mmi_mast_dealer_location dl ON dl.loc_code = dlm.location_code
LEFT JOIN temp_leads tl ON tl.dealer_code = mdl.dealer_id
LEFT JOIN temp_contacted cl ON cl.lead_id = tl.lead_id
LEFT JOIN temp_won wl ON wl.lead_id = tl.lead_id
LEFT JOIN temp_retention tr ON tr.lead_id = tl.lead_id
LEFT JOIN mmi_lead_archive_details larc ON larc.dealer_code = mdl.dealer_id
WHERE mdl.dealer_id IS NOT NULL
  AND (v_zone IS NULL OR v_zone = '' OR EXISTS (SELECT 1 FROM tmp_zone z WHERE TRIM(LOWER(z.zone)) = TRIM(LOWER(dlm.zone))))-- z.zone = dlm.zone))
  AND (v_state IS NULL OR v_state = '' OR EXISTS (SELECT 1 FROM tmp_state s WHERE TRIM(LOWER(s.state)) = TRIM(LOWER(dl.state)))) -- s.state = dl.state))
  AND (v_dealerId IS NULL OR v_dealerId = '' OR EXISTS (SELECT 1 FROM tmp_dealer d WHERE TRIM(LOWER(d.parent_code)) = TRIM(LOWER(mdl.parent_code)))) -- d.parent_code = mdl.parent_code))
  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR EXISTS (SELECT 1 FROM tmp_dealer_loc l WHERE TRIM(LOWER(l.loc_code)) = TRIM(LOWER(dl.loc_code)))) -- l.loc_code = dl.loc_code))
  AND (v_segment IS NULL OR v_segment = '' OR EXISTS (SELECT 1 FROM tmp_segment sg WHERE TRIM(LOWER(sg.segment)) = TRIM(LOWER( tl.vehicle_class)))) -- sg.segment = tl.vehicle_class))
  AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR tl.created_date BETWEEN v_startDate AND v_endDate
        OR tl.modified_date BETWEEN v_startDate AND v_endDate
  )
GROUP BY dlm.dealer_name, dl.loc_name, mdl.dealer_id
-- ORDER BY WonLeadsPercentage desc
ORDER BY 
CASE WHEN sortField = 'Conversion Ratio' AND sortOrder = 'asc' 
THEN IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag = 'CRM Renewal' 
THEN larc.lead_id END) / NULLIF(COUNT(cl.lead_id), 0)) * 100,2),0) END ASC,
CASE WHEN sortField = 'Conversion Ratio' AND sortOrder = 'desc' THEN IFNULL(ROUND((COUNT(DISTINCT CASE WHEN
 larc.lead_status = 'Won' AND larc.converted_flag = 'CRM Renewal' THEN larc.lead_id END) / NULLIF(COUNT(cl.lead_id), 0)) * 100,2),0) END DESC, 
CASE WHEN sortField = 'Retention Ratio' AND sortOrder = 'asc' THEN 
IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag IN ('CRM Renewal') THEN larc.lead_id END) * 100.0)
        / NULLIF(COUNT(CASE WHEN tl.assigned_agent IS NOT NULL THEN tl.lead_id END),0),2),0) END ASC,
CASE WHEN sortField = 'Retention Ratio' AND sortOrder = 'desc' THEN 
IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag IN ('CRM Renewal') THEN larc.lead_id END) * 100.0)
        / NULLIF(COUNT(CASE WHEN tl.assigned_agent IS NOT NULL THEN tl.lead_id END),0),2),0) END DESC
LIMIT 10;

