        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR tl.created_date BETWEEN v_startDate AND v_endDate
        OR tl.modified_date BETWEEN v_startDate AND v_endDate
  )
GROUP BY dlm.dealer_name, dl.loc_name, mdl.dealer_id
-- ORDER BY WonLeadsPercentage desc
ORDER BY 
CASE WHEN sortField = 'Conversion Ratio' AND sortOrder = 'asc' 
THEN IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag = 'CRM Renewal' 
THEN larc.lead_id END) / NULLIF(COUNT(cl.lead_id), 0)) * 100,2),0) END ASC,
CASE WHEN sortField = 'Conversion Ratio' AND sortOrder = 'desc' THEN IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status 
= 'Won' AND larc.converted_flag = 'CRM Renewal' THEN larc.lead_id END) / NULLIF(COUNT(cl.lead_id), 0)) * 100,2),0) END DESC, 
CASE WHEN sortField = 'Retention Ratio' AND sortOrder = 'asc' THEN 
IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag IN ('CRM Renewal') THEN larc.lead_id END) * 100.0)
        / NULLIF(COUNT(CASE WHEN tl.assigned_agent IS NOT NULL THEN tl.lead_id END),0),2),0) END ASC,
CASE WHEN sortField = 'Retention Ratio' AND sortOrder = 'desc' THEN 
IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag IN ('CRM Renewal') THEN larc.lead_id END) * 100.0)
        / NULLIF(COUNT(CASE WHEN tl.assigned_agent IS NOT NULL THEN tl.lead_id END),0),2),0) END DESC
LIMIT limitVal OFFSET calculated;

SELECT COUNT(*) AS paginationCount
FROM (
SELECT
    mdl.dealer_id AS DealCode    
FROM mmi_dealer_details mdl -- ON mdl.parent_code = md.parent_code
LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.dealer_code = mdl.dealer_id
LEFT JOIN mmi_mast_dealer_location dl ON dl.loc_code = dlm.location_code
LEFT JOIN temp_leads tl ON tl.dealer_code = mdl.dealer_id
LEFT JOIN temp_contacted cl ON cl.lead_id = tl.lead_id
LEFT JOIN temp_won wl ON wl.lead_id = tl.lead_id
LEFT JOIN temp_retention tr ON tr.lead_id = tl.lead_id
LEFT JOIN mmi_lead_archive_details larc ON larc.dealer_code = mdl.dealer_id
WHERE mdl.dealer_id IS NOT NULL
  AND (v_zone IS NULL OR v_zone = '' OR EXISTS (SELECT 1 FROM tmp_zone z WHERE TRIM(LOWER(z.zone)) = TRIM(LOWER(dlm.zone))))-- z.zone = dlm.zone))
  AND (v_state IS NULL OR v_state = '' OR EXISTS (SELECT 1 FROM tmp_state s WHERE TRIM(LOWER(s.state)) = TRIM(LOWER(dl.state)))) -- s.state = dl.state))
  AND (v_dealerId IS NULL OR v_dealerId = '' OR EXISTS (SELECT 1 FROM tmp_dealer d WHERE TRIM(LOWER(d.parent_code)) = TRIM(LOWER(mdl.parent_code)))) -- d.parent_code = mdl.parent_code))
  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR EXISTS (SELECT 1 FROM tmp_dealer_loc l WHERE TRIM(LOWER(l.loc_code)) = TRIM(LOWER(dl.loc_code)))) -- l.loc_code = dl.loc_code))
  AND (v_segment IS NULL OR v_segment = '' OR EXISTS (SELECT 1 FROM tmp_segment sg WHERE TRIM(LOWER(sg.segment)) = TRIM(LOWER( tl.vehicle_class)))) -- sg.segment = tl.vehicle_class))
  AND (
        ((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
        OR tl.created_date BETWEEN v_startDate AND v_endDate
        OR tl.modified_date BETWEEN v_startDate AND v_endDate
  )
GROUP BY dlm.dealer_name, dl.loc_name, mdl.dealer_id
-- ORDER BY WonLeadsPercentage desc
ORDER BY 
CASE WHEN sortField = 'Conversion Ratio' AND sortOrder = 'asc' 
THEN IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag = 'CRM Renewal' 
THEN larc.lead_id END) / NULLIF(COUNT(cl.lead_id), 0)) * 100,2),0) END ASC,
CASE WHEN sortField = 'Conversion Ratio' AND sortOrder = 'desc' THEN IFNULL(ROUND((COUNT(DISTINCT 
CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag = 'CRM Renewal' THEN larc.lead_id END) / NULLIF(COUNT(cl.lead_id), 0)) * 100,2),0) END DESC, 
CASE WHEN sortField = 'Retention Ratio' AND sortOrder = 'asc' THEN 
IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag IN ('CRM Renewal') THEN larc.lead_id END) * 100.0)
        / NULLIF(COUNT(CASE WHEN tl.assigned_agent IS NOT NULL THEN tl.lead_id END),0),2),0) END ASC,
CASE WHEN sortField = 'Retention Ratio' AND sortOrder = 'desc' THEN 
IFNULL(ROUND((COUNT(DISTINCT CASE WHEN larc.lead_status = 'Won' AND larc.converted_flag IN ('CRM Renewal') THEN larc.lead_id END) * 100.0)
        / NULLIF(COUNT(CASE WHEN tl.assigned_agent IS NOT NULL THEN tl.lead_id END),0),2),0) END DESC
) AS count_query;
-- LIMIT 10;


DROP TEMPORARY TABLE IF EXISTS temp_leads;
DROP TEMPORARY TABLE IF EXISTS temp_contacted;
DROP TEMPORARY TABLE IF EXISTS temp_won;

            SET SP_STATUS = '200';
            SET MESSAGE = 'Filtered admin dashboard data fetched successfully.';
            
        ELSE
            SET SP_STATUS = '400';
            SET MESSAGE = CONCAT('Invalid type: ', type);
        END IF;
    END IF;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_get_agent_performance_dashboard` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_agent_performance_dashboard`(
    IN Json_data JSON,
    OUT SP_STATUS VARCHAR(500),
    OUT MESSAGE VARCHAR(500)
)
BEGIN

	-- TODO: comment the AvgHandlingTime in Ctes
    DECLARE v_dealerId VARCHAR(550);
    DECLARE v_userId VARCHAR(550);
    DECLARE v_startDate VARCHAR(550);
    DECLARE v_endDate VARCHAR(550);
    DECLARE v_type VARCHAR(550);
    DECLARE v_role_type VARCHAR(100);
    DECLARE v_check_type VARCHAR(100); 
    DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 0;
    DECLARE calculated INT DEFAULT 0;

    DECLARE v_renewal_category VARCHAR(1000);
    DECLARE v_zone VARCHAR(100);
    DECLARE v_state VARCHAR(550);
    DECLARE v_dealerLocCode VARCHAR(550);
    DECLARE v_segment VARCHAR(550);  

    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            @sqlstate = RETURNED_SQLSTATE, errno = MYSQL_ERRNO, errmsg = MESSAGE_TEXT; 
        SET SP_STATUS = 407;
        SET MESSAGE = 'Something went wrong.';

        INSERT INTO mmi_mast_procedure_error (error_code, error_message, procedure_name, procedure_type, ERROR_TIMING, created_by, created_date)
        VALUES (errno, CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg), 'mmi_proc_get_agent_performance_dashboard', 'PERFORMANCE_DASHBOARD', CURRENT_TIMESTAMP(),
        'SYSTEM', NOW());
    END;

    SET v_dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
    SET v_userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
    
    -- Original
	SET v_startDate = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.startDate'));
	SET v_endDate = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.endDate'));
	-- New (check both)
	SET v_startDate = COALESCE(
		NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.startDate')), ''),
		NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.fromDate')), '')
	);
	SET v_endDate = COALESCE(
		NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.endDate')), ''),
		NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.toDate')), '')
	);
    
    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.type'));
    SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleType'));
    SET v_check_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.checkType'));

    SET v_renewal_category = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalCategory')), '');
    SET v_zone = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.zone')), '');
    SET v_state = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.state')), '');
    SET v_dealerLocCode = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerLocCode')), '');
    SET v_segment = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.segment')), '');

    SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.limit')) AS UNSIGNED), 10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.offset')) AS UNSIGNED), 1);
    IF offsetVal < 1 THEN SET offsetVal = 1; END IF;
    SET calculated = (offsetVal - 1) * limitVal;
    

	SELECT DISTINCT segment
	FROM mmi_mast_segment
	WHERE status = 1 AND segment IS NOT NULL AND segment != '';
	
	SELECT DISTINCT id, renewal_year
	FROM mmi_mast_renewal_category
	WHERE renewal_year IS NOT NULL AND renewal_year != ''
	ORDER BY id ASC;
	
	SELECT DISTINCT zone AS Zone
	FROM mmi_dealer_location_mapping dlm
	INNER JOIN mmi_dealer_details dl ON dlm.dealer_code = dl.dealer_id
	WHERE zone IS NOT NULL AND zone != '';
	
	SELECT DISTINCT state AS State
	FROM mmi_mast_dealer_location mdl
	INNER JOIN mmi_dealer_location_mapping dlm ON dlm.location_code = mdl.loc_code
	INNER JOIN mmi_dealer_details dl ON dlm.dealer_code = dl.dealer_id
	WHERE state IS NOT NULL AND state != '';
	
	SELECT DISTINCT dealer_name, mapping_dealer_code AS dealer_id FROM mmi_dealer_location_mapping;


    IF v_userId IS NULL OR v_userId = '' THEN
        SET SP_STATUS = '400';
        SET MESSAGE = 'UserId Missing';
        
        
    ELSE


	IF v_role_type = 'mibl' THEN
        
		IF v_type = 'performanceFilter' THEN
 
 
	IF v_check_type != 'fetchDealerAgent' THEN   --   -- dealer only with filter
    
	WITH
	dealer_agents AS (
		SELECT DISTINCT t.assigned_agent AS agentId, t.dealer_code
		FROM (
			SELECT assigned_agent, dealer_code FROM mmi_lead_details WHERE assigned_agent IS NOT NULL
			UNION
			SELECT assigned_agent, dealer_code FROM mmi_lead_archive_details WHERE assigned_agent IS NOT NULL
		) t
		INNER JOIN mmi_mast_user_registration_detail u ON u.id = t.assigned_agent
		WHERE (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(t.dealer_code), v_dealerId))
		  AND (v_zone IS NULL OR v_zone='' OR 1=1)
		  AND (v_state IS NULL OR v_state='' OR 1=1)
		  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR 1=1)
		  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND 1=1 ) )
	),

	leads_assigned_all AS (
		SELECT
			t.assigned_agent AS agentId,
			t.dealer_code,
			COUNT(DISTINCT t.lead_id) AS leadsAssigned
		FROM (
			SELECT assigned_agent, dealer_code, lead_id, created_date, modified_date, vehicle_class, renewal_category
			FROM mmi_lead_details WHERE assigned_agent IS NOT NULL
			UNION ALL
			SELECT assigned_agent, dealer_code, lead_id, created_date, modified_date, vehicle_class, renewal_category
			FROM mmi_lead_archive_details WHERE assigned_agent IS NOT NULL
		) t
		LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = t.dealer_code
		LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
		WHERE (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(t.dealer_code), v_dealerId))
		  AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
		  AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
		  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (t.created_date BETWEEN v_startDate AND v_endDate
						 OR t.modified_date BETWEEN v_startDate AND v_endDate) ) )
		  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(t.vehicle_class), v_segment))
		  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(t.renewal_category), v_renewal_category))
		  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
		GROUP BY t.assigned_agent, t.dealer_code
	),

	leads_contacted_all AS (
		SELECT
			leads.assigned_agent AS agentId,
			leads.dealer_code,
			COUNT(DISTINCT cdh.lead_id) AS leadsContacted
		FROM (
			SELECT assigned_agent, dealer_code, lead_id, created_date, modified_date, vehicle_class, renewal_category
			FROM mmi_lead_details WHERE assigned_agent IS NOT NULL
			UNION ALL
			SELECT assigned_agent, dealer_code, lead_id, created_date, modified_date, vehicle_class, renewal_category
			FROM mmi_lead_archive_details WHERE assigned_agent IS NOT NULL
		) leads
		JOIN mmi_call_disposition_history cdh ON cdh.lead_id = leads.lead_id
		LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = leads.dealer_code
		LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
		WHERE (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(leads.dealer_code), v_dealerId))
		  AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
		  AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
		  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (leads.created_date BETWEEN v_startDate AND v_endDate
						 OR leads.modified_date BETWEEN v_startDate AND v_endDate) ) )
		  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(leads.vehicle_class), v_segment))
		  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(leads.renewal_category), v_renewal_category))
		  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
		GROUP BY leads.assigned_agent, leads.dealer_code
	),

	policies_converted_all AS (
		SELECT
			lad.assigned_agent AS agentId,
			lad.dealer_code,
			COUNT(DISTINCT lad.policy_no) AS policiesConverted
		FROM mmi_lead_archive_details lad
		LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
		LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
		WHERE lad.assigned_agent IS NOT NULL
		  AND lad.lead_status = 'Won'
		  AND lad.converted_flag = 'CRM Renewal'
		  AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(lad.dealer_code), v_dealerId))
		  AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
		  AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
		  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (lad.created_date BETWEEN v_startDate AND v_endDate
						 OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
		  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
		  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
		  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
		GROUP BY lad.assigned_agent, lad.dealer_code
	),

	quote_shared_all AS (
		SELECT
			cdh.agent_code AS agentId,
			ld.dealer_code,
			COUNT(DISTINCT cdh.lead_id) AS QuoteShared
		FROM mmi_call_disposition_history cdh
		LEFT JOIN mmi_agent_disposition_field_response adf ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
		JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
		LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
		LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
		WHERE adf.field_value = 'Shared Quotes'
		  AND ld.assigned_agent IS NOT NULL
		  AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
		  AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
		  AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
		  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (ld.created_date BETWEEN v_startDate AND v_endDate
						 OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
		  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
		  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
		  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
		GROUP BY cdh.agent_code, ld.dealer_code
	),

	/*followup_data_all AS (
		SELECT
			cdh.agent_code AS agentId,
			ld.dealer_code,
			COUNT(CASE WHEN cdh.next_call_datetime IS NOT NULL THEN 1 END) AS TotalFollowUpsScheduled,
			COUNT(CASE WHEN cdh.next_call_datetime IS NOT NULL
						AND cdh.call_date <= STR_TO_DATE(cdh.next_call_datetime, '%Y-%m-%d %H:%i:%s')
				   THEN 1 END) AS FollowUpsDoneOnTime
		FROM mmi_call_disposition_history cdh
		JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
		LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
		LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
		WHERE ld.assigned_agent IS NOT NULL
		  AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
		  AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
		  AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
		  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (ld.created_date BETWEEN v_startDate AND v_endDate
						 OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
		  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
		  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
		  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
		GROUP BY cdh.agent_code, ld.dealer_code
	),*/
    followup_data_all AS (
				WITH latest_calls AS (
					SELECT 
						cdh.*,
						ROW_NUMBER() OVER (
							PARTITION BY cdh.lead_id 
							ORDER BY cdh.created_date DESC
						) AS rn
					FROM mmi_call_disposition_history cdh
				)
				SELECT 
					lc.agent_code AS agentId,
					ld.dealer_code,
					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL THEN 1 
					END) AS TotalFollowUpsScheduled,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL
						AND lc.call_date <= STR_TO_DATE(lc.next_call_datetime,'%Y-%m-%d %H:%i:%s') 
						THEN 1 
					END) AS FollowUpsDoneOnTime

				FROM latest_calls lc
				-- JOIN agent_list al 
					-- ON al.agentId = lc.agent_code
				JOIN mmi_lead_details ld 
					ON ld.lead_id = lc.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = ld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE lc.rn = 1 AND ld.assigned_agent IS NOT NULL
		  AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
		  AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
		  AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
		  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (ld.created_date BETWEEN v_startDate AND v_endDate
						 OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
		  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
		  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
		  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
		GROUP BY lc.agent_code, ld.dealer_code
			),

	shortest_call_conversion_all AS (
		SELECT
			cdh.agent_code AS agentId,
			cdh.dealer_code,
			COUNT(DISTINCT CASE WHEN cdh.call_rank <= 2 AND lad.lead_status = 'Won' THEN cdh.lead_id END) AS ConversionsWithinTwoCalls
		FROM (
			SELECT
				cdh2.lead_id,
				cdh2.agent_code,
				cdh2.call_date,
				ld2.dealer_code,
				ROW_NUMBER() OVER (PARTITION BY cdh2.lead_id ORDER BY cdh2.call_date) AS call_rank
			FROM mmi_call_disposition_history cdh2
			JOIN mmi_lead_archive_details ld2 ON ld2.lead_id = cdh2.lead_id
			WHERE ld2.assigned_agent IS NOT NULL
		) cdh
		LEFT JOIN mmi_lead_archive_details lad ON lad.lead_id = cdh.lead_id
		LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = cdh.dealer_code
		LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
		WHERE cdh.agent_code IN (SELECT agentId FROM dealer_agents)
		  AND cdh.dealer_code IN (SELECT dealer_code FROM dealer_agents)
		  AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(cdh.dealer_code), v_dealerId))
		  AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
		  AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
		  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (lad.created_date BETWEEN v_startDate AND v_endDate
						 OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
		  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
		  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
		  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
		GROUP BY cdh.agent_code, cdh.dealer_code
	),

	net_od_premium_all AS (
		SELECT
			ld.assigned_agent AS agentId,
			ld.dealer_code,
			SUM(CAST(IFNULL(ld.net_od_premium_amount, 0) AS DECIMAL(12,2)) +
				CAST(IFNULL(ld.addon_premium_amount, 0) AS DECIMAL(12,2))) AS NetODPremium
		FROM mmi_lead_details ld
		LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
		LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
		WHERE ld.assigned_agent IS NOT NULL
		  AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
		  AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
		  AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
		  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (ld.created_date BETWEEN v_startDate AND v_endDate
						 OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
		  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
		  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
		  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
		GROUP BY ld.assigned_agent, ld.dealer_code
	),

	premium_stats_all AS (
		SELECT
			lad.assigned_agent AS agentId,
			lad.dealer_code,
			SUM(mmd.net_premium) AS NetPremiumCollected
		FROM mmi_lead_archive_details lad
		JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
		LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
		LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
		WHERE lad.assigned_agent IS NOT NULL
		  AND lad.lead_status = 'Won'
		  AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(lad.dealer_code), v_dealerId))
		  AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
		  AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
		  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (lad.created_date BETWEEN v_startDate AND v_endDate
						 OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
		  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
		  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
		  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
		GROUP BY lad.assigned_agent, lad.dealer_code
	),

	addon_sales_all AS (
		SELECT
			ld.assigned_agent AS agentId,
			ld.dealer_code,
			COUNT(pad.id) AS AddonSales
		FROM mmi_poladdon_data pad
		JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
		LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
		LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
		WHERE ld.assigned_agent IS NOT NULL
		  AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
		  AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
		  AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
		  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (ld.created_date BETWEEN v_startDate AND v_endDate
						 OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
		  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
		  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
		  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
		GROUP BY ld.assigned_agent, ld.dealer_code
	),

	pre_due_renewals_all AS (
		SELECT
			lad.assigned_agent AS agentId,
			lad.dealer_code,
			COUNT(*) AS PreDueRenewals
		FROM mmi_lead_archive_details lad
		JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
		LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
		LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
		WHERE lad.lead_status = 'Won'
		  AND lad.converted_flag = 'CRM Renewal'
		  AND DATEDIFF(lad.created_date, mmd.policy_expiry_date) > 10
		  AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(lad.dealer_code), v_dealerId))
		  AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
		  AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
		  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (lad.created_date BETWEEN v_startDate AND v_endDate
						 OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
		  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
		  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
		  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
		GROUP BY lad.assigned_agent, lad.dealer_code
	),

	trigger_flag_all AS (
		SELECT agent_code AS agentId, 5 AS TriggerFlag
		FROM mmi_call_disposition_history
		WHERE agent_code IN (SELECT agentId FROM dealer_agents)
		GROUP BY agent_code
	),
    
    breach_stats AS (
				SELECT 
					mld.assigned_agent,
                    mld.dealer_code,
					COUNT(DISTINCT lb.lead_id) AS breachedLeads
				FROM mmi_lead_breached lb
				JOIN mmi_lead_details mld 
					ON mld.lead_id = lb.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = mld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE 
					(v_dealerId IS NULL OR v_dealerId='' OR FIND_IN_SET(TRIM(mld.dealer_code),v_dealerId))

					AND (((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
					OR
					(v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
					 AND (mld.created_date BETWEEN v_startDate AND v_endDate
						  OR mld.modified_date BETWEEN v_startDate AND v_endDate)))

					AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
					AND (v_renewal_category IS NULL OR v_renewal_category='' 
						 OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
					AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone),v_zone))
					AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state),v_state))
					AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' 
						 OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))  	
				GROUP BY mld.assigned_agent,mld.dealer_code
			),

	agent_metrics AS (
		SELECT
			da.agentId,
			da.dealer_code,
			COALESCE(la.leadsAssigned, 0) AS LeadsAssigned,
			COALESCE(lc.leadsContacted, 0) AS LeadsContacted,
			COALESCE(pc.policiesConverted, 0) AS PoliciesConverted,
			COALESCE(qs.QuoteShared, 0) AS QuoteShared,
			COALESCE(fd.FollowUpsDoneOnTime, 0) AS FollowUpsDoneOnTime,
			COALESCE(fd.TotalFollowUpsScheduled, 0) AS TotalFollowUpsScheduled,
			COALESCE(scc.ConversionsWithinTwoCalls, 0) AS ConversionsWithinTwoCalls,
			COALESCE(ps.NetPremiumCollected, 0) AS NetPremiumCollected,
			COALESCE(nop.NetODPremium, 0) AS NetODPremium,
			COALESCE(ads.AddonSales, 0) AS AddonSales,
			COALESCE(pdr.PreDueRenewals, 0) AS PreDueRenewals,
            COALESCE(bs.breachedLeads, 0) AS breachedLeads,
			COALESCE(tf.TriggerFlag, 0) AS TriggerFlag
		FROM dealer_agents da
		LEFT JOIN leads_assigned_all la ON la.agentId = da.agentId AND la.dealer_code = da.dealer_code
		LEFT JOIN leads_contacted_all lc ON lc.agentId = da.agentId AND lc.dealer_code = da.dealer_code
		LEFT JOIN policies_converted_all pc ON pc.agentId = da.agentId AND pc.dealer_code = da.dealer_code
		LEFT JOIN quote_shared_all qs ON qs.agentId = da.agentId AND qs.dealer_code = da.dealer_code
		LEFT JOIN followup_data_all fd ON fd.agentId = da.agentId AND fd.dealer_code = da.dealer_code
		LEFT JOIN shortest_call_conversion_all scc ON scc.agentId = da.agentId AND scc.dealer_code = da.dealer_code
		LEFT JOIN premium_stats_all ps ON ps.agentId = da.agentId AND ps.dealer_code = da.dealer_code
		LEFT JOIN net_od_premium_all nop ON nop.agentId = da.agentId AND nop.dealer_code = da.dealer_code
		LEFT JOIN addon_sales_all ads ON ads.agentId = da.agentId AND ads.dealer_code = da.dealer_code
		LEFT JOIN pre_due_renewals_all pdr ON pdr.agentId = da.agentId AND pdr.dealer_code = da.dealer_code
		LEFT JOIN trigger_flag_all tf ON tf.agentId = da.agentId
        LEFT JOIN breach_stats bs ON bs.assigned_agent = da.agentId AND bs.dealer_code = da.dealer_code
        
	),

	dealer_max_leads AS (
		SELECT am.dealer_code, MAX(am.LeadsAssigned) AS max_leads
		FROM agent_metrics am
		GROUP BY am.dealer_code
	),

	agent_scores AS (
		SELECT
			am.dealer_code,
			am.agentId,
			am.LeadsAssigned,
			am.LeadsContacted,
			am.PoliciesConverted,
			am.QuoteShared,
			am.ConversionsWithinTwoCalls,
			am.TotalFollowUpsScheduled,
			am.FollowUpsDoneOnTime,
			am.NetPremiumCollected,
			am.NetODPremium,
			am.AddonSales,
			am.PreDueRenewals,
            am.breachedLeads,
			-- dml.max_leads,
			-- AVG(am.LeadsAssigned) AS max_leads,
            am.TriggerFlag,
			-- ROUND(IFNULL(am.LeadsAssigned / NULLIF(dml.max_leads, 0), 0) * 10, 2) AS comp1,
			ROUND(IFNULL(am.LeadsAssigned / NULLIF(AVG(am.LeadsAssigned) OVER (),0), 0) * 100 / 10) AS comp1,
            ROUND(IFNULL(am.LeadsContacted / NULLIF(am.LeadsAssigned, 0), 0) * 10, 2) AS comp2,
			ROUND(IFNULL(am.FollowUpsDoneOnTime / NULLIF(am.TotalFollowUpsScheduled, 0), 0) * 10, 2) AS comp3,
			ROUND(IFNULL(am.QuoteShared / NULLIF(am.LeadsContacted, 0), 0) * 10, 2) AS comp4,
			ROUND(IFNULL(am.PoliciesConverted / NULLIF(am.LeadsContacted, 0), 0) * 25, 2) AS comp5,
			ROUND(IFNULL(am.PoliciesConverted / NULLIF(am.LeadsAssigned, 0), 0) * 15, 2) AS comp6,
			ROUND(IFNULL(am.ConversionsWithinTwoCalls / NULLIF(am.PoliciesConverted, 0), 0) * 5, 2) AS comp7,
			ROUND(IFNULL(GREATEST(am.NetPremiumCollected - 50000, 0) / 1000 * 10, 0), 2) AS netPremiumScore,
			ROUND(IFNULL(am.NetODPremium / 1000, 0), 2) AS netODPremiumScore,
			ROUND(IFNULL(am.AddonSales * 5, 0), 2) AS addonSalesScore,
			ROUND(IFNULL(am.PreDueRenewals * 10, 0), 2) AS preDueRenewalScore,
			/*ROUND(
				  IFNULL(am.LeadsAssigned / NULLIF(dml.max_leads, 0), 0) * 10
				+ IFNULL(am.LeadsContacted / NULLIF(am.LeadsAssigned, 0), 0) * 10
				+ IFNULL(am.FollowUpsDoneOnTime / NULLIF(am.TotalFollowUpsScheduled, 0), 0) * 10
				+ IFNULL(am.QuoteShared / NULLIF(am.LeadsContacted, 0), 0) * 10
				+ IFNULL(am.PoliciesConverted / NULLIF(am.LeadsContacted, 0), 0) * 25
				+ IFNULL(am.PoliciesConverted / NULLIF(am.LeadsAssigned, 0), 0) * 15
				+ IFNULL(am.ConversionsWithinTwoCalls / NULLIF(am.PoliciesConverted, 0), 0) * 5
				+ (CASE WHEN am.TriggerFlag <> 0 THEN 5 ELSE 0 END)
			, 2) AS PerformanceScore,*/
            
            ROUND((IFNULL(am.LeadsAssigned / NULLIF(AVG(am.LeadsAssigned) OVER (),0), 0) * 100 / 10)
                    + (IFNULL(am.LeadsContacted / NULLIF(am.LeadsAssigned,0), 0) * 10)
                    + (IFNULL((am.FollowUpsDoneOnTime / NULLIF(am.TotalFollowUpsScheduled,0)),0) * 10)
                    + (IFNULL(am.QuoteShared / NULLIF(am.LeadsContacted,0), 0) * 10)
                    + (IFNULL(am.PoliciesConverted / NULLIF(am.LeadsContacted,0), 0) * 25)
                    + (IFNULL(am.PoliciesConverted / NULLIF(am.LeadsAssigned,0), 0) * 15)
                    + (IFNULL(am.ConversionsWithinTwoCalls / NULLIF(am.PoliciesConverted,0), 0) * 100 * 5 / 100 )
                    + am.TriggerFlag
                ,2) AS PerformanceScore,
            
			/*ROUND(
				IFNULL(GREATEST(am.NetPremiumCollected - 50000, 0) / 1000 * 10, 0)
				+ IFNULL(am.NetODPremium / 1000, 0)
				+ IFNULL(am.AddonSales * 5, 0)
				+ IFNULL(am.PreDueRenewals * 10, 0)
			, 2) AS DynamicPerformanceScore*/
            0 AS DynamicPerformanceScore
		FROM agent_metrics am
		-- LEFT JOIN dealer_max_leads dml ON dml.dealer_code = am.dealer_code
	),

	dealer_aggregates AS (
		SELECT
			ag.dealer_code,
			SUM(ag.LeadsAssigned) AS LeadsAssigned,
			SUM(ag.LeadsContacted) AS LeadsContacted,
			SUM(ag.PoliciesConverted) AS PoliciesConverted,
			SUM(ag.NetPremiumCollected) AS NetPremiumCollected,
			SUM(ag.QuoteShared) AS QuoteShared,
			SUM(ag.ConversionsWithinTwoCalls) AS ConversionsWithinTwoCalls,
			SUM(ag.TotalFollowUpsScheduled) AS TotalFollowUpsScheduled,
			SUM(ag.FollowUpsDoneOnTime) AS FollowUpsDoneOnTime,
			SUM(ag.NetODPremium) AS NetODPremium,
			SUM(ag.AddonSales) AS AddonSales,
			SUM(ag.PreDueRenewals) AS PreDueRenewals,
			SUM(ag.DynamicPerformanceScore) AS DynamicPerformanceScore,
            SUM(ag.TriggerFlag) AS TriggerFlag,
            -- GREATEST(0,LEAST(100,100 - ROUND(SUM(ag.breachedLeads) / NULLIF(SUM(ag.LeadsAssigned), 0) * 100,2))) AS FollowUpEfficiencyData
			GREATEST(0,LEAST(100,100 - ROUND(NULLIF(COALESCE(SUM(ag.breachedLeads), 0), 0) / NULLIF(COALESCE(SUM(ag.LeadsAssigned), 0), 0) * 100,2))) AS FollowUpEfficiencyData
        FROM agent_scores ag
		GROUP BY ag.dealer_code
	),

	-- max LeadsAssigned across all dealers
	global_max AS (
		SELECT MAX(LeadsAssigned) AS max_leads
		FROM dealer_aggregates
	),


	dealer_target AS (
		SELECT am.dealer_code, COUNT(DISTINCT am.agentId) * SUM(IFNULL(mtp.target_value,0)) AS TargetPremium
		FROM agent_metrics am
		left join mmi_target_planning mtp on mtp.team_member = am.agentId
		GROUP BY am.dealer_code
	),

	dealer_data AS (
		SELECT
			da.dealer_code AS dealer_id,
			dlm.dealer_name,
			da.LeadsAssigned,
			da.LeadsContacted,
			da.PoliciesConverted,
			da.NetPremiumCollected,
			da.QuoteShared,
			da.ConversionsWithinTwoCalls,
			da.TotalFollowUpsScheduled,
			da.FollowUpsDoneOnTime,
			da.NetODPremium,
			da.AddonSales,
			da.PreDueRenewals,
			da.DynamicPerformanceScore,
			dt.TargetPremium,
            da.TriggerFlag,
            da.FollowUpEfficiencyData,
            
			-- Dealer level PerformanceScore
			/*ROUND(
				  IFNULL(da.LeadsAssigned / NULLIF(gm.max_leads, 0), 0) * 10
				+ IFNULL(da.LeadsContacted / NULLIF(da.LeadsAssigned, 0), 0) * 10
				+ IFNULL(da.FollowUpsDoneOnTime / NULLIF(da.TotalFollowUpsScheduled, 0), 0) * 10
				+ IFNULL(da.QuoteShared / NULLIF(da.LeadsContacted, 0), 0) * 10
				+ IFNULL(da.PoliciesConverted / NULLIF(da.LeadsContacted, 0), 0) * 25
				+ IFNULL(da.PoliciesConverted / NULLIF(da.LeadsAssigned, 0), 0) * 15
				+ IFNULL(da.ConversionsWithinTwoCalls / NULLIF(da.PoliciesConverted, 0), 0) * 5
			, 2) AS PerformanceScore,*/
            ROUND((IFNULL(da.LeadsAssigned / NULLIF(AVG(da.LeadsAssigned) OVER (),0), 0) * 100 / 10)
                    + (IFNULL(da.LeadsContacted / NULLIF(da.LeadsAssigned,0), 0) * 10)
                    + (IFNULL((da.FollowUpsDoneOnTime / NULLIF(da.TotalFollowUpsScheduled,0)),0) * 10)
                    + (IFNULL(da.QuoteShared / NULLIF(da.LeadsContacted,0), 0) * 10)
                    + (IFNULL(da.PoliciesConverted / NULLIF(da.LeadsContacted,0), 0) * 25)
                    + (IFNULL(da.PoliciesConverted / NULLIF(da.LeadsAssigned,0), 0) * 15)
                    + (IFNULL(da.ConversionsWithinTwoCalls / NULLIF(da.PoliciesConverted,0), 0) * 100 * 5 / 100 )
                    + da.TriggerFlag
                ,2) AS PerformanceScore,
            
            
			-- Recompute components for display
			-- ROUND(IFNULL(da.LeadsAssigned / NULLIF(gm.max_leads, 0), 0) * 10, 2) AS comp1,
            ROUND(IFNULL(da.LeadsAssigned / NULLIF(AVG(da.LeadsAssigned) OVER (),0), 0) * 100 / 10) AS comp1,
			ROUND(IFNULL(da.LeadsContacted / NULLIF(da.LeadsAssigned, 0), 0) * 10, 2) AS comp2,
			ROUND(IFNULL(da.FollowUpsDoneOnTime / NULLIF(da.TotalFollowUpsScheduled, 0), 0) * 10, 2) AS comp3,
			ROUND(IFNULL(da.QuoteShared / NULLIF(da.LeadsContacted, 0), 0) * 10, 2) AS comp4,
			ROUND(IFNULL(da.PoliciesConverted / NULLIF(da.LeadsContacted, 0), 0) * 25, 2) AS comp5,
			ROUND(IFNULL(da.PoliciesConverted / NULLIF(da.LeadsAssigned, 0), 0) * 15, 2) AS comp6,
			ROUND(IFNULL(da.ConversionsWithinTwoCalls / NULLIF(da.PoliciesConverted, 0), 0) * 5, 2) AS comp7,
			ROUND(IFNULL(da.FollowUpsDoneOnTime / NULLIF(da.TotalFollowUpsScheduled, 0), 0) * 100, 2) AS FollowUpEfficiency,
			ROUND(IFNULL(da.PoliciesConverted / NULLIF(da.LeadsContacted, 0), 0) * 100, 2) AS ConversionRate,
			ROUND(IFNULL(da.PoliciesConverted / NULLIF(da.LeadsAssigned, 0), 0) * 100, 2) AS RetentionRate
		FROM dealer_aggregates da
		CROSS JOIN global_max gm
		LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.dealer_code = da.dealer_code
		LEFT JOIN dealer_target dt ON dt.dealer_code = da.dealer_code
	),

	dealer_nonzero AS (
		SELECT *
		FROM dealer_data
		WHERE LeadsAssigned > 0
		   OR LeadsContacted > 0
		   OR PoliciesConverted > 0
		   OR NetPremiumCollected > 0
	),

	dealer_with_avg AS (
		SELECT
			dn.*,
			AVG(dn.PerformanceScore) OVER () AS avg_performance_score,
			AVG(dn.DynamicPerformanceScore) OVER () AS avg_dynamic_score
		FROM dealer_nonzero dn
	)

		SELECT
			dw.dealer_id AS dealerId,
			dw.dealer_name AS dealerName,
			NULL AS agentId,
			NULL AS agentName,
			dw.LeadsAssigned AS leadsAssigned,
			dw.LeadsContacted AS leadsContacted,
			dw.PoliciesConverted AS policiesConverted,
			dw.NetPremiumCollected AS netPremiumCollected,
			-- dw.FollowUpEfficiency AS followUpEfficiency,
            dw.FollowUpEfficiencyData AS followUpEfficiency,
			CONCAT(ROUND(dw.ConversionRate, 2)) AS conversionRate,
			CONCAT(ROUND(dw.RetentionRate, 2)) AS retentionRate,
			ROUND(dw.PerformanceScore, 2) AS performanceScore,
			ROUND(dw.DynamicPerformanceScore, 2) AS dynamicPerformanceScore,
			ROUND(dw.PerformanceScore + dw.DynamicPerformanceScore, 2) AS overallScore,
			ROUND(dw.avg_performance_score, 2) AS avg_performance_score,
			ROUND(dw.avg_dynamic_score, 2) AS avg_dynamic_score,
			RANK() OVER (ORDER BY (dw.PerformanceScore + dw.DynamicPerformanceScore) DESC) AS `rank`,
			ROUND(dw.comp1, 2) AS comp1,
			ROUND(dw.comp2, 2) AS comp2,
			ROUND(dw.comp3, 2) AS comp3,
			ROUND(dw.comp4, 2) AS comp4,
			ROUND(dw.comp5, 2) AS comp5,
			ROUND(dw.comp6, 2) AS comp6,
			ROUND(dw.comp7, 2) AS comp7,
			ROUND(dw.TargetPremium, 2) AS targetPremium
		FROM dealer_with_avg dw
		ORDER BY `rank`
		LIMIT limitVal OFFSET calculated;

		SELECT 
			COUNT(DISTINCT md.dealer_code) AS dealerCount
		FROM
			mmi_dealer_location_mapping md
		WHERE
			md.dealer_code IN (SELECT DISTINCT
				ld.dealer_code
        FROM
            mmi_lead_details ld
                LEFT JOIN
            mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
                LEFT JOIN
            mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                INNER JOIN
            mmi_mast_user_registration_detail mud ON mud.id = ld.assigned_agent
        WHERE
            ld.assigned_agent IS NOT NULL
			AND (v_segment IS NULL OR v_segment = ''
			OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
			AND (v_renewal_category IS NULL
			OR v_renewal_category = ''
			OR FIND_IN_SET(TRIM(ld.renewal_category),
				v_renewal_category))
			AND (v_dealerLocCode IS NULL
			OR v_dealerLocCode = ''
			OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			AND ((v_startDate IS NULL OR v_startDate = ''
			OR v_endDate IS NULL
			OR v_endDate = '')
			OR (v_startDate IS NOT NULL
			AND v_startDate != ''
			AND v_endDate IS NOT NULL
			AND v_endDate != ''
			AND (ld.created_date BETWEEN v_startDate AND v_endDate
			OR ld.modified_date BETWEEN v_startDate AND v_endDate)))
			AND (v_dealerId IS NULL OR v_dealerId = ''
			OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
			AND (v_zone IS NULL OR v_zone = ''
			OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
			AND (v_state IS NULL OR v_state = ''
			OR FIND_IN_SET(TRIM(dloc.state), v_state)));

	SET SP_STATUS = '200';
	SET MESSAGE = 'PerformanceBoard filter details fetched'; -- end v_check_type for performanceFilter 

    
    ELSE   -- v_check_type = 'fetchDealerAgent' (agent level with filters)

        WITH
        lead_assigned_detail AS (
            SELECT
                mld.assigned_agent AS agentId,
                COUNT(DISTINCT mld.lead_id) AS leadsAssigned
            FROM mmi_lead_details mld
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE mld.assigned_agent IS NOT NULL
              AND (v_dealerId IS NULL OR v_dealerId = '' OR mld.dealer_code = v_dealerId)
              AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                    OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
                        AND (mld.created_date BETWEEN v_startDate AND v_endDate
                             OR mld.modified_date BETWEEN v_startDate AND v_endDate) ) )
              AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
              AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
            GROUP BY mld.assigned_agent
        ),
        lead_assigned_archive AS (
            SELECT
                mld.assigned_agent AS agentId,
                COUNT(DISTINCT mld.lead_id) AS leadsAssigned
            FROM mmi_lead_archive_details mld
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE mld.assigned_agent IS NOT NULL
              AND (v_dealerId IS NULL OR v_dealerId = '' OR mld.dealer_code = v_dealerId)
              AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                    OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
                        AND (mld.created_date BETWEEN v_startDate AND v_endDate
                             OR mld.modified_date BETWEEN v_startDate AND v_endDate) ) )
              AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
              AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
            GROUP BY mld.assigned_agent
        ),
        lead_contacted_detail AS (
            SELECT
                mld.assigned_agent AS agentId,
                COUNT(DISTINCT cdh.lead_id) AS leadsContacted
            FROM mmi_call_disposition_history cdh
            JOIN mmi_lead_details mld ON mld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE (v_dealerId IS NULL OR v_dealerId = '' OR mld.dealer_code = v_dealerId)
              AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                    OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
                        AND (mld.created_date BETWEEN v_startDate AND v_endDate
                             OR mld.modified_date BETWEEN v_startDate AND v_endDate) ) )
              AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))
              AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
            GROUP BY mld.assigned_agent
        ),
        lead_contacted_archive AS (
            SELECT
                mld.assigned_agent AS agentId,
                COUNT(DISTINCT cdh.lead_id) AS leadsContacted
            FROM mmi_call_disposition_history cdh
            JOIN mmi_lead_archive_details mld ON mld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE (v_dealerId IS NULL OR v_dealerId = '' OR mld.dealer_code = v_dealerId)
              AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                    OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
                        AND (mld.created_date BETWEEN v_startDate AND v_endDate
                             OR mld.modified_date BETWEEN v_startDate AND v_endDate) ) )
              AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))
              AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
            GROUP BY mld.assigned_agent
        ),
        agent_lead_combined AS (
            SELECT
                COALESCE(ld.agentId, la.agentId) AS agentId,
                COALESCE(ld.leadsAssigned, 0) + COALESCE(la.leadsAssigned, 0) AS leadsAssigned_total,
                COALESCE(cd.leadsContacted, 0) + COALESCE(ca.leadsContacted, 0) AS leadsContacted_total
            FROM lead_assigned_detail ld
            LEFT JOIN lead_assigned_archive la ON ld.agentId = la.agentId
            LEFT JOIN lead_contacted_detail cd ON COALESCE(ld.agentId, la.agentId) = cd.agentId
            LEFT JOIN lead_contacted_archive ca ON COALESCE(ld.agentId, la.agentId, cd.agentId) = ca.agentId
        ),
        agent_list AS (
            SELECT DISTINCT agentId FROM agent_lead_combined
        ),
        agent_details AS (
            SELECT
                al.agentId,
                CONCAT(mud.first_name, ' ', mud.last_name) AS agentName
            FROM agent_list al
            JOIN mmi_mast_user_registration_detail mud ON mud.id = al.agentId
        ),
        leads_assigned AS (
            SELECT agentId, leadsAssigned_total AS LeadsAssigned FROM agent_lead_combined
        ),
        leads_contacted AS (
            SELECT agentId, leadsContacted_total AS LeadsContacted FROM agent_lead_combined
        ),
        /*followup_data AS (
            SELECT
                cdh.agent_code AS agentId,
                COUNT(CASE WHEN cdh.next_call_datetime IS NOT NULL THEN 1 END) AS TotalFollowUpsScheduled,
                COUNT(CASE WHEN cdh.next_call_datetime IS NOT NULL
                            AND cdh.call_date <= STR_TO_DATE(cdh.next_call_datetime,'%Y-%m-%d %H:%i:%s')
                       THEN 1 END) AS FollowUpsDoneOnTime
            FROM mmi_call_disposition_history cdh
            JOIN agent_list al ON al.agentId = cdh.agent_code
            JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE (v_dealerId IS NULL OR v_dealerId = '' OR ld.dealer_code = v_dealerId)
              AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                    OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
                        AND (ld.created_date BETWEEN v_startDate AND v_endDate
                             OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
              AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
              AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
            GROUP BY cdh.agent_code
        ),*/
        followup_data AS (
				WITH latest_calls AS (
					SELECT 
						cdh.*,
						ROW_NUMBER() OVER (
							PARTITION BY cdh.lead_id 
							ORDER BY cdh.created_date DESC
						) AS rn
					FROM mmi_call_disposition_history cdh
				)
				SELECT 
					lc.agent_code AS agentId,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL THEN 1 
					END) AS TotalFollowUpsScheduled,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL
						AND lc.call_date <= STR_TO_DATE(lc.next_call_datetime,'%Y-%m-%d %H:%i:%s') 
						THEN 1 
					END) AS FollowUpsDoneOnTime

				FROM latest_calls lc
				JOIN agent_list al 
					ON al.agentId = lc.agent_code
				JOIN mmi_lead_details ld 
					ON ld.lead_id = lc.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = ld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				-- WHERE lc.rn = 1 AND ld.dealer_code = v_dealerId
                WHERE lc.rn = 1 AND  (v_dealerId IS NULL OR v_dealerId = '' OR ld.dealer_code = v_dealerId)
              AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                    OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
                        AND (ld.created_date BETWEEN v_startDate AND v_endDate
                             OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
              AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
              AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
				GROUP BY lc.agent_code
			),
        quote_shared AS (
            SELECT
                cdh.agent_code AS agentId,
                COUNT(DISTINCT cdh.lead_id) AS QuoteShared
            FROM mmi_call_disposition_history cdh
            LEFT JOIN mmi_agent_disposition_field_response adf ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
            JOIN agent_list al ON al.agentId = cdh.agent_code
            JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE adf.field_value = 'Shared Quotes'
              AND (v_dealerId IS NULL OR v_dealerId = '' OR ld.dealer_code = v_dealerId)
              AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                    OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
                        AND (ld.created_date BETWEEN v_startDate AND v_endDate
                             OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
              AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
              AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
            GROUP BY cdh.agent_code
        ),
        converted_policies AS (
            SELECT
                lad.assigned_agent AS agentId,
                COUNT(DISTINCT lad.policy_no) AS policiesConverted
            FROM mmi_lead_archive_details lad
            JOIN agent_list al ON al.agentId = lad.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE lad.lead_status = 'Won' AND lad.converted_flag = 'CRM Renewal'
              AND (v_dealerId IS NULL OR v_dealerId = '' OR lad.dealer_code = v_dealerId)
              AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                    OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
                        AND (lad.created_date BETWEEN v_startDate AND v_endDate
                             OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
              AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
              AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
            GROUP BY lad.assigned_agent
        ),
        shortest_call_conversion AS (
            SELECT
                cdh.agent_code AS agentId,
                COUNT(DISTINCT CASE WHEN cdh.call_rank <= 2 AND lad.lead_status = 'Won' THEN cdh.lead_id END) AS ConversionsWithinTwoCalls
            FROM (
                SELECT
                    cdh2.lead_id,
                    cdh2.agent_code,
                    cdh2.call_date,
                    ROW_NUMBER() OVER (PARTITION BY cdh2.lead_id ORDER BY cdh2.call_date) AS call_rank
                FROM mmi_call_disposition_history cdh2
            ) cdh
            LEFT JOIN mmi_lead_archive_details lad ON lad.lead_id = cdh.lead_id
            JOIN agent_list al ON al.agentId = cdh.agent_code
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE cdh.agent_code IN (SELECT agentId FROM agent_list)
              AND (v_dealerId IS NULL OR v_dealerId = '' OR lad.dealer_code = v_dealerId)
              AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                    OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
                        AND (lad.created_date BETWEEN v_startDate AND v_endDate
                             OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
              AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
              AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
            GROUP BY cdh.agent_code
        ),
        trigger_flag AS (
            SELECT agent_code AS agentId, 5 AS TriggerFlag
            FROM mmi_call_disposition_history
            WHERE agent_code IN (SELECT agentId FROM agent_list)
            GROUP BY agent_code
        ),
        target_premium AS (
            SELECT al.agentId, SUM(IFNULL(mtp.target_value,0)) AS TargetPremium 
			FROM agent_list al
			left join mmi_target_planning mtp on mtp.team_member = al.agentId
			GROUP BY agentId
        ),
        net_od_premium AS (
            SELECT
                ld.assigned_agent AS agentId,
                SUM(CAST(IFNULL(ld.net_od_premium_amount,0) AS DECIMAL(12,2)) +
                    CAST(IFNULL(ld.addon_premium_amount,0) AS DECIMAL(12,2))) AS NetODPremium
            FROM mmi_lead_details ld
            JOIN agent_list al ON al.agentId = ld.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE (v_dealerId IS NULL OR v_dealerId = '' OR ld.dealer_code = v_dealerId)
              AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                    OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
                        AND (ld.created_date BETWEEN v_startDate AND v_endDate
                             OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
              AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
              AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
            GROUP BY ld.assigned_agent
        ),
        premium_stats AS (
            SELECT
                lad.assigned_agent AS agentId,
                SUM(mmd.net_premium) AS NetPremiumCollected
            FROM mmi_lead_archive_details lad
            JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
            JOIN agent_list al ON al.agentId = lad.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE lad.lead_status = 'Won'
              AND (v_dealerId IS NULL OR v_dealerId = '' OR lad.dealer_code = v_dealerId)
              AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                    OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
                        AND (lad.created_date BETWEEN v_startDate AND v_endDate
                             OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
              AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
              AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
            GROUP BY lad.assigned_agent
        ),
        addon_sales AS (
            SELECT
                ld.assigned_agent AS agentId,
                COUNT(pad.id) AS AddonSales
            FROM mmi_poladdon_data pad
            JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
            JOIN agent_list al ON al.agentId = ld.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE (v_dealerId IS NULL OR v_dealerId = '' OR ld.dealer_code = v_dealerId)
              AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                    OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
                        AND (ld.created_date BETWEEN v_startDate AND v_endDate
                             OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
              AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
              AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
            GROUP BY ld.assigned_agent
        ),
         pre_due_renewals AS (
			SELECT 
				lad.assigned_agent AS agentId,
				COUNT(*) AS PreDueRenewals
			FROM mmi_lead_archive_details lad
			JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
			JOIN agent_list al ON al.agentId = lad.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE lad.lead_status = 'Won' 
			  AND lad.converted_flag = 'CRM Renewal'
			  AND DATEDIFF(lad.created_date, mmd.policy_expiry_date) > 10
			  AND lad.dealer_code = v_dealerId
			   AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
					   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
						   AND (lad.created_date BETWEEN v_startDate AND v_endDate
								OR lad.modified_date BETWEEN v_startDate AND v_endDate)))
				  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
				  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
			GROUP BY lad.assigned_agent
		),
        conversion_data AS (
            SELECT
                lad.assigned_agent AS agentId,
                COUNT(DISTINCT CASE WHEN lad.lead_status = 'Won' AND lad.converted_flag = 'CRM Renewal' THEN lad.lead_id END) AS WonLeads
            FROM mmi_lead_archive_details lad
            JOIN agent_list al ON al.agentId = lad.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE (v_dealerId IS NULL OR v_dealerId = '' OR lad.dealer_code = v_dealerId)
              AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                    OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
                        AND (lad.created_date BETWEEN v_startDate AND v_endDate
                             OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
              AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
              AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state), v_state))
            GROUP BY lad.assigned_agent
        ),
        breach_stats AS (
				SELECT 
					mld.assigned_agent,
					COUNT(DISTINCT lb.lead_id) AS breachedLeads
				FROM mmi_lead_breached lb
				JOIN mmi_lead_details mld 
					ON mld.lead_id = lb.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = mld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE 
					(v_dealerId IS NULL OR v_dealerId='' OR FIND_IN_SET(TRIM(mld.dealer_code),v_dealerId))

					AND (((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
					OR
					(v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
					 AND (mld.created_date BETWEEN v_startDate AND v_endDate
						  OR mld.modified_date BETWEEN v_startDate AND v_endDate)))

					AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
					AND (v_renewal_category IS NULL OR v_renewal_category='' 
						 OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
					AND (v_zone IS NULL OR v_zone='' OR FIND_IN_SET(TRIM(dlm.zone),v_zone))
					AND (v_state IS NULL OR v_state='' OR FIND_IN_SET(TRIM(dloc.state),v_state))
					AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' 
						 OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))  	
				GROUP BY mld.assigned_agent
		),
        final_data AS (
            SELECT
                ad.agentId,
                ad.agentName,
                IFNULL(la.LeadsAssigned,0) AS LeadsAssigned,
                IFNULL(lc.LeadsContacted,0) AS LeadsContacted,
                IFNULL(cp.policiesConverted,0) AS PoliciesConverted,
                IFNULL(ps.NetPremiumCollected,0) AS NetPremiumCollected,
                IFNULL(fd.FollowUpsDoneOnTime,0) AS FollowUpsDoneOnTime,
                IFNULL(fd.TotalFollowUpsScheduled,0) AS TotalFollowUpsScheduled,
                IFNULL(qs.QuoteShared,0) AS QuoteShared,
                IFNULL(tf.TriggerFlag,0) AS TriggerFlag,
                IFNULL(scc.ConversionsWithinTwoCalls,0) AS ConversionsWithinTwoCalls,
                IFNULL(tp.TargetPremium,0) AS TargetPremium,
                IFNULL(nop.NetODPremium,0) AS NetODPremium,
                IFNULL(ads.AddonSales,0) AS AddonSales,
                IFNULL(pdr.PreDueRenewals,0) AS PreDueRenewals,
                IFNULL(ROUND((IFNULL(cd.WonLeads,0) / NULLIF(IFNULL(lc.LeadsContacted,0),0)) * 100,2),0) AS ConversionRate,
                IFNULL(ROUND((IFNULL(cp.policiesConverted,0) / NULLIF(IFNULL(la.LeadsAssigned,0),0)) * 100,2),0) AS RetentionRate,
                IFNULL(bs.breachedLeads,0) AS breachedLeads
            FROM agent_details ad
            LEFT JOIN leads_assigned la ON la.agentId = ad.agentId
            LEFT JOIN leads_contacted lc ON lc.agentId = ad.agentId
            LEFT JOIN converted_policies cp ON cp.agentId = ad.agentId
            LEFT JOIN premium_stats ps ON ps.agentId = ad.agentId
            LEFT JOIN followup_data fd ON fd.agentId = ad.agentId
            LEFT JOIN quote_shared qs ON qs.agentId = ad.agentId
            LEFT JOIN trigger_flag tf ON tf.agentId = ad.agentId
            LEFT JOIN shortest_call_conversion scc ON scc.agentId = ad.agentId
            LEFT JOIN conversion_data cd ON cd.agentId = ad.agentId
            LEFT JOIN target_premium tp ON tp.agentId = ad.agentId
            LEFT JOIN net_od_premium nop ON nop.agentId = ad.agentId
            LEFT JOIN addon_sales ads ON ads.agentId = ad.agentId
            LEFT JOIN pre_due_renewals pdr ON pdr.agentId = ad.agentId
            LEFT JOIN breach_stats bs ON bs.assigned_agent = ad.agentId
        ),
        score_data AS (
	 SELECT
        fd.agentId,
        fd.AgentName,
        fd.LeadsAssigned,
        fd.LeadsContacted,
        fd.PoliciesConverted,
        fd.NetPremiumCollected,
        fd.QuoteShared,
        fd.ConversionsWithinTwoCalls,
        fd.TargetPremium,
        fd.NetODPremium,
        fd.AddonSales,
        fd.PreDueRenewals,
        fd.FollowUpsDoneOnTime,
        fd.TotalFollowUpsScheduled,
        fd.ConversionRate,
        fd.RetentionRate,
        GREATEST(0,LEAST(100,100 - ROUND(NULLIF(fd.breachedLeads, 0) /NULLIF(IFNULL(fd.LeadsAssigned,0), 0) * 100,2))) AS FollowUpEfficiency,
        
       -- ROUND(IFNULL(fd.FollowUpsDoneOnTime / NULLIF(fd.TotalFollowUpsScheduled,0),0) * 100,2) AS FollowUpEfficiency,
        -- Performance components
        ROUND((fd.LeadsAssigned / NULLIF(MAX(fd.LeadsAssigned) OVER (),0)) * 10, 2) AS comp1,
        ROUND(IFNULL(fd.LeadsContacted / NULLIF(fd.LeadsAssigned,0),0) * 10, 2) AS comp2,
        ROUND(IFNULL(fd.FollowUpsDoneOnTime / NULLIF(fd.TotalFollowUpsScheduled,0),0) * 10, 2) AS comp3,
        ROUND(IFNULL(fd.QuoteShared / NULLIF(fd.LeadsContacted,0),0) * 10, 2) AS comp4,
        ROUND(IFNULL(fd.PoliciesConverted / NULLIF(fd.LeadsContacted,0),0) * 25, 2) AS comp5,
        ROUND(IFNULL(fd.PoliciesConverted / NULLIF(fd.LeadsAssigned,0),0) * 15, 2) AS comp6,
        ROUND(IFNULL(fd.ConversionsWithinTwoCalls / NULLIF(fd.PoliciesConverted,0),0) * 5, 2) AS comp7,
        -- Dynamic components
        ROUND(IFNULL(GREATEST(fd.NetPremiumCollected - fd.TargetPremium,0) / 1000 * 10,0), 2) AS netPremiumScore,
        ROUND(IFNULL(fd.NetODPremium / 1000,0), 2) AS netODPremiumScore,
        ROUND(IFNULL(fd.AddonSales * 5,0), 2) AS addonSalesScore,
        ROUND(IFNULL(fd.PreDueRenewals * 10,0), 2) AS preDueRenewalScore,
        -- PerformanceScore and DynamicPerformanceScore as before
        /*ROUND(((fd.LeadsAssigned / NULLIF(MAX(fd.LeadsAssigned) OVER (),0)) * 10)
            + IFNULL((fd.LeadsContacted / NULLIF(fd.LeadsAssigned,0)),0) * 10
            + IFNULL((fd.FollowUpsDoneOnTime / NULLIF(fd.TotalFollowUpsScheduled,0)),0) * 10
            + IFNULL((fd.QuoteShared / NULLIF(fd.LeadsContacted,0)),0) * 10
            + IFNULL((fd.PoliciesConverted / NULLIF(fd.LeadsContacted,0)),0) * 25
            + IFNULL((fd.PoliciesConverted / NULLIF(fd.LeadsAssigned,0)),0) * 15
            + IFNULL((fd.ConversionsWithinTwoCalls / NULLIF(fd.PoliciesConverted,0)),0) * 5
        , 2) AS PerformanceScore,*/
        
        ROUND((IFNULL(fd.LeadsAssigned / NULLIF(AVG(fd.LeadsAssigned) OVER (),0), 0) * 100 / 10)
                    + (IFNULL(fd.LeadsContacted / NULLIF(fd.LeadsAssigned,0), 0) * 10)
                    + (IFNULL((fd.FollowUpsDoneOnTime / NULLIF(fd.TotalFollowUpsScheduled,0)),0) * 10)
                    + (IFNULL(fd.QuoteShared / NULLIF(fd.LeadsContacted,0), 0) * 10)
                    + (IFNULL(fd.PoliciesConverted / NULLIF(fd.LeadsContacted,0), 0) * 25)
                    + (IFNULL(fd.PoliciesConverted / NULLIF(fd.LeadsAssigned,0), 0) * 15)
                    + (IFNULL(fd.ConversionsWithinTwoCalls / NULLIF(fd.PoliciesConverted,0), 0) * 100 * 5 / 100 )
                    + fd.TriggerFlag
                ,2) AS PerformanceScore,
        
        /*ROUND(IFNULL(GREATEST(fd.NetPremiumCollected - fd.TargetPremium,0) / 1000 * 10,0)
            + IFNULL(fd.NetODPremium / 1000,0)
            + IFNULL(fd.AddonSales * 5,0)
            + IFNULL(fd.PreDueRenewals * 10,0)
        , 2) AS DynamicPerformanceScore*/
        0 AS DynamicPerformanceScore
			FROM final_data fd
		)
			
		SELECT
			sd.agentId,
			sd.AgentName AS agentName,
			ROUND(sd.LeadsAssigned,2) AS leadsAssigned,
			ROUND(sd.LeadsContacted,2) AS leadsContacted,
			ROUND(sd.PoliciesConverted,2) AS policiesConverted,
			ROUND(sd.NetPremiumCollected,2) AS netPremiumCollected,
			ROUND(sd.FollowUpEfficiency,2) AS followUpEfficiency,
			CONCAT(ROUND(sd.ConversionRate,2)) AS conversionRate,
			CONCAT(ROUND(sd.RetentionRate,2)) AS retentionRate,
			ROUND(sd.PerformanceScore,2) AS performanceScore,
			ROUND(sd.DynamicPerformanceScore,2) AS dynamicPerformanceScore,
			ROUND(sd.PerformanceScore + sd.DynamicPerformanceScore,2) AS overallScore,
			RANK() OVER (ORDER BY (sd.PerformanceScore + sd.DynamicPerformanceScore) DESC) AS `rank`,
			-- Components
			ROUND(sd.comp1, 2) AS comp1,
			ROUND(sd.comp2, 2) AS comp2,
			ROUND(sd.comp3, 2) AS comp3,
			ROUND(sd.comp4, 2) AS comp4,
			ROUND(sd.comp5, 2) AS comp5,
			ROUND(sd.comp6, 2) AS comp6,
			ROUND(sd.comp7, 2) AS comp7,
			ROUND(sd.netPremiumScore, 2) AS comp_netPremium,
			ROUND(sd.netODPremiumScore, 2) AS comp_netOD,
			ROUND(sd.addonSalesScore, 2) AS comp_addonSales,
			ROUND(sd.preDueRenewalScore, 2) AS comp_preDueRenewals
		FROM score_data sd
		LIMIT limitVal OFFSET calculated;

        -- Count query (uses v_dealerId)
		SELECT 
			COUNT(DISTINCT ld.assigned_agent) AS agentCount
		FROM
			mmi_lead_details ld
				LEFT JOIN
			mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
				LEFT JOIN
			mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
				INNER JOIN
			mmi_mast_user_registration_detail mud ON mud.id = ld.assigned_agent
		WHERE
			ld.dealer_code = v_dealerId
        AND ld.assigned_agent IS NOT NULL
        AND (v_segment IS NULL OR v_segment = ''
        OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
        AND (v_renewal_category IS NULL
        OR v_renewal_category = ''
        OR FIND_IN_SET(TRIM(ld.renewal_category),
            v_renewal_category))
        AND (v_dealerLocCode IS NULL
        OR v_dealerLocCode = ''
        OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
        AND ((v_startDate IS NULL OR v_startDate = ''
        OR v_endDate IS NULL
        OR v_endDate = '')
        OR (v_startDate IS NOT NULL
        AND v_startDate != ''
        AND v_endDate IS NOT NULL
        AND v_endDate != ''
        AND (ld.created_date BETWEEN v_startDate AND v_endDate
        OR ld.modified_date BETWEEN v_startDate AND v_endDate)))
        AND (v_zone IS NULL OR v_zone = ''
        OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
        AND (v_state IS NULL OR v_state = ''
        OR FIND_IN_SET(TRIM(dloc.state), v_state));

        SET SP_STATUS = '200';
        SET MESSAGE = 'PerformanceBoard agents filter details fetched';

    END IF; -- end v_check_type for performanceFilter




	ELSEIF v_type = 'PerformanceBoard' THEN
		
		IF v_check_type != 'fetchDealerAgent' THEN     -- dash dealer rows only

		WITH
		dealer_agents AS (
			SELECT DISTINCT t.assigned_agent AS agentId, t.dealer_code
			FROM (
				SELECT assigned_agent, dealer_code FROM mmi_lead_details WHERE assigned_agent IS NOT NULL
				UNION
				SELECT assigned_agent, dealer_code FROM mmi_lead_archive_details WHERE assigned_agent IS NOT NULL
			) t
			INNER JOIN mmi_mast_user_registration_detail u ON u.id = t.assigned_agent
			-- WHERE t.assigned_agent NOT IN (SELECT dealer_code FROM mmi_dealer_location_mapping)
		),

		leads_assigned_all AS (
			SELECT assigned_agent AS agentId, dealer_code, COUNT(DISTINCT lead_id) AS leadsAssigned
			FROM (
				SELECT mld.assigned_agent, mld.dealer_code, mld.lead_id FROM mmi_lead_details mld
                LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = mld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code 	
                WHERE mld.assigned_agent IS NOT NULL
				UNION ALL
				SELECT mld.assigned_agent, mld.dealer_code, mld.lead_id FROM mmi_lead_archive_details mld
                LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = mld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code 	
                WHERE mld.assigned_agent IS NOT NULL
			) t
			GROUP BY assigned_agent, dealer_code
		),

		leads_contacted_all AS (
			SELECT leads.assigned_agent AS agentId, leads.dealer_code, COUNT(DISTINCT cdh.lead_id) AS leadsContacted
			FROM (
				SELECT assigned_agent, dealer_code, lead_id FROM mmi_lead_details WHERE assigned_agent IS NOT NULL
				UNION ALL
				SELECT assigned_agent, dealer_code, lead_id FROM mmi_lead_archive_details WHERE assigned_agent IS NOT NULL
			) leads
			JOIN mmi_call_disposition_history cdh ON cdh.lead_id = leads.lead_id
			GROUP BY leads.assigned_agent, leads.dealer_code
		),

		policies_converted_all AS (
			SELECT assigned_agent AS agentId, dealer_code, COUNT(DISTINCT policy_no) AS policiesConverted
			FROM mmi_lead_archive_details
			WHERE assigned_agent IS NOT NULL
			  AND lead_status = 'Won'
			  AND converted_flag = 'CRM Renewal'
			GROUP BY assigned_agent, dealer_code
		),

		quote_shared_all AS (
			SELECT cdh.agent_code AS agentId, ld.dealer_code, COUNT(DISTINCT cdh.lead_id) AS QuoteShared
			FROM mmi_call_disposition_history cdh
			LEFT JOIN mmi_agent_disposition_field_response adf
				ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
			JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
			WHERE adf.field_value = 'Shared Quotes'
			  AND ld.assigned_agent IS NOT NULL
			GROUP BY cdh.agent_code, ld.dealer_code
		),

		/*followup_data_all AS (
			SELECT cdh.agent_code AS agentId, ld.dealer_code,
				   COUNT(CASE WHEN next_call_datetime IS NOT NULL THEN 1 END) AS TotalFollowUpsScheduled,
				   COUNT(CASE WHEN next_call_datetime IS NOT NULL
							   AND call_date <= STR_TO_DATE(next_call_datetime, '%Y-%m-%d %H:%i:%s')
						  THEN 1 END) AS FollowUpsDoneOnTime
			FROM mmi_call_disposition_history cdh
			JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
			WHERE ld.assigned_agent IS NOT NULL
			GROUP BY cdh.agent_code, ld.dealer_code
		),*/
        followup_data_all AS (
				WITH latest_calls AS (
					SELECT 
						cdh.*,
						ROW_NUMBER() OVER (
							PARTITION BY cdh.lead_id 
							ORDER BY cdh.created_date DESC
						) AS rn
					FROM mmi_call_disposition_history cdh
				)
				SELECT 
					lc.agent_code AS agentId,
					ld.dealer_code,
					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL THEN 1 
					END) AS TotalFollowUpsScheduled,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL
						AND lc.call_date <= STR_TO_DATE(lc.next_call_datetime,'%Y-%m-%d %H:%i:%s') 
						THEN 1 
					END) AS FollowUpsDoneOnTime

				FROM latest_calls lc
				JOIN mmi_lead_details ld 
					ON ld.lead_id = lc.lead_id
				WHERE lc.rn = 1 AND ld.assigned_agent IS NOT NULL
				GROUP BY lc.agent_code, ld.dealer_code
			),

		shortest_call_conversion_all AS (
			SELECT cdh.agent_code AS agentId, cdh.dealer_code,
				   COUNT(DISTINCT CASE WHEN call_rank <= 2 AND lad.lead_status = 'Won' THEN cdh.lead_id END) AS ConversionsWithinTwoCalls
			FROM (
				SELECT cdh.lead_id, cdh.agent_code, cdh.call_date, ld.dealer_code,
					   ROW_NUMBER() OVER (PARTITION BY cdh.lead_id ORDER BY cdh.call_date) AS call_rank
				FROM mmi_call_disposition_history cdh
				JOIN mmi_lead_archive_details ld ON ld.lead_id = cdh.lead_id
				WHERE ld.assigned_agent IS NOT NULL
			) cdh
			LEFT JOIN mmi_lead_archive_details lad ON lad.lead_id = cdh.lead_id
			WHERE cdh.agent_code IN (SELECT agentId FROM dealer_agents)
			  AND cdh.dealer_code IN (SELECT dealer_code FROM dealer_agents)
			GROUP BY cdh.agent_code, cdh.dealer_code
		),

		net_od_premium_all AS (
			SELECT assigned_agent AS agentId, dealer_code,
				   SUM(CAST(IFNULL(net_od_premium_amount, 0) AS DECIMAL(12,2)) +
					   CAST(IFNULL(addon_premium_amount, 0) AS DECIMAL(12,2))) AS NetODPremium
			FROM mmi_lead_details
			WHERE assigned_agent IS NOT NULL
			GROUP BY assigned_agent, dealer_code
		),

		premium_stats_all AS (
			SELECT lad.assigned_agent AS agentId, lad.dealer_code,
				   SUM(mmd.net_premium) AS NetPremiumCollected
			FROM mmi_lead_archive_details lad
			JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
			WHERE lad.assigned_agent IS NOT NULL
			  AND lad.lead_status = 'Won'
			GROUP BY lad.assigned_agent, lad.dealer_code
		),

		addon_sales_all AS (
			SELECT ld.assigned_agent AS agentId, ld.dealer_code, COUNT(pad.id) AS AddonSales
			FROM mmi_poladdon_data pad
			JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
			WHERE ld.assigned_agent IS NOT NULL
			GROUP BY ld.assigned_agent, ld.dealer_code
		),

		pre_due_renewals_all AS (
			SELECT 
				lad.assigned_agent AS agentId, 
				lad.dealer_code,
				COUNT(*) AS PreDueRenewals
			FROM mmi_lead_archive_details lad
			JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
			WHERE lad.lead_status = 'Won' 
			  AND lad.converted_flag = 'CRM Renewal'
			  AND DATEDIFF(lad.created_date, mmd.policy_expiry_date) > 10
			GROUP BY lad.assigned_agent, lad.dealer_code
		),

		trigger_flag_all AS (
			SELECT agent_code AS agentId, 0 AS TriggerFlag
			FROM mmi_call_disposition_history
			WHERE agent_code IN (SELECT agentId FROM dealer_agents)
			GROUP BY agent_code
		),
        
        breach_stats AS (
				SELECT 
					mld.assigned_agent,
                    mld.dealer_code,
					COUNT(DISTINCT lb.lead_id) AS breachedLeads
				FROM mmi_lead_breached lb
				JOIN mmi_lead_details mld 
					ON mld.lead_id = lb.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = mld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				GROUP BY mld.assigned_agent,mld.dealer_code
			),

		agent_metrics AS (
			SELECT
				da.agentId,
				da.dealer_code,
				COALESCE(la.leadsAssigned, 0) AS LeadsAssigned,
				COALESCE(lc.leadsContacted, 0) AS LeadsContacted,
				COALESCE(pc.policiesConverted, 0) AS PoliciesConverted,
				COALESCE(qs.QuoteShared, 0) AS QuoteShared,
				COALESCE(fd.FollowUpsDoneOnTime, 0) AS FollowUpsDoneOnTime,
				COALESCE(fd.TotalFollowUpsScheduled, 0) AS TotalFollowUpsScheduled,
				COALESCE(scc.ConversionsWithinTwoCalls, 0) AS ConversionsWithinTwoCalls,
				COALESCE(ps.NetPremiumCollected, 0) AS NetPremiumCollected,
				COALESCE(nop.NetODPremium, 0) AS NetODPremium,
				COALESCE(ads.AddonSales, 0) AS AddonSales,
				COALESCE(pdr.PreDueRenewals, 0) AS PreDueRenewals,
                COALESCE(bs.breachedLeads, 0) AS breachedLeads,
				COALESCE(tf.TriggerFlag, 0) AS TriggerFlag
			FROM dealer_agents da
			LEFT JOIN leads_assigned_all la ON la.agentId = da.agentId AND la.dealer_code = da.dealer_code
			LEFT JOIN leads_contacted_all lc ON lc.agentId = da.agentId AND lc.dealer_code = da.dealer_code
			LEFT JOIN policies_converted_all pc ON pc.agentId = da.agentId AND pc.dealer_code = da.dealer_code
			LEFT JOIN quote_shared_all qs ON qs.agentId = da.agentId AND qs.dealer_code = da.dealer_code
			LEFT JOIN followup_data_all fd ON fd.agentId = da.agentId AND fd.dealer_code = da.dealer_code
			LEFT JOIN shortest_call_conversion_all scc ON scc.agentId = da.agentId AND scc.dealer_code = da.dealer_code
			LEFT JOIN premium_stats_all ps ON ps.agentId = da.agentId AND ps.dealer_code = da.dealer_code
			LEFT JOIN net_od_premium_all nop ON nop.agentId = da.agentId AND nop.dealer_code = da.dealer_code
			LEFT JOIN addon_sales_all ads ON ads.agentId = da.agentId AND ads.dealer_code = da.dealer_code
			LEFT JOIN pre_due_renewals_all pdr ON pdr.agentId = da.agentId AND pdr.dealer_code = da.dealer_code
            LEFT JOIN breach_stats bs ON bs.assigned_agent = da.agentId AND bs.dealer_code = da.dealer_code
			LEFT JOIN trigger_flag_all tf ON tf.agentId = da.agentId
		),

		dealer_max_leads AS (
			SELECT dealer_code, MAX(LeadsAssigned) AS max_leads
			FROM agent_metrics
			GROUP BY dealer_code
		),

		agent_scores AS (
			SELECT
				am.dealer_code,
				am.agentId,
				am.LeadsAssigned,
				am.LeadsContacted,
				am.PoliciesConverted,
				am.QuoteShared,
				am.ConversionsWithinTwoCalls,
				am.TotalFollowUpsScheduled,
				am.FollowUpsDoneOnTime,
				am.NetPremiumCollected,
				am.NetODPremium,
				am.AddonSales,
				am.PreDueRenewals,
				dml.max_leads,
				am.TriggerFlag,
                am.breachedLeads,
                GREATEST(0,LEAST(100,100 - ROUND(NULLIF(am.breachedLeads, 0) /NULLIF(IFNULL(am.LeadsAssigned,0), 0) * 100,2))) AS FollowUpEfficiencyData,
				ROUND(IFNULL(am.LeadsAssigned / NULLIF(dml.max_leads, 0), 0) * 10, 2) AS comp1,
				ROUND(IFNULL(am.LeadsContacted / NULLIF(am.LeadsAssigned, 0), 0) * 10, 2) AS comp2,
				ROUND(IFNULL(am.FollowUpsDoneOnTime / NULLIF(am.TotalFollowUpsScheduled, 0), 0) * 10, 2) AS comp3,
				ROUND(IFNULL(am.QuoteShared / NULLIF(am.LeadsContacted, 0), 0) * 10, 2) AS comp4,
				ROUND(IFNULL(am.PoliciesConverted / NULLIF(am.LeadsContacted, 0), 0) * 25, 2) AS comp5,
				ROUND(IFNULL(am.PoliciesConverted / NULLIF(am.LeadsAssigned, 0), 0) * 15, 2) AS comp6,
				ROUND(IFNULL(am.ConversionsWithinTwoCalls / NULLIF(am.PoliciesConverted, 0), 0) * 5, 2) AS comp7,
				ROUND(IFNULL(GREATEST(am.NetPremiumCollected - 50000, 0) / 1000 * 10, 0), 2) AS netPremiumScore,
				ROUND(IFNULL(am.NetODPremium / 1000, 0), 2) AS netODPremiumScore,
                
				ROUND(IFNULL(am.AddonSales * 5, 0), 2) AS addonSalesScore,
				ROUND(IFNULL(am.PreDueRenewals * 10, 0), 2) AS preDueRenewalScore,
				/*ROUND(
					  IFNULL(am.LeadsAssigned / NULLIF(dml.max_leads, 0), 0) * 10
					+ IFNULL(am.LeadsContacted / NULLIF(am.LeadsAssigned, 0), 0) * 10
					+ IFNULL(am.FollowUpsDoneOnTime / NULLIF(am.TotalFollowUpsScheduled, 0), 0) * 10
					+ IFNULL(am.QuoteShared / NULLIF(am.LeadsContacted, 0), 0) * 10
					+ IFNULL(am.PoliciesConverted / NULLIF(am.LeadsContacted, 0), 0) * 25
					+ IFNULL(am.PoliciesConverted / NULLIF(am.LeadsAssigned, 0), 0) * 15
					+ IFNULL(am.ConversionsWithinTwoCalls / NULLIF(am.PoliciesConverted, 0), 0) * 5
					+ (CASE WHEN am.TriggerFlag <> 0 THEN 5 ELSE 0 END)
				, 2) AS PerformanceScore,*/
                
                ROUND((IFNULL(am.LeadsAssigned / NULLIF(AVG(am.LeadsAssigned) OVER (),0), 0) * 100 / 10)
                    + (IFNULL(am.LeadsContacted / NULLIF(am.LeadsAssigned,0), 0) * 10)
                    + (IFNULL((am.FollowUpsDoneOnTime / NULLIF(am.TotalFollowUpsScheduled,0)),0) * 10)
                    + (IFNULL(am.QuoteShared / NULLIF(am.LeadsContacted,0), 0) * 10)
                    + (IFNULL(am.PoliciesConverted / NULLIF(am.LeadsContacted,0), 0) * 25)
                    + (IFNULL(am.PoliciesConverted / NULLIF(am.LeadsAssigned,0), 0) * 15)
                    + (IFNULL(am.ConversionsWithinTwoCalls / NULLIF(am.PoliciesConverted,0), 0) * 100 * 5 / 100 )
                    -- + (CASE WHEN am.TriggerFlag <> 0 THEN 5 ELSE 0 END)
                    + am.TriggerFlag
                ,2) AS PerformanceScore,
                
				/*ROUND(
					IFNULL(GREATEST(am.NetPremiumCollected - 50000, 0) / 1000 * 10, 0)
					+ IFNULL(am.NetODPremium / 1000, 0)
					+ IFNULL(am.AddonSales * 5, 0)
					+ IFNULL(am.PreDueRenewals * 10, 0)
				, 2) AS DynamicPerformanceScore*/
                0 AS DynamicPerformanceScore
			FROM agent_metrics am
			LEFT JOIN dealer_max_leads dml ON dml.dealer_code = am.dealer_code
		),

		dealer_aggregates AS (
			SELECT
				ag.dealer_code,
                SUM(ag.TriggerFlag) AS TriggerFlag,
				SUM(ag.LeadsAssigned) AS LeadsAssigned,
				SUM(ag.LeadsContacted) AS LeadsContacted,
				SUM(ag.PoliciesConverted) AS PoliciesConverted,
				SUM(ag.NetPremiumCollected) AS NetPremiumCollected,
				SUM(ag.QuoteShared) AS QuoteShared,
				SUM(ag.ConversionsWithinTwoCalls) AS ConversionsWithinTwoCalls,
				SUM(ag.TotalFollowUpsScheduled) AS TotalFollowUpsScheduled,
				SUM(ag.FollowUpsDoneOnTime) AS FollowUpsDoneOnTime,
				SUM(ag.NetODPremium) AS NetODPremium,
				SUM(ag.AddonSales) AS AddonSales,
				SUM(ag.PreDueRenewals) AS PreDueRenewals,
                -- GREATEST(0,LEAST(100,100 - ROUND(SUM(ag.breachedLeads) / NULLIF(SUM(ag.LeadsAssigned), 0) * 100,2))) AS FollowUpEfficiencyData
				GREATEST(0,LEAST(100,100 - ROUND(NULLIF(COALESCE(SUM(ag.breachedLeads), 0), 0) / NULLIF(COALESCE(SUM(ag.LeadsAssigned), 0), 0) * 100,2))) AS FollowUpEfficiencyData
                -- SUM(ag.FollowUpEfficiencyData) AS FollowUpEfficiencyData 
				-- SUM(ag.DynamicPerformanceScore) AS DynamicPerformanceScore
			FROM agent_scores ag
			GROUP BY ag.dealer_code
		),

		-- across all dealers 
		global_max AS (
			SELECT MAX(LeadsAssigned) AS max_leads
			FROM dealer_aggregates
		),

		dealer_target AS (
			SELECT am.dealer_code, COUNT(DISTINCT agentId) * SUM(IFNULL(mtp.target_value,0)) AS TargetPremium
			FROM agent_metrics am
			left join mmi_target_planning mtp on mtp.team_member = am.agentId
			GROUP BY am.dealer_code
		),

		dealer_data AS (
			SELECT
				da.dealer_code AS dealer_id,
				dlm.dealer_name,
				da.LeadsAssigned,
				da.LeadsContacted,
				da.PoliciesConverted,
				da.NetPremiumCollected,
				da.QuoteShared,
				da.ConversionsWithinTwoCalls,
				da.TotalFollowUpsScheduled,
				da.FollowUpsDoneOnTime,
				da.NetODPremium,
				da.AddonSales,
				da.PreDueRenewals,
                da.FollowUpEfficiencyData,
				-- da.DynamicPerformanceScore,
               /* ROUND(
                IFNULL(GREATEST(da.NetPremiumCollected - dt.TargetPremium,0) / 1000 * 10,0)
                + IFNULL(da.NetODPremium / 1000,0)
                + IFNULL(da.AddonSales * 5,0)
                + IFNULL(da.PreDueRenewals * 10,0)
                ,2) AS DynamicPerformanceScore,*/
                0 AS DynamicPerformanceScore,
				dt.TargetPremium,   -- added 
				-- Dealer level PerformanceScore 
				/*ROUND(
					  IFNULL(da.LeadsAssigned / NULLIF(gm.max_leads, 0), 0) * 10
					+ IFNULL(da.LeadsContacted / NULLIF(da.LeadsAssigned, 0), 0) * 10
					+ IFNULL(da.FollowUpsDoneOnTime / NULLIF(da.TotalFollowUpsScheduled, 0), 0) * 10
					+ IFNULL(da.QuoteShared / NULLIF(da.LeadsContacted, 0), 0) * 10
					+ IFNULL(da.PoliciesConverted / NULLIF(da.LeadsContacted, 0), 0) * 25
					+ IFNULL(da.PoliciesConverted / NULLIF(da.LeadsAssigned, 0), 0) * 15
					+ IFNULL(da.ConversionsWithinTwoCalls / NULLIF(da.PoliciesConverted, 0), 0) * 5
				, 2) AS PerformanceScore,*/
                ROUND((IFNULL(da.LeadsAssigned / NULLIF(AVG(da.LeadsAssigned) OVER (),0), 0) * 100 / 10)
                    + (IFNULL(da.LeadsContacted / NULLIF(da.LeadsAssigned,0), 0) * 10)
                    + (IFNULL((da.FollowUpsDoneOnTime / NULLIF(da.TotalFollowUpsScheduled,0)),0) * 10)
                    + (IFNULL(da.QuoteShared / NULLIF(da.LeadsContacted,0), 0) * 10)
                    + (IFNULL(da.PoliciesConverted / NULLIF(da.LeadsContacted,0), 0) * 25)
                    + (IFNULL(da.PoliciesConverted / NULLIF(da.LeadsAssigned,0), 0) * 15)
                    + (IFNULL(da.ConversionsWithinTwoCalls / NULLIF(da.PoliciesConverted,0), 0) * 100 * 5 / 100 )
                    + da.TriggerFlag
                ,2) AS PerformanceScore,
                
				-- 
				ROUND(IFNULL(da.LeadsAssigned / NULLIF(gm.max_leads, 0), 0) * 10, 2) AS comp1,
				ROUND(IFNULL(da.LeadsContacted / NULLIF(da.LeadsAssigned, 0), 0) * 10, 2) AS comp2,
				ROUND(IFNULL(da.FollowUpsDoneOnTime / NULLIF(da.TotalFollowUpsScheduled, 0), 0) * 10, 2) AS comp3,
				ROUND(IFNULL(da.QuoteShared / NULLIF(da.LeadsContacted, 0), 0) * 10, 2) AS comp4,
				ROUND(IFNULL(da.PoliciesConverted / NULLIF(da.LeadsContacted, 0), 0) * 25, 2) AS comp5,
				ROUND(IFNULL(da.PoliciesConverted / NULLIF(da.LeadsAssigned, 0), 0) * 15, 2) AS comp6,
				ROUND(IFNULL(da.ConversionsWithinTwoCalls / NULLIF(da.PoliciesConverted, 0), 0) * 5, 2) AS comp7,
				ROUND(IFNULL(da.FollowUpsDoneOnTime / NULLIF(da.TotalFollowUpsScheduled, 0), 0) * 100, 2) AS FollowUpEfficiency,
				ROUND(IFNULL(da.PoliciesConverted / NULLIF(da.LeadsContacted, 0), 0) * 100, 2) AS ConversionRate,
				ROUND(IFNULL(da.PoliciesConverted / NULLIF(da.LeadsAssigned, 0), 0) * 100, 2) AS RetentionRate
			FROM dealer_aggregates da
			CROSS JOIN global_max gm
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.dealer_code = da.dealer_code
			LEFT JOIN dealer_target dt ON dt.dealer_code = da.dealer_code
		),

		dealer_nonzero AS (
			SELECT *
			FROM dealer_data
			WHERE LeadsAssigned > 0
			   OR LeadsContacted > 0
			   OR PoliciesConverted > 0
			   OR NetPremiumCollected > 0
		),

		dealer_with_avg AS (
			SELECT
				dn.*,
				AVG(dn.PerformanceScore) OVER () AS avg_performance_score,
				AVG(dn.DynamicPerformanceScore) OVER () AS avg_dynamic_score
			FROM dealer_nonzero dn
		)

		SELECT
			dw.dealer_id AS dealerId,
			dw.dealer_name AS dealerName,
			NULL AS agentId,
			NULL AS agentName,
			dw.LeadsAssigned AS leadsAssigned,
			dw.LeadsContacted AS leadsContacted,
			dw.PoliciesConverted AS policiesConverted,
			dw.NetPremiumCollected AS netPremiumCollected,
			-- dw.FollowUpEfficiency AS followUpEfficiency,
            dw.FollowUpEfficiencyData AS followUpEfficiency,
			CONCAT(ROUND(dw.ConversionRate, 2)) AS conversionRate,
			CONCAT(ROUND(dw.RetentionRate, 2)) AS retentionRate,
			ROUND(dw.PerformanceScore, 2) AS performanceScore,
			ROUND(dw.DynamicPerformanceScore, 2) AS dynamicPerformanceScore,
			ROUND(dw.PerformanceScore + dw.DynamicPerformanceScore, 2) AS overallScore,
			ROUND(dw.avg_performance_score, 2) AS avg_performance_score,
			ROUND(dw.avg_dynamic_score, 2) AS avg_dynamic_score,
			RANK() OVER (ORDER BY (dw.PerformanceScore + dw.DynamicPerformanceScore) DESC) AS `rank`,
			ROUND(dw.comp1, 2) AS comp1,
			ROUND(dw.comp2, 2) AS comp2,
			ROUND(dw.comp3, 2) AS comp3,
			ROUND(dw.comp4, 2) AS comp4,
			ROUND(dw.comp5, 2) AS comp5,
			ROUND(dw.comp6, 2) AS comp6,
			ROUND(dw.comp7, 2) AS comp7,
			ROUND(dw.TargetPremium, 2) AS targetPremium   
		FROM dealer_with_avg dw
		ORDER BY `rank`
		LIMIT limitVal OFFSET calculated;

		-- count for pagination
		SELECT 
			COUNT(DISTINCT md.dealer_code) AS dealerCount
		FROM
			mmi_dealer_location_mapping md
		WHERE
			md.dealer_code IN (SELECT DISTINCT
            ld.dealer_code
        FROM
            mmi_lead_details ld
                LEFT JOIN
            mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
                LEFT JOIN
            mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                INNER JOIN
            mmi_mast_user_registration_detail mud ON mud.id = ld.assigned_agent
        WHERE
            ld.assigned_agent IS NOT NULL);

	SET SP_STATUS = '200';
	SET MESSAGE = 'PerformanceBoard details fetched';



	-- accordion agent rows only
	ELSE   -- v_check_type = 'fetchDealerAgent'
		
		WITH --  agent level ctes (no filters)
		lead_assigned_detail AS (
			SELECT
				mld.dealer_code,
				mld.assigned_agent AS agentId,
				COUNT(DISTINCT mld.lead_id) AS leadsAssigned
			FROM mmi_lead_details mld
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE mld.assigned_agent IS NOT NULL
			  AND (v_dealerId IS NULL OR v_dealerId = '' OR mld.dealer_code = v_dealerId)
			GROUP BY mld.dealer_code, mld.assigned_agent
		),
		lead_assigned_archive AS (
			SELECT
				mld.dealer_code,
				mld.assigned_agent AS agentId,
				COUNT(DISTINCT mld.lead_id) AS leadsAssigned
			FROM mmi_lead_archive_details mld
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE mld.assigned_agent IS NOT NULL
			  AND (v_dealerId IS NULL OR v_dealerId = '' OR mld.dealer_code = v_dealerId)
			GROUP BY mld.dealer_code, mld.assigned_agent
		),
		lead_contacted_detail AS (
			SELECT
				mld.dealer_code,
				mld.assigned_agent AS agentId,
				COUNT(DISTINCT cdh.lead_id) AS leadsContacted
				-- ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
			FROM mmi_call_disposition_history cdh
			JOIN mmi_lead_details mld ON mld.lead_id = cdh.lead_id
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE (v_dealerId IS NULL OR v_dealerId = '' OR mld.dealer_code = v_dealerId)
			GROUP BY mld.dealer_code, mld.assigned_agent
		),
		lead_contacted_archive AS (
			SELECT
				mld.dealer_code,
				mld.assigned_agent AS agentId,
				COUNT(DISTINCT cdh.lead_id) AS leadsContacted
				-- ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
			FROM mmi_call_disposition_history cdh
			JOIN mmi_lead_archive_details mld ON mld.lead_id = cdh.lead_id
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE (v_dealerId IS NULL OR v_dealerId = '' OR mld.dealer_code = v_dealerId)
			GROUP BY mld.dealer_code, mld.assigned_agent
		),
		agent_lead_combined AS (
			SELECT
				COALESCE(ld.dealer_code, la.dealer_code) AS dealer_code,
				COALESCE(ld.agentId, la.agentId) AS agentId,
				COALESCE(ld.leadsAssigned, 0) + COALESCE(la.leadsAssigned, 0) AS leadsAssigned_total,
				COALESCE(cd.leadsContacted, 0) + COALESCE(ca.leadsContacted, 0) AS leadsContacted_total
			FROM lead_assigned_detail ld
			LEFT JOIN lead_assigned_archive la ON ld.dealer_code = la.dealer_code AND ld.agentId = la.agentId
			LEFT JOIN lead_contacted_detail cd ON COALESCE(ld.dealer_code, la.dealer_code) = cd.dealer_code
											AND COALESCE(ld.agentId, la.agentId) = cd.agentId
			LEFT JOIN lead_contacted_archive ca ON COALESCE(ld.dealer_code, la.dealer_code, cd.dealer_code) = ca.dealer_code
											  AND COALESCE(ld.agentId, la.agentId, cd.agentId) = ca.agentId
		),
		agent_list AS (
			SELECT DISTINCT agentId, dealer_code AS dealerId FROM agent_lead_combined
		),
		agent_details AS (
			SELECT
				al.dealerId,
				md.dealer_name,
				al.agentId,
				CONCAT(mud.first_name, ' ', mud.last_name) AS agentName
			FROM agent_list al
			LEFT JOIN mmi_dealer_location_mapping md ON md.dealer_code = al.dealerId
			JOIN mmi_mast_user_registration_detail mud ON mud.id = al.agentId
		),
		leads_assigned AS (
			SELECT agentId, leadsAssigned_total AS LeadsAssigned FROM agent_lead_combined
		),
		leads_contacted AS (
			SELECT agentId, leadsContacted_total AS LeadsContacted FROM agent_lead_combined
		),
		/*followup_data AS (
			SELECT cdh.agent_code AS agentId,
				COUNT(CASE WHEN next_call_datetime IS NOT NULL THEN 1 END) AS TotalFollowUpsScheduled,
				COUNT(CASE WHEN next_call_datetime IS NOT NULL
					AND call_date <= STR_TO_DATE(next_call_datetime,'%Y-%m-%d %H:%i:%s') THEN 1 END) AS FollowUpsDoneOnTime
			FROM mmi_call_disposition_history cdh
			JOIN agent_list al ON al.agentId = cdh.agent_code
			JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE ld.dealer_code = v_dealerId
			GROUP BY cdh.agent_code
		),*/
        followup_data AS (
				WITH latest_calls AS (
					SELECT 
						cdh.*,
						ROW_NUMBER() OVER (
							PARTITION BY cdh.lead_id 
							ORDER BY cdh.created_date DESC
						) AS rn
					FROM mmi_call_disposition_history cdh
				)
				SELECT 
					lc.agent_code AS agentId,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL THEN 1 
					END) AS TotalFollowUpsScheduled,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL
						AND lc.call_date <= STR_TO_DATE(lc.next_call_datetime,'%Y-%m-%d %H:%i:%s') 
						THEN 1 
					END) AS FollowUpsDoneOnTime

				FROM latest_calls lc
				JOIN agent_list al 
					ON al.agentId = lc.agent_code
				JOIN mmi_lead_details ld 
					ON ld.lead_id = lc.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = ld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE lc.rn = 1 AND ld.dealer_code = v_dealerId
				GROUP BY lc.agent_code
			),
		quote_shared AS (
			SELECT cdh.agent_code AS agentId,
				   COUNT(DISTINCT cdh.lead_id) AS QuoteShared
			FROM mmi_call_disposition_history cdh
			LEFT JOIN mmi_agent_disposition_field_response adf ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
			JOIN agent_list al ON al.agentId = cdh.agent_code
			JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE adf.field_value = 'Shared Quotes'
			  AND ld.dealer_code = v_dealerId
			GROUP BY cdh.agent_code
		),
		eligible_leads AS (
			SELECT ld.assigned_agent AS agentId,
				   COUNT(DISTINCT ld.lead_id) AS eligibleLeads
			FROM mmi_lead_details ld
			JOIN agent_list al ON al.agentId = ld.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE lead_type IN ('Hot','Warm')
			  AND ld.dealer_code = v_dealerId
			GROUP BY ld.assigned_agent
		),
		converted_policies AS (
			SELECT lad.assigned_agent AS agentId,
				   COUNT(DISTINCT policy_no) AS policiesConverted
			FROM mmi_lead_archive_details lad
			JOIN agent_list al ON al.agentId = lad.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE lead_status = 'Won' AND converted_flag = 'CRM Renewal'
			  AND lad.dealer_code = v_dealerId
			GROUP BY lad.assigned_agent
		),
		shortest_call_conversion AS (
			SELECT cdh.agent_code AS agentId,
				   COUNT(DISTINCT CASE
					   WHEN call_rank <= 2 AND lad.lead_status = 'Won' THEN cdh.lead_id
				   END) AS ConversionsWithinTwoCalls
			FROM (
				SELECT lead_id, agent_code, call_date,
					   ROW_NUMBER() OVER (PARTITION BY lead_id ORDER BY call_date) AS call_rank
				FROM mmi_call_disposition_history
			) cdh
			LEFT JOIN mmi_lead_archive_details lad ON lad.lead_id = cdh.lead_id
			JOIN agent_list al ON al.agentId = cdh.agent_code
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE cdh.agent_code IN (SELECT agentId FROM agent_list)
			  AND lad.dealer_code = v_dealerId
			GROUP BY cdh.agent_code
		),
		disposition_quality AS (
			SELECT agent_code AS agentId,
				   COUNT(DISTINCT lead_id) AS CorrectDispositions
			FROM mmi_call_disposition_history
			WHERE dealer_disposition_id IS NOT NULL
			  AND agent_code IN (SELECT agentId FROM agent_list)
			GROUP BY agent_code
		),
		trigger_flag AS (
			SELECT agent_code AS agentId,
				   0 AS TriggerFlag
			FROM mmi_call_disposition_history
			WHERE agent_code IN (SELECT agentId FROM agent_list)
			GROUP BY agent_code
		),
		avg_handling_time AS (
			SELECT agent_code AS agentId,
				   0 AS AvgHandlingTime
			FROM mmi_call_disposition_history
			WHERE agent_code IN (SELECT agentId FROM agent_list)
			GROUP BY agent_code
		),
		target_premium AS (
			SELECT agentId, SUM(IFNULL(mtp.target_value,0)) AS TargetPremium FROM agent_list al
			left join mmi_target_planning mtp on mtp.team_member = al.agentId
			GROUP BY agentId
		),
		/* net_od_premium AS (
			SELECT assigned_agent AS agentId,
				   SUM(CAST(IFNULL(net_od_premium_amount,0) AS DECIMAL(12,2)) +
					   CAST(IFNULL(addon_premium_amount,0) AS DECIMAL(12,2))) AS NetODPremium
			FROM mmi_lead_details ld
			JOIN agent_list al ON al.agentId = ld.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE ld.dealer_code = v_dealerId
			GROUP BY assigned_agent
		), */
		net_od_premium AS (
		SELECT assigned_agent AS agentId,
			   SUM(CAST(IFNULL(net_od_premium_amount,0) AS DECIMAL(12,2)) +
				   CAST(IFNULL(addon_premium_amount,0) AS DECIMAL(12,2))) AS NetODPremium
		FROM mmi_lead_details
		WHERE assigned_agent IS NOT NULL AND dealer_code = v_dealerId
		GROUP BY assigned_agent
	),
		premium_stats AS (
			SELECT lad.assigned_agent AS agentId,
				   SUM(mmd.net_premium) AS NetPremiumCollected
			FROM mmi_lead_archive_details lad
			JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
			JOIN agent_list al ON al.agentId = lad.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE lad.lead_status = 'Won'
			  AND lad.dealer_code = v_dealerId
			GROUP BY lad.assigned_agent
		),
		addon_sales AS (
			SELECT ld.assigned_agent AS agentId,
				   COUNT(pad.id) AS AddonSales
			FROM mmi_poladdon_data pad
			JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
			JOIN agent_list al ON al.agentId = ld.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE ld.dealer_code = v_dealerId
			GROUP BY ld.assigned_agent
		),
		pre_due_renewals AS (
		SELECT 
			lad.assigned_agent AS agentId,
			COUNT(*) AS PreDueRenewals
		FROM mmi_lead_archive_details lad
		JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
		WHERE lad.lead_status = 'Won' 
		  AND lad.converted_flag = 'CRM Renewal'
		  AND DATEDIFF(lad.created_date, mmd.policy_expiry_date) > 10
		GROUP BY lad.assigned_agent
		),
		group_product AS (
			SELECT assigned_agent AS agentId,
				   COUNT(DISTINCT lead_id) AS RetainedCustomers
			FROM mmi_lead_details ld
			JOIN agent_list al ON al.agentId = ld.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE group_product IS NOT NULL
			  AND ld.dealer_code = v_dealerId
			GROUP BY assigned_agent
		),
		conversion_data AS (
			SELECT assigned_agent AS agentId,
				   COUNT(DISTINCT CASE WHEN lead_status = 'Won' AND converted_flag = 'CRM Renewal' THEN lead_id END) AS WonLeads
			FROM mmi_lead_archive_details lad
			JOIN agent_list al ON al.agentId = lad.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE lad.dealer_code = v_dealerId
			GROUP BY assigned_agent
		),
        breach_stats AS (
				SELECT 
					mld.assigned_agent,
					COUNT(DISTINCT lb.lead_id) AS breachedLeads
				FROM mmi_lead_breached lb
				JOIN mmi_lead_details mld 
					ON mld.lead_id = lb.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = mld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE mld.dealer_code = v_dealerId
				GROUP BY mld.assigned_agent
			),
		agent_final_data AS (
			SELECT
				ad.dealerId AS dealer_id,
				ad.dealer_name,
				ad.agentId,
				ad.agentName,
				IFNULL(la.LeadsAssigned,0) AS LeadsAssigned,
				IFNULL(lc.LeadsContacted,0) AS LeadsContacted,
				0 AS EligibleLeads,
				IFNULL(cp.policiesConverted,0) AS PoliciesConverted,
				IFNULL(ps.NetPremiumCollected,0) AS NetPremiumCollected,
				0 AS AvgHandlingTime,
				IFNULL(fd.FollowUpsDoneOnTime,0) AS FollowUpsDoneOnTime,
				IFNULL(fd.TotalFollowUpsScheduled,0) AS TotalFollowUpsScheduled,
				IFNULL(qs.QuoteShared,0) AS QuoteShared,
				0 AS CorrectDispositions,
				-- IFNULL(tf.TriggerFlag,0) AS TriggerFlag,
				IFNULL(scc.ConversionsWithinTwoCalls,0) AS ConversionsWithinTwoCalls,
				IFNULL(tp.TargetPremium,0) AS TargetPremium,
				5 AS TriggerFlag,
				IFNULL(nop.NetODPremium,0) AS NetODPremium,
				IFNULL(ads.AddonSales,0) AS AddonSales,
				IFNULL(pdr.PreDueRenewals,0) AS PreDueRenewals,
				IFNULL(gp.RetainedCustomers,0) AS RetainedCustomers,
				IFNULL(ROUND((IFNULL(cd.WonLeads,0) / NULLIF(IFNULL(lc.LeadsContacted,0),0)) * 100,2),0) AS ConversionRate,
				IFNULL(ROUND((IFNULL(cp.policiesConverted,0) / NULLIF(IFNULL(la.LeadsAssigned,0),0)) * 100,2),0) AS RetentionRate,
				IFNULL(bs.breachedLeads,0) AS breachedLeads
			FROM agent_details ad
			LEFT JOIN leads_assigned la ON la.agentId = ad.agentId
			LEFT JOIN leads_contacted lc ON lc.agentId = ad.agentId
			LEFT JOIN converted_policies cp ON cp.agentId = ad.agentId
			LEFT JOIN premium_stats ps ON ps.agentId = ad.agentId
			LEFT JOIN followup_data fd ON fd.agentId = ad.agentId
			LEFT JOIN quote_shared qs ON qs.agentId = ad.agentId
			LEFT JOIN trigger_flag tf ON tf.agentId = ad.agentId
			LEFT JOIN shortest_call_conversion scc ON scc.agentId = ad.agentId
			LEFT JOIN conversion_data cd ON cd.agentId = ad.agentId
			LEFT JOIN target_premium tp ON tp.agentId = ad.agentId
			LEFT JOIN net_od_premium nop ON nop.agentId = ad.agentId
			LEFT JOIN addon_sales ads ON ads.agentId = ad.agentId
			LEFT JOIN pre_due_renewals pdr ON pdr.agentId = ad.agentId
			LEFT JOIN group_product gp ON gp.agentId = ad.agentId
            LEFT JOIN breach_stats bs ON bs.assigned_agent = ad.agentId
		),
		agent_score_data AS (
			SELECT
				dealer_id,
				dealer_name,
				agentId,
				agentName AS AgentName,
				ROUND((LeadsAssigned / NULLIF(MAX(LeadsAssigned) OVER (PARTITION BY dealer_id),0)) * 10,2) AS comp1,
				ROUND((LeadsContacted / NULLIF(LeadsAssigned,0)) * 10,2) AS comp2,
				ROUND((FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0)) * 10,2) AS comp3,
				ROUND((QuoteShared / NULLIF(LeadsContacted,0)) * 10,2) AS comp4,
				ROUND((PoliciesConverted / NULLIF(LeadsContacted,0)) * 25,2) AS comp5,
				ROUND((PoliciesConverted / NULLIF(LeadsAssigned,0)) * 15,2) AS comp6,
				ROUND((ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0)) * 5,2) AS comp7,
				LeadsAssigned,
				LeadsContacted,
				PoliciesConverted,
				NetPremiumCollected,
				QuoteShared,
				-- TriggerFlag,
				ConversionsWithinTwoCalls,
				TargetPremium,
				NetODPremium,
				AddonSales,
				PreDueRenewals,
				RetainedCustomers,
				FollowUpsDoneOnTime,
				TotalFollowUpsScheduled,
				ConversionRate,
				RetentionRate,
				-- ROUND(IFNULL(FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0),0) * 100,2) AS FollowUpEfficiency,
                GREATEST(0,LEAST(100,100 - ROUND(NULLIF(breachedLeads, 0) /NULLIF(IFNULL(LeadsAssigned,0), 0) * 100,2))) AS FollowUpEfficiency,
			   -- ROUND(((LeadsAssigned / NULLIF(MAX(LeadsAssigned) OVER (),0)) * 100 * 10 / 100)
			   /*ROUND(((LeadsAssigned / NULLIF(MAX(LeadsAssigned) OVER (PARTITION BY dealer_id),0)) * 100 * 10 / 100)
					+ (IFNULL((LeadsContacted / NULLIF(LeadsAssigned,0)),0) * 100 * 10 / 100)
					+ (IFNULL((FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0)),0) * 100 * 10 / 100)
					+ (IFNULL((QuoteShared / NULLIF(LeadsContacted,0)),0) * 100 * 10 / 100)
					+ (IFNULL((PoliciesConverted / NULLIF(LeadsContacted,0)),0) * 100 * 25 / 100)
					-- + (CASE WHEN TriggerFlag <> 0 THEN 5 ELSE 0 END)
					+ (IFNULL((PoliciesConverted / NULLIF(LeadsAssigned,0)),0) * 100 * 15 / 100)
					+ (IFNULL((ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0)),0) * 100 * 5 / 100)
				,2) AS PerformanceScore,*/
                ROUND((IFNULL(LeadsAssigned / NULLIF(AVG(LeadsAssigned) OVER (PARTITION BY dealer_id),0), 0) * 100 / 10)
                    + (IFNULL(LeadsContacted / NULLIF(LeadsAssigned,0), 0) * 10)
                    + (IFNULL((FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0)),0) * 10)
                    + (IFNULL(QuoteShared / NULLIF(LeadsContacted,0), 0) * 10)
                    + (IFNULL(PoliciesConverted / NULLIF(LeadsContacted,0), 0) * 25)
                    + (IFNULL(PoliciesConverted / NULLIF(LeadsAssigned,0), 0) * 15)
                    + (IFNULL(ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0), 0)  * 100 * 5 / 100 )
                    + TriggerFlag
                ,2) AS PerformanceScore,
                
				/*ROUND(IFNULL(GREATEST(NetPremiumCollected - TargetPremium,0) / 1000 * 10,0)
					+ IFNULL(NetODPremium / 1000,0)
					+ IFNULL(AddonSales * 5,0)
					+ IFNULL(PreDueRenewals * 10,0)
				,2) AS DynamicPerformanceScore*/
                0 AS DynamicPerformanceScore
			  FROM agent_final_data
			)

			SELECT
				agentId,
				AgentName AS agentName,
				comp1,
				comp2,
				comp3,
				comp4,
				comp5,
				comp6,
				comp7,
				ROUND(LeadsAssigned, 2) AS leadsAssigned,
				ROUND(LeadsContacted, 2) AS leadsContacted,
				ROUND(PoliciesConverted, 2) AS policiesConverted,
				ROUND(NetPremiumCollected, 2) AS netPremiumCollected,
				ROUND(FollowUpEfficiency, 2) AS followUpEfficiency,
				ROUND(ConversionRate, 2) AS conversionRate,
				ROUND(RetentionRate, 2) AS retentionRate,
				ROUND(PerformanceScore, 2) AS performanceScore,
				ROUND(DynamicPerformanceScore, 2) AS dynamicPerformanceScore,
				ROUND(PerformanceScore + DynamicPerformanceScore, 2) AS overallScore,
				RANK() OVER (ORDER BY (PerformanceScore + DynamicPerformanceScore) DESC) AS `rank`
			FROM agent_score_data
			WHERE dealer_id = v_dealerId
			ORDER BY `rank`
			LIMIT limitVal OFFSET calculated;

			-- count for pagination (unfiltered)
			SELECT 
				COUNT(DISTINCT ld.assigned_agent) AS agentCount
			FROM
				mmi_lead_details ld
					LEFT JOIN
				mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
					LEFT JOIN
				mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
					INNER JOIN
				mmi_mast_user_registration_detail mud ON mud.id = ld.assigned_agent
			WHERE
				ld.dealer_code = v_dealerId
					AND ld.assigned_agent IS NOT NULL;

				SET SP_STATUS = '200';
				SET MESSAGE = 'PerformanceBoard agents details fetched';
            
		END IF;  -- end v_check_type for PerformanceBoard
	END IF;  -- end v_type for MIBL
    
    
    
		-- DEALER Role
	ELSEIF v_role_type = 'dealer' THEN
        
		IF v_type = 'performanceFilter' THEN
        
		WITH
		lead_assigned_detail AS (
			SELECT
				mld.assigned_agent,
				COUNT(DISTINCT mld.lead_id) AS leadsAssigned
			FROM mmi_lead_details mld
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE mld.assigned_agent IS NOT NULL
			  AND mld.dealer_code = v_dealerId
			  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (mld.created_date BETWEEN v_startDate AND v_endDate
							OR mld.modified_date BETWEEN v_startDate AND v_endDate) ) )
			  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			GROUP BY mld.assigned_agent
		),
		lead_assigned_archive AS (
			SELECT
				mld.assigned_agent,
				COUNT(DISTINCT mld.lead_id) AS leadsAssigned
			FROM mmi_lead_archive_details mld
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE mld.assigned_agent IS NOT NULL
			  AND mld.dealer_code = v_dealerId
			  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (mld.created_date BETWEEN v_startDate AND v_endDate
							OR mld.modified_date BETWEEN v_startDate AND v_endDate) ) )
			  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			GROUP BY mld.assigned_agent
		),
		lead_contacted_detail AS (
			SELECT
				mld.assigned_agent,
				COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
				ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
			FROM mmi_call_disposition_history cdh
			JOIN mmi_lead_details mld ON mld.lead_id = cdh.lead_id
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE mld.dealer_code = v_dealerId
			  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (mld.created_date BETWEEN v_startDate AND v_endDate
							OR mld.modified_date BETWEEN v_startDate AND v_endDate) ) )
			  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))
			GROUP BY mld.assigned_agent
		),
		lead_contacted_archive AS (
			SELECT
				mld.assigned_agent,
				COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
				ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
			FROM mmi_call_disposition_history cdh
			JOIN mmi_lead_archive_details mld ON mld.lead_id = cdh.lead_id
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE mld.dealer_code = v_dealerId
			  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (mld.created_date BETWEEN v_startDate AND v_endDate
							OR mld.modified_date BETWEEN v_startDate AND v_endDate) ) )
			 AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
			 AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ','')))
			GROUP BY mld.assigned_agent
		),
		agent_lead_combined AS (
			SELECT
				COALESCE(ld.assigned_agent, la.assigned_agent) AS assigned_agent,
				COALESCE(ld.leadsAssigned, 0) + COALESCE(la.leadsAssigned, 0) AS leadsAssigned_total,
				COALESCE(cd.leadsContacted, 0) + COALESCE(ca.leadsContacted, 0) AS leadsContacted_total
			FROM lead_assigned_detail ld
			LEFT JOIN lead_assigned_archive la ON ld.assigned_agent = la.assigned_agent
			LEFT JOIN lead_contacted_detail cd ON COALESCE(ld.assigned_agent, la.assigned_agent) = cd.assigned_agent
			LEFT JOIN lead_contacted_archive ca ON COALESCE(ld.assigned_agent, la.assigned_agent, cd.assigned_agent) = ca.assigned_agent
		),
		agent_list AS (
			SELECT DISTINCT assigned_agent AS agentId FROM agent_lead_combined
		),
		agent_details AS (
			SELECT 
				al.agentId,
				CONCAT(mud.first_name, ' ', mud.last_name) AS agentName
			FROM agent_list al
			JOIN mmi_mast_user_registration_detail mud ON mud.id = al.agentId
		),
		leads_assigned AS (
			SELECT assigned_agent, leadsAssigned_total AS LeadsAssigned FROM agent_lead_combined
		),
		leads_contacted AS (
			SELECT assigned_agent, leadsContacted_total AS LeadsContacted FROM agent_lead_combined
		),
		/*followup_data AS (
			SELECT cdh.agent_code AS agentId,
				COUNT(CASE WHEN next_call_datetime IS NOT NULL THEN 1 END) AS TotalFollowUpsScheduled,
				COUNT(CASE WHEN next_call_datetime IS NOT NULL
					AND call_date <= STR_TO_DATE(next_call_datetime,'%Y-%m-%d %H:%i:%s') THEN 1 END) AS FollowUpsDoneOnTime
			FROM mmi_call_disposition_history cdh
			JOIN agent_list al ON al.agentId = cdh.agent_code
			JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE ld.dealer_code = v_dealerId
			  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (ld.created_date BETWEEN v_startDate AND v_endDate
							OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
			 AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class),v_segment))
			GROUP BY cdh.agent_code
		),*/
        followup_data AS (
				WITH latest_calls AS (
					SELECT 
						cdh.*,
						ROW_NUMBER() OVER (
							PARTITION BY cdh.lead_id 
							ORDER BY cdh.created_date DESC
						) AS rn
					FROM mmi_call_disposition_history cdh
				)
				SELECT 
					lc.agent_code AS agentId,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL THEN 1 
					END) AS TotalFollowUpsScheduled,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL
						AND lc.call_date <= STR_TO_DATE(lc.next_call_datetime,'%Y-%m-%d %H:%i:%s') 
						THEN 1 
					END) AS FollowUpsDoneOnTime

				FROM latest_calls lc
				JOIN agent_list al 
					ON al.agentId = lc.agent_code
				JOIN mmi_lead_details ld 
					ON ld.lead_id = lc.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = ld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE lc.rn = 1 AND ld.dealer_code = v_dealerId 
                AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (ld.created_date BETWEEN v_startDate AND v_endDate
							OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
			 AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class),v_segment))
				GROUP BY lc.agent_code
			),
		quote_shared AS (
			SELECT cdh.agent_code AS agentId,
				   COUNT(DISTINCT cdh.lead_id) AS QuoteShared
			FROM mmi_call_disposition_history cdh
			LEFT JOIN mmi_agent_disposition_field_response adf ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
			JOIN agent_list al ON al.agentId = cdh.agent_code
			JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE adf.field_value = 'Shared Quotes'
			  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (ld.created_date BETWEEN v_startDate AND v_endDate
							OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
			  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class),v_segment))
			GROUP BY cdh.agent_code
		),
		eligible_leads AS (
			SELECT assigned_agent,
				   COUNT(DISTINCT ld.lead_id) AS eligibleLeads
			FROM mmi_lead_details ld
			JOIN agent_list al ON al.agentId = ld.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE lead_type IN ('Hot','Warm')
			  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (ld.created_date BETWEEN v_startDate AND v_endDate
							OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
			 AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class),v_segment))
			GROUP BY assigned_agent
		),
		converted_policies AS (
			SELECT assigned_agent,
				   COUNT(DISTINCT policy_no) AS policiesConverted
			FROM mmi_lead_archive_details lad
			JOIN agent_list al ON al.agentId = lad.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE lead_status = 'Won' AND converted_flag = 'CRM Renewal'
			  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (lad.created_date BETWEEN v_startDate AND v_endDate
							OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
			 AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(lad.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(lad.vehicle_class),v_segment))
			GROUP BY assigned_agent
		),
		shortest_call_conversion AS (
			SELECT cdh.agent_code AS agentId,
				   COUNT(DISTINCT CASE
					   WHEN call_rank <= 2 AND lad.lead_status = 'Won' THEN cdh.lead_id
				   END) AS ConversionsWithinTwoCalls
			FROM (
				SELECT lead_id, agent_code, call_date,
					   ROW_NUMBER() OVER (PARTITION BY lead_id ORDER BY call_date) AS call_rank
				FROM mmi_call_disposition_history
			) cdh
			LEFT JOIN mmi_lead_archive_details lad ON lad.lead_id = cdh.lead_id
			JOIN agent_list al ON al.agentId = cdh.agent_code
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE cdh.agent_code IN (SELECT agentId FROM agent_list)
			  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (lad.created_date BETWEEN v_startDate AND v_endDate
							OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
			  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(lad.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(lad.vehicle_class, v_segment))
			GROUP BY cdh.agent_code
		),
		disposition_quality AS (
			SELECT agent_code AS agentId,
				   COUNT(DISTINCT lead_id) AS CorrectDispositions
			FROM mmi_call_disposition_history
			WHERE dealer_disposition_id IS NOT NULL
			  AND agent_code IN (SELECT agentId FROM agent_list)
			GROUP BY agent_code
		),
		trigger_flag AS (
			SELECT agent_code AS agentId,
				   0 AS TriggerFlag
			FROM mmi_call_disposition_history
			WHERE agent_code IN (SELECT agentId FROM agent_list)
			GROUP BY agent_code
		),
		avg_handling_time AS (
			SELECT agent_code AS agentId,
				   0 AS AvgHandlingTime
			FROM mmi_call_disposition_history
			WHERE agent_code IN (SELECT agentId FROM agent_list)
			GROUP BY agent_code
		),
		target_premium AS (
			SELECT agentId, SUM(IFNULL(mtp.target_value,0)) AS TargetPremium FROM agent_list al
			left join mmi_target_planning mtp on mtp.team_member = al.agentId
			GROUP BY agentId
		),
		net_od_premium AS (
			SELECT assigned_agent AS agentId,
				   SUM(CAST(IFNULL(net_od_premium_amount,0) AS DECIMAL(12,2)) +
					   CAST(IFNULL(addon_premium_amount,0) AS DECIMAL(12,2))) AS NetODPremium
			FROM mmi_lead_archive_details ld
			JOIN agent_list al ON al.agentId = ld.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (ld.created_date BETWEEN v_startDate AND v_endDate
							OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
			  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class),v_segment))
			GROUP BY assigned_agent
		),
		premium_stats AS (
			SELECT lad.assigned_agent AS agentId,
				   SUM(mmd.net_premium) AS NetPremiumCollected
			FROM mmi_lead_archive_details lad
			JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
			JOIN agent_list al ON al.agentId = lad.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE lad.lead_status = 'Won'
			  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (lad.created_date BETWEEN v_startDate AND v_endDate
							OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
			  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(lad.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(lad.vehicle_class),v_segment))
			GROUP BY lad.assigned_agent
		),
		addon_sales AS (
			SELECT ld.assigned_agent AS agentId,
				   COUNT(pad.id) AS AddonSales
			FROM mmi_poladdon_data pad
			JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
			JOIN agent_list al ON al.agentId = ld.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE 1=1
			  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL 	OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (ld.created_date BETWEEN v_startDate AND v_endDate
							OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(ld.renewal_category, v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			 AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class),v_segment))
			GROUP BY ld.assigned_agent
		),
		  pre_due_renewals AS (
		SELECT 
			lad.assigned_agent AS agentId,
			COUNT(*) AS PreDueRenewals
		FROM mmi_lead_archive_details lad
		JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
		JOIN agent_list al ON al.agentId = lad.assigned_agent
		LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
		LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
		WHERE lad.lead_status = 'Won' 
		  AND lad.converted_flag = 'CRM Renewal'
		  AND DATEDIFF(lad.created_date, mmd.policy_expiry_date) > 10
		  AND lad.dealer_code = v_dealerId
		  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (lad.created_date BETWEEN v_startDate AND v_endDate
							OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
			  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(lad.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(lad.vehicle_class),v_segment))
		GROUP BY lad.assigned_agent
	),

		group_product AS (
			SELECT assigned_agent AS agentId,
				   COUNT(DISTINCT lead_id) AS RetainedCustomers
			FROM mmi_lead_details ld
			JOIN agent_list al ON al.agentId = ld.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE group_product IS NOT NULL
			  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (ld.created_date BETWEEN v_startDate AND v_endDate
							OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
			  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(ld.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(ld.vehicle_class),v_segment))
			GROUP BY assigned_agent
		),
		conversion_data AS (
			SELECT assigned_agent AS agentId,
				   COUNT(DISTINCT CASE WHEN lead_status = 'Won' AND converted_flag = 'CRM Renewal' THEN lead_id END) AS WonLeads
			FROM mmi_lead_archive_details lad
			JOIN agent_list al ON al.agentId = lad.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE 1=1
			  AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (lad.created_date BETWEEN v_startDate AND v_endDate
							OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
			  AND (v_renewal_category IS NULL OR v_renewal_category='' OR FIND_IN_SET(TRIM(lad.renewal_category),v_renewal_category))
			  AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
			  AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(lad.vehicle_class),v_segment))
			GROUP BY assigned_agent
		),
        breach_stats AS (
				SELECT 
					mld.assigned_agent,
					COUNT(DISTINCT lb.lead_id) AS breachedLeads
				FROM mmi_lead_breached lb
				JOIN mmi_lead_details mld 
					ON mld.lead_id = lb.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = mld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE -- mld.lead_status = 'Won'
					-- AND 
					(v_dealerId IS NULL OR v_dealerId='' OR FIND_IN_SET(TRIM(mld.dealer_code),v_dealerId))

					AND (((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
					OR
					(v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
					 AND (mld.created_date BETWEEN v_startDate AND v_endDate
						  OR mld.modified_date BETWEEN v_startDate AND v_endDate)))

					AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
					AND (v_renewal_category IS NULL OR v_renewal_category='' 
						 OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
					AND (v_dealerLocCode IS NULL OR v_dealerLocCode='' 
						 OR FIND_IN_SET(dloc.loc_code, REPLACE(v_dealerLocCode,' ',''))) 	
				GROUP BY mld.assigned_agent
			),
		final_data AS (
			SELECT
				ad.agentId,
				ad.agentName,
				IFNULL(la.LeadsAssigned,0) AS LeadsAssigned,
				IFNULL(lc.LeadsContacted,0) AS LeadsContacted,
				0 AS EligibleLeads,
				IFNULL(cp.policiesConverted,0) AS PoliciesConverted,
				IFNULL(ps.NetPremiumCollected,0) AS NetPremiumCollected,
				0 AS AvgHandlingTime,
				IFNULL(fd.FollowUpsDoneOnTime,0) AS FollowUpsDoneOnTime,
				IFNULL(fd.TotalFollowUpsScheduled,0) AS TotalFollowUpsScheduled,
				IFNULL(qs.QuoteShared,0) AS QuoteShared,
				0 AS CorrectDispositions,
				-- IFNULL(tf.TriggerFlag,0) AS TriggerFlag,
				IFNULL(scc.ConversionsWithinTwoCalls,0) AS ConversionsWithinTwoCalls,
				IFNULL(tp.TargetPremium,0) AS TargetPremium,
				5 AS TriggerFlag,
				-- SUM(IFNULL(mtp.target_value,0)) AS TargetPremium,
				IFNULL(nop.NetODPremium,0) AS NetODPremium,
				IFNULL(ads.AddonSales,0) AS AddonSales,
				IFNULL(pdr.PreDueRenewals,0) AS PreDueRenewals,
				-- IFNULL(gp.RetainedCustomers,0) AS RetainedCustomers,
				0 AS RetainedCustomers,
				IFNULL(ROUND((IFNULL(cd.WonLeads,0) / NULLIF(IFNULL(lc.LeadsContacted,0),0)) * 100,2),0) AS ConversionRate,
				IFNULL(ROUND((IFNULL(cp.policiesConverted,0) / NULLIF(IFNULL(la.LeadsAssigned,0),0)) * 100,2),0) AS RetentionRate,
                GREATEST(0,LEAST(100,100 - ROUND(NULLIF(bs.breachedLeads, 0) /NULLIF(IFNULL(la.LeadsAssigned,0), 0) * 100,2))) AS FollowUpEfficiency
			FROM agent_details ad
			LEFT JOIN leads_assigned la ON la.assigned_agent = ad.agentId
			LEFT JOIN leads_contacted lc ON lc.assigned_agent = ad.agentId
			LEFT JOIN converted_policies cp ON cp.assigned_agent = ad.agentId
			LEFT JOIN premium_stats ps ON ps.agentId = ad.agentId
			LEFT JOIN followup_data fd ON fd.agentId = ad.agentId
			LEFT JOIN quote_shared qs ON qs.agentId = ad.agentId
			LEFT JOIN trigger_flag tf ON tf.agentId = ad.agentId
			LEFT JOIN shortest_call_conversion scc ON scc.agentId = ad.agentId
			LEFT JOIN conversion_data cd ON cd.agentId = ad.agentId
			LEFT JOIN target_premium tp ON tp.agentId = ad.agentId
			LEFT JOIN net_od_premium nop ON nop.agentId = ad.agentId
			LEFT JOIN addon_sales ads ON ads.agentId = ad.agentId
			LEFT JOIN pre_due_renewals pdr ON pdr.agentId = ad.agentId
			LEFT JOIN group_product gp ON gp.agentId = ad.agentId
            LEFT JOIN breach_stats bs ON bs.assigned_agent = ad.agentId
		),
		score_data AS (
			SELECT
				agentId,
				agentName AS AgentName,
				LeadsAssigned,
				LeadsContacted,
				EligibleLeads,
				PoliciesConverted,
				NetPremiumCollected,
				AvgHandlingTime,
				QuoteShared,
				CorrectDispositions,
				TriggerFlag,
				ConversionsWithinTwoCalls,
				ConversionRate,
				RetentionRate,
				ROUND((LeadsContacted / NULLIF(LeadsAssigned,0)) * 100,2) AS ContactRate,
				-- ROUND(IFNULL(FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0),0) * 100,2) AS FollowUpEfficiency,
				FollowUpEfficiency,
                ROUND((QuoteShared / NULLIF(LeadsContacted,0)) * 100,2) AS QuoteRate,
				ROUND((PoliciesConverted / NULLIF(LeadsContacted,0)) * 100,2) AS PolicyConversionRate,
				ROUND((PoliciesConverted / NULLIF(LeadsAssigned,0)) * 100,2) AS OverallConversion,
				ROUND((ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0)) * 100,2) AS ShortestCallConversionRate,
				/*ROUND(((LeadsAssigned / NULLIF(AVG(LeadsAssigned) OVER (),0)) * 100 * 10 / 100)
					+ (IFNULL((LeadsContacted / NULLIF(LeadsAssigned,0)),0) * 100 * 10 / 100)
					+ (IFNULL((FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0)),0) * 100 * 10 / 100)
					+ (IFNULL((QuoteShared / NULLIF(LeadsContacted,0)),0) * 100 * 10 / 100)
					+ (IFNULL((PoliciesConverted / NULLIF(LeadsContacted,0)),0) * 100 * 25 / 100)
					+ (IFNULL((PoliciesConverted / NULLIF(LeadsAssigned,0)),0) * 100 * 15 / 100)
					+ (IFNULL((ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0)),0) * 100 * 5 / 100)
				,2) AS PerformanceScore,*/
                
                ROUND((IFNULL(LeadsAssigned / NULLIF(AVG(LeadsAssigned) OVER (),0), 0) * 100 / 10)
                    + (IFNULL(LeadsContacted / NULLIF(LeadsAssigned,0), 0) * 10)
                    + (IFNULL((FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0)),0) * 10)
                    + (IFNULL(QuoteShared / NULLIF(LeadsContacted,0), 0) * 10)
                    + (IFNULL(PoliciesConverted / NULLIF(LeadsContacted,0), 0) * 25)
                    + (IFNULL(PoliciesConverted / NULLIF(LeadsAssigned,0), 0) * 15)
                    + (IFNULL(ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0), 0) * 100 * 5 / 100 )
                    + TriggerFlag
                ,2) AS PerformanceScore,
                
				/*ROUND(
					IFNULL(GREATEST(NetPremiumCollected - TargetPremium,0) / 1000 * 10,0)
					+ IFNULL(NetODPremium / 1000,0)
					+ IFNULL(AddonSales * 5,0)
					+ IFNULL(PreDueRenewals * 10,0)
				,2) AS DynamicPerformanceScore*/
                0 AS DynamicPerformanceScore
			FROM final_data
		)
		SELECT
			agentId,
			AgentName AS agentName,
			ROUND(LeadsAssigned,2) AS leadsAssigned,
			ROUND(LeadsContacted,2) AS leadsContacted,
			ROUND(PoliciesConverted,2) AS policiesConverted,
			ROUND(NetPremiumCollected,2) AS netPremiumCollected,
			ROUND(FollowUpEfficiency,2) AS followUpEfficiency,
			CONCAT(ROUND(ConversionRate,2)) AS conversionRate,
			CONCAT(ROUND(RetentionRate,2)) AS retentionRate,
			ROUND(PerformanceScore,2) AS performanceScore,
			ROUND(DynamicPerformanceScore,2) AS dynamicPerformanceScore,
			ROUND(PerformanceScore + DynamicPerformanceScore,2) AS overallScore,
			RANK() OVER (ORDER BY (PerformanceScore + DynamicPerformanceScore) DESC) AS `rank`
		FROM score_data
		LIMIT limitVal OFFSET calculated;

    -- count for dealer role (filtered)
		SELECT 
			COUNT(DISTINCT ld.assigned_agent) AS agentCount
		FROM
			mmi_lead_details ld
				LEFT JOIN
			mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
				LEFT JOIN
			mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
				INNER JOIN
			mmi_mast_user_registration_detail mud ON mud.id = ld.assigned_agent
		WHERE
		ld.dealer_code = v_dealerId
        AND ld.assigned_agent IS NOT NULL
        AND (v_renewal_category IS NULL
        OR v_renewal_category = ''
        OR FIND_IN_SET(TRIM(ld.renewal_category),
            v_renewal_category))
        AND (v_dealerLocCode IS NULL
        OR v_dealerLocCode = ''
        OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
        AND (v_segment IS NULL OR v_segment = ''
        OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
        AND ((v_startDate IS NULL OR v_startDate = ''
        OR v_endDate IS NULL
        OR v_endDate = '')
        OR (v_startDate IS NOT NULL
        AND v_startDate != ''
        AND v_endDate IS NOT NULL
        AND v_endDate != ''
        AND (ld.created_date BETWEEN v_startDate AND v_endDate
        OR ld.modified_date BETWEEN v_startDate AND v_endDate)));

    SET SP_STATUS = '200';
    SET MESSAGE = 'PerformanceBoard filter details fetched';



            ELSEIF v_type = 'PerformanceBoard' THEN
            
        -- UNFILTERED DEALER 
        WITH
        lead_assigned_detail AS (
            SELECT
                mld.assigned_agent AS agentId,
                COUNT(DISTINCT mld.lead_id) AS leadsAssigned
            FROM mmi_lead_details mld
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE mld.assigned_agent IS NOT NULL
              AND mld.dealer_code = v_dealerId
            GROUP BY mld.assigned_agent
        ),
        lead_assigned_archive AS (
            SELECT
                mld.assigned_agent AS agentId,
                COUNT(DISTINCT mld.lead_id) AS leadsAssigned
            FROM mmi_lead_archive_details mld
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE mld.assigned_agent IS NOT NULL
              AND mld.dealer_code = v_dealerId
            GROUP BY mld.assigned_agent
        ),
        lead_contacted_detail AS (
            SELECT
                mld.assigned_agent AS agentId,
                COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
                ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
            FROM mmi_call_disposition_history cdh
            JOIN mmi_lead_details mld ON mld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE mld.dealer_code = v_dealerId
            GROUP BY mld.assigned_agent
        ),
        lead_contacted_archive AS (
            SELECT
                mld.assigned_agent AS agentId,
                COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
                ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
            FROM mmi_call_disposition_history cdh
            JOIN mmi_lead_archive_details mld ON mld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE mld.dealer_code = v_dealerId
            GROUP BY mld.assigned_agent
        ),
        agent_lead_combined AS (
            SELECT
                COALESCE(ld.agentId, la.agentId) AS agentId,
                COALESCE(ld.leadsAssigned, 0) + COALESCE(la.leadsAssigned, 0) AS leadsAssigned_total,
                COALESCE(cd.leadsContacted, 0) + COALESCE(ca.leadsContacted, 0) AS leadsContacted_total
            FROM lead_assigned_detail ld
            LEFT JOIN lead_assigned_archive la ON ld.agentId = la.agentId
            LEFT JOIN lead_contacted_detail cd ON COALESCE(ld.agentId, la.agentId) = cd.agentId
            LEFT JOIN lead_contacted_archive ca ON COALESCE(ld.agentId, la.agentId, cd.agentId) = ca.agentId
        ),
        agent_list AS (SELECT DISTINCT agentId FROM agent_lead_combined),
        agent_details AS (SELECT al.agentId, CONCAT(mud.first_name, ' ', mud.last_name) AS agentName
            FROM agent_list al
            JOIN mmi_mast_user_registration_detail mud ON mud.id = al.agentId
        ),
        leads_assigned AS (
            SELECT agentId, leadsAssigned_total AS LeadsAssigned FROM agent_lead_combined
        ),
        leads_contacted AS (
            SELECT agentId, leadsContacted_total AS LeadsContacted FROM agent_lead_combined
        ),
        /*followup_data AS (
            SELECT cdh.agent_code AS agentId,
                COUNT(CASE WHEN next_call_datetime IS NOT NULL THEN 1 END) AS TotalFollowUpsScheduled,
                COUNT(CASE WHEN next_call_datetime IS NOT NULL
                    AND call_date <= STR_TO_DATE(next_call_datetime,'%Y-%m-%d %H:%i:%s') THEN 1 END) AS FollowUpsDoneOnTime
            FROM mmi_call_disposition_history cdh
            JOIN agent_list al ON al.agentId = cdh.agent_code
            JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE ld.dealer_code = v_dealerId
            GROUP BY cdh.agent_code
        ),*/
        followup_data AS (
				WITH latest_calls AS (
					SELECT 
						cdh.*,
						ROW_NUMBER() OVER (
							PARTITION BY cdh.lead_id 
							ORDER BY cdh.created_date DESC
						) AS rn
					FROM mmi_call_disposition_history cdh
				)
				SELECT 
					lc.agent_code AS agentId,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL THEN 1 
					END) AS TotalFollowUpsScheduled,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL
						AND lc.call_date <= STR_TO_DATE(lc.next_call_datetime,'%Y-%m-%d %H:%i:%s') 
						THEN 1 
					END) AS FollowUpsDoneOnTime

				FROM latest_calls lc
				JOIN agent_list al 
					ON al.agentId = lc.agent_code
				JOIN mmi_lead_details ld 
					ON ld.lead_id = lc.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = ld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE lc.rn = 1 AND ld.dealer_code = v_dealerId
				GROUP BY lc.agent_code
			),
        quote_shared AS (
            SELECT cdh.agent_code AS agentId,
                   COUNT(DISTINCT cdh.lead_id) AS QuoteShared
            FROM mmi_call_disposition_history cdh
            LEFT JOIN mmi_agent_disposition_field_response adf ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
            JOIN agent_list al ON al.agentId = cdh.agent_code
			JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE adf.field_value = 'Shared Quotes'
              AND ld.dealer_code = v_dealerId
            GROUP BY cdh.agent_code
        ),
        eligible_leads AS (
            SELECT ld.assigned_agent AS agentId,
                   COUNT(DISTINCT ld.lead_id) AS eligibleLeads
            FROM mmi_lead_details ld
            JOIN agent_list al ON al.agentId = ld.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE lead_type IN ('Hot','Warm')
              AND ld.dealer_code = v_dealerId
            GROUP BY ld.assigned_agent
        ),
        converted_policies AS (
            SELECT lad.assigned_agent AS agentId,
                   COUNT(DISTINCT policy_no) AS policiesConverted
            FROM mmi_lead_archive_details lad
            JOIN agent_list al ON al.agentId = lad.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
          WHERE lead_status = 'Won' AND converted_flag = 'CRM Renewal'
              AND lad.dealer_code = v_dealerId
            GROUP BY lad.assigned_agent
        ),
        shortest_call_conversion AS (
            SELECT cdh.agent_code AS agentId,
                   COUNT(DISTINCT CASE
                       WHEN call_rank <= 2 AND lad.lead_status = 'Won' THEN cdh.lead_id
                   END) AS ConversionsWithinTwoCalls
            FROM (
                SELECT lead_id, agent_code, call_date,
                       ROW_NUMBER() OVER (PARTITION BY lead_id ORDER BY call_date) AS call_rank
                FROM mmi_call_disposition_history
            ) cdh
            LEFT JOIN mmi_lead_archive_details lad ON lad.lead_id = cdh.lead_id
            JOIN agent_list al ON al.agentId = cdh.agent_code
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE cdh.agent_code IN (SELECT agentId FROM agent_list)
              AND lad.dealer_code = v_dealerId
            GROUP BY cdh.agent_code
        ),
        disposition_quality AS (
            SELECT agent_code AS agentId,
                   COUNT(DISTINCT lead_id) AS CorrectDispositions
            FROM mmi_call_disposition_history
            WHERE dealer_disposition_id IS NOT NULL
              AND agent_code IN (SELECT agentId FROM agent_list)
            GROUP BY agent_code
        ),
        trigger_flag AS (
            SELECT agent_code AS agentId,
                   0 AS TriggerFlag
            FROM mmi_call_disposition_history
            WHERE agent_code IN (SELECT agentId FROM agent_list)
            GROUP BY agent_code
        ),
        avg_handling_time AS (
            SELECT agent_code AS agentId,
                   0 AS AvgHandlingTime
            FROM mmi_call_disposition_history
            WHERE agent_code IN (SELECT agentId FROM agent_list)
            GROUP BY agent_code
        ),
        target_premium AS (
            SELECT agentId, SUM(IFNULL(mtp.target_value,0)) AS TargetPremium FROM agent_list al
			left join mmi_target_planning mtp on mtp.team_member = al.agentId
			GROUP BY agentId
        ),
        net_od_premium AS (
            SELECT assigned_agent AS agentId,
                   SUM(CAST(IFNULL(net_od_premium_amount,0) AS DECIMAL(12,2)) +
                       CAST(IFNULL(addon_premium_amount,0) AS DECIMAL(12,2))) AS NetODPremium
            FROM mmi_lead_archive_details ld
            JOIN agent_list al ON al.agentId = ld.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE ld.dealer_code = v_dealerId
            GROUP BY assigned_agent
        ),
        premium_stats AS (
            SELECT lad.assigned_agent AS agentId,
                   SUM(mmd.net_premium) AS NetPremiumCollected
            FROM mmi_lead_archive_details lad
            JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
            JOIN agent_list al ON al.agentId = lad.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE lad.lead_status = 'Won'
              AND lad.dealer_code = v_dealerId
            GROUP BY lad.assigned_agent
        ),
        addon_sales AS (
            SELECT ld.assigned_agent AS agentId,
                   COUNT(pad.id) AS AddonSales
            FROM mmi_poladdon_data pad
            JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
            JOIN agent_list al ON al.agentId = ld.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE ld.dealer_code = v_dealerId
            GROUP BY ld.assigned_agent
        ),
       pre_due_renewals AS (
			SELECT 
				lad.assigned_agent AS agentId,
				COUNT(*) AS PreDueRenewals
			FROM mmi_lead_archive_details lad
			JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
			JOIN agent_list al ON al.agentId = lad.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE lad.lead_status = 'Won' 
			  AND lad.converted_flag = 'CRM Renewal'
			  AND DATEDIFF(lad.created_date, mmd.policy_expiry_date) > 10
			  AND lad.dealer_code = v_dealerId
			GROUP BY lad.assigned_agent
		),
        group_product AS (
            SELECT assigned_agent AS agentId,
                   COUNT(DISTINCT lead_id) AS RetainedCustomers
            FROM mmi_lead_details ld
            JOIN agent_list al ON al.agentId = ld.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
           WHERE group_product IS NOT NULL
              AND ld.dealer_code = v_dealerId
            GROUP BY assigned_agent
        ),
        conversion_data AS (
            SELECT assigned_agent AS agentId,
                   COUNT(DISTINCT CASE WHEN lead_status = 'Won' AND converted_flag = 'CRM Renewal' THEN lead_id END) AS WonLeads
            FROM mmi_lead_archive_details lad
            JOIN agent_list al ON al.agentId = lad.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE lad.dealer_code = v_dealerId
            GROUP BY assigned_agent
        ),
        breach_stats AS (
				SELECT 
					mld.assigned_agent,
					COUNT(DISTINCT lb.lead_id) AS breachedLeads
				FROM mmi_lead_breached lb
				JOIN mmi_lead_details mld 
					ON mld.lead_id = lb.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = mld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE mld.dealer_code = v_dealerId
				GROUP BY mld.assigned_agent
			),
        final_data AS (
            SELECT
                ad.agentId,
                ad.agentName,
                IFNULL(la.LeadsAssigned,0) AS LeadsAssigned,
                IFNULL(lc.LeadsContacted,0) AS LeadsContacted,
                0 AS EligibleLeads,
                IFNULL(cp.policiesConverted,0) AS PoliciesConverted,
                IFNULL(ps.NetPremiumCollected,0) AS NetPremiumCollected,
                0 AS AvgHandlingTime,
                IFNULL(fd.FollowUpsDoneOnTime,0) AS FollowUpsDoneOnTime,
                IFNULL(fd.TotalFollowUpsScheduled,0) AS TotalFollowUpsScheduled,
                IFNULL(qs.QuoteShared,0) AS QuoteShared,
                0 AS CorrectDispositions,
                -- IFNULL(tf.TriggerFlag,0) AS TriggerFlag,
                5 AS TriggerFlag,
                IFNULL(scc.ConversionsWithinTwoCalls,0) AS ConversionsWithinTwoCalls,
                IFNULL(tp.TargetPremium,0) AS TargetPremium,
                IFNULL(nop.NetODPremium,0) AS NetODPremium,
                IFNULL(ads.AddonSales,0) AS AddonSales,
                IFNULL(pdr.PreDueRenewals,0) AS PreDueRenewals,
                -- IFNULL(gp.RetainedCustomers,0) AS RetainedCustomers,
                0 AS RetainedCustomers,
                IFNULL(ROUND((IFNULL(cd.WonLeads,0) / NULLIF(IFNULL(lc.LeadsContacted,0),0)) * 100,2),0) AS ConversionRate,
                IFNULL(ROUND((IFNULL(cp.policiesConverted,0) / NULLIF(IFNULL(la.LeadsAssigned,0),0)) * 100,2),0) AS RetentionRate,
                GREATEST(0,LEAST(100,100 - ROUND(NULLIF(bs.breachedLeads, 0) /NULLIF(IFNULL(la.LeadsAssigned,0), 0) * 100,2))) AS FollowUpEfficiency
            FROM agent_details ad
            LEFT JOIN leads_assigned la ON la.agentId = ad.agentId
            LEFT JOIN leads_contacted lc ON lc.agentId = ad.agentId
            LEFT JOIN converted_policies cp ON cp.agentId = ad.agentId
            LEFT JOIN premium_stats ps ON ps.agentId = ad.agentId
            LEFT JOIN followup_data fd ON fd.agentId = ad.agentId
            LEFT JOIN quote_shared qs ON qs.agentId = ad.agentId
            LEFT JOIN trigger_flag tf ON tf.agentId = ad.agentId
            LEFT JOIN shortest_call_conversion scc ON scc.agentId = ad.agentId
            LEFT JOIN conversion_data cd ON cd.agentId = ad.agentId
            LEFT JOIN target_premium tp ON tp.agentId = ad.agentId
            LEFT JOIN net_od_premium nop ON nop.agentId = ad.agentId
            LEFT JOIN addon_sales ads ON ads.agentId = ad.agentId
            LEFT JOIN pre_due_renewals pdr ON pdr.agentId = ad.agentId
            LEFT JOIN group_product gp ON gp.agentId = ad.agentId
            LEFT JOIN breach_stats bs ON bs.assigned_agent = ad.agentId
        ),
        score_data AS (
            SELECT
                agentId,
                agentName AS AgentName,
                LeadsAssigned,
                LeadsContacted,
                EligibleLeads,
                PoliciesConverted,
                NetPremiumCollected,
                AvgHandlingTime,
                QuoteShared,
                CorrectDispositions,
                TriggerFlag,
                ConversionsWithinTwoCalls,
                ConversionRate,
                RetentionRate,
                ROUND((LeadsContacted / NULLIF(LeadsAssigned,0)) * 100,2) AS ContactRate,
                -- ROUND(IFNULL(FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0),0) * 100,2) AS FollowUpEfficiency,
                FollowUpEfficiency,
                ROUND((QuoteShared / NULLIF(LeadsContacted,0)) * 100,2) AS QuoteRate,
                ROUND((PoliciesConverted / NULLIF(LeadsContacted,0)) * 100,2) AS PolicyConversionRate,
                ROUND((PoliciesConverted / NULLIF(LeadsAssigned,0)) * 100,2) AS OverallConversion,
                ROUND((ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0)) * 100,2) AS ShortestCallConversionRate,
                /*ROUND(((LeadsAssigned / NULLIF(AVG(LeadsAssigned) OVER (),0)) * 100 * 10 / 100)
                    + (IFNULL((LeadsContacted / NULLIF(LeadsAssigned,0)),0) * 100 * 10 / 100)
                    + (IFNULL((FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0)),0) * 100 * 10 / 100)
                    + (IFNULL((QuoteShared / NULLIF(LeadsContacted,0)),0) * 100 * 10 / 100)
                    + (IFNULL((PoliciesConverted / NULLIF(LeadsContacted,0)),0) * 100 * 25 / 100)
                    + (IFNULL((PoliciesConverted / NULLIF(LeadsAssigned,0)),0) * 100 * 15 / 100)
                    + (IFNULL((ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0)),0) * 100 * 5 / 100)
                ,2) AS PerformanceScore,*/
                
                ROUND((IFNULL(LeadsAssigned / NULLIF(AVG(LeadsAssigned) OVER (),0), 0) * 100 / 10)
                    + (IFNULL(LeadsContacted / NULLIF(LeadsAssigned,0), 0) * 10)
                    + (IFNULL((FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0)),0) * 10)
                    + (IFNULL(QuoteShared / NULLIF(LeadsContacted,0), 0) * 10)
                    + (IFNULL(PoliciesConverted / NULLIF(LeadsContacted,0), 0) * 25)
                    + (IFNULL(PoliciesConverted / NULLIF(LeadsAssigned,0), 0) * 15)
                    + (IFNULL(ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0), 0) * 100 * 5 / 100 )
                    + TriggerFlag
                ,2) AS PerformanceScore,
                
                /*ROUND(
                    IFNULL(GREATEST(NetPremiumCollected - TargetPremium,0) / 1000 * 10,0)
                    + IFNULL(NetODPremium / 1000,0)
                    + IFNULL(AddonSales * 5,0)
                    + IFNULL(PreDueRenewals * 10,0)
                ,2) AS DynamicPerformanceScore*/
                0 AS DynamicPerformanceScore
            FROM final_data
        )
        SELECT
            agentId,
            AgentName AS agentName,
            ROUND(LeadsAssigned,2) AS leadsAssigned,
            ROUND(LeadsContacted,2) AS leadsContacted,
            ROUND(PoliciesConverted,2) AS policiesConverted,
            ROUND(NetPremiumCollected,2) AS netPremiumCollected,
            ROUND(FollowUpEfficiency,2) AS followUpEfficiency,
            CONCAT(ROUND(ConversionRate,2)) AS conversionRate,
            CONCAT(ROUND(RetentionRate,2)) AS retentionRate,
            ROUND(PerformanceScore,2) AS performanceScore,
            ROUND(DynamicPerformanceScore,2) AS dynamicPerformanceScore,
            ROUND(PerformanceScore + DynamicPerformanceScore,2) AS overallScore,
            RANK() OVER (ORDER BY (PerformanceScore + DynamicPerformanceScore) DESC) AS `rank`
        FROM score_data
        LIMIT limitVal OFFSET calculated;


        -- count for dealer role (unfiltered)
			SELECT 
    COUNT(DISTINCT ld.assigned_agent) AS agentCount
	FROM
		mmi_lead_details ld
			LEFT JOIN
		mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN
		mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			INNER JOIN
		mmi_mast_user_registration_detail mud ON mud.id = ld.assigned_agent
	WHERE
		ld.dealer_code = v_dealerId
			AND ld.assigned_agent IS NOT NULL;


				SET SP_STATUS = '200';
				SET MESSAGE = 'Agents Performance Dashboard Fetched Successfully';
			END IF; -- end v_type for dealer
            
            
            
	IF v_type = 'dealerExcel' THEN
		-- UNFILTERED EXPORT per dealer max
		WITH
		lead_assigned_detail AS (
			SELECT
				mld.assigned_agent AS agentId,
				COUNT(DISTINCT mld.lead_id) AS leadsAssigned
			FROM mmi_lead_details mld
LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE mld.assigned_agent IS NOT NULL
              AND mld.dealer_code = v_dealerId
            GROUP BY mld.assigned_agent
        ),
        lead_assigned_archive AS (
            SELECT
                mld.assigned_agent AS agentId,
                COUNT(DISTINCT mld.lead_id) AS leadsAssigned
            FROM mmi_lead_archive_details mld
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE mld.assigned_agent IS NOT NULL
              AND mld.dealer_code = v_dealerId
            GROUP BY mld.assigned_agent
        ),
        lead_contacted_detail AS (
            SELECT
                mld.assigned_agent AS agentId,
                COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
                ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
            FROM mmi_call_disposition_history cdh
            JOIN mmi_lead_details mld ON mld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE mld.dealer_code = v_dealerId
            GROUP BY mld.assigned_agent
        ),
        lead_contacted_archive AS (
            SELECT
                mld.assigned_agent AS agentId,
                COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
                ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
            FROM mmi_call_disposition_history cdh
            JOIN mmi_lead_archive_details mld ON mld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE mld.dealer_code = v_dealerId
            GROUP BY mld.assigned_agent
        ),
        agent_lead_combined AS (
            SELECT
                COALESCE(ld.agentId, la.agentId) AS agentId,
                COALESCE(ld.leadsAssigned, 0) + COALESCE(la.leadsAssigned, 0) AS leadsAssigned_total,
                COALESCE(cd.leadsContacted, 0) + COALESCE(ca.leadsContacted, 0) AS leadsContacted_total
            FROM lead_assigned_detail ld
            LEFT JOIN lead_assigned_archive la ON ld.agentId = la.agentId
            LEFT JOIN lead_contacted_detail cd ON COALESCE(ld.agentId, la.agentId) = cd.agentId
            LEFT JOIN lead_contacted_archive ca ON COALESCE(ld.agentId, la.agentId, cd.agentId) = ca.agentId
        ),
        agent_list AS (SELECT DISTINCT agentId FROM agent_lead_combined),
        agent_details AS (SELECT al.agentId, CONCAT(mud.first_name, ' ', mud.last_name) AS agentName
            FROM agent_list al
            JOIN mmi_mast_user_registration_detail mud ON mud.id = al.agentId
        ),
        leads_assigned AS (
            SELECT agentId, leadsAssigned_total AS LeadsAssigned FROM agent_lead_combined
        ),
        leads_contacted AS (
            SELECT agentId, leadsContacted_total AS LeadsContacted FROM agent_lead_combined
        ),
        /*followup_data AS (
            SELECT cdh.agent_code AS agentId,
                COUNT(CASE WHEN next_call_datetime IS NOT NULL THEN 1 END) AS TotalFollowUpsScheduled,
                COUNT(CASE WHEN next_call_datetime IS NOT NULL
                    AND call_date <= STR_TO_DATE(next_call_datetime,'%Y-%m-%d %H:%i:%s') THEN 1 END) AS FollowUpsDoneOnTime
            FROM mmi_call_disposition_history cdh
            JOIN agent_list al ON al.agentId = cdh.agent_code
            JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE ld.dealer_code = v_dealerId
            GROUP BY cdh.agent_code
        ),*/
        followup_data AS (
				WITH latest_calls AS (
					SELECT 
						cdh.*,
						ROW_NUMBER() OVER (
							PARTITION BY cdh.lead_id 
							ORDER BY cdh.created_date DESC
						) AS rn
					FROM mmi_call_disposition_history cdh
				)
				SELECT 
					lc.agent_code AS agentId,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL THEN 1 
					END) AS TotalFollowUpsScheduled,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL
						AND lc.call_date <= STR_TO_DATE(lc.next_call_datetime,'%Y-%m-%d %H:%i:%s') 
						THEN 1 
					END) AS FollowUpsDoneOnTime

				FROM latest_calls lc
				JOIN agent_list al 
					ON al.agentId = lc.agent_code
				JOIN mmi_lead_details ld 
					ON ld.lead_id = lc.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = ld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE lc.rn = 1 AND ld.dealer_code = v_dealerId
				GROUP BY lc.agent_code
			),
        quote_shared AS (
            SELECT cdh.agent_code AS agentId,
                   COUNT(DISTINCT cdh.lead_id) AS QuoteShared
            FROM mmi_call_disposition_history cdh
            LEFT JOIN mmi_agent_disposition_field_response adf ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
            JOIN agent_list al ON al.agentId = cdh.agent_code
			JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE adf.field_value = 'Shared Quotes'
              AND ld.dealer_code = v_dealerId
            GROUP BY cdh.agent_code
        ),
        eligible_leads AS (
            SELECT ld.assigned_agent AS agentId,
                   COUNT(DISTINCT ld.lead_id) AS eligibleLeads
            FROM mmi_lead_details ld
            JOIN agent_list al ON al.agentId = ld.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE lead_type IN ('Hot','Warm')
              AND ld.dealer_code = v_dealerId
            GROUP BY ld.assigned_agent
        ),
        converted_policies AS (
            SELECT lad.assigned_agent AS agentId,
                   COUNT(DISTINCT policy_no) AS policiesConverted
            FROM mmi_lead_archive_details lad
            JOIN agent_list al ON al.agentId = lad.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
          WHERE lead_status = 'Won' AND converted_flag = 'CRM Renewal'
              AND lad.dealer_code = v_dealerId
            GROUP BY lad.assigned_agent
        ),
        shortest_call_conversion AS (
            SELECT cdh.agent_code AS agentId,
                   COUNT(DISTINCT CASE
                       WHEN call_rank <= 2 AND lad.lead_status = 'Won' THEN cdh.lead_id
                   END) AS ConversionsWithinTwoCalls
            FROM (
                SELECT lead_id, agent_code, call_date,
                       ROW_NUMBER() OVER (PARTITION BY lead_id ORDER BY call_date) AS call_rank
                FROM mmi_call_disposition_history
            ) cdh
            LEFT JOIN mmi_lead_archive_details lad ON lad.lead_id = cdh.lead_id
            JOIN agent_list al ON al.agentId = cdh.agent_code
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE cdh.agent_code IN (SELECT agentId FROM agent_list)
              AND lad.dealer_code = v_dealerId
            GROUP BY cdh.agent_code
        ),
        disposition_quality AS (
            SELECT agent_code AS agentId,
                   COUNT(DISTINCT lead_id) AS CorrectDispositions
            FROM mmi_call_disposition_history
            WHERE dealer_disposition_id IS NOT NULL
              AND agent_code IN (SELECT agentId FROM agent_list)
            GROUP BY agent_code
        ),
        trigger_flag AS (
            SELECT agent_code AS agentId,
                   0 AS TriggerFlag
            FROM mmi_call_disposition_history
            WHERE agent_code IN (SELECT agentId FROM agent_list)
            GROUP BY agent_code
        ),
        avg_handling_time AS (
            SELECT agent_code AS agentId,
                   0 AS AvgHandlingTime
            FROM mmi_call_disposition_history
            WHERE agent_code IN (SELECT agentId FROM agent_list)
            GROUP BY agent_code
        ),
        target_premium AS (
            SELECT agentId, SUM(IFNULL(mtp.target_value,0)) AS TargetPremium FROM agent_list al
			left join mmi_target_planning mtp on mtp.team_member = al.agentId
			GROUP BY agentId
        ),
        net_od_premium AS (
            SELECT assigned_agent AS agentId,
                   SUM(CAST(IFNULL(net_od_premium_amount,0) AS DECIMAL(12,2)) +
                       CAST(IFNULL(addon_premium_amount,0) AS DECIMAL(12,2))) AS NetODPremium
            FROM mmi_lead_archive_details ld
            JOIN agent_list al ON al.agentId = ld.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE ld.dealer_code = v_dealerId
            GROUP BY assigned_agent
        ),
        premium_stats AS (
            SELECT lad.assigned_agent AS agentId,
                   SUM(mmd.net_premium) AS NetPremiumCollected
            FROM mmi_lead_archive_details lad
            JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
            JOIN agent_list al ON al.agentId = lad.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE lad.lead_status = 'Won'
              AND lad.dealer_code = v_dealerId
            GROUP BY lad.assigned_agent
        ),
        addon_sales AS (
            SELECT ld.assigned_agent AS agentId,
                   COUNT(pad.id) AS AddonSales
            FROM mmi_poladdon_data pad
            JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
            JOIN agent_list al ON al.agentId = ld.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE ld.dealer_code = v_dealerId
            GROUP BY ld.assigned_agent
        ),
       pre_due_renewals AS (
			SELECT 
				lad.assigned_agent AS agentId,
				COUNT(*) AS PreDueRenewals
			FROM mmi_lead_archive_details lad
			JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
			JOIN agent_list al ON al.agentId = lad.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE lad.lead_status = 'Won' 
			  AND lad.converted_flag = 'CRM Renewal'
			  AND DATEDIFF(lad.created_date, mmd.policy_expiry_date) > 10
			  AND lad.dealer_code = v_dealerId
			GROUP BY lad.assigned_agent
		),
        group_product AS (
            SELECT assigned_agent AS agentId,
                   COUNT(DISTINCT lead_id) AS RetainedCustomers
            FROM mmi_lead_details ld
            JOIN agent_list al ON al.agentId = ld.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
           WHERE group_product IS NOT NULL
              AND ld.dealer_code = v_dealerId
            GROUP BY assigned_agent
        ),
        conversion_data AS (
            SELECT assigned_agent AS agentId,
                   COUNT(DISTINCT CASE WHEN lead_status = 'Won' AND converted_flag = 'CRM Renewal' THEN lead_id END) AS WonLeads
            FROM mmi_lead_archive_details lad
            JOIN agent_list al ON al.agentId = lad.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE lad.dealer_code = v_dealerId
            GROUP BY assigned_agent
        ),
        breach_stats AS (
				SELECT 
					mld.assigned_agent,
					COUNT(DISTINCT lb.lead_id) AS breachedLeads
				FROM mmi_lead_breached lb
				JOIN mmi_lead_details mld 
					ON mld.lead_id = lb.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = mld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE mld.dealer_code = v_dealerId
				GROUP BY mld.assigned_agent
			),
		final_data AS (
            SELECT
                ad.agentId,
                ad.agentName,
                IFNULL(la.LeadsAssigned,0) AS LeadsAssigned,
                IFNULL(lc.LeadsContacted,0) AS LeadsContacted,
                0 AS EligibleLeads,
                IFNULL(cp.policiesConverted,0) AS PoliciesConverted,
                IFNULL(ps.NetPremiumCollected,0) AS NetPremiumCollected,
                0 AS AvgHandlingTime,
                IFNULL(fd.FollowUpsDoneOnTime,0) AS FollowUpsDoneOnTime,
                IFNULL(fd.TotalFollowUpsScheduled,0) AS TotalFollowUpsScheduled,
                IFNULL(qs.QuoteShared,0) AS QuoteShared,
                0 AS CorrectDispositions,
                -- IFNULL(tf.TriggerFlag,0) AS TriggerFlag,
                5 AS TriggerFlag,
                IFNULL(scc.ConversionsWithinTwoCalls,0) AS ConversionsWithinTwoCalls,
                IFNULL(tp.TargetPremium,0) AS TargetPremium,
                IFNULL(nop.NetODPremium,0) AS NetODPremium,
                IFNULL(ads.AddonSales,0) AS AddonSales,
                IFNULL(pdr.PreDueRenewals,0) AS PreDueRenewals,
                -- IFNULL(gp.RetainedCustomers,0) AS RetainedCustomers,
                0 AS RetainedCustomers,
                IFNULL(ROUND((IFNULL(cd.WonLeads,0) / NULLIF(IFNULL(lc.LeadsContacted,0),0)) * 100,2),0) AS ConversionRate,
                IFNULL(ROUND((IFNULL(cp.policiesConverted,0) / NULLIF(IFNULL(la.LeadsAssigned,0),0)) * 100,2),0) AS RetentionRate,
                GREATEST(0,LEAST(100,100 - ROUND(NULLIF(bs.breachedLeads, 0) /NULLIF(IFNULL(la.LeadsAssigned,0), 0) * 100,2))) AS FollowUpEfficiency
            FROM agent_details ad
            LEFT JOIN leads_assigned la ON la.agentId = ad.agentId
            LEFT JOIN leads_contacted lc ON lc.agentId = ad.agentId
            LEFT JOIN converted_policies cp ON cp.agentId = ad.agentId
            LEFT JOIN premium_stats ps ON ps.agentId = ad.agentId
            LEFT JOIN followup_data fd ON fd.agentId = ad.agentId
            LEFT JOIN quote_shared qs ON qs.agentId = ad.agentId
            LEFT JOIN trigger_flag tf ON tf.agentId = ad.agentId
            LEFT JOIN shortest_call_conversion scc ON scc.agentId = ad.agentId
            LEFT JOIN conversion_data cd ON cd.agentId = ad.agentId
            LEFT JOIN target_premium tp ON tp.agentId = ad.agentId
            LEFT JOIN net_od_premium nop ON nop.agentId = ad.agentId
            LEFT JOIN addon_sales ads ON ads.agentId = ad.agentId
            LEFT JOIN pre_due_renewals pdr ON pdr.agentId = ad.agentId
            LEFT JOIN group_product gp ON gp.agentId = ad.agentId
            LEFT JOIN breach_stats bs ON bs.assigned_agent = ad.agentId
        ),
        score_data AS (
            SELECT
                agentId,
                agentName AS AgentName,
                LeadsAssigned,
                LeadsContacted,
                EligibleLeads,
                PoliciesConverted,
                -- NetPremiumCollected,
                AvgHandlingTime,
                QuoteShared,
                CorrectDispositions,
                TriggerFlag,
                ConversionsWithinTwoCalls,
                ConversionRate,
                RetentionRate,
                -- AddonSales,
                -- PreDueRenewals,
                -- ROUND((LeadsContacted / NULLIF(LeadsAssigned,0)) * 100,2) AS ContactRate,
                -- ROUND(IFNULL(FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0),0) * 100,2) AS FollowUpEfficiency,
                -- ROUND((QuoteShared / NULLIF(LeadsContacted,0)) * 100,2) AS QuoteRate,
                -- ROUND((PoliciesConverted / NULLIF(LeadsContacted,0)) * 100,2) AS PolicyConversionRate,
                -- ROUND((PoliciesConverted / NULLIF(LeadsAssigned,0)) * 100,2) AS OverallConversion,
                -- ROUND((ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0)) * 100,2) AS ShortestCallConversionRate,
                
                ROUND((IFNULL(LeadsAssigned / NULLIF(AVG(LeadsAssigned) OVER (),0), 0)  * 100 / 10), 2) AS leadsAssignedScore,
                ROUND((IFNULL(LeadsContacted / NULLIF(LeadsAssigned,0), 0) * 10), 2) AS ContactRate,
                ROUND((IFNULL((FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0)),0) * 10), 2) AS FollowUpEfficiencyData,
				FollowUpEfficiency,
                ROUND((IFNULL(QuoteShared / NULLIF(leadsContacted,0), 0) * 10), 2) AS QuoteRate,
				ROUND((IFNULL(PoliciesConverted / NULLIF(LeadsContacted,0), 0) * 25), 2) AS PolicyConversionRate,
				ROUND((IFNULL(PoliciesConverted / NULLIF(LeadsAssigned,0), 0) * 15), 2) AS OverallConversion,
				ROUND((IFNULL(ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0), 0)  * 100 * 5 / 100), 2) AS ShortestCallConversionRate,
                NetPremiumCollected as TotalNetPremiumCollected,
				ROUND((IFNULL(GREATEST(NetPremiumCollected - TargetPremium, 0) / 1000 * 10, 0)), 2) AS NetPremiumCollected,
				ROUND((IFNULL(NetODPremium / 1000, 0)), 2) AS NetODPremium,
				ROUND((IFNULL(AddonSales * 5, 0)), 2) AS AddonSales,
				ROUND((IFNULL(PreDueRenewals * 10, 0)), 2) AS PreDueRenewals,
                
                /*ROUND(((LeadsAssigned / NULLIF(AVG(LeadsAssigned) OVER (),0)) * 100 * 10 / 100)
                    + (IFNULL((LeadsContacted / NULLIF(LeadsAssigned,0)),0) * 100 * 10 / 100)
                    + (IFNULL((FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0)),0) * 100 * 10 / 100)
                    + (IFNULL((QuoteShared / NULLIF(LeadsContacted,0)),0) * 100 * 10 / 100)
                    + (IFNULL((PoliciesConverted / NULLIF(LeadsContacted,0)),0) * 100 * 25 / 100)
                    + (IFNULL((PoliciesConverted / NULLIF(LeadsAssigned,0)),0) * 100 * 15 / 100)
                    + (IFNULL((ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0)),0) * 100 * 5 / 100)
                ,2) AS PerformanceScore,*/
                
                ROUND((IFNULL(LeadsAssigned / NULLIF(AVG(LeadsAssigned) OVER (),0), 0) * 100  / 10)
                    + (IFNULL(LeadsContacted / NULLIF(LeadsAssigned,0), 0) * 10)
                    + (IFNULL((FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0)),0) * 10)
                    + (IFNULL(QuoteShared / NULLIF(LeadsContacted,0), 0) * 10)
                    + (IFNULL(PoliciesConverted / NULLIF(LeadsContacted,0), 0) * 25)
                    + (IFNULL(PoliciesConverted / NULLIF(LeadsAssigned,0), 0) * 15)
                    + (IFNULL(ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0), 0)  * 100 * 5 / 100 )
                    + TriggerFlag
                ,2) AS PerformanceScore,
                
                /*ROUND(
                    IFNULL(GREATEST(NetPremiumCollected - TargetPremium,0) / 1000 * 10,0)
                    + IFNULL(NetODPremium / 1000,0)
                    + IFNULL(AddonSales * 5,0)
                    + IFNULL(PreDueRenewals * 10,0)
                ,2) AS DynamicPerformanceScore*/
                0 AS DynamicPerformanceScore
            FROM final_data
        )
        SELECT
            agentId,
            AgentName AS agentName,
            ROUND(LeadsAssigned,2) AS leadsAssigned,
            ROUND(LeadsContacted,2) AS leadsContacted,
            ROUND(PoliciesConverted,2) AS policiesConverted,
            ROUND(TotalNetPremiumCollected,2) AS netPremiumCollected,
            ROUND(FollowUpEfficiency,2) AS followUpEfficiency,
            -- CONCAT(ROUND(ConversionRate,2)) AS conversionRate,
            -- CONCAT(ROUND(RetentionRate,2)) AS retentionRate,
            ROUND(ConversionRate,2) AS conversionRate,
            ROUND(RetentionRate,2) AS retentionRate,
            ROUND(PerformanceScore,2) AS performanceScore,
            ROUND(DynamicPerformanceScore,2) AS dynamicPerformanceScore,
            ROUND(PerformanceScore + DynamicPerformanceScore,2) AS overallScore,
            RANK() OVER (ORDER BY (PerformanceScore + DynamicPerformanceScore) DESC) AS `rank`,
            
            -- ROUND(LeadsAssigned, 2) AS leadsAssignedScore,
			leadsAssignedScore,
            ROUND(ContactRate, 2) AS contactRateScore,
			ROUND(FollowUpEfficiencyData, 2) AS followUpScore,
			ROUND(QuoteRate, 2) AS quoteShareScore,
			ROUND(PolicyConversionRate, 2) AS conversionScore,
			ROUND(OverallConversion, 2) AS retentionScore,
			ROUND(ShortestCallConversionRate, 2) AS shortestCallToConversion,
			-- ROUND(NetPremiumCollected, 2) AS netPremiumScore,
			-- ROUND(NetPremiumCollected, 2) AS netODPremiumScore,
			-- ROUND(AddonSales, 2) AS addonSalesScore,
			-- ROUND(PreDueRenewals, 2) AS preDueRenewalsScore,
            
            0 AS netPremiumScore,
			0 AS netODPremiumScore,
			0 AS addonSalesScore,
			0 AS preDueRenewalsScore,
            
			TriggerFlag AS triggerFlag
        FROM score_data
        LIMIT limitVal OFFSET calculated;
              
	ELSEIF v_type = 'dealerFilterExcel' THEN
		WITH
		lead_assigned_detail AS (
			SELECT
				mld.assigned_agent AS agentId,
				COUNT(DISTINCT mld.lead_id) AS leadsAssigned
			FROM mmi_lead_details mld
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE mld.assigned_agent IS NOT NULL
			  AND mld.dealer_code = v_dealerId
			  AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (mld.created_date BETWEEN v_startDate AND v_endDate
							OR mld.modified_date BETWEEN v_startDate AND v_endDate)))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
			GROUP BY mld.assigned_agent
		),
		lead_assigned_archive AS (
			SELECT
				mld.assigned_agent AS agentId,
				COUNT(DISTINCT mld.lead_id) AS leadsAssigned
			FROM mmi_lead_archive_details mld
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE mld.assigned_agent IS NOT NULL
			  AND mld.dealer_code = v_dealerId
			  AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (mld.created_date BETWEEN v_startDate AND v_endDate
							OR mld.modified_date BETWEEN v_startDate AND v_endDate)))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
			GROUP BY mld.assigned_agent
		),
		  lead_contacted_detail AS (
            SELECT
                mld.assigned_agent AS agentId,
                COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
                ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
            FROM mmi_call_disposition_history cdh
            JOIN mmi_lead_details mld ON mld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE mld.dealer_code = v_dealerId
			  AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (mld.created_date BETWEEN v_startDate AND v_endDate
							OR mld.modified_date BETWEEN v_startDate AND v_endDate)))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
			GROUP BY mld.assigned_agent
		),
		lead_contacted_archive AS (
            SELECT
                mld.assigned_agent AS agentId,
                COUNT(DISTINCT cdh.lead_id) AS leadsContacted,
                ROUND(AVG(cdh.call_date)/60,2) AS avgHandlingTime
            FROM mmi_call_disposition_history cdh
            JOIN mmi_lead_archive_details mld ON mld.lead_id = cdh.lead_id
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE mld.dealer_code = v_dealerId
			  AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (mld.created_date BETWEEN v_startDate AND v_endDate
							OR mld.modified_date BETWEEN v_startDate AND v_endDate)))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
			GROUP BY mld.assigned_agent
		),
		agent_lead_combined AS (
			SELECT
				COALESCE(ld.agentId, la.agentId) AS agentId,
				COALESCE(ld.leadsAssigned, 0) + COALESCE(la.leadsAssigned, 0) AS leadsAssigned_total,
				COALESCE(cd.leadsContacted, 0) + COALESCE(ca.leadsContacted, 0) AS leadsContacted_total
			FROM lead_assigned_detail ld
			LEFT JOIN lead_assigned_archive la ON ld.agentId = la.agentId
			LEFT JOIN lead_contacted_detail cd ON COALESCE(ld.agentId, la.agentId) = cd.agentId
			LEFT JOIN lead_contacted_archive ca ON COALESCE(ld.agentId, la.agentId, cd.agentId) = ca.agentId
		),
		
       agent_list AS (
       SELECT DISTINCT agentId FROM agent_lead_combined
       ),
        agent_details AS (SELECT al.agentId, CONCAT(mud.first_name, ' ', mud.last_name) AS agentName
			FROM agent_list al
			JOIN mmi_mast_user_registration_detail mud ON mud.id = al.agentId
		),
		leads_assigned AS (
			SELECT agentId, leadsAssigned_total AS LeadsAssigned FROM agent_lead_combined
		),
		leads_contacted AS (
			SELECT agentId, leadsContacted_total AS LeadsContacted FROM agent_lead_combined
		),
		/*followup_data AS (
			SELECT cdh.agent_code AS agentId,
				COUNT(CASE WHEN next_call_datetime IS NOT NULL THEN 1 END) AS TotalFollowUpsScheduled,
				COUNT(CASE WHEN next_call_datetime IS NOT NULL
					AND call_date <= STR_TO_DATE(next_call_datetime,'%Y-%m-%d %H:%i:%s') THEN 1 END) AS FollowUpsDoneOnTime
			FROM mmi_call_disposition_history cdh
			JOIN agent_list al ON al.agentId = cdh.agent_code
			JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE ld.dealer_code = v_dealerId
			  AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (ld.created_date BETWEEN v_startDate AND v_endDate
							OR ld.modified_date BETWEEN v_startDate AND v_endDate)))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
			GROUP BY cdh.agent_code
		),*/
        followup_data AS (
				WITH latest_calls AS (
					SELECT 
						cdh.*,
						ROW_NUMBER() OVER (
							PARTITION BY cdh.lead_id 
							ORDER BY cdh.created_date DESC
						) AS rn
					FROM mmi_call_disposition_history cdh
				)
				SELECT 
					lc.agent_code AS agentId,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL THEN 1 
					END) AS TotalFollowUpsScheduled,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL
						AND lc.call_date <= STR_TO_DATE(lc.next_call_datetime,'%Y-%m-%d %H:%i:%s') 
						THEN 1 
					END) AS FollowUpsDoneOnTime

				FROM latest_calls lc
				JOIN agent_list al 
					ON al.agentId = lc.agent_code
				JOIN mmi_lead_details ld 
					ON ld.lead_id = lc.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = ld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE lc.rn = 1 AND ld.dealer_code = v_dealerId
                AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (ld.created_date BETWEEN v_startDate AND v_endDate
							OR ld.modified_date BETWEEN v_startDate AND v_endDate)))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
			GROUP BY lc.agent_code
			),
		quote_shared AS (
			SELECT cdh.agent_code AS agentId,
				   COUNT(DISTINCT cdh.lead_id) AS QuoteShared
			FROM mmi_call_disposition_history cdh
			LEFT JOIN mmi_agent_disposition_field_response adf ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
			JOIN agent_list al ON al.agentId = cdh.agent_code
			JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE adf.field_value = 'Shared Quotes'
			  AND ld.dealer_code = v_dealerId
			  AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (ld.created_date BETWEEN v_startDate AND v_endDate
							OR ld.modified_date BETWEEN v_startDate AND v_endDate)))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
			GROUP BY cdh.agent_code
		),
 eligible_leads AS (
            SELECT ld.assigned_agent AS agentId,
                   COUNT(DISTINCT ld.lead_id) AS eligibleLeads
            FROM mmi_lead_details ld
            JOIN agent_list al ON al.agentId = ld.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE lead_type IN ('Hot','Warm')
              AND ld.dealer_code = v_dealerId
            GROUP BY ld.assigned_agent
        ),
		converted_policies AS (
			SELECT lad.assigned_agent AS agentId,
				    COUNT(DISTINCT policy_no) AS policiesConverted
			FROM mmi_lead_archive_details lad
			JOIN agent_list al ON al.agentId = lad.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
		 WHERE lead_status = 'Won' AND converted_flag = 'CRM Renewal'
			  AND lad.dealer_code = v_dealerId
			  AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (lad.created_date BETWEEN v_startDate AND v_endDate
							OR lad.modified_date BETWEEN v_startDate AND v_endDate)))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
			GROUP BY lad.assigned_agent
		),
		shortest_call_conversion AS (
			SELECT cdh.agent_code AS agentId,
				   COUNT(DISTINCT CASE
					   WHEN call_rank <= 2 AND lad.lead_status = 'Won' THEN cdh.lead_id
				   END) AS ConversionsWithinTwoCalls
			FROM (
				SELECT lead_id, agent_code, call_date,
					   ROW_NUMBER() OVER (PARTITION BY lead_id ORDER BY call_date) AS call_rank
				FROM mmi_call_disposition_history
			) cdh
			LEFT JOIN mmi_lead_archive_details lad ON lad.lead_id = cdh.lead_id
			JOIN agent_list al ON al.agentId = cdh.agent_code
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE cdh.agent_code IN (SELECT agentId FROM agent_list)
			  AND lad.dealer_code = v_dealerId
			  AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (lad.created_date BETWEEN v_startDate AND v_endDate
							OR lad.modified_date BETWEEN v_startDate AND v_endDate)))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
			GROUP BY cdh.agent_code
),
        disposition_quality AS (
            SELECT agent_code AS agentId,
                   COUNT(DISTINCT lead_id) AS CorrectDispositions
            FROM mmi_call_disposition_history
            WHERE dealer_disposition_id IS NOT NULL
              AND agent_code IN (SELECT agentId FROM agent_list)
            GROUP BY agent_code
        ),
        trigger_flag AS (
            SELECT agent_code AS agentId,
                   0 AS TriggerFlag
            FROM mmi_call_disposition_history
            WHERE agent_code IN (SELECT agentId FROM agent_list)
            GROUP BY agent_code
        ),
        avg_handling_time AS (
            SELECT agent_code AS agentId,
                   0 AS AvgHandlingTime
            FROM mmi_call_disposition_history
            WHERE agent_code IN (SELECT agentId FROM agent_list)
            GROUP BY agent_code
        ),
        target_premium AS (
            SELECT agentId, SUM(IFNULL(mtp.target_value,0)) AS TargetPremium FROM agent_list al
			left join mmi_target_planning mtp on mtp.team_member = al.agentId
			GROUP BY agentId
		),
		net_od_premium AS (  
			SELECT assigned_agent AS agentId,
				   SUM(CAST(IFNULL(net_od_premium_amount,0) AS DECIMAL(12,2)) +
					   CAST(IFNULL(addon_premium_amount,0) AS DECIMAL(12,2))) AS NetODPremium
			FROM mmi_lead_archive_details  ld
			JOIN agent_list al ON al.agentId = ld.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE ld.dealer_code = v_dealerId
			  AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (ld.created_date BETWEEN v_startDate AND v_endDate
							OR ld.modified_date BETWEEN v_startDate AND v_endDate)))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
			GROUP BY assigned_agent
		),
		premium_stats AS (
			SELECT lad.assigned_agent AS agentId,
				   SUM(mmd.net_premium) AS NetPremiumCollected
			FROM mmi_lead_archive_details lad
			JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
			JOIN agent_list al ON al.agentId = lad.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE lad.lead_status = 'Won'
			  AND lad.dealer_code = v_dealerId
			  AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (lad.created_date BETWEEN v_startDate AND v_endDate
							OR lad.modified_date BETWEEN v_startDate AND v_endDate)))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
			GROUP BY lad.assigned_agent
		),
		addon_sales AS (
			SELECT ld.assigned_agent AS agentId,
				   COUNT(pad.id) AS AddonSales
			FROM mmi_poladdon_data pad
			JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
			JOIN agent_list al ON al.agentId = ld.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE ld.dealer_code = v_dealerId
			  AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (ld.created_date BETWEEN v_startDate AND v_endDate
							OR ld.modified_date BETWEEN v_startDate AND v_endDate)))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
			GROUP BY ld.assigned_agent
		),
		 pre_due_renewals AS (
			SELECT 
				lad.assigned_agent AS agentId,
				COUNT(*) AS PreDueRenewals
			FROM mmi_lead_archive_details lad
			JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
			JOIN agent_list al ON al.agentId = lad.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE lad.lead_status = 'Won' 
			  AND lad.converted_flag = 'CRM Renewal'
			  AND DATEDIFF(lad.created_date, mmd.policy_expiry_date) > 10
			  AND lad.dealer_code = v_dealerId
			   AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
					   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
						   AND (lad.created_date BETWEEN v_startDate AND v_endDate
								OR lad.modified_date BETWEEN v_startDate AND v_endDate)))
				  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
				  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
			GROUP BY lad.assigned_agent
),
        group_product AS (
            SELECT assigned_agent AS agentId,
                   COUNT(DISTINCT lead_id) AS RetainedCustomers
            FROM mmi_lead_details ld
            JOIN agent_list al ON al.agentId = ld.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
           WHERE group_product IS NOT NULL
              AND ld.dealer_code = v_dealerId
            GROUP BY assigned_agent
		),
		conversion_data AS (
			SELECT assigned_agent AS agentId,
				   COUNT(DISTINCT CASE WHEN lead_status = 'Won' AND converted_flag = 'CRM Renewal' THEN lead_id END) AS WonLeads
			FROM mmi_lead_archive_details lad
			JOIN agent_list al ON al.agentId = lad.assigned_agent
			LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
			WHERE lad.dealer_code = v_dealerId
			  AND ((v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				   OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					   AND (lad.created_date BETWEEN v_startDate AND v_endDate
							OR lad.modified_date BETWEEN v_startDate AND v_endDate)))
			  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
			  AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
			GROUP BY assigned_agent
		),
        breach_stats AS (
				SELECT 
					mld.assigned_agent,
					COUNT(DISTINCT lb.lead_id) AS breachedLeads
				FROM mmi_lead_breached lb
				JOIN mmi_lead_details mld 
					ON mld.lead_id = lb.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = mld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE 
					(v_dealerId IS NULL OR v_dealerId='' OR FIND_IN_SET(TRIM(mld.dealer_code),v_dealerId))

					AND (((v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = ''))
					OR
					(v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
					 AND (mld.created_date BETWEEN v_startDate AND v_endDate
						  OR mld.modified_date BETWEEN v_startDate AND v_endDate)))

					AND (v_segment IS NULL OR v_segment='' OR FIND_IN_SET(TRIM(mld.vehicle_class),v_segment))
					AND (v_renewal_category IS NULL OR v_renewal_category='' 
						 OR FIND_IN_SET(TRIM(mld.renewal_category),v_renewal_category))
				GROUP BY mld.assigned_agent
			),
		final_data AS (
			SELECT
				ad.agentId,
				ad.agentName,
				IFNULL(la.LeadsAssigned,0) AS LeadsAssigned,
				IFNULL(lc.LeadsContacted,0) AS LeadsContacted,
0 AS EligibleLeads,
				IFNULL(cp.policiesConverted,0) AS PoliciesConverted,
				IFNULL(ps.NetPremiumCollected,0) AS NetPremiumCollected,
0 AS AvgHandlingTime,
				IFNULL(fd.FollowUpsDoneOnTime,0) AS FollowUpsDoneOnTime,
				IFNULL(fd.TotalFollowUpsScheduled,0) AS TotalFollowUpsScheduled,
				IFNULL(qs.QuoteShared,0) AS QuoteShared,
   0 AS CorrectDispositions,
                -- IFNULL(tf.TriggerFlag,0) AS TriggerFlag,
                5 AS TriggerFlag,
                IFNULL(scc.ConversionsWithinTwoCalls,0) AS ConversionsWithinTwoCalls,
                IFNULL(tp.TargetPremium,0) AS TargetPremium,
                IFNULL(nop.NetODPremium,0) AS NetODPremium, 
                IFNULL(ads.AddonSales,0) AS AddonSales,
                IFNULL(pdr.PreDueRenewals,0) AS PreDueRenewals,
                -- IFNULL(gp.RetainedCustomers,0) AS RetainedCustomers,
                0 AS RetainedCustomers,
                IFNULL(ROUND((IFNULL(cd.WonLeads,0) / NULLIF(IFNULL(lc.LeadsContacted,0),0)) * 100,2),0) AS ConversionRate,
                IFNULL(ROUND((IFNULL(cp.policiesConverted,0) / NULLIF(IFNULL(la.LeadsAssigned,0),0)) * 100,2),0) AS RetentionRate,
                GREATEST(0,LEAST(100,100 - ROUND(NULLIF(bs.breachedLeads, 0) /NULLIF(IFNULL(la.LeadsAssigned,0), 0) * 100,2))) AS FollowUpEfficiency
            FROM agent_details ad
            LEFT JOIN leads_assigned la ON la.agentId = ad.agentId
            LEFT JOIN leads_contacted lc ON lc.agentId = ad.agentId
            LEFT JOIN converted_policies cp ON cp.agentId = ad.agentId
            LEFT JOIN premium_stats ps ON ps.agentId = ad.agentId
            LEFT JOIN followup_data fd ON fd.agentId = ad.agentId
            LEFT JOIN quote_shared qs ON qs.agentId = ad.agentId
            LEFT JOIN trigger_flag tf ON tf.agentId = ad.agentId
            LEFT JOIN shortest_call_conversion scc ON scc.agentId = ad.agentId
            LEFT JOIN conversion_data cd ON cd.agentId = ad.agentId
            LEFT JOIN target_premium tp ON tp.agentId = ad.agentId
            LEFT JOIN net_od_premium nop ON nop.agentId = ad.agentId
            LEFT JOIN addon_sales ads ON ads.agentId = ad.agentId
            LEFT JOIN pre_due_renewals pdr ON pdr.agentId = ad.agentId
            LEFT JOIN group_product gp ON gp.agentId = ad.agentId
            LEFT JOIN breach_stats bs ON bs.assigned_agent = ad.agentId
        ),
        score_data AS (
            SELECT
                agentId,
                agentName AS AgentName,
                LeadsAssigned,
                LeadsContacted,
                EligibleLeads,
                PoliciesConverted,
                -- NetPremiumCollected,
                AvgHandlingTime,
                QuoteShared,
                CorrectDispositions,
                TriggerFlag,
                ConversionsWithinTwoCalls,
                ConversionRate,
                RetentionRate,
                -- AddonSales,
                -- PreDueRenewals,
                -- ROUND((LeadsContacted / NULLIF(LeadsAssigned,0)) * 100,2) AS ContactRate,
                -- ROUND(IFNULL(FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0),0) * 100,2) AS FollowUpEfficiency,
                -- ROUND((QuoteShared / NULLIF(LeadsContacted,0)) * 100,2) AS QuoteRate,
                -- ROUND((PoliciesConverted / NULLIF(LeadsContacted,0)) * 100,2) AS PolicyConversionRate,
                -- ROUND((PoliciesConverted / NULLIF(LeadsAssigned,0)) * 100,2) AS OverallConversion,
                -- ROUND((ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0)) * 100,2) AS ShortestCallConversionRate,
                
                ROUND((IFNULL(LeadsAssigned / NULLIF(AVG(LeadsAssigned) OVER (),0), 0) * 100 / 10), 2) AS leadsAssignedScore,
                ROUND((IFNULL(LeadsContacted / NULLIF(LeadsAssigned,0), 0) * 10), 2) AS ContactRate,
                ROUND((IFNULL((FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0)),0) * 10), 2) AS FollowUpEfficiencyData,
				FollowUpEfficiency,
                ROUND((IFNULL(QuoteShared / NULLIF(leadsContacted,0), 0) * 10), 2) AS QuoteRate,
				ROUND((IFNULL(PoliciesConverted / NULLIF(LeadsContacted,0), 0) * 25), 2) AS PolicyConversionRate,
				ROUND((IFNULL(PoliciesConverted / NULLIF(LeadsAssigned,0), 0) * 15), 2) AS OverallConversion,
				ROUND((IFNULL(ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0), 0)  * 100 * 5 / 100), 2) AS ShortestCallConversionRate,
				NetPremiumCollected as TotalNetPremiumCollected,
                ROUND((IFNULL(GREATEST(NetPremiumCollected - TargetPremium, 0) / 1000 * 10, 0)), 2) AS NetPremiumCollected,
				ROUND((IFNULL(NetODPremium / 1000, 0)), 2) AS NetODPremium,
				ROUND((IFNULL(AddonSales * 5, 0)), 2) AS AddonSales,
				ROUND((IFNULL(PreDueRenewals * 10, 0)), 2) AS PreDueRenewals,
                
                ROUND((IFNULL(LeadsAssigned / NULLIF(AVG(LeadsAssigned) OVER (),0), 0) * 100 / 10)
                    + (IFNULL(LeadsContacted / NULLIF(LeadsAssigned,0), 0) * 10)
                    + (IFNULL((FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0)),0) * 10)
                    + (IFNULL(QuoteShared / NULLIF(leadsContacted,0), 0) * 10)
                    + (IFNULL(PoliciesConverted / NULLIF(LeadsContacted,0), 0) * 25)
                    + (IFNULL(PoliciesConverted / NULLIF(LeadsAssigned,0), 0) * 15)
                    + (IFNULL(ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0), 0)  * 100 * 5 / 100 )
                    + TriggerFlag
                ,2) AS PerformanceScore,
                
                /*ROUND(((LeadsAssigned / NULLIF(AVG(LeadsAssigned) OVER (),0)) * 100 * 10 / 100)
                    + (IFNULL((LeadsContacted / NULLIF(LeadsAssigned,0)),0) * 100 * 10 / 100)
                    + (IFNULL((FollowUpsDoneOnTime / NULLIF(TotalFollowUpsScheduled,0)),0) * 100 * 10 / 100)
                    + (IFNULL((QuoteShared / NULLIF(LeadsContacted,0)),0) * 100 * 10 / 100)
                    + (IFNULL((PoliciesConverted / NULLIF(LeadsContacted,0)),0) * 100 * 25 / 100)
                    + (IFNULL((PoliciesConverted / NULLIF(LeadsAssigned,0)),0) * 100 * 15 / 100)
                    + (IFNULL((ConversionsWithinTwoCalls / NULLIF(PoliciesConverted,0)),0) * 100 * 5 / 100)
                ,2) AS PerformanceScore,*/
                
                /*ROUND(
                    IFNULL(GREATEST(NetPremiumCollected - TargetPremium,0) / 1000 * 10,0)
                    + IFNULL(NetODPremium / 1000,0)
                    + IFNULL(AddonSales * 5,0)
                    + IFNULL(PreDueRenewals * 10,0)
                ,2) AS DynamicPerformanceScore*/
                0 AS DynamicPerformanceScore
            FROM final_data
        )
        SELECT
            agentId,
            AgentName AS agentName,
            ROUND(LeadsAssigned,2) AS leadsAssigned,
            ROUND(LeadsContacted,2) AS leadsContacted,
            ROUND(PoliciesConverted,2) AS policiesConverted,
            ROUND(TotalNetPremiumCollected,2) AS netPremiumCollected,
            ROUND(FollowUpEfficiency,2) AS followUpEfficiency,
            ROUND(ConversionRate,2) AS conversionRate,
            ROUND(RetentionRate,2) AS retentionRate,
            ROUND(PerformanceScore,2) AS performanceScore,
            ROUND(DynamicPerformanceScore,2) AS dynamicPerformanceScore,
            ROUND(PerformanceScore + DynamicPerformanceScore,2) AS overallScore,
            RANK() OVER (ORDER BY (PerformanceScore + DynamicPerformanceScore) DESC) AS `rank`,
            
            leadsAssignedScore,
            ROUND(ContactRate, 2) AS contactRateScore,
			ROUND(FollowUpEfficiencyData, 2) AS followUpScore,
			ROUND(QuoteRate, 2) AS quoteShareScore,
			ROUND(PolicyConversionRate, 2) AS conversionScore,
			ROUND(OverallConversion, 2) AS retentionScore,
			ROUND(ShortestCallConversionRate, 2) AS shortestCallToConversion,
			-- ROUND(NetPremiumCollected, 2) AS netPremiumScore,
			-- ROUND(NetPremiumCollected, 2) AS netODPremiumScore,
			-- ROUND(AddonSales, 2) AS addonSalesScore,
			-- ROUND(PreDueRenewals, 2) AS preDueRenewalsScore,
            
            0 AS netPremiumScore,
			0 AS netODPremiumScore,
			0 AS addonSalesScore,
			0 AS preDueRenewalsScore,
            
			TriggerFlag AS triggerFlag
        FROM score_data
        LIMIT limitVal OFFSET calculated;

		SET SP_STATUS = '200';
		SET MESSAGE = 'Dealer Performance Dashboard Filtered Excel Data Fetched Successfully';
		END IF; -- end of excel sheet code
			
			END IF; -- end v_role_type

        IF v_role_type = 'mibl' THEN
            SET SP_STATUS = '200';
            SET MESSAGE = 'Dealers Performance Dashboard Fetched Successfully';
            
        ELSE
        
            SET SP_STATUS = '200';
            SET MESSAGE = 'Agents Performance Dashboard Fetched Successfully';
        END IF;
    END IF; -- end v_userId check
    
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_get_agent_performance_dashboard_excel` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
