/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_agent_performance_dashboard_excel`(
    IN Json_data JSON,
    OUT SP_STATUS VARCHAR(500),
    OUT MESSAGE VARCHAR(500))
BEGIN
    
    DECLARE v_type VARCHAR(20);
    DECLARE v_role_type VARCHAR(100);
    DECLARE v_check_type VARCHAR(100);
    DECLARE v_dealerId VARCHAR(550);
    DECLARE v_startDate VARCHAR(550);
    DECLARE v_endDate VARCHAR(550);
    DECLARE v_zone VARCHAR(100);
    DECLARE v_state VARCHAR(550);
    DECLARE v_segment VARCHAR(550);
    DECLARE v_renewal_category VARCHAR(1000);
    DECLARE v_dealerLocCode VARCHAR(550);
    
    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            @sqlstate = RETURNED_SQLSTATE, errno = MYSQL_ERRNO, errmsg = MESSAGE_TEXT;
        SET SP_STATUS = 407;
        SET MESSAGE = 'Something went wrong.';

        INSERT INTO mmi_mast_procedure_error (error_code, error_message, procedure_name, procedure_type, ERROR_TIMING, created_by, created_date)
        VALUES (errno, CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg), 'mmi_proc_get_agent_performance_dashboard_excel', 'PERFORMANCE_DASHBOARD', CURRENT_TIMESTAMP(), 'SYSTEM', NOW());
    END;
    

    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.type'));
    SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleType'));
    SET v_check_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.checkType'));
    SET v_dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
    SET v_startDate = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.startDate'));
	SET v_endDate = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.endDate'));
    
    SET v_startDate = COALESCE(
        NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.startDate')), ''),
        NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.fromDate')), '')
    );
    SET v_endDate = COALESCE(
        NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.endDate')), ''),
        NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.toDate')), '')
    );
    
    SET v_zone = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.zone')), '');
    SET v_state = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.state')), '');
    SET v_segment = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.segment')), '');
    SET v_renewal_category = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalCategory')), '');
    SET v_dealerLocCode = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerLocCode')), '');
    
    
	IF v_role_type = 'mibl' THEN

		IF v_type = 'miblFilterExcel' THEN

    DROP TEMPORARY TABLE IF EXISTS mibl_temp_score_data;

    CREATE TEMPORARY TABLE mibl_temp_score_data (
        dealer_id VARCHAR(45),
        dealer_name VARCHAR(255),
        agentId INT,
        agentName VARCHAR(255),
        leadsAssigned INT DEFAULT 0,
        leadsContacted INT DEFAULT 0,
        policiesConverted INT DEFAULT 0,
        netPremiumCollected DECIMAL(12,2) DEFAULT 0,
        conversionRate DECIMAL(6,2) DEFAULT 0,
        retentionRate DECIMAL(6,2) DEFAULT 0,
        followUpEfficiency DECIMAL(10,2) DEFAULT 0,
        FollowUpsDoneOnTime INT DEFAULT 0,
        TotalFollowUpsScheduled INT DEFAULT 0,
        QuoteShared INT DEFAULT 0,
        ConversionsWithinTwoCalls INT DEFAULT 0,
        TriggerFlag INT DEFAULT 5,
        TargetPremium DECIMAL(12,2) DEFAULT 0,
        NetODPremium DECIMAL(12,2) DEFAULT 0,
        AddonSales INT DEFAULT 0,
        PreDueRenewals INT DEFAULT 0,
        PerformanceScore DECIMAL(12,2) DEFAULT 0,
        DynamicPerformanceScore DECIMAL(12,2) DEFAULT 0,
        OverallScore DECIMAL(12,2) DEFAULT 0,
        r INT DEFAULT 0
    );

    INSERT INTO mibl_temp_score_data (dealer_id, dealer_name, agentId, agentName)
    SELECT DISTINCT
        ld.dealer_code,
        COALESCE(md.dealer_name, ' '),
        ld.assigned_agent,
        CONCAT(IFNULL(mud.first_name,''), ' ', IFNULL(mud.last_name,''))
    FROM (
        SELECT ld.dealer_code, ld.assigned_agent
        FROM mmi_lead_details ld
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE ld.assigned_agent IS NOT NULL
          AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = ''
               OR ld.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d')
                   AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
        UNION
        SELECT lad.dealer_code, lad.assigned_agent
        FROM mmi_lead_archive_details lad
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE lad.assigned_agent IS NOT NULL
          /*AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = ''
               OR lad.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d')
                   AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))*/
          AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (lad.created_date BETWEEN v_startDate AND v_endDate
						 OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )         
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(lad.dealer_code), v_dealerId))
    ) ld
    JOIN mmi_mast_user_registration_detail mud ON mud.id = ld.assigned_agent
    LEFT JOIN mmi_dealer_location_mapping md ON md.mapping_dealer_code = ld.dealer_code;


    UPDATE mibl_temp_score_data t
    JOIN (
        SELECT assigned_agent, dealer_code, COUNT(DISTINCT lead_id) AS leadsAssigned
        FROM (
            SELECT ld.lead_id, ld.assigned_agent, ld.dealer_code
            FROM mmi_lead_details ld
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (ld.created_date BETWEEN v_startDate AND v_endDate
						 OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) ) 
              AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
              AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
              AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
            UNION ALL
            SELECT lad.lead_id, lad.assigned_agent, lad.dealer_code
            FROM mmi_lead_archive_details lad
            LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
            LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
            WHERE ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (lad.created_date BETWEEN v_startDate AND v_endDate
						 OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) ) 
              AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
              AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
              AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
              AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
              AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
              AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(lad.dealer_code), v_dealerId))
        ) x
        WHERE assigned_agent IS NOT NULL
        GROUP BY assigned_agent, dealer_code
    ) la ON t.agentId = la.assigned_agent AND t.dealer_id = la.dealer_code
    SET t.leadsAssigned = la.leadsAssigned;


    UPDATE mibl_temp_score_data t
    LEFT JOIN (
        SELECT mld.assigned_agent, mld.dealer_code, COUNT(DISTINCT cdh.lead_id) AS leadsContacted
        FROM mmi_call_disposition_history cdh
        JOIN mmi_lead_details mld ON mld.lead_id = cdh.lead_id
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (mld.created_date BETWEEN v_startDate AND v_endDate
						 OR mld.modified_date BETWEEN v_startDate AND v_endDate) ) ) 
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealerId))
        GROUP BY mld.assigned_agent, mld.dealer_code
    ) cs ON t.agentId = cs.assigned_agent AND t.dealer_id = cs.dealer_code
    LEFT JOIN (
        SELECT mld.assigned_agent, mld.dealer_code, COUNT(DISTINCT cdh.lead_id) AS leadsContacted
        FROM mmi_call_disposition_history cdh
        JOIN mmi_lead_archive_details mld ON mld.lead_id = cdh.lead_id
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = mld.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE /*(v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = ''
               OR mld.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d')
                   AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))*/
          ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (mld.created_date BETWEEN v_startDate AND v_endDate
						 OR mld.modified_date BETWEEN v_startDate AND v_endDate) ) )         
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealerId))
        GROUP BY mld.assigned_agent, mld.dealer_code
    ) lac ON t.agentId = lac.assigned_agent AND t.dealer_id = lac.dealer_code
    SET t.leadsContacted = COALESCE(cs.leadsContacted, 0) + COALESCE(lac.leadsContacted, 0);


    UPDATE mibl_temp_score_data t
    JOIN (
        SELECT lad.assigned_agent AS agentId, lad.dealer_code, COUNT(DISTINCT lad.policy_no) AS policiesConverted
        FROM mmi_lead_archive_details lad
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE lad.lead_status = 'Won' AND lad.converted_flag = 'CRM Renewal'
          AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (lad.created_date BETWEEN v_startDate AND v_endDate
						 OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(lad.dealer_code), v_dealerId))
        GROUP BY lad.assigned_agent, lad.dealer_code
    ) pc ON t.agentId = pc.agentId AND t.dealer_id = pc.dealer_code
    SET t.policiesConverted = pc.policiesConverted;


    UPDATE mibl_temp_score_data t
    JOIN (
        SELECT lad.assigned_agent AS agentId, lad.dealer_code, SUM(CAST(mmd.net_premium AS DECIMAL(12,2))) AS netPremiumCollected
        FROM mmi_lead_archive_details lad
        JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE lad.lead_status = 'Won'
          AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (lad.created_date BETWEEN v_startDate AND v_endDate
						 OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(lad.dealer_code), v_dealerId))
        GROUP BY lad.assigned_agent, lad.dealer_code
    ) np ON t.agentId = np.agentId AND t.dealer_id = np.dealer_code
    SET t.netPremiumCollected = np.netPremiumCollected;


    UPDATE mibl_temp_score_data t
    JOIN (
        /*SELECT 
            cdh.agent_code AS agentId,
            ld.dealer_code,
            COUNT(CASE WHEN cdh.next_call_datetime IS NOT NULL THEN 1 END) AS TotalScheduled,
            COUNT(CASE WHEN cdh.next_call_datetime IS NOT NULL 
                       AND cdh.call_date <= STR_TO_DATE(cdh.next_call_datetime,'%Y-%m-%d %H:%i:%s') THEN 1 END) AS DoneOnTime
        FROM mmi_call_disposition_history cdh
        JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (ld.created_date BETWEEN v_startDate AND v_endDate
						 OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
        GROUP BY cdh.agent_code, ld.dealer_code*/
        WITH latest_calls AS (
					SELECT 
						cdh.*,
						ROW_NUMBER() OVER (
							PARTITION BY cdh.lead_id 
							ORDER BY cdh.created_date DESC
						) AS rn
					FROM mmi_call_disposition_history cdh
				)
				SELECT 
					lc.agent_code  AS agentId,
					ld.dealer_code,
					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL THEN 1 
					END) AS TotalScheduled,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL
						AND lc.call_date <= STR_TO_DATE(lc.next_call_datetime,'%Y-%m-%d %H:%i:%s') 
						THEN 1 
					END) AS DoneOnTime

				FROM latest_calls lc
				JOIN mmi_lead_details ld 
					ON ld.lead_id = lc.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = ld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE lc.rn = 1
			AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (ld.created_date BETWEEN v_startDate AND v_endDate
						 OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
			GROUP BY lc.agent_code,ld.dealer_code
    ) f ON t.agentId = f.agentId AND t.dealer_id = f.dealer_code
    SET 
        t.TotalFollowUpsScheduled = IFNULL(f.TotalScheduled, 0),
        t.FollowUpsDoneOnTime    = IFNULL(f.DoneOnTime, 0);
        -- t.followUpEfficiency     = IFNULL(ROUND((f.DoneOnTime / NULLIF(f.TotalScheduled,0)) * 100, 2), 0);

	
    UPDATE mibl_temp_score_data t
    JOIN (
				SELECT 
					mld.assigned_agent as agentId,
                    mld.dealer_code,
					COUNT(DISTINCT lb.lead_id) AS breachedLeads
				FROM mmi_lead_breached lb
				JOIN mmi_lead_details mld 
					ON mld.lead_id = lb.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = mld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (mld.created_date BETWEEN v_startDate AND v_endDate
						 OR mld.modified_date BETWEEN v_startDate AND v_endDate) ) )
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealerId))
				GROUP BY mld.assigned_agent,mld.dealer_code
        ) f ON t.agentId = f.agentId AND t.dealer_id = f.dealer_code
    SET 
        t.followUpEfficiency = GREATEST(0,LEAST(100,100 - ROUND(NULLIF(f.breachedLeads, 0) /NULLIF(IFNULL(t.leadsAssigned,0), 0) * 100,2)));


    UPDATE mibl_temp_score_data t
    JOIN (
        SELECT cdh.agent_code AS agentId, ld.dealer_code, COUNT(DISTINCT cdh.lead_id) AS QuoteShared
        FROM mmi_call_disposition_history cdh
        LEFT JOIN mmi_agent_disposition_field_response adf ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
        JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE adf.field_value = 'Shared Quotes'
          AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (ld.created_date BETWEEN v_startDate AND v_endDate
						 OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
        GROUP BY cdh.agent_code, ld.dealer_code
    ) q ON t.agentId = q.agentId AND t.dealer_id = q.dealer_code
    SET t.QuoteShared = q.QuoteShared;


    UPDATE mibl_temp_score_data t
    JOIN (
        SELECT cdh.agent_code AS agentId, lad.dealer_code,
               COUNT(DISTINCT CASE WHEN call_rank <= 2 AND lad.lead_status = 'Won' THEN cdh.lead_id END) AS ConversionsWithinTwoCalls
        FROM (
            SELECT lead_id, agent_code, call_date,
                   ROW_NUMBER() OVER (PARTITION BY lead_id ORDER BY call_date) AS call_rank
            FROM mmi_call_disposition_history
        ) cdh
        -- JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
        LEFT JOIN mmi_lead_archive_details lad ON lad.lead_id = cdh.lead_id
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (lad.created_date BETWEEN v_startDate AND v_endDate
						 OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(lad.dealer_code), v_dealerId))
        GROUP BY cdh.agent_code, lad.dealer_code
    ) sc ON t.agentId = sc.agentId AND t.dealer_id = sc.dealer_code
    SET t.ConversionsWithinTwoCalls = sc.ConversionsWithinTwoCalls;


    UPDATE mibl_temp_score_data t
    JOIN (
        SELECT assigned_agent AS agentId, ld.dealer_code,
               SUM(IFNULL(ld.net_od_premium_amount,0) + IFNULL(ld.addon_premium_amount,0)) AS NetODPremium
        FROM mmi_lead_details ld
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (ld.created_date BETWEEN v_startDate AND v_endDate
						 OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
        GROUP BY assigned_agent, ld.dealer_code
    ) od ON t.agentId = od.agentId AND t.dealer_id = od.dealer_code
    SET t.NetODPremium = od.NetODPremium;
    
    
    UPDATE mibl_temp_score_data t
	JOIN (
		SELECT team_member AS agentId, ld.dealer_code,
		SUM(IFNULL(target_value,0)) AS TargetPremium
        FROM mmi_target_planning tp
        LEFT JOIN mmi_lead_details ld ON ld.assigned_agent = tp.team_member
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (ld.created_date BETWEEN v_startDate AND v_endDate
						 OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
        GROUP BY team_member, ld.dealer_code
    ) x ON t.agentId = x.agentId
	SET t.TargetPremium = x.TargetPremium;
    
    
    UPDATE mibl_temp_score_data t
    JOIN (
        SELECT ld.assigned_agent AS agentId, ld.dealer_code, COUNT(pad.id) AS AddonSales
        FROM mmi_poladdon_data pad
        JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (ld.created_date BETWEEN v_startDate AND v_endDate
						 OR ld.modified_date BETWEEN v_startDate AND v_endDate) ) )
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(ld.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(ld.dealer_code), v_dealerId))
        GROUP BY ld.assigned_agent, ld.dealer_code
    ) ad ON t.agentId = ad.agentId AND t.dealer_id = ad.dealer_code
    SET t.AddonSales = ad.AddonSales;

   
    UPDATE mibl_temp_score_data t
    JOIN (
        SELECT lad.assigned_agent AS agentId, lad.dealer_code, COUNT(*) AS PreDueRenewals
        FROM mmi_lead_archive_details lad
        JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE lad.lead_status = 'Won'
          AND lad.converted_flag = 'CRM Renewal'
          AND DATEDIFF(lad.created_date, mmd.policy_expiry_date) > 10
          AND ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (lad.created_date BETWEEN v_startDate AND v_endDate
						 OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(lad.dealer_code), v_dealerId))
        GROUP BY lad.assigned_agent, lad.dealer_code
    ) pdr ON t.agentId = pdr.agentId AND t.dealer_id = pdr.dealer_code
    SET t.PreDueRenewals = pdr.PreDueRenewals;


	-- CONVERSION RATE
    UPDATE mibl_temp_score_data t
    JOIN (
        SELECT assigned_agent AS agentId, lad.dealer_code,
               COUNT(DISTINCT CASE WHEN lad.lead_status = 'Won' AND lad.converted_flag = 'CRM Renewal' THEN lad.lead_id END) AS WonLeads
        FROM mmi_lead_archive_details lad
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
        WHERE ( (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != ''
					AND (lad.created_date BETWEEN v_startDate AND v_endDate
						 OR lad.modified_date BETWEEN v_startDate AND v_endDate) ) )
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
          AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(lad.renewal_category), v_renewal_category))
          AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dlm.zone), v_zone))
          AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
          AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
          AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(lad.dealer_code), v_dealerId))
        GROUP BY assigned_agent, lad.dealer_code
    ) cr ON t.agentId = cr.agentId AND t.dealer_id = cr.dealer_code
    SET t.conversionRate = IFNULL(ROUND((cr.WonLeads / NULLIF(t.leadsContacted,0)) * 100, 2), 0);

    --  RETENTION RATE
    UPDATE mibl_temp_score_data t
    SET t.retentionRate = IFNULL(ROUND((t.policiesConverted / NULLIF(t.leadsAssigned,0)) * 100, 2), 0);

    -- TRIGGER FLAG
    UPDATE mibl_temp_score_data t SET t.TriggerFlag = 5;

    -- Per dealer max leads for scoring
    DROP TEMPORARY TABLE IF EXISTS dealer_max_temp;
    CREATE TEMPORARY TABLE dealer_max_temp AS
    SELECT dealer_id, MAX(leadsAssigned) AS max_leads
    FROM mibl_temp_score_data
    GROUP BY dealer_id;
    
    DROP TEMPORARY TABLE IF EXISTS tmp_avg_leads;
    CREATE TEMPORARY TABLE tmp_avg_leads AS
	SELECT dealer_id,AVG(LeadsAssigned) AS avg_leads
	FROM mibl_temp_score_data
	GROUP BY dealer_id;


    -- PERFORMANCE SCORE (per dealer normaln)
    UPDATE mibl_temp_score_data t
    -- JOIN dealer_max_temp dm ON t.dealer_id = dm.dealer_id
    JOIN tmp_avg_leads dm ON t.dealer_id = dm.dealer_id
    SET t.PerformanceScore =
        /*(IFNULL(t.leadsAssigned / NULLIF(dm.max_leads, 0), 0) * 10)
        + (IFNULL(t.leadsContacted / NULLIF(t.leadsAssigned, 0), 0) * 10)
        + (IFNULL(t.FollowUpsDoneOnTime / NULLIF(t.TotalFollowUpsScheduled, 0), 0) * 10)
        + (IFNULL(t.QuoteShared / NULLIF(t.leadsContacted, 0), 0) * 10)
        + (IFNULL(t.policiesConverted / NULLIF(t.leadsContacted, 0), 0) * 25)
        + (IFNULL(t.policiesConverted / NULLIF(t.leadsAssigned, 0), 0) * 15)
        + (IFNULL(t.ConversionsWithinTwoCalls / NULLIF(t.policiesConverted, 0), 0) * 5);*/
        ROUND((IFNULL(t.leadsAssigned / NULLIF(dm.avg_leads,0), 0) * 100 / 10)
                    + (IFNULL(t.leadsContacted / NULLIF(t.leadsAssigned,0), 0) * 10)
                    + (IFNULL((t.FollowUpsDoneOnTime / NULLIF(t.TotalFollowUpsScheduled,0)),0) * 10)
                    + (IFNULL(t.QuoteShared / NULLIF(t.leadsContacted,0), 0) * 10)
                    + (IFNULL(t.policiesConverted / NULLIF(t.leadsContacted,0), 0) * 25)
                    + (IFNULL(t.policiesConverted / NULLIF(t.leadsAssigned,0), 0) * 15)
                    + (IFNULL(t.ConversionsWithinTwoCalls / NULLIF(t.policiesConverted,0), 0) * 100 * 5 / 100 )
                    + t.TriggerFlag
                ,2);

    -- DYNAMIC PERFORMANCE SCORE
    UPDATE mibl_temp_score_data t
    SET t.DynamicPerformanceScore = 0;
       /* IFNULL(GREATEST(t.netPremiumCollected - t.TargetPremium, 0) / 1000 * 10, 0)
        + IFNULL(t.NetODPremium / 1000, 0)
        + IFNULL(t.AddonSales * 5, 0)
        + IFNULL(t.PreDueRenewals * 10, 0);*/

    -- OVERALL SCORE
    UPDATE mibl_temp_score_data t
    SET t.OverallScore = t.PerformanceScore + t.DynamicPerformanceScore;

    -- Rank per dealer
    DROP TEMPORARY TABLE IF EXISTS temp_ranked_agents;
    CREATE TEMPORARY TABLE temp_ranked_agents AS
    SELECT agentId, dealer_id,
           ROW_NUMBER() OVER (PARTITION BY dealer_id ORDER BY OverallScore DESC, agentId ASC) AS rn
    FROM mibl_temp_score_data;

    UPDATE mibl_temp_score_data t
    JOIN temp_ranked_agents r ON t.agentId = r.agentId AND t.dealer_id = r.dealer_id
    SET t.r = r.rn;

    DROP TEMPORARY TABLE IF EXISTS temp_ranked_agents;


    SELECT 
        t.dealer_id AS dealerId,
        t.dealer_name AS dealerName,
        t.agentId,
        t.agentName,
        t.leadsAssigned,
        t.leadsContacted,
        t.policiesConverted,
        t.netPremiumCollected,
        t.followUpEfficiency,
        -- ROUND(IFNULL(t.FollowUpsDoneOnTime / NULLIF(t.TotalFollowUpsScheduled,0),0) * 100, 2) AS followUpEfficiency,
        ROUND(t.conversionRate, 2) AS conversionRate,
        ROUND(t.retentionRate, 2) AS retentionRate,
        ROUND(t.PerformanceScore, 2) AS performanceScore,
        ROUND(t.DynamicPerformanceScore, 2) AS dynamicPerformanceScore,
        ROUND(t.OverallScore, 2) AS overallScore,
        t.r AS `rank`,
        ROUND((IFNULL(t.leadsAssigned / NULLIF(dm.avg_leads, 0), 0) * 100 / 10), 2) AS leadsAssignedScore,
        ROUND((IFNULL(t.leadsContacted / NULLIF(t.leadsAssigned,0), 0) * 10), 2) AS contactRateScore,
        ROUND((IFNULL((t.FollowUpsDoneOnTime / NULLIF(t.TotalFollowUpsScheduled,0)),0) * 10), 2) AS followUpScore,
        ROUND((IFNULL(t.QuoteShared / NULLIF(t.leadsContacted,0), 0) * 10), 2) AS quoteShareScore,
        ROUND((IFNULL(t.policiesConverted / NULLIF(t.leadsContacted,0), 0) * 25), 2) AS conversionScore,
        ROUND((IFNULL(t.policiesConverted / NULLIF(t.leadsAssigned,0), 0) * 15), 2) AS retentionScore,
        ROUND((IFNULL(t.ConversionsWithinTwoCalls / NULLIF(t.policiesConverted,0), 0)  * 100 * 5 / 100 ), 2) AS shortestCallToConversion,
        
        -- ROUND((IFNULL(GREATEST(t.NetPremiumCollected - t.TargetPremium, 0) / 1000 * 10, 0)), 2) AS netPremiumScore,
        -- ROUND((IFNULL(t.NetODPremium / 1000, 0)), 2) AS netODPremiumScore,
        -- ROUND((IFNULL(t.AddonSales * 5, 0)), 2) AS addonSalesScore,
        -- ROUND((IFNULL(t.PreDueRenewals * 10, 0)), 2) AS preDueRenewalsScore,
        
        0 AS netPremiumScore,
		0 AS netODPremiumScore,
		0 AS addonSalesScore,
		0 AS preDueRenewalsScore,
        
        t.TriggerFlag AS TriggerFlag
    FROM mibl_temp_score_data t
    JOIN tmp_avg_leads dm ON t.dealer_id = dm.dealer_id
    ORDER BY t.dealer_id, t.r;

    DROP TEMPORARY TABLE IF EXISTS tmp_avg_leads;
    DROP TEMPORARY TABLE IF EXISTS dealer_max_temp;

    SET SP_STATUS = '200';
    SET MESSAGE = 'MIBL Performance Dashboard Filter Data Fetched Successfully';
        
        
        
        ELSEIF v_type = 'miblExcel' THEN
        
            DROP TEMPORARY TABLE IF EXISTS mibl_temp_score_data;
            
            CREATE TEMPORARY TABLE mibl_temp_score_data (
                dealer_id VARCHAR(45),
                dealer_name VARCHAR(255),
                agentId INT,
                agentName VARCHAR(255),
                leadsAssigned INT DEFAULT 0,
                leadsContacted INT DEFAULT 0,
                policiesConverted INT DEFAULT 0,
                netPremiumCollected DECIMAL(12,2) DEFAULT 0,
                conversionRate DECIMAL(6,2) DEFAULT 0,
                retentionRate DECIMAL(6,2) DEFAULT 0,
                followUpEfficiency DECIMAL(10,2) DEFAULT 0,
                FollowUpsDoneOnTime INT DEFAULT 0,
				TotalFollowUpsScheduled INT DEFAULT 0,
                QuoteShared INT DEFAULT 0,
                ConversionsWithinTwoCalls INT DEFAULT 0,
                TriggerFlag INT DEFAULT 5,
                TargetPremium DECIMAL(12,2) DEFAULT 0,
                NetODPremium DECIMAL(12,2) DEFAULT 0,
                AddonSales INT DEFAULT 0,
                PreDueRenewals INT DEFAULT 0,
                PerformanceScore DECIMAL(12,2) DEFAULT 0,
                DynamicPerformanceScore DECIMAL(12,2) DEFAULT 0,
                OverallScore DECIMAL(12,2) DEFAULT 0,
                r INT DEFAULT 0
            );
            
            -- Base agent insertion (no filters)
            INSERT INTO mibl_temp_score_data (dealer_id, dealer_name, agentId, agentName)
            SELECT DISTINCT
                ld.dealer_code AS dealer_id,
                md.dealer_name,
                ld.assigned_agent AS agentId,
                CONCAT(IFNULL(mud.first_name,''), ' ', IFNULL(mud.last_name,'')) AS agentName
            FROM (
                SELECT dealer_code, assigned_agent FROM mmi_lead_details
                UNION
                SELECT dealer_code, assigned_agent FROM mmi_lead_archive_details
            ) ld
            JOIN mmi_mast_user_registration_detail mud ON mud.id = ld.assigned_agent
            LEFT JOIN mmi_dealer_location_mapping md ON md.mapping_dealer_code = ld.dealer_code
            WHERE ld.assigned_agent IS NOT NULL AND md.dealer_name IS NOT NULL;
            
            -- LEADS ASSIGNED
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT 
                    assigned_agent,
                    dealer_code,
                    COUNT(DISTINCT lead_id) AS leadsAssigned
                FROM (
                    SELECT lead_id, assigned_agent, dealer_code FROM mmi_lead_details
                    UNION ALL
                    SELECT lead_id, assigned_agent, dealer_code FROM mmi_lead_archive_details
                ) x
                WHERE assigned_agent IS NOT NULL
                GROUP BY assigned_agent, dealer_code
            ) la 
            ON t.agentId = la.assigned_agent AND t.dealer_id = la.dealer_code
            SET t.leadsAssigned = la.leadsAssigned;
            
            -- LEADS CONTACTED
            UPDATE mibl_temp_score_data t
            LEFT JOIN (
                SELECT
                    mld.assigned_agent,
                    mld.dealer_code,
                    COUNT(DISTINCT cdh.lead_id) AS leadsContacted
                FROM mmi_call_disposition_history cdh
                JOIN mmi_lead_details mld ON mld.lead_id = cdh.lead_id
                GROUP BY mld.assigned_agent, mld.dealer_code
            ) cs
            ON t.agentId = cs.assigned_agent AND t.dealer_id = cs.dealer_code
            LEFT JOIN (
                SELECT
                    mld.assigned_agent,
                    mld.dealer_code,
                    COUNT(DISTINCT cdh.lead_id) AS leadsContacted
                FROM mmi_call_disposition_history cdh
                JOIN mmi_lead_archive_details mld ON mld.lead_id = cdh.lead_id
                GROUP BY mld.assigned_agent, mld.dealer_code
            ) lac
            ON t.agentId = lac.assigned_agent AND t.dealer_id = lac.dealer_code
            SET t.leadsContacted = COALESCE(cs.leadsContacted, 0) + COALESCE(lac.leadsContacted, 0);
            
           
            -- POLICIES CONVERTED (archive)
			UPDATE mibl_temp_score_data t
			JOIN (
				SELECT assigned_agent AS agentId, COUNT(DISTINCT policy_no) AS policiesConverted
				FROM mmi_lead_archive_details
				WHERE lead_status = 'Won' AND converted_flag = 'CRM Renewal'
				GROUP BY assigned_agent
			) x ON t.agentId = x.agentId
			SET t.PoliciesConverted = x.policiesConverted;
            
            -- NET PREMIUM COLLECTED
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT lad.assigned_agent AS agentId, SUM(CAST(mmd.net_premium AS DECIMAL(12,2))) AS netPremiumCollected
                FROM mmi_lead_archive_details lad
                JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
                WHERE lad.lead_status = 'Won'
                GROUP BY lad.assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.NetPremiumCollected = x.NetPremiumCollected;
            
            -- FOLLOW UP EFFICIENCY 
          /*  UPDATE mibl_temp_score_data t
            JOIN (
                SELECT 
                    cdh.agent_code AS agentId,
                    COUNT(CASE WHEN next_call_datetime IS NOT NULL THEN 1 END) AS TotalFollowUpsScheduled,
                    COUNT(CASE WHEN next_call_datetime IS NOT NULL 
                               AND call_date <= STR_TO_DATE(next_call_datetime,'%Y-%m-%d %H:%i:%s') THEN 1 END) AS FollowUpsDoneOnTime
                FROM mmi_call_disposition_history cdh
                GROUP BY cdh.agent_code
            ) f ON t.agentId = f.agentId
            SET t.followUpEfficiency = IFNULL(
                ROUND((IFNULL(f.FollowUpsDoneOnTime,0) / NULLIF(IFNULL(f.TotalFollowUpsScheduled,0),0)) * 100, 2), 0); */
                
			-- FOLLOW UP EFFICIENCY
			  UPDATE mibl_temp_score_data t
				JOIN (
					/*SELECT 
						cdh.agent_code AS agentId,
						ld.dealer_code,
						COUNT(CASE WHEN cdh.next_call_datetime IS NOT NULL THEN 1 END) AS TotalScheduled,
						COUNT(CASE WHEN cdh.next_call_datetime IS NOT NULL 
								   AND cdh.call_date <= STR_TO_DATE(cdh.next_call_datetime,'%Y-%m-%d %H:%i:%s') THEN 1 END) AS DoneOnTime
					FROM mmi_call_disposition_history cdh
					JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
					-- opt joins
					-- LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
					-- LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
					GROUP BY cdh.agent_code, ld.dealer_code*/
                    WITH latest_calls AS (
					SELECT 
						cdh.*,
						ROW_NUMBER() OVER (
							PARTITION BY cdh.lead_id 
							ORDER BY cdh.created_date DESC
						) AS rn
					FROM mmi_call_disposition_history cdh
				)
				SELECT 
					lc.agent_code  AS agentId,
					ld.dealer_code,
					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL THEN 1 
					END) AS TotalScheduled,

					COUNT(CASE 
						WHEN lc.next_call_datetime IS NOT NULL
						AND lc.call_date <= STR_TO_DATE(lc.next_call_datetime,'%Y-%m-%d %H:%i:%s') 
						THEN 1 
					END) AS DoneOnTime

				FROM latest_calls lc
				JOIN mmi_lead_details ld 
					ON ld.lead_id = lc.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = ld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				WHERE lc.rn = 1
                GROUP BY lc.agent_code,ld.dealer_code
				) f ON t.agentId = f.agentId AND t.dealer_id = f.dealer_code
				SET 
					t.TotalFollowUpsScheduled = IFNULL(f.TotalScheduled, 0),
					t.FollowUpsDoneOnTime    = IFNULL(f.DoneOnTime, 0);
					-- t.followUpEfficiency     = IFNULL(ROUND((f.DoneOnTime / NULLIF(f.TotalScheduled,0)) * 100, 2), 0);
        
            
             UPDATE mibl_temp_score_data t
		JOIN (
				SELECT 
					mld.assigned_agent as agentId,
                    mld.dealer_code,
					COUNT(DISTINCT lb.lead_id) AS breachedLeads
				FROM mmi_lead_breached lb
				JOIN mmi_lead_details mld 
					ON mld.lead_id = lb.lead_id
				LEFT JOIN mmi_dealer_location_mapping dlm 
					ON dlm.mapping_dealer_code = mld.dealer_code
				LEFT JOIN mmi_mast_dealer_location dloc 
					ON dloc.loc_code = dlm.location_code
				GROUP BY mld.assigned_agent,mld.dealer_code
        ) f ON t.agentId = f.agentId AND t.dealer_id = f.dealer_code
    SET 
        t.followUpEfficiency = GREATEST(0,LEAST(100,100 - ROUND(NULLIF(f.breachedLeads, 0) /NULLIF(IFNULL(t.leadsAssigned,0), 0) * 100,2)));
            
            -- QUOTE SHARED
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT cdh.agent_code AS agentId, COUNT(DISTINCT cdh.lead_id) AS QuoteShared
                FROM mmi_call_disposition_history cdh
                LEFT JOIN mmi_agent_disposition_field_response adf ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
                WHERE adf.field_value = 'Shared Quotes'
                GROUP BY cdh.agent_code
            ) x ON t.agentId = x.agentId
            SET t.QuoteShared = x.QuoteShared;
            
            -- CONVERSIONS WITHIN TWO CALLS
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT cdh.agent_code AS agentId,
                       COUNT(DISTINCT CASE WHEN call_rank <= 2 AND lad.lead_status='Won' THEN cdh.lead_id END) AS ConversionsWithinTwoCalls
                FROM (
                    SELECT lead_id, agent_code, call_date,
                           ROW_NUMBER() OVER (PARTITION BY lead_id ORDER BY call_date) AS call_rank
                    FROM mmi_call_disposition_history
                ) cdh
                LEFT JOIN mmi_lead_archive_details lad ON lad.lead_id = cdh.lead_id
                GROUP BY cdh.agent_code
            ) x ON t.agentId = x.agentId
            SET t.ConversionsWithinTwoCalls = x.ConversionsWithinTwoCalls;
            
            -- NET OD PREMIUM
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT assigned_agent AS agentId,
                       SUM(IFNULL(net_od_premium_amount,0) + IFNULL(addon_premium_amount,0)) AS NetODPremium
                FROM mmi_lead_details
                GROUP BY assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.NetODPremium = x.NetODPremium;
            
            
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT team_member AS agentId,
                       SUM(IFNULL(target_value,0)) AS TargetPremium
                FROM mmi_target_planning
                GROUP BY team_member
            ) x ON t.agentId = x.agentId
            SET t.TargetPremium = x.TargetPremium;
            
            -- ADDON SALES
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT ld.assigned_agent AS agentId, COUNT(pad.id) AS AddonSales
                FROM mmi_poladdon_data pad
                JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
                GROUP BY ld.assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.AddonSales = x.AddonSales;
            
            -- PRE DUE RENEWALS
			UPDATE mibl_temp_score_data t
			JOIN (
				SELECT 
					lad.assigned_agent AS agentId,
					COUNT(*) AS PreDueRenewals
				FROM mmi_lead_archive_details lad
				JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
				WHERE lad.lead_status = 'Won'
				  AND lad.converted_flag = 'CRM Renewal'
				  AND DATEDIFF(lad.created_date, mmd.policy_expiry_date) > 10
				GROUP BY lad.assigned_agent
			) x ON t.agentId = x.agentId
			SET t.PreDueRenewals = x.PreDueRenewals;
            
          
                
			-- CONVERSION RATE non filtered
			UPDATE mibl_temp_score_data t
			JOIN (
				SELECT assigned_agent AS agentId,
					   COUNT(DISTINCT CASE WHEN lead_status = 'Won' AND converted_flag = 'CRM Renewal' THEN lead_id END) AS WonLeads
				FROM mmi_lead_archive_details
				GROUP BY assigned_agent
			) x ON t.agentId = x.agentId
			SET t.conversionRate = IFNULL((x.WonLeads / NULLIF(t.LeadsContacted,0)) * 100, 0);
            
            -- RETENTION RATE
            UPDATE mibl_temp_score_data t
            SET t.retentionRate = IFNULL((t.PoliciesConverted / NULLIF(t.LeadsAssigned,0)) * 100, 0);
            
            -- TRIGGER FLAG
            -- UPDATE mibl_temp_score_data t
            -- SET t.TriggerFlag = 1;
            
            UPDATE mibl_temp_score_data t
			SET t.TriggerFlag = 5;
            
            -- PERFORMANCE SCORE calculation
            DROP TEMPORARY TABLE IF EXISTS temp_max_values;
            -- CREATE TEMPORARY TABLE temp_max_values AS
            -- SELECT MAX(LeadsAssigned) AS maxLeadsAssigned FROM mibl_temp_score_data;
            CREATE TEMPORARY TABLE dealer_max_temp AS
			SELECT dealer_id, MAX(LeadsAssigned) AS max_leads FROM mibl_temp_score_data
			GROUP BY dealer_id;
            
            
            /*UPDATE mibl_temp_score_data t
			JOIN dealer_max_temp dm 
				ON t.dealer_id = dm.dealer_id
			SET t.PerformanceScore =
				/*((t.LeadsAssigned / NULLIF(dm.max_leads,0)) * 10)
				+ (IFNULL((t.LeadsContacted / NULLIF(t.LeadsAssigned,0)),0) * 10)
				+ (IFNULL((t.FollowUpsDoneOnTime / NULLIF(t.TotalFollowUpsScheduled,0)),0) * 10)
				+ (IFNULL((t.QuoteShared / NULLIF(t.LeadsContacted,0)),0) * 10)
				+ (IFNULL((t.PoliciesConverted / NULLIF(t.LeadsContacted,0)),0) * 25)
				+ (CASE WHEN t.TriggerFlag <> 0 THEN 5 ELSE 0 END)
				+ (IFNULL((t.PoliciesConverted / NULLIF(t.LeadsAssigned,0)),0) * 15)
				+ (IFNULL((t.ConversionsWithinTwoCalls / NULLIF(t.PoliciesConverted,0)),0) * 5);*/
                /*ROUND((IFNULL(t.LeadsAssigned / NULLIF(AVG(t.LeadsAssigned) OVER (),0), 0) * 100 / 10)
                    + (IFNULL(t.LeadsContacted / NULLIF(t.LeadsAssigned,0), 0) * 10)
                    + (IFNULL((t.FollowUpsDoneOnTime / NULLIF(t.TotalFollowUpsScheduled,0)),0) * 10)
                    + (IFNULL(t.QuoteShared / NULLIF(t.LeadsContacted,0), 0) * 10)
                    + (IFNULL(t.PoliciesConverted / NULLIF(t.LeadsContacted,0), 0) * 25)
                    + (IFNULL(t.PoliciesConverted / NULLIF(t.LeadsAssigned,0), 0) * 15)
                    + (IFNULL(t.ConversionsWithinTwoCalls / NULLIF(t.PoliciesConverted,0), 0)  * 100 * 5 / 100 )
                    -- + (CASE WHEN t.TriggerFlag <> 0 THEN 5 ELSE 0 END)
                    + t.TriggerFlag
                ,2);*/
            
CREATE TEMPORARY TABLE tmp_avg_leads AS
SELECT dealer_id,AVG(LeadsAssigned) AS avg_leads
FROM mibl_temp_score_data
GROUP BY dealer_id;

UPDATE mibl_temp_score_data t
-- JOIN dealer_max_temp dm 
   -- ON t.dealer_id = dm.dealer_id
JOIN tmp_avg_leads a
ON t.dealer_id = a.dealer_id
SET t.PerformanceScore =
    ROUND(
        (IFNULL(t.LeadsAssigned / NULLIF(a.avg_leads,0), 0) * 100 / 10)
        + (IFNULL(t.LeadsContacted / NULLIF(t.LeadsAssigned,0), 0) * 10)
        + (IFNULL(t.FollowUpsDoneOnTime / NULLIF(t.TotalFollowUpsScheduled,0),0) * 10)
        + (IFNULL(t.QuoteShared / NULLIF(t.LeadsContacted,0), 0) * 10)
        + (IFNULL(t.PoliciesConverted / NULLIF(t.LeadsContacted,0), 0) * 25)
        + (IFNULL(t.PoliciesConverted / NULLIF(t.LeadsAssigned,0), 0) * 15)
        + (IFNULL(t.ConversionsWithinTwoCalls / NULLIF(t.PoliciesConverted,0), 0)  * 100 * 5 / 100 )
        + t.TriggerFlag
    ,2);

DROP TEMPORARY TABLE tmp_avg_leads;
    

            -- DYNAMIC PERFORMANCE SCORE
            UPDATE mibl_temp_score_data t
            SET t.DynamicPerformanceScore = 0;
				/*IFNULL(GREATEST(t.NetPremiumCollected - t.TargetPremium,0) / 1000 * 10, 0)
				+ IFNULL(t.NetODPremium / 1000, 0)
				+ IFNULL(t.AddonSales * 5, 0)
				+ IFNULL(t.PreDueRenewals * 10, 0);*/
            
            -- OVERALL SCORE
            UPDATE mibl_temp_score_data t
            SET t.OverallScore = t.PerformanceScore + t.DynamicPerformanceScore;
            
            -- RANK calculation
            DROP TEMPORARY TABLE IF EXISTS temp_ranked_agents;
            CREATE TEMPORARY TABLE temp_ranked_agents AS 
            SELECT agentId, 
                   ROW_NUMBER() OVER (PARTITION BY dealer_id ORDER BY OverallScore DESC, agentId ASC) AS rn
            FROM mibl_temp_score_data;
            
            UPDATE mibl_temp_score_data t
            JOIN temp_ranked_agents r ON t.agentId = r.agentId
            SET t.r = r.rn;
            
            DROP TEMPORARY TABLE IF EXISTS temp_max_values;
            DROP TEMPORARY TABLE IF EXISTS temp_ranked_agents;
            
            
		 -- FINAL OUTPUT per dealer max, raw breakdowns
		DROP TEMPORARY TABLE IF EXISTS dealer_max_temp;
		CREATE TEMPORARY TABLE dealer_max_temp AS
		SELECT dealer_id, MAX(leadsAssigned) AS max_leads
		FROM mibl_temp_score_data
		GROUP BY dealer_id;

		/*SELECT 
			t.dealer_id AS dealerId,
			t.dealer_name AS dealerName,
			t.agentId,
			t.agentName,
			t.leadsAssigned,
			t.leadsContacted,
			t.policiesConverted,
			t.netPremiumCollected,
			-- follow up efficiency perc (rounded)
			ROUND(IFNULL(t.FollowUpsDoneOnTime / NULLIF(t.TotalFollowUpsScheduled,0),0) * 100, 2) AS followUpEfficiency,
			-- Conversion & retention rates (rounded)
			ROUND(t.conversionRate, 2) AS conversionRate,
			ROUND(t.retentionRate, 2) AS retentionRate,
			-- performanceScore (rounded)
			ROUND(
				(IFNULL(t.leadsAssigned / NULLIF(dm.max_leads, 0), 0) * 10)
				+ (IFNULL(t.leadsContacted / NULLIF(t.leadsAssigned,0), 0) * 10)
				+ IFNULL((t.FollowUpsDoneOnTime / NULLIF(t.TotalFollowUpsScheduled,0)),0) * 10
				+ (IFNULL(t.QuoteShared / NULLIF(t.leadsContacted,0), 0) * 10)
				+ (IFNULL(t.policiesConverted / NULLIF(t.leadsContacted,0), 0) * 25)
				+ (CASE WHEN t.TriggerFlag <> 0 THEN 5 ELSE 0 END)
				+ (IFNULL(t.policiesConverted / NULLIF(t.leadsAssigned,0), 0) * 15)
				+ (IFNULL(t.ConversionsWithinTwoCalls / NULLIF(t.policiesConverted,0), 0) * 5)
			, 2) AS performanceScore,
			-- dynamicPerformanceScore (rounded)
			/*ROUND(
				IFNULL(GREATEST(t.NetPremiumCollected - t.TargetPremium, 0) / 1000 * 10, 0)
				+ IFNULL(t.NetODPremium / 1000, 0)
				+ IFNULL(t.AddonSales * 5, 0)
				+ IFNULL(t.PreDueRenewals * 10, 0)
			, 2) AS dynamicPerformanceScore,*/
          /*  0 AS DynamicPerformanceScore,
			-- overallScore (rounded)
			ROUND(
				(IFNULL(t.leadsAssigned / NULLIF(dm.max_leads, 0), 0) * 10)
				+ (IFNULL(t.leadsContacted / NULLIF(t.leadsAssigned,0), 0) * 10)
				+ IFNULL((t.FollowUpsDoneOnTime / NULLIF(t.TotalFollowUpsScheduled,0)),0) * 10
				+ (IFNULL(t.QuoteShared / NULLIF(t.leadsContacted,0), 0) * 10)
				+ (IFNULL(t.policiesConverted / NULLIF(t.leadsContacted,0), 0) * 25)
				+ (CASE WHEN t.TriggerFlag <> 0 THEN 5 ELSE 0 END)
				+ (IFNULL(t.policiesConverted / NULLIF(t.leadsAssigned,0), 0) * 15)
				+ (IFNULL(t.ConversionsWithinTwoCalls / NULLIF(t.policiesConverted,0), 0) * 5)
				+ IFNULL(GREATEST(t.NetPremiumCollected - t.TargetPremium, 0) / 1000 * 10, 0)
				+ IFNULL(t.NetODPremium / 1000, 0)
				+ IFNULL(t.AddonSales * 5, 0)
				+ IFNULL(t.PreDueRenewals * 10, 0)
			, 2) AS overallScore,
				t.QuoteShared,
				t.ConversionsWithinTwoCalls,
				t.TriggerFlag,
				t.TargetPremium,
				t.NetODPremium,
				t.AddonSales,
				t.PreDueRenewals,
			-- Rank per dealer
				ROW_NUMBER() OVER (PARTITION BY t.dealer_id ORDER BY (performanceScore + dynamicPerformanceScore) DESC) AS `rank`,
				-- raw breakdown components 
				ROUND((IFNULL(t.leadsAssigned / NULLIF(dm.max_leads, 0), 0) * 10), 2) AS leadsAssignedScore,
				ROUND((IFNULL(t.leadsContacted / NULLIF(t.leadsAssigned,0), 0) * 10), 2) AS contactRateScore,
				ROUND((IFNULL((t.FollowUpsDoneOnTime / NULLIF(t.TotalFollowUpsScheduled,0)),0) * 10), 2) AS followUpScore,
				ROUND((IFNULL(t.QuoteShared / NULLIF(t.leadsContacted,0), 0) * 10), 2) AS quoteShareScore,
				ROUND((IFNULL(t.policiesConverted / NULLIF(t.leadsContacted,0), 0) * 25), 2) AS conversionScore,
				ROUND((IFNULL(t.policiesConverted / NULLIF(t.leadsAssigned,0), 0) * 15), 2) AS retentionScore,
				ROUND((IFNULL(t.ConversionsWithinTwoCalls / NULLIF(t.policiesConverted,0), 0) * 5), 2) AS shortestCallToConversion,
				ROUND((IFNULL(GREATEST(t.NetPremiumCollected - t.TargetPremium, 0) / 1000 * 10, 0)), 2) AS netPremiumScore,
				ROUND((IFNULL(t.NetODPremium / 1000, 0)), 2) AS netODPremiumScore,
				ROUND((IFNULL(t.AddonSales * 5, 0)), 2) AS addonSalesScore,
				ROUND((IFNULL(t.PreDueRenewals * 10, 0)), 2) AS preDueRenewalsScore,
				t.TriggerFlag AS triggerFlag
				FROM mibl_temp_score_data t
				JOIN dealer_max_temp dm ON t.dealer_id = dm.dealer_id
				ORDER BY t.dealer_id, `rank`;*/
                
                 CREATE TEMPORARY TABLE tmp_avg_leads AS
				SELECT dealer_id,AVG(LeadsAssigned) AS avg_leads
				FROM mibl_temp_score_data
                GROUP BY dealer_id;
                
              SELECT 
        t.dealer_id AS dealerId,
        t.dealer_name AS dealerName,
        t.agentId,
        t.agentName,
        t.leadsAssigned,
        t.leadsContacted,
        t.policiesConverted,
        t.netPremiumCollected,
        t.followUpEfficiency,
        -- ROUND(IFNULL(t.FollowUpsDoneOnTime / NULLIF(t.TotalFollowUpsScheduled,0),0) * 100, 2) AS followUpEfficiency,
        ROUND(t.conversionRate, 2) AS conversionRate,
        ROUND(t.retentionRate, 2) AS retentionRate,
        ROUND(t.PerformanceScore, 2) AS performanceScore,
        ROUND(t.DynamicPerformanceScore, 2) AS dynamicPerformanceScore,
        ROUND(t.OverallScore, 2) AS overallScore,
        t.r AS `rank`,
        ROUND((IFNULL(t.leadsAssigned / NULLIF(dm.avg_leads, 0), 0) * 100 / 10), 2) AS leadsAssignedScore,
        ROUND((IFNULL(t.leadsContacted / NULLIF(t.leadsAssigned,0), 0) * 10), 2) AS contactRateScore,
        ROUND((IFNULL((t.FollowUpsDoneOnTime / NULLIF(t.TotalFollowUpsScheduled,0)),0) * 10), 2) AS followUpScore,
        ROUND((IFNULL(t.QuoteShared / NULLIF(t.leadsContacted,0), 0) * 10), 2) AS quoteShareScore,
        ROUND((IFNULL(t.policiesConverted / NULLIF(t.leadsContacted,0), 0) * 25), 2) AS conversionScore,
        ROUND((IFNULL(t.policiesConverted / NULLIF(t.leadsAssigned,0), 0) * 15), 2) AS retentionScore,
        ROUND((IFNULL(t.ConversionsWithinTwoCalls / NULLIF(t.policiesConverted,0), 0) * 100 * 5 / 100), 2) AS shortestCallToConversion,
        
        -- ROUND((IFNULL(GREATEST(t.NetPremiumCollected - t.TargetPremium, 0) / 1000 * 10, 0)), 2) AS netPremiumScore,
        -- ROUND((IFNULL(t.NetODPremium / 1000, 0)), 2) AS netODPremiumScore,
        -- ROUND((IFNULL(t.AddonSales * 5, 0)), 2) AS addonSalesScore,
        -- ROUND((IFNULL(t.PreDueRenewals * 10, 0)), 2) AS preDueRenewalsScore,
        
        0 AS netPremiumScore,
		0 AS netODPremiumScore,
		0 AS addonSalesScore,
		0 AS preDueRenewalsScore,
        
        t.TriggerFlag AS TriggerFlag
    FROM mibl_temp_score_data t
    -- JOIN dealer_max_temp dm ON t.dealer_id = dm.dealer_id
    JOIN tmp_avg_leads dm ON t.dealer_id = dm.dealer_id 
    ORDER BY t.dealer_id, t.r;
  

				DROP TEMPORARY TABLE IF EXISTS dealer_max_temp;
                DROP TEMPORARY TABLE IF EXISTS tmp_avg_leads;
                
        
        END IF;
    
    END IF;
    
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_get_agent_performance_dashboard_temp` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_agent_performance_dashboard_temp`(
    IN Json_data JSON,
    OUT SP_STATUS VARCHAR(500),
    OUT MESSAGE VARCHAR(500))
BEGIN
    -- =========================
    -- DECLARE VARIABLES
    -- =========================
    DECLARE v_type VARCHAR(20);
    DECLARE v_role_type VARCHAR(100);
    DECLARE v_check_type VARCHAR(100);
    DECLARE v_dealerId VARCHAR(550);
    DECLARE v_startDate VARCHAR(550);
    DECLARE v_endDate VARCHAR(550);
    DECLARE v_zone VARCHAR(100);
    DECLARE v_state VARCHAR(550);
    DECLARE v_segment VARCHAR(550);
    DECLARE v_renewal_category VARCHAR(1000);
    DECLARE v_dealerLocCode VARCHAR(550);
    
    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            @sqlstate = RETURNED_SQLSTATE, errno = MYSQL_ERRNO, errmsg = MESSAGE_TEXT;
        SET SP_STATUS = 407;
        SET MESSAGE = 'Something went wrong.';

        INSERT INTO mmi_mast_procedure_error (error_code, error_message, procedure_name, procedure_type, ERROR_TIMING, created_by, created_date)
        VALUES (errno, CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg), 'mmi_proc_get_agent_performance_dashboard_temp', 'PERFORMANCE_DASHBOARD', CURRENT_TIMESTAMP(), 'SYSTEM', NOW());
    END;
    
    -- =========================
    -- EXTRACT JSON VALUES
    -- =========================
    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.type'));
    SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleType'));
    SET v_check_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.checkType'));
    SET v_dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
    
    -- Handle both startDate/endDate and fromDate/toDate
    SET v_startDate = COALESCE(
        NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.startDate')), ''),
        NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.fromDate')), '')
    );
    SET v_endDate = COALESCE(
        NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.endDate')), ''),
        NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.toDate')), '')
    );
    
    SET v_zone = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.zone')), '');
    SET v_state = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.state')), '');
    SET v_segment = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.segment')), '');
    SET v_renewal_category = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalCategory')), '');
    SET v_dealerLocCode = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerLocCode')), '');
    
    -- =========================
    -- MIBL ROLE LOGIC
    -- =========================
    IF v_role_type = 'mibl' THEN
    
        -- ===========================================
        -- BLOCK 1: FILTER DATA (with all filters applied)
        -- ===========================================
        IF v_type = 'miblFilterExcel' THEN
        
            DROP TEMPORARY TABLE IF EXISTS mibl_temp_score_data;
            
            CREATE TEMPORARY TABLE mibl_temp_score_data (
                dealer_id VARCHAR(45),
                dealer_name VARCHAR(255),
                agentId INT,
                agentName VARCHAR(255),
                leadsAssigned INT DEFAULT 0,
                leadsContacted INT DEFAULT 0,
                policiesConverted INT DEFAULT 0,
                netPremiumCollected DECIMAL(12,2) DEFAULT 0,
                conversionRate DECIMAL(6,2) DEFAULT 0,
                retentionRate DECIMAL(6,2) DEFAULT 0,
                followUpEfficiency DECIMAL(10,2) DEFAULT 0,
                QuoteShared INT DEFAULT 0,
                ConversionsWithinTwoCalls INT DEFAULT 0,
                TriggerFlag INT DEFAULT 0,
                TargetPremium DECIMAL(12,2) DEFAULT 50000,
                NetODPremium DECIMAL(12,2) DEFAULT 0,
                AddonSales INT DEFAULT 0,
                PreDueRenewals INT DEFAULT 0,
                PerformanceScore DECIMAL(12,2) DEFAULT 0,
                DynamicPerformanceScore DECIMAL(12,2) DEFAULT 0,
                OverallScore DECIMAL(12,2) DEFAULT 0,
                r INT DEFAULT 0
            );
            
            -- Base agent insertion with dealer mapping
            INSERT INTO mibl_temp_score_data (dealer_id, dealer_name, agentId, agentName)
            SELECT DISTINCT
                dlm.dealer_code AS dealer_id,
                md.dealer_name,
                udm.user_id AS agentId,
                CONCAT(IFNULL(mud.first_name,''), ' ', IFNULL(mud.last_name,'')) AS agentName
            FROM mmi_user_dealer_mapping udm
            JOIN mmi_mast_user_registration_detail mud ON udm.user_id = mud.id
            JOIN mmi_dealer_location_mapping dlm ON udm.dealer_id = dlm.dealer_code
            LEFT JOIN mmi_dealer_location_mapping md ON md.mapping_dealer_code = dlm.dealer_code
            WHERE 1=1;
                -- AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(dlm.dealer_code, v_dealerId));
            
            -- LEADS ASSIGNED (with filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT assigned_agent, COUNT(DISTINCT lead_id) AS leadsAssigned
                FROM (
                    SELECT ld.assigned_agent, ld.lead_id
                    FROM mmi_lead_details ld
                    LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
                    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                    WHERE 1=1
                        AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '' 
                            OR ld.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d') 
                                AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
                        AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(ld.vehicle_class, v_segment))
                        AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(ld.renewal_category, v_renewal_category))
                        AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(dlm.zone, v_zone))
                        AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(dloc.state, v_state))
                        AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
                        AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(ld.dealer_code, v_dealerId))
                    
                    UNION ALL
                    
                    SELECT ld.assigned_agent, ld.lead_id
                    FROM mmi_lead_archive_details ld
                    LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
                    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                    WHERE 1=1
                        AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '' 
                            OR ld.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d') 
                                AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
                        AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(ld.vehicle_class, v_segment))
                        AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(ld.renewal_category, v_renewal_category))
                        AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(dlm.zone, v_zone))
                        AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(dloc.state, v_state))
                        AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
                        AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(ld.dealer_code, v_dealerId))
                ) combined
                GROUP BY assigned_agent
            ) x ON t.agentId = x.assigned_agent
            SET t.LeadsAssigned = x.LeadsAssigned;
            
            -- LEADS CONTACTED (with filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT cdh.agent_code AS agentId, COUNT(DISTINCT cdh.lead_id) AS leadsContacted
                FROM mmi_call_disposition_history cdh
                JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
                LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
                LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                WHERE 1=1
                    AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '' 
                        OR ld.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d') 
                            AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
                    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(ld.vehicle_class, v_segment))
                    AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(ld.renewal_category, v_renewal_category))
                    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(dlm.zone, v_zone))
                    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(dloc.state, v_state))
                    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
                    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(ld.dealer_code, v_dealerId))
                GROUP BY cdh.agent_code
                
                UNION ALL
                
                SELECT cdh.agent_code AS agentId, COUNT(DISTINCT cdh.lead_id) AS leadsContacted
                FROM mmi_call_disposition_history cdh
                JOIN mmi_lead_archive_details ld ON ld.lead_id = cdh.lead_id
                LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
                LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                WHERE 1=1
                    AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '' 
                        OR ld.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d') 
                            AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
                    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(ld.vehicle_class, v_segment))
                    AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(ld.renewal_category, v_renewal_category))
                    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(dlm.zone, v_zone))
                    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(dloc.state, v_state))
                    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
                    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(ld.dealer_code, v_dealerId))
                GROUP BY cdh.agent_code
            ) x ON t.agentId = x.agentId
            SET t.LeadsContacted = x.LeadsContacted;
            
            -- POLICIES CONVERTED (with filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT assigned_agent AS agentId, COUNT(DISTINCT policy_no) AS policiesConverted
                FROM mmi_lead_archive_details lad
                LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
                LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                WHERE lad.lead_status = 'Won' AND lad.converted_flag = 'CRM Renewal'
                    AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '' 
                        OR lad.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d') 
                            AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
                    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(lad.vehicle_class, v_segment))
                    AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(lad.renewal_category, v_renewal_category))
                    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(dlm.zone, v_zone))
                    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(dloc.state, v_state))
                    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
                    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(lad.dealer_code, v_dealerId))
                GROUP BY assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.PoliciesConverted = x.PoliciesConverted;
            
            -- NET PREMIUM COLLECTED (with filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT lad.assigned_agent AS agentId, SUM(CAST(mmd.net_premium AS DECIMAL(12,2))) AS netPremiumCollected
                FROM mmi_lead_archive_details lad
                JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
                LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
                LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                WHERE lad.lead_status = 'Won'
                    AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '' 
                        OR lad.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d') 
                            AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
                    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(lad.vehicle_class, v_segment))
                    AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(lad.renewal_category, v_renewal_category))
                    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(dlm.zone, v_zone))
                    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(dloc.state, v_state))
                    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
                    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(lad.dealer_code, v_dealerId))
                GROUP BY lad.assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.NetPremiumCollected = x.NetPremiumCollected;
            
            -- FOLLOW UP EFFICIENCY (with filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT 
                    cdh.agent_code AS agentId,
                    COUNT(CASE WHEN next_call_datetime IS NOT NULL THEN 1 END) AS TotalFollowUpsScheduled,
                    COUNT(CASE WHEN next_call_datetime IS NOT NULL 
                               AND call_date <= STR_TO_DATE(next_call_datetime,'%Y-%m-%d %H:%i:%s') THEN 1 END) AS FollowUpsDoneOnTime
                FROM mmi_call_disposition_history cdh
                JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
                LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
                LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                WHERE 1=1
                    AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '' 
                        OR ld.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d') 
                            AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
                    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(ld.vehicle_class, v_segment))
                    AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(ld.renewal_category, v_renewal_category))
                    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(dlm.zone, v_zone))
                    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(dloc.state, v_state))
                    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
                    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(ld.dealer_code, v_dealerId))
                GROUP BY cdh.agent_code
            ) f ON t.agentId = f.agentId
            SET t.followUpEfficiency = IFNULL(
                ROUND((IFNULL(f.FollowUpsDoneOnTime,0) / NULLIF(IFNULL(f.TotalFollowUpsScheduled,0),0)) * 100, 2), 0);
            
            -- QUOTE SHARED (with filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT cdh.agent_code AS agentId, COUNT(DISTINCT cdh.lead_id) AS QuoteShared
                FROM mmi_call_disposition_history cdh
                LEFT JOIN mmi_agent_disposition_field_response adf ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
                JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
                LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
                LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                WHERE adf.field_value = 'Shared Quotes'
                    AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '' 
                        OR ld.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d') 
                            AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
                    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(ld.vehicle_class, v_segment))
                    AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(ld.renewal_category, v_renewal_category))
                    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(dlm.zone, v_zone))
                    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(dloc.state, v_state))
                    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
                    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(ld.dealer_code, v_dealerId))
                GROUP BY cdh.agent_code
            ) x ON t.agentId = x.agentId
            SET t.QuoteShared = x.QuoteShared;
            
            -- CONVERSIONS WITHIN TWO CALLS (with filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT cdh.agent_code AS agentId,
                       COUNT(DISTINCT CASE WHEN call_rank <= 2 AND lad.lead_status='Won' THEN cdh.lead_id END) AS ConversionsWithinTwoCalls
                FROM (
                    SELECT lead_id, agent_code, call_date,
                           ROW_NUMBER() OVER (PARTITION BY lead_id ORDER BY call_date) AS call_rank
                    FROM mmi_call_disposition_history
                ) cdh
                LEFT JOIN mmi_lead_archive_details lad ON lad.lead_id = cdh.lead_id
                LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
                LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                WHERE 1=1
                    AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '' 
                        OR lad.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d') 
                            AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
                    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(lad.vehicle_class, v_segment))
                    AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(lad.renewal_category, v_renewal_category))
                    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(dlm.zone, v_zone))
                    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(dloc.state, v_state))
                    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
                    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(lad.dealer_code, v_dealerId))
                GROUP BY cdh.agent_code
            ) x ON t.agentId = x.agentId
            SET t.ConversionsWithinTwoCalls = x.ConversionsWithinTwoCalls;
            
            -- NET OD PREMIUM (with filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT assigned_agent AS agentId,
                       SUM(IFNULL(net_od_premium_amount,0) + IFNULL(addon_premium_amount,0)) AS NetODPremium
                FROM mmi_lead_details ld
                LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
                LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                WHERE 1=1
                    AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '' 
                        OR ld.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d') 
                            AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
                    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(ld.vehicle_class, v_segment))
                    AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(ld.renewal_category, v_renewal_category))
                    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(dlm.zone, v_zone))
                    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(dloc.state, v_state))
                    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
                    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(ld.dealer_code, v_dealerId))
                GROUP BY assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.NetODPremium = x.NetODPremium;
            
            -- ADDON SALES (with filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT ld.assigned_agent AS agentId, COUNT(pad.id) AS AddonSales
                FROM mmi_poladdon_data pad
                JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
                LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
                LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                WHERE 1=1
                    AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '' 
                        OR ld.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d') 
                            AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
                    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(ld.vehicle_class, v_segment))
                    AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(ld.renewal_category, v_renewal_category))
                    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(dlm.zone, v_zone))
                    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(dloc.state, v_state))
                    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
                    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(ld.dealer_code, v_dealerId))
                GROUP BY ld.assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.AddonSales = x.AddonSales;
            
            -- PRE DUE RENEWALS (with filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT assigned_agent AS agentId, COUNT(*) AS PreDueRenewals
                FROM mmi_lead_details ld
                LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = ld.dealer_code
                LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                WHERE 1=1
                    AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '' 
                        OR ld.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d') 
                            AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
                    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(ld.vehicle_class, v_segment))
                    AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(ld.renewal_category, v_renewal_category))
                    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(dlm.zone, v_zone))
                    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(dloc.state, v_state))
                    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
                    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(ld.dealer_code, v_dealerId))
                GROUP BY assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.PreDueRenewals = x.PreDueRenewals;
            
            -- CONVERSION RATE (Won Leads with filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT assigned_agent AS agentId,
                       COUNT(DISTINCT CASE WHEN lead_status = 'Won' AND converted_flag = 'CRM Renewal' THEN lead_id END) AS WonLeads
                FROM mmi_lead_archive_details lad
                LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = lad.dealer_code
                LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dlm.location_code
                WHERE 1=1
                    AND (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '' 
                        OR lad.created_date BETWEEN STR_TO_DATE(v_startDate,'%Y-%m-%d') 
                            AND DATE_ADD(STR_TO_DATE(v_endDate,'%Y-%m-%d'), INTERVAL 1 DAY))
                    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(lad.vehicle_class, v_segment))
                    AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(lad.renewal_category, v_renewal_category))
                    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(dlm.zone, v_zone))
                    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(dloc.state, v_state))
                    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(dloc.loc_code, v_dealerLocCode))
                    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(lad.dealer_code, v_dealerId))
                GROUP BY assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.conversionRate = IFNULL(ROUND((x.WonLeads / NULLIF(t.LeadsContacted,0)) * 100, 2), 0);
            
            -- RETENTION RATE
            UPDATE mibl_temp_score_data t
            SET t.retentionRate = IFNULL(ROUND((t.PoliciesConverted / NULLIF(t.LeadsAssigned,0)) * 100, 2), 0);
            
            -- TRIGGER FLAG
            UPDATE mibl_temp_score_data t
            SET t.TriggerFlag = 1;
            
            -- PERFORMANCE SCORE calculation
            DROP TEMPORARY TABLE IF EXISTS temp_max_values;
            CREATE TEMPORARY TABLE temp_max_values AS
            SELECT MAX(LeadsAssigned) AS maxLeadsAssigned FROM mibl_temp_score_data;
            
            UPDATE mibl_temp_score_data t
            JOIN temp_max_values m
            SET t.PerformanceScore = ROUND(
                ((t.LeadsAssigned / NULLIF(m.maxLeadsAssigned,0)) * 100 * 10 / 100)
                + (IFNULL((t.LeadsContacted / NULLIF(t.LeadsAssigned,0)),0) * 100 * 10 / 100)
                + (IFNULL((t.followUpEfficiency / 100),0) * 100 * 10 / 100)
                + (IFNULL((t.QuoteShared / NULLIF(t.LeadsContacted,0)),0) * 100 * 10 / 100)
                + (IFNULL((t.PoliciesConverted / NULLIF(t.LeadsContacted,0)),0) * 100 * 25 / 100)
                + (CASE WHEN t.TriggerFlag <> 0 THEN 5 ELSE 0 END)
                + (IFNULL((t.PoliciesConverted / NULLIF(t.LeadsAssigned,0)),0) * 100 * 15 / 100)
                + (IFNULL((t.ConversionsWithinTwoCalls / NULLIF(t.PoliciesConverted,0)),0) * 100 * 5 / 100)
            , 2);
            
            -- DYNAMIC PERFORMANCE SCORE
            UPDATE mibl_temp_score_data t
            SET t.DynamicPerformanceScore = ROUND(
                IFNULL(GREATEST(t.NetPremiumCollected - t.TargetPremium,0) / 1000 * 10, 0)
                + IFNULL(t.NetODPremium / 1000, 0)
                + IFNULL(t.AddonSales * 5, 0)
                + IFNULL(t.PreDueRenewals * 10, 0)
            , 2);
            
            -- OVERALL SCORE
            UPDATE mibl_temp_score_data t
            SET t.OverallScore = t.PerformanceScore + t.DynamicPerformanceScore;
            
            -- RANK calculation
            DROP TEMPORARY TABLE IF EXISTS temp_ranked_agents;
            CREATE TEMPORARY TABLE temp_ranked_agents AS
            SELECT agentId, ROW_NUMBER() OVER (ORDER BY OverallScore DESC) AS rn
            FROM mibl_temp_score_data;
            
            UPDATE mibl_temp_score_data t
            JOIN temp_ranked_agents r ON t.agentId = r.agentId
            SET t.r = r.rn;
            
            DROP TEMPORARY TABLE IF EXISTS temp_max_values;
            DROP TEMPORARY TABLE IF EXISTS temp_ranked_agents;
            
            -- Final output
            SELECT 
                dealer_id AS dealerId,
                dealer_name AS dealerName,
                agentId,
                agentName,
                leadsAssigned,
                leadsContacted,
                policiesConverted,
                netPremiumCollected,
                followUpEfficiency,
                conversionRate,
                retentionRate,
                PerformanceScore,
                DynamicPerformanceScore,
                OverallScore,
                QuoteShared,
    ConversionsWithinTwoCalls,
    TriggerFlag,
    TargetPremium,
    NetODPremium,
    AddonSales,
    PreDueRenewals,
                r AS `rank`
            FROM mibl_temp_score_data
            ORDER BY OverallScore DESC;
            
            SET SP_STATUS = '200';
            SET MESSAGE = 'MIBL Performance Dashboard Filter Data Fetched Successfully';
        
        -- ===========================================
        -- BLOCK 2: NON-FILTER DATA (PerformanceBoard - no filters)
        -- ===========================================
        ELSEIF v_type = 'miblExcel' THEN
        
            DROP TEMPORARY TABLE IF EXISTS mibl_temp_score_data;
            
            CREATE TEMPORARY TABLE mibl_temp_score_data (
                dealer_id VARCHAR(45),
                dealer_name VARCHAR(255),
                agentId INT,
                agentName VARCHAR(255),
                leadsAssigned INT DEFAULT 0,
                leadsContacted INT DEFAULT 0,
                policiesConverted INT DEFAULT 0,
                netPremiumCollected DECIMAL(12,2) DEFAULT 0,
                conversionRate DECIMAL(6,2) DEFAULT 0,
                retentionRate DECIMAL(6,2) DEFAULT 0,
                followUpEfficiency DECIMAL(10,2) DEFAULT 0,
                QuoteShared INT DEFAULT 0,
                ConversionsWithinTwoCalls INT DEFAULT 0,
                TriggerFlag INT DEFAULT 0,
                TargetPremium DECIMAL(12,2) DEFAULT 50000,
                NetODPremium DECIMAL(12,2) DEFAULT 0,
                AddonSales INT DEFAULT 0,
                PreDueRenewals INT DEFAULT 0,
                PerformanceScore DECIMAL(12,2) DEFAULT 0,
                DynamicPerformanceScore DECIMAL(12,2) DEFAULT 0,
                OverallScore DECIMAL(12,2) DEFAULT 0,
                r INT DEFAULT 0
            );
            
            -- Base agent insertion with dealer mapping
            INSERT INTO mibl_temp_score_data (dealer_id, dealer_name, agentId, agentName)
            SELECT DISTINCT
                dlm.dealer_code AS dealer_id,
                md.dealer_name,
                udm.user_id AS agentId,
                CONCAT(IFNULL(mud.first_name,''), ' ', IFNULL(mud.last_name,'')) AS agentName
            FROM mmi_user_dealer_mapping udm
            JOIN mmi_mast_user_registration_detail mud ON udm.user_id = mud.id
            JOIN mmi_dealer_location_mapping dlm ON udm.dealer_id = dlm.dealer_code
            LEFT JOIN mmi_dealer_location_mapping md ON md.mapping_dealer_code = dlm.dealer_code
            WHERE 1=1;
                -- AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(dlm.dealer_code, v_dealerId));
            
            -- LEADS ASSIGNED (without filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT assigned_agent, COUNT(DISTINCT lead_id) AS leadsAssigned
                FROM (
                    SELECT assigned_agent, lead_id FROM mmi_lead_details
                    UNION ALL
                    SELECT assigned_agent, lead_id FROM mmi_lead_archive_details
                ) combined
                GROUP BY assigned_agent
            ) x ON t.agentId = x.assigned_agent
            SET t.LeadsAssigned = x.LeadsAssigned;
            
            -- LEADS CONTACTED (without filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT cdh.agent_code AS agentId, COUNT(DISTINCT cdh.lead_id) AS leadsContacted
                FROM mmi_call_disposition_history cdh
                GROUP BY cdh.agent_code
            ) x ON t.agentId = x.agentId
            SET t.LeadsContacted = x.LeadsContacted;
            
            -- POLICIES CONVERTED (without filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT assigned_agent AS agentId, COUNT(DISTINCT policy_no) AS policiesConverted
                FROM mmi_lead_archive_details
                WHERE lead_status = 'Won' AND converted_flag = 'CRM Renewal'
                GROUP BY assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.PoliciesConverted = x.PoliciesConverted;
            
            -- NET PREMIUM COLLECTED (without filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT lad.assigned_agent AS agentId, SUM(CAST(mmd.net_premium AS DECIMAL(12,2))) AS netPremiumCollected
                FROM mmi_lead_archive_details lad
                JOIN mmi_ebm_policy_data mmd ON lad.policy_no = mmd.previous_policy_no
                WHERE lad.lead_status = 'Won'
                GROUP BY lad.assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.NetPremiumCollected = x.NetPremiumCollected;
            
            -- FOLLOW UP EFFICIENCY (without filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT 
                    cdh.agent_code AS agentId,
                    COUNT(CASE WHEN next_call_datetime IS NOT NULL THEN 1 END) AS TotalFollowUpsScheduled,
                    COUNT(CASE WHEN next_call_datetime IS NOT NULL 
                               AND call_date <= STR_TO_DATE(next_call_datetime,'%Y-%m-%d %H:%i:%s') THEN 1 END) AS FollowUpsDoneOnTime
                FROM mmi_call_disposition_history cdh
                GROUP BY cdh.agent_code
            ) f ON t.agentId = f.agentId
            SET t.followUpEfficiency = IFNULL(
                ROUND((IFNULL(f.FollowUpsDoneOnTime,0) / NULLIF(IFNULL(f.TotalFollowUpsScheduled,0),0)) * 100, 2), 0);
            
            -- QUOTE SHARED (without filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT cdh.agent_code AS agentId, COUNT(DISTINCT cdh.lead_id) AS QuoteShared
                FROM mmi_call_disposition_history cdh
                LEFT JOIN mmi_agent_disposition_field_response adf ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
                WHERE adf.field_value = 'Shared Quotes'
                GROUP BY cdh.agent_code
            ) x ON t.agentId = x.agentId
            SET t.QuoteShared = x.QuoteShared;
            
            -- CONVERSIONS WITHIN TWO CALLS (without filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT cdh.agent_code AS agentId,
                       COUNT(DISTINCT CASE WHEN call_rank <= 2 AND lad.lead_status='Won' THEN cdh.lead_id END) AS ConversionsWithinTwoCalls
                FROM (
                    SELECT lead_id, agent_code, call_date,
                           ROW_NUMBER() OVER (PARTITION BY lead_id ORDER BY call_date) AS call_rank
                    FROM mmi_call_disposition_history
                ) cdh
                LEFT JOIN mmi_lead_archive_details lad ON lad.lead_id = cdh.lead_id
                GROUP BY cdh.agent_code
            ) x ON t.agentId = x.agentId
            SET t.ConversionsWithinTwoCalls = x.ConversionsWithinTwoCalls;
            
            -- NET OD PREMIUM (without filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT assigned_agent AS agentId,
                       SUM(IFNULL(net_od_premium_amount,0) + IFNULL(addon_premium_amount,0)) AS NetODPremium
                FROM mmi_lead_details
                GROUP BY assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.NetODPremium = x.NetODPremium;
            
            -- ADDON SALES (without filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT ld.assigned_agent AS agentId, COUNT(pad.id) AS AddonSales
                FROM mmi_poladdon_data pad
                JOIN mmi_lead_details ld ON ld.policy_no = pad.policy_no
                GROUP BY ld.assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.AddonSales = x.AddonSales;
            
            -- PRE DUE RENEWALS (without filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT assigned_agent AS agentId, COUNT(*) AS PreDueRenewals
                FROM mmi_lead_details
                GROUP BY assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.PreDueRenewals = x.PreDueRenewals;
            
            -- CONVERSION RATE (without filters)
            UPDATE mibl_temp_score_data t
            JOIN (
                SELECT assigned_agent AS agentId,
                       COUNT(DISTINCT CASE WHEN lead_status = 'Won' AND converted_flag = 'CRM Renewal' THEN lead_id END) AS WonLeads
                FROM mmi_lead_archive_details
                GROUP BY assigned_agent
            ) x ON t.agentId = x.agentId
            SET t.conversionRate = IFNULL(ROUND((x.WonLeads / NULLIF(t.LeadsContacted,0)) * 100, 2), 0);
            
            -- RETENTION RATE
            UPDATE mibl_temp_score_data t
            SET t.retentionRate = IFNULL(ROUND((t.PoliciesConverted / NULLIF(t.LeadsAssigned,0)) * 100, 2), 0);
            
            -- TRIGGER FLAG
            UPDATE mibl_temp_score_data t
            SET t.TriggerFlag = 1;
            
            -- PERFORMANCE SCORE calculation
            DROP TEMPORARY TABLE IF EXISTS temp_max_values;
            CREATE TEMPORARY TABLE temp_max_values AS
            SELECT MAX(LeadsAssigned) AS maxLeadsAssigned FROM mibl_temp_score_data;
            
            UPDATE mibl_temp_score_data t
            JOIN temp_max_values m
            SET t.PerformanceScore = ROUND(
                ((t.LeadsAssigned / NULLIF(m.maxLeadsAssigned,0)) * 100 * 10 / 100)
                + (IFNULL((t.LeadsContacted / NULLIF(t.LeadsAssigned,0)),0) * 100 * 10 / 100)
                + (IFNULL((t.followUpEfficiency / 100),0) * 100 * 10 / 100)
                + (IFNULL((t.QuoteShared / NULLIF(t.LeadsContacted,0)),0) * 100 * 10 / 100)
                + (IFNULL((t.PoliciesConverted / NULLIF(t.LeadsContacted,0)),0) * 100 * 25 / 100)
                + (CASE WHEN t.TriggerFlag <> 0 THEN 5 ELSE 0 END)
                + (IFNULL((t.PoliciesConverted / NULLIF(t.LeadsAssigned,0)),0) * 100 * 15 / 100)
                + (IFNULL((t.ConversionsWithinTwoCalls / NULLIF(t.PoliciesConverted,0)),0) * 100 * 5 / 100)
            , 2);
            
            -- DYNAMIC PERFORMANCE SCORE
            UPDATE mibl_temp_score_data t
            SET t.DynamicPerformanceScore = ROUND(
                IFNULL(GREATEST(t.NetPremiumCollected - t.TargetPremium,0) / 1000 * 10, 0)
                + IFNULL(t.NetODPremium / 1000, 0)
                + IFNULL(t.AddonSales * 5, 0)
                + IFNULL(t.PreDueRenewals * 10, 0)
            , 2);
            
            -- OVERALL SCORE
            UPDATE mibl_temp_score_data t
            SET t.OverallScore = t.PerformanceScore + t.DynamicPerformanceScore;
            
            -- RANK calculation
            DROP TEMPORARY TABLE IF EXISTS temp_ranked_agents;
            CREATE TEMPORARY TABLE temp_ranked_agents AS
            SELECT agentId, ROW_NUMBER() OVER (ORDER BY OverallScore DESC) AS rn
            FROM mibl_temp_score_data;
            
            UPDATE mibl_temp_score_data t
            JOIN temp_ranked_agents r ON t.agentId = r.agentId
            SET t.r = r.rn;
            
            DROP TEMPORARY TABLE IF EXISTS temp_max_values;
            DROP TEMPORARY TABLE IF EXISTS temp_ranked_agents;
            
            -- Final output
            SELECT 
                dealer_id AS dealerId,
                dealer_name AS dealerName,
                agentId,
                agentName,
                leadsAssigned,
                leadsContacted,
                policiesConverted,
                netPremiumCollected,
                followUpEfficiency,
                conversionRate,
                retentionRate,
                PerformanceScore,
                DynamicPerformanceScore,
                OverallScore,
                QuoteShared,
    ConversionsWithinTwoCalls,
    TriggerFlag,
    TargetPremium,
    NetODPremium,
    AddonSales,
    PreDueRenewals,
                r AS `rank`
            FROM mibl_temp_score_data
            ORDER BY OverallScore DESC;
            
            SET SP_STATUS = '200';
            SET MESSAGE = 'MIBL Performance Dashboard Non-Filter Data Fetched Successfully';
        
        END IF;
    
    END IF;
    
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_get_all_mapped_dealers` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_all_mapped_dealers`(
    IN p_json_data JSON,
    OUT p_status_code VARCHAR(50),
    OUT p_status_message VARCHAR(250)
)
BEGIN
	procedure_end: BEGIN 
    
    DECLARE v_limit INT DEFAULT 10; 
    DECLARE v_offset INT DEFAULT 0; 
    DECLARE v_calculated INT DEFAULT 0;
    DECLARE v_parent_code varchar(50);
    DECLARE v_role_type varchar(50);
	DECLARE v_search_name VARCHAR(100);

    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
            
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred while fetching mapped dealers. Please try again later.';
 
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_all_mapped_dealers', 'FETCH_MAPPED_DEALERS', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

END;

    SET v_limit = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.limit')) AS UNSIGNED), 10);
    SET v_offset = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.offset')) AS UNSIGNED), 0);
    SET v_calculated = (v_offset - 1) * v_limit;
    -- SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode'));
    SET v_parent_code = TRIM(SUBSTRING_INDEX(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode')),'-',-1));
	SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.roleType'));
	SET v_search_name = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.searchName'));
    
    IF v_limit IS NULL OR v_offset IS NULL OR v_limit = '' OR v_offset = '' THEN
        SET p_status_code = '300';
        SET p_status_message = 'Limit or offset cannot be empty';
        LEAVE procedure_end;
    END IF;
	IF v_parent_code IS NOT NULL THEN
    /*SELECT DISTINCT
        r.role_id,
        r.role AS roleName,
        d.parent_code,
        -- d.dealer_name AS dealerName,
        concat(dl.dealer_name,' - ',mdl.loc_name,' - ',dl.dealer_id) as dealerName,
        drm.role_location,
        mr.role AS reportingRole,
        mrt.role_type,
        r.status
    FROM mmi_mast_role r
    JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id AND drm.status = '1'
    JOIN mmi_mast_dealer d ON d.parent_code = drm.parent_code AND d.status = '1'
    LEFT JOIN mmi_dealer_details dl on drm.dealer_code = dl.dealer_id -- ON dl.parent_code = drm.parent_code
    LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
    LEFT JOIN mmi_mast_role_type mrt ON mrt.id = m.role_type_id
    LEFT JOIN mmi_mast_role mr ON drm.reporting_role_id = mr.role_id
    left join mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = dl.dealer_id
	left join mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
    WHERE -- r.status = '1' AND
       m.role_id IS NOT NULL  -- Ensure there is at least one feature mapped
      AND d.parent_code = v_parent_code AND mrt.role_type = 'DEALER'
    AND (
        v_search_name IS NULL OR v_search_name = ''
        OR (
            r.role LIKE CONCAT('%', v_search_name, '%') 
            OR mr.role LIKE CONCAT('%', v_search_name, '%')
            OR d.dealer_name LIKE CONCAT('%', v_search_name, '%') 
            OR drm.role_location LIKE CONCAT('%', v_search_name, '%')
            OR ((v_search_name = 'active' AND r.status = 1) OR (v_search_name = 'inactive' AND r.status = 0))
        )
    ) GROUP BY r.role_id, d.parent_code, dl.dealer_name, mr.role,drm.role_location,mrt.role_type,mdl.loc_name,dl.dealer_id
    ORDER BY d.dealer_name, r.role
    LIMIT v_limit OFFSET v_calculated;*/
    
    SELECT
		r.role_id,
		r.role AS roleName,
		d.parent_code,
		CONCAT(
			di.dealer_name,
			' - ',
			di.loc_name,
			' - ',
			drm.dealer_code
		) AS dealerName,
		drm.role_location,
		mr.role AS reportingRole,
		'DEALER' AS role_type,
		r.status
	FROM mmi_mast_role r
	JOIN mmi_mast_dealer_role_mapping drm
		ON drm.role_id = r.role_id
	   AND drm.status = '1'
	JOIN mmi_dealer_location_mapping d
		-- ON d.parent_code = drm.parent_code
        ON d.mapping_dealer_code = drm.dealer_code
	   AND d.is_active = '1'
	LEFT JOIN mmi_mast_role mr
		ON drm.reporting_role_id = mr.role_id
	LEFT JOIN (
		SELECT
			dl.dealer_id,
			MAX(dl.dealer_name) AS dealer_name,
			MAX(mdl.loc_name) AS loc_name
		FROM mmi_dealer_details dl
		LEFT JOIN mmi_dealer_location_mapping dlm
			ON dlm.mapping_dealer_code = dl.dealer_id
		LEFT JOIN mmi_mast_dealer_location mdl
			ON mdl.loc_code = dlm.location_code
		GROUP BY dl.dealer_id
	) di
		ON di.dealer_id = drm.dealer_code
	WHERE
		-- d.parent_code = v_parent_code
        di.dealer_id = v_parent_code
		AND EXISTS (
			SELECT 1
			FROM mmi_user_feature_access_mapping m
			JOIN mmi_mast_role_type mrt
				ON mrt.id = m.role_type_id
			WHERE m.role_id = r.role_id
			  AND mrt.role_type = 'DEALER'
		)
		AND (
			v_search_name IS NULL
			OR v_search_name = ''
			OR r.role LIKE CONCAT('%', v_search_name, '%')
			OR mr.role LIKE CONCAT('%', v_search_name, '%')
			OR d.dealer_name LIKE CONCAT('%', v_search_name, '%')
			OR drm.role_location LIKE CONCAT('%', v_search_name, '%')
			OR (v_search_name = 'active' AND r.status = 1)
			OR (v_search_name = 'inactive' AND r.status = 0)
		)
	ORDER BY d.dealer_name, r.role
	LIMIT v_limit OFFSET v_calculated;


    SELECT COUNT(*) AS paginationCount
    FROM (
        SELECT DISTINCT r.role_id, d.parent_code, mr.role,drm.role_location,
        mr.role AS reportingRole,mrt.role_type,r.status
        FROM mmi_mast_role r
        JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id AND drm.status = '1'
        -- JOIN mmi_mast_dealer d ON d.parent_code = drm.parent_code AND d.status = '1'
        JOIN mmi_dealer_location_mapping d ON d.mapping_dealer_code = drm.dealer_code AND d.is_active = '1'-- ON d.parent_code = drm.parent_code AND d.is_active = '1'
        LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = d.mapping_dealer_code
        LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
        LEFT JOIN mmi_mast_role mr ON drm.reporting_role_id = mr.role_id
        LEFT JOIN mmi_mast_role_type mrt ON mrt.id = m.role_type_id
        WHERE -- r.status = '1' AND 
        m.role_id IS NOT NULL AND dl.dealer_id = v_parent_code  -- d.parent_code = v_parent_code 
        AND mrt.role_type = 'DEALER'
        AND (
			v_search_name IS NULL OR v_search_name = ''
			OR (
				r.role LIKE CONCAT('%', v_search_name, '%') 
				OR mr.role LIKE CONCAT('%', v_search_name, '%')
				OR d.dealer_name LIKE CONCAT('%', v_search_name, '%') 
				OR drm.role_location LIKE CONCAT('%', v_search_name, '%')
                OR ((v_search_name = 'active' AND r.status = 1) OR (v_search_name = 'inactive' AND r.status = 0))
			)
		)  
    ) AS unique_rows;
    
    ELSEIF v_role_type = 'DEALER' THEN
	
		/*SELECT distinct dl.parent_code,dl.dealer_name from mmi_mast_dealer md left join
		mmi_dealer_details dl on md.parent_code = dl.parent_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL; */ 
        
        SELECT distinct dl.parent_code,concat(dl.dealer_name,' - ',mdl.loc_name,' - ',dl.dealer_id) as dealer_name 
        -- from mmi_mast_dealer md left join
		from mmi_dealer_details dl -- on md.parent_code = dl.parent_code
		left join mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = dl.dealer_id -- on dlm.parent_code = md.parent_code
		left join mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL; 
		
        /*SELECT distinct dl.dealer_name from mmi_mast_dealer md left join
		mmi_dealer_details dl on md.parent_code = dl.parent_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL; */
        
        /*SELECT DISTINCT r.role_id,r.role AS roleName,
        d.parent_code,
        -- d.dealer_name AS dealerName,
        concat(dl.dealer_name,' - ',mdl.loc_name,' - ',dl.dealer_id) as dealerName,
        drm.role_location,
        mr.role AS reportingRole,
        mrt.role_type,
        r.status
		FROM mmi_mast_role r
		JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id AND drm.status = '1'
		LEFT JOIN mmi_dealer_details dl on drm.dealer_code = dl.dealer_id-- ON dl.parent_code = drm.parent_code
        LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
		LEFT JOIN mmi_mast_role mr ON drm.reporting_role_id = mr.role_id
		LEFT JOIN mmi_mast_role_type mrt ON mrt.id = m.role_type_id
        LEFT JOIN mmi_mast_dealer d ON d.parent_code = drm.parent_code AND d.status = '1'
        left join mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = dl.dealer_id
		left join mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
		WHERE-- r.status = '1' AND 
        m.role_id IS NOT NULL AND mrt.id = 2 AND m.role_type_id IS NOT NULL
		AND (
        v_search_name IS NULL OR v_search_name = ''
        OR (
            r.role LIKE CONCAT('%', v_search_name, '%') 
            OR mr.role LIKE CONCAT('%', v_search_name, '%')
            OR d.dealer_name LIKE CONCAT('%', v_search_name, '%') 
            OR drm.role_location LIKE CONCAT('%', v_search_name, '%')
            OR ((v_search_name = 'active' AND r.status = 1) OR (v_search_name = 'inactive' AND r.status = 0))
			)
		) GROUP BY r.role_id,mr.role,d.parent_code,dl.dealer_name,drm.role_location,mdl.loc_name,dl.dealer_id ORDER BY r.role
		LIMIT v_limit OFFSET v_calculated;*/
        
        SELECT
    r.role_id,
    r.role AS roleName,
    d.parent_code,
    CONCAT(
        dealer_info.dealer_name,
        ' - ',
        dealer_info.loc_name,
        ' - ',
        drm.dealer_code
    ) AS dealerName,
    drm.role_location,
    mr.role AS reportingRole,
    rt.role_type,
    r.status
FROM mmi_mast_role r
JOIN mmi_mast_dealer_role_mapping drm
    ON drm.role_id = r.role_id
   AND drm.status = '1'

-- ✅ role_type joined safely (1 row per role)
JOIN (
    SELECT DISTINCT
        m.role_id,
        mrt.role_type
    FROM mmi_user_feature_access_mapping m
    JOIN mmi_mast_role_type mrt
        ON mrt.id = m.role_type_id
    WHERE mrt.id = 2
) rt
    ON rt.role_id = r.role_id

LEFT JOIN mmi_mast_role mr
    ON drm.reporting_role_id = mr.role_id
-- LEFT JOIN mmi_mast_dealer d
LEFT JOIN mmi_dealer_location_mapping d
    -- ON d.parent_code = drm.parent_code
    ON d.mapping_dealer_code = drm.dealer_code
   AND d.is_active = '1'

-- ✅ dealer/location pre-aggregated
LEFT JOIN (
    SELECT
        dl.dealer_id,
        MAX(dl.dealer_name) AS dealer_name,
        MAX(mdl.loc_name) AS loc_name
    FROM mmi_dealer_details dl
    LEFT JOIN mmi_dealer_location_mapping dlm
        ON dlm.mapping_dealer_code = dl.dealer_id
    LEFT JOIN mmi_mast_dealer_location mdl
        ON mdl.loc_code = dlm.location_code
    GROUP BY dl.dealer_id
) dealer_info
    ON dealer_info.dealer_id = drm.dealer_code

WHERE
    (
        v_search_name IS NULL
        OR v_search_name = ''
        OR r.role LIKE CONCAT('%', v_search_name, '%')
        OR mr.role LIKE CONCAT('%', v_search_name, '%')
        OR d.dealer_name LIKE CONCAT('%', v_search_name, '%')
        OR drm.role_location LIKE CONCAT('%', v_search_name, '%')
        OR (v_search_name = 'active' AND r.status = 1)
        OR (v_search_name = 'inactive' AND r.status = 0)
    )
ORDER BY r.role
LIMIT v_limit OFFSET v_calculated;




		SELECT COUNT(*) AS paginationCount
		FROM (
			SELECT DISTINCT r.role_id,r.role AS roleName,
			d.parent_code,
			d.dealer_name AS dealerName,
			drm.role_location,
			mr.role AS reportingRole,
            r.status
			FROM mmi_mast_role r
			JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id AND drm.status = '1'
			LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = drm.dealer_code-- ON dl.parent_code = drm.parent_code
			LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
			LEFT JOIN mmi_mast_role mr ON drm.reporting_role_id = mr.role_id
			LEFT JOIN mmi_mast_role_type mrt ON mrt.id = m.role_type_id
			-- LEFT JOIN mmi_mast_dealer d ON d.parent_code = drm.parent_code AND d.status = '1'
            LEFT JOIN mmi_dealer_location_mapping d ON d.mapping_dealer_code = dl.dealer_id AND d.status = '1'
			WHERE -- r.status = '1' AND
            m.role_id IS NOT NULL AND mrt.id = 2 AND m.role_type_id IS NOT NULL
			AND (
				v_search_name IS NULL OR v_search_name = ''
				OR (
					r.role LIKE CONCAT('%', v_search_name, '%') 
					OR mr.role LIKE CONCAT('%', v_search_name, '%')
					OR d.dealer_name LIKE CONCAT('%', v_search_name, '%') 
					OR drm.role_location LIKE CONCAT('%', v_search_name, '%')
                    OR ((v_search_name = 'active' AND r.status = 1) OR (v_search_name = 'inactive' AND r.status = 0))
					)
				)
            GROUP BY r.role_id,mr.role,d.parent_code,d.dealer_name,drm.role_location ORDER BY r.role
			) AS unique_rows;
    
	ELSE
		/*SELECT distinct dl.parent_code,dl.dealer_name from mmi_mast_dealer md left join
		mmi_dealer_details dl on md.parent_code = dl.parent_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL; */
        
        SELECT  distinct dl.parent_code,concat(dl.dealer_name,' - ',mdl.loc_name,' - ',dl.dealer_id) as dealer_name 
        -- from mmi_mast_dealer md left join
		from mmi_dealer_details dl -- on md.parent_code = dl.parent_code
		left join mmi_dealer_location_mapping dlm on dl.dealer_id = dlm.mapping_dealer_code
		left join mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL;
        
        /*SELECT distinct dl.dealer_name from mmi_mast_dealer md left join
		mmi_dealer_details dl on md.parent_code = dl.parent_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL; */
        
		SELECT DISTINCT r.role_id,r.role AS roleName,mrt.role_type,
        mr.role AS reportingRole,r.status
		FROM mmi_mast_role r
		JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id AND drm.status = '1'
		LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = drm.dealer_code-- ON dl.parent_code = drm.parent_code
        LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
		LEFT JOIN mmi_mast_role mr ON drm.reporting_role_id = mr.role_id
		LEFT JOIN mmi_mast_role_type mrt ON mrt.id = m.role_type_id
		WHERE -- r.status = '1' AND 
        m.role_id IS NOT NULL AND mrt.id = 1 AND m.role_type_id IS NOT NULL
		AND (
			v_search_name IS NULL OR v_search_name = ''
			OR (
				r.role LIKE CONCAT('%', v_search_name, '%') 
				OR mr.role LIKE CONCAT('%', v_search_name, '%')
				OR mrt.role_type LIKE CONCAT('%', v_search_name, '%')
                OR ((v_search_name = 'active' AND r.status = 1) OR (v_search_name = 'inactive' AND r.status = 0))
			)
		)  
        GROUP BY r.role_id,mrt.role_type, mr.role ORDER BY r.role
		LIMIT v_limit OFFSET v_calculated;

		SELECT COUNT(*) AS paginationCount
		FROM (
			SELECT DISTINCT r.role_id,r.role AS roleName,mrt.role_type,
			mr.role AS reportingRole,r.status
			FROM mmi_mast_role r
			JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id AND drm.status = '1'
			LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
            LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = drm.dealer_code-- ON dl.parent_code = drm.parent_code
			LEFT JOIN mmi_mast_role mr ON drm.reporting_role_id = mr.role_id
			LEFT JOIN mmi_mast_role_type mrt ON mrt.id = m.role_type_id
			WHERE -- r.status = '1' AND
            m.role_id IS NOT NULL AND mrt.id = 1 AND m.role_type_id IS NOT NULL
			AND (
				v_search_name IS NULL OR v_search_name = ''
				OR (
					r.role LIKE CONCAT('%', v_search_name, '%') 
					OR mr.role LIKE CONCAT('%', v_search_name, '%')
					OR mrt.role_type LIKE CONCAT('%', v_search_name, '%')
                    OR ((v_search_name = 'active' AND r.status = 1) OR (v_search_name = 'inactive' AND r.status = 0))
				)
			)  
            GROUP BY r.role_id,mrt.role_type, mr.role ORDER BY r.role
		) AS unique_rows;
    
	END IF;
		SET p_status_code = '200';
		SET p_status_message = 'Fetched successfully';
    END procedure_end;

END ;;
