CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_bucket_creation_values`(
	IN p_json JSON,
    OUT SP_STATUS VARCHAR(50),
    OUT SP_MESSAGE VARCHAR(100)
)
BEGIN
	DECLARE v_dealer_code varchar(100);
    DECLARE v_parent_code varchar(100);
    DECLARE v_type varchar(100);
    DECLARE v_role_type varchar(100);
    DECLARE v_dealer_name VARCHAR(100);
    
    DECLARE err_code INT;
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
            
            SET SP_STATUS = '500';
			SET SP_MESSAGE = 'An error occurred. Please try again.';

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_bucket_creation_values', 'BUCKET_CREATION', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    
	SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.dealerCode'));
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.parentCode'));
    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.type'));
    SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.roleType'));
    
		IF v_role_type = 'MIBL' THEN 
            SET v_dealer_name = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.dealerName'));
        
			select DISTINCT ic_code,ic_name from mmi_mast_insurancecompany;
			select DISTINCT id,renewal_year from mmi_mast_renewal_category;
			select DISTINCT segment_id,name from mmi_mast_segment;
			select DISTINCT datapull_id,datapull_name from mmi_mast_datapull;
			select DISTINCT id,addon_description from mmi_mast_addon;
            
			-- IF v_type = 'Dealer' THEN
				/* SELECT DISTINCT md.parent_code,md.dealer_name 
				FROM mmi_dealer_details dl
				-- LEFT JOIN mmi_mast_dealer md ON md.parent_code = dl.parent_code;
                LEFT JOIN mmi_dealer_location_mapping md ON md.mapping_dealer_code = dl.dealer_id; */
                
                SELECT DISTINCT md.parent_code, md.dealer_name, dl.dealer_id AS dealer_code  -- herek
				FROM mmi_dealer_details dl
				LEFT JOIN mmi_dealer_location_mapping md ON md.mapping_dealer_code = dl.dealer_id;
				
			IF v_type = 'location' THEN   
				/* SELECT DISTINCT mdl.loc_code,loc_name
				FROM mmi_mast_dealer_location mdl
				LEFT JOIN mmi_dealer_location_mapping dlm ON mdl.loc_code = dlm.location_code
				-- LEFT JOIN mmi_mast_dealer md ON dlm.parent_code = md.parent_code
				LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = dlm.mapping_dealer_code
				WHERE dlm.dealer_name = v_dealer_name; */ 
                
                SELECT DISTINCT mdl.loc_code, mdl.loc_name, dl.dealer_id AS dealer_code   -- ADDED
				FROM mmi_mast_dealer_location mdl
				LEFT JOIN mmi_dealer_location_mapping dlm  ON mdl.loc_code = dlm.location_code
				LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = dlm.mapping_dealer_code
				WHERE dlm.dealer_name = v_dealer_name;
			END IF;

            SET SP_STATUS = '200';
			SET SP_MESSAGE = 'Data Fetched Successfully';
            
        ELSE 
			IF v_dealer_code IS NULL OR v_parent_code IS NULL THEN
				SET SP_STATUS = '400';
				SET SP_MESSAGE = 'Invalid input parameters. dealerCode and parentCode cannot be NULL or empty';
			ELSE
				select DISTINCT ic_code,ic_name from mmi_mast_insurancecompany;
				select DISTINCT id,renewal_year from mmi_mast_renewal_category;
				select DISTINCT segment_id,name from mmi_mast_segment;
				select DISTINCT datapull_id,datapull_name from mmi_mast_datapull;
				select DISTINCT id,addon_description from mmi_mast_addon;
				select distinct loc_code,loc_name from mmi_mast_dealer_location mdl left join
				mmi_dealer_location_mapping dlm on mdl.loc_code = dlm.location_code
				-- left join mmi_mast_dealer md on dlm.parent_code = md.parent_code 
                LEFT JOIN mmi_dealer_details dl ON dlm.mapping_dealer_code = 'D100'
                where dlm.dealer_code = v_dealer_code and dlm.parent_code = v_parent_code;
                
                SET SP_STATUS = '200';
				SET SP_MESSAGE = 'Data Fetched Successfully';
		END IF;
END IF;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
