CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_bucket_preferences_summary`(
    IN p_dealer_name VARCHAR(100),
    IN p_bucket_name VARCHAR(100),
    OUT p_status VARCHAR(50),
    OUT p_message VARCHAR(250)
)
BEGIN

	DECLARE err_code INT;
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
		SET p_status = '500';
        SET p_message = 'An error occurred. Please try again.';
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_bucket_preferences_summary', 'GET_BUCKET_PREFERENCES', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    IF p_dealer_name IS NULL OR p_bucket_name IS NULL THEN
        SET p_status = '400';
        SET p_message = 'Invalid input parameters. dealerName and bucketName cannot be NULL or empty';
	ELSE
    SELECT
        dlm.dealer_name,
        b.bucket_name,
        GROUP_CONCAT(DISTINCT ic.ic_name ORDER BY ic.ic_name SEPARATOR ', ') AS insurance_preferences,
        GROUP_CONCAT(DISTINCT ms.name ORDER BY ms.name SEPARATOR ', ') AS segment_preferences,
        GROUP_CONCAT(DISTINCT rc.renewal_year ORDER BY rc.renewal_year SEPARATOR ', ') AS renewal_preferences,
		GROUP_CONCAT(DISTINCT dp.datapull_name ORDER BY dp.datapull_name SEPARATOR ', ') AS datapull_preferences,
        GROUP_CONCAT(DISTINCT ma.addon_description ORDER BY ma.addon_description SEPARATOR ', ') AS addon_preferences
    FROM mmi_mast_bucket b 
	JOIN mmi_dealer_location_mapping dlm on b.dealer_code = dlm.mapping_dealer_code
    -- JOIN mmi_mast_dealer d ON dlm.parent_code = d.parent_code

    LEFT JOIN mmi_call_user_preference_insurance pi
           ON pi.bucket_id = b.id AND pi.status = 1
    LEFT JOIN mmi_mast_insurancecompany ic
           ON pi.ic_code = ic.ic_code

    LEFT JOIN mmi_call_user_preference_segment ps
           ON ps.bucket_id = b.id AND ps.status = 1
    LEFT JOIN mmi_mast_segment ms
           ON ps.segment_id = ms.segment_id

    LEFT JOIN mmi_call_user_preference_renewal pr
           ON pr.bucket_id = b.id AND pr.status = 1
    LEFT JOIN mmi_mast_renewal_category rc
           ON pr.renewal_category_id = rc.id
           
   LEFT JOIN mmi_call_user_preference_datapull pd
           ON pd.bucket_id = b.id AND pd.status = 1
    LEFT JOIN mmi_mast_datapull dp
           ON pd.datapull_id = dp.datapull_id        

    LEFT JOIN mmi_call_user_preference_addon pa
           ON pa.bucket_id = b.id AND pa.status = 1
    LEFT JOIN mmi_mast_addon ma
           ON pa.addon_id = ma.addon_type

    WHERE (p_dealer_name IS NULL OR dlm.dealer_name = p_dealer_name)
      AND (p_bucket_name IS NULL OR b.bucket_name = p_bucket_name)

    GROUP BY dlm.dealer_name, b.bucket_name;

    SET p_status = '200';
	SET p_message = 'Successfully Data Fetched';
   END IF; 
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_get_bucket_preferences_with_status` */;
