/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_bucket_preferences_with_status`(
    IN p_bucket_id INT,
    OUT p_status_code varchar(50),
    OUT p_status_message varchar(255)
)
BEGIN

	DECLARE err_code INT;
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO, 
            err_msg = MESSAGE_TEXT;
		
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_bucket_preferences_with_status', 'GET_BUCKET_PREFERENCES_WITH_STATUS', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    IF p_bucket_id IS NULL THEN
        SET p_status_code = '400';
        SET p_status_message = 'Invalid input parameters. bucketId cannot be NULL or empty';
	ELSE
    -- Insurance
    SELECT pi.ic_code, ic.ic_name, pi.status
    FROM mmi_call_user_preference_insurance pi
    JOIN mmi_mast_insurancecompany ic ON pi.ic_code = ic.ic_code
    WHERE pi.bucket_id = p_bucket_id;

    -- Segment
    SELECT ps.segment_id, ms.name AS segment_name, ps.status
    FROM mmi_call_user_preference_segment ps
    JOIN mmi_mast_segment ms ON ps.segment_id = ms.segment_id
    WHERE ps.bucket_id = p_bucket_id;

    -- Renewal
    SELECT pr.renewal_category_id, rc.renewal_year, pr.status
    FROM mmi_call_user_preference_renewal pr
    JOIN mmi_mast_renewal_category rc ON pr.renewal_category_id = rc.id
    WHERE pr.bucket_id = p_bucket_id;
    
    SELECT pd.datapull_id, md.datapull_name, pd.status
    FROM mmi_call_user_preference_datapull pd
    JOIN mmi_mast_datapull md ON pd.datapull_id = md.datapull_id
    WHERE pd.bucket_id = p_bucket_id;

    SELECT pa.addon_id, ma.addon_description, pa.status
    FROM mmi_call_user_preference_addon pa
    JOIN mmi_mast_addon ma ON pa.addon_id = ma.id
    WHERE pa.bucket_id = p_bucket_id;
    
    select bucket_location from mmi_mast_bucket where id = p_bucket_id;
    
    select d.dealer_name from mmi_mast_bucket b inner join mmi_dealer_details d 
	on d.dealer_id =  b.dealer_code where b.id = p_bucket_id; 
    
    SET p_status_code = '200';
	SET p_status_message = 'Successfully Data Fetched';
    
  END IF;  
END ;;
DELIMITER ;
