CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_callqueuedetails`(
    IN Json_data JSON,
    IN type VARCHAR(45),
    OUT SP_STATUS VARCHAR(500),
    OUT MESSAGE VARCHAR(500)
)
BEGIN
	
	Declare userid varchar(45);
    DECLARE calculated INT DEFAULT 0;
	DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 0;
    DECLARE statustype varchar(45) default "";
	DECLARE filtersearch varchar(45) default "";
	DECLARE savesearch varchar(45) default "";
	Declare roleId varchar(45);
    -- Error handler
    DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(250);
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
        SET SP_STATUS = '500';
        SET MESSAGE = 'An error occurred. Please try again.';
        ROLLBACK;
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_callqueuedetails', 'CallQueue', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    
    -- getcallqueue details
	set statustype=JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.callQueType'));
    SET userid = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
	START TRANSACTION;
   IF type = 'getcallqueuedetails' THEN
   
	SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.limit')) AS UNSIGNED), 10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.offset')) AS UNSIGNED), 0);
	SET calculated = (offsetVal - 1) * limitVal;
	-- set statustype=JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.callQueType'));
    IF userid IS NULL OR userid = '' OR offsetVal IS NULL OR limitVal IS NULL THEN
        SET SP_STATUS = '1101';
        SET MESSAGE = 'userid, offset, and limitVal cannot be empty';
    ELSE
		if roleId=1 then 
			if statustype = 'current' then
				   SELECT distinct customerName,leadId,leadType,model,renewal_category,expiry_date,recentupdates,next_status,clusterId,expiryDays 
				FROM mmi_get_caller_details_by_manager 
				WHERE assigned_agent = userid and call_date_time=current_date() order by leadType desc 
				LIMIT limitVal OFFSET calculated;
            elseif statustype = 'noncaller' then
					SELECT distinct customerName,leadId,leadType,model,agentName,renewal_category,expiry_date,expiryDays,recentupdates,next_status,clusterId,expiryDays 
				FROM mmi_get_caller_details_by_manager 
				WHERE supervisor_id = userid order by leadType desc
				LIMIT limitVal OFFSET calculated;
			else
				SELECT distinct customerName,leadId,model,leadType,renewal_category,expiry_date,expiryDays,recentupdates,next_status,clusterId,expiryDays 
				FROM mmi_get_caller_details_by_manager 
				WHERE assigned_agent = userid order by leadType desc 
				LIMIT limitVal OFFSET calculated;
			end if;
		else 
			if statustype = 'current' then
				   SELECT distinct customerName,leadId,leadType,model,renewal_category,expiry_date,expiryDays,recentupdates,next_status,clusterId,expiryDays 
				FROM mmi_get_caller_details_by_manager 
				WHERE assigned_agent = userid and call_date_time=current_date() order by leadType desc
				LIMIT limitVal OFFSET calculated;
            elseif statustype = 'noncaller' then
					SELECT distinct customerName,leadId,leadType,model,agentName,renewal_category,expiry_date,expiryDays,recentupdates,next_status,clusterId,expiryDays 
				FROM mmi_get_caller_details_by_manager 
				WHERE supervisor_id = userid order by leadType desc
				LIMIT limitVal OFFSET calculated;    
			else
				SELECT distinct customerName,leadId,leadType,model,renewal_category,expiry_date,expiryDays,recentupdates,next_status,clusterId,expiryDays 
				FROM mmi_get_caller_details_by_manager 
				WHERE assigned_agent = userid order by leadType desc 
				LIMIT limitVal OFFSET calculated;
			end if;
		end if;
    if statustype = 'noncaller' then
    		SELECT count(distinct leadId) as total FROM mmi_get_caller_details_by_manager WHERE supervisor_id = userid;
    else
			SELECT count(distinct leadId) as total FROM mmi_get_caller_details_by_manager WHERE assigned_agent = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')); 
			SELECT count(distinct leadId) as total  FROM mmi_get_caller_details_by_manager WHERE assigned_agent = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')) and call_date_time=current_date();
	end if;
    SET SP_STATUS = '0000';
	SET MESSAGE = 'Success';
END IF;
elseif type="getcallqueuedetailstotal" then
	if statustype = 'noncaller' then
		SELECT count(distinct leadId) as total FROM mmi_get_caller_details_by_manager WHERE supervisor_id = userid;
    else
    	SELECT count(distinct leadId) as total FROM mmi_get_caller_details_by_manager WHERE assigned_agent = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')); 
    end if;
