CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_crm_headerinputs`(
    IN Json_data TEXT,
    -- IN type VARCHAR(45),
    OUT SP_STATUS VARCHAR(45),
    OUT MESSAGE VARCHAR(500)
)
BEGIN
    DECLARE pageId VARCHAR(45);
    DECLARE accessType VARCHAR(45);
    DECLARE flagVal VARCHAR(45);
    DECLARE userId VARCHAR(45);
    DECLARE callingFlag VARCHAR(5); -- Y or N

    DECLARE err_code VARCHAR(50);
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        SET SP_STATUS = '500';
        SET MESSAGE = 'An error occurred. Please try again.';

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_crm_headerinputs', 'GET_CRM_HEADER_INPUT', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    -- Extract fields from JSON
    SET pageId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.pageId'));
    SET accessType = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.accessType'));
    SET flagVal = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.flag'));
    SET userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
    
    -- Get calling flag from user profile
    SELECT calling_flag INTO callingFlag
    FROM mmi_mast_user
    WHERE user_id = userId
    LIMIT 1;

    -- Main logic
   -- IF type = 'getmisppageinputs' THEN
        IF pageId IS NULL OR pageId = '' OR userId IS NULL OR userId = '' THEN
            SET SP_STATUS = '1101';
            SET MESSAGE = 'pageId and userId cannot be empty';

        ELSE
            IF callingFlag = 'Y' THEN
                IF accessType = 'noncaller' THEN
                    -- Caller view: caller + shared headers
                    SELECT DISTINCT input_name, sequence_id, filter
                    FROM mmi_mast_inputs
                    WHERE status = 1
                      AND page_id = pageId
                      AND sequence_id IS NOT NULL
                    ORDER BY sequence_id ASC;
                    SET SP_STATUS = '0000';
                    SET MESSAGE = 'success - default manager view';

                ELSEIF accessType = 'caller' THEN
                SELECT DISTINCT input_name, sequence_id, filter
                    FROM mmi_mast_inputs
                    WHERE status = 1
                      AND page_id = pageId
                      AND sequence_id IS NOT NULL
                       AND input_name <> 'Agent Name'
                    ORDER BY sequence_id ASC;
                    SET SP_STATUS = '0000';
                    SET MESSAGE = 'success - caller headers';
                    
                 ELSEIF flagVal = 'assigned' THEN
                    SELECT DISTINCT input_name, sequence_id, filter
                    FROM mmi_mast_inputs
                    WHERE status = 1
                      AND page_id = pageId
                      AND input_name <> 'Action'
                      AND sequence_id IS NOT NULL
                    ORDER BY sequence_id ASC;

                    SET SP_STATUS = '0000';
                    SET MESSAGE = CONCAT('success - manager headers (', flagVal, ')');

                ELSEIF flagVal = 'unassigned' OR flagVal = 'myLeads' THEN
                    SELECT DISTINCT input_name, sequence_id, filter
                    FROM mmi_mast_inputs
                    WHERE status = 1
                      AND page_id = pageId
                      AND input_name <> 'Agent Name' AND input_name <> 'Action'
                      AND sequence_id IS NOT NULL
                    ORDER BY sequence_id ASC;

                    SET SP_STATUS = '0000';
                    SET MESSAGE = 'success - manager unassigned headers';
                    
                ELSEIF flagVal = 'lostLeads' THEN
                    SELECT DISTINCT input_name, sequence_id, filter
                    FROM mmi_mast_inputs
                    WHERE status = 1
                      AND page_id = pageId
                      AND input_name <> 'Agent Name' AND input_name <> 'Expiry Days'
                      AND sequence_id IS NOT NULL
                    ORDER BY sequence_id ASC;

                    SET SP_STATUS = '0000';
                    SET MESSAGE = 'success - manager lostLeads headers';      
                END IF;

            ELSEIF callingFlag = 'N' THEN
                -- Manager view (callingFlag = 'N')
                IF accessType = 'noncaller' THEN
                    -- Caller view: caller + shared headers
                    SELECT DISTINCT input_name, sequence_id, filter
                    FROM mmi_mast_inputs
                    WHERE status = 1
                      AND page_id = pageId
                      AND sequence_id IS NOT NULL
                    ORDER BY sequence_id ASC;
                    SET SP_STATUS = '0000';
                    SET MESSAGE = 'success - default manager view';
                
                ELSEIF flagVal = 'assigned' THEN
                    SELECT DISTINCT input_name, sequence_id, filter
                    FROM mmi_mast_inputs
                    WHERE status = 1
                      AND page_id = pageId AND input_name <> 'Action'
                      AND sequence_id IS NOT NULL
                    ORDER BY sequence_id ASC;

                    SET SP_STATUS = '0000';
                    SET MESSAGE = CONCAT('success - manager headers (', flagVal, ')');

                ELSEIF flagVal = 'unassigned' OR flagVal = 'myLeads' THEN
                    SELECT DISTINCT input_name, sequence_id, filter
                    FROM mmi_mast_inputs
                    WHERE status = 1
                      AND page_id = pageId
                      AND input_name <> 'Agent Name' AND input_name <> 'Action'
                      AND sequence_id IS NOT NULL
                    ORDER BY sequence_id ASC;

                    SET SP_STATUS = '0000';
                    SET MESSAGE = 'success - manager unassigned headers';
                    
               ELSEIF flagVal = 'lostLeads' THEN
                    SELECT DISTINCT input_name, sequence_id, filter
                    FROM mmi_mast_inputs
                    WHERE status = 1
                      AND page_id = pageId
                      AND input_name <> 'Agent Name' AND input_name <> 'Expiry Days'
                      AND sequence_id IS NOT NULL
                    ORDER BY sequence_id ASC;

                    SET SP_STATUS = '0000';
                    SET MESSAGE = 'success - manager lostLeads headers';     

                ELSEIF pageId = '1' THEN
                    -- Default non-caller (manager) view: non-caller fields only
                    SELECT DISTINCT input_name, sequence_id, filter
                    FROM mmi_mast_inputs
                    WHERE status = 1
                      AND page_id = pageId
                      -- AND flag = 1
                      AND sequence_id IS NOT NULL
                    ORDER BY sequence_id ASC;

                    SET SP_STATUS = '0000';
                    SET MESSAGE = 'success - default manager view';

                ELSE
                    SET SP_STATUS = '1103';
                    SET MESSAGE = 'Invalid flag value';
                END IF;
            ELSE
                SET SP_STATUS = '1104';
                SET MESSAGE = 'Invalid callingFlag value';
            END IF;
        END IF;

  --  ELSE
    --    SET SP_STATUS = '1102';
      --  SET MESSAGE = 'Invalid request type';
   -- END IF;

    -- Output the status and message
    -- SELECT SP_STATUS, MESSAGE;

END ;;
DELIMITER ;
