/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_customer_details`(
    IN Json_data JSON,
    -- IN type VARCHAR(45),
    OUT p_status_code VARCHAR(500),
    OUT p_status_message VARCHAR(500)
)
BEGIN
    DECLARE clusterId VARCHAR(50);
    DECLARE v_clusterId VARCHAR(50);
    DECLARE vehicleName VARCHAR(50);
    DECLARE v_leadId VARCHAR(50);
    DECLARE type VARCHAR(50); 
    DECLARE v_vehicle_reg_no VARCHAR(50);
    DECLARE v_policyno VARCHAR(500);
    DECLARE v_mobile_no VARCHAR(50);
    DECLARE v_email VARCHAR(500);
    DECLARE v_chassis_no VARCHAR(500);
    DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 0;
    DECLARE calculated INT DEFAULT 0;

	DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
            
		SET type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.type'));
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_customer_details', type, CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    
    SET clusterId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.clusterId'));
    SET vehicleName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.vehicleName'));
	SET type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.type'));
    SET v_clusterId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.clusterId'));
    SET v_leadId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.leadId'));
	SET v_policyno = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.policyno'));
    SET v_vehicle_reg_no = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.vehicleRegNo'));
    SET v_chassis_no = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.chassisNo'));
    SET v_mobile_no = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.mobileNo'));
    SET v_email = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.emailId'));

    IF clusterId IS NULL OR vehicleName IS NULL OR type IS NULL THEN
        SET p_status_code = '400';
        SET p_status_message = 'Invalid input parameters. Required Fields cannot be NULL or empty';
	ELSE
        
     IF type = 'fetchVehicleDetails' THEN
		
        SELECT DISTINCT mcd.customer_email,mcd.customer_phone
		INTO v_email,v_mobile_no
		FROM mmi_lead_details mld LEFT JOIN mmi_mast_customer_details mcd ON mcd.chassis_no = mld.vin
		WHERE mld.lead_id = v_leadId AND mcd.customer_email IS NOT NULL AND mcd.customer_phone IS NOT NULL;
        
		select distinct mcd.cluster_id as clusterId,mld.model,mld.vin as chassisNo,mcd.customer_email,
        mcd.customer_phone,mld.lead_id as leadId,mld.expiry_days
        from mmi_lead_details mld left join mmi_mast_customer_details mcd on mcd.chassis_no = mld.vin
        where mcd.cluster_id = clusterId and mcd.customer_phone = v_mobile_no and mcd.customer_email = v_email;
     
     ELSEIF type = 'init' THEN
     
		select distinct model,expiry_days,MAX(created_date) AS latest_created_date
        from mmi_lead_details where cluster_id = clusterId and 
        -- lead_id = v_leadId 
        vin = v_chassis_no
        and model = vehicleName GROUP BY model,expiry_days order by latest_created_date desc;  
		-- select distinct customer_email,customer_phone,created_date from mmi_mast_customer_details
		-- where cluster_id = clusterId order by created_date desc;
        /*SELECT customer_email, customer_phone
			FROM (SELECT customer_email, customer_phone, created_date FROM mmi_mast_customer_details
				WHERE cluster_id = clusterId
				ORDER BY created_date DESC
			) t
			GROUP BY customer_email, customer_phone;*/
          WITH numbered AS (
				SELECT distinct
					customer_email,
					customer_phone,
					ROW_NUMBER() OVER (ORDER BY created_date DESC) AS rn
				FROM mmi_mast_customer_details
				WHERE cluster_id = clusterId and chassis_no = v_chassis_no
			)
			SELECT
				customer_email,
				CASE WHEN rn = 1 THEN customer_phone ELSE NULL END AS customer_phone
			FROM numbered;
  
        
        /*select DISTINCT recentUpdates,next_status,call_date_time 
		from mmi_get_caller_details_by_manager 
		where clusterId = v_clusterId -- and model=vehicleName 
        order by call_date_time desc LIMIT 1;*/
    
			SELECT 
				CONCAT(
					IFNULL(cdh.call_status, ''),
					' | ',
					DATE_FORMAT(cdh.call_date, '%Y-%m-%d %H:%i:%s'),
					' \n ',
					IFNULL(adfr.field_value, ''),
					' | ',
					IFNULL(cdh.next_call_datetime, '')
				) AS recentupdates,
				CONCAT(
					IFNULL(adfr.field_value, ''),
					'(',
					IFNULL((SELECT COUNT(*) FROM mmi_call_disposition_history cdh2 WHERE cdh2.customer_id = cdh.customer_id), 0),
					')'
				) AS next_status
			FROM  mmi_call_disposition_history cdh
			LEFT JOIN mmi_agent_disposition_field_response adfr ON adfr.response_id = cdh.id AND adfr.field_label = 'Sub Disposition'
			LEFT JOIN mmi_mast_disposition md  ON md.disposition_id = cdh.dealer_disposition_id
			WHERE -- cdh.customer_id = v_clusterId and 
            cdh.lead_id = v_leadId
			GROUP BY cdh.call_status, cdh.call_date, cdh.next_call_datetime, adfr.field_value, cdh.customer_id 
			ORDER BY cdh.call_date DESC LIMIT 1; 

		select distinct policy_no,insurance_company,podc_end,customer_city,customer_pincode,mld.customer_type,mld.created_date 
        from mmi_lead_details mld left join mmi_mast_customer_details mcd on mld.vin = mcd.chassis_no and mld.engine_no = mcd.engine_no-- on mld.cluster_id = mcd.cluster_id
		where -- mld.cluster_id = clusterId and 
        mld.model = vehicleName and mld.lead_id = v_leadId

        order by mld.created_date desc limit 1;
        
        /*select distinct mld.lead_id,mld.policy_no,mcd.customer_phone,mcd.customer_email,
        mld.make,mld.variant,mld.fuel_type,mld.vehicle_class,mld.model,
		mcd.vehicle_reg_no,mld.engine_no,mcd.chassis_no,csh.invoice_date_time,mld.plan_type,
		mld.net_premium,mld.addon_premium_amount,rrd.renewal_Link,
        concat(mld.podc_start,' | ',mld.podc_end) as odDates,concat(mld.plc_start,' | ',mld.plc_end) as tpDates,
		mld.net_od_premium_amount as totalod,mld.net_liability as totaltp,
        CASE WHEN cch.chassis_number IS NOT NULL THEN 'Yes' ELSE 'No' END AS claim_history,
        mld.od_discount_percentage as od_discount,mld.ncb_percentage,
        mld.created_date*/
        select distinct mld.lead_id,mld.policy_no,mcd.customer_phone,mcd.customer_email,
        mld.make,mld.variant,mld.fuel_type,mld.vehicle_class,mld.model,
		mcd.vehicle_reg_no,mld.engine_no,mcd.chassis_no,-- mld.invoice_date,
        date_format(mld.invoice_date,'%d %b %Y') as invoice_date,mld.plan_type,
		mld.gross_premium as net_premium,mld.addon_premium_amount,rrd.renewal_Link AS renewal_link_old, psh.renewal_link_read_only AS renewal_Link,
        concat(DATE_FORMAT(mld.podc_start,'%d %b %Y'),' | ',DATE_FORMAT(mld.podc_end,'%d %b %Y')) as odDates,
        concat(DATE_FORMAT(mld.plc_start,'%d %b %Y'),' | ',DATE_FORMAT(mld.plc_end,'%d %b %Y')) as tpDates,
		mld.net_od_premium_amount as totalod,mld.net_liability as totaltp,
        CASE WHEN cch.chassis_number IS NOT NULL THEN 'Yes' ELSE 'No' END AS claim_history,
        mld.od_discount_percentage as od_discount,mld.ncb_percentage,
        date_format(mld.registration_date,'%d %b %Y') as registration_date,
        mld.group_product,  urd_lead.ebm_user_id AS assigned_agent_ebm_user_id, urd_lead.mobile_no AS crm_user_phone_no, -- mld.proposal_no as old_proposal_no, -- herek
		COALESCE(psh.proposal_no, mld.proposal_no) AS proposal_no, psh.remarks, mld.total_idv,
        -- EBM herek - Modified to include color
		-- COALESCE(ebm.proposal_status, 'N/A') AS ebmStatus,
        COALESCE(
    NULLIF(ebm.proposal_status,'N/A'),
    (
        SELECT proposal_status
        FROM mmi_proposal_status_history
        WHERE lead_id = mld.lead_id
        AND proposal_status IS NOT NULL
        AND proposal_status <> 'N/A'
        ORDER BY created_date DESC
        LIMIT 1
    ),
    'N/A'
) AS ebmStatus,

COALESCE(ems.ebm_status_color,'#000000') AS ebmStatusColor,
DATE_FORMAT(mld.policy_expiry_date, '%Y-%m-%d') AS policy_expiry_date,
		--
        mld.created_date
        from mmi_lead_details mld
		-- left join mmi_mast_customer_details mcd on mld.cluster_id = mcd.cluster_id
		LEFT JOIN LATERAL (
				SELECT cluster_id, MIN(customer_name) AS customer_name, MIN(vehicle_reg_no) AS vehicle_reg_no,
                MIN(customer_phone) AS customer_phone,MIN(customer_email) AS customer_email,
                MIN(chassis_no) AS chassis_no
				FROM mmi_mast_customer_details cd WHERE mld.vin = cd.chassis_no and mld.engine_no = cd.engine_no-- cd.cluster_id = mld.cluster_id
				GROUP BY cluster_id LIMIT 1
		) mcd ON TRUE
        left join mmi_ebm_sales_data csh on mcd.chassis_no = csh.chassis_number
		left join mmi_renewalreminder_data rrd on mld.policy_no = rrd.policy_no
       -- LEFT JOIN mmi_proposal_status_history psh ON psh.policy_no = mld.policy_no -- herek
       LEFT JOIN (
		SELECT p1.policy_no, p1.renewal_link_read_only, p1.proposal_no, p1.remarks
		FROM mmi_proposal_status_history p1
		INNER JOIN (
        SELECT policy_no, MAX(id) AS max_id
        FROM mmi_proposal_status_history
        GROUP BY policy_no
		) p2 ON p1.id = p2.max_id
		) psh ON psh.policy_no = mld.policy_no
        left join mmi_ebm_claim_data cch on cch.chassis_number = mcd.chassis_no
        -- EBM herek - Modified to join with color table
		LEFT JOIN (
        SELECT e1.* FROM mmi_crm_ebm_transaction_details e1
        LEFT JOIN mmi_crm_ebm_transaction_details e2 
		ON e1.lead_id = e2.lead_id AND e1.created_date < e2.created_date
        WHERE e2.id IS NULL
		) ebm ON ebm.lead_id = mld.lead_id
		LEFT JOIN mmi_mast_ebm_status ems ON ems.sub_ebm_status = ebm.proposal_status
        LEFT JOIN mmi_mast_user_registration_detail urd_lead 
		ON urd_lead.id = mld.assigned_agent

		--
        
        where mld.cluster_id = clusterId and 
        mld.model = vehicleName and mld.vin = v_chassis_no and mld.lead_id = v_leadId
        order by mld.created_date desc;

        SELECT distinct
            cph.insurance_company,
            cph.policy_no,
            cph.policy_tenure,
            cph.policy_type,
            cph.policy_effective_date,
            cph.policy_expiry_date,
            cph.plan_type,
            cph.yom,
            cph.created_date
            -- IFNULL(cdh.call_date, 'NA') AS recent_updates,
            -- IFNULL(cdh.call_status, 'NA') AS status
        FROM mmi_ebm_policy_data cph
        -- LEFT JOIN mmi_lead_details mld ON cph.cluster_id = mld.cluster_id
        left join mmi_lead_details mld on mld.vin = cph.vin and mld.engine_no = cph.engine_no
        LEFT JOIN mmi_call_disposition_history cdh ON cdh.customer_id = cph.cluster_id
        WHERE cph.cluster_id = clusterId AND 
        mld.model = vehicleName and mld.vin = v_chassis_no -- mld.lead_id = v_leadId
        order by cph.created_date desc;
    
    
    ELSEIF type = 'overview' THEN
        /*select distinct mld.lead_id,mld.policy_no,mcd.customer_phone,mcd.customer_email,
        mld.make,mld.variant,mld.fuel_type,mld.vehicle_class,mld.model,
		mcd.vehicle_reg_no,mld.engine_no,mcd.chassis_no,csh.invoice_date_time,mld.plan_type,
		mld.net_premium,mld.addon_premium_amount,rrd.renewal_Link,
        concat(mld.podc_start,' | ',mld.podc_end) as odDates,concat(mld.plc_start,' | ',mld.plc_end) as tpDates,
		mld.net_od_premium_amount as totalod,mld.net_liability as totaltp,
        CASE WHEN cch.chassis_number IS NOT NULL THEN 'Yes' ELSE 'No' END AS claim_history,
        mld.od_discount_percentage as od_discount,mld.ncb_percentage,mld.created_date*/
        select distinct mld.lead_id,mld.policy_no,mcd.customer_phone,mcd.customer_email,
        mld.make,mld.variant,mld.fuel_type,mld.vehicle_class,mld.model,
		mcd.vehicle_reg_no,mld.engine_no,mcd.chassis_no,-- mld.invoice_date,
        date_format(mld.invoice_date,'%d %b %Y') as invoice_date,mld.plan_type,
		mld.gross_premium as net_premium,mld.addon_premium_amount,rrd.renewal_Link AS renewal_link_old, psh.renewal_link_read_only AS renewal_Link,
        concat(DATE_FORMAT(mld.podc_start,'%d %b %Y'),' | ',DATE_FORMAT(mld.podc_end,'%d %b %Y')) as odDates,
        concat(DATE_FORMAT(mld.plc_start,'%d %b %Y'),' | ',DATE_FORMAT(mld.plc_end,'%d %b %Y')) as tpDates,
		mld.net_od_premium_amount as totalod,mld.net_liability as totaltp,
        CASE WHEN cch.chassis_number IS NOT NULL THEN 'Yes' ELSE 'No' END AS claim_history,
        mld.od_discount_percentage as od_discount,mld.ncb_percentage,
        date_format(mld.registration_date,'%d %b %Y') as registration_date,mld.group_product, urd_lead.ebm_user_id AS assigned_agent_ebm_user_id,
        urd_lead.mobile_no AS crm_user_phone_no, COALESCE(psh.proposal_no, mld.proposal_no) AS proposal_no, psh.remarks, mld.total_idv,-- mld.proposal_no, -- herek
        -- EBM herek - Add EBM status and color to overview
		-- COALESCE(ebm.proposal_status, 'N/A') AS ebmStatus,
        COALESCE(
    NULLIF(ebm.proposal_status,'N/A'),
    (
        SELECT proposal_status
        FROM mmi_proposal_status_history
        WHERE lead_id = mld.lead_id
        AND proposal_status IS NOT NULL
        AND proposal_status <> 'N/A'
        ORDER BY created_date DESC
        LIMIT 1
    ),
    'N/A'
) AS ebmStatus,

COALESCE(ems.ebm_status_color,'#000000') AS ebmStatusColor,
DATE_FORMAT(mld.policy_expiry_date, '%Y-%m-%d') AS policy_expiry_date,
		--
        mld.created_date
        from mmi_lead_details mld
		-- left join mmi_mast_customer_details mcd on mld.cluster_id = mcd.cluster_id
		LEFT JOIN LATERAL (
				SELECT cluster_id, MIN(customer_name) AS customer_name, MIN(vehicle_reg_no) AS vehicle_reg_no,
                MIN(customer_phone) AS customer_phone,MIN(customer_email) AS customer_email,
                MIN(chassis_no) AS chassis_no
				FROM mmi_mast_customer_details cd WHERE mld.vin = cd.chassis_no and mld.engine_no = cd.engine_no-- cd.cluster_id = mld.cluster_id
				GROUP BY cluster_id LIMIT 1
		) mcd ON TRUE
        left join mmi_ebm_sales_data csh on mcd.chassis_no = csh.chassis_number
		left join mmi_renewalreminder_data rrd on mld.policy_no = rrd.policy_no
       -- LEFT JOIN mmi_proposal_status_history psh ON psh.policy_no = mld.policy_no -- herek
       LEFT JOIN (
		SELECT p1.policy_no, p1.renewal_link_read_only, p1.proposal_no, p1.remarks
		FROM mmi_proposal_status_history p1
		INNER JOIN (
        SELECT policy_no, MAX(id) AS max_id
        FROM mmi_proposal_status_history
        GROUP BY policy_no
		) p2 ON p1.id = p2.max_id
		) psh ON psh.policy_no = mld.policy_no
        left join mmi_ebm_claim_data cch on cch.chassis_number = mcd.chassis_no
		-- EBM herek - Add EBM join for overview
		LEFT JOIN (
        SELECT e1.* FROM mmi_crm_ebm_transaction_details e1
        LEFT JOIN mmi_crm_ebm_transaction_details e2 
		ON e1.lead_id = e2.lead_id AND e1.created_date < e2.created_date
        WHERE e2.id IS NULL
		) ebm ON ebm.lead_id = mld.lead_id
		LEFT JOIN mmi_mast_ebm_status ems ON ems.sub_ebm_status = ebm.proposal_status
        LEFT JOIN mmi_mast_user_registration_detail urd_lead  -- herek
		ON urd_lead.id = mld.assigned_agent

		--
        
        where mld.cluster_id = clusterId and 
        mld.model = vehicleName and mld.vin = v_chassis_no-- mld.lead_id = v_leadId
        order by mld.created_date desc;

    ELSEIF type = 'policy' THEN 
        select cph.insurance_company,cph.policy_no,cph.policy_tenure,cph.policy_type,
        date_format(cph.policy_effective_date,'%Y-%m-%d') as policy_effective_date,
		date_format(cph.policy_expiry_date,'%Y-%m-%d') as policy_expiry_date,cph.plan_type,cph.yom,cph.created_date 
        -- from mmi_customer_policy_history cph
        from mmi_ebm_policy_data cph
        left join mmi_lead_details mld on mld.vin = cph.vin and mld.engine_no = cph.engine_no-- on cph.cluster_id = mld.cluster_id
        -- where cph.created_date = (SELECT MAX(created_date) FROM mmi_ebm_policy_data cph2 WHERE cph2.vin = cph.vin) 
        -- and cph.cluster_id = clusterId 
        
        where -- cph.policy_expiry_date = (SELECT MAX(policy_expiry_date) FROM mmi_ebm_policy_data cph2 WHERE cph2.vin = cph.vin) 
        cph.cluster_id = clusterId 
        and cph.vin = v_chassis_no
        and mld.model = vehicleName -- and mld.lead_id = v_leadId
        -- group by cph.vin
        order by cph.policy_expiry_date desc LIMIT 5;   -- herek

    ELSEIF type = 'service' THEN
        select distinct csh.service_type,csh.repair_order_no,csh.service_category,csh.ro_date,csh.customer_mobile_no,csh.service_advisor,csh.created_date
		-- from mmi_customer_service_history csh left join 
        from mmi_ebm_service_data csh left join 
        mmi_mast_customer_details mcd on mcd.chassis_no = csh.chassis_number 
        left join mmi_lead_details mld on mld.vin = mcd.chassis_no and mld.engine_no = mcd.engine_no-- on mcd.cluster_id = mld.cluster_id 
        where mcd.cluster_id = clusterId and 
        mld.model = vehicleName and mld.vin = v_chassis_no-- mld.lead_id = v_leadId
        order by csh.created_date desc; 
        

    ELSEIF type = 'claim' THEN
        select distinct mld.policy_no,cch.claim_no, cch.claim_intimation_date_time,cch.nature_of_loss,
        cch.insurance_claim_no,cch.accident_city,cch.claim_status,cch.created_date 
        -- from mmi_customer_claim_history cch left join 
        from mmi_ebm_claim_data cch left join 
        mmi_mast_customer_details mcd on mcd.chassis_no = cch.chassis_number
        left join mmi_lead_details mld on mld.vin = mcd.chassis_no and mld.engine_no = mcd.engine_no -- on mcd.cluster_id = mld.cluster_id 
        where mcd.cluster_id = clusterId and
        -- mld.lead_id = v_leadId 
        mld.vin = v_chassis_no and mld.model = vehicleName order by cch.created_date desc;
        
    ELSEIF type = 'sales' THEN
        select distinct mcsh.invoice_number,mcsh.invoice_date_time,
        -- date_format(mcsh.invoice_date_time,'%Y-%m-%d') as invoice_date_time,
        mcsh.dealer_parent_code,mcsh.dealer_parent_name,mcsh.dealer_location_code,
        mcsh.created_date  
        -- from mmi_customer_sales_history mcsh left join 
        from mmi_ebm_sales_data mcsh left join 
        mmi_mast_customer_details mcd on mcd.chassis_no = mcsh.chassis_number
        left join mmi_lead_details mld on mld.vin = mcd.chassis_no and mld.engine_no = mcd.engine_no -- on mcd.cluster_id = mld.cluster_id 
        where mcd.cluster_id = clusterId and
        -- mld.lead_id = v_leadId 
        mld.vin = v_chassis_no and mld.model = vehicleName order by mcsh.created_date desc;
        
    ELSEIF type = 'reminder' THEN
		SELECT distinct -- crh.policy_id,crh.mode,crh.reminder_frequency,crh.created_date,
        crh.mode,crh.reminder_frequency,crh.created_date,
        date_format(crh.sent_date,'%Y-%m-%d') as sent_date FROM 
        -- date_format(crh.created_date,'%Y-%m-%d') as sent_date FROM 
        -- crh.sent_date 
        -- crh.renewal_link,crh.sent_date FROM 
        -- mmi_customer_renewalreminder_history crh left join mmi_lead_details mld 
        mmi_renewalreminder_data crh left join mmi_lead_details mld 
        on crh.policy_no = mld.policy_no where mld.cluster_id = clusterId and
        -- mld.lead_id = v_leadId 
        mld.vin = v_chassis_no and mld.model = vehicleName order by crh.created_date desc;
        
	ELSEIF type = 'communication' THEN
		-- select call_status,concat(step2_input,call_date) as NextCallDateTime,remarks,next_status 
		-- from mmi_call_disposition_history cdh left join mmi_mast_call_disposition mcd 
		-- on cdh.dealer_disposition_id = mcd.disposition_id where customer_id= clusterId;
        select concat(call_status,' | ',CONVERT( DATE_FORMAT(call_date,'%d/%m/%Y %H:%i') USING UTF8MB4)) as call_status,
		urd.first_name,concat(sub_disposition,' ',CONVERT( DATE_FORMAT(next_call_datetime,'%d/%m/%Y %H:%i') USING UTF8MB4))
		as NextCallDateTime,cdh.remarks,sub_disposition,cdh.created_date from mmi_call_disposition_history cdh left join 
        mmi_mast_disposition mcd on cdh.dealer_disposition_id = mcd.disposition_id
        left join mmi_mast_user_registration_detail urd on urd.id = cdh.agent_code
		left join mmi_agent_disposition_field_response adfr on adfr.response_id = cdh.id AND 
        field_value = sub_disposition
        where -- customer_id= clusterId and 
        cdh.lead_id = v_leadId
        and field_label = 'Sub Disposition' order by cdh.created_date desc;
        
    ELSEIF type = 'addon' THEN
		select distinct add_on_name,bundle_name,premium,addon.created_date from mmi_poladdon_data addon
		-- left join mmi_lead_details mld on addon.cluster_id = mld.cluster_id
		left join mmi_lead_details mld on addon.policy_no = mld.policy_no
        where mld.cluster_id= clusterId and mld.vin = v_chassis_no and
        -- mld.lead_id = v_leadId and mld.model = vehicleName and add_on_name IS NOT NULL
        addon.policy_no = v_policyno and add_on_name IS NOT NULL
        order by addon.created_date desc;
        
	ELSEIF type = 'remarks' THEN
       SELECT DISTINCT
        proposal_no,
        proposal_status,
        remarks,
        created_by,
        DATE_FORMAT(created_date,'%d/%m/%Y %H:%i') AS created_date
        
		FROM mmi_proposal_status_history
		WHERE lead_id = v_leadId
		  AND remarks IS NOT NULL
		  AND remarks <> ''
		ORDER BY created_date DESC;
    
     ELSEIF type = 'endorsement' THEN
			   SELECT DISTINCT  
			ced.fkpolicy_id AS policy_id,
			ced.endorsement_id,
			ced.policy_no,
			ced.endorsement_no,
			ced.endo_created_date,
			ced.approval_date,
			ced.endorsement_type_description,
			ced.total_prem_payable,
			DATE_FORMAT(ced.created_date,'%d/%m/%Y %H:%i') AS created_date

		FROM mmi_ebm_endorsement_data ced  

		INNER JOIN mmi_lead_details mld ON ced.policy_no = mld.policy_no  
		WHERE mld.cluster_id = clusterId
			AND mld.vin = v_chassis_no
			AND mld.model = vehicleName
		 -- AND mld.lead_id = v_leadId 
		ORDER BY created_date DESC;
        
    END IF;

    SET p_status_code = '200';
    SET p_status_message = 'Fetched successfully';
  END IF;  
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_get_customer_filters` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_customer_filters`(
    IN Json_data JSON,
    OUT p_status_code VARCHAR(500),
    OUT p_status_message VARCHAR(500)
)
BEGIN 

    DECLARE v_name VARCHAR(255);  
    DECLARE type VARCHAR(255); 
    DECLARE customerPhone VARCHAR(50);
    DECLARE chassisNo VARCHAR(100);
    DECLARE vehicleRegNo VARCHAR(50);
    DECLARE v_userid VARCHAR(50);
    DECLARE v_historyType VARCHAR(50);
    DECLARE calculated INT DEFAULT 0;
    DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 0;
    DECLARE v_dealer_code VARCHAR(50);
    DECLARE v_role VARCHAR(50);
    DECLARE v_reporting_manager VARCHAR(100);
    DECLARE v_search_name VARCHAR(100);
    DECLARE v_role_type_id INT;
	DECLARE v_status_type VARCHAR(45) DEFAULT "";
	DECLARE v_policy_no VARCHAR(100);
	DECLARE v_policy_tenure VARCHAR(100);
	DECLARE v_policy_type VARCHAR(100);
	DECLARE v_make VARCHAR(100);
	DECLARE v_model VARCHAR(100);
	DECLARE v_variant VARCHAR(1000);
	DECLARE v_vehicle_class VARCHAR(100);
	DECLARE v_engine_no VARCHAR(100);
	DECLARE v_insurance_company VARCHAR(100);
	DECLARE v_fuel_type VARCHAR(100);
	DECLARE v_yom VARCHAR(100);
	DECLARE v_add_on_name VARCHAR(100);
    DECLARE sortField VARCHAR(45);
    DECLARE sortOrder VARCHAR(45);

    DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        SET type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.type'));
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_customer_filters', type, CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;

    SET v_name = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customerName'));
    SET customerPhone = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customerPhone'));
    SET chassisNo = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.chassisNo'));
    SET vehicleRegNo = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.vehicleRegNo'));
    SET v_search_name = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.searchName'));
    SET v_userid = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
    SET v_historyType = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.historyType'));
    SET type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.type'));
	SET v_role_type_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleTypeId'));
	SET v_status_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.callQueType'));
    SET v_policy_no = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.policyNo'));
    SET v_policy_tenure = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.policyTenure'));
    SET v_policy_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.policyType'));
    SET v_make = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.make'));
    SET v_model = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.model'));
    SET v_variant = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.variant'));
    SET v_vehicle_class = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.vehicleClass'));
    SET v_engine_no = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.engineNo'));
	SET v_insurance_company = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.insuranceCompany'));
    SET v_fuel_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.fuelType'));
    SET v_yom = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.yom'));
	SET v_add_on_name = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.addonName'));
    SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));

	
    SET sortField = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.sortField'));
    SET sortOrder = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.sortOrder'));

    -- Set default sort field
    IF sortField IS NULL OR sortField = '' THEN
        SET sortField = 'expiryDays';
    END IF;

    -- Set default sort order
    IF sortOrder IS NULL OR sortOrder = '' THEN
        SET sortOrder = 'asc';
    END IF;

    IF type IS NULL THEN
        SET p_status_code = '400';
        SET p_status_message = 'Invalid input parameters. Required Fields cannot be NULL or empty';
    ELSE
    IF type = 'caller' then
    SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.limit')) AS UNSIGNED), 10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.offset')) AS UNSIGNED), 0);
    SET calculated = (offsetVal - 1) * limitVal;
	
	IF v_status_type = 'current' THEN

		
		WITH dealer_scope AS (
			SELECT DISTINCT dealer_code
			FROM mmi_dealer_location_mapping
			WHERE mapping_dealer_code = v_dealer_code
		), 
        latest_dispositions AS (
            SELECT
                h1.id,
                h1.lead_id,
                h1.dealer_disposition_id,
                h1.call_status,
                h1.call_date,
                h1.next_call_datetime,
                ROW_NUMBER() OVER (PARTITION BY h1.lead_id ORDER BY h1.call_date DESC) AS rn
            FROM mmi_call_disposition_history h1
        ),
        dispo_counts_by_lead AS (
            SELECT lead_id, COUNT(*) AS dispo_count
            FROM mmi_call_disposition_history
            GROUP BY lead_id
        ),
        caller_data AS (
            SELECT
                customer.customer_name AS customerName,
                lead_details.lead_id AS leadId,
                lead_details.lead_type AS leadType,
                lead_details.model AS vehicleName,
                CONCAT(user.first_name, ' ', user.last_name) AS agentName,
                DATE_FORMAT(lead_details.policy_expiry_date, '%Y-%m-%d') AS expiryDate,
                lead_details.expiry_days AS expiryDays,
                CONCAT(
                    IFNULL(latest_dispo.call_status, 'No Status'), ' | ',
                    DATE_FORMAT(latest_dispo.call_date, '%Y-%m-%d %H:%i:%s'), ' \n ',
                    IFNULL(adfr.field_value, ''), ' | ',
                    IFNULL(latest_dispo.next_call_datetime, '')
                ) AS recentUpdates,
                CONCAT(
                    IFNULL(adfr.field_value, ''),
                    CASE WHEN dispo_counts_by_lead.dispo_count > 0
                         THEN CONCAT('(', dispo_counts_by_lead.dispo_count, ')')
                         ELSE '' END
                ) AS status,
                customer.customer_phone AS phone_number,
                customer.chassis_no AS chassis_no,
                customer.vehicle_reg_no AS vehicle_reg_no,
                lead_details.assigned_agent,
                latest_dispo.next_call_datetime AS call_date_time,
                lead_details.renewal_category AS renewalCategory,
                userreporting.supervisor_id AS supervisor_id,
                customer.cluster_id AS clusterId,
                lead_details.policy_no,
                lead_details.policy_tenure,
                lead_details.policy_type,
                lead_details.make,
                lead_details.variant,
                lead_details.vehicle_class,
                lead_details.engine_no,
                lead_details.insurance_company,
                lead_details.fuel_type,
                lead_details.yom,
				customer.vehicle_reg_no AS vehicleRegNo,
                pd.add_on_name AS add_on_name,
				-- IFNULL(ebt.proposal_no, 'N/A') AS proposalNo, -- herek
				IFNULL(ebt.proposal_status, 'N/A') AS ebmStatus,
				-- IFNULL(mes.ebm_final_status, 'N/A') AS ebmFinalStatus,
				IFNULL(mes.ebm_status_color, 'N/A') AS ebmStatusColor,
                lead_details.vin as vin

				
            FROM mmi_lead_details lead_details
			INNER JOIN dealer_scope ds ON ds.dealer_code = lead_details.dealer_code
            LEFT JOIN mmi_mast_customer_details customer
              ON lead_details.vin = customer.chassis_no and lead_details.engine_no = customer.engine_no -- ON customer.cluster_id = lead_details.cluster_id
            LEFT JOIN latest_dispositions latest_dispo
              ON latest_dispo.lead_id = lead_details.lead_id AND latest_dispo.rn = 1
            LEFT JOIN dispo_counts_by_lead
              ON dispo_counts_by_lead.lead_id = lead_details.lead_id
            LEFT JOIN mmi_agent_disposition_field_response adfr
              ON adfr.response_id = latest_dispo.id AND adfr.field_label = 'Sub Disposition'
            LEFT JOIN mmi_mast_user_registration_detail user
              ON user.id = lead_details.assigned_agent
            LEFT JOIN mmi_user_reporting userreporting
              ON userreporting.user_id = user.id
            LEFT JOIN mmi_poladdon_data pd
              ON pd.policy_no = lead_details.policy_no
	      
	      -- EBM latest txn join -- herek
			LEFT JOIN mmi_crm_ebm_transaction_details ebt
				ON ebt.lead_id = lead_details.lead_id
			AND ebt.id = (
            SELECT MAX(id)
            FROM mmi_crm_ebm_transaction_details
            WHERE lead_id = lead_details.lead_id
      )

-- EBM status master mapping
LEFT JOIN mmi_mast_ebm_status mes
       ON mes.sub_ebm_status = ebt.proposal_status

        )
		
		
		SELECT 
        MAX(customerName) AS customerName,MAX(leadId) AS leadId,MAX(leadType) AS leadType,MAX(vehicleName) AS vehicleName,
		MAX(vehicleRegNo) AS vehicleRegNo,MAX(renewalCategory) AS renewalCategory,MAX(expiryDate) AS expiryDate,MAX(recentUpdates) AS recentUpdates,
		MAX(status) AS status,MAX(clusterId) AS clusterId,MAX(expiryDays) AS expiryDays, 
        -- MAX(proposalNo) AS proposalNo, -- herek
		MAX(ebmStatus) AS ebmStatus,
		-- MAX(ebmFinalStatus)   AS ebmFinalStatus,
		MAX(ebmStatusColor)   AS ebmStatusColor,MAX(vin) as chassisNo
        FROM caller_data WHERE assigned_agent = v_userid 
        -- AND call_date_time = CURRENT_DATE() 
		AND (DATE(call_date_time) = CURRENT_DATE() OR DATE(expiryDate) = CURRENT_DATE())
        AND (v_name IS NULL OR v_name = '' OR LOWER(TRIM(REGEXP_REPLACE(customerName, '\\s+', ' '))) LIKE CONCAT('%', LOWER(TRIM(REGEXP_REPLACE(v_name, '\\s+', ' '))), '%'))
		AND (customerPhone IS NULL OR customerPhone = '' OR phone_number LIKE CONCAT('%', customerPhone, '%'))
		AND (vehicleRegNo IS NULL OR vehicleRegNo = '' OR vehicle_reg_no LIKE CONCAT('%', vehicleRegNo, '%'))
		AND (chassisNo IS NULL OR chassisNo = '' OR  chassis_no LIKE CONCAT('%', chassisNo, '%'))
		AND (v_policy_no IS NULL OR v_policy_no = ''  OR policy_no LIKE CONCAT('%', v_policy_no, '%'))
		AND (v_policy_tenure IS NULL OR v_policy_tenure = '' OR policy_tenure LIKE CONCAT('%', v_policy_tenure, '%'))
		AND (v_policy_type IS NULL OR v_policy_type = '' OR policy_type LIKE CONCAT('%', v_policy_type, '%'))
		AND (v_make IS NULL OR v_make = '' OR make LIKE CONCAT('%', v_make, '%'))
		AND (v_model IS NULL OR v_model = '' OR vehicleName LIKE CONCAT('%', v_model, '%'))
		AND (v_variant IS NULL OR v_variant = '' OR variant LIKE CONCAT('%', v_variant, '%'))
		AND (v_vehicle_class IS NULL OR v_vehicle_class = '' OR vehicle_class LIKE CONCAT('%', v_vehicle_class, '%'))
		AND (v_engine_no IS NULL OR v_engine_no = '' OR engine_no LIKE CONCAT('%', v_engine_no, '%'))
		AND (v_insurance_company IS NULL OR v_insurance_company = ''  OR v_insurance_company = '' OR insurance_company LIKE CONCAT('%', v_insurance_company, '%'))
		AND (v_fuel_type IS NULL OR v_fuel_type = ''  OR fuel_type LIKE CONCAT('%', v_fuel_type, '%'))
		AND (v_yom IS NULL OR v_yom = ''  OR yom LIKE CONCAT('%', v_yom, '%'))
		AND (v_add_on_name IS NULL OR v_add_on_name = ''  OR add_on_name LIKE CONCAT('%', v_add_on_name, '%'))
        group by chassis_no ORDER BY 
        CASE WHEN sortField = 'Expiry Date' AND sortOrder = 'asc' THEN CAST(MAX(expiryDays) as UNSIGNED) END ASC,
		CASE WHEN sortField = 'Expiry Date' AND sortOrder = 'desc' THEN CAST(MAX(expiryDays) as UNSIGNED) END DESC,
        CASE WHEN sortField = 'customerName' AND sortOrder = 'asc' THEN MAX(customerName) END ASC,
        CASE WHEN sortField = 'customerName' AND sortOrder = 'desc' THEN MAX(customerName) END DESC,
        CASE WHEN sortField = 'status' AND sortOrder = 'asc' THEN MAX(status) END ASC,
        CASE WHEN sortField = 'status' AND sortOrder = 'desc' THEN MAX(status) END DESC,
        CASE WHEN sortField = 'Vehicle Name' AND sortOrder = 'asc' THEN MAX(vehicleName) END ASC,
		CASE WHEN sortField = 'Vehicle Name' AND sortOrder = 'desc' THEN MAX(vehicleName) END DESC,
        CASE WHEN sortField = 'Renewal Category' AND sortOrder = 'asc' THEN MAX(renewalCategory) END ASC,
        CASE WHEN sortField = 'Renewal Category' AND sortOrder = 'desc' THEN MAX(renewalCategory) END DESC
        LIMIT limitVal OFFSET calculated;
        
	END IF;
		
		WITH dealer_scope AS (
			SELECT DISTINCT dealer_code
			FROM mmi_dealer_location_mapping
			WHERE mapping_dealer_code = v_dealer_code
		), 
        latest_dispositions AS (
            SELECT
                h1.id,
                h1.lead_id,
                h1.dealer_disposition_id,
                h1.call_status,
                h1.call_date,
                h1.next_call_datetime,
                ROW_NUMBER() OVER (PARTITION BY h1.lead_id ORDER BY h1.call_date DESC) AS rn
            FROM mmi_call_disposition_history h1
        ),
        dispo_counts_by_lead AS (
            SELECT lead_id, COUNT(*) AS dispo_count
            FROM mmi_call_disposition_history
            GROUP BY lead_id
        ),
        caller_data AS (
            SELECT
                customer.customer_name AS customerName,
                lead_details.lead_id AS leadId,
                lead_details.lead_type AS leadType,
                lead_details.model AS vehicleName,
                CONCAT(user.first_name, ' ', user.last_name) AS agentName,
                DATE_FORMAT(lead_details.policy_expiry_date, '%Y-%m-%d') AS expiryDate,
                lead_details.expiry_days AS expiryDays,
                CONCAT(
                    IFNULL(latest_dispo.call_status, 'No Status'), ' | ',
                    DATE_FORMAT(latest_dispo.call_date, '%Y-%m-%d %H:%i:%s'), ' \n ',
                    IFNULL(adfr.field_value, ''), ' | ',
                    IFNULL(latest_dispo.next_call_datetime, '')
                ) AS recentUpdates,
                CONCAT(
                    IFNULL(adfr.field_value, ''),
                    CASE WHEN dispo_counts_by_lead.dispo_count > 0
                         THEN CONCAT('(', dispo_counts_by_lead.dispo_count, ')')
                         ELSE '' END
                ) AS status,
                customer.customer_phone AS phone_number,
                customer.chassis_no AS chassis_no,
                customer.vehicle_reg_no AS vehicle_reg_no,
                lead_details.assigned_agent,
                latest_dispo.next_call_datetime AS call_date_time,
                lead_details.renewal_category AS renewalCategory,
                userreporting.supervisor_id AS supervisor_id,
                customer.cluster_id AS clusterId,
                lead_details.policy_no,
                lead_details.policy_tenure,
                lead_details.policy_type,
                lead_details.make,
                lead_details.variant,
                lead_details.vehicle_class,
                lead_details.engine_no,
                lead_details.insurance_company,
                lead_details.fuel_type,
                lead_details.yom,
				customer.vehicle_reg_no AS vehicleRegNo,
                pd.add_on_name AS add_on_name,
               -- IFNULL(ebt.proposal_no, 'N/A')        AS proposalNo,
				IFNULL(ebt.proposal_status, 'N/A')    AS ebmStatus,
				-- IFNULL(mes.ebm_final_status, 'N/A')   AS ebmFinalStatus,
				IFNULL(mes.ebm_status_color, 'N/A')   AS ebmStatusColor,
                lead_details.vin as vin


            FROM mmi_lead_details lead_details
			INNER JOIN dealer_scope ds ON ds.dealer_code = lead_details.dealer_code
            LEFT JOIN mmi_mast_customer_details customer
              ON lead_details.vin = customer.chassis_no and lead_details.engine_no = customer.engine_no -- ON customer.cluster_id = lead_details.cluster_id
            LEFT JOIN latest_dispositions latest_dispo
              ON latest_dispo.lead_id = lead_details.lead_id AND latest_dispo.rn = 1
            LEFT JOIN dispo_counts_by_lead
              ON dispo_counts_by_lead.lead_id = lead_details.lead_id
            LEFT JOIN mmi_agent_disposition_field_response adfr
              ON adfr.response_id = latest_dispo.id AND adfr.field_label = 'Sub Disposition'
            LEFT JOIN mmi_mast_user_registration_detail user
              ON user.id = lead_details.assigned_agent
            LEFT JOIN mmi_user_reporting userreporting
              ON userreporting.user_id = user.id
            LEFT JOIN mmi_poladdon_data pd
              ON pd.policy_no = lead_details.policy_no
              
	      -- EBM latest txn join -- herek
			LEFT JOIN mmi_crm_ebm_transaction_details ebt
				ON ebt.lead_id = lead_details.lead_id
			AND ebt.id = (
            SELECT MAX(id)
            FROM mmi_crm_ebm_transaction_details
            WHERE lead_id = lead_details.lead_id
      )
			-- EBM status master mapping
			LEFT JOIN mmi_mast_ebm_status mes
			   ON mes.sub_ebm_status = ebt.proposal_status
        )
		
        SELECT 
        MAX(customerName) AS customerName,MAX(leadId) AS leadId,MAX(leadType) AS leadType,MAX(vehicleName) AS vehicleName,
		MAX(vehicleRegNo) AS vehicleRegNo,MAX(renewalCategory) AS renewalCategory,MAX(expiryDate) AS expiryDate,MAX(recentUpdates) AS recentUpdates,
		MAX(status) AS status,MAX(clusterId) AS clusterId,MAX(expiryDays) AS expiryDays, 
        -- MAX(proposalNo)       AS proposalNo,
		MAX(ebmStatus)        AS ebmStatus,
		-- MAX(ebmFinalStatus)   AS ebmFinalStatus,
		MAX(ebmStatusColor)   AS ebmStatusColor,MAX(vin) as chassisNo

        FROM caller_data WHERE assigned_agent = v_userid 
        AND (v_name IS NULL OR v_name = '' OR LOWER(TRIM(REGEXP_REPLACE(customerName, '\\s+', ' '))) LIKE CONCAT('%', LOWER(TRIM(REGEXP_REPLACE(v_name, '\\s+', ' '))), '%'))
		AND (customerPhone IS NULL OR customerPhone = '' OR phone_number LIKE CONCAT('%', customerPhone, '%'))
		AND (vehicleRegNo IS NULL OR vehicleRegNo = '' OR vehicle_reg_no LIKE CONCAT('%', vehicleRegNo, '%'))
		AND (chassisNo IS NULL OR chassisNo = '' OR  chassis_no LIKE CONCAT('%', chassisNo, '%'))
		AND (v_policy_no IS NULL OR v_policy_no = ''  OR policy_no LIKE CONCAT('%', v_policy_no, '%'))
		AND (v_policy_tenure IS NULL OR v_policy_tenure = '' OR policy_tenure LIKE CONCAT('%', v_policy_tenure, '%'))
		AND (v_policy_type IS NULL OR v_policy_type = '' OR policy_type LIKE CONCAT('%', v_policy_type, '%'))
		AND (v_make IS NULL OR v_make = '' OR make LIKE CONCAT('%', v_make, '%'))
		AND (v_model IS NULL OR v_model = '' OR vehicleName LIKE CONCAT('%', v_model, '%'))
		AND (v_variant IS NULL OR v_variant = '' OR variant LIKE CONCAT('%', v_variant, '%'))
		AND (v_vehicle_class IS NULL OR v_vehicle_class = '' OR vehicle_class LIKE CONCAT('%', v_vehicle_class, '%'))
		AND (v_engine_no IS NULL OR v_engine_no = '' OR engine_no LIKE CONCAT('%', v_engine_no, '%'))
		AND (v_insurance_company IS NULL OR v_insurance_company = ''  OR v_insurance_company = '' OR insurance_company LIKE CONCAT('%', v_insurance_company, '%'))
		AND (v_fuel_type IS NULL OR v_fuel_type = ''  OR fuel_type LIKE CONCAT('%', v_fuel_type, '%'))
		AND (v_yom IS NULL OR v_yom = ''  OR yom LIKE CONCAT('%', v_yom, '%'))
		AND (v_add_on_name IS NULL OR v_add_on_name = ''  OR add_on_name LIKE CONCAT('%', v_add_on_name, '%'))
        group by chassis_no 
        ORDER BY
        CASE WHEN sortField = 'Expiry Date' AND sortOrder = 'asc' THEN CAST(MAX(expiryDays) as UNSIGNED) END ASC,
		CASE WHEN sortField = 'Expiry Date' AND sortOrder = 'desc' THEN CAST(MAX(expiryDays) as UNSIGNED) END DESC,
        CASE WHEN sortField = 'customerName' AND sortOrder = 'asc' THEN MAX(customerName) END ASC,
        CASE WHEN sortField = 'customerName' AND sortOrder = 'desc' THEN MAX(customerName) END DESC,
        CASE WHEN sortField = 'status' AND sortOrder = 'asc' THEN MAX(status) END ASC,
        CASE WHEN sortField = 'status' AND sortOrder = 'desc' THEN MAX(status) END DESC,
        CASE WHEN sortField = 'Vehicle Name' AND sortOrder = 'asc' THEN MAX(vehicleName) END ASC,
		CASE WHEN sortField = 'Vehicle Name' AND sortOrder = 'desc' THEN MAX(vehicleName) END DESC,
