                h1.call_status,
                h1.call_date,
                h1.next_call_datetime,
                ROW_NUMBER() OVER (PARTITION BY h1.lead_id ORDER BY h1.call_date DESC) AS rn
            FROM mmi_call_disposition_history h1
        ),
        dispo_counts_by_lead AS (
            SELECT lead_id, COUNT(*) AS dispo_count
            FROM mmi_call_disposition_history
            GROUP BY lead_id
        ),
        caller_data AS (
            SELECT
                customer.customer_name AS customerName,
                lead_details.lead_id AS leadId,
                lead_details.lead_type AS leadType,
                lead_details.model AS vehicleName,
                CONCAT(user.first_name, ' ', user.last_name) AS agentName,
                DATE_FORMAT(lead_details.policy_expiry_date, '%Y-%m-%d') AS expiryDate,
                lead_details.expiry_days AS expiryDays,
                CONCAT(
                    IFNULL(latest_dispo.call_status, 'No Status'), ' | ',
                    DATE_FORMAT(latest_dispo.call_date, '%Y-%m-%d %H:%i:%s'), ' \n ',
                    IFNULL(adfr.field_value, ''), ' | ',
                    IFNULL(latest_dispo.next_call_datetime, '')
                ) AS recentUpdates,
                CONCAT(
                    IFNULL(adfr.field_value, ''),
                    CASE WHEN dispo_counts_by_lead.dispo_count > 0
                         THEN CONCAT('(', dispo_counts_by_lead.dispo_count, ')')
                         ELSE '' END
                ) AS status,
                customer.customer_phone AS phone_number,
                customer.chassis_no AS chassis_no,
                customer.vehicle_reg_no AS vehicle_reg_no,
                lead_details.assigned_agent,
                latest_dispo.next_call_datetime AS call_date_time,
                lead_details.renewal_category AS renewalCategory,
                userreporting.supervisor_id AS supervisor_id,
                customer.cluster_id AS clusterId,
                lead_details.policy_no,
                lead_details.policy_tenure,
                lead_details.policy_type,
                lead_details.make,
                lead_details.variant,
                lead_details.vehicle_class,
                lead_details.engine_no,
                lead_details.insurance_company,
                lead_details.fuel_type,
                lead_details.yom,
				customer.vehicle_reg_no AS vehicleRegNo,
                pd.add_on_name AS add_on_name,
	
				-- IFNULL(ebt.proposal_no, 'N/A') AS proposalNo,
				IFNULL(ebt.proposal_status, 'N/A') AS ebmStatus,
				-- IFNULL(mes.ebm_final_status, 'N/A) AS ebmFinalStatus,
				IFNULL(mes.ebm_status_color, 'N/A') AS ebmStatusColor,
                lead_details.vin as vin


            FROM mmi_lead_details lead_details
			INNER JOIN dealer_scope ds ON ds.dealer_code = lead_details.dealer_code
            LEFT JOIN mmi_mast_customer_details customer
              ON lead_details.vin = customer.chassis_no and lead_details.engine_no = customer.engine_no -- ON customer.cluster_id = lead_details.cluster_id
            LEFT JOIN latest_dispositions latest_dispo
              ON latest_dispo.lead_id = lead_details.lead_id AND latest_dispo.rn = 1
            LEFT JOIN dispo_counts_by_lead
              ON dispo_counts_by_lead.lead_id = lead_details.lead_id
            LEFT JOIN mmi_agent_disposition_field_response adfr
              ON adfr.response_id = latest_dispo.id AND adfr.field_label = 'Sub Disposition'
            LEFT JOIN mmi_mast_user_registration_detail user
              ON user.id = lead_details.assigned_agent
            LEFT JOIN mmi_user_reporting userreporting
              ON userreporting.user_id = user.id
            LEFT JOIN mmi_poladdon_data pd
              ON pd.policy_no = lead_details.policy_no
            LEFT JOIN supervisor_hierarchy sh
              ON sh.user_id = userreporting.supervisor_id
	      
	     /* -- EBM latest transaction join
		LEFT JOIN mmi_crm_ebm_transaction_details ebt
			ON ebt.lead_id = lead_details.lead_id
		AND ebt.id = (
            SELECT MAX(id)
            FROM mmi_crm_ebm_transaction_details
            WHERE lead_id = lead_details.lead_id
      )

		-- EBM status master mapping
			LEFT JOIN mmi_mast_ebm_status mes
				ON mes.sub_ebm_status = ebt.proposal_status */

        )
		
        SELECT COUNT(*) AS total
		FROM (
			SELECT MAX(leadId)
			FROM caller_data
			WHERE -- supervisor_id = v_userid and 
			  assigned_agent <> v_userid
			  AND (v_name IS NULL OR v_name = '' OR LOWER(TRIM(REGEXP_REPLACE(customerName, '\\s+', ' '))) LIKE CONCAT('%', LOWER(TRIM(REGEXP_REPLACE(v_name, '\\s+', ' '))), '%'))
			  AND (customerPhone IS NULL OR customerPhone = '' OR phone_number LIKE CONCAT('%', customerPhone, '%'))
			  AND (vehicleRegNo IS NULL OR vehicleRegNo = '' OR vehicle_reg_no LIKE CONCAT('%', vehicleRegNo, '%'))
			  AND (chassisNo IS NULL OR chassisNo = '' OR  chassis_no LIKE CONCAT('%', chassisNo, '%'))
			  AND (v_policy_no IS NULL OR v_policy_no = ''  OR policy_no LIKE CONCAT('%', v_policy_no, '%'))
			  AND (v_policy_tenure IS NULL OR v_policy_tenure = '' OR policy_tenure LIKE CONCAT('%', v_policy_tenure, '%'))
			  AND (v_policy_type IS NULL OR v_policy_type = '' OR policy_type LIKE CONCAT('%', v_policy_type, '%'))
			  AND (v_make IS NULL OR v_make = '' OR make LIKE CONCAT('%', v_make, '%'))
			  AND (v_model IS NULL OR v_model = '' OR vehicleName LIKE CONCAT('%', v_model, '%'))
			  AND (v_variant IS NULL OR v_variant = '' OR variant LIKE CONCAT('%', v_variant, '%'))
			  AND (v_vehicle_class IS NULL OR v_vehicle_class = '' OR vehicle_class LIKE CONCAT('%', v_vehicle_class, '%'))
			  AND (v_engine_no IS NULL OR v_engine_no = '' OR engine_no LIKE CONCAT('%', v_engine_no, '%'))
			  AND (v_insurance_company IS NULL OR v_insurance_company = ''  OR insurance_company LIKE CONCAT('%', v_insurance_company, '%'))
			  AND (v_fuel_type IS NULL OR v_fuel_type = ''  OR fuel_type LIKE CONCAT('%', v_fuel_type, '%'))
			  AND (v_yom IS NULL OR v_yom = ''  OR yom LIKE CONCAT('%', v_yom, '%'))
			  AND (v_add_on_name IS NULL OR v_add_on_name = ''  OR add_on_name LIKE CONCAT('%', v_add_on_name, '%'))
			GROUP BY chassis_no
			ORDER BY
			CASE WHEN sortField = 'Expiry Date' AND sortOrder = 'asc' THEN CAST(MAX(expiryDays) as UNSIGNED) END ASC,
			CASE WHEN sortField = 'Expiry Date' AND sortOrder = 'desc' THEN CAST(MAX(expiryDays) as UNSIGNED) END DESC,
			CASE WHEN sortField = 'customerName' AND sortOrder = 'asc' THEN MAX(customerName) END ASC,
			CASE WHEN sortField = 'customerName' AND sortOrder = 'desc' THEN MAX(customerName) END DESC,
			CASE WHEN sortField = 'status' AND sortOrder = 'asc' THEN MAX(status) END ASC,
			CASE WHEN sortField = 'status' AND sortOrder = 'desc' THEN MAX(status) END DESC,
            CASE WHEN sortField = 'Vehicle Name' AND sortOrder = 'asc' THEN MAX(vehicleName) END ASC,
			CASE WHEN sortField = 'Vehicle Name' AND sortOrder = 'desc' THEN MAX(vehicleName) END DESC,
			CASE WHEN sortField = 'Renewal Category' AND sortOrder = 'asc' THEN MAX(renewalCategory) END ASC,
			CASE WHEN sortField = 'Renewal Category' AND sortOrder = 'desc' THEN MAX(renewalCategory) END DESC
		) AS counted_data;

    ELSEIF type = 'assigned' then
    SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.limit')) AS UNSIGNED), 10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.offset')) AS UNSIGNED), 0);
    SET calculated = (offsetVal - 1) * limitVal;

        WITH RECURSIVE subordinates AS (
        SELECT ur.user_id
        FROM mmi_user_reporting ur
        WHERE ur.supervisor_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
        UNION ALL
        SELECT ur.user_id
        FROM mmi_user_reporting ur
        INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
    ) 
        SELECT MAX(leadId) AS leadId,MAX(customerName) AS customerName,MAX(model) AS model,
        MAX(agentName) AS agentName,MAX(renewalCategory) AS renewalCategory,MAX(date_format(policy_expiry_date,'%d %b %Y')) AS policy_expiry_date,
        MAX(expiry_days) AS expiry_days,MAX(assigned_agent) AS agentId,MAX(leadType) AS leadType, 
        -- MAX(proposalNo) AS proposalNo,
		MAX(ebmStatus) AS ebmStatus,
		-- MAX(ebmFinalStatus) AS ebmFinalStatus,
		MAX(ebmStatusColor) AS ebmStatusColor
		FROM mmi_get_all_lead_details
		left join mmi_dealer_location_mapping dlm on dlm.dealer_code = mmi_get_all_lead_details.dealer_code
        WHERE dlm.mapping_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
        AND assigned_agent IN (SELECT user_id FROM subordinates) 
		AND (v_name IS NULL OR v_name = '' OR LOWER(TRIM(REGEXP_REPLACE(customerName, '\\s+', ' '))) LIKE CONCAT('%', LOWER(TRIM(REGEXP_REPLACE(v_name, '\\s+', ' '))), '%'))
		AND (customerPhone IS NULL OR customerPhone = '' OR phone_number LIKE CONCAT('%', customerPhone, '%'))
		AND (vehicleRegNo IS NULL OR vehicleRegNo = '' OR vehicle_reg_no LIKE CONCAT('%', vehicleRegNo, '%'))
		AND (chassisNo IS NULL OR chassisNo = '' OR  chassis_no LIKE CONCAT('%', chassisNo, '%'))
		AND (v_policy_no IS NULL OR v_policy_no = ''  OR policy_no LIKE CONCAT('%', v_policy_no, '%'))
		AND (v_policy_tenure IS NULL OR v_policy_tenure = '' OR policy_tenure LIKE CONCAT('%', v_policy_tenure, '%'))
		AND (v_policy_type IS NULL OR v_policy_type = '' OR policy_type LIKE CONCAT('%', v_policy_type, '%'))
		AND (v_make IS NULL OR v_make = '' OR make LIKE CONCAT('%', v_make, '%'))
		AND (v_model IS NULL OR v_model = '' OR model LIKE CONCAT('%', v_model, '%'))
		AND (v_variant IS NULL OR v_variant = '' OR variant LIKE CONCAT('%', v_variant, '%'))
		AND (v_vehicle_class IS NULL OR v_vehicle_class = '' OR vehicle_class LIKE CONCAT('%', v_vehicle_class, '%'))
		AND (v_engine_no IS NULL OR v_engine_no = '' OR engine_no LIKE CONCAT('%', v_engine_no, '%'))
		AND (v_insurance_company IS NULL OR v_insurance_company = ''  OR insurance_company LIKE CONCAT('%', v_insurance_company, '%'))
		AND (v_fuel_type IS NULL OR v_fuel_type = ''  OR fuel_type LIKE CONCAT('%', v_fuel_type, '%'))
		AND (v_yom IS NULL OR v_yom = ''  OR yom LIKE CONCAT('%', v_yom, '%'))
		AND (v_add_on_name IS NULL OR v_add_on_name = ''  OR add_on_name LIKE CONCAT('%', v_add_on_name, '%'))
        group by chassis_no
		ORDER BY CAST(MAX(expiry_days) AS UNSIGNED) ASC LIMIT limitVal OFFSET calculated;


        SELECT
    (
		SELECT COUNT(*) FROM (
        SELECT MAX(DISTINCT ml.lead_id)
        FROM mmi_lead_details ml
		left join mmi_dealer_location_mapping dlm on dlm.dealer_code = ml.dealer_code
        LEFT JOIN mmi_mast_customer_details mc ON ml.vin = mc.chassis_no and ml.engine_no = mc.engine_no -- ON ml.cluster_id = mc.cluster_id
		LEFT JOIN mmi_poladdon_data pd on pd.policy_no = ml.policy_no
		LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent
        WHERE dlm.mapping_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
        AND ml.assigned_agent IS NULL
        AND (v_name IS NULL OR v_name = '' OR LOWER(TRIM(REGEXP_REPLACE(mc.customer_name, '\\s+', ' '))) LIKE CONCAT('%', LOWER(TRIM(REGEXP_REPLACE(v_name, '\\s+', ' '))), '%'))
		AND (customerPhone IS NULL OR customerPhone = '' OR mc.customer_phone LIKE CONCAT('%', customerPhone, '%'))
		AND (vehicleRegNo IS NULL OR vehicleRegNo = '' OR mc.vehicle_reg_no LIKE CONCAT('%', vehicleRegNo, '%'))
		AND (chassisNo IS NULL OR chassisNo = '' OR  mc.chassis_no LIKE CONCAT('%', chassisNo, '%'))
		AND (v_policy_no IS NULL OR v_policy_no = ''  OR ml.policy_no LIKE CONCAT('%', v_policy_no, '%'))
		AND (v_policy_tenure IS NULL OR v_policy_tenure = '' OR ml.policy_tenure LIKE CONCAT('%', v_policy_tenure, '%'))
		AND (v_policy_type IS NULL OR v_policy_type = '' OR ml.policy_type LIKE CONCAT('%', v_policy_type, '%'))
		AND (v_make IS NULL OR v_make = '' OR ml.make LIKE CONCAT('%', v_make, '%'))
		AND (v_model IS NULL OR v_model = '' OR ml.model LIKE CONCAT('%', v_model, '%'))
		AND (v_variant IS NULL OR v_variant = '' OR ml.variant LIKE CONCAT('%', v_variant, '%'))
		AND (v_vehicle_class IS NULL OR v_vehicle_class = '' OR ml.vehicle_class LIKE CONCAT('%', v_vehicle_class, '%'))
		AND (v_engine_no IS NULL OR v_engine_no = '' OR ml.engine_no LIKE CONCAT('%', v_engine_no, '%'))
		AND (v_insurance_company IS NULL OR v_insurance_company = ''  OR ml.insurance_company LIKE CONCAT('%', v_insurance_company, '%'))
		AND (v_fuel_type IS NULL OR v_fuel_type = ''  OR ml.fuel_type LIKE CONCAT('%', v_fuel_type, '%'))
		AND (v_yom IS NULL OR v_yom = ''  OR ml.yom LIKE CONCAT('%', v_yom, '%'))
		AND (v_add_on_name IS NULL OR v_add_on_name = ''  OR pd.add_on_name LIKE CONCAT('%', v_add_on_name, '%'))
        group by mc.chassis_no
		) AS Unassigned
    ) AS unassignedCount,

    (
		SELECT COUNT(*) FROM (
        SELECT MAX(ml.lead_id)
        FROM mmi_lead_details ml
		left join mmi_dealer_location_mapping dlm on dlm.dealer_code = ml.dealer_code
        LEFT JOIN mmi_mast_customer_details mc ON ml.vin = mc.chassis_no and ml.engine_no = mc.engine_no -- ON ml.cluster_id = mc.cluster_id
		LEFT JOIN mmi_poladdon_data pd on pd.policy_no = ml.policy_no
		LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent
        INNER JOIN (
            WITH RECURSIVE subordinates AS (
                SELECT ur.user_id
                FROM mmi_user_reporting ur
                -- WHERE ur.supervisor_id <> JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
                WHERE ur.supervisor_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
                UNION ALL
                SELECT ur.user_id
                FROM mmi_user_reporting ur
                INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
            )
            SELECT * FROM subordinates
        ) AS s ON ml.assigned_agent = s.user_id
        WHERE dlm.mapping_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
        AND (v_name IS NULL OR v_name = '' OR LOWER(TRIM(REGEXP_REPLACE(mc.customer_name, '\\s+', ' '))) LIKE CONCAT('%', LOWER(TRIM(REGEXP_REPLACE(v_name, '\\s+', ' '))), '%'))
		AND (customerPhone IS NULL OR customerPhone = '' OR mc.customer_phone LIKE CONCAT('%', customerPhone, '%'))
		AND (vehicleRegNo IS NULL OR vehicleRegNo = '' OR mc.vehicle_reg_no LIKE CONCAT('%', vehicleRegNo, '%'))
		AND (chassisNo IS NULL OR chassisNo = '' OR  mc.chassis_no LIKE CONCAT('%', chassisNo, '%'))
		AND (v_policy_no IS NULL OR v_policy_no = ''  OR ml.policy_no LIKE CONCAT('%', v_policy_no, '%'))
		AND (v_policy_tenure IS NULL OR v_policy_tenure = '' OR ml.policy_tenure LIKE CONCAT('%', v_policy_tenure, '%'))
		AND (v_policy_type IS NULL OR v_policy_type = '' OR ml.policy_type LIKE CONCAT('%', v_policy_type, '%'))
		AND (v_make IS NULL OR v_make = '' OR ml.make LIKE CONCAT('%', v_make, '%'))
		AND (v_model IS NULL OR v_model = '' OR ml.model LIKE CONCAT('%', v_model, '%'))
		AND (v_variant IS NULL OR v_variant = '' OR ml.variant LIKE CONCAT('%', v_variant, '%'))
		AND (v_vehicle_class IS NULL OR v_vehicle_class = '' OR ml.vehicle_class LIKE CONCAT('%', v_vehicle_class, '%'))
		AND (v_engine_no IS NULL OR v_engine_no = '' OR ml.engine_no LIKE CONCAT('%', v_engine_no, '%'))
		AND (v_insurance_company IS NULL OR v_insurance_company = ''  OR ml.insurance_company LIKE CONCAT('%', v_insurance_company, '%'))
		AND (v_fuel_type IS NULL OR v_fuel_type = ''  OR ml.fuel_type LIKE CONCAT('%', v_fuel_type, '%'))
		AND (v_yom IS NULL OR v_yom = ''  OR ml.yom LIKE CONCAT('%', v_yom, '%'))
		AND (v_add_on_name IS NULL OR v_add_on_name = ''  OR pd.add_on_name LIKE CONCAT('%', v_add_on_name, '%'))
        group by mc.chassis_no
		) AS assigned
    ) AS assignedCount,

    (
		SELECT COUNT(*) FROM (
        SELECT MAX(ml.lead_id)
        FROM mmi_lead_details ml
		left join mmi_dealer_location_mapping dlm on dlm.dealer_code = ml.dealer_code
        LEFT JOIN mmi_mast_customer_details mc ON ml.vin = mc.chassis_no and ml.engine_no = mc.engine_no -- ON ml.cluster_id = mc.cluster_id
		LEFT JOIN mmi_poladdon_data pd on pd.policy_no = ml.policy_no
		LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent
        WHERE dlm.mapping_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
        AND ml.assigned_agent = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
        AND (v_name IS NULL OR v_name = '' OR LOWER(TRIM(REGEXP_REPLACE(mc.customer_name, '\\s+', ' '))) LIKE CONCAT('%', LOWER(TRIM(REGEXP_REPLACE(v_name, '\\s+', ' '))), '%'))
		AND (customerPhone IS NULL OR customerPhone = '' OR mc.customer_phone LIKE CONCAT('%', customerPhone, '%'))
		AND (vehicleRegNo IS NULL OR vehicleRegNo = '' OR mc.vehicle_reg_no LIKE CONCAT('%', vehicleRegNo, '%'))
		AND (chassisNo IS NULL OR chassisNo = '' OR  mc.chassis_no LIKE CONCAT('%', chassisNo, '%'))
		AND (v_policy_no IS NULL OR v_policy_no = ''  OR ml.policy_no LIKE CONCAT('%', v_policy_no, '%'))
		AND (v_policy_tenure IS NULL OR v_policy_tenure = '' OR ml.policy_tenure LIKE CONCAT('%', v_policy_tenure, '%'))
		AND (v_policy_type IS NULL OR v_policy_type = '' OR ml.policy_type LIKE CONCAT('%', v_policy_type, '%'))
		AND (v_make IS NULL OR v_make = '' OR ml.make LIKE CONCAT('%', v_make, '%'))
		AND (v_model IS NULL OR v_model = '' OR ml.model LIKE CONCAT('%', v_model, '%'))
		AND (v_variant IS NULL OR v_variant = '' OR ml.variant LIKE CONCAT('%', v_variant, '%'))
		AND (v_vehicle_class IS NULL OR v_vehicle_class = '' OR ml.vehicle_class LIKE CONCAT('%', v_vehicle_class, '%'))
		AND (v_engine_no IS NULL OR v_engine_no = '' OR ml.engine_no LIKE CONCAT('%', v_engine_no, '%'))
		AND (v_insurance_company IS NULL OR v_insurance_company = ''  OR ml.insurance_company LIKE CONCAT('%', v_insurance_company, '%'))
		AND (v_fuel_type IS NULL OR v_fuel_type = ''  OR ml.fuel_type LIKE CONCAT('%', v_fuel_type, '%'))
		AND (v_yom IS NULL OR v_yom = ''  OR ml.yom LIKE CONCAT('%', v_yom, '%'))
		AND (v_add_on_name IS NULL OR v_add_on_name = ''  OR pd.add_on_name LIKE CONCAT('%', v_add_on_name, '%'))
        group by mc.chassis_no
		) AS myLead
    ) AS myLeadCount,
	
	(
		SELECT COUNT(*) FROM (
		select MAX(lad.lead_id) as leadId
			from mmi_lead_archive_details lad
			left join mmi_dealer_location_mapping dlm on dlm.dealer_code = lad.dealer_code
			LEFT JOIN mmi_mast_customer_details mc ON lad.vin = mc.chassis_no and lad.engine_no = mc.engine_no -- on lad.cluster_id=mc.cluster_id
			LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = lad.assigned_agent
			LEFT JOIN mmi_user_dealer_mapping udm on lad.assigned_agent = udm.user_id and udm.dealer_id = lad.dealer_code
			LEFT JOIN mmi_poladdon_data pd on pd.policy_no = lad.policy_no
			WHERE dlm.mapping_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode')) and lad.lead_status = 'Lost'
			AND (v_name IS NULL OR v_name = '' OR LOWER(TRIM(REGEXP_REPLACE(mc.customer_name, '\\s+', ' '))) LIKE CONCAT('%', LOWER(TRIM(REGEXP_REPLACE(v_name, '\\s+', ' '))), '%'))
			AND (customerPhone IS NULL OR customerPhone = '' OR mc.customer_phone LIKE CONCAT('%', customerPhone, '%'))
			AND (vehicleRegNo IS NULL OR vehicleRegNo = '' OR mc.vehicle_reg_no LIKE CONCAT('%', vehicleRegNo, '%'))
			AND (chassisNo IS NULL OR chassisNo = '' OR  mc.chassis_no LIKE CONCAT('%', chassisNo, '%'))
			AND (v_policy_no IS NULL OR v_policy_no = ''  OR lad.policy_no LIKE CONCAT('%', v_policy_no, '%'))
			AND (v_policy_tenure IS NULL OR v_policy_tenure = '' OR lad.policy_tenure LIKE CONCAT('%', v_policy_tenure, '%'))
			AND (v_policy_type IS NULL OR v_policy_type = '' OR lad.policy_type LIKE CONCAT('%', v_policy_type, '%'))
			AND (v_make IS NULL OR v_make = '' OR lad.make LIKE CONCAT('%', v_make, '%'))
			AND (v_model IS NULL OR v_model = '' OR lad.model LIKE CONCAT('%', v_model, '%'))
			AND (v_variant IS NULL OR v_variant = '' OR lad.variant LIKE CONCAT('%', v_variant, '%'))
			AND (v_vehicle_class IS NULL OR v_vehicle_class = '' OR lad.vehicle_class LIKE CONCAT('%', v_vehicle_class, '%'))
			AND (v_engine_no IS NULL OR v_engine_no = '' OR lad.engine_no LIKE CONCAT('%', v_engine_no, '%'))
			AND (v_insurance_company IS NULL OR v_insurance_company = ''  OR lad.insurance_company LIKE CONCAT('%', v_insurance_company, '%'))
			AND (v_fuel_type IS NULL OR v_fuel_type = ''  OR lad.fuel_type LIKE CONCAT('%', v_fuel_type, '%'))
			AND (v_yom IS NULL OR v_yom = ''  OR lad.yom LIKE CONCAT('%', v_yom, '%'))
			AND (v_add_on_name IS NULL OR v_add_on_name = ''  OR pd.add_on_name LIKE CONCAT('%', v_add_on_name, '%'))
			group by mc.chassis_no
			) AS lostLead
	) AS lostLeadCount;
	
	SELECT COUNT(*) as paginationCount FROM(
	SELECT MAX(ml.lead_id)
        FROM mmi_lead_details ml
		left join mmi_dealer_location_mapping dlm on dlm.dealer_code = ml.dealer_code
        LEFT JOIN mmi_mast_customer_details mc ON ml.vin = mc.chassis_no and ml.engine_no = mc.engine_no -- ON ml.cluster_id = mc.cluster_id
		LEFT JOIN mmi_poladdon_data pd on pd.policy_no = ml.policy_no
		LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent
        INNER JOIN (
            WITH RECURSIVE subordinates AS (
                SELECT ur.user_id
                FROM mmi_user_reporting ur
                -- WHERE ur.supervisor_id <> JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
                WHERE ur.supervisor_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
                UNION ALL
                SELECT ur.user_id
                FROM mmi_user_reporting ur
                INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
            )
            SELECT * FROM subordinates
        ) AS s ON ml.assigned_agent = s.user_id
        WHERE dlm.mapping_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
        AND (v_name IS NULL OR v_name = '' OR LOWER(TRIM(REGEXP_REPLACE(mc.customer_name, '\\s+', ' '))) LIKE CONCAT('%', LOWER(TRIM(REGEXP_REPLACE(v_name, '\\s+', ' '))), '%'))
		AND (customerPhone IS NULL OR customerPhone = '' OR mc.customer_phone LIKE CONCAT('%', customerPhone, '%'))
		AND (vehicleRegNo IS NULL OR vehicleRegNo = '' OR mc.vehicle_reg_no LIKE CONCAT('%', vehicleRegNo, '%'))
