        select MAX(mld.policy_no) as policy_no,MAX(mld.make) as make,MAX(mld.variant) as variant,MAX(mld.fuel_type) as fuel_type,
		MAX(mld.vehicle_class) as vehicle_class,MAX(mld.model) as model,
        MAX(mcd.vehicle_reg_no) as vehicle_reg_no,MAX(mld.engine_no) as engine_no,MAX(mcd.chassis_no) as chassis_no,
		MAX(DATE_FORMAT(mld.invoice_date,'%d %b %Y')) as invoice_date, -- MAX(mld.invoice_date) as invoice_date,
		MAX(mld.plan_type) as plan_type,
        MAX(mld.gross_premium) as net_premium,MAX(mld.addon_premium_amount) as addon_premium_amount,MAX(rrd.renewal_Link) as renewal_Link,
		concat(DATE_FORMAT(MAX(mld.podc_start),'%d %b %Y'),' | ',DATE_FORMAT(MAX(mld.podc_end),'%d %b %Y')) as odDates,
        concat(DATE_FORMAT(MAX(mld.plc_start),'%d %b %Y'),' | ',DATE_FORMAT(MAX(mld.plc_end),'%d %b %Y')) as tpDates,
		MAX(mld.net_od_premium_amount) as totalod,MAX(mld.net_liability) as totaltp,
        MAX(CASE WHEN cch.chassis_number IS NOT NULL THEN 'Yes' ELSE 'No' END) AS claim_history,
        MAX(mld.od_discount_percentage) as od_discount,MAX(mld.ncb_percentage) AS ncb_percentage,
        MAX(date_format(mld.registration_date,'%d %b %Y')) as registration_date,
        MAX(mld.group_product) as group_product,
		MAX(mld.created_date) as created_date from mmi_ebm_policy_data mld
        left join mmi_mast_customer_details mcd ON mld.vin = mcd.chassis_no and mld.engine_no = mcd.engine_no -- on mld.cluster_id = mcd.cluster_id
        left join mmi_ebm_sales_data csh on csh.chassis_number = mcd.chassis_no
        left join mmi_renewalreminder_data rrd on mld.policy_no = rrd.policy_no
		LEFT JOIN mmi_poladdon_data pd on pd.policy_no = mld.policy_no
		left join mmi_ebm_claim_data cch on cch.chassis_number = mcd.chassis_no
        WHERE (v_name IS NULL OR v_name = '' OR LOWER(TRIM(REGEXP_REPLACE(mcd.customer_name, '\\s+', ' '))) LIKE CONCAT('%', LOWER(TRIM(REGEXP_REPLACE(v_name, '\\s+', ' '))), '%'))
