		AND (customerPhone IS NULL OR customerPhone = '' OR mcd.customer_phone LIKE CONCAT('%', customerPhone, '%'))
		AND (vehicleRegNo IS NULL OR vehicleRegNo = '' OR mcd.vehicle_reg_no LIKE CONCAT('%', vehicleRegNo, '%'))
