        order by mcsh.created_date desc;-- LIMIT limitVal OFFSET calculated;

    ELSEIF v_historyType = 'reminder' THEN
    SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.limit')) AS UNSIGNED), 10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.offset')) AS UNSIGNED), 0);
    SET calculated = (offsetVal - 1) * limitVal;
 
        -- SELECT distinct crh.policy_id,crh.mode,crh.reminder_frequency,crh.sent_date,mcd.created_date FROM
		SELECT distinct -- crh.policy_id,crh.mode,crh.reminder_frequency,crh.created_date,
        crh.mode,crh.reminder_frequency,
        -- date_format(crh.created_date,'%Y-%m-%d') as sent_date,
        date_format(crh.sent_date,'%Y-%m-%d') as sent_date,
        crh.created_date FROM 
        mmi_renewalreminder_data crh left join mmi_ebm_policy_data mld on crh.policy_no = mld.policy_no 
        LEFT JOIN mmi_mast_customer_details mcd ON mld.vin = mcd.chassis_no and mld.engine_no = mcd.engine_no -- on mcd.cluster_id = mld.cluster_id
		LEFT JOIN mmi_poladdon_data pd on pd.policy_no = mld.policy_no
        WHERE (v_name IS NULL OR v_name = '' OR LOWER(TRIM(REGEXP_REPLACE(mcd.customer_name, '\\s+', ' '))) LIKE CONCAT('%', LOWER(TRIM(REGEXP_REPLACE(v_name, '\\s+', ' '))), '%'))
		AND (customerPhone IS NULL OR customerPhone= '' OR mcd.customer_phone LIKE CONCAT('%', customerPhone, '%'))
		AND (vehicleRegNo IS NULL OR vehicleRegNo = '' OR mcd.vehicle_reg_no LIKE CONCAT('%', vehicleRegNo, '%'))
		AND (chassisNo IS NULL OR chassisNo = '' OR  mcd.chassis_no LIKE CONCAT('%', chassisNo, '%'))
		AND (v_policy_no IS NULL OR v_policy_no = ''  OR mld.policy_no LIKE CONCAT('%', v_policy_no, '%'))
		AND (v_policy_tenure IS NULL OR v_policy_tenure = '' OR mld.policy_tenure LIKE CONCAT('%', v_policy_tenure, '%'))
		AND (v_policy_type IS NULL OR v_policy_type = '' OR mld.policy_type LIKE CONCAT('%', v_policy_type, '%'))
		AND (v_make IS NULL OR v_make = '' OR mld.make LIKE CONCAT('%', v_make, '%'))
		AND (v_model IS NULL OR v_model = '' OR mld.model LIKE CONCAT('%', v_model, '%'))
		AND (v_variant IS NULL OR v_variant = '' OR mld.variant LIKE CONCAT('%', v_variant, '%'))
		AND (v_vehicle_class IS NULL OR v_vehicle_class = '' OR mld.vehicle_class LIKE CONCAT('%', v_vehicle_class, '%'))
		AND (v_engine_no IS NULL OR v_engine_no = '' OR mld.engine_no LIKE CONCAT('%', v_engine_no, '%'))
		AND (v_insurance_company IS NULL OR v_insurance_company = ''  OR mld.insurance_company LIKE CONCAT('%', v_insurance_company, '%'))
		AND (v_fuel_type IS NULL OR v_fuel_type = ''  OR mld.fuel_type LIKE CONCAT('%', v_fuel_type, '%'))
		AND (v_yom IS NULL OR v_yom = ''  OR mld.yom LIKE CONCAT('%', v_yom, '%'))
		AND (v_add_on_name IS NULL OR v_add_on_name = ''  OR pd.add_on_name LIKE CONCAT('%', v_add_on_name, '%'))
        order by crh.created_date desc;-- LIMIT limitVal OFFSET calculated;
	
	ELSEIF v_historyType = 'addon' THEN
		select add_on_name,bundle_name,premium,addon.created_date from mmi_poladdon_data addon
		left join mmi_ebm_policy_data mld on addon.policy_no = mld.policy_no
		LEFT JOIN mmi_mast_customer_details mcd ON mld.vin = mcd.chassis_no and mld.engine_no = mcd.engine_no -- on mcd.cluster_id = mld.cluster_id
        WHERE (v_name IS NULL OR v_name = '' OR LOWER(TRIM(REGEXP_REPLACE(mcd.customer_name, '\\s+', ' '))) LIKE CONCAT('%', LOWER(TRIM(REGEXP_REPLACE(v_name, '\\s+', ' '))), '%'))
		AND (customerPhone IS NULL OR customerPhone= '' OR mcd.customer_phone LIKE CONCAT('%', customerPhone, '%'))
		AND (vehicleRegNo IS NULL OR vehicleRegNo = '' OR mcd.vehicle_reg_no LIKE CONCAT('%', vehicleRegNo, '%'))
		AND (chassisNo IS NULL OR chassisNo = '' OR  mcd.chassis_no LIKE CONCAT('%', chassisNo, '%'))
		AND (v_policy_no IS NULL OR v_policy_no = ''  OR mld.policy_no LIKE CONCAT('%', v_policy_no, '%'))
		AND (v_policy_tenure IS NULL OR v_policy_tenure = '' OR mld.policy_tenure LIKE CONCAT('%', v_policy_tenure, '%'))
		AND (v_policy_type IS NULL OR v_policy_type = '' OR mld.policy_type LIKE CONCAT('%', v_policy_type, '%'))
		AND (v_make IS NULL OR v_make = '' OR mld.make LIKE CONCAT('%', v_make, '%'))
		AND (v_model IS NULL OR v_model = '' OR mld.model LIKE CONCAT('%', v_model, '%'))
		AND (v_variant IS NULL OR v_variant = '' OR mld.variant LIKE CONCAT('%', v_variant, '%'))
		AND (v_vehicle_class IS NULL OR v_vehicle_class = '' OR mld.vehicle_class LIKE CONCAT('%', v_vehicle_class, '%'))
		AND (v_engine_no IS NULL OR v_engine_no = '' OR mld.engine_no LIKE CONCAT('%', v_engine_no, '%'))
		AND (v_insurance_company IS NULL OR v_insurance_company = ''  OR mld.insurance_company LIKE CONCAT('%', v_insurance_company, '%'))
		AND (v_fuel_type IS NULL OR v_fuel_type = ''  OR mld.fuel_type LIKE CONCAT('%', v_fuel_type, '%'))
		AND (v_yom IS NULL OR v_yom = ''  OR mld.yom LIKE CONCAT('%', v_yom, '%'))
		AND (v_add_on_name IS NULL OR v_add_on_name = ''  OR addon.add_on_name LIKE CONCAT('%', v_add_on_name, '%'))
        order by mcd.created_date desc;	

    END IF;
	
	-- *****************  Assign to Agent Master Lit Fetching ***************
    IF type = 'assigned' || type = 'unassigned' THEN

        (select DISTINCT CONCAT(urd.first_name, ' ', urd.last_name) AS agentName,
        urd.id AS agentId from mmi_mast_user_registration_detail urd
        left join mmi_user_dealer_mapping urm on urd.id = urm.user_id 
        LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = urm.dealer_id
        LEFT JOIN mmi_mast_user mu on urd.id = mu.user_id
		Where mu.calling_flag = 'Y' and urm.dealer_id =JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode')) 
		and urd.id=JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')))

            union all

           ( WITH RECURSIVE subordinates AS
            (
            SELECT ur.user_id
            FROM mmi_user_reporting ur where ur.supervisor_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
            UNION ALL
            SELECT ur.user_id
            FROM mmi_user_reporting ur
            INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
            )

            SELECT DISTINCT

            CONCAT(urd.first_name, ' ', urd.last_name) AS agentName,
            urd.id AS agentId
            FROM subordinates s
            LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = s.user_id
            LEFT JOIN mmi_user_dealer_mapping urm on s.user_id = urm.user_id
            LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = urm.dealer_id
			LEFT JOIN mmi_mast_user mu on urd.id = mu.user_id
			Where mu.calling_flag = 'Y' and urd.id is not null AND urm.dealer_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode')))
            ;
            
		select renewal_year as renewalCategory from mmi_mast_renewal_category where status =1;

    ELSEIF type = 'myLeads' THEN

            WITH RECURSIVE subordinates AS
            (
            SELECT ur.user_id
            FROM mmi_user_reporting ur where ur.supervisor_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
            UNION ALL
            SELECT ur.user_id
            FROM mmi_user_reporting ur
            INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
            )

            SELECT DISTINCT

            CONCAT(urd.first_name, ' ', urd.last_name) AS agentName,
            urd.id AS agentId
            FROM subordinates s
            LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = s.user_id
            LEFT JOIN mmi_user_dealer_mapping urm on s.user_id = urm.user_id
            LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = urm.dealer_id
            LEFT JOIN mmi_mast_user mu on urd.id = mu.user_id
			Where mu.calling_flag = 'Y' and urd.id is not null AND urm.dealer_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
            and urd.id <> JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
            ;
            
	 select renewal_year as renewalCategory from mmi_mast_renewal_category where status =1;         
   END IF;
	
    END IF; 

    SET p_status_code = '200'; 
    SET p_status_message = 'Fetched successfully';
END IF;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_get_dashboardDetails` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_dashboardDetails`(
  IN Json_data JSON,
    IN type VARCHAR(45),
    OUT SP_STATUS VARCHAR(500),
    OUT MESSAGE VARCHAR(500))
BEGIN
 DECLARE v_dealerId VARCHAR(45);
    DECLARE v_userId VARCHAR(45);
    DECLARE v_roleId VARCHAR(45);
    DECLARE v_conversion VARCHAR(45);
    DECLARE v_startDate VARCHAR(45);
    DECLARE v_endDate VARCHAR(45);
    DECLARE v_segment VARCHAR(500);
    DECLARE v_teamMemberId VARCHAR(500);
    DECLARE v_user_role_type VARCHAR(45); 
 --    DECLARE v_check_reporting_manager INT DEFAULT 0;
    DECLARE v_check_reporting_manager INT DEFAULT 0; -- subordinates count
    DECLARE v_has_supervisor INT DEFAULT 0; 

    DECLARE v_calling_access VARCHAR(1) DEFAULT 'N';
    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;
   DECLARE EXIT HANDLER FOR SQLEXCEPTION
        BEGIN

                GET DIAGNOSTICS CONDITION 1
                @sqlstate = RETURNED_SQLSTATE,errno = MYSQL_ERRNO,errmsg = MESSAGE_TEXT;
                SET SP_STATUS = 407;
                SET MESSAGE = 'Something went wrong.';


        INSERT INTO mmi_mast_procedure_error (error_code, error_message, procedure_name,procedure_type,ERROR_TIMING,created_by,created_date)
        VALUES (errno, CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg), 'mmi_proc_dashboard', type ,CURRENT_TIMESTAMP(),'SYSTEM',NOW());
        END;

    SET v_dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
    SET v_userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
    SET v_roleId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleId'));
     -- Only extract conversion for filterData type
    SET v_conversion = CASE WHEN type = 'filterData' THEN JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.conversion')) ELSE NULL END;
    SET v_startDate = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.startDate'));
    SET v_endDate = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.endDate'));
    SET v_segment = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.segment'));
    SET v_teamMemberId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.teamMemberId'));

    IF v_dealerId IS NULL OR v_dealerId = ''
        OR v_userId IS NULL OR v_userId = '' OR v_userId = '0'
        OR v_roleId IS NULL OR v_roleId = '' OR v_roleId = '0'

    THEN
        SET SP_STATUS = '400';
        SET MESSAGE = CONCAT(
            CASE
                WHEN v_dealerId IS NULL OR v_dealerId = '' THEN 'dealer Id is missing'
                WHEN v_userId IS NULL OR v_userId = '' THEN 'user Id is missing'
                WHEN v_roleId IS NULL OR v_roleId = '' THEN 'role Id is missing'
                WHEN v_userId = '0' THEN 'userId is Invalid'
                WHEN v_roleId = '0' THEN 'role Id is Invalid'

            END
        );

    ELSE

    -- count subordinates
SELECT COUNT(*) INTO v_check_reporting_manager
FROM mmi_user_reporting
WHERE supervisor_id = v_userId;

-- check if this user reports to someone
SELECT COUNT(*) INTO v_has_supervisor
FROM mmi_user_reporting
WHERE user_id = v_userId;

        -- Check if user is a manager
     --    SELECT COUNT(*) INTO v_check_reporting_manager FROM mmi_user_reporting WHERE supervisor_id = v_userId;

        -- Check calling access
        SELECT calling_flag INTO v_calling_access FROM mmi_mast_user WHERE user_id = v_userId;


      --   select v_conversion as Conversion;

-- ---------------------- Manager with calling access ( own + team data ) --------------------------------------------


        IF v_check_reporting_manager > 0

        AND (v_has_supervisor > 0 OR v_has_supervisor = 0) THEN -- USER IS A MANAGER

            IF v_calling_access = 'Y' THEN

                IF type = 'fetchDashboard' THEN


WITH RECURSIVE team_hierarchy AS (

    -- manager

    SELECT v_userId AS user_id

    UNION ALL

    -- team members

    SELECT ur.user_id
    FROM mmi_user_reporting ur
    INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
dealer_team_members AS (
    SELECT th.user_id
    FROM team_hierarchy th
    JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
    WHERE udm.dealer_id = v_dealerId
)

SELECT 'Total Leads' AS leadType, IFNULL(COUNT(DISTINCT l.lead_id), 0) AS Count
FROM mmi_lead_details l
-- LEFT JOIN mmi_user_dealer_mapping udm ON l.assigned_agent = udm.user_id
WHERE l.dealer_code = v_dealerId
AND l.lead_type IN ('Hot', 'Warm', 'Cold')
 -- AND udm.dealer_id = v_dealerId
 -- AND l.assigned_agent IN (SELECT user_id FROM dealer_team_members)

UNION ALL

SELECT 'Hot Leads' AS leadType, IFNULL(COUNT(DISTINCT l.lead_id), 0) AS Count
FROM mmi_lead_details l
-- LEFT JOIN mmi_user_dealer_mapping udm ON l.assigned_agent = udm.user_id
WHERE l.dealer_code = v_dealerId
AND l.lead_type = 'Hot'
 -- AND udm.dealer_id = v_dealerId
--  AND l.assigned_agent IN (SELECT user_id FROM dealer_team_members)

UNION ALL

SELECT 'Warm Leads' AS leadType, IFNULL(COUNT(DISTINCT l.lead_id), 0) AS Count
FROM mmi_lead_details l
-- LEFT JOIN mmi_user_dealer_mapping udm ON l.assigned_agent = udm.user_id
WHERE l.dealer_code = v_dealerId
AND l.lead_type = 'Warm'
--  AND udm.dealer_id = v_dealerId
--  AND l.assigned_agent IN (SELECT user_id FROM dealer_team_members)

UNION ALL

SELECT 'Cold Leads' AS leadType, IFNULL(COUNT(DISTINCT l.lead_id), 0) AS Count
FROM mmi_lead_details l
-- LEFT JOIN mmi_user_dealer_mapping udm ON l.assigned_agent = udm.user_id
WHERE l.dealer_code = v_dealerId
AND l.lead_type = 'Cold';
 -- AND udm.dealer_id = v_dealerId
 -- AND l.assigned_agent IN (SELECT user_id FROM dealer_team_members);


                    -- Disposition Summary

-- Main Dispositions

WITH RECURSIVE team_hierarchy AS (
    SELECT v_userId AS user_id
    UNION ALL
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
team_users AS (
    SELECT user_id FROM team_hierarchy
),
latest_dispositions AS (
    SELECT
        cdh.lead_id,
        cdh.dealer_disposition_id,
        adf.field_value as sub_disposition_value,
        ROW_NUMBER() OVER(PARTITION BY cdh.lead_id ORDER BY cdh.created_date DESC) AS rn
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_agent_disposition_field_response adf
        ON adf.response_id = cdh.id
        AND adf.field_label = 'Sub Disposition'
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE led.assigned_agent IN (SELECT user_id FROM team_users)
      AND udm.dealer_id = v_dealerId
      AND cdh.dealer_id = v_dealerId
)
SELECT
    md.disposition AS disposition,
    COUNT(ld.lead_id) AS count,
    ROUND((COUNT(ld.lead_id) * 100.0 /
           NULLIF((SELECT COUNT(*)
                   FROM mmi_lead_details
                   WHERE assigned_agent IN (SELECT user_id FROM team_users)
                   AND lead_id IN (
                       SELECT lead_id FROM mmi_lead_details led
                       JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
                       WHERE udm.dealer_id = v_dealerId
                   )), 0)), 2) AS percentage
FROM mmi_mast_disposition md
LEFT JOIN latest_dispositions ld
    ON md.disposition_id = ld.dealer_disposition_id
    AND md.sub_disposition = ld.sub_disposition_value
    -- AND ld.rn = 1
GROUP BY md.disposition
ORDER BY COUNT(ld.lead_id) DESC, md.disposition;



-- Sub Dispositions using the same hierarchy

WITH RECURSIVE team_hierarchy AS (
    SELECT v_userId AS user_id
    UNION ALL
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
team_users AS (
    SELECT user_id FROM team_hierarchy
)
SELECT
    md.disposition,
    md.sub_disposition,
    COALESCE(sub.total_count, 0) AS total_count
FROM
    mmi_mast_disposition md
LEFT JOIN (
    SELECT
        t1.dealer_disposition_id,
        t1.field_value,
        COUNT(t1.lead_id) AS total_count
    FROM (
        SELECT
            cdh.lead_id,
            cdh.dealer_disposition_id,
            adf.field_value
            -- ROW_NUMBER() OVER(PARTITION BY cdh.lead_id ORDER BY cdh.created_date DESC) AS rn
        FROM
            mmi_call_disposition_history cdh
        LEFT JOIN mmi_agent_disposition_field_response adf
            ON adf.response_id = cdh.id
            AND adf.field_label = 'Sub Disposition'
        JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
        JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
        WHERE led.assigned_agent IN (SELECT user_id FROM team_users)
          AND udm.dealer_id = v_dealerId
          AND cdh.dealer_id = v_dealerId
    ) AS t1
    -- WHERE t1.rn = 1
    GROUP BY
        t1.dealer_disposition_id,
        t1.field_value
) AS sub
    ON md.disposition_id = sub.dealer_disposition_id
    AND md.sub_disposition = sub.field_value
ORDER BY
    md.disposition,
    md.sub_disposition;

                    -- Lead Conversion


WITH RECURSIVE team_hierarchy AS (
    -- manager
    SELECT v_userId AS user_id

    UNION ALL

    -- all team members
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
dealer_team_users AS (
    SELECT tu.user_id
    FROM team_hierarchy tu
    JOIN mmi_user_dealer_mapping udm ON tu.user_id = udm.user_id
    WHERE udm.dealer_id = v_dealerId
),
total_leads AS (
    SELECT COUNT(DISTINCT lead_id) AS total_count
    FROM mmi_lead_details
    WHERE lead_type IN ('Hot', 'Warm', 'Cold')
    AND assigned_agent IN (SELECT user_id FROM dealer_team_users)
),
latest_dispositions AS (
    SELECT
        cdh.lead_id,
        cdh.dealer_disposition_id,
        adf.field_value as sub_disposition_value -- ,
        -- ROW_NUMBER() OVER(PARTITION BY cdh.lead_id ORDER BY cdh.created_date DESC) AS rn
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_agent_disposition_field_response adf
        ON adf.response_id = cdh.id
        AND adf.field_label = 'Sub Disposition'
    INNER JOIN (
        SELECT lead_id, MAX(created_date) AS max_created_date
        FROM mmi_call_disposition_history
        GROUP BY lead_id
    ) latest ON cdh.lead_id = latest.lead_id AND cdh.created_date = latest.max_created_date
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE led.assigned_agent IN (SELECT user_id FROM dealer_team_users)
      AND udm.dealer_id = v_dealerId
      AND cdh.dealer_id = v_dealerId
)

SELECT
    leadStatus,
    COALESCE(count, 0) AS count,
    CONCAT(ROUND(COALESCE(percentage, 0), 2)) AS percentage
FROM (
    -- Converted (direct from archive table where lead_status = 'Won')
    SELECT
        'Converted' AS leadStatus,
        COUNT(DISTINCT la.lead_id) AS count,
        (COUNT(DISTINCT la.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM mmi_lead_archive_details la
    JOIN mmi_user_dealer_mapping udm ON la.assigned_agent = udm.user_id
    WHERE la.lead_status = 'Won'
      AND la.assigned_agent IN (SELECT user_id FROM dealer_team_users)
      AND udm.dealer_id = v_dealerId

    UNION ALL

    -- Contacted (all latest dispositions - same as main dispositions total count)
    SELECT
        'Contacted' AS leadStatus,
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM latest_dispositions ld
    -- WHERE ld.rn = 1

    UNION ALL

    -- Quote Shared (using latest disposition logic)
    SELECT
        'Quote Shared' AS leadStatus,
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM latest_dispositions ld
    JOIN mmi_mast_disposition md ON md.disposition_id = ld.dealer_disposition_id
        AND md.sub_disposition = ld.sub_disposition_value
    WHERE -- ld.rn = 1 AND 
	md.sub_disposition = 'Shared Quotes'

    UNION ALL

    -- Total Leads
    SELECT
        'Total Leads' AS leadStatus,
        (SELECT total_count FROM total_leads) AS count,
        CASE
            WHEN (SELECT total_count FROM total_leads) = 0 THEN 0.00
            ELSE 100.00
        END AS percentage
) AS lead_summary
ORDER BY
    CASE leadStatus
        WHEN 'Converted' THEN 1
        WHEN 'Contacted' THEN 2
        WHEN 'Quote Shared' THEN 3
        WHEN 'Total Leads' THEN 4
    END;

                    -- recently converted And closed leads

       WITH RECURSIVE team_hierarchy AS (
    -- manager
    SELECT v_userId AS user_id

    UNION ALL

    -- all team members
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
leads AS (
    SELECT DISTINCT
        l.insured_name AS customerName,
        l.lead_id AS leadId,
        l.policy_no AS policyNo,
        l.model AS vehicleDetail,
		adfr.field_value AS status,
        l.modified_date,
        l.created_date,
        disposition_color AS dispositionColor,
        ROW_NUMBER() OVER (PARTITION BY l.lead_id ORDER BY l.modified_date DESC) AS rn
    FROM mmi_lead_archive_details l
    LEFT JOIN mmi_call_disposition_history dis ON dis.lead_id = l.lead_id
    -- LEFT JOIN mmi_mast_disposition mdisp ON mdisp.disposition_id = dis.dealer_disposition_id
    LEFT JOIN mmi_agent_disposition_field_response adfr on adfr.response_id = dis.id
