WITH RECURSIVE team_hierarchy AS (
    SELECT v_userId AS user_id
    UNION ALL
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
dealer_team_users AS (
    SELECT th.user_id
    FROM team_hierarchy th
    JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
    WHERE udm.dealer_id = v_dealerId
),
disposition_events AS (
    SELECT
        cdh.id AS dispo_id,
        cdh.lead_id,
        cdh.call_status AS disposition, 
        led.assigned_agent,
        led.vehicle_class,
        led.created_date AS lead_created_date,
        led.modified_date AS lead_modified_date,
        cdh.created_date AS dispo_created_date
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE led.assigned_agent IN (SELECT user_id FROM dealer_team_users)
      AND udm.dealer_id = v_dealerId
      AND cdh.dealer_id = v_dealerId
		AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
		AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(led.assigned_agent), v_teamMemberId))
		AND (
			(v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
		OR
			(
			(DATE(led.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
		OR
			(DATE(led.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
		OR
			(DATE(cdh.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
		)
	)
),
user_dispo_counts AS (
    SELECT
        CONCAT(COALESCE(mur.first_name, ''), ' ', COALESCE(mur.last_name, ''), ' / ', COALESCE(mr.role, '')) AS user_name_role,
        de.disposition,
        COUNT(*) AS event_count
    FROM disposition_events de
    JOIN mmi_mast_user_registration_detail mur ON mur.id = de.assigned_agent
    LEFT JOIN mmi_user_role_mapping urm ON mur.id = urm.user_id
    LEFT JOIN mmi_mast_role mr ON urm.role_id = mr.role_id
    GROUP BY user_name_role, de.disposition
),
pivoted AS (
    SELECT
        user_name_role,
        COALESCE(MAX(CASE WHEN disposition = 'Callback Scheduled' THEN event_count END), 0) AS 'Callback Scheduled',
        COALESCE(MAX(CASE WHEN disposition = 'Converted/ Won' THEN event_count END), 0) AS 'Converted/ Won',
        COALESCE(MAX(CASE WHEN disposition = 'Follow-Up' THEN event_count END), 0) AS 'Follow-Up',
        COALESCE(MAX(CASE WHEN disposition = 'Interested' THEN event_count END), 0) AS 'Interested',
        COALESCE(MAX(CASE WHEN disposition = 'Not Eligible' THEN event_count END), 0) AS 'Not Eligible',
        COALESCE(MAX(CASE WHEN disposition = 'Not Interested' THEN event_count END), 0) AS 'Not Interested',
        COALESCE(MAX(CASE WHEN disposition = 'Not Reachable' THEN event_count END), 0) AS 'Not Reachable',
        SUM(event_count) AS 'Grand Total'
    FROM user_dispo_counts
    GROUP BY user_name_role
)
SELECT * FROM pivoted
UNION ALL
SELECT 
    'Grand Total',
    SUM(`Callback Scheduled`),
    SUM(`Converted/ Won`),
    SUM(`Follow-Up`),
    SUM(`Interested`),
    SUM(`Not Eligible`),
    SUM(`Not Interested`),
    SUM(`Not Reachable`),
    SUM(`Grand Total`)
FROM pivoted
ORDER BY CASE WHEN user_name_role = 'Grand Total' THEN 1 ELSE 0 END, user_name_role;
            

SET SP_STATUS = '200';
SET MESSAGE = 'Excel download data prepared.';

