    FROM mmi_user_reporting ur2
    INNER JOIN team_hierarchy th ON ur2.supervisor_id = th.user_id
    AND ur2.user_id <> ur2.supervisor_id
),
dealer_team_members AS (
    SELECT th.user_id
    FROM team_hierarchy th
    JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
    WHERE udm.dealer_id = v_dealerId
),
leads AS (
    SELECT DISTINCT
        l.insured_name AS customerName,
        l.lead_id AS leadId,
        l.policy_no AS policyNo,
        l.model AS vehicleDetail,
        -- mdisp.next_status AS status,
        adfr.field_value AS status,
        l.modified_date,
        l.created_date,
        disposition_color AS dispositionColor,
        ROW_NUMBER() OVER (PARTITION BY l.lead_id ORDER BY l.modified_date DESC) AS rn 
    FROM mmi_lead_archive_details l
    LEFT JOIN mmi_call_disposition_history dis
           ON dis.lead_id = l.lead_id
    LEFT JOIN mmi_agent_disposition_field_response adfr on adfr.response_id = dis.id
			AND adfr.field_label = 'Sub Disposition'
    LEFT JOIN mmi_mast_disposition mdisp ON mdisp.sub_disposition = adfr.field_value        
    -- LEFT JOIN mmi_mast_call_disposition mcd
          -- ON mcd.disposition_id = mdisp.disposition_id
    LEFT JOIN mmi_mast_user mu
           ON l.assigned_agent = mu.user_id
    WHERE l.lead_status IN ('Won','Lost')
      AND dis.agent_code IN (SELECT user_id FROM dealer_team_members)
)
SELECT 
    customerName,
    leadId,
    policyNo,
    vehicleDetail,
    status,
    modified_date,
    created_date,
    dispositionColor
FROM leads
WHERE rn = 1

UNION ALL

