                    -- Disposition Summary with filters

 -- Main Dispositions with Filters for Manager without Calling Access

WITH RECURSIVE team_hierarchy AS (
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    WHERE ur.supervisor_id = v_userId
    UNION ALL
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
dealer_team_users AS (
    SELECT th.user_id
    FROM team_hierarchy th
    JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
    WHERE udm.dealer_id = v_dealerId
),
latest_dispositions AS (
    SELECT
        cdh.lead_id,
        cdh.dealer_disposition_id,
        adf.field_value as sub_disposition_value,
        ROW_NUMBER() OVER(PARTITION BY cdh.lead_id ORDER BY cdh.created_date DESC) AS rn
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_agent_disposition_field_response adf
        ON adf.response_id = cdh.id
        AND adf.field_label = 'Sub Disposition'
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE led.assigned_agent IN (SELECT user_id FROM dealer_team_users)
      AND udm.dealer_id = v_dealerId
      AND cdh.dealer_id = v_dealerId
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
      AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(led.assigned_agent), v_teamMemberId))
      AND (
          (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
          OR
          (
              (DATE(led.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
              OR
              (DATE(led.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
              OR
              (DATE(cdh.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
          )
      )
)
SELECT
    md.disposition AS disposition,
    COUNT(DISTINCT ld.lead_id) AS count,
    ROUND(
        COUNT(DISTINCT ld.lead_id) * 100.0 /
        NULLIF(
            (SELECT COUNT(DISTINCT led.lead_id)
             FROM mmi_lead_details led
             JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
             WHERE led.assigned_agent IN (SELECT user_id FROM dealer_team_users)
               AND udm.dealer_id = v_dealerId
               AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
               AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(led.assigned_agent), v_teamMemberId))
               AND (
                   (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                   OR
                   (
                       DATE(led.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
                       OR DATE(led.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
                   )
               )
            ), 0
        ), 2
    ) AS percentage
FROM mmi_mast_disposition md
LEFT JOIN latest_dispositions ld
    ON md.disposition_id = ld.dealer_disposition_id
    AND md.sub_disposition = ld.sub_disposition_value
    AND ld.rn = 1
GROUP BY md.disposition
ORDER BY COUNT(DISTINCT ld.lead_id) DESC, md.disposition;



-- Sub Dispositions with Filters for Manager without Calling Access

WITH RECURSIVE team_hierarchy AS (
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    WHERE ur.supervisor_id = v_userId
    UNION ALL
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
dealer_team_users AS (
    SELECT th.user_id
    FROM team_hierarchy th
    JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
    WHERE udm.dealer_id = v_dealerId
)
SELECT
    md.disposition,
    md.sub_disposition,
    COALESCE(COUNT(DISTINCT ld.lead_id), 0) AS total_count
FROM mmi_mast_disposition md
LEFT JOIN (
    SELECT
        cdh.lead_id,
        cdh.dealer_disposition_id,
        adf.field_value,
        ROW_NUMBER() OVER(PARTITION BY cdh.lead_id ORDER BY cdh.created_date DESC) AS rn
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_agent_disposition_field_response adf
        ON adf.response_id = cdh.id
        AND adf.field_label = 'Sub Disposition'
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE led.assigned_agent IN (SELECT user_id FROM dealer_team_users)
      AND udm.dealer_id = v_dealerId
      AND cdh.dealer_id = v_dealerId
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
      AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(led.assigned_agent), v_teamMemberId))
      AND (
          (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
          OR
          (
              (DATE(led.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
              OR
              (DATE(led.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
              OR
              (DATE(cdh.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
          )
      )
) ld
ON md.disposition_id = ld.dealer_disposition_id
   AND md.sub_disposition = ld.field_value
   AND ld.rn = 1
GROUP BY md.disposition, md.sub_disposition
ORDER BY md.disposition, md.sub_disposition;


                    -- Lead Conversion with filters


WITH RECURSIVE team_hierarchy AS (
    -- direct team members
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    WHERE ur.supervisor_id = v_userId

    UNION ALL

    -- indirect team members
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
dealer_team_users AS (
    SELECT th.user_id
    FROM team_hierarchy th
    JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
    WHERE udm.dealer_id = v_dealerId
),
total_leads AS (
    SELECT COUNT(DISTINCT lead_id) AS total_count
    FROM mmi_lead_details l
    WHERE l.lead_type IN ('Hot', 'Warm', 'Cold')
    AND l.assigned_agent IN (SELECT user_id FROM dealer_team_users)
    AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(l.assigned_agent), v_teamMemberId))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
    AND (
        (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
        OR
        (
            (DATE(l.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
            OR
            (DATE(l.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
        )
    )
),
latest_dispositions AS (
    SELECT
        cdh.lead_id,
        cdh.dealer_disposition_id,
        adf.field_value as sub_disposition_value -- ,
        -- ROW_NUMBER() OVER(PARTITION BY cdh.lead_id ORDER BY cdh.created_date DESC) AS rn
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_agent_disposition_field_response adf
        ON adf.response_id = cdh.id
        AND adf.field_label = 'Sub Disposition'
	INNER JOIN (
        SELECT lead_id, MAX(created_date) AS max_created_date
        FROM mmi_call_disposition_history
        GROUP BY lead_id
    ) latest ON cdh.lead_id = latest.lead_id AND cdh.created_date = latest.max_created_date
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id	
    -- JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE led.assigned_agent IN (SELECT user_id FROM dealer_team_users)
      AND udm.dealer_id = v_dealerId
      AND cdh.dealer_id = v_dealerId
      AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(led.assigned_agent), v_teamMemberId))
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
      AND (
          (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
          OR
          (
              DATE(cdh.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
          )
      )
)

SELECT
    leadStatus,
    COALESCE(count, 0) AS count,
    CONCAT(ROUND(COALESCE(percentage, 0), 2)) AS percentage
FROM (
    -- Converted (direct from archive table where lead_status = 'Won')
    SELECT
        'Converted' AS leadStatus,
        COUNT(DISTINCT la.lead_id) AS count,
        (COUNT(DISTINCT la.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM mmi_lead_archive_details la
    JOIN mmi_user_dealer_mapping udm ON la.assigned_agent = udm.user_id
    WHERE la.lead_status = 'Won'
      AND la.assigned_agent IN (SELECT user_id FROM dealer_team_users)
      AND udm.dealer_id = v_dealerId
      AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(la.assigned_agent), v_teamMemberId))
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(la.vehicle_class), v_segment))
      AND (
          (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
          OR
          (
              (DATE(la.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
              OR
              (DATE(la.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
          )
      )

    UNION ALL

    -- Contacted (all latest dispositions - same as main dispositions total count)
    SELECT
        'Contacted' AS leadStatus,
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM latest_dispositions ld
    -- WHERE ld.rn = 1

    UNION ALL

    -- Quote Shared (using latest disposition logic)
    SELECT
        'Quote Shared' AS leadStatus,
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM latest_dispositions ld
    JOIN mmi_mast_disposition md ON md.disposition_id = ld.dealer_disposition_id
        AND md.sub_disposition = ld.sub_disposition_value
    WHERE -- ld.rn = 1  AND 
	md.sub_disposition = 'Shared Quotes'

    UNION ALL

    -- Total Leads
    SELECT
        'Total Leads' AS leadStatus,
        (SELECT total_count FROM total_leads) AS count,
        CASE
            WHEN (SELECT total_count FROM total_leads) = 0 THEN 0.00
            ELSE 100.00
        END AS percentage
) AS lead_summary
ORDER BY
    CASE leadStatus
        WHEN 'Converted' THEN 1
        WHEN 'Contacted' THEN 2
        WHEN 'Quote Shared' THEN 3
        WHEN 'Total Leads' THEN 4
    END;



                    -- Converted And Closed Leads

 WITH RECURSIVE team_hierarchy AS (
    -- direct team members
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    WHERE ur.supervisor_id = v_userId
AND ur.user_id <> v_userId
    UNION ALL

    -- indirect team members
    SELECT ur2.user_id
    FROM mmi_user_reporting ur2
    INNER JOIN team_hierarchy th ON ur2.supervisor_id = th.user_id
    AND ur2.user_id <> ur2.supervisor_id
),
dealer_team_members AS (
    SELECT th.user_id
    FROM team_hierarchy th
    JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
    WHERE udm.dealer_id = v_dealerId
),
leads AS (
    SELECT DISTINCT
        l.insured_name AS customerName,
        l.lead_id AS leadId,
        l.policy_no AS policyNo,
        l.model AS vehicleDetail,
        adfr.field_value AS status,
        l.modified_date,
        l.created_date,
        disposition_color AS dispositionColor,
        ROW_NUMBER() OVER (PARTITION BY l.lead_id ORDER BY l.modified_date DESC) AS rn 
    FROM mmi_lead_archive_details l
    LEFT JOIN mmi_call_disposition_history dis
           ON dis.lead_id = l.lead_id
    LEFT JOIN mmi_agent_disposition_field_response adfr on adfr.response_id = dis.id
    AND adfr.field_label = 'Sub Disposition'
    LEFT JOIN mmi_mast_disposition mdisp ON mdisp.sub_disposition = adfr.field_value
    -- LEFT JOIN mmi_mast_call_disposition mcd
          -- ON mcd.disposition_id = mdisp.disposition_id
    LEFT JOIN mmi_mast_user mu
           ON l.assigned_agent = mu.user_id
     WHERE l.lead_status IN ('Won','Lost') AND l.assigned_agent in (v_teamMemberId)
  --   WHERE mdisp.final_status IN ('Won','Lost')
      AND dis.agent_code IN (SELECT user_id FROM dealer_team_members)
)
SELECT 
    customerName,
    leadId,
    policyNo,
    vehicleDetail,
    status,
    modified_date,
    created_date,
    dispositionColor
FROM leads
WHERE rn = 1
UNION ALL
SELECT
    '0' AS customerName,
    0 AS leadId,
    '0' AS policyNo,
    '0' AS vehicleDetail,
    '0' AS status,
    '0' AS modified_date,
    '0' AS created_date,
    '0' AS dispositionColor
WHERE NOT EXISTS (SELECT 1 FROM leads)
LIMIT 10;



