                ELSEIF type = 'downloadExcel' THEN

WITH RECURSIVE team_hierarchy AS (
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    WHERE ur.supervisor_id = v_userId AND ur.user_id <> v_userId
    UNION ALL
    SELECT ur2.user_id
    FROM mmi_user_reporting ur2
    INNER JOIN team_hierarchy th ON ur2.supervisor_id = th.user_id
    WHERE ur2.user_id <> ur2.supervisor_id
),
dealer_team_users AS (
    SELECT th.user_id
    FROM team_hierarchy th
    JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
    WHERE udm.dealer_id = v_dealerId
),
disposition_events AS (
    SELECT
        cdh.id AS dispo_id,
        cdh.lead_id,
        cdh.call_status,
        cdh.remarks,
        cdh.next_call_datetime,
        cdh.dealer_disposition_id,
        cdh.created_date AS dispo_created_date,
        adf.field_value AS sub_disposition_value,
        led.dealer_code,
        led.assigned_agent,
        led.policy_no,
        led.insurance_company,
        led.insured_name,
        led.model,
        led.reg_no AS vehicle_reg_no,
        led.vin,
        led.plan_type,
        led.vehicle_class,
        led.policy_expiry_date,
        led.renewal_category,
        led.lead_status,
        led.lead_assignment_date_time,
        led.created_date AS lead_created_date,
        led.modified_date AS lead_modified_date,
        led.podc_start,
        led.podc_end,
        led.plc_start,
        led.plc_end
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_agent_disposition_field_response adf
        ON adf.response_id = cdh.id
        AND adf.field_label = 'Sub Disposition'
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE led.assigned_agent IN (SELECT user_id FROM dealer_team_users)
      AND udm.dealer_id = v_dealerId
      AND cdh.dealer_id = v_dealerId
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
      AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(led.assigned_agent), v_teamMemberId))
      AND (
          (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
          OR
          (
              (DATE(led.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
              OR
              (DATE(led.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
              OR
              (DATE(cdh.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
          )
      )
),
user_agg AS (
    SELECT
        mu.id AS user_id,
        CONCAT(mu.first_name, ' ', mu.last_name) AS agent_name,
        mr.role AS agent_role,
        urd.id AS reporting_id,
        CONCAT(urd.first_name, ' ', urd.last_name) AS reporting_name,
        mmr.role AS reporting_role
    FROM mmi_mast_user_registration_detail mu
    LEFT JOIN mmi_user_role_mapping urm ON mu.id = urm.user_id
    LEFT JOIN mmi_mast_role mr ON urm.role_id = mr.role_id
    LEFT JOIN mmi_user_reporting ur ON ur.user_id = mu.id
    LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ur.supervisor_id
    LEFT JOIN mmi_user_role_mapping murm ON urd.id = murm.user_id
    LEFT JOIN mmi_mast_role mmr ON murm.role_id = mmr.role_id
)
SELECT
    de.lead_id AS 'Lead Reference Number',
    de.policy_no AS 'Policy No',
    de.insurance_company AS 'Insurance Company',
    de.insured_name AS 'Insured Name',
    de.model AS 'Model',
    de.vehicle_reg_no AS 'Vehicle Reg No',
    de.vin AS 'VIN',
    CONCAT(u.agent_name, ' / ', u.agent_role) AS 'User Name/ User Type',
    CONCAT(u.reporting_name, ' / ', u.reporting_role) AS 'Assignee Name/ User Type',
    de.plan_type AS 'Plan Type',
    de.vehicle_class AS 'Vehicle Class',
    de.call_status AS 'Main Disposition Status',
    de.sub_disposition_value AS 'Sub Disposition',
    de.remarks AS 'Remarks',
    de.podc_start AS 'Period of Own Damage Cover start',
    de.podc_end AS 'Period of Own Damage Cover end',
    de.plc_start AS 'Period of Liability Cover start',
    de.plc_end AS 'Period of Liability Cover end',
    de.policy_expiry_date AS 'Policy Expiry Date',
    de.renewal_category AS 'Renewal Category',
    de.next_call_datetime AS 'Next Follow Up date and Time',
    de.lead_status AS 'Final Lead Status',
    de.lead_assignment_date_time AS 'Date and Time of Lead Assignment',
    CASE WHEN de.lead_status IN ('Won','Lost','Closed') THEN de.lead_created_date ELSE NULL END AS 'Date and Time of Lead Converted/Closed',
    COALESCE(de.lead_modified_date, de.lead_created_date) AS 'Date and Time of Last updated',
    de.dispo_created_date AS 'Disposition Date/Time'
FROM disposition_events de
LEFT JOIN user_agg u ON de.assigned_agent = u.user_id
ORDER BY de.dispo_created_date DESC;

