SELECT
    leadStatus,
    COALESCE(count, 0) AS count,
    CONCAT(ROUND(COALESCE(percentage, 0), 2)) AS percentage
FROM (
    -- Converted (direct from archive table where lead_status = 'Won')
    SELECT
        'Converted' AS leadStatus,
        COUNT(DISTINCT la.lead_id) AS count,
        (COUNT(DISTINCT la.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM mmi_lead_archive_details la
    JOIN mmi_user_dealer_mapping udm ON la.assigned_agent = udm.user_id
    WHERE la.lead_status = 'Won'
      AND la.assigned_agent = v_userId
      AND udm.dealer_id = v_dealerId
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(la.vehicle_class), v_segment))
      AND (
          (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
          OR
          (
              DATE(la.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d')
              AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
              OR DATE(la.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d')
              AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
          )
      )

    UNION ALL

    -- Contacted (all disposition counts from main query)
    SELECT
        'Contacted' AS leadStatus,
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM latest_dispositions ld
    -- WHERE ld.rn = 1

    UNION ALL

    -- Quote Shared (using latest disposition logic)
    SELECT
        'Quote Shared' AS leadStatus,
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM latest_dispositions ld
    JOIN mmi_mast_disposition md ON md.disposition_id = ld.dealer_disposition_id
        AND md.sub_disposition = ld.sub_disposition_value
    WHERE -- ld.rn = 1  AND 
	md.sub_disposition = 'Shared Quotes'

    UNION ALL

    -- Total Leads
    SELECT
        'Total Leads' AS leadStatus,
        (SELECT total_count FROM total_leads) AS count,
        CASE
            WHEN (SELECT total_count FROM total_leads) = 0 THEN 0.00
            ELSE 100.00
        END AS percentage
) AS lead_summary
ORDER BY
    CASE leadStatus
        WHEN 'Converted' THEN 1
        WHEN 'Contacted' THEN 2
        WHEN 'Quote Shared' THEN 3
        WHEN 'Total Leads' THEN 4
    END;

                    -- Converted And Closed Leads

   WITH leads AS (
    SELECT DISTINCT
        l.insured_name AS customerName,
        l.lead_id AS leadId,
        l.policy_no AS policyNo,
        l.model AS vehicleDetail,
        -- mdisp.next_status AS status,
        adfr.field_value AS status,
        l.modified_date,
        l.created_date,
        disposition_color AS dispositionColor,
        ROW_NUMBER() OVER (PARTITION BY l.lead_id ORDER BY l.modified_date DESC) AS rn 
    FROM mmi_lead_archive_details l
    LEFT JOIN mmi_call_disposition_history dis ON dis.lead_id = l.lead_id
    LEFT JOIN mmi_agent_disposition_field_response adfr on adfr.response_id = dis.id
		AND adfr.field_label = 'Sub Disposition'
    LEFT JOIN mmi_mast_disposition mdisp ON mdisp.sub_disposition = adfr.field_value    
    -- LEFT JOIN mmi_mast_disposition mdisp ON mdisp.disposition_id = dis.dealer_disposition_id
    -- LEFT JOIN mmi_mast_call_disposition mcd ON mcd.disposition_id = mdisp.disposition_id
    LEFT JOIN mmi_user_dealer_mapping udm ON dis.agent_code = udm.user_id
     WHERE l.lead_status IN ('Won','Lost')
   --  WHERE mdisp.final_status IN ('Won','Lost')
      AND dis.agent_code = v_userId
      AND udm.dealer_id = v_dealerId
)
SELECT 
    customerName,
    leadId,
    policyNo,
    vehicleDetail,
    status,
    modified_date,
    created_date,
    dispositionColor
FROM leads
WHERE rn = 1 
UNION ALL
