                    -- Disposition Summary


-- Main Dispositions for Agent

WITH latest_dispositions AS (
    SELECT
        cdh.lead_id,
        cdh.dealer_disposition_id,
        adf.field_value AS sub_disposition_value,
        ROW_NUMBER() OVER(PARTITION BY cdh.lead_id ORDER BY cdh.created_date DESC) AS rn
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_agent_disposition_field_response adf
        ON adf.response_id = cdh.id
        AND adf.field_label = 'Sub Disposition'
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE
      udm.dealer_id = v_dealerId
      AND cdh.dealer_id = v_dealerId
)
SELECT
    md.disposition AS disposition,
    COUNT(DISTINCT ld.lead_id) AS count,
    ROUND((COUNT(DISTINCT ld.lead_id) * 100.0 /
           NULLIF((SELECT COUNT(DISTINCT led.lead_id)
                   FROM mmi_lead_details led
                   JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
                   WHERE
                     udm.dealer_id = v_dealerId), 0)), 2) AS percentage
FROM mmi_mast_disposition md
LEFT JOIN latest_dispositions ld
    ON md.disposition_id = ld.dealer_disposition_id
    AND md.sub_disposition = ld.sub_disposition_value
     AND ld.rn = 1
GROUP BY md.disposition
ORDER BY COUNT(DISTINCT ld.lead_id) DESC, md.disposition;


-- Sub Dispositions for Agent
SELECT
    md.disposition,
    md.sub_disposition,
    COALESCE(COUNT(DISTINCT ld.lead_id), 0) AS total_count
FROM mmi_mast_disposition md
LEFT JOIN (
    SELECT
        cdh.lead_id,
        cdh.dealer_disposition_id,
        adf.field_value AS sub_disposition_value -- ,
        -- ROW_NUMBER() OVER(PARTITION BY cdh.lead_id ORDER BY cdh.created_date DESC) AS rn
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_agent_disposition_field_response adf
        ON adf.response_id = cdh.id
        AND adf.field_label = 'Sub Disposition'
    -- JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
	INNER JOIN (
        SELECT lead_id, MAX(created_date) AS max_created_date
        FROM mmi_call_disposition_history
        GROUP BY lead_id
    ) latest ON cdh.lead_id = latest.lead_id AND cdh.created_date = latest.max_created_date
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE
          udm.dealer_id = v_dealerId
          AND cdh.dealer_id = v_dealerId
) ld
ON md.disposition_id = ld.dealer_disposition_id
    AND md.sub_disposition = ld.sub_disposition_value
    -- AND ld.rn = 1
GROUP BY md.disposition, md.sub_disposition
ORDER BY md.disposition, md.sub_disposition;


-- Lead Conversion

WITH total_leads AS (
    SELECT COUNT(DISTINCT l.lead_id) AS total_count
    FROM mmi_lead_details l
    JOIN mmi_user_dealer_mapping udm ON l.assigned_agent = udm.user_id
    WHERE l.lead_type IN ('Hot', 'Warm', 'Cold')
      AND udm.dealer_id = v_dealerId
),
latest_dispositions AS (
    SELECT
        cdh.lead_id,
        cdh.dealer_disposition_id,
        adf.field_value AS sub_disposition_value -- ,
        -- ROW_NUMBER() OVER(PARTITION BY cdh.lead_id ORDER BY cdh.created_date DESC) AS rn
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_agent_disposition_field_response adf
        ON adf.response_id = cdh.id
        AND adf.field_label = 'Sub Disposition'
    -- JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
	INNER JOIN (
        SELECT lead_id, MAX(created_date) AS max_created_date
        FROM mmi_call_disposition_history
        GROUP BY lead_id
    ) latest ON cdh.lead_id = latest.lead_id AND cdh.created_date = latest.max_created_date
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE udm.dealer_id = v_dealerId
      AND cdh.dealer_id = v_dealerId
)

SELECT
    leadStatus,
    COALESCE(count, 0) AS count,
    CONCAT(ROUND(COALESCE(percentage, 0), 2)) AS percentage
FROM (
    -- Converted (direct from archive table where lead_status = 'Won')
    SELECT
        'Converted' AS leadStatus,
        COUNT(DISTINCT la.lead_id) AS count,
        (COUNT(DISTINCT la.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM mmi_lead_archive_details la
    JOIN mmi_user_dealer_mapping udm ON la.assigned_agent = udm.user_id
    WHERE la.lead_status = 'Won'
      AND udm.dealer_id = v_dealerId

    UNION ALL

    -- Contacted (all latest dispositions - same as main dispositions total count)
    SELECT
        'Contacted' AS leadStatus,
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM latest_dispositions ld
    -- WHERE ld.rn = 1

    UNION ALL

    -- Quote Shared (using latest disposition logic)
    SELECT
        'Quote Shared' AS leadStatus,
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM latest_dispositions ld
    JOIN mmi_mast_disposition md ON md.disposition_id = ld.dealer_disposition_id
        AND md.sub_disposition = ld.sub_disposition_value
    WHERE -- ld.rn = 1 AND 
	md.sub_disposition = 'Shared Quotes'

    UNION ALL

    -- Total Leads
    SELECT
        'Total Leads' AS leadStatus,
        (SELECT total_count FROM total_leads) AS count,
        CASE
            WHEN (SELECT total_count FROM total_leads) = 0 THEN 0.00
            ELSE 100.00
        END AS percentage
) AS lead_summary
ORDER BY
    CASE leadStatus
        WHEN 'Converted' THEN 1
        WHEN 'Contacted' THEN 2
        WHEN 'Quote Shared' THEN 3
        WHEN 'Total Leads' THEN 4
    END;


