  )

UNION ALL

SELECT 'Warm Leads' AS leadType, IFNULL(COUNT(DISTINCT l.lead_id), 0) AS Count
FROM mmi_lead_details l
JOIN mmi_user_dealer_mapping udm ON l.assigned_agent = udm.user_id
WHERE l.lead_type = 'Warm'
 --  AND l.assigned_agent = v_userId
  AND udm.dealer_id = v_dealerId
  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
  AND (
      (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
      OR
      (
          DATE(l.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
          OR DATE(l.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
      )
  )

UNION ALL

SELECT 'Cold Leads' AS leadType, IFNULL(COUNT(DISTINCT l.lead_id), 0) AS Count
FROM mmi_lead_details l
JOIN mmi_user_dealer_mapping udm ON l.assigned_agent = udm.user_id
WHERE l.lead_type = 'Cold'
  -- AND l.assigned_agent = v_userId
  AND udm.dealer_id = v_dealerId
  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
  AND (
      (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
      OR
      (
          DATE(l.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
          OR DATE(l.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
      )
  );


                    -- Disposition Summary with filters

 -- Main Dispositions for Agent

WITH latest_dispositions AS (
    SELECT
        cdh.lead_id,
        cdh.dealer_disposition_id,
        adf.field_value AS sub_disposition_value,
        ROW_NUMBER() OVER(PARTITION BY cdh.lead_id ORDER BY cdh.created_date DESC) AS rn
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_agent_disposition_field_response adf
        ON adf.response_id = cdh.id
        AND adf.field_label = 'Sub Disposition'
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE
      udm.dealer_id = v_dealerId
      AND cdh.dealer_id = v_dealerId
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
      AND (
          (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
          OR
          (
              (DATE(led.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
              OR
              (DATE(led.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
              OR
              (DATE(cdh.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
          )
      )
)
SELECT
    md.disposition AS disposition,
    COUNT(DISTINCT ld.lead_id) AS count,
    ROUND((COUNT(DISTINCT ld.lead_id) * 100.0 /
           NULLIF((SELECT COUNT(*)
                   FROM mmi_lead_details led
                   JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
                   WHERE
                     udm.dealer_id = v_dealerId
                     AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
                     AND (
                         (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
                         OR
                         (
                             (DATE(led.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
                             OR
                             (DATE(led.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
                         )
                     )), 0)), 2) AS percentage
FROM mmi_mast_disposition md
LEFT JOIN latest_dispositions ld
    ON md.disposition_id = ld.dealer_disposition_id
    AND md.sub_disposition = ld.sub_disposition_value
    AND ld.rn = 1
GROUP BY md.disposition
ORDER BY COUNT(DISTINCT ld.lead_id) DESC, md.disposition;


-- Sub Dispositions for Agent
SELECT
    md.disposition,
    md.sub_disposition,
    COALESCE(COUNT(DISTINCT ld.lead_id), 0) AS total_count
FROM mmi_mast_disposition md
LEFT JOIN (
    SELECT
        cdh.lead_id,
        cdh.dealer_disposition_id,
        adf.field_value AS sub_disposition_value,
        ROW_NUMBER() OVER(PARTITION BY cdh.lead_id ORDER BY cdh.created_date DESC) AS rn
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_agent_disposition_field_response adf
        ON adf.response_id = cdh.id
        AND adf.field_label = 'Sub Disposition'
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE
          udm.dealer_id = v_dealerId
          AND cdh.dealer_id = v_dealerId
          AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
          AND (
              (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
              OR
              (
                  (DATE(led.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
                  OR
                  (DATE(led.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
                  OR
                  (DATE(cdh.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
              )
          )
) ld ON md.disposition_id = ld.dealer_disposition_id
    AND md.sub_disposition = ld.sub_disposition_value
    AND ld.rn = 1
GROUP BY md.disposition, md.sub_disposition
ORDER BY md.disposition, md.sub_disposition;


                    -- Lead Conversion with filters

WITH total_leads AS (
    SELECT COUNT(DISTINCT lead_id) AS total_count
    FROM mmi_lead_details AS main
    JOIN mmi_user_dealer_mapping udm ON main.assigned_agent = udm.user_id
    WHERE main.lead_type IN ('Hot', 'Warm', 'Cold')
      AND udm.dealer_id = v_dealerId
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(main.vehicle_class), v_segment))
      AND (
          (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
          OR (
              DATE(main.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d')
              AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
              OR DATE(main.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d')
              AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
          )
      )
),
latest_dispositions AS (
    SELECT
        cdh.lead_id,
        cdh.dealer_disposition_id,
        adf.field_value AS sub_disposition_value -- ,
        -- ROW_NUMBER() OVER(PARTITION BY cdh.lead_id ORDER BY cdh.created_date DESC) AS rn
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_agent_disposition_field_response adf
        ON adf.response_id = cdh.id
        AND adf.field_label = 'Sub Disposition'
    -- JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
	INNER JOIN (
        SELECT lead_id, MAX(created_date) AS max_created_date
        FROM mmi_call_disposition_history
        GROUP BY lead_id
    ) latest ON cdh.lead_id = latest.lead_id AND cdh.created_date = latest.max_created_date
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE udm.dealer_id = v_dealerId
      AND cdh.dealer_id = v_dealerId
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
      AND (
          (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
          OR (
              DATE(cdh.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d')
              AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
          )
      )
)

SELECT
    leadStatus,
    COALESCE(count, 0) AS count,
    CONCAT(ROUND(COALESCE(percentage, 0), 2)) AS percentage
FROM (
    -- Converted (direct from archive table where lead_status = 'Won')
    SELECT
        'Converted' AS leadStatus,
        COUNT(DISTINCT la.lead_id) AS count,
        (COUNT(DISTINCT la.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM mmi_lead_archive_details la
    JOIN mmi_user_dealer_mapping udm ON la.assigned_agent = udm.user_id
    WHERE la.lead_status = 'Won'
      AND udm.dealer_id = v_dealerId
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(la.vehicle_class), v_segment))
      AND (
          (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
          OR (
              DATE(la.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d')
              AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
              OR DATE(la.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d')
              AND STR_TO_DATE(v_endDate, '%Y-%m-%d')
          )
      )

    UNION ALL

    -- Contacted (all latest dispositions)
    SELECT
        'Contacted' AS leadStatus,
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM latest_dispositions ld
    -- WHERE ld.rn = 1

    UNION ALL

    -- Quote Shared (using latest disposition logic)
    SELECT
        'Quote Shared' AS leadStatus,
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) /
        NULLIF((SELECT total_count FROM total_leads), 0) AS percentage
    FROM latest_dispositions ld
    JOIN mmi_mast_disposition md ON md.disposition_id = ld.dealer_disposition_id
        AND md.sub_disposition = ld.sub_disposition_value
    WHERE -- ld.rn = 1  AND 
	md.sub_disposition = 'Shared Quotes'

    UNION ALL

    -- Total Leads
    SELECT
        'Total Leads' AS leadStatus,
        (SELECT total_count FROM total_leads) AS count,
        CASE
            WHEN (SELECT total_count FROM total_leads) = 0 THEN 0.00
            ELSE 100.00
        END AS percentage
) AS lead_summary
ORDER BY
    CASE leadStatus
        WHEN 'Converted' THEN 1
        WHEN 'Contacted' THEN 2
        WHEN 'Quote Shared' THEN 3
        WHEN 'Total Leads' THEN 4
    END;

                    -- Converted And Closed Leads

   WITH leads AS (
    SELECT DISTINCT
        l.insured_name AS customerName,
        l.lead_id AS leadId,
        l.policy_no AS policyNo,
        l.model AS vehicleDetail,
        adfr.field_value AS status,
        l.modified_date,
        l.created_date,
        disposition_color AS dispositionColor,
        ROW_NUMBER() OVER (PARTITION BY l.lead_id ORDER BY l.modified_date DESC) AS rn
    FROM mmi_lead_archive_details l
    LEFT JOIN mmi_call_disposition_history dis ON dis.lead_id = l.lead_id
    LEFT JOIN mmi_agent_disposition_field_response adfr on adfr.response_id = dis.id
    AND adfr.field_label = 'Sub Disposition'
    LEFT JOIN mmi_mast_disposition mdisp ON mdisp.sub_disposition = adfr.field_value
    -- LEFT JOIN mmi_mast_disposition mdisp ON mdisp.disposition_id = dis.dealer_disposition_id
    -- LEFT JOIN mmi_mast_call_disposition mcd ON mcd.disposition_id = mdisp.disposition_id
    LEFT JOIN mmi_user_dealer_mapping udm ON dis.agent_code = udm.user_id
   WHERE l.lead_status IN ('Won','Lost')

     --  AND dis.agent_code = v_userId
AND
      udm.dealer_id = v_dealerId
)
SELECT 
    customerName,
    leadId,
    policyNo,
    vehicleDetail,
    status,
    modified_date,
    created_date,
    dispositionColor
FROM leads
WHERE rn = 1 
UNION ALL
SELECT
    '0' AS customerName,
    0 AS leadId,
    '0' AS policyNo,
    '0' AS vehicleDetail,
    '0' AS status,
    '0' AS modified_date,
    '0' AS created_date,
    '0' AS dispositionColor
WHERE NOT EXISTS (SELECT 1 FROM leads)
ORDER BY created_date DESC
LIMIT 10;


                    SET SP_STATUS = '200';
                    SET MESSAGE = 'Fetched Filtered Dashboard for Agents without calling access.';
                    
                -- EXCEL AGENT WITHOUT CALLING ACCESS
                ELSEIF type = 'downloadExcel' THEN

WITH disposition_events AS (
    SELECT
        cdh.id AS dispo_id,
        cdh.lead_id,
        cdh.call_status,
        cdh.remarks,
        cdh.next_call_datetime,
        cdh.dealer_disposition_id,
        cdh.created_date AS dispo_created_date,
        adf.field_value AS sub_disposition_value,
        led.dealer_code,
        led.assigned_agent,
        led.policy_no,
        led.insurance_company,
        led.insured_name,
        led.model,
        led.reg_no AS vehicle_reg_no,
        led.vin,
        led.plan_type,
        led.vehicle_class,
        led.policy_expiry_date,
        led.renewal_category,
        led.lead_status,
        led.lead_assignment_date_time,
        led.created_date AS lead_created_date,
        led.modified_date AS lead_modified_date,
        led.podc_start,
        led.podc_end,
        led.plc_start,
        led.plc_end
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_agent_disposition_field_response adf
        ON adf.response_id = cdh.id
        AND adf.field_label = 'Sub Disposition'
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE udm.dealer_id = v_dealerId
      AND cdh.dealer_id = v_dealerId
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
      -- No agent filter (whole dealer)
      AND (
          (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
          OR
          (
              (DATE(led.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
              OR
              (DATE(led.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
              OR
              (DATE(cdh.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
          )
      )
),
user_agg AS (
    SELECT
        mu.id AS user_id,
        CONCAT(mu.first_name, ' ', mu.last_name) AS agent_name,
        mr.role AS agent_role,
        urd.id AS reporting_id,
        CONCAT(urd.first_name, ' ', urd.last_name) AS reporting_name,
        mmr.role AS reporting_role
    FROM mmi_mast_user_registration_detail mu
    LEFT JOIN mmi_user_role_mapping urm ON mu.id = urm.user_id
    LEFT JOIN mmi_mast_role mr ON urm.role_id = mr.role_id
    LEFT JOIN mmi_user_reporting ur ON ur.user_id = mu.id
    LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ur.supervisor_id
    LEFT JOIN mmi_user_role_mapping murm ON urd.id = murm.user_id
    LEFT JOIN mmi_mast_role mmr ON murm.role_id = mmr.role_id
)
SELECT
    de.lead_id AS 'Lead Reference Number',
    de.policy_no AS 'Policy No',
    de.insurance_company AS 'Insurance Company',
    de.insured_name AS 'Insured Name',
    de.model AS 'Model',
    de.vehicle_reg_no AS 'Vehicle Reg No',
    de.vin AS 'VIN',
    CONCAT(u.agent_name, ' / ', u.agent_role) AS 'User Name/ User Type',
    CONCAT(u.reporting_name, ' / ', u.reporting_role) AS 'Assignee Name/ User Type',
    de.plan_type AS 'Plan Type',
    de.vehicle_class AS 'Vehicle Class',
    de.call_status AS 'Main Disposition Status',
    de.sub_disposition_value AS 'Sub Disposition',
    de.remarks AS 'Remarks',
    de.podc_start AS 'Period of Own Damage Cover start',
    de.podc_end AS 'Period of Own Damage Cover end',
    de.plc_start AS 'Period of Liability Cover start',
    de.plc_end AS 'Period of Liability Cover end',
    de.policy_expiry_date AS 'Policy Expiry Date',
    de.renewal_category AS 'Renewal Category',
    de.next_call_datetime AS 'Next Follow Up date and Time',
    de.lead_status AS 'Final Lead Status',
    de.lead_assignment_date_time AS 'Date and Time of Lead Assignment',
    CASE WHEN de.lead_status IN ('Won','Lost','Closed') THEN de.lead_created_date ELSE NULL END AS 'Date and Time of Lead Converted/Closed',
    COALESCE(de.lead_modified_date, de.lead_created_date) AS 'Date and Time of Last updated',
    de.dispo_created_date AS 'Disposition Date/Time'
FROM disposition_events de
LEFT JOIN user_agg u ON de.assigned_agent = u.user_id
ORDER BY de.dispo_created_date DESC;

	--

	
WITH RECURSIVE team_hierarchy AS (
    SELECT v_userId AS user_id
    UNION ALL
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
dealer_team_users AS (
    SELECT th.user_id
    FROM team_hierarchy th
    JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
    WHERE udm.dealer_id = v_dealerId
),
disposition_events AS (
    SELECT
        cdh.id AS dispo_id,
        cdh.lead_id,
        cdh.call_status AS disposition, 
        led.assigned_agent,
        led.vehicle_class,
        led.created_date AS lead_created_date,
        led.modified_date AS lead_modified_date,
        cdh.created_date AS dispo_created_date
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
    JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
    WHERE led.assigned_agent IN (SELECT user_id FROM dealer_team_users)
      AND udm.dealer_id = v_dealerId
      AND cdh.dealer_id = v_dealerId
		AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
		AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(led.assigned_agent), v_teamMemberId))
		AND (
			(v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
		OR
			(
			(DATE(led.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
		OR
			(DATE(led.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
		OR
			(DATE(cdh.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
		)
	)
),
user_dispo_counts AS (
    SELECT
        CONCAT(COALESCE(mur.first_name, ''), ' ', COALESCE(mur.last_name, ''), ' / ', COALESCE(mr.role, '')) AS user_name_role,
        de.disposition,
        COUNT(*) AS event_count
    FROM disposition_events de
    JOIN mmi_mast_user_registration_detail mur ON mur.id = de.assigned_agent
    LEFT JOIN mmi_user_role_mapping urm ON mur.id = urm.user_id
    LEFT JOIN mmi_mast_role mr ON urm.role_id = mr.role_id
    GROUP BY user_name_role, de.disposition
),
pivoted AS (
    SELECT
        user_name_role,
        COALESCE(MAX(CASE WHEN disposition = 'Callback Scheduled' THEN event_count END), 0) AS 'Callback Scheduled',
        COALESCE(MAX(CASE WHEN disposition = 'Converted/ Won' THEN event_count END), 0) AS 'Converted/ Won',
        COALESCE(MAX(CASE WHEN disposition = 'Follow-Up' THEN event_count END), 0) AS 'Follow-Up',
        COALESCE(MAX(CASE WHEN disposition = 'Interested' THEN event_count END), 0) AS 'Interested',
        COALESCE(MAX(CASE WHEN disposition = 'Not Eligible' THEN event_count END), 0) AS 'Not Eligible',
        COALESCE(MAX(CASE WHEN disposition = 'Not Interested' THEN event_count END), 0) AS 'Not Interested',
        COALESCE(MAX(CASE WHEN disposition = 'Not Reachable' THEN event_count END), 0) AS 'Not Reachable',
        SUM(event_count) AS 'Grand Total'
    FROM user_dispo_counts
    GROUP BY user_name_role
)
SELECT * FROM pivoted
UNION ALL
SELECT 
    'Grand Total',
    SUM(`Callback Scheduled`),
    SUM(`Converted/ Won`),
    SUM(`Follow-Up`),
    SUM(`Interested`),
    SUM(`Not Eligible`),
    SUM(`Not Interested`),
    SUM(`Not Reachable`),
    SUM(`Grand Total`)
FROM pivoted
ORDER BY CASE WHEN user_name_role = 'Grand Total' THEN 1 ELSE 0 END, user_name_role;
    

SET SP_STATUS = '200';
SET MESSAGE = 'Excel download data prepared.';

    END IF;
            END IF;
        END IF;
    END IF;
END ;;
DELIMITER ;
