DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_dealer_bucket_mapping`(
	IN p_json JSON,
	OUT p_status_code VARCHAR(100),
    OUT p_status_message VARCHAR(200)
)
BEGIN
	DECLARE v_dealer_code varchar(100);
    DECLARE v_parent_code varchar(100);
    DECLARE v_role_type varchar(100);
    DECLARE v_type varchar(100) DEFAULT '';
    DECLARE v_limit INT DEFAULT 10; 
    DECLARE v_offset INT DEFAULT 0;
    DECLARE v_calculated INT DEFAULT 0;
    
    DECLARE err_code INT;
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_dealer_bucket_mapping', 'DealerBucketMap', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    
	SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.dealerCode'));
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.parentCode'));
	SET v_limit = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.limit')) AS UNSIGNED), 10);
    SET v_offset = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.offset')) AS UNSIGNED), 0);
	SET v_calculated = (v_offset - 1) * v_limit;
    
    SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.roleType'));
    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.type'));
	
    
    IF v_role_type = 'MIBL' THEN
		
        SELECT distinct dl.parent_code,dl.dealer_name 
        -- from mmi_mast_dealer md left join
		from mmi_dealer_details dl -- on md.parent_code = dl.parent_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL; 
        
		IF v_type = 'Dealer' THEN
			SELECT DISTINCT 
				mb.id AS bucket_id,mb.bucket_name,location.value AS bucket_location,
				dlm.dealer_name FROM mmi_mast_bucket mb
				LEFT JOIN mmi_dealer_location_mapping dlm ON mb.dealer_code = dlm.mapping_dealer_code
				LEFT JOIN mmi_mast_dealer_location mdl ON dlm.location_code = mdl.loc_code
				-- LEFT JOIN mmi_mast_dealer md ON md.parent_code = dlm.parent_code
                LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = dlm.mapping_dealer_code
				LEFT JOIN JSON_TABLE(CASE
				WHEN JSON_VALID(mb.bucket_location) = 1 THEN CAST(mb.bucket_location AS JSON)
				ELSE JSON_ARRAY(mb.bucket_location)
				END,
				"$[*]" COLUMNS (value VARCHAR(255) PATH "$")
				) AS location ON 1 = 1
				WHERE dlm.parent_code = v_parent_code 
				LIMIT v_limit OFFSET v_calculated;

				SELECT COUNT(DISTINCT mb.id) AS bucket_count
				FROM mmi_mast_bucket mb
				LEFT JOIN mmi_dealer_location_mapping dlm ON mb.dealer_code = dlm.mapping_dealer_code
				LEFT JOIN mmi_mast_dealer_location mdl ON dlm.location_code = mdl.loc_code
				-- LEFT JOIN mmi_mast_dealer md ON md.parent_code = dlm.parent_code
                LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = dlm.mapping_dealer_code
				LEFT JOIN JSON_TABLE(
				CASE
				WHEN JSON_VALID(mb.bucket_location) = 1 THEN CAST(mb.bucket_location AS JSON)
				ELSE JSON_ARRAY(mb.bucket_location)
				END,
				"$[*]" COLUMNS (value VARCHAR(255) PATH "$")
				) AS location ON 1 = 1
				WHERE dlm.parent_code = v_parent_code 
				LIMIT v_limit OFFSET v_calculated;
			SET p_status_code = '200';
			SET p_status_message = 'Data Fetched Successfully';
		
        ELSE
            SELECT DISTINCT 
			mb.id AS bucket_id,mb.bucket_name,location.value AS bucket_location,
			dlm.dealer_name FROM mmi_mast_bucket mb
			LEFT JOIN mmi_dealer_location_mapping dlm ON mb.dealer_code = dlm.mapping_dealer_code
			LEFT JOIN mmi_mast_dealer_location mdl ON dlm.location_code = mdl.loc_code
			-- LEFT JOIN mmi_mast_dealer md ON md.parent_code = dlm.parent_code
            LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = dlm.mapping_dealer_code
			LEFT JOIN JSON_TABLE(CASE
			WHEN JSON_VALID(mb.bucket_location) = 1 THEN CAST(mb.bucket_location AS JSON)
			ELSE JSON_ARRAY(mb.bucket_location)
			END,
			"$[*]" COLUMNS (value VARCHAR(255) PATH "$")
			) AS location ON 1 = 1
			-- WHERE mb.dealer_code = v_dealer_code AND md.parent_code = v_parent_code 
            LIMIT v_limit OFFSET v_calculated;

			SELECT COUNT(DISTINCT mb.id) AS bucket_count
			FROM mmi_mast_bucket mb
			LEFT JOIN mmi_dealer_location_mapping dlm ON mb.dealer_code = dlm.mapping_dealer_code
			LEFT JOIN mmi_mast_dealer_location mdl ON dlm.location_code = mdl.loc_code
			-- LEFT JOIN mmi_mast_dealer md ON md.parent_code = dlm.parent_code
            LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = dlm.mapping_dealer_code
			LEFT JOIN JSON_TABLE(
			CASE
			WHEN JSON_VALID(mb.bucket_location) = 1 THEN CAST(mb.bucket_location AS JSON)
			ELSE JSON_ARRAY(mb.bucket_location)
			END,
			"$[*]" COLUMNS (value VARCHAR(255) PATH "$")
			) AS location ON 1 = 1;
			-- WHERE mb.dealer_code = v_dealer_code AND md.parent_code = v_parent_code 
            -- LIMIT v_limit OFFSET v_calculated;
			SET p_status_code = '200';
			SET p_status_message = 'Data Fetched Successfully';
        END IF;
    ELSE
    IF v_dealer_code IS NULL OR v_parent_code IS NULL THEN
        SET p_status_code = '400';
        SET p_status_message = 'Invalid input parameters. Required Fields cannot be NULL or empty';
	ELSE
		SELECT DISTINCT 
			mb.id AS bucket_id,mb.bucket_name,location.value AS bucket_location,
			dlm.dealer_name FROM mmi_mast_bucket mb
			LEFT JOIN mmi_dealer_location_mapping dlm ON mb.dealer_code = dlm.mapping_dealer_code
			LEFT JOIN mmi_mast_dealer_location mdl ON dlm.location_code = mdl.loc_code
			-- LEFT JOIN mmi_mast_dealer md ON md.parent_code = dlm.parent_code
            LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = dlm.mapping_dealer_code
			LEFT JOIN JSON_TABLE(CASE
			WHEN JSON_VALID(mb.bucket_location) = 1 THEN CAST(mb.bucket_location AS JSON)
			ELSE JSON_ARRAY(mb.bucket_location)
			END,
			"$[*]" COLUMNS (value VARCHAR(255) PATH "$")
			) AS location ON 1 = 1
			WHERE mb.dealer_code = v_dealer_code AND dlm.parent_code = v_parent_code 
            LIMIT v_limit OFFSET v_calculated;

			SELECT COUNT(DISTINCT mb.id) AS bucket_count
			FROM mmi_mast_bucket mb
			LEFT JOIN mmi_dealer_location_mapping dlm ON mb.dealer_code = dlm.mapping_dealer_code
			LEFT JOIN mmi_mast_dealer_location mdl ON dlm.location_code = mdl.loc_code
			-- LEFT JOIN mmi_mast_dealer md ON md.parent_code = dlm.parent_code
            LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = dlm.mapping_dealer_code
			LEFT JOIN JSON_TABLE(
			CASE
			WHEN JSON_VALID(mb.bucket_location) = 1 THEN CAST(mb.bucket_location AS JSON)
			ELSE JSON_ARRAY(mb.bucket_location)
			END,
			"$[*]" COLUMNS (value VARCHAR(255) PATH "$")
			) AS location ON 1 = 1
			WHERE mb.dealer_code = v_dealer_code AND dlm.parent_code = v_parent_code 
            LIMIT v_limit OFFSET v_calculated;
		SET p_status_code = '200';
        SET p_status_message = 'Data Fetched Successfully';
    END IF;
    END IF;
END ;;
DELIMITER ;
