CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_dealer_bucket_preferences_by_id`(
    IN p_bucketId INT,
    OUT p_status_code VARCHAR(100),
    OUT p_status_message VARCHAR(200)
)
BEGIN

	DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_dealer_bucket_preferences_by_id', 'DealerBucketByID', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    IF p_bucketId IS NULL THEN
        SET p_status_code = '400';
        SET p_status_message = 'Invalid input parameters. Required Fields cannot be NULL or empty';
	ELSE
			SELECT
				b.bucket_name,
				d.dealer_name,
				GROUP_CONCAT(DISTINCT ins.ic_name) AS insurance_preferences,
				GROUP_CONCAT(DISTINCT seg.name) AS segment_preferences,
				GROUP_CONCAT(DISTINCT rc.renewal_category) AS renewal_preferences,
				GROUP_CONCAT(DISTINCT ao.addon_description) AS addon_preferences
			FROM mmi_bucket_dealer_mapping bd
			JOIN mmi_mast_bucket b ON bd.bucket_id = b.id
			JOIN mmi_get_dealer_list d ON bd.delaer_id = d.id
			LEFT JOIN mmi_call_user_preference_insurance pi ON pi.bucket_id = b.id
			LEFT JOIN mmi_mast_insurancecompany ins ON ins.ic_code = pi.ic_code
			LEFT JOIN mmi_call_user_preference_segment ps ON ps.bucket_id = b.id
			LEFT JOIN mmi_mast_segment seg ON seg.segment_id = ps.segment_id
			LEFT JOIN mmi_call_user_preference_renewal pr ON pr.bucket_id = b.id
			LEFT JOIN mmi_mast_renewal_category rc ON rc.id = pr.renewal_category_id
			LEFT JOIN mmi_call_user_preference_addon pa ON pa.bucket_id = b.id
			LEFT JOIN mmi_mast_addon ao ON ao.addon_code = pa.addon_id
			WHERE b.id = p_bucketId
			GROUP BY d.id, d.dealer_name, b.id, b.bucket_name;

		SET p_status_code = '200';
        SET p_status_message = 'Data Fetched Successfully';
    END IF;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
