CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_disposition_by_flag`(
 IN p_json_data JSON,
 OUT p_status VARCHAR(500),
 OUT p_message VARCHAR(500)
)
BEGIN
    DECLARE v_type VARCHAR(50); 
    DECLARE v_dealer_code VARCHAR(500);
    DECLARE v_disposition VARCHAR(50);
    DECLARE v_sub_disposition VARCHAR(50);
    DECLARE v_communication_types VARCHAR(500); 
	DECLARE v_parent_code VARCHAR(50);
    
    DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

		SET v_type = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.type'));
        SET p_status = '500';
        SET p_message = 'An error occurred. Please try again.';
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_disposition_by_flag', v_type, CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        ); 

    END;
    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.type'));
    SET v_disposition = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.disposition'));
    SET v_sub_disposition = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.subdisposition'));
    -- SET v_communication_types = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.communicationtype'));
	SET v_communication_types = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.fetchcommunicationtype'));
    SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerCode'));
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode'));
    
    IF v_type IS NULL OR v_type = '' THEN
        SET p_status = '200';
        SET p_message = 'Type cannot be empty or null';
    ELSE
        IF v_type = 'init' THEN
            SELECT DISTINCT disposition,final_status as dispositionStatus FROM mmi_mast_disposition;
            /*SELECT DISTINCT communication FROM mmi_dealer_details where 
            dealer_id = v_dealer_code and parent_code = v_parent_code;*/
            
            SET p_status = '200';
			SET p_message = 'Disposition Details';
        ELSEIF v_type = 'notification' THEN
            /*IF v_communication_types IS NULL OR v_communication_types = '' THEN
                SET p_status = '200';
                SET p_message = 'Communication types cannot be empty or null';
            ELSE*/
                -- Step 4.1: Fetch the template body using FIND_IN_SET to match communication types
                /*SELECT communication_type,template_body
                FROM mmi_disposition_template_master dtm
                JOIN mmi_mast_disposition md ON dtm.disposition_id = md.id
                WHERE FIND_IN_SET(dtm.communication_type, v_communication_types) > 0
                AND md.disposition = v_disposition
                AND md.sub_disposition = v_sub_disposition
                AND dtm.is_active = 1;*/
                
                SELECT DISTINCT dt.communication_type as communication
				FROM mmi_vw_fetch_disposition_templates dt
				LEFT JOIN mmi_dealer_details dl ON FIND_IN_SET(dt.communication_type, dl.communication) > 0
				WHERE dt.disposition = v_disposition AND dt.sub_disposition = v_sub_disposition
				AND dl.dealer_id = v_dealer_code 
                AND (FIND_IN_SET('Email', dl.communication) > 0 
				OR FIND_IN_SET('SMS', dl.communication) > 0
				OR FIND_IN_SET('WhatsApp', dl.communication) > 0);
                
                SET p_status = '200';
                SET p_message = 'Fetched successfully for the specified communication types';
            -- END IF;
        END IF;
    END IF;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
