CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_disposition_details_by_input`(
 IN Json_data JSON,
 OUT p_status_code VARCHAR(500),
 OUT p_status_message VARCHAR(500)
)
BEGIN
    DECLARE v_options_input VARCHAR(50);
    DECLARE err_code INT;
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_disposition_details_by_input', 'DispositionByInput', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    SET v_options_input = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.options_input'));
    
    IF v_options_input is null or v_options_input = '' or v_options_input = 'null' then
		SET p_status_code = '300';
		SET p_status_message = 'Dispostion Id Cannot be null or empty';
	ELSE
        /*select distinct mast_config_id,field_label,field_type,field_order,options from mmi_mast_disposition_config mdc left join
		mmi_mast_call_disposition mcd on mdc.mast_disposition_id = mcd.disposition_id
		where mcd.step1_input = v_options_input and field_label != 'step1_input';*/
        select distinct mast_config_id,field_label,field_type,field_order,options from mmi_mast_disposition_config1 mdc left join
		mmi_mast_disposition mcd on mdc.mast_disposition_id = mcd.disposition_id
		where mcd.disposition = v_options_input and mdc.is_required = 1 order by mast_config_id;
             
	 SET p_status_code = '200';
     SET p_status_message = 'Fetched successfully';
   END IF;  
END ;;
DELIMITER ;
