/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_dynamic_weighted_leads`()
BEGIN
    DECLARE total_weight INT;

    SELECT SUM(weight_percent) INTO total_weight
    FROM mmi_lead_categorization_weights
    WHERE metric IN (
        'expiry_days', 'expiry_diff', 'addon_premium', 'ncb',
        'invoice_years', 'service_history', 'claims', 'call_followup',
        'agent_dispo', 'quote', 'renewal'
    );

    IF total_weight != 100 THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Total weight of all metrics must be exactly 100%';
    END IF;

    SELECT
        mld.lead_id,
        mld.cluster_id,

        -- Calculate total_score using SUM() over weighted_score from unioned metrics
        -- COALESCE is used here to treat NULL scores (for leads not matching any metric) as 0,
        -- ensuring they contribute correctly to the total sum.
        -- The MAX(100) ensures the total score does not exceed 100, though with the
        -- corrected subqueries, it should naturally stay <= 100.
        ROUND(LEAST(COALESCE(SUM(metric_weighted.weighted_score), 0), 100), 2) AS total_score,

        -- Final dynamic categorization based on the corrected total_score
        CASE
            WHEN ROUND(LEAST(COALESCE(SUM(metric_weighted.weighted_score), 0), 100), 2) >= 60 THEN 'Hot'
            WHEN ROUND(LEAST(COALESCE(SUM(metric_weighted.weighted_score), 0), 100), 2) >= 40 THEN 'Warm'
            ELSE 'Cold'
        END AS final_lead_type

    FROM mmi_lead_details mld

    LEFT JOIN (
        SELECT lead_id, weighted_score FROM (
            -- [1] expiry_days
            SELECT mld.lead_id,
                MAX(w.weight_percent * lb.score_factor) AS weighted_score
            FROM mmi_lead_details mld
            JOIN mmi_lead_categorize_thresholds th ON th.metric='expiry_days'
                AND mld.expiry_days BETWEEN th.min_value AND th.max_value
            JOIN mmi_lead_categorize_labels lb ON lb.label_key = th.label_key
            JOIN mmi_lead_categorization_weights w ON w.metric='expiry_days'
            GROUP BY mld.lead_id -- Ensure unique score per lead for this metric

            UNION ALL

            -- [2] expiry_diff
            SELECT mld.lead_id,
                MAX(w.weight_percent * lb.score_factor)
            FROM mmi_lead_details mld
            JOIN mmi_lead_categorize_thresholds th ON th.metric='expiry_diff'
                AND DATEDIFF(mld.policy_expiry_date, NOW()) BETWEEN th.min_value AND th.max_value
            JOIN mmi_lead_categorize_labels lb ON lb.label_key = th.label_key
            JOIN mmi_lead_categorization_weights w ON w.metric='expiry_diff'
            GROUP BY mld.lead_id -- Ensure unique score per lead for this metric

            UNION ALL

            -- [3] addon_premium
            SELECT mld.lead_id,
                MAX(w.weight_percent * lb.score_factor)
            FROM mmi_lead_details mld
            JOIN mmi_lead_categorize_thresholds th ON th.metric='addon_premium'
                AND mld.addon_premium_amount BETWEEN th.min_value AND th.max_value
            JOIN mmi_lead_categorize_labels lb ON lb.label_key=th.label_key
            JOIN mmi_lead_categorization_weights w ON w.metric='addon_premium'
            GROUP BY mld.lead_id -- Ensure unique score per lead for this metric

            UNION ALL

            -- [4] ncb
            SELECT mld.lead_id,
                MAX(w.weight_percent * lb.score_factor)
            FROM mmi_lead_details mld
            JOIN mmi_lead_categorize_thresholds th ON th.metric='ncb'
                AND mld.ncb_percentage BETWEEN th.min_value AND th.max_value
            JOIN mmi_lead_categorize_labels lb ON lb.label_key=th.label_key
            JOIN mmi_lead_categorization_weights w ON w.metric='ncb'
            GROUP BY mld.lead_id -- Ensure unique score per lead for this metric

            UNION ALL

            -- [5] invoice_years
            SELECT mld.lead_id,
                MAX(w.weight_percent * lb.score_factor)
            FROM mmi_lead_details mld
            LEFT JOIN mmi_ebm_sales_data esd ON esd.chassis_number = (
                SELECT chassis_no FROM mmi_mast_customer_details
                WHERE cluster_id = mld.cluster_id LIMIT 1
            )
            JOIN mmi_lead_categorize_thresholds th ON th.metric='invoice_years'
                AND TIMESTAMPDIFF(YEAR, STR_TO_DATE(esd.invoice_date_time,'%d-%m-%Y %H:%i:%s'),NOW())
                    BETWEEN th.min_value AND th.max_value
            JOIN mmi_lead_categorize_labels lb ON lb.label_key=th.label_key
            JOIN mmi_lead_categorization_weights w ON w.metric='invoice_years'
            GROUP BY mld.lead_id -- Ensure unique score per lead for this metric

            UNION ALL

            -- [6] service_history
            SELECT s.cluster_id AS lead_id,
                MAX(w.weight_percent * lb.score_factor)
            FROM (
                SELECT c.cluster_id, COUNT(h.id) AS cnt
                FROM mmi_customer_service_history h
                JOIN mmi_mast_customer_details c ON h.chassis_number = c.chassis_no
                WHERE h.created_date >= CURDATE() - INTERVAL 1 YEAR
                GROUP BY c.cluster_id
            ) s
            JOIN mmi_lead_categorize_thresholds th ON th.metric='service_history'
                AND s.cnt BETWEEN th.min_value AND th.max_value
            JOIN mmi_lead_categorize_labels lb ON lb.label_key=th.label_key
            JOIN mmi_lead_categorization_weights w ON w.metric='service_history'
            GROUP BY s.cluster_id -- Ensure unique score per lead for this metric

            UNION ALL

            -- [7] claims
            SELECT s.cluster_id AS lead_id,
                MAX(w.weight_percent * lb.score_factor)
            FROM (
                SELECT c.cluster_id, COUNT(h.id) AS cnt
                FROM mmi_customer_claim_history h
                JOIN mmi_mast_customer_details c ON h.chassis_number = c.chassis_no
                GROUP BY c.cluster_id
            ) s
            JOIN mmi_lead_categorize_thresholds th ON th.metric='claims'
                AND s.cnt BETWEEN th.min_value AND th.max_value
            JOIN mmi_lead_categorize_labels lb ON lb.label_key=th.label_key
            JOIN mmi_lead_categorization_weights w ON w.metric='claims'
            GROUP BY s.cluster_id -- Ensure unique score per lead for this metric

            UNION ALL

            -- [8] call_followup
            SELECT sub.lead_id,
                MAX(w.weight_percent * lb.score_factor)
            FROM (
                SELECT lead_id, DATEDIFF(next_call_datetime, CURDATE()) AS dd
                FROM mmi_call_disposition_history
                WHERE next_call_datetime >= CURDATE()
            ) sub
            JOIN mmi_lead_categorize_datetime_thresholds dt ON dt.metric='call_followup'
                AND sub.dd BETWEEN dt.min_days_diff AND dt.max_days_diff
            JOIN mmi_lead_categorize_labels lb ON lb.label_key=dt.label_key
            JOIN mmi_lead_categorization_weights w ON w.metric='call_followup'
            GROUP BY sub.lead_id -- Ensure unique score per lead for this metric

            UNION ALL

            -- [9] agent_dispo
            SELECT cdh.lead_id,
                MAX(w.weight_percent * lb.score_factor)
            FROM mmi_agent_disposition_field_response adfr
            JOIN mmi_call_disposition_history cdh ON cdh.id=adfr.response_id
            JOIN mmi_lead_categorization_weights w ON w.metric='agent_dispo'
            -- Dynamically determine the label_key based on field_value
            JOIN mmi_lead_categorize_labels lb ON lb.label_key = (
                CASE
                    WHEN adfr.field_value IN ('Ready to Pay','Interested') THEN 'HOT'
                    WHEN adfr.field_value IN ('Shared Quotes','Awaiting Documents') THEN 'WARM'
                    ELSE 'COLD'
                END
            )
            GROUP BY cdh.lead_id -- Ensure unique score per lead for this metric

            UNION ALL

            -- [10] quote
            SELECT cdh.lead_id,
                MAX(w.weight_percent * lb.score_factor)
            FROM mmi_agent_disposition_field_response adfr
            JOIN mmi_call_disposition_history cdh ON cdh.id=adfr.response_id
            JOIN mmi_lead_categorization_weights w ON w.metric='quote'
            -- Dynamically determine the label_key based on field_value
            JOIN mmi_lead_categorize_labels lb ON lb.label_key = (
                CASE
                    WHEN adfr.field_value='Quote / Premium Ok' THEN 'HOT'
                    WHEN adfr.field_value IN ('Shared Quotes','Awaiting Documents') THEN 'WARM'
                    ELSE 'COLD'
                END
            )
            GROUP BY cdh.lead_id -- Ensure unique score per lead for this metric

            UNION ALL

            -- [11] renewal
            SELECT renewal_type.lead_id,
                MAX(w.weight_percent * lb.score_factor) AS weighted_score
            FROM (
                SELECT mld.lead_id,
                    CASE
                        WHEN COUNT(*)>=2 AND MAX(YEAR(epd.policy_effective_date))=YEAR(CURDATE())-1
                            OR MAX(YEAR(esd.invoice_date_time))=YEAR(CURDATE())-1 THEN 'Hot'
                        WHEN COUNT(*)=1 AND MAX(YEAR(epd.policy_effective_date))=YEAR(CURDATE())-1 THEN 'Warm'
                        ELSE 'Cold'
                    END AS renewal_lead_type
                FROM mmi_ebm_policy_data epd
                JOIN mmi_lead_details mld on epd.cluster_id=mld.cluster_id
                LEFT JOIN mmi_mast_customer_details mcd on mcd.cluster_id=mld.cluster_id
                LEFT JOIN mmi_ebm_sales_data esd ON esd.chassis_number=mcd.chassis_no
                GROUP BY mld.lead_id
            ) renewal_type
            JOIN mmi_lead_categorization_weights w ON w.metric='renewal'
            JOIN mmi_lead_categorize_labels lb ON lb.label_value = renewal_type.renewal_lead_type
            GROUP BY renewal_type.lead_id -- Ensure unique score per lead for this metric

        ) AS metric_weighted_subquery
    ) AS metric_weighted ON metric_weighted.lead_id = mld.lead_id
    GROUP BY mld.lead_id, mld.cluster_id;

 END ;;
DELIMITER ;
