DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_dynamic_weighted_leads1`()
BEGIN
    DECLARE total_weight INT;
    DECLARE priority_fields TEXT;

    -- 1. Validate total weights
    SELECT SUM(weight_percent) INTO total_weight
    FROM mmi_lead_categorization_weights;

    IF total_weight IS NULL OR total_weight != 100 THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Total weight of all metrics must be exactly 100%';
    END IF;

    -- 2. Get all priority field names dynamically
    SELECT GROUP_CONCAT(field_name) INTO priority_fields
    FROM mmi_lead_categorization_weights
    WHERE is_priority = 1;

    -- 3. Temp table for category scores
    CREATE TEMPORARY TABLE IF NOT EXISTS temp_lead_category_scores (
        lead_id INT PRIMARY KEY,
        hot_score_sum DECIMAL(10, 2) DEFAULT 0,
        warm_score_sum DECIMAL(10, 2) DEFAULT 0,
        cold_score_sum DECIMAL(10, 2) DEFAULT 0
    );

    -- 4. Populate category scores
    INSERT INTO temp_lead_category_scores (lead_id, hot_score_sum, warm_score_sum, cold_score_sum)
    SELECT
        mld.lead_id,
        COALESCE(SUM(CASE WHEN all_metric_contributions.label_key = 'HOT' THEN all_metric_contributions.weighted_score ELSE 0 END), 0) AS hot_score_sum,
        COALESCE(SUM(CASE WHEN all_metric_contributions.label_key = 'WARM' THEN all_metric_contributions.weighted_score ELSE 0 END), 0) AS warm_score_sum,
        COALESCE(SUM(CASE WHEN all_metric_contributions.label_key = 'COLD' THEN all_metric_contributions.weighted_score ELSE 0 END), 0) AS cold_score_sum
    FROM mmi_lead_details mld
    LEFT JOIN (
        SELECT * FROM mmi_vw_fetch_lead_categorize_details
    ) AS all_metric_contributions 
        ON mld.lead_id = all_metric_contributions.lead_id
    GROUP BY mld.lead_id
    ON DUPLICATE KEY UPDATE
        hot_score_sum = VALUES(hot_score_sum),
        warm_score_sum = VALUES(warm_score_sum),
        cold_score_sum = VALUES(cold_score_sum);

    -- 5. Update final category
    -- UPDATE mmi_lead_details mld
    -- LEFT JOIN temp_lead_category_scores tls ON mld.lead_id = tls.lead_id
    -- LEFT JOIN (
        SELECT lead_id,
               CASE
                   -- Priority check: any priority field is 'Hot'
                   WHEN (
                       SELECT COUNT(*) 
                       FROM mmi_lead_categorization_weights w
                       WHERE w.is_priority = 1
                         AND (CASE w.field_name
                                 WHEN 'renewal_due_date_logic' THEN mld.renewal_due_date_logic
                                 WHEN 'policy_lapse_logic' THEN mld.policy_lapse_logic
                                 WHEN 'customer_readiness_to_buy_logic' THEN mld.customer_readiness_to_buy_logic
                                 WHEN 'customer_life_cycle_logic' THEN mld.customer_life_cycle_logic
                              END) = 'Hot'
                   ) > 0
                   THEN 'Hot'

                   -- Otherwise follow mapping table
                   ELSE (
                       SELECT final_cat
                       FROM mmi_category_matrix m
                       WHERE m.weightage_cat = CASE
                           WHEN tls.hot_score_sum >= tls.warm_score_sum 
                                AND tls.hot_score_sum >= tls.cold_score_sum THEN 'Hot'
                           WHEN tls.warm_score_sum > tls.hot_score_sum 
                                AND tls.warm_score_sum >= tls.cold_score_sum THEN 'Warm'
                           ELSE 'Cold'
                       END
                       AND m.individual_cat = CASE
                           WHEN tls.hot_score_sum >= tls.warm_score_sum 
                                AND tls.hot_score_sum >= tls.cold_score_sum THEN 'Hot'
                           WHEN tls.warm_score_sum > tls.hot_score_sum 
                                AND tls.warm_score_sum >= tls.cold_score_sum THEN 'Warm'
                           ELSE 'Cold'
                       END
                       LIMIT 1
                   )
               END AS final_category
        FROM mmi_lead_details mld
        LEFT JOIN temp_lead_category_scores tls2 ON mld.lead_id = tls2.lead_id;
    -- ) cat_map ON mld.lead_id = cat_map.lead_id
    -- SET mld.lead_type = cat_map.final_category;

    -- 6. Drop temp table
    DROP TEMPORARY TABLE IF EXISTS temp_lead_category_scores;
END ;;
DELIMITER ;
