CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_dynamic_weighted_leads2`()
BEGIN
  DECLARE total_weight INT;

  
  SELECT SUM(weight_percent) INTO total_weight
  FROM mmi_lead_categorization_weights;

  IF total_weight IS NULL OR total_weight != 100 THEN
    SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'Total weight of all metrics must be 100%';
  END IF;

  
  DROP TEMPORARY TABLE IF EXISTS temp_lead_category_scores;
  CREATE TEMPORARY TABLE temp_lead_category_scores (
    lead_id INT PRIMARY KEY,
    hot_score_sum DECIMAL(10,2) DEFAULT 0,
    warm_score_sum DECIMAL(10,2) DEFAULT 0,
    cold_score_sum DECIMAL(10,2) DEFAULT 0,
    tScore DECIMAL(10,2) DEFAULT 0
  );

  
  INSERT INTO temp_lead_category_scores (lead_id, hot_score_sum, warm_score_sum, cold_score_sum, tScore)
  SELECT
    mld.lead_id,
    COALESCE(SUM(CASE WHEN cd.label_key = 'HOT' THEN cd.weighted_score ELSE 0 END), 0) AS hot_score_sum,
