    COALESCE(SUM(CASE WHEN cd.label_key = 'COLD' THEN cd.weighted_score ELSE 0 END), 0) AS cold_score_sum,
    COALESCE(SUM(cd.weighted_score), 0) AS tScore
  FROM mmi_lead_details mld
  LEFT JOIN mmi_vw_fetch_final_lead_categorize_details_complete cd USING (lead_id)
  GROUP BY mld.lead_id;

  
  DROP TEMPORARY TABLE IF EXISTS temp_lead_final_category;
