INSERT INTO temp_lead_final_category (lead_id, final_category)
SELECT
  mld.lead_id,
  CASE
    -- Priority HOT override
    WHEN EXISTS (
      SELECT 1
      FROM mmi_vw_fetch_final_lead_categorize_details_complete cd2
      JOIN mmi_lead_categorization_weights w ON cd2.metric = w.metric
      WHERE w.is_priority = 1
        AND cd2.label_key = 'HOT'
        AND cd2.lead_id = mld.lead_id
    ) THEN 'Hot'

    -- Matrix-based logic
    WHEN EXISTS (
      SELECT 1
      FROM mmi_vw_fetch_final_lead_categorize_details_complete cd2
      JOIN mmi_lead_categorization_weights w ON cd2.metric = w.metric
      WHERE w.is_priority = 1
        AND cd2.lead_id = mld.lead_id
    ) THEN (
      SELECT mcm.final_cat
      FROM mmi_lead_category_matrix mcm
      WHERE mcm.weightage_cat = (
        CASE
          -- WHEN tls.hot_score_sum >= tls.warm_score_sum AND tls.hot_score_sum >= tls.cold_score_sum THEN 'Hot'
          -- WHEN tls.warm_score_sum > tls.hot_score_sum AND tls.warm_score_sum >= tls.cold_score_sum THEN 'Warm'
          -- ELSE 'Cold'
          WHEN tls.tScore > 75 THEN 'Hot'
		  WHEN tls.tScore BETWEEN 51 AND 75 THEN 'Warm'
		  ELSE 'Cold'
        END
      )
      AND mcm.individual_cat = (
        SELECT cd2.label_key
        FROM mmi_vw_fetch_final_lead_categorize_details_complete cd2
        JOIN mmi_lead_categorization_weights w ON cd2.metric = w.metric
        WHERE w.is_priority = 1 AND cd2.lead_id = mld.lead_id
        ORDER BY
          CASE cd2.label_key
            WHEN 'HOT' THEN 1
            WHEN 'WARM' THEN 2
            WHEN 'COLD' THEN 3
            ELSE 4
          END
        LIMIT 1
      )
      LIMIT 1
    )

    -- Score-based fallback
    WHEN tls.tScore > 75 THEN 'Hot'
    WHEN tls.tScore BETWEEN 51 AND 75 THEN 'Warm'
    ELSE 'Cold'
  END AS final_category
FROM mmi_lead_details mld
JOIN temp_lead_category_scores tls USING (lead_id);
  

UPDATE mmi_lead_details mld
JOIN temp_lead_category_scores tls ON mld.lead_id = tls.lead_id
JOIN temp_lead_final_category tfc ON mld.lead_id = tfc.lead_id
SET 
    mld.lead_type = tfc.final_category,
    mld.lead_type_score = tls.tScore;

  
  SELECT 
    tls.lead_id,
    tls.hot_score_sum,
    tls.warm_score_sum,
    tls.cold_score_sum,
    tls.tScore,
    tfc.final_category AS final_lead_type
  FROM temp_lead_category_scores tls
  JOIN temp_lead_final_category tfc USING (lead_id)
  ORDER BY tls.tScore DESC; 

  
  DROP TEMPORARY TABLE IF EXISTS temp_lead_category_scores;
  DROP TEMPORARY TABLE IF EXISTS temp_lead_final_category;
END ;;
