DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_ebm_proposal_communication_template`(
    IN p_json_data JSON,
    OUT p_status VARCHAR(500),
    OUT p_message VARCHAR(500)
)
BEGIN
    DECLARE v_lead_id VARCHAR(50);
    DECLARE v_dealer_code VARCHAR(500);
    DECLARE v_parent_code VARCHAR(50);
    DECLARE v_proposal_status VARCHAR(100);
    DECLARE v_cluster_id VARCHAR(100);
    DECLARE v_customer_name VARCHAR(255);
    DECLARE v_mobile_no VARCHAR(20);
    DECLARE v_email VARCHAR(255);
    DECLARE v_vehicle_reg_no VARCHAR(100);
    DECLARE v_chassis_no VARCHAR(100);
    DECLARE v_ebm_status_color VARCHAR(20);
    
    DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        SET p_status = '500';
        SET p_message = 'An error occurred. Please try again.';
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_ebm_proposal_communication_template', 'EBM_PROPOSAL_COMMUNICATION', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        ); 
    END;
    
    -- Extract JSON parameters
    SET v_lead_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.leadId'));
    SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerCode'));
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode'));
    
    -- Validate required parameters
    IF v_lead_id IS NULL OR v_lead_id = '' THEN
        SET p_status = '400';
        SET p_message = 'Lead ID is required';
    ELSE
        -- Step 1: Get customer and EBM details from lead
        SELECT 
            mld.cluster_id,
            mcd.customer_name,
            mcd.customer_phone,
            mcd.customer_email,
            mcd.vehicle_reg_no,
            mcd.chassis_no,
            COALESCE(ebm.proposal_status, 'N/A') AS ebm_status,
            CASE 
                WHEN ebm.proposal_status IS NULL THEN '#FFFFFF'
                WHEN ebm.proposal_status = 'PENDING' THEN '#3498DB'
                WHEN ebm.proposal_status = 'IN_PROGRESS' THEN '#9B59B6'
                WHEN ebm.proposal_status = 'OK' THEN '#2ECC71'
                WHEN ebm.proposal_status = 'NEED_TO_CHECK' THEN '#E74C3C'
                ELSE '#FFFFFF'
            END AS status_color
        INTO 
            v_cluster_id,
            v_customer_name,
            v_mobile_no,
            v_email,
            v_vehicle_reg_no,
            v_chassis_no,
            v_proposal_status,
            v_ebm_status_color
        FROM mmi_lead_details mld
        LEFT JOIN LATERAL (
            SELECT cluster_id, MIN(customer_name) AS customer_name, 
                   MIN(customer_phone) AS customer_phone, 
                   MIN(customer_email) AS customer_email,
                   MIN(vehicle_reg_no) AS vehicle_reg_no,
                   MIN(chassis_no) AS chassis_no
            FROM mmi_mast_customer_details cd 
            WHERE mld.vin = cd.chassis_no and mld.engine_no = cd.engine_no
            GROUP BY cluster_id LIMIT 1
        ) mcd ON TRUE
        LEFT JOIN (
            SELECT e1.* FROM mmi_crm_ebm_transaction_details e1
            LEFT JOIN mmi_crm_ebm_transaction_details e2 
            ON e1.lead_id = e2.lead_id AND e1.created_date < e2.created_date
            WHERE e2.id IS NULL
        ) ebm ON ebm.lead_id = mld.lead_id
        WHERE mld.lead_id = v_lead_id
        LIMIT 1;
        
        IF v_cluster_id IS NULL THEN
            SET p_status = '404';
            SET p_message = 'Lead not found';
        ELSE
            -- Step 2: Check if we have proposal status history, otherwise use EBM status
            IF v_proposal_status IS NULL OR v_proposal_status = 'N/A' THEN
                -- Fallback to proposal status history
                SELECT proposal_status INTO v_proposal_status
                FROM mmi_proposal_status_history
                WHERE lead_id = v_lead_id
                ORDER BY created_date DESC
                LIMIT 1;
                
                IF v_proposal_status IS NULL THEN
                    SET p_status = '404';
                    SET p_message = 'No proposal status found for this lead';
                ELSE
                    SET p_status = '200';
                    SET p_message = CONCAT('Using proposal status: ', v_proposal_status);
                END IF;
            ELSE
                SET p_status = '200';
                SET p_message = CONCAT('Using EBM status: ', v_proposal_status);
            END IF;
            
            -- Only proceed if we have a status
            IF p_status = '200' THEN
                -- Step 3: Get communication channels that:
                -- a) Have templates for this EBM/proposal status
                -- b) Are supported by the dealer
                -- c) Customer has not opted out (if preference tracking exists)
                
                -- First, check what communication channels the dealer supports
                IF EXISTS (SELECT 1 FROM mmi_dealer_details 
                          WHERE dealer_id = v_dealer_code 
                          AND parent_code = v_parent_code
                          AND communication IS NOT NULL 
                          AND communication != '') THEN
                    
                    -- Return 3 result sets for different communication types
                    
                    -- Result Set 1: Available communication channels (like in mmi_proc_get_disposition_by_flag)
                    SELECT DISTINCT 
                        dtm.communication_type,
                        dtm.template_id,
                        CASE 
                            WHEN dtm.communication_type = 'Email' THEN 'Email Template Available'
                            WHEN dtm.communication_type = 'SMS' THEN 'SMS Template Available'
                            WHEN dtm.communication_type = 'WhatsApp' THEN 'WhatsApp Template Available'
                            ELSE dtm.communication_type
                        END AS template_description,
                        -- Check if dealer supports this communication type
                        CASE 
                            WHEN FIND_IN_SET(dtm.communication_type, dd.communication) > 0 THEN 1
                            ELSE 0
                        END AS dealer_supports,
                        -- Customer preference (if tracking exists)
                        IFNULL(ccp.is_active, 1) AS customer_opted_in
                    FROM mmi_ebm_template_master dtm
                    LEFT JOIN mmi_dealer_details dd ON 
                        dd.dealer_id = v_dealer_code
                        AND dd.parent_code = v_parent_code
                        AND FIND_IN_SET(dtm.communication_type, dd.communication) > 0
                    LEFT JOIN mmi_customer_communication_preferences ccp ON 
                        ccp.cluster_id = v_cluster_id
                        AND ccp.communication_type = dtm.communication_type
                    WHERE dtm.ebm_status = v_proposal_status
                        AND dtm.is_active = 1
                        AND FIND_IN_SET(dtm.communication_type, dd.communication) > 0
                        AND (ccp.communication_type IS NULL OR ccp.is_active = 1)
                    ORDER BY 
                        CASE dtm.communication_type 
                            WHEN 'Email' THEN 1
                            WHEN 'SMS' THEN 2
                            WHEN 'WhatsApp' THEN 3
                            ELSE 4
                        END;
                    
                    -- Result Set 2: Template placeholders for each communication type (like in mmi_proc_fetch_customer_details_for_communication)
                    -- For Email
                    SELECT 
                        v_customer_name AS `Customer Name`,
                        v_mobile_no AS `Mobile Number`,
                        v_email AS `Email Address`,
                        v_vehicle_reg_no AS `Vehicle Number`,
                        v_proposal_status AS `EBM Status`,
                        v_ebm_status_color AS `Status Color`,
                        DATE_FORMAT(NOW(), '%Y-%m-%d') AS `Date`,
                        'Email' AS `Communication Type`
                    FROM dual
                    WHERE EXISTS (SELECT 1 FROM mmi_ebm_template_master 
                                 WHERE ebm_status = v_proposal_status 
                                 AND communication_type = 'Email'
                                 AND is_active = 1);
                    
                    -- For SMS
                    SELECT 
                        v_customer_name AS `Customer Name`,
                        v_mobile_no AS `Mobile Number`,
                        v_vehicle_reg_no AS `Vehicle Number`,
                        v_proposal_status AS `EBM Status`,
                        DATE_FORMAT(NOW(), '%d/%m/%Y') AS `Date`,
                        'SMS' AS `Communication Type`
                    FROM dual
                    WHERE EXISTS (SELECT 1 FROM mmi_ebm_template_master 
                                 WHERE ebm_status = v_proposal_status 
                                 AND communication_type = 'SMS'
                                 AND is_active = 1);
                    
                    -- For WhatsApp
                    SELECT 
                        v_customer_name AS `1`,
                        v_vehicle_reg_no AS `2`,
                        v_proposal_status AS `3`,
                        DATE_FORMAT(NOW(), '%d/%m/%Y') AS `4`,
                        'WhatsApp' AS `Communication Type`
                    FROM dual
                    WHERE EXISTS (SELECT 1 FROM mmi_ebm_template_master 
                                 WHERE ebm_status = v_proposal_status 
                                 AND communication_type = 'WhatsApp'
                                 AND is_active = 1);
                    
                    -- Result Set 3: Actual template bodies
                    SELECT 
    dtm.communication_type,
    dtm.template_body,
    dtm.template_subject,
    dtm.template_id,
    CONCAT('{{customer_name}},',
            '{{mobile_no}},',
            '{{vehicle_no}},',
            '{{ebm_status}},',
            '{{date}}') AS placeholders,
    dtm.priority_order,
    dtm.created_date,
    dtm.created_by
FROM
    mmi_ebm_template_master dtm
        LEFT JOIN
    mmi_dealer_details dd ON dd.dealer_id = v_dealer_code
        AND dd.parent_code = v_parent_code
        AND FIND_IN_SET(dtm.communication_type, dd.communication) > 0
WHERE
    dtm.ebm_status = v_proposal_status
        AND dtm.is_active = 1
        AND FIND_IN_SET(dtm.communication_type, dd.communication) > 0
ORDER BY dtm.priority_order ASC;
                    
                ELSE
                    -- Dealer not found or no communication channels configured
                    SELECT 
                        'No communication channels configured for this dealer' AS error_message,
                        v_dealer_code AS dealer_id,
                        v_parent_code AS parent_code
                    FROM dual;
                    
                    SET p_status = '404';
                    SET p_message = 'Dealer communication channels not configured';
                END IF;
            END IF;
        END IF;
    END IF;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_get_ebm_proposal_status_history` */;
