DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_ebm_proposal_status_history`(
    IN p_json_data JSON,
    OUT p_status_code VARCHAR(500),
    OUT p_status_message VARCHAR(500)
)
BEGIN
    DECLARE v_lead_id INT;
    DECLARE v_policy_no VARCHAR(200);
    -- DECLARE v_comm_type VARCHAR(50);
	-- DECLARE v_template_body LONGTEXT;
    DECLARE v_renewal_link_modify VARCHAR(500);
    DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;


DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code,
            error_message,
            procedure_name,
            procedure_type,
            error_timing,
            created_by,
            created_date
        ) VALUES (
            err_code,
            err_msg,
            'mmi_proc_get_ebm_proposal_status_history',
            'EBM_PROPOSAL_DATA',
            NOW(),
            'SYSTEM',
            NOW()
        );
    END;

    SET v_lead_id = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.leadId')) AS UNSIGNED);
    SET v_policy_no = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.policyNo'));
    -- SET v_comm_type = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.communicationType'));


    IF v_lead_id IS NULL AND v_policy_no IS NULL THEN
        SET p_status_code = '400';
        SET p_status_message = 'Invalid input parameters. Either leadId or policyNo is required';
    ELSE
        -- get the renewal_link_modify from the latest transaction details
        -- TODO: TO CHANGE: change the table to the history table -need confirmation
       /* SELECT renewal_link_modify INTO v_renewal_link_modify
        FROM mmi_crm_ebm_transaction_details
		-- From mmi_crm_ebm_transaction_log
        WHERE (v_lead_id IS NOT NULL AND lead_id = v_lead_id)
           OR (v_policy_no IS NOT NULL AND policy_no = v_policy_no)
        ORDER BY created_date DESC
        LIMIT 1; */
        
        SELECT renewal_link_modify
		INTO v_renewal_link_modify
		FROM (
			SELECT renewal_link_modify,
			ROW_NUMBER() OVER (ORDER BY created_date DESC) AS rn
			FROM mmi_ebm_proposal_history
			WHERE (v_lead_id IS NOT NULL AND lead_id = v_lead_id)
			OR (v_policy_no IS NOT NULL AND policy_no = v_policy_no)) t
		WHERE rn = 1;
        
       /* IF v_comm_type IS NOT NULL THEN
		SELECT template_body
		INTO v_template_body
		FROM mmi_emb_template_master
		WHERE communication_type = v_comm_type
		AND is_active = 1
		ORDER BY id DESC
		-- LIMIT 1;
		-- END IF; */

        
        -- Single result set with all history records, using modify link from transaction details
        SELECT 
    psh.id,
    psh.lead_id,
    NULL AS crm_transaction_token_no,
    psh.policy_no,
    psh.proposal_no,
    psh.proposal_status,
    v_renewal_link_modify AS renewal_link_modify,
    psh.renewal_link_read_only,
    psh.proposal_timestamp,
    psh.ebm_action_user_id AS ebm_user_id,
    psh.crm_token,
    psh.created_by,
    psh.created_date,
    NULL AS ebm_transaction_token_no,
    NULL AS ebm_token_expiry_time,
    COALESCE(ems.ebm_status_color, '#000000') AS ebm_status_color,
    CASE WHEN psh.proposal_status IS NULL THEN 'N/A' ELSE psh.proposal_status END AS status_display,
    DATE_FORMAT(psh.proposal_timestamp, '%Y-%m-%d %H:%i') AS formatted_timestamp,
    'History' AS record_type,
    ROW_NUMBER() OVER (ORDER BY psh.created_date DESC) AS display_order

   /* v_comm_type AS communication_type,
    v_template_body AS template_body */

FROM mmi_proposal_status_history psh
LEFT JOIN mmi_mast_ebm_status ems ON ems.sub_ebm_status = psh.proposal_status
WHERE (v_lead_id IS NOT NULL AND psh.lead_id = v_lead_id)
   OR (v_policy_no IS NOT NULL AND psh.policy_no = v_policy_no)
ORDER BY psh.created_date DESC;


        SET p_status_code = '200';
        SET p_status_message = 'EBM transaction history fetched successfully';
    END IF;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
