DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_ebm_templates_by_communication`(
    IN p_json_data JSON,
    OUT p_status_code VARCHAR(100),
    OUT p_status_message VARCHAR(255)
)
BEGIN
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        SET p_status_code = '500';
        SET p_status_message = CONCAT('Error: ', err_msg);

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg,
            'mmi_proc_get_templates_by_communication',
            'TEMPLATE_FETCH', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;


    IF JSON_EXTRACT(p_json_data, '$.communicationType') IS NULL THEN
        SET p_status_code = '400';
        SET p_status_message = 'communicationType is required';
    ELSE

        SELECT 
            id,
            lead_id,
            template_id,
            communication_type,
            template_subject,
            template_body,
            created_date
        FROM mmi_emb_template_master
        WHERE is_active = 1
          AND JSON_CONTAINS(
                JSON_EXTRACT(p_json_data, '$.communicationType'),
                JSON_QUOTE(communication_type)
              )
        ORDER BY communication_type, id DESC;

        SET p_status_code = '200';
        SET p_status_message = 'Templates fetched successfully';
    END IF;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
