CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_expiring_pass_users`(
    OUT o_status_code INT,
    OUT o_status_message VARCHAR(255)
)
BEGIN
    DECLARE v_expiry_days INT DEFAULT 60;

    -- Error handler for exceptions
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        SET o_status_code = 500;
        SET o_status_message = 'Error occurred in procedure mmi_proc_get_expiring_pass_users';
    END;

    -- Get password expiry interval (in days) from mmi_services_config
    SELECT CAST(services_value AS UNSIGNED)
    INTO v_expiry_days
    FROM mmi_services_config
    WHERE services_property = 'password_expiry_days';

    -- Select users whose passwords will expire in the given range
    SELECT 
        email_id, 
        DATEDIFF(DATE_ADD(pass_set_date, INTERVAL v_expiry_days DAY), CURDATE()) AS remaining_days
    FROM mmi_mast_user
    WHERE 
        is_lock = 'U' 
        AND status = '1'
        AND DATEDIFF(DATE_ADD(pass_set_date, INTERVAL v_expiry_days DAY), CURDATE()) IN (10, 5, 3, 2, 1);

    SET o_status_code = 200;
    SET o_status_message = 'Fetched expiring password users successfully';
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
