CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_filtered_data_by_supervisor`(
	IN p_supervisorId VARCHAR(50),
    OUT p_status_code VARCHAR(500),
    OUT p_status_message VARCHAR(500)
)
BEGIN
	DECLARE err_code INT;
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_filtered_data_by_supervisor', 'FilterDataSupervisor', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    IF p_supervisorId IS NULL OR p_supervisorId = '' THEN
            SET p_status_code = '300';
            SET p_status_message = 'supervisorId is missing';
    ELSE        
	SELECT customerName,leadId,model,agentName,renewal_category,expiry_date,recentupdates,next_status 
			FROM mmi_get_caller_details_by_manager WHERE supervisor_id = p_supervisorId LIMIT 1;
		SET p_status_code = '200';
		SET p_status_message = 'Success';   
    END IF;        
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
