CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_filtered_data_by_supervisor1`(
    IN p_supervisorId VARCHAR(50),
    OUT p_status_code VARCHAR(500),
    OUT p_status_message VARCHAR(500),
    OUT p_supervisor_data JSON
)
BEGIN
    DECLARE err_code INT;
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT; 
        
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_filtered_data_by_supervisor', 'FilterDataSupervisor', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

        SET p_supervisor_data = JSON_OBJECT('error', 'An error occurred. Please try again.');
    END;
        
    -- Get the filtered data by supervisor
   /* SELECT JSON_ARRAYAGG(
        JSON_OBJECT(
            'customerName', customerName,
            'leadId', leadId,
            'model', model,
            'agentName', agentName,
            'renewal_category', renewal_category,
            'expiry_date', expiry_date,
            'recentupdates', recentupdates,
            'next_status', next_status
        )
    ) INTO p_supervisor_data
    FROM mmi_get_caller_details_by_manager
    WHERE supervisor_id = p_supervisorId LIMIT 1;*/
    -- SELECT JSON_OBJECT('customerName', customerName)  INTO p_supervisor_data 
    -- FROM mmi_get_caller_details_by_manager
    -- WHERE supervisor_id = p_supervisorId LIMIT 1; 
    -- select JSON_ARRAY(
       -- CONCAT_WS('userId', user_id)) INTO p_supervisor_data
    -- JSON_OBJECT('userId', user_id) INTO p_supervisor_data
    -- from mmi_user_reporting where supervisor_id = p_supervisorId LIMIT 1;
    
    
    WITH RECURSIVE subordinates AS
            (
            SELECT ur.user_id
            FROM mmi_user_reporting ur where ur.supervisor_id = p_supervisorId
            UNION ALL
            SELECT ur.user_id
            FROM mmi_user_reporting ur
            INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
            )

            SELECT DISTINCT
            JSON_ARRAY(
			CONCAT_WS('userId', urd.id)) INTO p_supervisor_data
            FROM subordinates s
            LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = s.user_id
            LEFT JOIN mmi_user_dealer_mapping urm on s.user_id = urm.user_id
            LEFT JOIN mmi_dealer_details mdl on mdl.dealer_id = urm.dealer_id
            WHERE urd.id is not null
            and urd.id <> p_supervisorId LIMIT 1;
    
    SET p_status_code = '200';
    SET p_status_message = 'Success';
    
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_get_filtered_leads` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_filtered_leads`(
    IN p_filters_json JSON
)
BEGIN
    DECLARE v_userId VARCHAR(100);
    DECLARE v_type VARCHAR(100);
    DECLARE v_status_type VARCHAR(45);
    DECLARE v_limit INT DEFAULT 10;
    DECLARE v_offset INT DEFAULT 0;
    DECLARE v_sortField VARCHAR(45);
    DECLARE v_sortOrder VARCHAR(45);
    DECLARE calculated INT DEFAULT 0;

    DECLARE v_has_recent_updates BOOL DEFAULT FALSE;
    DECLARE v_has_status BOOL DEFAULT FALSE;
    DECLARE v_has_lead BOOL DEFAULT FALSE;
    DECLARE v_renewal_count INT DEFAULT 0;
    -- DECLARE v_expiry_days INT DEFAULT NULL;
    DECLARE v_expiry_date_from DATE DEFAULT NULL;
    DECLARE v_expiry_date_to DATE DEFAULT NULL;
    DECLARE v_has_ebm_status BOOL DEFAULT FALSE; -- herek

    DECLARE err_code INT;
    DECLARE err_msg TEXT;
	DECLARE v_sort_col INT DEFAULT 1;
	DECLARE v_sort_dir INT DEFAULT 1;

    -- Error handler
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
        ROLLBACK;
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_filtered_leads', v_type, CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    START TRANSACTION;

    -- Extract inputs
    SET v_userId = JSON_UNQUOTE(JSON_EXTRACT(p_filters_json, '$.userId'));
    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(p_filters_json, '$.type'));
    SET v_status_type = JSON_UNQUOTE(JSON_EXTRACT(p_filters_json, '$.callQueType'));
    -- SET v_limit = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_filters_json, '$.limit')) AS UNSIGNED), 10);
    -- SET v_offset = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_filters_json, '$.offset')) AS UNSIGNED), 0);
    SET v_sortField = JSON_UNQUOTE(JSON_EXTRACT(p_filters_json, '$.sortField'));
    SET v_sortOrder = JSON_UNQUOTE(JSON_EXTRACT(p_filters_json, '$.sortOrder'));

    IF v_sortField IS NULL OR v_sortField = '' THEN
        SET v_sortField = 'expiryDays';
    END IF;
    IF v_sortOrder IS NULL OR v_sortOrder = '' THEN
        SET v_sortOrder = 'asc';
    END IF;
    
	SET v_sort_col =
		CASE v_sortField
			WHEN 'expiryDays'   THEN 1
			WHEN 'customerName' THEN 2
			WHEN 'status'       THEN 3
			ELSE 1
		END;

	SET v_sort_dir = IF(LOWER(v_sortOrder) = 'desc', -1, 1);
    
    -- SET calculated = v_offset;

    -- Temporary tables for filter values
    DROP TEMPORARY TABLE IF EXISTS tmp_renewal_category;
    DROP TEMPORARY TABLE IF EXISTS tmp_recent_updates;
    DROP TEMPORARY TABLE IF EXISTS tmp_status;
    DROP TEMPORARY TABLE IF EXISTS tmp_lead;
    DROP TEMPORARY TABLE IF EXISTS tmp_ebm_status;

    CREATE TEMPORARY TABLE tmp_renewal_category(val VARCHAR(100));
    CREATE TEMPORARY TABLE tmp_recent_updates(val VARCHAR(100));
    CREATE TEMPORARY TABLE tmp_status(val VARCHAR(100));
    CREATE TEMPORARY TABLE tmp_lead(val VARCHAR(100));
    CREATE TEMPORARY TABLE tmp_ebm_status(val VARCHAR(100));

    INSERT INTO tmp_renewal_category(val)
    SELECT jt.filterValue
    FROM JSON_TABLE(
        JSON_EXTRACT(p_filters_json, '$.saveLeadFilters'),
        '$[*]' COLUMNS (
          filterType VARCHAR(100) PATH '$.filterType',
          filterValue VARCHAR(100) PATH '$.filterValue'
        )
    ) jt
    WHERE jt.filterType = 'Renewal Category';

    INSERT INTO tmp_recent_updates(val)
    SELECT jt.filterValue
    FROM JSON_TABLE(
        JSON_EXTRACT(p_filters_json, '$.saveLeadFilters'),
        '$[*]' COLUMNS (
          filterType VARCHAR(100) PATH '$.filterType',
          filterValue VARCHAR(100) PATH '$.filterValue'
        )
    ) jt
    WHERE jt.filterType = 'Recent Updates';

    INSERT INTO tmp_status(val)
    SELECT jt.filterValue
    FROM JSON_TABLE(
        JSON_EXTRACT(p_filters_json, '$.saveLeadFilters'),
        '$[*]' COLUMNS (
          filterType VARCHAR(100) PATH '$.filterType',
          filterValue VARCHAR(100) PATH '$.filterValue'
        )
    ) jt
    WHERE jt.filterType = 'Status';

    INSERT INTO tmp_lead(val)
    SELECT jt.filterValue
    FROM JSON_TABLE(
        JSON_EXTRACT(p_filters_json, '$.saveLeadFilters'),
        '$[*]' COLUMNS (
          filterType VARCHAR(100) PATH '$.filterType',
          filterValue VARCHAR(100) PATH '$.filterValue'
        )
    ) jt
    WHERE jt.filterType = 'Lead';
    
    -- herek - EBM Filter
    INSERT INTO tmp_ebm_status(val)
	SELECT jt.filterValue
	FROM JSON_TABLE(
        JSON_EXTRACT(p_filters_json, '$.saveLeadFilters'),
        '$[*]' COLUMNS (
            filterType VARCHAR(100) PATH '$.filterType',
            filterValue VARCHAR(100) PATH '$.filterValue'
        )
    ) jt
	WHERE jt.filterType = 'EBM'; -- Changed from 'EBM Status' to 'EBM'
    
	COMMIT;
    
    SELECT EXISTS (SELECT 1 FROM tmp_recent_updates) INTO v_has_recent_updates;
    SELECT EXISTS (SELECT 1 FROM tmp_status) INTO v_has_status;
    SELECT EXISTS (SELECT 1 FROM tmp_lead) INTO v_has_lead;
    SELECT COUNT(*) INTO v_renewal_count FROM tmp_renewal_category;
    SELECT EXISTS (SELECT 1 FROM tmp_ebm_status) INTO v_has_ebm_status; -- herek

    
    SELECT MAX(CAST(jt.filterValue AS DATE)) INTO v_expiry_date_from
    FROM JSON_TABLE(
        JSON_EXTRACT(p_filters_json, '$.saveLeadFilters'),
        '$[*]' COLUMNS (
          filterType VARCHAR(100) PATH '$.filterType',
          filterValue VARCHAR(100) PATH '$.filterValue'
        )
    ) jt
    WHERE jt.filterType = 'Expiry Date From';

    SELECT MAX(CAST(jt.filterValue AS DATE)) INTO v_expiry_date_to
    FROM JSON_TABLE(
        JSON_EXTRACT(p_filters_json, '$.saveLeadFilters'),
        '$[*]' COLUMNS (
          filterType VARCHAR(100) PATH '$.filterType',
          filterValue VARCHAR(100) PATH '$.filterValue'
        )
    ) jt
    WHERE jt.filterType = 'Expiry Date To';

	SET v_limit = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_filters_json, '$.limit')) AS UNSIGNED), 10);
    SET v_offset = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_filters_json, '$.offset')) AS UNSIGNED), 0);
    SET calculated = (v_offset - 1) * v_limit;

    -- Caller branch
    IF v_type = 'caller' THEN
		IF v_status_type = 'current' THEN
        -- Fetch data + count for caller
        WITH dispo_counts AS (
            SELECT lead_id, COUNT(*) AS dispo_count
            FROM mmi_call_disposition_history
            GROUP BY lead_id
        ),
        latest_dispositions AS (
            SELECT h1.*
            FROM mmi_call_disposition_history h1
            LEFT JOIN mmi_call_disposition_history h2
              ON h1.lead_id = h2.lead_id AND h1.created_date < h2.created_date
            WHERE h2.id IS NULL
        ),
        -- EBM herek - Add latest EBM status CTE
       latest_ebm_status AS (
    SELECT 
        e1.lead_id,

        COALESCE(
            NULLIF(e1.proposal_status, 'N/A'),

            (
                SELECT psh2.proposal_status
                FROM mmi_proposal_status_history psh2
                WHERE psh2.lead_id = e1.lead_id
                  AND psh2.proposal_status IS NOT NULL
                  AND psh2.proposal_status <> 'N/A'
                ORDER BY psh2.created_date DESC
                LIMIT 1
            ),

            'N/A'
        ) AS proposal_status,

        ems.ebm_status_color

    FROM mmi_crm_ebm_transaction_details e1
    LEFT JOIN mmi_crm_ebm_transaction_details e2 
        ON e1.lead_id = e2.lead_id 
       AND e1.created_date < e2.created_date
    LEFT JOIN mmi_mast_ebm_status ems 
        ON ems.sub_ebm_status = e1.proposal_status
    WHERE e2.id IS NULL
),
        base_data AS (
            SELECT
                cust.customer_name AS customerName,
                ld.lead_id AS leadId,
                ld.lead_type AS leadType,
                ld.model AS vehicleName,
                cust.vehicle_reg_no AS vehicleRegNo,
                CONCAT(u.first_name, ' ', u.last_name) AS agentName,
                DATE_FORMAT(ld.policy_expiry_date, '%Y-%m-%d') AS expiryDate,
                -- ld.expiry_days AS expiryDays,
                CONCAT(
                    lat.call_status, ' | ',
                    DATE_FORMAT(lat.call_date, '%Y-%m-%d %H:%i:%s'), ' \n ',
                    IFNULL(adfr.field_value, ''), ' | ',
                    IFNULL(lat.next_call_datetime, '')
                ) AS recentUpdates,
                CONCAT(
                    IFNULL(adfr.field_value, ''),
                    CASE WHEN dc.dispo_count > 0 THEN CONCAT('(', dc.dispo_count, ')') ELSE '' END
                ) AS status,
                cust.cluster_id AS clusterId,
                lat.next_call_datetime AS call_date_time,
                ld.assigned_agent,
                (CAST(lat.next_call_datetime AS DATE) = CURDATE()) AS is_today_call,
                (CAST(ld.policy_expiry_date AS DATE) = CURDATE()) AS is_today_expiry,
                ld.renewal_category,
                -- EBM herek - Add EBM status and color
                COALESCE(ebm.proposal_status, 'N/A') AS ebmStatus,
                CASE 
                    WHEN ebm.proposal_status IS NULL THEN '#000000'  -- White for no EBM status
                    WHEN ebm.proposal_status = 'PENDING' THEN '#3498DB'  -- Blue for PENDING
                    WHEN ebm.proposal_status = 'IN_PROGRESS' THEN 
                        CASE 
                            WHEN ebm.ebm_status_color = '#9B59B6' THEN '#9B59B6'  -- Purple for specific IN_PROGRESS
                            WHEN ebm.ebm_status_color = '#F39C12' THEN '#F39C12'  -- Orange for other IN_PROGRESS
                            ELSE COALESCE(ebm.ebm_status_color, '#F39C12')  -- Default orange
                        END
                    WHEN ebm.proposal_status = 'OK' THEN '#2ECC71'  -- Green for OK
                    WHEN ebm.proposal_status = 'NEED_TO_CHECK' THEN '#E74C3C'  -- Red for NEED_TO_CHECK
                    ELSE COALESCE(ebm.ebm_status_color, '#000000')  -- Default white
                END AS ebmStatusColor
                FROM mmi_lead_details ld
		 -- LEFT JOIN mmi_mast_customer_details cust
         -- ON cust.cluster_id = ld.cluster_id
            
            LEFT JOIN LATERAL (
                SELECT cluster_id, MIN(customer_name) AS customer_name, MIN(vehicle_reg_no) AS vehicle_reg_no
                FROM mmi_mast_customer_details cd WHERE ld.vin = cd.chassis_no and ld.engine_no = cd.engine_no
                GROUP BY cluster_id LIMIT 1
            ) cust ON TRUE
            LEFT JOIN latest_dispositions lat
              ON lat.lead_id = ld.lead_id
            LEFT JOIN dispo_counts dc
              ON dc.lead_id = ld.lead_id
            LEFT JOIN mmi_agent_disposition_field_response adfr
              ON adfr.response_id = lat.id AND adfr.field_label = 'Sub Disposition'
            LEFT JOIN mmi_mast_user_registration_detail u
              ON u.id = ld.assigned_agent
            LEFT JOIN mmi_user_reporting ur
              ON ur.user_id = u.id
            -- EBM herek - Add LEFT JOIN to EBM status
            LEFT JOIN latest_ebm_status ebm ON ebm.lead_id = ld.lead_id
        )
        SELECT
            filtered.customerName,
            filtered.leadId,
            filtered.leadType,
            filtered.vehicleName,
            filtered.vehicleRegNo,
            filtered.renewal_category AS renewalCategory,
            filtered.expiryDate,
            filtered.recentUpdates,
            filtered.status,
            filtered.clusterId,
            -- filtered.expiryDays,
            -- EBM herek - Include EBM status and color in SELECT
            filtered.ebmStatus,
            filtered.ebmStatusColor
        FROM (
            SELECT *,
                ROW_NUMBER() OVER (
                    PARTITION BY leadId
                    ORDER BY call_date_time DESC, expiryDate ASC  
                ) AS rn
            FROM base_data bd
            WHERE bd.assigned_agent = v_userId
              AND (bd.is_today_call = 1 OR bd.is_today_expiry = 1)
              AND (v_renewal_count = 0 OR bd.renewal_category IN (SELECT val FROM tmp_renewal_category))
              -- AND (v_expiry_days IS NULL OR bd.expiryDays <= v_expiry_days)
              AND (v_expiry_date_from IS NULL OR bd.expiryDate >= v_expiry_date_from)
              AND (v_expiry_date_to IS NULL OR bd.expiryDate <= v_expiry_date_to)
        ) AS filtered
        WHERE filtered.rn = 1
          AND (v_has_recent_updates = FALSE
               OR EXISTS (
                   SELECT 1 FROM tmp_recent_updates r
                   WHERE filtered.recentUpdates LIKE CONCAT('%', r.val, '%')
               ))
          AND (v_has_status = FALSE
               OR EXISTS (
                   SELECT 1 FROM tmp_status s
                   WHERE filtered.status LIKE CONCAT('%', s.val, '%')
               ))
          AND (v_has_lead = FALSE
               OR EXISTS (
                   SELECT 1 FROM tmp_lead l
                   WHERE filtered.leadType LIKE CONCAT('%', l.val, '%')
               ))
          -- EBM Filter condition
          AND (v_has_ebm_status = FALSE
               OR EXISTS (
                   SELECT 1 FROM tmp_ebm_status e
                   WHERE 
                       -- Handle exact matches (case-insensitive)
                       UPPER(TRIM(filtered.ebmStatus)) = UPPER(TRIM(e.val))
                       -- Handle 'Blank' filter
                       OR (UPPER(TRIM(e.val)) = 'BLANK' AND 
                           (filtered.ebmStatus IS NULL OR UPPER(TRIM(filtered.ebmStatus)) IN ('N/A', 'NA', '')))
               ))
               
                 /*ORDER BY
			filtered.expiryDays DESC,
            -- filtered.leadId ASC,
            CASE WHEN v_sortField = 'expiryDays' AND v_sortOrder = 'asc' THEN filtered.expiryDays END ASC,
            CASE WHEN v_sortField = 'expiryDays' AND v_sortOrder = 'desc' THEN filtered.expiryDays END DESC,
            CASE WHEN v_sortField = 'customerName' AND v_sortOrder = 'asc' THEN filtered.customerName END ASC,
            CASE WHEN v_sortField = 'customerName' AND v_sortOrder = 'desc' THEN filtered.customerName END DESC,
            CASE WHEN v_sortField = 'status' AND v_sortOrder = 'asc' THEN filtered.status END ASC,
            CASE WHEN v_sortField = 'status' AND v_sortOrder = 'desc' THEN filtered.status END DESC*/
        ORDER BY
			CASE v_sort_col
				WHEN 1 THEN filtered.expiryDate 
				WHEN 2 THEN filtered.customerName
				WHEN 3 THEN filtered.status
			END * v_sort_dir,
			filtered.leadId
		LIMIT v_limit OFFSET calculated;
  
	ELSE
        WITH dispo_counts AS (
            SELECT lead_id, COUNT(*) AS dispo_count
            FROM mmi_call_disposition_history
            GROUP BY lead_id
        ),
        latest_dispositions AS (
            SELECT h1.*
            FROM mmi_call_disposition_history h1
            LEFT JOIN mmi_call_disposition_history h2
              ON h1.lead_id = h2.lead_id AND h1.created_date < h2.created_date
            WHERE h2.id IS NULL
        ),
        latest_ebm_status AS (
    SELECT 
        e1.lead_id,

        COALESCE(
            NULLIF(e1.proposal_status, 'N/A'),

            (
                SELECT psh2.proposal_status
                FROM mmi_proposal_status_history psh2
                WHERE psh2.lead_id = e1.lead_id
                  AND psh2.proposal_status IS NOT NULL
                  AND psh2.proposal_status <> 'N/A'
                ORDER BY psh2.created_date DESC
                LIMIT 1
            ),

            'N/A'
        ) AS proposal_status,

        ems.ebm_status_color

    FROM mmi_crm_ebm_transaction_details e1
    LEFT JOIN mmi_crm_ebm_transaction_details e2 
        ON e1.lead_id = e2.lead_id 
       AND e1.created_date < e2.created_date
    LEFT JOIN mmi_mast_ebm_status ems 
        ON ems.sub_ebm_status = e1.proposal_status
    WHERE e2.id IS NULL
),
        base_data AS (
            SELECT
                cust.customer_name AS customerName,
                ld.lead_id AS leadId,
                ld.lead_type AS leadType,
                ld.model AS vehicleName,
                cust.vehicle_reg_no AS vehicleRegNo,
                CONCAT(u.first_name, ' ', u.last_name) AS agentName,
                DATE_FORMAT(ld.policy_expiry_date, '%Y-%m-%d') AS expiryDate,
                -- ld.expiry_days AS expiryDays,
                CONCAT(
                    lat.call_status, ' | ',
                    DATE_FORMAT(lat.call_date, '%Y-%m-%d %H:%i:%s'), ' \n ',
                    IFNULL(adfr.field_value, ''), ' | ',
                    IFNULL(lat.next_call_datetime, '')
                ) AS recentUpdates,
                CONCAT(
                    IFNULL(adfr.field_value, ''),
                    CASE WHEN dc.dispo_count > 0 THEN CONCAT('(', dc.dispo_count, ')') ELSE '' END
                ) AS status,
                cust.cluster_id AS clusterId,
                lat.next_call_datetime AS call_date_time,
                ld.assigned_agent,
                (CAST(lat.next_call_datetime AS DATE) = CURDATE()) AS is_today_call,
                (CAST(ld.policy_expiry_date AS DATE) = CURDATE()) AS is_today_expiry,
                ld.renewal_category,
                COALESCE(ebm.proposal_status, 'N/A') AS ebmStatus,
                CASE 
                    WHEN ebm.proposal_status IS NULL THEN '#000000'
                    WHEN ebm.proposal_status = 'PENDING' THEN '#3498DB'
                    WHEN ebm.proposal_status = 'IN_PROGRESS' THEN 
                        CASE 
                            WHEN ebm.ebm_status_color = '#9B59B6' THEN '#9B59B6'
                            WHEN ebm.ebm_status_color = '#F39C12' THEN '#F39C12'
                            ELSE COALESCE(ebm.ebm_status_color, '#F39C12')
                        END
                    WHEN ebm.proposal_status = 'OK' THEN '#2ECC71'
                    WHEN ebm.proposal_status = 'NEED_TO_CHECK' THEN '#E74C3C'
                    ELSE COALESCE(ebm.ebm_status_color, '#000000')
                END AS ebmStatusColor
            FROM mmi_lead_details ld
		 -- LEFT JOIN mmi_mast_customer_details cust
         -- ON cust.cluster_id = ld.cluster_id
            LEFT JOIN LATERAL (
                SELECT cluster_id, MIN(customer_name) AS customer_name, MIN(vehicle_reg_no) AS vehicle_reg_no
                FROM mmi_mast_customer_details cd WHERE ld.vin = cd.chassis_no and ld.engine_no = cd.engine_no
                GROUP BY cluster_id LIMIT 1
            ) cust ON TRUE 
            LEFT JOIN latest_dispositions lat
              ON lat.lead_id = ld.lead_id
            LEFT JOIN dispo_counts dc
              ON dc.lead_id = ld.lead_id
            LEFT JOIN mmi_agent_disposition_field_response adfr
              ON adfr.response_id = lat.id AND adfr.field_label = 'Sub Disposition'
            LEFT JOIN mmi_mast_user_registration_detail u
              ON u.id = ld.assigned_agent
            LEFT JOIN mmi_user_reporting ur
              ON ur.user_id = u.id
            LEFT JOIN latest_ebm_status ebm ON ebm.lead_id = ld.lead_id
        )
        SELECT
            filtered.customerName,
            filtered.leadId,
            filtered.leadType,
            filtered.vehicleName,
            filtered.vehicleRegNo,
            filtered.renewal_category AS renewalCategory,
            filtered.expiryDate,
            filtered.recentUpdates,
            filtered.status,
            filtered.clusterId,
            -- filtered.expiryDays,
            filtered.ebmStatus,
            filtered.ebmStatusColor
        FROM (
            SELECT *,
                ROW_NUMBER() OVER (
                    PARTITION BY leadId
                    ORDER BY call_date_time DESC, expiryDate ASC  
                ) AS rn
            FROM base_data bd
            WHERE bd.assigned_agent = v_userId
              AND (v_renewal_count = 0 OR bd.renewal_category IN (SELECT val FROM tmp_renewal_category))
              -- AND (v_expiry_days IS NULL OR bd.expiryDays <= v_expiry_days)
              AND (v_expiry_date_from IS NULL OR bd.expiryDate >= v_expiry_date_from)
              AND (v_expiry_date_to IS NULL OR bd.expiryDate <= v_expiry_date_to)
        ) AS filtered
        WHERE filtered.rn = 1
          AND (v_has_recent_updates = FALSE
               OR EXISTS (
                   SELECT 1 FROM tmp_recent_updates r
                   WHERE filtered.recentUpdates LIKE CONCAT('%', r.val, '%')
               ))
          AND (v_has_status = FALSE
               OR EXISTS (
                   SELECT 1 FROM tmp_status s
                   WHERE filtered.status LIKE CONCAT('%', s.val, '%')
                   OR (s.val = 'Blank' AND (filtered.status IS NULL OR filtered.status = ''))
               ))
          AND (v_has_lead = FALSE
               OR EXISTS (
                   SELECT 1 FROM tmp_lead l
                   WHERE filtered.leadType LIKE CONCAT('%', l.val, '%')
               ))
          -- EBM Filter condition
          AND (v_has_ebm_status = FALSE
               OR EXISTS (
                   SELECT 1 FROM tmp_ebm_status e
                   WHERE 
                       -- Handle exact matches (case-insensitive)
                       UPPER(TRIM(filtered.ebmStatus)) = UPPER(TRIM(e.val))
                       -- Handle 'Blank' filter
                       OR (UPPER(TRIM(e.val)) = 'BLANK' AND 
                           (filtered.ebmStatus IS NULL OR UPPER(TRIM(filtered.ebmStatus)) IN ('N/A', 'NA', '')))
               ))
               /*ORDER BY
			filtered.expiryDays DESC,
            -- filtered.leadId ASC,
            CASE WHEN v_sortField = 'expiryDays' AND v_sortOrder = 'asc' THEN filtered.expiryDays END ASC,
            CASE WHEN v_sortField = 'expiryDays' AND v_sortOrder = 'desc' THEN filtered.expiryDays END DESC,
            CASE WHEN v_sortField = 'customerName' AND v_sortOrder = 'asc' THEN filtered.customerName END ASC,
            CASE WHEN v_sortField = 'customerName' AND v_sortOrder = 'desc' THEN filtered.customerName END DESC,
            CASE WHEN v_sortField = 'status' AND v_sortOrder = 'asc' THEN filtered.status END ASC,
            CASE WHEN v_sortField = 'status' AND v_sortOrder = 'desc' THEN filtered.status END DESC
        LIMIT v_limit OFFSET calculated;*/
        ORDER BY
			CASE v_sort_col
				WHEN 1 THEN filtered.expiryDate
				WHEN 2 THEN filtered.customerName
				WHEN 3 THEN filtered.status
			END * v_sort_dir,
			filtered.leadId
		LIMIT v_limit OFFSET calculated;
        
       END IF; 
        
