                SELECT cluster_id, MIN(customer_name) AS customer_name, MIN(vehicle_reg_no) AS vehicle_reg_no
                FROM mmi_mast_customer_details cd WHERE ld.vin = cd.chassis_no and ld.engine_no = cd.engine_no
                GROUP BY cluster_id LIMIT 1
            ) cust ON TRUE
            LEFT JOIN latest_dispositions lat
              ON lat.lead_id = ld.lead_id
            LEFT JOIN dispo_counts dc
              ON dc.lead_id = ld.lead_id
            LEFT JOIN mmi_agent_disposition_field_response adfr
              ON adfr.response_id = lat.id AND adfr.field_label = 'Sub Disposition'
            LEFT JOIN mmi_mast_user_registration_detail u
              ON u.id = ld.assigned_agent
            LEFT JOIN mmi_user_reporting ur
              ON ur.user_id = u.id
            INNER JOIN supervisor_hierarchy sh
              ON sh.user_id = ur.user_id
            LEFT JOIN latest_ebm_status ebm ON ebm.lead_id = ld.lead_id
        )
        SELECT COUNT(DISTINCT leadId) AS total
        FROM base_data bd  
        WHERE bd.assigned_agent <> v_userId
          AND (v_renewal_count = 0 OR bd.renewal_category IN (SELECT val FROM tmp_renewal_category))
          -- AND (v_expiry_days IS NULL OR bd.expiryDays <= v_expiry_days)
          AND (v_expiry_date_from IS NULL OR bd.expiryDate >= v_expiry_date_from)
          AND (v_expiry_date_to IS NULL OR bd.expiryDate <= v_expiry_date_to)
          AND (v_has_recent_updates = FALSE
               OR EXISTS (
                   SELECT 1 FROM tmp_recent_updates r
                   WHERE bd.recentUpdates LIKE CONCAT('%', r.val, '%')
               ))
          AND (v_has_status = FALSE
               OR EXISTS (
                   SELECT 1 FROM tmp_status s
                   WHERE bd.status LIKE CONCAT('%', s.val, '%')
                   OR (s.val = 'Blank' AND (bd.status IS NULL OR bd.status = ''))
               ))
          AND (v_has_lead = FALSE
               OR EXISTS (
                   SELECT 1 FROM tmp_lead l
                   WHERE bd.leadType LIKE CONCAT('%', l.val, '%')
               ))
          -- EBM Filter condition
          AND (v_has_ebm_status = FALSE
               OR EXISTS (
                   SELECT 1 FROM tmp_ebm_status e
                   WHERE 
                       UPPER(TRIM(bd.ebmStatus)) = UPPER(TRIM(e.val))
                       OR (UPPER(TRIM(e.val)) = 'BLANK' AND 
                           (bd.ebmStatus IS NULL OR UPPER(TRIM(bd.ebmStatus)) IN ('N/A', 'NA', '')))
               ));
    END IF;
END ;;
DELIMITER ;
