    SELECT renewal_year FROM mmi_mast_renewal_category order by id asc; 
    
      -- herek
SELECT ebm_status, ebm_status_color
FROM mmi_mast_ebm_status
WHERE is_active = 1
ORDER BY id ASC;
	
    SELECT DISTINCT disposition AS recentUpdate FROM mmi_mast_disposition; -- where final_status = 'Pending';
    
    SELECT 'Blank' AS status
