    -- SELECT DISTINCT insurance_company FROM mmi_customer_policy_history;
    -- SELECT DISTINCT claim_status FROM mmi_customer_claim_history;

    SET p_status_code = '200';
    SET p_status_message = 'Filter details fetched successfully.';
END ;;
