CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_fresh_dealer_role_mappings`(
    IN p_json_data JSON,
    OUT p_status_code VARCHAR(50),
    OUT p_status_message VARCHAR(255)
)
BEGIN
    DECLARE v_role_id INT;
    DECLARE v_dealer_name varchar(500);
    DECLARE v_type varchar(50);
    DECLARE v_parent_code varchar(50);
    DECLARE v_dealer_role_id varchar(50);
    DECLARE v_dealer_code VARCHAR(45);  
    
    DECLARE err_code INT;
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_fresh_dealer_role_mappings', 'freshDealerRoleMap', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    -- SET v_dealer_name = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerName'));
	-- SET v_dealer_name = TRIM(SUBSTRING_INDEX(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerName')),'-',1));
    SET v_dealer_name = TRIM(SUBSTRING_INDEX(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerName')),'-',-1));
    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.type'));
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode'));
    SET v_dealer_role_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerRoleId'));
	SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerCode'));
    
       
    IF v_type = 'MIBL' THEN
		/*SELECT 
        mr.role AS role,mr.role_id
		FROM mmi_mast_role r
		JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id AND drm.status = '1'
		LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
		LEFT JOIN mmi_mast_role mr ON drm.reporting_role_id = mr.role_id
		LEFT JOIN mmi_mast_role_type mrt ON mrt.id = m.role_type_id
		WHERE r.status = '1' AND m.role_id IS NOT NULL AND mrt.id = 1 AND m.role_type_id 
        IS NOT NULL AND mr.role is not null
		GROUP BY  mr.role,mr.role_id;*/
        
        SELECT 
        r.role AS role,r.role_id
		FROM mmi_mast_role r
		LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
		LEFT JOIN mmi_mast_role_type mrt ON mrt.id = m.role_type_id
		WHERE r.status = '1' AND m.role_id IS NOT NULL  AND mrt.id = 1 AND m.role_type_id 
        IS NOT NULL
		GROUP BY r.role,r.role_id;
        
		select distinct id,features from mmi_mast_feature where status = 1
        and parent_feature_id IS NULL;
        
		select distinct id,access_name from mmi_mast_access_feature where status = 1;
		SELECT f.id AS feature_id,GROUP_CONCAT(a.id) AS access_id
		FROM mmi_mast_feature f
		LEFT JOIN mmi_mast_feature_access_mapping m ON f.id = m.feature_id
		LEFT JOIN mmi_mast_access_feature a ON m.access_id = a.id
		where a.status = 1 and f.status = 1
		GROUP BY f.id, f.features;
        select distinct id,parent_feature_id,features from mmi_mast_feature where 
        parent_feature_id IS NOT NULL;
    ELSEIF v_type = 'DEALER' THEN 
    IF v_parent_code IS NOT NULL then
		select distinct loc_name,loc_code from mmi_mast_dealer_location mdl left join
        mmi_dealer_location_mapping dlm on mdl.loc_code = dlm.location_code
        left join mmi_dealer_details dl on dlm.dealer_code = dl.dealer_id
        -- WHERE dl.parent_code = v_parent_code; 
        WHERE dl.dealer_id = v_dealer_name;
        
        /*select distinct role_location from mmi_mast_dealer_location mdl left join
        mmi_dealer_location_mapping dlm on mdl.loc_code = dlm.location_code
        left join mmi_dealer_details dl on dlm.dealer_code = dl.dealer_id
        left join mmi_mast_dealer_role_mapping drm on drm.parent_code = dl.parent_code 
        and dlm.location_code = drm.role_location
        WHERE dl.parent_code = v_parent_code and role_id = v_dealer_role_id 
        and role_location IS NULL;*/
        
    END IF;    
    IF v_dealer_name IS NOT NULL then
		/*SELECT DISTINCT
        mr.role AS role,
        mr.role_id
		FROM mmi_mast_role r
		JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id AND drm.status = '1'
		LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
		LEFT JOIN mmi_mast_role mr ON drm.reporting_role_id = mr.role_id
		LEFT JOIN mmi_mast_role_type mrt ON mrt.id = m.role_type_id
		WHERE r.status = '1' AND m.role_id IS NOT NULL AND mrt.id = 1 AND m.role_type_id 
        IS NOT NULL AND mr.role is not null
		GROUP BY  mr.role,mr.role_id
        UNION ALL*/
		select distinct role,mr.role_id from mmi_mast_role mr left join
		mmi_mast_dealer_role_mapping drm on mr.role_id = drm.role_id 
		-- left join mmi_mast_dealer md on drm.parent_code = md.parent_code
        left join mmi_dealer_location_mapping md on drm.dealer_code = md.mapping_dealer_code -- on drm.parent_code = md.parent_code
        left join mmi_dealer_details dl on md.mapping_dealer_code = dl.dealer_id -- on md.parent_code = dl.parent_code
		-- where md.dealer_name = v_dealer_name and role IS NOT NULL;
        where dl.dealer_id = v_dealer_name and role IS NOT NULL;
	ELSE
		-- select distinct dealer_name,parent_code from mmi_mast_dealer;
		/*select distinct md.dealer_name,md.parent_code from mmi_dealer_details dl left join 
		mmi_mast_dealer md on md.parent_code = dl.parent_code;*/
        
        /*SELECT DISTINCT dl.dealer_name-- ,dl.dealer_id  
        FROM mmi_dealer_details dl
        LEFT JOIN mmi_mast_dealer md ON md.parent_code = dl.parent_code;*/
        
        SELECT distinct concat(dl.dealer_name,' - ',mdl.loc_name,' - ',dl.dealer_id) as dealer_name,dl.parent_code 
        -- from mmi_mast_dealer md left join
		from mmi_dealer_details dl -- on md.parent_code = dl.parent_code
		left join mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = dl.dealer_id
		left join mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
		WHERE dl.parent_code IS NOT NULL and dl.dealer_name IS NOT NULL; 
        
		-- select distinct role from mmi_mast_role;
		select distinct id,features from mmi_mast_feature where status = 1 
		and parent_feature_id IS NULL and features not in 
        ('Add & Setup Outlet','Admin Add','MIBL Role','System Configuration','MIBL User');
        
		select distinct id,access_name from mmi_mast_access_feature where status = 1;
		SELECT f.id AS feature_id,GROUP_CONCAT(a.id) AS access_id
		FROM mmi_mast_feature f
		LEFT JOIN mmi_mast_feature_access_mapping m ON f.id = m.feature_id
		LEFT JOIN mmi_mast_access_feature a ON m.access_id = a.id
		where a.status = 1 and f.status = 1 and f.id not in (1,2,3,4,14)
		GROUP BY f.id, f.features;
    
		END IF;
      ELSEIF v_parent_code IS NOT NULL THEN
		/*SELECT DISTINCT
        mr.role AS role,mr.role_id
		FROM mmi_mast_role r
		JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id AND drm.status = '1'
		LEFT JOIN mmi_user_feature_access_mapping m ON m.role_id = r.role_id
		LEFT JOIN mmi_mast_role mr ON drm.reporting_role_id = mr.role_id
		LEFT JOIN mmi_mast_role_type mrt ON mrt.id = m.role_type_id
		WHERE r.status = '1' AND m.role_id IS NOT NULL AND mrt.id = 1 AND m.role_type_id 
        IS NOT NULL AND mr.role is not null
		GROUP BY  mr.role,mr.role_id
        UNION ALL*/
		select distinct role,mr.role_id from mmi_mast_role mr left join
		mmi_mast_dealer_role_mapping drm on mr.role_id = drm.role_id 
		-- left join mmi_mast_dealer md on drm.parent_code = md.parent_code
        left join mmi_dealer_location_mapping md on drm.dealer_code = md.mapping_dealer_code-- drm.parent_code = md.parent_code
        left join mmi_dealer_details dl on md.mapping_dealer_code = dl.dealer_id -- on md.parent_code = dl.parent_code
		-- where md.dealer_name = v_dealer_name and role IS NOT NULL;
        WHERE dl.dealer_id = v_dealer_name and role IS NOT NULL;
        
		select distinct id,features from mmi_mast_feature where status = 1 
		and parent_feature_id IS NULL and features not in
        ('Add & Setup Outlet','Admin Add','MIBL Role','System Configuration','MIBL User');
		select distinct id,access_name from mmi_mast_access_feature where status = 1;
		SELECT f.id AS feature_id,GROUP_CONCAT(a.id) AS access_id
		FROM mmi_mast_feature f
		LEFT JOIN mmi_mast_feature_access_mapping m ON f.id = m.feature_id
		LEFT JOIN mmi_mast_access_feature a ON m.access_id = a.id
		where a.status = 1 and f.status = 1 and f.id not in (1,2,3,4,14)
		GROUP BY f.id, f.features;
        
        select distinct loc_code,loc_name from mmi_mast_dealer_location mdl left join
        mmi_dealer_location_mapping dlm on mdl.loc_code = dlm.location_code
        left join mmi_dealer_details dl on dlm.mapping_dealer_code = dl.dealer_id
        -- WHERE dl.parent_code = v_parent_code and dl.dealer_id = v_dealer_code;
        WHERE dl.dealer_id = v_dealer_name;
      ELSE
		select distinct id,role_type from mmi_mast_role_type where status = 1;
		select distinct id,features from mmi_mast_feature where 
        parent_feature_id IS NULL and status = 1;
		select distinct id,access_name from mmi_mast_access_feature where status = 1;
		SELECT f.id AS feature_id,GROUP_CONCAT(a.id) AS access_id
		FROM mmi_mast_feature f
		LEFT JOIN mmi_mast_feature_access_mapping m ON f.id = m.feature_id
		LEFT JOIN mmi_mast_access_feature a ON m.access_id = a.id
		where a.status = 1 and f.status = 1
		GROUP BY f.id, f.features;
        select distinct id,parent_feature_id,features from mmi_mast_feature where 
        parent_feature_id IS NOT NULL;
	END IF;
    SELECT v_dealer_code;
    SET p_status_code = '200';
    SET p_status_message = 'New dealer-role mappings fetched successfully';

END ;;
