CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_inactive_users`()
BEGIN
    DECLARE v_interval_days INT;

    -- Handle any errors
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
    END;

    START TRANSACTION;

    -- ✅ Get value from mmi_services_config using correct column
    SELECT CAST(`services_value` AS UNSIGNED)
    INTO v_interval_days
    FROM mmi_services_config
    WHERE services_property = 'inactive_user_threshold_days'
    LIMIT 1;
    
    -- Fail if config not found
    IF v_interval_days IS NULL THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'inactive_user_threshold_days config missing in mmi_services_config';
    END IF;
    -- ✅ Update users where last login exceeds the threshold
    UPDATE mmi_mast_user
    SET status = '0'
    WHERE 
        status = '1'
        AND last_login_date IS NOT NULL
          AND DATE(STR_TO_DATE(last_login_date, '%Y-%m-%d %H:%i:%s.%f')) <= CURDATE() - INTERVAL v_interval_days DAY;

    COMMIT;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
