CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_otp_details`(
	IN otpEmail VARCHAR(255), 
    IN otpCode VARCHAR(255)
)
BEGIN
	DECLARE err_code INT;
    DECLARE err_msg TEXT;
    DECLARE v_otp_id VARCHAR(200); 
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1 
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		ROLLBACK;
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_otp_details', 'getOtpDetails', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
        
    END;
    START TRANSACTION;
    IF otpEmail IS NULL or otpEmail = '' or otpCode IS NULL or otpCode = '' THEN
		SET err_code = 300;
        SET err_msg = 'Required Fields are missing';
    ELSE
		SELECT otp_id INTO v_otp_id
        FROM mmi_otp_details WHERE otp_email = otpEmail AND otp_code = otpCode
          AND is_used = 0 AND created_date >= NOW() - INTERVAL 10 MINUTE
        ORDER BY created_date DESC
        LIMIT 1;
        
		/*SELECT * FROM mmi_otp_details
		WHERE otp_email = otpEmail
		  AND otp_code = otpCode
		ORDER BY created_date DESC
		LIMIT 1;*/
        
        IF v_otp_id IS NOT NULL AND v_otp_id != '' THEN
            -- Mark OTP as used
            UPDATE mmi_otp_details
            SET is_used = TRUE,
                otp_verified_time = NOW()
            WHERE otp_id = v_otp_id;

            -- Return the OTP details
            SELECT *
            FROM mmi_otp_details
            WHERE otp_id = v_otp_id;
        ELSE
            SET err_code = 404;
            SET err_msg = 'OTP is invalid, expired, or already used';
            SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = err_msg;
        END IF;
        
    END IF;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
