CREATE DEFINER=`crmmispadmin`@`%` PROCEDURE `mmi_proc_get_reports`(
    IN Json_data JSON,
    -- IN report_Id varchar(500),
    OUT SP_STATUS VARCHAR(500),
    OUT MESSAGE VARCHAR(500),
    OUT REPORT_NAME VARCHAR(255))
BEGIN
    DECLARE v_roleId VARCHAR(45);
    DECLARE v_userId VARCHAR(45); 
    DECLARE v_role_type VARCHAR(20);
    DECLARE v_dealerId TEXT; 
    DECLARE v_startDate VARCHAR(20);
    DECLARE v_endDate VARCHAR(20);
    DECLARE report_Id VARCHAR(20); 

    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;
    DECLARE row_count INT DEFAULT 0;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
        @sqlstate = RETURNED_SQLSTATE, errno = MYSQL_ERRNO, errmsg = MESSAGE_TEXT;
        SET SP_STATUS = '407';
        SET MESSAGE = CONCAT('Something went wrong. Error: ', errno, ' - ', errmsg);
        SET REPORT_NAME = 'Error_Report';

        INSERT INTO mmi_mast_procedure_error (error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date)
        VALUES (errno, CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg), 'mmi_proc_get_reports', report_Id, CURRENT_TIMESTAMP(), 'SYSTEM', NOW());
    END;

    SET v_roleId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleId'));
    SET v_userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
    SET v_startDate = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.startDate'));
    SET v_endDate = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.endDate'));
    SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleType'));
    SET v_dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
	SET report_Id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.report_Id'));
    
    IF v_role_type IS NULL OR v_role_type = ''
        OR v_userId IS NULL OR v_userId = '' OR v_userId = 0
    THEN
        SET SP_STATUS = '400';
        SET MESSAGE = CONCAT(
            CASE
                WHEN v_role_type IS NULL OR v_roleId = '' THEN 'roleId is missing'
              --  WHEN v_roleId = 0 THEN 'roleId is Invalid'
                WHEN v_userId IS NULL OR v_userId = '' THEN 'userId is missing'
                WHEN v_userId = 0 THEN 'userId is Invalid'
                ELSE ''
            END
        );
        SET REPORT_NAME = 'Error_Report';
    ELSE

-- ----------------------------------------------------------MIBL----------------------------------------------------------------------

        IF v_role_type = 'MIBL' THEN

        IF report_Id = '1' THEN

