-- 2. Select the LATEST Disposition only (Required for joining to mmi_mast_disposition and sub-disposition)
latest_disposition AS (
    SELECT
        lead_id,
        id,
        remarks,
        dealer_disposition_id,
        ROW_NUMBER() OVER (
            PARTITION BY lead_id
            ORDER BY call_date DESC, id DESC
        ) as rn
    FROM mmi_call_disposition_history
),
final_disposition AS (
    SELECT lead_id, id, remarks, dealer_disposition_id
    FROM latest_disposition
    WHERE rn = 1
),

-- 3. Deduplicate the Sub Disposition field value (GUARANTEED ONE ROW per response_id)
final_sub_disposition AS (
    SELECT
        response_id,
        field_value AS sub_disposition_value
    FROM (
        SELECT
            response_id,
            field_value,
            ROW_NUMBER() OVER (
                PARTITION BY response_id
                ORDER BY field_value ASC
            ) as rn
        FROM mmi_agent_disposition_field_response
        WHERE field_label = 'Sub Disposition'
    ) ranked_sub_disposition
    WHERE rn = 1
),

-- 4. Deduplicate Dealer Location Mapping (GUARANTEED ONE ROW)
latest_dealer_map AS (
    SELECT dealer_code, zone, location_code
    FROM (
        SELECT dealer_code, zone, location_code,
            ROW_NUMBER() OVER (PARTITION BY dealer_code ORDER BY location_code DESC) as rn
        FROM mmi_dealer_location_mapping
    ) ranked_map
    WHERE rn = 1
),

-- 5. Deduplicate Master Dealer Location (GUARANTEED ONE ROW)
latest_mast_dealer_loc AS (
    SELECT loc_code, state, loc_name
    FROM (
        SELECT loc_code, state, loc_name,
            ROW_NUMBER() OVER (PARTITION BY loc_code ORDER BY loc_code ASC) as rn
        FROM mmi_mast_dealer_location
    ) ranked_loc
    WHERE rn = 1
),

-- 6. Deduplicate Customer Details (GUARANTEED ONE ROW)
latest_customer AS (
    SELECT cluster_id, customer_address, customer_state, customer_city, customer_pincode,vehicle_reg_no
    FROM (
        SELECT cluster_id, customer_address, customer_state, customer_city, customer_pincode,vehicle_reg_no,
            ROW_NUMBER() OVER (PARTITION BY cluster_id ORDER BY cluster_id ASC) as rn
        FROM mmi_mast_customer_details
    ) ranked_customer
    WHERE rn = 1
),

-- 7. Deduplicate Master Disposition (Guaranteed one row per disposition_id, for safety)
final_mast_disposition AS (
    SELECT disposition_id, disposition
    FROM (
        SELECT disposition_id, disposition,
               ROW_NUMBER() OVER (PARTITION BY disposition_id ORDER BY disposition_id ASC) AS rn
        FROM mmi_mast_disposition
    ) ranked_md
    WHERE rn = 1
),

-- 8. Get the Assigned Agent's Name and Role (GUARANTEED ONE ROW per agent, even if multiple roles exist)
latest_user AS (
    SELECT 
        mu.id AS user_id, 
        CONCAT(mu.first_name, ' ', mu.last_name) AS agent_name,
        mr.role AS agent_role
    FROM mmi_mast_user_registration_detail mu
    LEFT JOIN mmi_user_role_mapping urm ON mu.id = urm.user_id
    LEFT JOIN mmi_mast_role mr ON urm.role_id = mr.role_id
),
renewal_agg AS (
    SELECT policy_no, GROUP_CONCAT(DISTINCT reminder_frequency) AS reminder_triggered,
            MAX(created_date) AS last_sent_date
    FROM mmi_renewalreminder_data
    GROUP BY policy_no
)
