    fd.remarks AS 'Remarks',
    rr.reminder_triggered AS 'Renewal Reminder Triggered',
    rr.last_sent_date AS 'Renewal Reminder Triggered Date and Time',
    -- l.expiry_days AS Lead_Aging_Days,
    DATEDIFF(CURDATE(), STR_TO_DATE(l.policy_expiry_date, '%Y-%m-%d')) AS 'Lead Aging Number of Days',
    -- Use the assigned agent logic (now guaranteed single role)
    -- CONCAT(l.assigned_agent, '/', COALESCE(lu.user_role, '')) AS 'User Name/ User Type',
    CONCAT(lu.agent_name, ' / ', lu.agent_role) AS 'User Name/ User Type',
    -- l.modified_date AS 'Date and Time of Last updated',
    COALESCE(l.modified_date, l.created_date) AS 'Date and Time of Last updated',
    NOW() AS 'Date and Time of the report',
    l.renewal_category AS 'Renewal Category',
    l.lead_status AS 'Final Lead Status'

FROM latest_lead l
-- Disposition Joins
LEFT JOIN final_disposition fd ON l.lead_id = fd.lead_id
LEFT JOIN final_mast_disposition fmd ON fd.dealer_disposition_id = fmd.disposition_id -- Using deduplicated master disposition
LEFT JOIN final_sub_disposition fsd ON fd.id = fsd.response_id

-- Other Deduplicated Joins
LEFT JOIN latest_customer c ON l.cluster_id = c.cluster_id
LEFT JOIN latest_dealer_map dlm ON l.dealer_code = dlm.dealer_code
LEFT JOIN latest_mast_dealer_loc mdl ON dlm.location_code = mdl.loc_code
-- Assigned Agent Join
LEFT JOIN latest_user lu ON l.assigned_agent = lu.user_id
LEFT JOIN renewal_agg rr ON l.policy_no = rr.policy_no
WHERE
(v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(l.dealer_code, v_dealerId))
AND (
    (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
    -- OR (l.created_date BETWEEN v_startDate AND v_endDate)
    -- OR (l.modified_date BETWEEN v_startDate AND v_endDate)
    OR (DATE(l.policy_expiry_date) BETWEEN v_startDate AND v_endDate)  -- Stripping time part
	-- OR (DATE(l.modified_date) BETWEEN v_startDate AND v_endDate)
)
ORDER BY l.policy_expiry_date DESC;


