-- CHANGS
WITH followup_leads AS (
    SELECT DISTINCT lead_id
    FROM mmi_call_disposition_history
    WHERE DATE(next_call_datetime) BETWEEN v_startDate AND v_endDate
),
combined_leads AS (
    SELECT
        *,
        ROW_NUMBER() OVER (
            PARTITION BY lead_id
            ORDER BY modified_date DESC, created_date DESC
        ) as rn_lead
    FROM (
        SELECT
            lead_id, dealer_code, dealer, cluster_id, insurance_company,
            policy_no, policy_type, insured_name, reg_no, ncb_percentage,
            oem_code, vehicle_class, vehicle_sub_class, carrier_type,
            policy_effective_date, policy_expiry_date, group_product,
            model, vehicle_body_type, fuel_type, variant, vin, engine_no,
            yom, od_discount_percentage, total_idv, addon_premium_amount,
            net_od_premium_amount, third_party_liability, pa_cover,
            legal_liability, net_liability, net_premium, gross_premium,
            podc_start, podc_end, plc_start, plc_end, plan_type,
            lead_status, assigned_agent, modified_date, created_date, lead_type,
            reg_no AS vehicle_reg_no, lead_assignment_type, lead_assignment_date_time
        FROM mmi_lead_details
        WHERE lead_id IN (SELECT lead_id FROM followup_leads)

        UNION ALL

        SELECT
            lead_id, dealer_code, dealer, cluster_id, insurance_company,
            policy_no, policy_type, insured_name, reg_no, ncb_percentage,
            oem_code, vehicle_class, vehicle_sub_class, carrier_type,
            policy_effective_date, policy_expiry_date, group_product,
            model, vehicle_body_type, fuel_type, variant, vin, engine_no,
            yom, od_discount_percentage, total_idv, addon_premium_amount,
            net_od_premium_amount, third_party_liability, pa_cover,
            legal_liability, net_liability, net_premium, gross_premium,
            podc_start, podc_end, plc_start, plc_end, plan_type,
            lead_status, assigned_agent, modified_date, created_date, lead_type,
            reg_no AS vehicle_reg_no, lead_assignment_type, lead_assignment_date_time
        FROM mmi_lead_archive_details
        WHERE lead_id IN (SELECT lead_id FROM followup_leads)
    ) AS all_lead_data
),
latest_lead AS (
    SELECT * FROM combined_leads
    WHERE rn_lead = 1
),
latest_disposition AS (
    SELECT
        lead_id, id, remarks, dealer_disposition_id, next_call_datetime,
        COUNT(lead_id) OVER (PARTITION BY lead_id) AS followups,
        ROW_NUMBER() OVER (
            PARTITION BY lead_id
            ORDER BY call_date DESC, id DESC
        ) as rn
    FROM mmi_call_disposition_history
    WHERE DATE(next_call_datetime) BETWEEN v_startDate AND v_endDate
),
final_disposition AS (
    SELECT lead_id, id, remarks, dealer_disposition_id, next_call_datetime, followups
    FROM latest_disposition
    WHERE rn = 1
),

final_sub_disposition AS (
    SELECT
        response_id,
        field_value AS sub_disposition_value
    FROM (
        SELECT
            response_id, field_value,
            ROW_NUMBER() OVER (PARTITION BY response_id ORDER BY field_value ASC) as rn
        FROM mmi_agent_disposition_field_response
        WHERE field_label = 'Sub Disposition'
    ) ranked_sub_disposition
    WHERE rn = 1
),

final_mast_disposition AS (
    SELECT disposition_id, disposition, sub_disposition AS md_sub_disposition
    FROM (
        SELECT disposition_id, disposition, sub_disposition,
               ROW_NUMBER() OVER (PARTITION BY disposition_id ORDER BY disposition_id ASC) AS rn
        FROM mmi_mast_disposition
    ) ranked_md
    WHERE rn = 1
),

latest_customer AS (
    SELECT cluster_id, customer_state, customer_city, vehicle_reg_no
    FROM (
        SELECT cluster_id, customer_state, customer_city, vehicle_reg_no,
            ROW_NUMBER() OVER (PARTITION BY cluster_id ORDER BY cluster_id ASC) as rn
        FROM mmi_mast_customer_details
    ) ranked_customer
    WHERE rn = 1
),

latest_user AS (
    SELECT 
        mu.id AS user_id, 
        CONCAT(mu.first_name, ' ', mu.last_name) AS agent_name,
        mr.role AS agent_role
    FROM mmi_mast_user_registration_detail mu
    LEFT JOIN mmi_user_role_mapping urm ON mu.id = urm.user_id
    LEFT JOIN mmi_mast_role mr ON urm.role_id = mr.role_id
)

SELECT
