    CASE WHEN l.lead_status IN ('Won','Lost','Closed') THEN l.created_date ELSE NULL END AS 'Date and Time of Lead Converted/Closed'
FROM latest_lead l
LEFT JOIN latest_disposition cdh ON l.lead_id = cdh.lead_id
LEFT JOIN latest_sub_disposition sd ON cdh.id = sd.response_id
LEFT JOIN latest_customer c ON l.cluster_id = c.cluster_id
LEFT JOIN latest_dealer_map dlm ON l.dealer_code = dlm.dealer_code
