CREATE TEMPORARY TABLE tmp_latest_lead AS
SELECT t.*
FROM (
    SELECT *,
           ROW_NUMBER() OVER (
               PARTITION BY lead_id
               ORDER BY COALESCE(modified_date, created_date) DESC
           ) AS rn
    FROM tmp_combined_leads
) t
WHERE t.rn = 1;

-- ALTER TABLE tmp_latest_lead ADD PRIMARY KEY (lead_id);

CREATE TEMPORARY TABLE tmp_latest_disposition AS
SELECT c1.*
FROM mmi_call_disposition_history c1
JOIN (
    SELECT lead_id, MAX(call_date) AS max_dt
    FROM mmi_call_disposition_history
    GROUP BY lead_id
) c2 ON c1.lead_id = c2.lead_id
    AND c1.call_date = c2.max_dt;

-- ALTER TABLE tmp_latest_disposition ADD PRIMARY KEY (lead_id);

CREATE TEMPORARY TABLE tmp_latest_sub_disposition AS
SELECT response_id, MIN(field_value) AS sub_disposition_value
FROM mmi_agent_disposition_field_response
WHERE field_label = 'Sub Disposition'
GROUP BY response_id;

CREATE TEMPORARY TABLE tmp_followup_agg AS
SELECT lead_id, COUNT(*) AS followups
FROM mmi_call_disposition_history
GROUP BY lead_id;


CREATE TEMPORARY TABLE tmp_dealer_map AS
SELECT dealer_code,
       MAX(zone) AS zone,
       MAX(location_code) AS location_code
FROM mmi_dealer_location_mapping
GROUP BY dealer_code;

CREATE TEMPORARY TABLE tmp_mast_dealer_loc AS
SELECT loc_code,
       MAX(state) AS state,
       MAX(loc_name) AS loc_name
FROM mmi_mast_dealer_location
GROUP BY loc_code;


CREATE TEMPORARY TABLE tmp_customer AS
SELECT *
FROM (
    SELECT cd.*,
           ROW_NUMBER() OVER (PARTITION BY cd.cluster_id ORDER BY cd.cluster_id) AS rn
    FROM mmi_mast_customer_details cd
    JOIN tmp_latest_lead ld on cd.chassis_no = ld.vin
) t
WHERE rn = 1;


CREATE TEMPORARY TABLE tmp_addon_agg AS
SELECT pd.policy_no, GROUP_CONCAT(DISTINCT pd.add_on_name) AS addon_list
FROM mmi_poladdon_data pd
JOIN tmp_latest_lead ld on ld.policy_no = pd.policy_no
GROUP BY pd.policy_no;

CREATE TEMPORARY TABLE tmp_renewal_agg AS
SELECT rrd.policy_no,
       GROUP_CONCAT(DISTINCT rrd.reminder_frequency) AS reminder_triggered,
       MAX(rrd.created_date) AS last_sent_date
FROM mmi_renewalreminder_data rrd
JOIN tmp_latest_lead ld on ld.policy_no = rrd.policy_no
GROUP BY rrd.policy_no;

CREATE TEMPORARY TABLE tmp_claim_agg AS
SELECT cd.chassis_number, COUNT(*) AS reported_claim,
       SUM(CAST(cd.total_estimate_amount AS DECIMAL(10,2))) AS claim_amount
FROM mmi_ebm_claim_data cd
JOIN tmp_latest_lead ld on ld.policy_no = cd.policy_no and ld.vin = cd.chassis_number
GROUP BY cd.chassis_number;

CREATE TEMPORARY TABLE tmp_service_agg AS
SELECT chassis_number, COUNT(*) AS service_count, MAX(ro_date) AS latest_service_date
FROM mmi_ebm_service_data
GROUP BY chassis_number;

CREATE TEMPORARY TABLE tmp_sales_agg AS
SELECT chassis_number, COUNT(*) AS sales_count, MAX(invoice_date_time) AS latest_sales_date
FROM mmi_ebm_sales_data
GROUP BY chassis_number;

CREATE TEMPORARY TABLE tmp_communication_agg AS
SELECT lead_id, GROUP_CONCAT(DISTINCT communication_mode) AS notification_triggered,
       MAX(communication_date_time) AS last_communication_date
FROM mmi_customer_communication_history
GROUP BY lead_id;

CREATE TEMPORARY TABLE tmp_user_agg AS
SELECT 
    mu.id AS user_id, 
    CONCAT(mu.first_name, ' ', mu.last_name) AS agent_name,
    mr.role AS agent_role,
    urd.id AS reporting_id, 
    CONCAT(urd.first_name, ' ', urd.last_name) AS reporting_name,
    mmr.role AS reporting_role
FROM mmi_mast_user_registration_detail mu
LEFT JOIN mmi_user_role_mapping urm ON mu.id = urm.user_id
LEFT JOIN mmi_mast_role mr ON urm.role_id = mr.role_id
LEFT JOIN mmi_user_reporting ur ON ur.user_id = mu.id
LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ur.supervisor_id
LEFT JOIN mmi_user_role_mapping murm ON urd.id = murm.user_id
LEFT JOIN mmi_mast_role mmr ON murm.role_id = mmr.role_id;

CREATE TEMPORARY TABLE tmp_bucket_details AS
SELECT urd.id AS user_id,
       GROUP_CONCAT(DISTINCT mb.bucket_name ORDER BY mb.bucket_name ASC) AS bucket_names
FROM mmi_mast_bucket mb
LEFT JOIN mmi_bucket_user_mapping bum ON mb.id = bum.bucket_id
LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = bum.user_id
GROUP BY urd.id;


SELECT
	l.lead_id AS 'Lead Reference Number',
    dlm.zone AS 'Zone',
    mdl.state AS 'State',
    mdl.loc_name AS 'Location',
    l.dealer_code AS 'Dealer Code',
    l.dealer AS 'Dealer Name',
    l.insurance_company AS 'Insurance Company',
    l.policy_no AS 'Policy No',
    l.policy_type AS 'Policy Type',
    l.insured_name AS 'Insured Name',
    c.customer_address AS 'Customer Address',
    c.customer_state AS 'Customer State',
    c.customer_city AS 'Customer City',
    c.customer_pincode AS 'Customer Pin Code',
    c.vehicle_reg_no AS 'Vehicle Reg No',
    l.ncb_percentage AS 'NCB%',
    l.oem_code AS 'Vehicle Sub OEM',
    l.vehicle_class AS 'Vehicle Class',
    l.vehicle_sub_class AS 'Vehicle Sub Class',
    l.carrier_type AS 'Carrier Type',
    l.policy_effective_date AS 'Policy Effective Date',
    l.policy_expiry_date AS 'Policy Expiry Date',
    l.group_product AS 'Combi Product',
    l.model AS 'Model',
    l.vehicle_body_type AS 'Vehicle Body Type',
    l.fuel_type AS 'Fuel Type',
    l.variant AS 'Variant',
    l.vin AS 'VIN',
    l.engine_no AS 'Engine No',
    l.yom AS 'Manufacturing year',
    l.od_discount_percentage AS 'OD Discount(%).',
    l.total_idv AS 'Total IDV',
    l.addon_premium_amount AS 'Add On Premium A',
    l.net_od_premium_amount AS 'Net OD Premium A',
    l.third_party_liability AS 'Third Party Liability',
    l.pa_cover AS 'PA Cover',
    l.legal_liability AS 'Legal Liability',
    l.net_liability AS 'Net Liability',
    l.net_premium AS 'Net Premium',
    l.imt_23 AS 'IMT 23',
    -- l.imt_34tp AS IMT_34TP,
    l.gross_premium AS 'Gross Premium',
    l.rto_display_name AS 'RTO Display Name',
    l.podc_start AS 'Period of Own Damage Cover start',
    l.podc_end AS 'Period of Own Damage Cover end',
    l.plc_start AS 'Period of Liability Cover start',
    l.plc_end AS 'Period of Liability Cover end',
    l.proposal_no AS 'Proposal No',
    l.plan_type AS 'Plan Type',
    -- l.bundle_product AS 'Bundle Addon',
    cdh.call_status AS 'Main Disposition Status',
    sd.sub_disposition_value AS 'Sub Disposition',
    cdh.remarks AS 'Remarks',
    pol.addon_list AS 'Add On Cover List',
    CONCAT_WS(', ',
		IF(l.imt_23 IS NOT NULL AND l.imt_23 != '' AND l.imt_23 != '0', CONCAT('IMT-23'), NULL),
		IF(l.imt_34tp IS NOT NULL AND l.imt_34tp != '' AND l.imt_34tp != '0', CONCAT('IMT-34TP'), NULL),
		IF(l.trailer_imt30 IS NOT NULL AND l.trailer_imt30 != '' AND l.trailer_imt30 != '0', CONCAT('IMT-30'), NULL),
		IF(l.pa_cover_unnamed_persons_imt16 IS NOT NULL AND l.pa_cover_unnamed_persons_imt16 != '' AND l.pa_cover_unnamed_persons_imt16 != '0', CONCAT('IMT-16'), NULL),
		IF(l.legal_liability_nfpp_imt37 IS NOT NULL AND l.legal_liability_nfpp_imt37 != '' AND l.legal_liability_nfpp_imt37 != '0', CONCAT('IMT-37'), NULL)
	) AS 'IMT Covers List',
    fa.followups AS 'Number of Follow ups',
     DATEDIFF(CURDATE(), STR_TO_DATE(l.policy_expiry_date, '%Y-%m-%d')) AS 'Lead Aging Number of Days',
    -- l.expiry_days AS Lead_Aging_Days,
    -- users.user_roles AS User_Name_User_Type, 
	CONCAT(users.agent_name, ' / ', users.agent_role) AS 'User Name/ User Type', -- Name and Role of Assigned Agent
    CONCAT(users.reporting_name, ' / ', users.reporting_role) AS 'Assignee Name/ User Type',
    -- l.assigned_agent AS Assignee_Name_User_Type,
    l.lead_type AS 'Category',
    l.lead_type_score AS 'Category Score',
    -- l.modified_date AS 'Date and Time of Last updated',
    COALESCE(l.modified_date, l.created_date) AS 'Date and Time of Last updated',
    NOW() AS 'Date and Time of the report',
    l.renewal_category AS 'Renewal Category',
    cdh.next_call_datetime AS 'Next Follow Up date and Time',
    ch.reported_claim AS 'Reported Claim',
    ch.claim_amount AS 'Claim Amount',
    rr.reminder_triggered AS 'Renewal Reminder Triggered',
    rr.last_sent_date AS 'Renewal Reminder Triggered Date and Time',
    CASE WHEN sh.service_count > 0 THEN 'Yes' ELSE 'No' END AS 'Service History',
    sh.latest_service_date AS 'Latest Service Date',
    CASE WHEN sa.sales_count > 0 THEN 'Yes' ELSE 'No' END AS 'Sales History',
    sa.latest_sales_date AS 'Latest Sales Date',
    com.notification_triggered AS 'Notification Triggered',
    com.last_communication_date AS 'Notification Triggered Date & Time',
    l.lead_status AS 'Final Lead Status',
    leadPool.bucket_names AS 'Lead Pool Name',
    l.lead_assignment_date_time AS 'Date and Time of Lead Assignment',
    l.lead_assignment_type AS 'Lead Assignment',
    -- CASE WHEN l.assigned_agent IS NOT NULL THEN 'Manual' ELSE 'Auto' END AS Lead_Assignment,
    -- l.created_date AS Lead_Assignment_DateTime,
    CASE WHEN l.lead_status IN ('Won','Lost','Closed') THEN l.created_date ELSE NULL END AS 'Date and Time of Lead Converted/Closed'
FROM tmp_latest_lead l
LEFT JOIN tmp_latest_disposition cdh ON l.lead_id = cdh.lead_id
LEFT JOIN tmp_latest_sub_disposition sd ON cdh.id = sd.response_id
LEFT JOIN tmp_customer c ON l.cluster_id = c.cluster_id
LEFT JOIN tmp_dealer_map dlm ON l.dealer_code = dlm.dealer_code
LEFT JOIN tmp_mast_dealer_loc mdl ON dlm.location_code = mdl.loc_code
LEFT JOIN tmp_addon_agg pol ON l.policy_no = pol.policy_no
LEFT JOIN tmp_renewal_agg rr ON l.policy_no = rr.policy_no
LEFT JOIN tmp_claim_agg ch ON l.vin = ch.chassis_number
LEFT JOIN tmp_service_agg sh ON l.vin = sh.chassis_number
LEFT JOIN tmp_sales_agg sa ON l.vin = sa.chassis_number
LEFT JOIN tmp_communication_agg com ON l.lead_id = com.lead_id
LEFT JOIN tmp_user_agg users ON l.assigned_agent = users.user_id
LEFT JOIN tmp_bucket_details leadPool ON users.user_id = leadPool.user_id
LEFT JOIN tmp_followup_agg fa ON l.lead_id = fa.lead_id;

                SET REPORT_NAME = 'Master_Report';
                SET MESSAGE = 'Master report with all columns downloaded';
                SET SP_STATUS = '200';

            ELSEIF report_Id = '2' THEN

    WITH combined_leads AS (
    SELECT
        *,
        ROW_NUMBER() OVER (
            PARTITION BY lead_id
            ORDER BY modified_date DESC, created_date DESC
        ) as rn_lead
    FROM (
        SELECT
            lead_id, dealer_code, dealer, cluster_id, insurance_company,
            policy_no, policy_type, insured_name, reg_no, ncb_percentage,
            oem_code, vehicle_class, vehicle_sub_class, carrier_type,
            policy_effective_date, policy_expiry_date, group_product,
            model, vehicle_body_type, fuel_type, variant, vin, engine_no,
            yom, od_discount_percentage, total_idv, addon_premium_amount,
            net_od_premium_amount, third_party_liability, pa_cover,
            legal_liability, net_liability, net_premium, imt_23,
            imt_34tp, gross_premium, rto_display_name, podc_start, podc_end,
            plc_start, plc_end, proposal_no, plan_type, bundle_product,
            lead_status, lead_type, assigned_agent, modified_date,
            created_date, renewal_category,
            reg_no AS vehicle_reg_no,lead_assignment_type,lead_assignment_date_time,lead_type_score
        FROM mmi_lead_details

        UNION ALL

        SELECT
            lead_id, dealer_code, dealer, cluster_id, insurance_company,
            policy_no, policy_type, insured_name, reg_no, ncb_percentage,
            oem_code, vehicle_class, vehicle_sub_class, carrier_type,
            policy_effective_date, policy_expiry_date, group_product,
            model, vehicle_body_type, fuel_type, variant, vin, engine_no,
            yom, od_discount_percentage, total_idv, addon_premium_amount,
            net_od_premium_amount, third_party_liability, pa_cover,
            legal_liability, net_liability, net_premium, imt_23,
            imt_34tp, gross_premium, rto_display_name, podc_start, podc_end,
            plc_start, plc_end, proposal_no, plan_type, bundle_product,
            lead_status, lead_type, assigned_agent, modified_date,
            created_date, renewal_category,
            reg_no AS vehicle_reg_no,lead_assignment_type,lead_assignment_date_time,lead_type_score
        FROM mmi_lead_archive_details
    ) AS all_lead_data
),
latest_lead AS (
    SELECT * FROM combined_leads
    WHERE rn_lead = 1
),

latest_disposition AS (
    SELECT
        lead_id,
        id,
        remarks,
        next_call_datetime,
        dealer_disposition_id,
        call_status,
        followups
    FROM (
        SELECT
            c1.lead_id,
            c1.id,
            c1.remarks,
            c1.next_call_datetime,
            c1.dealer_disposition_id,
            c1.call_status,
            COUNT(c1.lead_id) OVER (PARTITION BY c1.lead_id) AS followups,
            ROW_NUMBER() OVER (
                PARTITION BY c1.lead_id
                ORDER BY c1.call_date DESC, c1.id DESC
            ) as rn
        FROM mmi_call_disposition_history c1
    ) ranked_disposition
    WHERE rn = 1
),

latest_sub_disposition AS (
    SELECT
        response_id,
        field_value AS sub_disposition_value
    FROM (
        SELECT
            response_id,
            field_value,
            ROW_NUMBER() OVER (
                PARTITION BY response_id
                ORDER BY field_value ASC
            ) as rn
        FROM mmi_agent_disposition_field_response
        WHERE field_label = 'Sub Disposition'
    ) ranked_sub_disposition
    WHERE rn = 1
),

latest_dealer_map AS (
    SELECT
        dealer_code,
        zone,
        location_code
    FROM (
        SELECT
            dealer_code,
            zone,
            location_code,
            ROW_NUMBER() OVER (
                PARTITION BY dealer_code
                ORDER BY location_code DESC
            ) as rn
        FROM mmi_dealer_location_mapping
    ) ranked_map
    WHERE rn = 1
),

latest_mast_dealer_loc AS (
    SELECT
        loc_code,
        state,
        loc_name
    FROM (
        SELECT
            loc_code,
            state,
            loc_name,
            ROW_NUMBER() OVER (
                PARTITION BY loc_code
                ORDER BY loc_code ASC
            ) as rn
        FROM mmi_mast_dealer_location
    ) ranked_loc
    WHERE rn = 1
),

latest_customer AS (
    SELECT
        cluster_id,
        customer_address,
        customer_state,
        customer_city,
        customer_pincode,
        vehicle_reg_no
    FROM (
        SELECT
            cluster_id,
            customer_address,
            customer_state,
            customer_city,
            customer_pincode,
            vehicle_reg_no,
            ROW_NUMBER() OVER (
                PARTITION BY cluster_id
                ORDER BY cluster_id ASC 
            ) as rn
        FROM mmi_mast_customer_details
    ) ranked_customer
    WHERE rn = 1
),

user_agg AS (
    SELECT 
        mu.id AS user_id, 
        CONCAT(mu.first_name, ' ', mu.last_name) AS agent_name,
        mr.role AS agent_role
    FROM mmi_mast_user_registration_detail mu
    LEFT JOIN mmi_user_role_mapping urm ON mu.id = urm.user_id
    LEFT JOIN mmi_mast_role mr ON urm.role_id = mr.role_id
)

SELECT
    c.customer_state AS 'State',
    l.dealer_code AS 'Dealer Code',
    l.dealer AS 'Dealer',
    l.insurance_company AS 'Insurance Company',
    l.policy_no AS 'Policy No',
    l.policy_type AS 'Policy Type',
    l.insured_name AS 'Insured Name',
    c.customer_city AS 'Customer City',
    c.vehicle_reg_no AS 'Vehicle Reg No',
    l.ncb_percentage AS 'NCB%',
    l.vehicle_class AS 'Vehicle Class',
    l.vehicle_sub_class AS 'Vehicle Sub Class',
    l.carrier_type AS 'Carrier Type',
    l.policy_effective_date AS 'Policy Effective Date',
    l.policy_expiry_date AS 'Policy Expiry Date',
    l.model AS 'Model',
    l.variant AS 'Variant',
    l.od_discount_percentage AS 'OD Discount(%)',
    l.total_idv AS 'Total IDV',
    l.net_premium AS 'Net Premium',
    l.gross_premium AS 'Gross Premium',
    l.podc_start AS 'Period of Own Damage Cover start',
    l.podc_end AS 'Period of Own Damage Cover end',
    l.plc_start AS 'Period of Liability Cover start',
    l.plc_end AS 'Period of Liability Cover end',
    l.plan_type AS 'Plan Type',
    l.lead_id AS 'Lead Reference Number',
    cdh.call_status AS 'Main Disposition Status',
    sd.sub_disposition_value AS 'Sub Disposition',
    cdh.remarks AS 'Remarks',
    DATEDIFF(CURDATE(), STR_TO_DATE(l.policy_expiry_date, '%Y-%m-%d')) AS 'Lead Aging Number of Days',
    -- l.expiry_days AS 'Lead Aging Number of Days',
    CONCAT(users.agent_name, ' / ', users.agent_role) AS 'User Name/ User Type', 
    l.lead_type AS 'Category',
    l.lead_type_score AS 'Category Score',
    -- l.modified_date AS 'Date and Time of Last updated',
    COALESCE(l.modified_date, l.created_date) AS 'Date and Time of Last updated',
    NOW() AS 'Date and Time of the report',
    l.renewal_category AS 'Renewal Category',
    l.lead_status AS 'Final Lead Status'

FROM latest_lead l
LEFT JOIN latest_disposition cdh ON l.lead_id = cdh.lead_id
LEFT JOIN latest_sub_disposition sd ON cdh.id = sd.response_id
LEFT JOIN latest_customer c ON l.cluster_id = c.cluster_id
LEFT JOIN latest_dealer_map dlm ON l.dealer_code = dlm.dealer_code
LEFT JOIN latest_mast_dealer_loc mdl ON dlm.location_code = mdl.loc_code
LEFT JOIN user_agg users ON l.assigned_agent = users.user_id -- Use the user_agg for combined roles
WHERE l.dealer_code = v_dealerId
-- CHANGS
AND l.lead_status NOT IN ('Won', 'Lost', 'Closed')
AND (
    (v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
    OR (DATE(l.policy_expiry_date) BETWEEN v_startDate AND v_endDate)
    OR EXISTS (
        SELECT 1
        FROM mmi_call_disposition_history cdh
        WHERE cdh.lead_id = l.lead_id
          AND DATE(cdh.call_date) BETWEEN v_startDate AND v_endDate
          AND EXISTS (
              SELECT 1 FROM mmi_lead_archive_details lad
              WHERE lad.lead_id = l.lead_id AND lad.lead_status = 'Lost'
          )
    )
)
-- CHANGE
ORDER BY l.policy_expiry_date DESC;

