latest_dealer_map AS (
    SELECT dealer_code, zone, location_code
    FROM (
        SELECT dealer_code, zone, location_code,
            ROW_NUMBER() OVER (PARTITION BY dealer_code ORDER BY location_code DESC) as rn
        FROM mmi_dealer_location_mapping
    ) ranked_map
