CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_reports_onload`(
    IN Json_data JSON,
    IN type VARCHAR(45),
    OUT SP_STATUS VARCHAR(500),
    OUT MESSAGE VARCHAR(500)
)
BEGIN
    DECLARE v_roleId VARCHAR(45); 
    DECLARE v_userId VARCHAR(45);
    DECLARE v_report_Id VARCHAR(255);
    DECLARE v_role_type VARCHAR(45);
    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;
    DECLARE v_sqlstate VARCHAR(5);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
        v_sqlstate = RETURNED_SQLSTATE, errno = MYSQL_ERRNO, errmsg = MESSAGE_TEXT;
        SET SP_STATUS = '407';
        SET MESSAGE = CONCAT('Something went wrong. Error: ', errno, ' - ', errmsg);
        
        INSERT INTO mmi_mast_procedure_error (error_code, error_message, procedure_name, procedure_type, ERROR_TIMING, created_by, created_date)
        VALUES (errno, CONCAT('SQLSTATE: ', v_sqlstate, ', Error: ', errmsg), 'mmi_proc_get_reports_onload', type, CURRENT_TIMESTAMP(), 'SYSTEM', NOW());
    END;

    SET v_roleId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleId'));
    SET v_userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
    SET v_report_Id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.report_Id')); 
	SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleType')); 

    IF v_roleId IS NULL OR v_roleId = '' OR v_roleId = '0' OR
       v_userId IS NULL OR v_userId = '' OR v_userId = '0' OR
       type IS NULL OR type = ''
    THEN
        SET SP_STATUS = '400';
        SET MESSAGE = CONCAT(
            CASE
                WHEN v_roleId IS NULL OR v_roleId = '' THEN 'roleId is missing. '
                WHEN v_roleId = '0' THEN 'roleId is Invalid. '
                ELSE ''
            END,
            CASE
                WHEN v_userId IS NULL OR v_userId = '' THEN 'userId is missing. '
                WHEN v_userId = '0' THEN 'userId is Invalid. '
                ELSE ''
            END,
            CASE 
                WHEN type IS NULL OR type = '' THEN 'type is missing.'
                ELSE ''
            END
        );
    ELSEIF type = 'onloadReportType' THEN -- AND v_roleId = '1' 
	IF v_role_type = 'MIBL' THEN
        SELECT DISTINCT report_type, report_id 
        FROM mmi_mast_report_type_dropdown_values 
        WHERE report_id IS NOT NULL 
        ORDER BY report_id;
        
       SELECT DISTINCT 
    dl.dealer_name ,
    dl.dealer_id AS dealer_code
FROM mmi_dealer_details dl
-- LEFT JOIN mmi_mast_dealer mmd ON dl.parent_code = mmd.parent_code     
LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.mapping_dealer_code = dl.dealer_id
LEFT JOIN mmi_mast_dealer_location mdl ON dlm.location_code = mdl.loc_code
WHERE dlm.dealer_name IS NOT NULL;
        
        SET SP_STATUS = '200';
        SET MESSAGE = 'Fetched Report types successfully';
     ELSEIF v_role_type = 'Dealer' THEN
		SELECT DISTINCT report_type, report_id 
        FROM mmi_mast_report_type_dropdown_values 
        WHERE report_id IS NOT NULL and report_id !=1
        ORDER BY report_id;
        
        SET SP_STATUS = '200';
        SET MESSAGE = 'Fetched Report types successfully';
        
     END IF;   
  /*  ELSEIF type = 'onloadReportId' AND v_roleId = '1' THEN
  
        SELECT dropdown_value 
        FROM mmi_mast_report_type_dropdown_values 
        WHERE report_type = (SELECT report_type 
                            FROM mmi_mast_report_type_dropdown_values 
                            WHERE report_Id = v_report_Id
                            LIMIT 1)
        AND dropdown_value IS NOT NULL 
        AND dropdown_value != '';
  
        SET SP_STATUS = '200';
        SET MESSAGE = 'Fetched dropdown values successfully';*/
   
   ELSE
        SET SP_STATUS = '400';
        SET MESSAGE = CONCAT('Invalid type or role: ', type, ' / ', v_roleId);
    END IF;
END ;;
DELIMITER ;
