CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_role_feature_matrix`(
    IN p_json_data JSON,
    OUT p_status_code VARCHAR(50),
    OUT p_status_message VARCHAR(255)
)
BEGIN
    DECLARE v_role_name VARCHAR(100);
    DECLARE v_parent_code VARCHAR(100);
    DECLARE v_role_id INT;

    DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_role_feature_matrix', 'getRoleFeatureMatrix', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;

    SET v_role_name = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.roleName'));
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode'));
    IF v_role_name IS NULL OR v_role_name = '' THEN
            SET p_status_code = '300';
            SET p_status_message = 'Required Fields are missing';
    ELSE
    IF v_parent_code IS NOT NULL OR v_parent_code = '' THEN
			SELECT r.role_id INTO v_role_id
			FROM mmi_mast_role r
			LEFT JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id
			-- LEFT JOIN mmi_mast_dealer d ON d.parent_code = drm.parent_code
            LEFT JOIN mmi_dealer_location_mapping d ON d.parent_code = drm.parent_code
            LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = d.mapping_dealer_code
			WHERE r.role = v_role_name
			  AND d.parent_code = v_parent_code
			  AND r.status = '1'
			  AND drm.status = '1'
			  AND d.is_active = '1'
			LIMIT 1;
			IF v_role_id IS NULL OR v_role_id = '' THEN
				SET p_status_code = '300';
				SET p_status_message = 'Role is not present'; 
            ELSE
				SELECT DISTINCT
					f.id AS feature_id,
					f.features AS feature_name,
					a.id AS access_id,
					a.access_name,
					IF(m.id IS NOT NULL AND m.status = '1', '1', '0') AS status
				FROM mmi_mast_feature f
				CROSS JOIN mmi_mast_access_feature a
				LEFT JOIN mmi_user_feature_access_mapping m
				ON m.feature_id = f.id AND m.access_id = a.id AND m.role_id = v_role_id
				LEFT JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = m.role_id
				-- LEFT JOIN mmi_mast_dealer d ON d.parent_code = drm.parent_code
                LEFT JOIN mmi_dealer_location_mapping d ON d.parent_code = drm.parent_code
                LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = d.mapping_dealer_code
				where m.role_id = v_role_id and d.parent_code = v_parent_code and m.status=1;
				SET p_status_code = '200';
				SET p_status_message = 'Data Fetched Successfully';   
            END IF;
       ELSE
			SELECT r.role_id INTO v_role_id
			FROM mmi_mast_role r
			WHERE r.role = v_role_name AND r.status = '1' LIMIT 1;
            IF v_role_id IS NULL OR v_role_id = '' THEN
				SET p_status_code = '300';
				SET p_status_message = 'Role is not present'; 
            ELSE
				SELECT DISTINCT
					f.id AS feature_id,
					f.features AS feature_name,
					a.id AS access_id,
					a.access_name,
					IF(m.id IS NOT NULL AND m.status = '1', '1', '0') AS status
				FROM mmi_mast_feature f
				CROSS JOIN mmi_mast_access_feature a
				LEFT JOIN mmi_user_feature_access_mapping m
				ON m.feature_id = f.id AND m.access_id = a.id AND m.role_id = v_role_id
				LEFT JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = m.role_id
				where m.role_id = v_role_id and m.status=1;
                SET p_status_code = '200';
				SET p_status_message = 'Data Fetched Successfully';   
				END IF;
       END IF;     
END IF;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_get_role_feature_view` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
