/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_role_feature_view`(
    IN p_json_data JSON,
    OUT p_status_code VARCHAR(50),
    OUT p_status_message VARCHAR(255)
)
BEGIN
    DECLARE v_role_name VARCHAR(100);
    DECLARE v_parent_code VARCHAR(100);
    DECLARE v_role_id INT;

    DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(250); 
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
            
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_role_feature_view', 'getRoleFeatureView', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;

    SET v_role_name = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.roleName'));
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode'));
	-- IF v_role_name IS NULL OR v_role_name = '' OR v_parent_code IS NULL OR v_parent_code = '' THEN
     IF v_role_name IS NULL OR v_role_name = '' THEN
			SET p_status_code = '300';
            SET p_status_message = 'Required Fields are missing';
    ELSE
		IF v_parent_code IS NOT NULL THEN 
			SELECT r.role_id
			INTO v_role_id
			FROM mmi_mast_role r
			LEFT JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id
			-- LEFT JOIN mmi_mast_dealer d ON d.parent_code = drm.parent_code
            LEFT JOIN mmi_dealer_location_mapping d ON d.parent_code = drm.parent_code
            LEFT JOIN mmi_dealer_details dl on drm.dealer_code = dl.dealer_id -- ON dl.parent_code = drm.parent_code
			WHERE r.role = v_role_name
			  AND d.parent_code = v_parent_code
			  AND r.status = '1'
			  AND drm.status = '1'
			  AND d.is_active = '1'
			LIMIT 1;
         IF v_role_id IS NULL OR v_role_id = '' THEN
				SET p_status_code = '300';
				SET p_status_message = 'Role Is Not Present';
         ELSE   
				-- select distinct id,features from mmi_mast_feature;
				select distinct id,features from mmi_mast_feature where status = 1 
				and parent_feature_id IS NULL and features not in 
                ('Add & Setup Outlet','Admin Add','MIBL Role','System Configuration','MIBL User');
				select distinct id,access_name from mmi_mast_access_feature;
		
				SELECT DISTINCT
					f.id AS feature_id,
					f.features AS feature_name,
					a.id AS access_id,
					a.access_name,
					-- '1' AS status,
					m.status,
					r.role AS role_name,
					-- d.dealer_name AS dealer_name,
                    concat(dl.dealer_name,' - ',mdl.loc_name,' - ',dl.dealer_id) as dealer_name,
                    mr.role AS reportingRole,
                    mdrm.role_location AS location
				FROM mmi_user_feature_access_mapping m
				LEFT JOIN mmi_mast_feature f ON f.id = m.feature_id
				LEFT JOIN mmi_mast_access_feature a ON a.id = m.access_id
				LEFT JOIN mmi_mast_role r ON r.role_id = m.role_id
				LEFT JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id
				-- LEFT JOIN mmi_mast_dealer d ON d.parent_code = drm.parent_code
                LEFT JOIN mmi_dealer_details dl on drm.dealer_code = dl.dealer_id -- ON dl.parent_code = drm.parent_code
                LEFT JOIN mmi_mast_dealer_role_mapping mdrm ON mdrm.reporting_role_id = r.role_id
                LEFT JOIN mmi_mast_role mr ON mr.role_id = mdrm.role_id
                left join mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = dl.dealer_id
				left join mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
				WHERE m.role_id = v_role_id
				  AND m.status = '1';
                SET p_status_code = '200';
				SET p_status_message = 'Details Fetched Successfully';  
			END IF;	
		ELSE 
			-- SELECT r.role_id INTO v_role_id FROM mmi_mast_role r WHERE r.role = v_role_name 
			-- AND r.status = '1' LIMIT 1;
            SELECT r.role_id INTO v_role_id FROM mmi_mast_role r
			LEFT JOIN mmi_user_feature_access_mapping am ON am.role_id = r.role_id
			WHERE r.role = v_role_name
			  AND r.status = '1'
			  AND am.status = '1'
              AND am.role_type_id = 1
			LIMIT 1;
		IF v_role_id IS NULL OR v_role_id = '' THEN
				SET p_status_code = '300';
				SET p_status_message = 'Role Is Not Present';
        ELSE
				select distinct id,features from mmi_mast_feature where 
                parent_feature_id IS NULL and status = 1;
				select distinct id,access_name from mmi_mast_access_feature;
		
				SELECT 
					f.id AS feature_id,
					f.features AS feature_name,
					a.id AS access_id,
					a.access_name,
					m.status,
					r.role AS role_name,
                    f.parent_feature_id,
                    MAX(mr.role) AS reportingRole
				FROM mmi_user_feature_access_mapping m
				LEFT JOIN mmi_mast_feature f ON f.id = m.feature_id
				LEFT JOIN mmi_mast_access_feature a ON a.id = m.access_id
				LEFT JOIN mmi_mast_role r ON r.role_id = m.role_id
                LEFT JOIN mmi_mast_dealer_role_mapping mdrm ON mdrm.reporting_role_id = r.role_id
                LEFT JOIN mmi_mast_role mr ON mr.role_id = mdrm.role_id
				WHERE m.role_id = v_role_id
				  AND m.status = '1' AND mdrm.parent_code IS NULL
                GROUP BY f.id, f.features, a.id, a.access_name, m.status, r.role, 
                f.parent_feature_id;
                  
                select distinct id,parent_feature_id,features from mmi_mast_feature where 
				parent_feature_id IS NOT NULL and status = 1;
                
				SET p_status_code = '200';
				SET p_status_message = 'Details Fetched Successfully';
			END IF; 
        END IF;
   END IF;           
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
