DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_user_communication_modes`(
    IN p_json_data JSON,
    OUT p_status VARCHAR(500),
    OUT p_message VARCHAR(500)
)
BEGIN
    DECLARE v_cluster_id VARCHAR(50);
    DECLARE v_dealer_code VARCHAR(50);
    DECLARE v_parent_code VARCHAR(50);

    DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;

    -- Error handling
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        SET p_status = '500';
        SET p_message = 'An error occurred. Please try again.';

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_user_communication_modes', 'fetch_user_comm_modes', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    -- Extract input parameters from JSON
    SET v_cluster_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.cluster_id'));
    SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerCode'));
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode'));

    -- Validate mandatory input
    IF v_cluster_id IS NULL OR v_cluster_id = '' THEN
        SET p_status = '200';
        SET p_message = 'User ID cannot be empty or null';
    ELSE
        -- Fetch communication modes for the user
        SELECT DISTINCT
            communication AS communication_mode
        FROM mmi_dealer_details dl
        WHERE dl.cluster_id = v_cluster_id
          AND dl.dealer_id = v_dealer_code
          AND dl.parent_code = v_parent_code
          AND (FIND_IN_SET('Email', dl.communication) > 0 
               OR FIND_IN_SET('SMS', dl.communication) > 0
               OR FIND_IN_SET('WhatsApp', dl.communication) > 0);

        SET p_status = '200';
        SET p_message = 'Fetched communication modes successfully';
    END IF;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
