CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_user_details`(
	IN p_emailId VARCHAR(255)
)
BEGIN

	DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(250); 
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_user_details', 'getUserLoginDetails', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    IF p_emailId IS NULL or p_emailId = '' THEN
		SET err_code = MYSQL_ERRNO;
        SET err_code = MESSAGE_TEXT;
    ELSE
        select distinct mu.email_id,first_name,ad_flag,mu.user_id,mr.role,mu.last_login_date,
		mr.role_id,mu.calling_flag,udm.dealer_id,dlm.parent_code,dlm.marque,dl.otp_flag,
        mu.is_lock,mu.lead_flag,ugd.team_email_flag,mrt.role_type,ugd.sap_code,ugd.is_group
		-- GROUP_CONCAT(DISTINCT mm.menu_url) AS menu_urls
        -- GROUP_CONCAT(DISTINCT mf.features) AS features, 
        -- GROUP_CONCAT(DISTINCT maf.access_name) AS access_name 
        from mmi_mast_user mu 
		left join mmi_mast_user_registration_detail ugd on mu.user_id = ugd.id
		left join mmi_user_role_mapping urm on mu.user_id = urm.user_id
		left join mmi_mast_role mr on urm.role_id = mr.role_id
		left join mmi_user_dealer_mapping udm on mu.user_id = udm.user_id
		left join mmi_dealer_location_mapping dlm on dlm.dealer_code = udm.dealer_id
        left join mmi_dealer_details dl on udm.dealer_id = dl.dealer_id
		-- left join mmi_mast_dealer md on dlm.parent_code = md.parent_code
		left join mmi_menu_role_mapping mrm on mr.role_id = mrm.role_id
		left join mmi_mast_menu mm on mrm.menu_id = mm.menu_id
        left join mmi_user_feature_access_mapping ufam on mr.role_id = ufam.role_id
        left join mmi_mast_feature mf on ufam.feature_id = mf.id
        left join mmi_mast_access_feature maf on ufam.access_id = maf.id
        left join mmi_mast_role_type mrt on mrt.id = ugd.role_type_id
		where -- mu.email_id=p_emailId  -- and mrm.status =1 
        (mu.email_id = p_emailId OR ugd.mobile_no = p_emailId OR ugd.sap_code = p_emailId)
        and (mu.is_lock = 'U' OR mu.is_lock IS NULL) and mu.status=1 GROUP BY 
		mu.email_id, first_name, mu.ad_flag, mu.user_id, mr.role, mu.last_login_date,
		mr.role_id, mu.calling_flag, udm.dealer_id, dlm.parent_code,dlm.marque,dl.otp_flag LIMIT 1;
    END IF;
END ;;
DELIMITER ;
