CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_user_details_combined`(
    IN p_emailId VARCHAR(255),
    -- IN p_supervisorId VARCHAR(50),
    OUT p_status_code VARCHAR(500),
    OUT p_status_message VARCHAR(500),
    OUT p_user_details JSON,
    OUT p_feature_access JSON,
    OUT p_supervisor_data JSON
)
BEGIN
    DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(250);
    DECLARE v_roleId VARCHAR(255);
    DECLARE v_user_id INT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
        
        ROLLBACK;
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_user_details_combined', 'getUserDetailsCombined', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
        
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
    END;

    START TRANSACTION;
    
    -- Step 1: Get User Details
    IF p_emailId IS NULL OR p_emailId = '' THEN
        SET p_status_code = '300';
        SET p_status_message = 'Email ID is missing';
        ROLLBACK;
    ELSE
        -- Fetch user details (User ID and Role ID)
        SELECT DISTINCT mu.user_id, mu.email_id, first_name, ad_flag, mu.last_login_date,
            mr.role, mr.role_id, mu.calling_flag, udm.dealer_id, md.parent_code, md.marque, dl.otp_flag,
            mu.is_lock, mu.lead_flag, ugd.team_email_flag, mrt.role_type
        INTO v_user_id, p_user_details
        FROM mmi_mast_user mu
        LEFT JOIN mmi_mast_user_registration_detail ugd ON mu.user_id = ugd.id
        LEFT JOIN mmi_user_role_mapping urm ON mu.user_id = urm.user_id
        LEFT JOIN mmi_mast_role mr ON urm.role_id = mr.role_id
        LEFT JOIN mmi_user_dealer_mapping udm ON mu.user_id = udm.user_id
        LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.dealer_code = udm.dealer_id
        LEFT JOIN mmi_dealer_details dl ON udm.dealer_id = dl.dealer_id
        LEFT JOIN mmi_mast_dealer md ON dlm.parent_code = md.parent_code
        LEFT JOIN mmi_menu_role_mapping mrm ON mr.role_id = mrm.role_id
        LEFT JOIN mmi_mast_menu mm ON mrm.menu_id = mm.menu_id
        LEFT JOIN mmi_user_feature_access_mapping ufam ON mr.role_id = ufam.role_id
        LEFT JOIN mmi_mast_feature mf ON ufam.feature_id = mf.id
        LEFT JOIN mmi_mast_access_feature maf ON ufam.access_id = maf.id
        LEFT JOIN mmi_mast_role_type mrt ON mrt.id = ugd.role_type_id
        WHERE mu.email_id = p_emailId
          AND (mu.is_lock = 'U' OR mu.is_lock IS NULL)
          AND mu.status = 1
        GROUP BY mu.email_id, first_name, mu.ad_flag, mu.user_id, mr.role, mu.last_login_date,
            mr.role_id, mu.calling_flag, udm.dealer_id, md.parent_code, dl.otp_flag;

        -- If no user is found, return error message
        IF v_user_id IS NULL THEN
            SET p_status_code = '401';
            SET p_status_message = 'User not found';
            ROLLBACK;
        END IF;

        -- Get the Role ID
        SET v_roleId = (SELECT mr.role_id FROM mmi_user_role_mapping urm
                         LEFT JOIN mmi_mast_role mr ON urm.role_id = mr.role_id
                         WHERE urm.user_id = v_user_id LIMIT 1);
        
    END IF;

    -- Step 2: Get User Feature Access (using Role ID)
    IF v_roleId IS NULL OR v_roleId = '' THEN
        SET p_status_code = '300';
        SET p_status_message = 'Role ID is missing';
        ROLLBACK;
    ELSE
        -- Call the second procedure to fetch user feature access based on role
        CALL mmi_proc_get_user_feature_access(v_roleId);
        -- Assuming procedure mmi_proc_get_user_feature_access fills `p_feature_access`
    END IF;

    -- Step 3: Get Filtered Data by Supervisor
    IF v_user_id IS NULL OR v_user_id = '' THEN
        SET p_status_code = '300';
        SET p_status_message = 'Supervisor ID is missing';
        ROLLBACK;
    ELSE
        -- Call the third procedure to fetch filtered data by supervisor
        CALL mmi_proc_get_filtered_data_by_supervisor(v_user_id, p_status_code, p_status_message, p_supervisor_data);
    END IF;

    -- Final success
    SET p_status_code = '200';
    SET p_status_message = 'Success';
    COMMIT;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_get_user_details_combined1` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_user_details_combined1`(
    IN p_emailId VARCHAR(255),
    IN p_checkLoginType VARCHAR(255),
    OUT p_status_code VARCHAR(500),
    OUT p_status_message VARCHAR(500)
    -- OUT p_combined_result JSON
)
BEGIN 
	procedure_exit: BEGIN 
    DECLARE err_code VARCHAR(100); 
    DECLARE err_msg VARCHAR(250); 
    DECLARE v_roleId VARCHAR(255);
    DECLARE v_user_id INT; 
    DECLARE p_user_details JSON;
    DECLARE p_feature_access JSON;
    DECLARE p_supervisor_data JSON;
    DECLARE p_combined_result JSON;
    DECLARE current_datetime DATETIME;
    DECLARE v_exit_flag BOOLEAN DEFAULT FALSE;
    DECLARE v_check_password_updated_flag VARCHAR(100); 

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        -- Log error into error table
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_user_details_combined1', 'getUserDetailsCombined', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
        
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        
        -- Set JSON formatted error message
        SET p_combined_result = JSON_OBJECT(
			'msg', p_status_message,
			'status', p_status_code
		);

		SELECT p_combined_result;

    END;

    -- Step 1: Get the current date and time
    SET current_datetime = NOW();

    -- Step 2: Check if email and password are provided
    IF p_emailId IS NULL OR p_emailId = '' THEN
        SET p_status_code = '300';
        SET p_status_message = 'Email ID is missing';
        
        SET p_combined_result = JSON_OBJECT(
			'msg', p_status_message,
			'status', p_status_code
		);
		SELECT p_combined_result;
        ROLLBACK;
        LEAVE procedure_exit;
    END IF;

    -- Step 3: Check if the login (email and password) exists
    SELECT COUNT(*) INTO v_user_id
    FROM mmi_mast_user mu
	LEFT JOIN mmi_mast_user_registration_detail ugd ON mu.user_id = ugd.id
    WHERE -- mu.email_id = p_emailId 
    (mu.email_id = p_emailId OR ugd.sap_code = p_emailId OR ugd.mobile_no = p_emailId)
    AND (mu.is_lock = 'U' OR mu.is_lock IS NULL) AND mu.status = 1;

    -- If login does not exist, return error message
    IF v_user_id = 0 THEN
        SET p_status_code = '401';
        -- SET p_status_message = 'Invalid Email ID ';
        SET p_status_message = 'User Inactive or account locked please contact admin or dealer';
        
        SET p_combined_result = JSON_OBJECT(
			'msg', p_status_message,
			'status', p_status_code
		);
		SELECT p_combined_result;
        ROLLBACK;
        LEAVE procedure_exit;
    END IF;

    -- Step 4: Update the last login date to current time for the user
    -- UPDATE mmi_mast_user
    -- SET last_login_date = current_datetime
    -- WHERE email_id = p_emailId;
    

    -- Step 5: Fetch user details (User ID, Role, and other details)
    SELECT DISTINCT mu.user_id, JSON_OBJECT(
        'user_id', mu.user_id,
        'email', mu.email_id,
        'UserName', CONCAT(ugd.first_name, ' ', ugd.last_name),
        'adFlag', mu.ad_flag,
        'lastLoginDate', mu.last_login_date,
        'role', mr.role,
        'roleId', mr.role_id,
        'callingFlag', mu.calling_flag,
        'dealerCode', udm.dealer_id,
        'parentCode', dlm.parent_code,
        'marque', dlm.marque,
        'otp', dl.otp_flag,
        'is_lock', mu.is_lock,
        'lead_flag', mu.lead_flag,
        'team_email_flag', ugd.team_email_flag,
        'roleType', mrt.role_type,
        'sapCode', ugd.sap_code
        -- 'dealerName', concat(dl.dealer_name,' - ',mdl.loc_name,' - ',dl.dealer_id) -- from uat herek
    ) INTO v_user_id, p_user_details
    FROM mmi_mast_user mu
    LEFT JOIN mmi_mast_user_registration_detail ugd ON mu.user_id = ugd.id
    LEFT JOIN mmi_user_role_mapping urm ON mu.user_id = urm.user_id
    LEFT JOIN mmi_mast_role mr ON urm.role_id = mr.role_id
    LEFT JOIN mmi_user_dealer_mapping udm ON mu.user_id = udm.user_id
    LEFT JOIN mmi_dealer_location_mapping dlm ON dlm.dealer_code = udm.dealer_id
    LEFT JOIN mmi_dealer_details dl ON udm.dealer_id = dl.dealer_id
    -- LEFT JOIN mmi_mast_dealer md ON dlm.parent_code = md.parent_code
    LEFT JOIN mmi_mast_role_type mrt ON mrt.id = ugd.role_type_id
    WHERE -- mu.email_id = p_emailId 
    (mu.email_id = p_emailId OR ugd.sap_code = p_emailId OR ugd.mobile_no = p_emailId) and
    (mu.is_lock = 'U' OR mu.is_lock IS NULL) AND mu.status = 1;

    -- If no user is found after the login validation
    IF p_user_details IS NULL THEN
        SET p_status_code = '401';
        SET p_status_message = 'User not found';
        
        SET p_combined_result = JSON_OBJECT(
			'msg', p_status_message,
			'status', p_status_code
		);
        SELECT p_combined_result;
        ROLLBACK;
        LEAVE procedure_exit;
    END IF;

    -- Step 6: Get the Role ID
    SET v_roleId = (SELECT mr.role_id 
                    FROM mmi_user_role_mapping urm
                    LEFT JOIN mmi_mast_role mr ON urm.role_id = mr.role_id
                    WHERE urm.user_id = v_user_id LIMIT 1);

    -- Step 7: Get User Feature Access (using Role ID)
    IF v_roleId IS NULL OR v_roleId = '' THEN
        SET p_status_code = '300';
        SET p_status_message = 'RoleId not present';
        
        SET p_combined_result = JSON_OBJECT(
			'msg', p_status_message,
			'status', p_status_code
		);
        SELECT p_combined_result;
        ROLLBACK;
        LEAVE procedure_exit;
    ELSE
        -- Call procedure to fetch feature access based on role
        CALL mmi_proc_get_user_feature_access1(v_roleId, p_feature_access);
    END IF;

    -- Step 8: Get Filtered Data by Supervisor
    IF v_user_id IS NULL OR v_user_id = '' THEN
        SET p_status_code = '300';
        SET p_status_message = 'User Id not found';
        
        SET p_combined_result = JSON_OBJECT(
			'msg', p_status_message,
			'status', p_status_code
		);
        SELECT p_combined_result;
        ROLLBACK;
        LEAVE procedure_exit;
    ELSE
        -- Call procedure to fetch filtered data by supervisor
        CALL mmi_proc_get_filtered_data_by_supervisor1(v_user_id, p_status_code, p_status_message, p_supervisor_data);
    END IF;
    
    IF p_checkLoginType = 'Email' THEN
		select password_updated_flag INTO v_check_password_updated_flag from mmi_mast_user WHERE email_id = p_emailId;
        
        IF v_check_password_updated_flag = 'Y' THEN
			UPDATE mmi_mast_user
			SET last_login_date = current_datetime
			WHERE email_id = p_emailId;
        END IF;
        
    ELSEIF p_checkLoginType = 'SapCode' THEN
		SELECT DISTINCT u.password_updated_flag INTO v_check_password_updated_flag FROM mmi_mast_user u 
		JOIN mmi_mast_user_registration_detail r ON r.sap_code = p_emailId OR r.mobile_no = p_emailId
		WHERE u.user_id = r.id LIMIT 1;
		
        IF v_check_password_updated_flag = 'Y' THEN
			UPDATE mmi_mast_user u 
				JOIN mmi_mast_user_registration_detail r
				ON r.sap_code = p_emailId OR r.mobile_no = p_emailId
			SET 
				u.last_login_date = CURRENT_TIMESTAMP(),  -- Update last_login_date
				u.modified_date = NOW()
			WHERE u.user_id = r.id;
        END IF;    
    /*ELSEIF p_checkLoginType = 'Mobile' THEN
		UPDATE mmi_mast_user u 
			JOIN mmi_mast_user_registration_detail r
            ON r.mobile_no = p_emailId
        SET 
            u.last_login_date = CURRENT_TIMESTAMP(),  -- Update last_login_date
            u.modified_date = NOW()
        WHERE u.email_id = r.email_id;*/
     END IF;   

    IF ROW_COUNT() = 0 THEN
        SET p_status_code = '500';
        SET p_status_message = 'Failed to update last login date';
        
        SET p_combined_result = JSON_OBJECT(
			'msg', p_status_message,
			'status', p_status_code
		);
		SELECT p_combined_result;
        ROLLBACK;
        LEAVE procedure_exit;
    END IF; 
    

    -- Final success: Combine results into a JSON object
    SET p_combined_result = JSON_OBJECT(
        'userDetail', p_user_details,
        'FeatureAccess', p_feature_access,
        'fetchUserByManager', p_supervisor_data,
        'msg', p_status_message,
        'status', p_status_code
    );

    -- Return combined result as JSON
    SELECT p_combined_result;
    SET p_status_code = '200';
    SET p_status_message = JSON_OBJECT(
        'error_code', '200',
        'error_message', 'Details Fetched Successfully'
    );

    -- Label for exiting the procedure
    END procedure_exit;
    -- Nothing to do here as the procedure will exit
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_get_user_feature_access` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_user_feature_access`(
	IN p_roleId VARCHAR(255)
)
BEGIN
	DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(250);
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		ROLLBACK;
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_user_details', 'getUserLoginDetails', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
	START TRANSACTION;
    IF p_roleId IS NULL or p_roleId = '' THEN
		SET err_code = MYSQL_ERRNO;
        SET err_code = MESSAGE_TEXT;
    ELSE 
		SELECT DISTINCT m.menu_url,'ALL' AS features,'Public' AS access_name
		FROM mmi_mast_menu m WHERE m.is_common = 1 
		UNION
		SELECT DISTINCT m.menu_url, f.features,a.access_name
		FROM mmi_user_feature_access_mapping ufam
		LEFT JOIN mmi_mast_feature f ON ufam.feature_id = f.id
		LEFT JOIN mmi_mast_access_feature a ON ufam.access_id = a.id
		LEFT JOIN mmi_mast_feature_access_mapping fam ON fam.feature_id = f.id
		AND fam.access_id = ufam.access_id
		LEFT JOIN mmi_mast_menu m ON m.menu_id = fam.menu_id
		WHERE ufam.role_id = p_roleId and ufam.status=1 ORDER BY 2,1,3;
			-- ORDER BY f.id, m.menu_url, a.access_name;
	END IF;		
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
