CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_get_user_feature_access1`(
    IN p_roleId VARCHAR(255),
    OUT p_feature_access JSON
)
BEGIN
    DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(250);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_get_user_feature_access', 'getUserFeatureAccess', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

        SET p_feature_access = JSON_OBJECT('error', 'An error occurred. Please try again.');
    END;

    -- Get user feature access for the given roleId using CTE (Common Table Expression)
    WITH feature_access AS (
        SELECT 
			f.features, 
            m.menu_url, 
            a.access_name
        FROM mmi_user_feature_access_mapping ufam
        LEFT JOIN mmi_mast_feature f ON ufam.feature_id = f.id
        LEFT JOIN mmi_mast_access_feature a ON ufam.access_id = a.id
        LEFT JOIN mmi_mast_feature_access_mapping fam ON fam.feature_id = f.id
            AND fam.access_id = ufam.access_id
        LEFT JOIN mmi_mast_menu m ON m.menu_id = fam.menu_id
        WHERE ufam.role_id = p_roleId AND ufam.status = 1
    )
    
    -- Step 2: Concatenate the access names
    SELECT JSON_ARRAYAGG(
                JSON_OBJECT(
					'FeatureName', access_names.features,
                    'Url', access_names.menu_url,
                    'AccessName', access_names.access_name
                )
            ) INTO p_feature_access
    FROM (
        SELECT 
			features, 
            menu_url, 
            GROUP_CONCAT(DISTINCT access_name ORDER BY access_name SEPARATOR ', ') AS access_name
        FROM feature_access
        GROUP BY menu_url, features
        ORDER BY menu_url, features
    ) AS access_names;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
