CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_insert_customer_details`()
BEGIN
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_insert_customer_details', 'CUSTOMER_INSERT', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    START TRANSACTION;

    -- ✅ Step 1: UPDATE records where both chassis_no and engine_no match
    /*UPDATE mmi_mast_customer_details AS target
    JOIN mmi_ebm_policy_data AS source
        ON target.chassis_no = source.vin AND target.engine_no = source.engine_no
    SET
        target.cluster_id = source.cluster_id,
        target.customer_address = source.customer_address,
        target.customer_city = source.customer_city,
        target.customer_email = source.customer_email,
        target.customer_name = source.insured_name,
        target.customer_phone = source.customer_phone,
        target.customer_pincode = source.customer_pincode,
        target.customer_state = source.customer_state,
        target.vehicle_reg_no = source.vehicle_reg_no,
        target.status = '1',
        target.modified_by = 'SYSTEM',
        target.modified_date = NOW()
    WHERE source.engine_no IS NOT NULL;*/
    SET SQL_SAFE_UPDATES = 0;
    
    /*UPDATE mmi_mast_customer_details AS target
		JOIN (
		   SELECT vin, engine_no, cluster_id, customer_address, customer_city,
           customer_email, insured_name, customer_phone, customer_pincode,
           customer_state, vehicle_reg_no
			FROM mmi_ebm_policy_data AS source1
			WHERE engine_no IS NOT NULL
			AND (vin, engine_no, policy_expiry_date) IN (
				SELECT vin, engine_no, MAX(policy_expiry_date)
				FROM mmi_ebm_policy_data
				GROUP BY vin, engine_no)
		) AS latest_source
		ON TRIM(target.chassis_no) = TRIM(latest_source.vin)
		AND TRIM(target.engine_no) = TRIM(latest_source.engine_no)
		SET
			target.cluster_id = latest_source.cluster_id,
			target.customer_address = latest_source.customer_address,
			target.customer_city = latest_source.customer_city,
			target.customer_email = latest_source.customer_email,
			target.customer_name = latest_source.insured_name,
			target.customer_phone = latest_source.customer_phone,
			target.customer_pincode = latest_source.customer_pincode,
			target.customer_state = latest_source.customer_state,
			target.vehicle_reg_no = latest_source.vehicle_reg_no,
			target.status = '1',
			target.modified_by = 'SYSTEM',
			target.modified_date = NOW();*/
            
      WITH latest_source AS (
        SELECT vin, engine_no, cluster_id, customer_address, customer_city,
               customer_email, insured_name, customer_phone, customer_pincode,
               customer_state, vehicle_reg_no,
               ROW_NUMBER() OVER (PARTITION BY vin, engine_no ORDER BY policy_expiry_date DESC) AS rn
        FROM mmi_ebm_policy_data
        WHERE engine_no IS NOT NULL
    )
    UPDATE mmi_mast_customer_details AS target
    JOIN latest_source AS source
        ON target.chassis_no = source.vin
        AND target.engine_no = source.engine_no
        AND source.rn = 1
    SET
        target.cluster_id = source.cluster_id,
        target.customer_address = source.customer_address,
        target.customer_city = source.customer_city,
        target.customer_email = source.customer_email,
        target.customer_name = source.insured_name,
        target.customer_phone = source.customer_phone,
        target.customer_pincode = source.customer_pincode,
        target.customer_state = source.customer_state,
        target.vehicle_reg_no = source.vehicle_reg_no,
        target.status = '1',
        target.modified_by = 'SYSTEM',
        target.modified_date = NOW();        

    -- ✅ Step 2: INSERT new records if no match on chassis_no + engine_no
    INSERT INTO mmi_mast_customer_details (
        chassis_no, cluster_id, customer_address, customer_city, customer_email,
        customer_name, customer_phone, customer_pincode, customer_state, engine_no,
        status, vehicle_reg_no, created_by, created_date
    )
    SELECT
        source.vin AS chassis_no, source.cluster_id, source.customer_address, source.customer_city, source.customer_email,
        source.insured_name AS customer_name, source.customer_phone, source.customer_pincode, source.customer_state, source.engine_no,
        '1' AS status, source.vehicle_reg_no, 'SYSTEM', NOW()
    FROM mmi_ebm_policy_data AS source
    WHERE source.engine_no IS NOT NULL
      AND NOT EXISTS (
          SELECT 1
          FROM mmi_mast_customer_details AS target
          WHERE target.chassis_no = source.vin AND target.engine_no = source.engine_no
      );

    COMMIT;
END ;;
DELIMITER ;
