CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_insert_dealer_data`(
    IN p_dealer_code   VARCHAR(100),
    IN p_dealer_name   VARCHAR(100),
    IN p_parent_code   VARCHAR(50),
    IN p_source        VARCHAR(100),
    IN p_loc_code      VARCHAR(100),
    IN p_loc_name      VARCHAR(100),
    IN p_comm_address  VARCHAR(255),
    IN p_state         VARCHAR(100),
    IN p_city          VARCHAR(100),
    IN p_locality      VARCHAR(100),
	IN p_zone      VARCHAR(100)
)
BEGIN
    DECLARE errno INT DEFAULT 0; 
    DECLARE errmsg TEXT; 
    DECLARE exit handler FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            @sqlstate = RETURNED_SQLSTATE, errno = MYSQL_ERRNO, errmsg = MESSAGE_TEXT;
        ROLLBACK;
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, ERROR_TIMING, created_by, created_date
        ) VALUES (errno, CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg), 'mmi_proc_insert_dealer_data', 'Insert', CURRENT_TIMESTAMP(), 'SYSTEM', NOW());
    END;

    START TRANSACTION;

    -- Insert or Update Dealer if already exists based on dealer_name and parent_code
	IF EXISTS (
        SELECT 1 
        FROM mmi_mast_dealer 
        WHERE dealer_name = p_dealer_name 
          AND parent_code = p_parent_code
    ) THEN
        -- Update Dealer record if it exists
        UPDATE mmi_mast_dealer
        SET
            dealer_name = p_dealer_name,
            parent_code = p_parent_code,
            status = 1,
            modified_by = 'SYSTEM',
            modified_date = NOW()
        WHERE dealer_name = p_dealer_name 
          AND parent_code = p_parent_code;
    ELSE
        -- Insert new Dealer record if not found
        INSERT INTO mmi_mast_dealer (
            dealer_name, parent_code, status, is_active
        ) 
        VALUES (
            p_dealer_name, p_parent_code, 1, 1
        );
    END IF;

    -- Insert or Update Dealer Location if already exists based on loc_code and loc_name
    IF EXISTS (
        SELECT 1 
        FROM mmi_mast_dealer_location 
        WHERE loc_code = p_loc_code
    ) THEN
        -- Update Dealer Location if it exists
        UPDATE mmi_mast_dealer_location
        SET
            loc_name = p_loc_name,
            comm_address = p_comm_address,
            state = p_state,
            city = p_city,
            locality = p_locality,
            location_status = 1,
            modified_by = 'SYSTEM',
            modified_date = NOW()
        WHERE loc_code = p_loc_code;
    ELSE
        -- Insert new Dealer Location if not found
        INSERT INTO mmi_mast_dealer_location (
            loc_code, loc_name, comm_address, state, city, locality, location_status
        ) 
        VALUES (
            p_loc_code, p_loc_name, p_comm_address, p_state, p_city, p_locality, 1
        );
    END IF;

      -- Check if Dealer-Location Mapping already exists (based on dealer_code and loc_code)
    IF EXISTS (
        SELECT 1 
        FROM mmi_dealer_location_mapping 
        WHERE dealer_code = p_dealer_code AND location_code = p_loc_code
    ) THEN
        -- Update Dealer-Location Mapping if it exists
        UPDATE mmi_dealer_location_mapping
        SET
            
            source = p_source,
            parent_code = p_parent_code,
            dealer_name = p_dealer_name,
            zone = p_zone,
            modified_by = 'SYSTEM',
            modified_date = NOW()
        WHERE dealer_code = p_dealer_code AND location_code = p_loc_code;
    ELSE
        -- Insert new Dealer-Location Mapping if not found
        INSERT INTO mmi_dealer_location_mapping (
            dealer_code, status, source, location_code, parent_code, is_active, zone, dealer_name
        ) 
        VALUES (
            p_dealer_code, 1, p_source, p_loc_code, p_parent_code, 1, p_zone, p_dealer_name
        );
    END IF;  

    COMMIT;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_insert_feature_access_by_role_name` */;
