CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_insert_feature_access_by_role_name`(
    IN p_json_data JSON,
    OUT p_status_code VARCHAR(45),
    OUT p_status_message VARCHAR(500)
)
proc_block: BEGIN
    DECLARE v_type VARCHAR(20);
    DECLARE v_role_name VARCHAR(100);
    DECLARE v_parent_name VARCHAR(100);
    DECLARE v_parent_code VARCHAR(100);
    DECLARE v_role_id INT;
    DECLARE v_role_type_id INT;
    DECLARE v_reporting_role_name VARCHAR(100);
    DECLARE v_reporting_role_id INT;
    DECLARE v_parent_code_exists INT;
    DECLARE v_check_role_exists INT;
    DECLARE v_created_user_id INT;
    DECLARE v_role_location VARCHAR(100);
    DECLARE v_dealerCode VARCHAR(100);
    DECLARE v_check_dealerCode VARCHAR(100);

    DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(500);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_insert_feature_access_by_role_name', 'InsertRoleFeature', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    START TRANSACTION;

    -- Extract fields
    SET v_type = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.type'));
    SET v_role_name = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.roleName'));
    -- SET v_parent_name = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode'));
    SET v_parent_name = TRIM(SUBSTRING_INDEX(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode')),'-',1));
    SET v_check_dealerCode = TRIM(SUBSTRING_INDEX(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode')),'-',-1));
    SET v_reporting_role_name = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.reportingRole'));
    SET v_created_user_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.userId'));
	SET v_role_type_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.roleTypeId'));
    SET v_role_location = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.location'));
    
    -- Validate role
    IF v_role_name IS NULL OR v_role_name = '' OR LENGTH(v_role_name) > 100 THEN
        SET p_status_code = '400';
        SET p_status_message = 'Invalid or empty role name.';
        ROLLBACK;
        LEAVE proc_block;
    END IF;

    -- Check if role already exists
    SELECT COUNT(*) INTO v_check_role_exists
    FROM mmi_mast_role
    WHERE role = v_role_name;

    IF v_check_role_exists > 0 THEN
        SET p_status_code = '300';
        SET p_status_message = 'Role Already Present.';
        ROLLBACK;
        LEAVE proc_block;
    END IF;

    -- Insert role
    INSERT INTO mmi_mast_role (role, status, created_by) VALUES (v_role_name, '1', v_created_user_id);

    -- Get new role_id
    SELECT role_id INTO v_role_id
    FROM mmi_mast_role
    WHERE role = v_role_name
    ORDER BY role_id DESC
    LIMIT 1;

    -- Set role_level same as role_id
    UPDATE mmi_mast_role SET role_level = v_role_id WHERE role_id = v_role_id;

    -- Process only for DEALER type
    IF v_type = 'DEALER' THEN
        -- Validate parent_code (dealer_name)
        IF v_parent_name IS NULL OR v_parent_name = '' OR LENGTH(v_parent_name) > 100 THEN
            SET p_status_code = '400';
            SET p_status_message = 'Invalid or empty parent code.';
            ROLLBACK;
            LEAVE proc_block;
        END IF;

        SELECT COUNT(*) INTO v_parent_code_exists
        -- FROM mmi_mast_dealer
        FROM mmi_dealer_location_mapping
        WHERE dealer_name = v_parent_name;
        
        SELECT dlm.dealer_code INTO v_dealerCode 
        -- FROM mmi_mast_dealer md 
        FROM mmi_dealer_location_mapping dlm -- ON md.parent_code = dlm.parent_code
        LEFT JOIN mmi_dealer_details dl on dl.dealer_id = dlm.mapping_dealer_code
        LEFT JOIN mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
        -- WHERE md.dealer_name = v_parent_name and mdl.loc_name = v_role_location LIMIT 1;
		WHERE dl.dealer_id = v_check_dealerCode and mdl.loc_name = v_role_location LIMIT 1;
        
        IF v_parent_code_exists = 0 THEN
            SET p_status_code = '400';
            SET p_status_message = 'Invalid parent_code. Not found in mmi_mast_dealer.';
            ROLLBACK;
            LEAVE proc_block;
        END IF;

        -- SELECT parent_code INTO v_parent_code FROM mmi_mast_dealer WHERE dealer_name = v_parent_name;
        SELECT dlm.parent_code INTO v_parent_code 
        -- FROM mmi_mast_dealer md 
        FROM mmi_dealer_location_mapping dlm -- ON md.parent_code = dlm.parent_code
        LEFT JOIN mmi_dealer_details dl on dl.dealer_id = dlm.mapping_dealer_code
        LEFT JOIN mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
        -- WHERE md.dealer_name = v_parent_name and mdl.loc_name = v_role_location LIMIT 1;
        WHERE dl.dealer_id = v_check_dealerCode and mdl.loc_name = v_role_location LIMIT 1;

        -- Get reporting role id
        IF v_reporting_role_name IS NOT NULL AND v_reporting_role_name != '' THEN
            SELECT role_id INTO v_reporting_role_id
            FROM mmi_mast_role
            WHERE role = v_reporting_role_name
            LIMIT 1;
        ELSE
            SET v_reporting_role_id = NULL;
        END IF;

        -- Insert into dealer-role mapping
        INSERT INTO mmi_mast_dealer_role_mapping (role_id, parent_code, reporting_role_id,role_location, status, dealer_code, created_by)
        VALUES (v_role_id, v_parent_code, v_reporting_role_id,v_role_location, '1',v_dealerCode, v_created_user_id);
    ELSE
		IF v_reporting_role_name IS NOT NULL AND v_reporting_role_name != '' THEN
            SELECT role_id INTO v_reporting_role_id
            FROM mmi_mast_role
            WHERE role = v_reporting_role_name
            LIMIT 1;
        ELSE
            SET v_reporting_role_id = NULL;
        END IF;
        -- Insert into dealer-role mapping
        INSERT INTO mmi_mast_dealer_role_mapping (role_id, reporting_role_id, status, created_by)
        VALUES (v_role_id, v_reporting_role_id, '1', v_created_user_id);
        
	END IF;

    -- Insert feature-access mappings
    INSERT INTO mmi_user_feature_access_mapping (role_id, feature_id, access_id,role_type_id, status, created_by)
    SELECT
        v_role_id,
        jt.feature_id,
        jt.access_id,
        v_role_type_id,
        '1',
        v_created_user_id
    FROM JSON_TABLE(
        p_json_data,
        '$.featureAccessMappings[*]'
        COLUMNS (
            feature_id INT PATH '$.featureId',
            access_id INT PATH '$.accessId'
        )
    ) AS jt
    WHERE NOT EXISTS (
        SELECT 1
        FROM mmi_user_feature_access_mapping
        WHERE role_id = v_role_id
          AND feature_id = jt.feature_id
          AND access_id = jt.access_id
    );

    -- Logging
    INSERT INTO mmi_insert_log_details (
        service_name, user_id, log_payload,
        service_type, created_by, created_date
    ) VALUES (
        'mmi_proc_insert_feature_access_by_role_name',
        v_created_user_id,
        p_json_data,
        'INSERT',
        v_created_user_id,
        CURRENT_TIMESTAMP(3)
    );

    COMMIT;

    SET p_status_code = '200';
    SET p_status_message = 'Feature access mappings inserted successfully.';
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_insert_lead_breached_data` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
