CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_insert_lead_breached_data`()
BEGIN

DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error
        (
            error_code,
            error_message,
            procedure_name,
            procedure_type,
            error_timing,
            created_by,
            created_date
        )
        VALUES
        (
            err_code,
            err_msg,
            'mmi_proc_insert_lead_breached_data',
            'INSERT_LEAD_BREACHED_DETAILS',
            CURRENT_TIMESTAMP(),
            'SYSTEM',
            NOW()
        );
    END;

START TRANSACTION;

INSERT INTO mmi_lead_breached
(
    lead_id,
    breached_datetime,
    reason_for_breached,
    created_by,
    created_date
)
WITH latest_disposition AS
(
    SELECT *
    FROM
    (
        SELECT cdh.*,ROW_NUMBER() OVER (PARTITION BY lead_id ORDER BY id DESC) rn
        FROM mmi_call_disposition_history cdh
    ) t
    WHERE rn = 1
)

SELECT lead_id,NOW() AS breached_datetime,reason,'SYSTEM' AS created_by,NOW() AS created_date
FROM
(
    SELECT lead_id, reason,ROW_NUMBER() OVER (PARTITION BY lead_id ORDER BY priority) rn
    FROM
    (
        SELECT ld.lead_id, 'CallBack Scheduled TAT' AS reason, 1 AS priority
        FROM latest_disposition ld
        LEFT JOIN mmi_lead_details mld ON ld.lead_id = mld.lead_id
        WHERE ld.call_status = 'Callback Scheduled'
        AND NOW() > DATE_ADD(ld.next_call_datetime, INTERVAL 2 HOUR)
        AND NOW() > DATE_ADD(mld.lead_assignment_date_time, INTERVAL 2 HOUR)

        UNION ALL

        SELECT mld.lead_id, 'Hot Lead TAT', 2
        FROM mmi_lead_details mld
        WHERE mld.assigned_agent is not null and mld.lead_assignment_date_time <= NOW() + INTERVAL 1 DAY
        and mld.lead_type = 'Hot' 
        AND NOT EXISTS (
            SELECT 1
            FROM latest_disposition ld
            WHERE ld.lead_id = mld.lead_id
        )

        UNION ALL

        SELECT ld.lead_id, 'Ready To Pay TAT', 3
        FROM latest_disposition ld
        LEFT JOIN mmi_lead_details mld ON ld.lead_id = mld.lead_id
        LEFT JOIN mmi_agent_disposition_field_response adfr
            ON adfr.response_id = ld.id
            AND adfr.field_label = 'Sub Disposition'
        WHERE ld.call_status = 'Interested'
        AND adfr.field_value = 'Ready to Pay'
        AND NOW() > DATE_ADD(ld.next_call_datetime, INTERVAL 24 HOUR)
        AND NOW() > DATE_ADD(mld.lead_assignment_date_time, INTERVAL 24 HOUR)

        UNION ALL

        SELECT ld.lead_id, 'Awaiting Documents TAT', 4
        FROM latest_disposition ld
        LEFT JOIN mmi_lead_details mld ON ld.lead_id = mld.lead_id
        LEFT JOIN mmi_agent_disposition_field_response adfr
            ON adfr.response_id = ld.id
            AND adfr.field_label = 'Sub Disposition'
        WHERE ld.call_status = 'Interested'
        AND adfr.field_value = 'Awaiting Documents'
        AND NOW() > DATE_ADD(ld.next_call_datetime, INTERVAL 24 HOUR)
        AND NOW() > DATE_ADD(mld.lead_assignment_date_time, INTERVAL 24 HOUR)

        UNION ALL

        SELECT mld.lead_id, 'Warm Lead TAT', 5
        FROM mmi_lead_details mld
        WHERE mld.assigned_agent is not null and mld.lead_assignment_date_time <= NOW() + INTERVAL 2 DAY
        and mld.lead_type = 'Warm'
        AND NOT EXISTS (
            SELECT 1
            FROM latest_disposition ld
            WHERE ld.lead_id = mld.lead_id
        )
    ) t
) x
WHERE rn = 1
AND NOT EXISTS (
    SELECT 1
    FROM mmi_lead_breached lb
    WHERE lb.lead_id = x.lead_id
);

COMMIT;

END ;;
DELIMITER ;
