CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_insert_lead_tat_escalation`()
BEGIN

    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error
        (
            error_code,
            error_message,
            procedure_name,
            procedure_type,
            error_timing,
            created_by,
            created_date
        )
        VALUES
        (
            err_code,
            err_msg,
            'mmi_proc_insert_lead_tat_escalation',
            'INSERT_LEAD_TAT_ESCALATION',
            NOW(),
            'SYSTEM',
            NOW()
        );
    END;

    START TRANSACTION;
    INSERT INTO mmi_lead_tat_escalation (
        lead_id,
        assigned_agent_id,
        tat_due_datetime,
        hours_past_tat,
        escalation_level,
        escalated_to_name,
        escalated_to_user_id,
        reason
    )
    WITH RECURSIVE user_hierarchy AS (
    SELECT user_id AS agent_id, supervisor_id, 1 AS lvl
    FROM mmi_user_reporting

    UNION ALL

    SELECT uh.agent_id, ur.supervisor_id, uh.lvl + 1
    FROM user_hierarchy uh
    JOIN mmi_user_reporting ur 
        ON ur.user_id = uh.supervisor_id
    WHERE uh.lvl < 10
),

user_hierarchy_dedup AS (
    SELECT agent_id, supervisor_id, lvl,
           ROW_NUMBER() OVER (PARTITION BY agent_id, lvl) rn
    FROM user_hierarchy
),

latest_breach AS (
    SELECT lead_id, MAX(breached_datetime) AS breached_datetime
    FROM mmi_lead_breached
    GROUP BY lead_id
),

tat_calc AS (
    SELECT 
        mld.lead_id,
        mld.assigned_agent,
        lb.breached_datetime,
        TIMESTAMPDIFF(HOUR, lb.breached_datetime, NOW()) AS hours_past_tat
    FROM mmi_lead_details mld
    LEFT JOIN latest_breach lb 
        ON lb.lead_id = mld.lead_id
    WHERE mld.assigned_agent IS NOT NULL
)

SELECT
    t.lead_id,
    t.assigned_agent,
    t.breached_datetime,
    t.hours_past_tat,
    CASE
        WHEN t.hours_past_tat >= 24 THEN 'Level 3'
        WHEN t.hours_past_tat >= 4 THEN 'Level 2'
        WHEN t.hours_past_tat >= 1 THEN 'Level 1'
    END AS escalation_level,
    CASE
        WHEN t.hours_past_tat >= 24 THEN COALESCE(ho_user.first_name, manager_user.first_name, tl_user.first_name)
        WHEN t.hours_past_tat >= 4 THEN COALESCE(manager_user.first_name, tl_user.first_name)
        WHEN t.hours_past_tat >= 1 THEN tl_user.first_name
    END AS escalated_to_name,
    CASE
            WHEN t.hours_past_tat >= 24 THEN COALESCE(ho_user.id, manager_user.id, tl_user.id)
            WHEN t.hours_past_tat >= 4 THEN COALESCE(manager_user.id, tl_user.id)
            WHEN t.hours_past_tat >= 1 THEN tl_user.id
        END AS escalated_to_user_id,
        'TAT Missed - Followup not done' AS reason
FROM tat_calc t
LEFT JOIN user_hierarchy_dedup tl 
    ON tl.agent_id = t.assigned_agent AND tl.lvl = 1 AND tl.rn = 1
LEFT JOIN user_hierarchy_dedup manager 
    ON manager.agent_id = t.assigned_agent AND manager.lvl = 2 AND manager.rn = 1
LEFT JOIN user_hierarchy_dedup ho 
    ON ho.agent_id = t.assigned_agent AND ho.lvl = 3 AND ho.rn = 1
LEFT JOIN mmi_mast_user_registration_detail tl_user 
    ON tl_user.id = tl.supervisor_id
LEFT JOIN mmi_mast_user_registration_detail manager_user 
    ON manager_user.id = manager.supervisor_id
LEFT JOIN mmi_mast_user_registration_detail ho_user 
    ON ho_user.id = ho.supervisor_id
WHERE t.breached_datetime IS NOT NULL
  AND t.hours_past_tat >= 1
  AND NOT EXISTS (
      SELECT 1
      FROM mmi_lead_tat_escalation lte
      WHERE lte.lead_id = t.lead_id
        AND lte.escalation_status = 'OPEN'
  );

    COMMIT;

END ;;
DELIMITER ;
