CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_insert_new_user_details`(
    IN p_user_data JSON,
    OUT p_status_code VARCHAR(50),
    OUT p_status_message VARCHAR(255)
)
BEGIN
    -- Declare necessary variables
    procedure_end: BEGIN
    DECLARE v_firstname VARCHAR(100); 
    DECLARE v_lastname VARCHAR(100);
    DECLARE v_contactinfo VARCHAR(15);
    DECLARE v_emailid VARCHAR(255); 
    DECLARE v_status VARCHAR(20); 
    DECLARE v_userID INT;
    DECLARE v_dealerName VARCHAR(50);
    DECLARE v_location VARCHAR(100);
    DECLARE v_roleID INT;
    DECLARE v_reportingManager VARCHAR(100);
    DECLARE v_bucket_name VARCHAR(1000); 
    DECLARE v_callingFlag CHAR(1);
    DECLARE v_check_email_exist VARCHAR(255);
	DECLARE v_check_mobile_exist VARCHAR(15);  -- Mobile number check variable
    DECLARE v_parent_code VARCHAR(255);
    DECLARE v_bucket_id VARCHAR(255);
    DECLARE v_dealerCode VARCHAR(50);
    DECLARE v_lead_flag VARCHAR(50);
    DECLARE v_team_email_flag VARCHAR(10);
    DECLARE v_reportingManager_Id INT DEFAULT 0;
    DECLARE v_role_name VARCHAR(50);
	DECLARE v_role_id INT;
    DECLARE v_ad_flag Varchar(10);
    DECLARE v_password Varchar(200);
    DECLARE v_created_user_id Varchar(10);
    DECLARE v_role_type Varchar(10);
    DECLARE v_role_type_id INT;
    DECLARE v_sap_code VARCHAR(100);
    DECLARE v_check_sap_code_exist VARCHAR(255);
    DECLARE v_email_flag VARCHAR(100);
    DECLARE v_is_group VARCHAR(10);
    
    -- Declare variables for error logging
    DECLARE v_error_code VARCHAR(50);
    DECLARE v_error_message VARCHAR(255);
    DECLARE v_procedure_name VARCHAR(100) DEFAULT 'mmi_proc_insert_new_user_details';
    DECLARE v_procedure_type VARCHAR(50) DEFAULT 'INSERT';
    DECLARE v_error_timing VARCHAR(50) DEFAULT CURRENT_TIMESTAMP();

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        -- Capture warning details
        GET DIAGNOSTICS CONDITION 1
            v_error_code = MYSQL_ERRNO,
            v_error_message = MESSAGE_TEXT;
            
		
        SET p_status_code = '300';
        SET p_status_message = 'Something Went Wrong.';
        ROLLBACK;
        -- Log the warning in the procedure error table
        INSERT INTO mmi_mast_procedure_error (error_code, error_message, procedure_name, procedure_type, ERROR_TIMING, created_by, created_date)
        VALUES (v_error_code, v_error_message, v_procedure_name, v_procedure_type, v_error_timing, 'SYSTEM', NOW());        
        
        END;

    START TRANSACTION;

    -- Extract values from JSON input
    SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.roleType'));
    SET v_firstname = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.firstname'));
    SET v_lastname = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.lastname'));
    SET v_contactinfo = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.contactinfo'));
    SET v_emailid = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.emailid'));
    SET v_status = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.status'));
    -- SET v_dealerName = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.dealerCode'));
	SET v_dealerName = TRIM(SUBSTRING_INDEX(JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.dealerCode')),'-',-1));
    SET v_location = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.location'));
    SET v_roleID = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.roleID'));
    SET v_reportingManager = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.manager'));
    SET v_callingFlag = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.callingFlag'));
    SET v_bucket_name = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.leadPool'));
    SET v_team_email_flag = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.teamEmail'));
    SET v_role_name = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.roleName'));
	SET v_ad_flag = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.adFlag'));
	SET v_created_user_id  = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.userId'));
    SET v_password = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.encryptedPassword'));
    SET v_sap_code = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.sapCode'));
    SET v_email_flag = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.emailFlag'));
    SET v_is_group = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.isGroup'));
    
    -- Check if required fields are missing
    IF v_firstname IS NULL OR v_lastname IS NULL OR v_contactinfo IS NULL OR v_emailid IS NULL OR v_is_group IS NULL OR v_status IS NULL THEN
        SET p_status_code = '400';  -- Bad Request
        SET p_status_message = 'Required fields are missing.';
        -- ROLLBACK;
    ELSE
		select id INTO v_role_type_id from mmi_mast_role_type where role_type = v_role_type;
		IF v_role_type = 'DEALER' THEN
        -- Check if email already exists
        SELECT email_id INTO v_check_email_exist FROM mmi_mast_user_registration_detail WHERE email_id = v_emailid LIMIT 1;
		SELECT mobile_no INTO v_check_mobile_exist FROM mmi_mast_user_registration_detail WHERE mobile_no = v_contactinfo LIMIT 1;
        
        -- Get dealer code from dealer name
        -- SELECT dlm.dealer_code INTO v_dealerCode FROM mmi_mast_dealer md 
        -- LEFT JOIN mmi_dealer_location_mapping dlm ON md.parent_code = dlm.parent_code
        -- WHERE md.dealer_name = v_dealerName LIMIT 1; 
        SELECT dlm.dealer_code INTO v_dealerCode 
        -- FROM mmi_mast_dealer md 
        FROM mmi_dealer_location_mapping dlm -- ON md.parent_code = dlm.parent_code
        LEFT JOIN mmi_dealer_details dl on dl.dealer_id = dlm.mapping_dealer_code
        LEFT JOIN mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
        -- WHERE dlm.dealer_name = v_dealerName and mdl.loc_name = v_location LIMIT 1;
        WHERE dl.dealer_id = v_dealerName and mdl.loc_name = v_location LIMIT 1;

        -- Check if email exists or dealer details are missing
        IF v_is_group = 'N' THEN
			IF v_check_email_exist IS NOT NULL THEN
				SET p_status_code = '300'; 
				SET p_status_message = 'Email ID Already Exists';
				ROLLBACK;  -- Rollback if email exists
				LEAVE procedure_end;
			END IF;
        END IF;
        IF v_dealerCode IS NULL OR v_dealerCode = '' THEN
            SET p_status_code = '300';
            SET p_status_message = 'Dealer Details Not Exist';
            -- ROLLBACK;  -- Rollback if dealer code is missing
        ELSEIF v_check_mobile_exist IS NOT NULL THEN 
			SET p_status_code = '300'; 
            SET p_status_message = 'Mobile Number Already Exists';
        ELSE 
            -- Proceed with insertion of user data
            INSERT INTO mmi_mast_user_registration_detail (first_name, last_name, mobile_no, email_id, address, status, team_email_flag,role_type_id, is_group,created_by)
            VALUES (v_firstname, v_lastname, v_contactinfo, v_emailid, v_location, v_status, v_team_email_flag,v_role_type_id,v_is_group,v_created_user_id);

            -- Get the user ID after insertion
            SET v_userID = LAST_INSERT_ID();

            -- Handle calling flag and insert corresponding data
            IF v_callingFlag = 'Y' THEN
                -- SELECT id INTO v_bucket_id FROM mmi_mast_bucket WHERE bucket_name = v_bucket_name LIMIT 1;
                INSERT INTO mmi_mast_user (user_id, email_id, status, calling_flag, ad_flag, password, is_lock,created_by)
                VALUES (v_userID, v_emailid, v_status, v_callingFlag, v_ad_flag, v_password,'U',v_created_user_id);
                -- INSERT INTO mmi_bucket_user_mapping (bucket_id, user_id)
                -- VALUES (v_bucket_id, v_userID);
                
                -- INSERT INTO mmi_bucket_user_mapping (bucket_id, user_id)
				-- SELECT b.id, v_userID
				-- FROM mmi_mast_bucket b
				-- WHERE b.bucket_name IN (v_bucket_name);
                IF v_bucket_name IS NOT NULL OR v_bucket_name != '' THEN
                INSERT INTO mmi_bucket_user_mapping (bucket_id, user_id, created_by)
    SELECT b.id, v_userID, v_created_user_id
    FROM JSON_TABLE(
            v_bucket_name, 
            '$[*]' COLUMNS (bucket_name VARCHAR(255) PATH '$')
        ) AS jt
    JOIN mmi_mast_bucket b 
    ON b.bucket_name = jt.bucket_name
    AND b.dealer_code = v_dealerCode;
    END IF;
                
            ELSEIF v_callingFlag = 'N' THEN
                SET v_lead_flag = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.leadsFlag'));
                INSERT INTO mmi_mast_user (user_id, email_id, status, calling_flag, lead_flag, ad_flag, password, is_lock,created_by)
                VALUES (v_userID, v_emailid, v_status,v_callingFlag, v_lead_flag, v_ad_flag, v_password,'U',v_created_user_id);
            END IF;

            -- Insert user dealer mapping
            INSERT INTO mmi_user_dealer_mapping (user_id, dealer_id,created_by)
            VALUES (v_userID, v_dealerCode,v_created_user_id);

            -- Insert user role mapping
            IF v_role_name IS NOT NULL THEN
				select role_id into v_role_id from mmi_mast_role where role =  v_role_name LIMIT 1;
					IF v_role_id IS NOT NULL THEN
						INSERT INTO mmi_user_role_mapping (user_id, role_id, status,created_by)
						VALUES (v_userID, v_role_id, '1',v_created_user_id);
					END IF;
            END IF;

            -- Insert user reporting mapping if reporting manager is provided
            -- 
            IF v_reportingManager IS NOT NULL AND v_reportingManager!='' THEN
                -- SELECT id INTO v_reportingManager_Id FROM mmi_mast_user_registration_detail 
                -- WHERE first_name = v_reportingManager LIMIT 1;
                -- WHERE CONCAT(first_name , ' ', last_name) = v_reportingManager LIMIT 1;
                SELECT urd.id INTO v_reportingManager_Id FROM mmi_mast_user_registration_detail urd 
				LEFT JOIN mmi_user_dealer_mapping udm on udm.user_id = urd.id 
                WHERE CONCAT(first_name , ' ', last_name) = v_reportingManager 
                AND dealer_id = v_dealerCode LIMIT 1;
                
                INSERT INTO mmi_user_reporting (user_id, supervisor_id, created_by)
                VALUES (v_userID, v_reportingManager_Id,v_created_user_id);
            END IF;
			
            INSERT INTO mmi_insert_log_details (service_name,user_id,log_payload,
			service_type,created_by,created_date) 
			VALUES ('mmi_proc_insert_new_user_details',v_created_user_id,
			p_user_data,v_role_type,v_created_user_id,CURRENT_TIMESTAMP(3));
            
            -- Set success status
            SET p_status_code = '200';
            SET p_status_message = 'Data inserted successfully.';
       END IF;
        ELSE
            -- Check if email already exists
        SELECT email_id INTO v_check_email_exist FROM mmi_mast_user_registration_detail WHERE email_id = v_emailid LIMIT 1;
		SELECT mobile_no INTO v_check_mobile_exist FROM mmi_mast_user_registration_detail WHERE mobile_no = v_contactinfo LIMIT 1;
        SELECT sap_code INTO v_check_sap_code_exist FROM mmi_mast_user_registration_detail WHERE sap_code = v_sap_code LIMIT 1;
        
        -- Check if email exists or dealer details are missing
        IF v_is_group = 'N' THEN
			IF v_check_email_exist IS NOT NULL THEN
				SET p_status_code = '300'; 
				SET p_status_message = 'Email ID Already Exists';
				ROLLBACK;  -- Rollback if email exists
				LEAVE procedure_end; 
			END IF;
        END IF;    
        IF v_check_mobile_exist IS NOT NULL THEN 
			SET p_status_code = '300'; 
            SET p_status_message = 'Mobile Number Already Exists';
		ELSEIF v_check_sap_code_exist IS NOT NULL THEN 
			SET p_status_code = '300'; 
            SET p_status_message = 'SAP Code Already Exists';  
        ELSE 
            -- Proceed with insertion of user data
            INSERT INTO mmi_mast_user_registration_detail (first_name, last_name, mobile_no, email_id, address, status, team_email_flag,role_type_id,sap_code,is_group,created_by)
            VALUES (v_firstname, v_lastname, v_contactinfo, v_emailid, v_location, v_status, v_team_email_flag,v_role_type_id,v_sap_code,v_is_group,v_created_user_id);

            -- Get the user ID after insertion
            SET v_userID = LAST_INSERT_ID();

           INSERT INTO mmi_mast_user (user_id, email_id, status,calling_flag,ad_flag, password, is_lock,created_by)
           VALUES (v_userID, v_emailid, v_status,'N', v_ad_flag, v_password,'U',v_created_user_id);

            -- Insert user role mapping
            IF v_role_name IS NOT NULL THEN
				select role_id into v_role_id from mmi_mast_role where role =  v_role_name LIMIT 1;
					IF v_role_id IS NOT NULL THEN
						INSERT INTO mmi_user_role_mapping (user_id, role_id, status, created_by)
						VALUES (v_userID, v_role_id, '1',v_created_user_id);
					END IF;
            END IF;

            -- Insert user reporting mapping if reporting manager is provided
            -- 
            IF v_reportingManager IS NOT NULL AND v_reportingManager!='' THEN
                SELECT id INTO v_reportingManager_Id FROM mmi_mast_user_registration_detail 
                -- WHERE first_name = v_reportingManager LIMIT 1;
                WHERE CONCAT(first_name , ' ', last_name) = v_reportingManager LIMIT 1;
                
                INSERT INTO mmi_user_reporting (user_id, supervisor_id, created_by)
                VALUES (v_userID, v_reportingManager_Id,v_created_user_id);
            END IF;
			
            INSERT INTO mmi_insert_log_details (service_name,user_id,log_payload,
			service_type,created_by,created_date) 
			VALUES ('mmi_proc_insert_new_user_details',v_created_user_id,
			p_user_data,v_role_type,v_created_user_id,CURRENT_TIMESTAMP(3));
            
			
			SET p_status_code = '200';
            SET p_status_message = 'Data inserted successfully.';
          END IF;  
        END IF;
    END IF;

    -- Commit if no errors occurred
    IF p_status_code = '200' THEN
        COMMIT;
    END IF;
	END procedure_end;
END ;;
DELIMITER ;
