DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_lead_bulk_reassign`(
    IN Json_data JSON,
    IN type VARCHAR(45),
    OUT SP_STATUS VARCHAR(500),
    OUT MESSAGE VARCHAR(500)
)
proc_main: BEGIN
    -- Variables
    DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 0;
    DECLARE calculated INT DEFAULT 0;
    DECLARE flagVal VARCHAR(50);
    DECLARE leadIndex INT DEFAULT 0;
    DECLARE leadCount INT DEFAULT 0;
    DECLARE agentIdVal INT DEFAULT 0;
    DECLARE leadIdVal INT;
    
    DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(500);
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
        SET SP_STATUS = '500';
        SET MESSAGE = 'An error occurred. Please try again.';
        ROLLBACK;
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_lead_bulk_reassign', 'BulkLeadAssign', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
	START TRANSACTION;
    -- Type validation
    IF type IS NULL OR TRIM(type) = '' THEN
        SET SP_STATUS = '1003';
        SET MESSAGE = 'Type not provided or empty.';
        LEAVE proc_main;
    END IF;

    -- Extract pagination and flag safely
    SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.limit')) AS UNSIGNED), 10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.offset')) AS UNSIGNED), 0);
    SET calculated = (offsetVal - 1) * limitVal;
    IF calculated < 0 THEN
        SET calculated = 0;
    END IF;

    SET flagVal = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.flag'));

    IF flagVal = '' THEN
        SET SP_STATUS = '1001';
        SET MESSAGE = 'Flag not provided or empty.';
        LEAVE proc_main;
    END IF;

    -- Main logic
    IF type = 'leadList' THEN

        IF flagVal = 'assigned' THEN            

            -- Assigned List Based on Dealer Code and UserId	
            WITH RECURSIVE subordinates AS 
            (
                SELECT ur.user_id  
                FROM mmi_user_reporting ur 
                WHERE ur.supervisor_id <> JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
                UNION ALL
                SELECT ur.user_id 
                FROM mmi_user_reporting ur 
                INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
            )

            SELECT DISTINCT
                mc.customer_name,
                ml.dealer_code,
                ml.lead_id,
                ml.model,
                CONCAT(urd.first_name, ' ', urd.last_name) AS AgentName,
                ml.renewal_category,
                ml.policy_expiry_date,
                ml.expiry_days,
                sa.invoice_date_time,
                urd.id AS AgentId
            FROM mmi_lead_details ml
            INNER JOIN subordinates s ON ml.assigned_agent = s.user_id
            LEFT JOIN mmi_mast_customer_details mc ON mc.cluster_id = ml.cluster_id
            LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent 
            LEFT JOIN mmi_ebm_sales_data sa ON ml.engine_no = sa.engine_number
            WHERE ml.dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
            ORDER BY ml.policy_expiry_date
            LIMIT limitVal OFFSET calculated;

            -- Assigned List Count Based on Dealer Code and UserId	
            WITH RECURSIVE subordinates AS 
            (
                SELECT ur.user_id  
                FROM mmi_user_reporting ur 
                WHERE ur.supervisor_id <> JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
                UNION ALL
                SELECT ur.user_id 
                FROM mmi_user_reporting ur 
                INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
            )

            SELECT COUNT(DISTINCT ml.lead_id) AS listCount
            FROM mmi_lead_details ml
            INNER JOIN subordinates s ON ml.assigned_agent = s.user_id
            LEFT JOIN mmi_mast_customer_details mc ON mc.cluster_id = ml.cluster_id
            LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent 
            LEFT JOIN mmi_ebm_sales_data sa ON ml.engine_no = sa.engine_number
            WHERE ml.dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
   
   -- ********** MyLeads List and Count **************************
   ELSEIF flagVal = 'myLeads' THEN            

            -- Assigned List Based on Dealer Code and UserId	
            WITH RECURSIVE subordinates AS 
            (
                SELECT ur.user_id  
                FROM mmi_user_reporting ur 
                WHERE ur.supervisor_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
                UNION ALL
                SELECT ur.user_id 
                FROM mmi_user_reporting ur 
                INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
            )

            SELECT DISTINCT
                mc.customer_name,
                ml.dealer_code,
                ml.lead_id,
                ml.model,
                CONCAT(urd.first_name, ' ', urd.last_name) AS AgentName,
                ml.renewal_category,
                ml.policy_expiry_date,
                ml.expiry_days,
                sa.invoice_date_time,
                urd.id AS AgentId
            FROM mmi_lead_details ml
            INNER JOIN subordinates s ON ml.assigned_agent = s.user_id
            LEFT JOIN mmi_mast_customer_details mc ON mc.cluster_id = ml.cluster_id
            LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent 
            LEFT JOIN mmi_ebm_sales_data sa ON ml.engine_no = sa.engine_number
            WHERE ml.dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
            ORDER BY ml.policy_expiry_date
            LIMIT limitVal OFFSET calculated;

            -- Assigned List Count Based on Dealer Code and UserId	
            WITH RECURSIVE subordinates AS 
            (
                SELECT ur.user_id  
                FROM mmi_user_reporting ur 
                WHERE ur.supervisor_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
                UNION ALL
                SELECT ur.user_id 
                FROM mmi_user_reporting ur 
                INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
            )

            SELECT COUNT(DISTINCT ml.lead_id) AS listCount
            FROM mmi_lead_details ml
            INNER JOIN subordinates s ON ml.assigned_agent = s.user_id
            LEFT JOIN mmi_mast_customer_details mc ON mc.cluster_id = ml.cluster_id
            LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent 
            LEFT JOIN mmi_ebm_sales_data sa ON ml.engine_no = sa.engine_number
            WHERE ml.dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));

	 ELSEIF flagVal = 'unassigned' THEN           

SELECT 
	mc.customer_name, ml.lead_id, ml.model,
	CONCAT(urd.first_name, ' ', urd.last_name) AS AgentName,
	ml.renewal_category,ml.policy_expiry_date,ml.expiry_days, sa.invoice_date_time
	,IFNULL(urd.id, '') AS AgentId
FROM mmi_mast_customer_details mc 
LEFT JOIN mmi_lead_details ml ON mc.cluster_id = ml.cluster_id
LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent 
LEFT JOIN mmi_ebm_sales_data sa ON ml.engine_no = sa.engine_number
	WHERE 
	ml.dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
	AND urd.id IS NULL
	ORDER BY ml.policy_expiry_date
	LIMIT limitVal OFFSET calculated;

SELECT COUNT(*) AS listCount
		FROM mmi_mast_customer_details mc 
		LEFT JOIN mmi_lead_details ml ON mc.cluster_id = ml.cluster_id
		LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent 
		LEFT JOIN mmi_ebm_sales_data sa ON ml.engine_no = sa.engine_number
WHERE 
		ml.dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
		AND urd.id IS NULL
		ORDER BY ml.policy_expiry_date;

        END IF;
--
ELSEIF type = 'leadCount' THEN

 -- All 3 counts: assigned, unassigned, myLeads
        SELECT
            (SELECT COUNT(ml.lead_id) FROM mmi_lead_details ml
             WHERE ml.dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
             AND ml.assigned_agent IS NULL) AS unassignedCount,

            (SELECT COUNT(DISTINCT ml.lead_id) 
             FROM mmi_lead_details ml
             INNER JOIN (
                WITH RECURSIVE subordinates AS (
                    SELECT ur.user_id FROM mmi_user_reporting ur 
                    WHERE ur.supervisor_id <> JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
                    UNION ALL
                    SELECT ur.user_id FROM mmi_user_reporting ur 
                    INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
                ) SELECT * FROM subordinates
             ) AS s ON ml.assigned_agent = s.user_id
             WHERE ml.dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
            ) AS assignedCount,

            (SELECT COUNT(DISTINCT ml.lead_id) 
             FROM mmi_lead_details ml
             INNER JOIN (
                WITH RECURSIVE subordinates AS (
                    SELECT ur.user_id FROM mmi_user_reporting ur 
                    WHERE ur.supervisor_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
                    UNION ALL
                    SELECT ur.user_id FROM mmi_user_reporting ur 
                    INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
                ) SELECT * FROM subordinates
             ) AS s ON ml.assigned_agent = s.user_id
             WHERE ml.dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
            ) AS myLeadCount;
            
-- Master Renewel List
select renewal_year as renewal_category from mmi_mast_renewal_category where status =1;

    
    -- *****************  Assigned Agent Master Lit Fetching ***************
 IF flagVal = 'assigned' THEN           
		
        WITH RECURSIVE subordinates AS 
			(SELECT ur.user_id FROM mmi_user_reporting ur 
			WHERE ur.supervisor_id <> JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
			UNION ALL
			SELECT ur.user_id 
			FROM mmi_user_reporting ur 
			INNER JOIN subordinates s ON ur.supervisor_id = s.user_id)

			SELECT DISTINCT urd.id,CONCAT(urd.first_name, ' ', urd.last_name) AS AgentName
			FROM mmi_lead_details ml
			INNER JOIN subordinates s ON ml.assigned_agent = s.user_id
			LEFT JOIN mmi_mast_customer_details mc ON mc.cluster_id = ml.cluster_id
			LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent 
			LEFT JOIN mmi_ebm_sales_data sa ON ml.engine_no = sa.engine_number
			WHERE ml.dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));   
	
ELSEIF flagVal = 'myLeads' THEN           
		
        WITH RECURSIVE subordinates AS 
			(SELECT ur.user_id FROM mmi_user_reporting ur 
			WHERE ur.supervisor_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
			UNION ALL
			SELECT ur.user_id 
			FROM mmi_user_reporting ur 
			INNER JOIN subordinates s ON ur.supervisor_id = s.user_id)

			SELECT DISTINCT urd.id,CONCAT(urd.first_name, ' ', urd.last_name) AS AgentName
			FROM mmi_lead_details ml
			INNER JOIN subordinates s ON ml.assigned_agent = s.user_id
			LEFT JOIN mmi_mast_customer_details mc ON mc.cluster_id = ml.cluster_id
			LEFT JOIN mmi_mast_user_registration_detail urd ON urd.id = ml.assigned_agent 
			LEFT JOIN mmi_ebm_sales_data sa ON ml.engine_no = sa.engine_number
			WHERE ml.dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));   

	END IF; -- LeadCount END

--  ******************** select multipe Leads and Assigning Agent
ELSEIF type = 'assignLeads' THEN

-- Get total count of leadIds
    SET leadCount = JSON_LENGTH(JSON_EXTRACT(Json_data, '$.leadIds'));

    -- Get the agent ID
    SET agentIdVal = CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.agentId')) AS UNSIGNED);

    -- Loop through leadIds and update
    WHILE leadIndex < leadCount DO
        SET leadIdVal = CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, CONCAT('$.leadIds[', leadIndex, ']'))) AS UNSIGNED);

        UPDATE mmi_lead_details
        SET assigned_agent = agentIdVal
        WHERE lead_id = leadIdVal
        AND dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));

        SET leadIndex = leadIndex + 1;
    END WHILE;
    
 ELSEIF type = 'leadFilterData' THEN
    
IF flagVal = 'assigned' THEN 

--  ************* Assigne Filter List ******************

WITH RECURSIVE subordinates AS 
(
    SELECT ur.user_id  
    FROM mmi_user_reporting ur 
    WHERE ur.supervisor_id <> JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'))
    
    UNION ALL

    SELECT ur.user_id 
    FROM mmi_user_reporting ur 
    INNER JOIN subordinates s ON ur.supervisor_id = s.user_id
)

SELECT *
FROM (
    SELECT DISTINCT
        mc.customer_name,
        ml.dealer_code,
        ml.lead_id,
        ml.model,
        CONCAT(urd.first_name, ' ', urd.last_name) AS AgentName,
        ml.renewal_category,
        DATE_FORMAT(ml.policy_expiry_date, '%d-%m-%Y') AS policy_expiry_date,
        ml.policy_expiry_date AS raw_policy_expiry_date, -- for ORDER BY
        ml.expiry_days,
        urd.id AS AgentId
    FROM mmi_lead_details ml
    INNER JOIN subordinates s ON ml.assigned_agent = s.user_id
    LEFT JOIN mmi_mast_customer_details mc ON mc.cluster_id = ml.cluster_id
