    JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode')) IS NULL 
    OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode')) = '' 
    OR ml.dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'))
  )
  -- Customer Name (LIKE)
  AND (
    JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customerName')) IS NULL 
    OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customerName')) = '' 
    OR LOWER(mc.customer_name) LIKE LOWER(CONCAT('%', JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customerName')), '%'))
  )
  -- Customer Phone (LIKE)
  AND (
    JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customerPhone')) IS NULL 
    OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customerPhone')) = '' 
    OR mc.customer_phone LIKE CONCAT('%', JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customerPhone')), '%')
  )
  -- Registration No (LIKE)
  AND (
    JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.vehicleRegNo')) IS NULL 
    OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.vehicleRegNo')) = '' 
    OR mc.vehicle_reg_no LIKE CONCAT('%', JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.vehicleRegNo')), '%')
  )
  -- VIN or Chassis No
  AND (
    JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.vin')) IS NULL 
    OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.vin')) = '' 
    OR ml.vin LIKE CONCAT('%', JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.vin')), '%') 
    OR mc.chassis_no LIKE CONCAT('%', JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.vin')), '%')
  )
--  Agent multipe call
AND (
    JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.agentId')) IS NULL 
    OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.agentId')) = '' 
    OR FIND_IN_SET(CAST(ml.assigned_agent AS CHAR), JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.agentId')))
)
  -- Renewal Category (multiple comma-separated values, allow empty = fetch all)
AND (
  JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalCategory')) IS NULL
  OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalCategory')) = ''
  OR FIND_IN_SET(TRIM(ml.renewal_category), TRIM(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalCategory'))))
)
  -- Expiry Days
  AND (
    JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.expiry_days')) IS NULL 
    OR JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.expiry_days')) = '' 
    OR ml.expiry_days <= CAST(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.expiry_days')) AS UNSIGNED)
  )

ORDER BY ml.policy_expiry_date
-- LIMIT limitVal OFFSET calculated
;
END IF;
  
ELSEIF type = 'bulkassignLeads' THEN
BEGIN
    DECLARE i INT DEFAULT 0;
    DECLARE total INT;
    DECLARE leadIdVal INT;
    DECLARE agentIdVal INT;
    DECLARE jsonArray JSON;

    SET jsonArray = CAST(Json_data AS JSON); -- â Cast to JSON

    SET total = JSON_LENGTH(jsonArray);
    
    WHILE i < total DO
      
		SET leadIdVal = CAST(JSON_UNQUOTE(JSON_EXTRACT(jsonArray, CONCAT('$[', i, '].lead_id'))) AS UNSIGNED);
        SET agentIdVal = CAST(JSON_UNQUOTE(JSON_EXTRACT(jsonArray, CONCAT('$[', i, '].AgentId'))) AS UNSIGNED);

	UPDATE mmi_lead_details SET assigned_agent = agentIdVal WHERE lead_id = leadIdVal;

        SET i = i + 1;
    END WHILE;
END;
    
    ELSE
        -- This handles unknown `type` directly
        SET SP_STATUS = '1004';
        SET MESSAGE = CONCAT('Invalid type: ', type);
        LEAVE proc_main;
    END IF;

    -- Final status
    SET SP_STATUS = '0000';
    SET MESSAGE = 'success';
END ;;
DELIMITER ;
