CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_lock_useraccount_by_email`(
     IN Json_data JSON,
    OUT p_status_code INT,
    OUT p_status_message VARCHAR(255)
)
BEGIN
	DECLARE p_email_id VARCHAR(200);
    DECLARE p_lock_status VARCHAR(45); 
    DECLARE p_modified_by VARCHAR(45);
    DECLARE p_remark VARCHAR(255);
    DECLARE p_user_id VARCHAR(200); 
    
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
            
            SET p_status_code = 500;
			SET p_status_message = 'An error occurred. Please try again.';
            
             ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_lock_useraccount_by_email', 'LOCK_USER_ACCOUNT', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;

    START TRANSACTION;

    -- SET p_email_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.email'));
    SET p_lock_status = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.lockStatus'));
    SET p_modified_by = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
    SET p_remark = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.remark'));
	SET p_user_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.puserId'));

    /*IF EXISTS (
        SELECT 1 FROM mmi_mast_user
        WHERE email_id = p_email_id AND status = '1'
    ) THEN*/
        UPDATE mmi_mast_user
        SET
            is_Lock = p_lock_status,
            remark = p_remark,
            modified_by = p_modified_by,
            modified_date = NOW()
        WHERE -- email_id = p_email_id 
        user_id = p_user_id AND status = '1';

	IF ROW_COUNT() > 0 THEN
        SET p_status_code = 200;
        IF p_lock_status = 'L' THEN
            SET p_status_message = 'User account locked successfully.';
        ELSE
            SET p_status_message = 'User account unlocked successfully.';
        END IF;

        COMMIT;
    ELSE
        SET p_status_code = 404;
        SET p_status_message = 'User not found or inactive';
        ROLLBACK;
    END IF;

END ;;
DELIMITER ;
