CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_renewal_dashboard`(
    IN Json_data JSON,
    IN type VARCHAR(45),
    OUT SP_STATUS VARCHAR(500),
    OUT MESSAGE VARCHAR(500)
)
BEGIN 
    DECLARE v_userId VARCHAR(45);
    DECLARE v_roleId VARCHAR(45);
    DECLARE v_role_type VARCHAR(45);
    
    DECLARE v_zone VARCHAR(45);
    DECLARE v_segment VARCHAR(45);
    DECLARE v_startDate VARCHAR(20);
    DECLARE v_endDate VARCHAR(20);
    DECLARE v_leadType VARCHAR(45);
     DECLARE v_dealerCode VARCHAR(450);
    DECLARE v_dealerId VARCHAR(450);
    DECLARE v_dealerLocCode VARCHAR(450);
    DECLARE v_parentCode VARCHAR(100); 
    DECLARE v_dealerName VARCHAR(500);
	DECLARE v_branch VARCHAR(500);
	DECLARE v_location VARCHAR(500);
	DECLARE v_state VARCHAR(500);
    DECLARE v_teamMemberId VARCHAR(500);
    DECLARE v_user_role_type VARCHAR(45);
        DECLARE v_modifiedEndDate VARCHAR(20);
    
    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;
    DECLARE dealer_name VARCHAR(255);
    DECLARE agent_name VARCHAR(255);
    DECLARE policy_expiry_date VARCHAR(255);
    DECLARE lead_type VARCHAR(50);
    DECLARE vehicle_type VARCHAR(50);
    DECLARE segment VARCHAR(50);
    DECLARE lead_source VARCHAR(50);
    DECLARE current_disposition INT;
    DECLARE conversion_status VARCHAR(50);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        GET DIAGNOSTICS CONDITION 1 
            @sqlstate = RETURNED_SQLSTATE,
            errno = MYSQL_ERRNO,
            errmsg = MESSAGE_TEXT;

        SET SP_STATUS = '407';
        SET MESSAGE = 'Something went wrong.';

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error 
        (error_code, error_message, procedure_name, procedure_type, ERROR_TIMING, created_by, created_date) 
        VALUES 
        (errno, CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg), 'mmi_proc_renewal_dashboard', type, CURRENT_TIMESTAMP(), 'SYSTEM', NOW());      
    END;

    -- Extract JSON values
    SET v_userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
    SET v_roleId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleId'));
    SET v_dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'));
	SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleType'));
    
    -- Input validation
    IF v_userId IS NULL OR v_userId = '' OR v_userId = '0' 
        OR v_role_type = '' or v_role_type is null  THEN
        SET SP_STATUS = '400';
        SET MESSAGE = CONCAT(
            CASE 
                WHEN v_userId IS NULL OR v_userId = '' THEN 'user Id is missing'
                WHEN v_userId = '0' THEN 'user Id is invalid'
                WHEN v_role_type IS NULL OR v_role_type = '' THEN 'Role Type is missing'
            END
        );

    ELSE 
    
		SET v_zone = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.zone'));
		SET v_segment = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.segment'));
        SET v_startDate = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.startDate'));
        SET v_endDate = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.endDate'));
        SET v_dealerLocCode = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerLocCode'));
        SET v_parentCode = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentCode'));
        SET v_state = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.state'));
        SET v_dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'));
        SET v_modifiedEndDate = v_endDate;
		SET v_teamMemberId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.teamMemberId'));
        
        IF v_role_type = 'MIBL' THEN

		IF type = 'renewalPipeLine' THEN
                -- SELECT * FROM mmi_lead_details WHERE lead_type IN ('Hot', 'Warm');
                SELECT lead_id, policy_id,dealer_code,dealer,insurance_company,insured_name,
				policy_no,policy_effective_date,policy_expiry_date,vin,cluster_id, assigned_agent 
				FROM mmi_lead_details WHERE lead_type IN ('Hot', 'Warm')
				AND created_date >= CURDATE() - INTERVAL 3 MONTH;

                SET SP_STATUS = '200';
                SET MESSAGE = CONCAT('Fetched ', type, ' list.');

		ELSEIF type = 'NotContactable' THEN
				SELECT ld.lead_id,ld.policy_id,ld.dealer_code,ld.dealer,insurance_company,ld.insured_name,
				ld.policy_no,ld.policy_effective_date,ld.policy_expiry_date,ld.vin,ld.cluster_id,ld.assigned_agent
                FROM mmi_lead_details ld 
				LEFT JOIN mmi_call_disposition_history cdh ON 
				ld.lead_id = cdh.lead_id and  ld.assigned_agent = cdh.agent_code AND 
                ld.dealer_code = cdh.dealer_id
				WHERE cdh.lead_id IS NULL;

                SET SP_STATUS = '200';
                SET MESSAGE = CONCAT('Fetched ', type, ' list.');

		ELSEIF type = 'promiseToPayTracker' THEN
                SELECT ld.lead_id,ld.policy_id,ld.dealer_code,ld.dealer,insurance_company,ld.insured_name,
				ld.policy_no,ld.policy_effective_date,ld.policy_expiry_date,ld.vin,ld.cluster_id,ld.assigned_agent
                FROM mmi_call_disposition_history cdh 
                LEFT JOIN mmi_lead_details ld ON cdh.lead_id = ld.lead_id
                and  ld.assigned_agent = cdh.agent_code AND ld.dealer_code = cdh.dealer_id
                LEFT JOIN mmi_agent_disposition_field_response adfr ON adfr.response_id = cdh.id 
                WHERE adfr.field_label = 'Sub Disposition' 
			    AND adfr.field_value = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.fieldValue'));

                SET SP_STATUS = '200';
                SET MESSAGE = CONCAT('Fetched ', type, ' list.');
        
        ELSEIF type = 'dailyAgentWiseCallRenewal' THEN
				SELECT ld.lead_id,ld.policy_id,ld.dealer_code,ld.dealer,insurance_company,ld.insured_name,
				ld.policy_no,ld.policy_effective_date,ld.policy_expiry_date,ld.vin,ld.cluster_id,ld.assigned_agent
                FROM mmi_lead_details ld 
				LEFT JOIN mmi_call_disposition_history cdh ON 
				ld.lead_id = cdh.lead_id and  ld.assigned_agent = cdh.agent_code AND 
                ld.dealer_code = cdh.dealer_id
				WHERE cdh.lead_id IS NULL;

                SET SP_STATUS = '200';
                SET MESSAGE = CONCAT('Fetched ', type, ' list.');
        
        ELSEIF type = 'dealerWiseRevenueAndRetention' THEN
				SELECT ld.lead_id,ld.policy_id,ld.dealer_code,ld.dealer,insurance_company,ld.insured_name,
				ld.policy_no,ld.policy_effective_date,ld.policy_expiry_date,ld.vin,ld.cluster_id,ld.assigned_agent
                FROM mmi_lead_details ld 
				LEFT JOIN mmi_call_disposition_history cdh ON 
				ld.lead_id = cdh.lead_id and  ld.assigned_agent = cdh.agent_code AND 
                ld.dealer_code = cdh.dealer_id
				WHERE cdh.lead_id IS NULL;

                SET SP_STATUS = '200';
                SET MESSAGE = CONCAT('Fetched ', type, ' list.');
        
		ELSEIF TYPE = 'fetchDashboard' THEN 
            -- Fetching Renewal Dashboard Counts
				-- Total Leads Assigned 
WITH CombinedTotals AS (
    SELECT COUNT(DISTINCT CASE WHEN assigned_agent IS NOT NULL THEN lead_id END) AS AssignedCount, COUNT(*) AS TotalBaseCount
    FROM mmi_lead_details
    UNION ALL
    SELECT COUNT(DISTINCT CASE WHEN assigned_agent IS NOT NULL THEN  lead_id END) AS AssignedCount,COUNT(*) AS TotalBaseCount
    FROM mmi_lead_archive_details
)
SELECT
    'Total Assigned Leads' AS Name,
    SUM(AssignedCount) AS count,
    COALESCE(ROUND(SUM(AssignedCount) * 100.0 / NULLIF(SUM(TotalBaseCount), 0), 0),0) AS percentage
FROM CombinedTotals

UNION ALL

-- Leads Contacted
SELECT 
    'Leads Contacted' AS Name,
    COALESCE(count, 0) AS count,
    CONCAT(ROUND(COALESCE(percentage, 0), 2)) AS percentage
FROM (
    WITH latest_dispositions AS (
        SELECT
            cdh.lead_id,
            cdh.dealer_disposition_id,
            adf.field_value AS sub_disposition_value
        FROM mmi_call_disposition_history cdh
        LEFT JOIN mmi_agent_disposition_field_response adf
            ON adf.response_id = cdh.id
            AND adf.field_label = 'Sub Disposition'
        INNER JOIN (
            SELECT lead_id, MAX(created_date) AS max_created_date
            FROM mmi_call_disposition_history
            GROUP BY lead_id
        ) latest ON cdh.lead_id = latest.lead_id AND cdh.created_date = latest.max_created_date
        JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
        WHERE led.lead_type IN ('Hot', 'Warm', 'Cold')
    )
    SELECT 
        'Contacted' AS leadStatus, 
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) / 
        NULLIF((SELECT COUNT(DISTINCT lead_id) FROM mmi_lead_details WHERE lead_type IN ('Hot', 'Warm', 'Cold')), 0) AS percentage
    -- FROM latest_dispositions ld
    from mmi_call_disposition_history ld
    left join mmi_lead_details mld on mld.lead_id = ld.lead_id
) AS lead_summary

UNION ALL

-- Policy Renewed
SELECT 'Policy Renewed' AS Name, 
    COUNT(DISTINCT CASE WHEN lead_status = 'Won' THEN lead_id END) AS count,
    COALESCE(ROUND(COUNT(DISTINCT CASE WHEN lead_status = 'Won' THEN lead_id END) * 100.0 / NULLIF(COUNT(*), 0), 0), 0) AS percentage
FROM mmi_lead_archive_details 
WHERE lead_source_type = 'Renewal'

UNION ALL

-- Renewal Retention
SELECT 
    'Renewal Retention' AS Name,
     -- ROUND(LEAST((COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(total_leads.count, 0), 100), 2) AS count,
    ROUND((COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(total_leads.count, 0), 2) AS count,
    ROUND((COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(total_leads.count, 0), 2) AS percentage
       -- ROUND(LEAST((COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(total_leads.count, 0), 100), 2) AS percentage
       -- ROUND(LEAST((COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(total_leads.count, 0), 100), 2) AS count,
       -- ROUND(LEAST((COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(total_leads.count, 0), 100), 2) AS percentage
	
FROM 
	(SELECT count FROM(
	WITH CombinedTotals AS (
    SELECT COUNT(DISTINCT CASE WHEN assigned_agent IS NOT NULL THEN lead_id END) AS AssignedCount, COUNT(*) AS TotalBaseCount
    FROM mmi_lead_details
    UNION ALL
    SELECT COUNT(DISTINCT CASE WHEN assigned_agent IS NOT NULL THEN  lead_id END) AS AssignedCount,COUNT(*) AS TotalBaseCount
    FROM mmi_lead_archive_details
)
SELECT
    SUM(AssignedCount) AS count
FROM CombinedTotals
)as total )total_leads,
    -- (SELECT COUNT(DISTINCT CASE WHEN assigned_agent IS NOT NULL THEN lead_id END) AS count
    -- FROM mmi_lead_details) total_leads,
    (SELECT COUNT(DISTINCT CASE WHEN lead_status = 'Won' THEN lead_id END) AS count
    FROM mmi_lead_archive_details WHERE lead_source_type = 'Renewal') policy_renewed

UNION ALL

-- Net Premium (in Lacs)
/*SELECT 
    'Net Premium' AS Name,
    -- CONCAT('₹ ', FORMAT(SUM(CASE WHEN lead_status = 'Won' THEN net_premium END), 2)) AS count,
	-- CONCAT('₹ ', FORMAT(SUM(CASE WHEN lead_status = 'Won' THEN net_premium ELSE 0 END), 2)) AS count,
    CONCAT('₹ ', FORMAT(ROUND(SUM(CASE WHEN lead_status = 'Won' THEN net_premium ELSE 0 END), 0), 0)) AS count,
    COALESCE(
        ROUND(
            SUM(CASE WHEN lead_status = 'Won' THEN net_premium END) * 100.0 
            / NULLIF(SUM(net_premium), 0),
        2),
    0) AS percentage
FROM mmi_lead_archive_details*/
SELECT 
    'Net Premium' AS Name,
    CONCAT('₹ ', FORMAT(ROUND(SUM(CASE WHEN archive.lead_status = 'Won' THEN mmd.net_premium ELSE 0 END), 0), 0)) AS count,
    COALESCE(
        ROUND(
            SUM(CASE WHEN archive.lead_status = 'Won' THEN mmd.net_premium END) * 100.0 
            / NULLIF(SUM(mmd.net_premium), 0),
        2),
    0) AS percentage
FROM mmi_lead_archive_details archive
-- LEFT JOIN mmi_lead_details mmd
LEFT JOIN mmi_ebm_policy_data mmd
    ON archive.policy_no = mmd.previous_policy_no
    
UNION ALL    
-- Conversion Rate
SELECT 
    'Conversion Rate' AS Name,
    COALESCE(ROUND(ps.count * 100.0 / NULLIF(lc.count, 0), 2), 0) AS count,
    COALESCE(ROUND(ps.count * 100.0 / NULLIF(lc.count, 0), 2), 0) AS percentage
FROM 
    (SELECT COUNT(DISTINCT lead_id) AS count FROM mmi_lead_archive_details WHERE lead_status = 'Won' AND converted_flag = 'CRM Renewal' ) ps,
    (SELECT COUNT(DISTINCT cdh.lead_id) AS count 
     FROM mmi_call_disposition_history cdh
     -- LEFT JOIN mmi_lead_details ld ON cdh.lead_id = ld.lead_id
     -- WHERE ld.lead_type IN ('Hot', 'Warm', 'Cold')
     ) lc;
            
			-- Renewal Conversion by Month
SELECT 
    LEFT(mrdh.month_name, 3) AS month,
    COALESCE(ld.total_leads, 0) AS leadCount,
     COALESCE(
        ROUND((la.renewed_leads * 100.0) / NULLIF(lc.contacted_leads, 0), 2),
        0
    ) AS renewalConversionPercentage
FROM mmi_mast_renewal_dashboard_month mrdh
LEFT JOIN (
    -- Total assigned leads from lead_details
    WITH CombinedTotals AS (
    SELECT DATE_FORMAT(created_date, '%M') AS month_name, COUNT(mmi_lead_details.lead_id) AS total_leads
    FROM mmi_lead_details
    WHERE assigned_agent IS NOT NULL
    GROUP BY DATE_FORMAT(created_date, '%M')
    UNION ALL
     SELECT DATE_FORMAT(created_date, '%M') AS month_name, COUNT(mmi_lead_archive_details.lead_id) AS total_leads
    FROM mmi_lead_archive_details
    WHERE assigned_agent IS NOT NULL
    GROUP BY DATE_FORMAT(created_date, '%M')
    ) SELECT month_name,SUM(total_leads) AS total_leads
    FROM CombinedTotals
     GROUP BY month_name
) ld ON mrdh.month_name = ld.month_name
-- Leads Contacted (from disposition history)

LEFT JOIN (
    SELECT 
        DATE_FORMAT(first_contact_date, '%M') AS month_name,
        COUNT(*) AS contacted_leads
    FROM (
        SELECT 
            lead_id,
            MIN(created_date) AS first_contact_date
        FROM mmi_call_disposition_history
        GROUP BY lead_id
    ) AS first_calls
    GROUP BY DATE_FORMAT(first_contact_date, '%M')
) lc ON mrdh.month_name = lc.month_name
LEFT JOIN (
    -- Renewed / won leads from lead_archive
    SELECT DATE_FORMAT(created_date, '%M') AS month_name, COUNT(lead_id) AS renewed_leads
    FROM mmi_lead_archive_details
    WHERE lead_status = 'Won' AND converted_flag = 'CRM Renewal' 
    -- WHERE assigned_agent IS NOT NULL 
    GROUP BY DATE_FORMAT(created_date, '%M')
) la ON mrdh.month_name = la.month_name
WHERE mrdh.status = '1'
ORDER BY MONTH(STR_TO_DATE(mrdh.month_name, '%M'));

--  Daily and Weekly Trends
 WITH RECURSIVE

-- Week count for previous month (Unchanged)
prev_month_info AS (
    SELECT
        MONTH(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH)) AS month,
        YEAR(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH)) AS year,
        CEIL((DAY(LAST_DAY(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH)))
             + (DAYOFWEEK(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH) - INTERVAL 1 DAY) - 1)) / 7) AS total_weeks
),

-- Week count for current month (Unchanged)
curr_month_info AS (
    SELECT
        MONTH(CURRENT_DATE) AS month,
        YEAR(CURRENT_DATE) AS year,
        CEIL((DAY(LAST_DAY(CURRENT_DATE))
             + (DAYOFWEEK(CURRENT_DATE - INTERVAL 1 DAY) - 1)) / 7) AS total_weeks
),

-- Recursive weeks for previous month (Unchanged)
prev_month_weeks AS (
    SELECT
        1 AS week_num,
        p.month,
        p.year,
        p.total_weeks
    FROM prev_month_info p
    UNION ALL
    SELECT
        week_num + 1,
        month,
        year,
        total_weeks
    FROM prev_month_weeks
    WHERE week_num + 1 <= total_weeks
),

-- Recursive weeks for current month (Unchanged)
curr_month_weeks AS (
    SELECT
        1 AS week_num,
        c.month,
        c.year,
        c.total_weeks
    FROM curr_month_info c
    UNION ALL
    SELECT
        week_num + 1,
        month,
        year,
        total_weeks
    FROM curr_month_weeks
    WHERE week_num + 1 <= total_weeks
),

-- Combine both + add week start and end date (Unchanged)
week_numbers AS (
    SELECT
        week_num,
        month,
        year,
        DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 DAY) AS week_start,
        LEAST(
            DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 + 6 DAY),
            LAST_DAY(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')))
        ) AS week_end
    FROM prev_month_weeks

    UNION ALL

    SELECT
        week_num,
        month,
        year,
        DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 DAY),
        LEAST(
            DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 + 6 DAY),
            LAST_DAY(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')))
        )
    FROM curr_month_weeks
),

-- Cleaned leads (all leads created in the period)
cleaned_leads AS (
    SELECT DISTINCT
        ld.lead_id,
        ld.lead_status,
        ld.net_premium,
        NULL as converted_flag
    FROM mmi_lead_details ld
    WHERE ld.created_date >= DATE_FORMAT(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH), '%Y-%m-01')

    UNION ALL 

    SELECT DISTINCT
        la.lead_id,
        la.lead_status,
        la.net_premium,
        la.converted_flag
    FROM mmi_lead_archive_details la
    WHERE la.created_date >= DATE_FORMAT(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH), '%Y-%m-01')
),

-- Contacted leads: NOW INCLUDES CONTACT DATE FOR WEEKLY GROUPING
contacted_leads AS (
    -- Get the first contact date for each lead within the reporting period
    SELECT
        cdh.lead_id,
        DATE(MIN(cdh.created_date)) AS first_contact_date
    FROM mmi_call_disposition_history cdh
    WHERE cdh.created_date >= DATE_FORMAT(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH), '%Y-%m-01')
    GROUP BY cdh.lead_id
),

-- Weekly aggregates (GROUPED BY CONTACT WEEK)
weekly_leads AS (
    SELECT
        YEAR(c.first_contact_date) AS year,
        MONTH(c.first_contact_date) AS month,
        -- Calculate the week number based on the CONTACT date
        FLOOR((DAYOFMONTH(c.first_contact_date) - 1) / 7) + 1 AS week_num,

        -- Leads contacted in this week (Denominator)
        COUNT(DISTINCT c.lead_id) AS leads_contacted,

        -- Leads won in this week (Numerator)
        COUNT(DISTINCT
            CASE
                -- A lead is won if it has 'Won' status AND was contacted this week
                WHEN cl.lead_status = 'Won' AND cl.converted_flag = 'CRM Renewal'  THEN cl.lead_id
            END
        ) AS leads_won,

        SUM(CASE WHEN cl.lead_status = 'Won' THEN cl.net_premium ELSE 0 END) AS total_net_premium
    -- Start from contacted leads and link them to their lead status/premium
    FROM contacted_leads c
    -- INNER JOIN to ensure we only analyze leads that were actually created in the period
    INNER JOIN cleaned_leads cl ON cl.lead_id = c.lead_id
    GROUP BY 1, 2, 3
)
-- Final output
SELECT
    'Weekly' AS metric_type,
    CONCAT('Week ', wn.week_num, ' (', wn.year, '-', LPAD(wn.month, 2, '0'), ')') AS period,
    wn.week_start,
    wn.week_end,
    COALESCE(wl.leads_contacted, 0) AS leads_contacted,
    -- CORRECT CONVERSION RATE: (Leads Won) / (Leads Contacted in that week)
    COALESCE(
        ROUND((wl.leads_won * 100.0) / NULLIF(wl.leads_contacted, 0), 2),
        0.00
    ) AS conversion_rate,
    COALESCE(wl.total_net_premium, 0) AS total_net_premium
FROM week_numbers wn
LEFT JOIN weekly_leads wl
    ON wn.week_num = wl.week_num
    AND wn.month = wl.month
    AND wn.year = wl.year
ORDER BY wn.year, wn.month, wn.week_num;



            
            
				SET SP_STATUS = '200';
                SET MESSAGE = CONCAT('Fetched Renewal Dashboard Details');
            
            
            
            ELSEIF TYPE = 'filterfetchDashboard' THEN 

WITH CombinedTotals AS (
    SELECT COUNT(DISTINCT CASE WHEN assigned_agent IS NOT NULL THEN lead_id END) AS AssignedCount, 
           COUNT(*) AS TotalBaseCount
    FROM mmi_lead_details l
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = l.dealer_code
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
    WHERE 
        (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
        AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
        AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
        AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
        AND (
            (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
            OR
            (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
             AND (l.created_date BETWEEN v_startDate AND v_endDate
                  OR l.modified_date BETWEEN v_startDate AND v_endDate))
        )
    UNION ALL
    SELECT COUNT(DISTINCT CASE WHEN assigned_agent IS NOT NULL THEN lead_id END) AS AssignedCount, 
           COUNT(*) AS TotalBaseCount
    FROM mmi_lead_archive_details l
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = l.dealer_code
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
    WHERE 
        (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
        AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
        AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
        AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
        AND (
            (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
            OR
            (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
             AND (l.created_date BETWEEN v_startDate AND v_endDate
                  OR l.modified_date BETWEEN v_startDate AND v_endDate))
        )
)
SELECT
    'Total Assigned Leads' AS Name,
    SUM(AssignedCount) AS count,
    COALESCE(ROUND(SUM(AssignedCount) * 100.0 / NULLIF(SUM(TotalBaseCount), 0), 0), 0) AS percentage
FROM CombinedTotals

UNION ALL

-- Leads Contacted
SELECT 
    'Leads Contacted' AS Name,
    COALESCE(count, 0) AS count,
    CONCAT(ROUND(COALESCE(percentage, 0), 2)) AS percentage
FROM (
    WITH latest_dispositions AS (
        SELECT
            cdh.lead_id,
            cdh.dealer_disposition_id,
            adf.field_value AS sub_disposition_value
        FROM mmi_call_disposition_history cdh
        LEFT JOIN mmi_agent_disposition_field_response adf
            ON adf.response_id = cdh.id
            AND adf.field_label = 'Sub Disposition'
        INNER JOIN (
            SELECT lead_id, MAX(created_date) AS max_created_date
            FROM mmi_call_disposition_history
            GROUP BY lead_id
        ) latest ON cdh.lead_id = latest.lead_id AND cdh.created_date = latest.max_created_date
        JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
        LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = led.dealer_code
        LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
        WHERE 
            led.lead_type IN ('Hot', 'Warm', 'Cold')
            AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
            AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
            AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
            AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
            AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
            AND (
                (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
                OR
                (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
                 AND (led.created_date BETWEEN v_startDate AND v_endDate
                      OR led.modified_date BETWEEN v_startDate AND v_endDate))
            )
    )
    SELECT 
        'Contacted' AS leadStatus, 
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) / 
        NULLIF((SELECT COUNT(DISTINCT lead_id) FROM mmi_lead_details WHERE lead_type IN ('Hot', 'Warm', 'Cold')), 0) AS percentage
    FROM latest_dispositions ld
) AS lead_summary

UNION ALL

-- Policy Renewed
SELECT 'Policy Renewed' AS Name, 
    COUNT(DISTINCT CASE WHEN lead_status = 'Won' THEN lead_id END) AS count,
    COALESCE(ROUND(COUNT(DISTINCT CASE WHEN lead_status = 'Won' THEN lead_id END) * 100.0 / NULLIF(COUNT(*), 0), 0), 0) AS percentage
FROM mmi_lead_archive_details l
LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = l.dealer_code
LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
WHERE 
