    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
    AND (
        (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
        OR
        (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
         AND (l.created_date BETWEEN v_startDate AND v_endDate
              OR l.modified_date BETWEEN v_startDate AND v_endDate))
    )

UNION ALL

-- Renewal Retention
SELECT 
    'Renewal Retention' AS Name,
    ROUND(
        (COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(COALESCE(total_leads.count, 0), 0), 
        2
    ) AS count,
    ROUND(
        (COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(COALESCE(total_leads.count, 0), 0), 
        2
    ) AS percentage
    -- ROUND((COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(total_leads.count, 0), 2) AS count,
    -- ROUND((COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(total_leads.count, 0), 2) AS percentage
FROM 
    (SELECT count FROM(
        WITH CombinedTotals AS (
            SELECT COUNT(DISTINCT CASE WHEN assigned_agent IS NOT NULL THEN lead_id END) AS AssignedCount, COUNT(*) AS TotalBaseCount
            FROM mmi_lead_details l
			LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = l.dealer_code
			LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
			WHERE 
				(v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
				AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
				AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
				AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
				AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
				AND (
					(v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
					OR
					(v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
					 AND (l.created_date BETWEEN v_startDate AND v_endDate
						  OR l.modified_date BETWEEN v_startDate AND v_endDate))
				)
            UNION ALL
            SELECT COUNT(DISTINCT CASE WHEN assigned_agent IS NOT NULL THEN lead_id END) AS AssignedCount, COUNT(*) AS TotalBaseCount
            FROM mmi_lead_archive_details l
			LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = l.dealer_code
			LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
			LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
			WHERE 
				 (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
				AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
				AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
				AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
				AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
				AND (
					(v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
					OR
					(v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
					 AND (l.created_date BETWEEN v_startDate AND v_endDate
						  OR l.modified_date BETWEEN v_startDate AND v_endDate))
				)
        )
        SELECT
            SUM(AssignedCount) AS count
        FROM CombinedTotals
    ) AS total ) total_leads,
    (SELECT COUNT(DISTINCT CASE WHEN lead_status = 'Won' THEN lead_id END) AS count
    FROM mmi_lead_archive_details WHERE lead_source_type = 'Renewal') policy_renewed

UNION ALL

