SELECT 
    'Net Premium' AS Name,
    -- CONCAT('₹ ', FORMAT(SUM(CASE WHEN lead_status = 'Won' THEN mmd.net_premium END), 2)) AS count,
    -- CONCAT('₹ ', FORMAT(SUM(CASE WHEN lead_status = 'Won' THEN mmd.net_premium ELSE 0 END), 2)) AS count,
    CONCAT('₹ ', FORMAT(ROUND(SUM(CASE WHEN l.lead_status = 'Won' THEN mmd.net_premium ELSE 0 END), 0), 0)) AS count,
    COALESCE(
        ROUND(
            SUM(CASE WHEN l.lead_status = 'Won' THEN mmd.net_premium END) * 100.0 
            / NULLIF(SUM(mmd.net_premium), 0),
        2),
    0) AS percentage
FROM mmi_lead_archive_details l
-- LEFT JOIN mmi_lead_details mmd
LEFT JOIN mmi_ebm_policy_data mmd
    ON l.policy_no = mmd.previous_policy_no
LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = l.dealer_code
LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
WHERE 
    (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
    AND (
        (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
        OR
        (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
         AND (l.created_date BETWEEN v_startDate AND v_endDate
              OR l.modified_date BETWEEN v_startDate AND v_endDate))
    )
    
UNION ALL    
-- Conversion Rate
SELECT 
    'Conversion Rate' AS Name,
    COALESCE(ROUND(ps.count * 100.0 / NULLIF(lc.count, 0), 2), 0) AS count,
    COALESCE(ROUND(ps.count * 100.0 / NULLIF(lc.count, 0), 2), 0) AS percentage
FROM 
    (SELECT COUNT(DISTINCT lead_id) AS count
     FROM mmi_lead_archive_details l
     LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = l.dealer_code
     LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
     LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
     WHERE l.lead_status = 'Won' AND l.converted_flag = 'CRM Renewal' 
     AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
     AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
     AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
     AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
     AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
     AND (
         (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
         OR
         (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
          AND (l.created_date BETWEEN v_startDate AND v_endDate
               OR l.modified_date BETWEEN v_startDate AND v_endDate))
     )
    ) ps,
    (SELECT COUNT(DISTINCT cdh.lead_id) AS count 
     FROM mmi_call_disposition_history cdh
     LEFT JOIN mmi_lead_details ld ON cdh.lead_id = ld.lead_id
     LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = ld.dealer_code
     LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
     LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
     WHERE (ld.lead_type IN ('Hot', 'Warm', 'Cold'))
     AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
     AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
     AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
     AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
     AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
     AND (
         (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
         OR
         (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
          AND (ld.created_date BETWEEN v_startDate AND v_endDate
               OR ld.modified_date BETWEEN v_startDate AND v_endDate))
     )
    ) lc;
            
			-- Renewal Conversion by Month
SELECT 
    LEFT(mrdh.month_name, 3) AS month,
    COALESCE(ld.total_leads, 0) AS leadCount,
    COALESCE(
        ROUND((la.renewed_leads * 100.0) / NULLIF(lc.contacted_leads, 0), 2),
        0
    ) AS renewalConversionPercentage
FROM mmi_mast_renewal_dashboard_month mrdh
LEFT JOIN (
    -- Total assigned leads from lead_details
    WITH CombinedTotals AS (
        SELECT 
            DATE_FORMAT(l.created_date, '%M') AS month_name, 
            COUNT(l.lead_id) AS total_leads
        FROM mmi_lead_details l
        LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = l.dealer_code
        LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
        WHERE l.assigned_agent IS NOT NULL
        AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
        AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
        AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
        AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
        AND (
            (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
            OR
            (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
            AND (l.created_date BETWEEN v_startDate AND v_endDate
                 OR l.modified_date BETWEEN v_startDate AND v_endDate))
        )
        GROUP BY DATE_FORMAT(l.created_date, '%M')
        UNION ALL
        SELECT 
            DATE_FORMAT(l.created_date, '%M') AS month_name, 
            COUNT(l.lead_id) AS total_leads
        FROM mmi_lead_archive_details l
        LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = l.dealer_code
        LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
        WHERE l.assigned_agent IS NOT NULL
        AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
        AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
        AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
        AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
        AND (
            (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
            OR
            (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
            AND (l.created_date BETWEEN v_startDate AND v_endDate
                 OR l.modified_date BETWEEN v_startDate AND v_endDate))
        )
        GROUP BY DATE_FORMAT(l.created_date, '%M')
    ) 
    SELECT month_name, SUM(total_leads) AS total_leads
    FROM CombinedTotals
    GROUP BY month_name
) ld ON mrdh.month_name = ld.month_name
-- Leads Contacted (from disposition history)
LEFT JOIN (
    SELECT 
        DATE_FORMAT(first_contact_date, '%M') AS month_name,
        COUNT(*) AS contacted_leads
    FROM (
        SELECT 
            lead_id,
            MIN(created_date) AS first_contact_date
        FROM mmi_call_disposition_history
        GROUP BY lead_id
    ) AS first_calls
    GROUP BY DATE_FORMAT(first_contact_date, '%M')
) lc ON mrdh.month_name = lc.month_name
LEFT JOIN (
    -- Renewed / won leads from lead_archive
    SELECT 
        DATE_FORMAT(l.created_date, '%M') AS month_name, 
        COUNT(l.lead_id) AS renewed_leads
    FROM mmi_lead_archive_details l
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = l.dealer_code
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
    WHERE l.lead_status = 'Won'
    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
    AND (
        (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
        OR
        (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
        AND (l.created_date BETWEEN v_startDate AND v_endDate
             OR l.modified_date BETWEEN v_startDate AND v_endDate))
    )
    GROUP BY DATE_FORMAT(l.created_date, '%M')
) la ON mrdh.month_name = la.month_name
WHERE mrdh.status = '1'
ORDER BY MONTH(STR_TO_DATE(mrdh.month_name, '%M'));

--  Daily and Weekly Trends
WITH RECURSIVE

-- Week count for previous month (Unchanged)
prev_month_info AS (
    SELECT
        MONTH(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH)) AS month,
        YEAR(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH)) AS year,
        CEIL((DAY(LAST_DAY(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH)))
             + (DAYOFWEEK(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH) - INTERVAL 1 DAY) - 1)) / 7) AS total_weeks
),

-- Week count for current month (Unchanged)
curr_month_info AS (
    SELECT
        MONTH(CURRENT_DATE) AS month,
        YEAR(CURRENT_DATE) AS year,
        CEIL((DAY(LAST_DAY(CURRENT_DATE))
             + (DAYOFWEEK(CURRENT_DATE - INTERVAL 1 DAY) - 1)) / 7) AS total_weeks
),

-- Recursive weeks for previous month (Unchanged)
prev_month_weeks AS (
    SELECT
        1 AS week_num,
        p.month,
        p.year,
        p.total_weeks
    FROM prev_month_info p
    UNION ALL
    SELECT
        week_num + 1,
        month,
        year,
        total_weeks
    FROM prev_month_weeks
    WHERE week_num + 1 <= total_weeks
),

-- Recursive weeks for current month (Unchanged)
curr_month_weeks AS (
    SELECT
        1 AS week_num,
        c.month,
        c.year,
        c.total_weeks
    FROM curr_month_info c
    UNION ALL
    SELECT
        week_num + 1,
        month,
        year,
        total_weeks
    FROM curr_month_weeks
    WHERE week_num + 1 <= total_weeks
),

-- Combine both + add week start and end date (Unchanged)
week_numbers AS (
    SELECT
        week_num,
        month,
        year,
        DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 DAY) AS week_start,
        LEAST(
            DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 + 6 DAY),
            LAST_DAY(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')))
        ) AS week_end
    FROM prev_month_weeks

    UNION ALL

    SELECT
        week_num,
        month,
        year,
        DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 DAY),
        LEAST(
            DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 + 6 DAY),
            LAST_DAY(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')))
        )
    FROM curr_month_weeks
),

-- Cleaned leads (all leads created in the period)
cleaned_leads AS (
    SELECT DISTINCT
        ld.lead_id,
        ld.lead_status,
        ld.net_premium,
        NULL AS converted_flag 
    FROM mmi_lead_details ld
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = ld.dealer_code
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
    WHERE ld.created_date >= DATE_FORMAT(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH), '%Y-%m-01')
    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
    AND (
        (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
        OR
        (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
         AND (ld.created_date BETWEEN v_startDate AND v_endDate
              OR ld.modified_date BETWEEN v_startDate AND v_endDate))
    )
    UNION ALL
    SELECT DISTINCT
        la.lead_id,
        la.lead_status,
        la.net_premium,
        la.converted_flag 
    FROM mmi_lead_archive_details la
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = la.dealer_code
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
    WHERE la.created_date >= DATE_FORMAT(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH), '%Y-%m-01')
    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(la.vehicle_class), v_segment))
    AND (
        (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
        OR
        (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
         AND (la.created_date BETWEEN v_startDate AND v_endDate
              OR la.modified_date BETWEEN v_startDate AND v_endDate))
    )
),

-- Contacted leads: NOW INCLUDES CONTACT DATE FOR WEEKLY GROUPING
contacted_leads AS (
    SELECT
        cdh.lead_id,
        DATE(MIN(cdh.created_date)) AS first_contact_date
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_lead_details ld ON ld.lead_id = cdh.lead_id
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = ld.dealer_code
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
    WHERE cdh.created_date >= DATE_FORMAT(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH), '%Y-%m-01')
    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
    GROUP BY cdh.lead_id
    UNION
    SELECT
        cdh.lead_id,
        DATE(MIN(cdh.created_date)) AS first_contact_date
    FROM mmi_call_disposition_history cdh
    LEFT JOIN mmi_lead_archive_details ld ON ld.lead_id = cdh.lead_id
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = ld.dealer_code
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
    WHERE cdh.created_date >= DATE_FORMAT(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH), '%Y-%m-01')
    AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
    AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
    AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
    AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
    AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
    GROUP BY cdh.lead_id
    
),

-- Weekly aggregates (GROUPED BY CONTACT WEEK)
weekly_leads AS (
    SELECT
        YEAR(c.first_contact_date) AS year,
        MONTH(c.first_contact_date) AS month,
        -- Calculate the week number based on the CONTACT date
        FLOOR((DAYOFMONTH(c.first_contact_date) - 1) / 7) + 1 AS week_num,

        -- Leads contacted in this week (Denominator)
        COUNT(DISTINCT c.lead_id) AS leads_contacted,

        -- Leads won in this week (Numerator)
        COUNT(DISTINCT
            CASE
                -- A lead is won if it has 'Won' status AND was contacted this week
                WHEN cl.lead_status = 'Won' AND cl.converted_flag = 'CRM Renewal'  THEN cl.lead_id
            END
        ) AS leads_won,

        SUM(CASE WHEN cl.lead_status = 'Won' AND cl.converted_flag = 'CRM Renewal'  THEN cl.net_premium ELSE 0 END) AS total_net_premium
    -- Start from contacted leads and link them to their lead status/premium
    FROM contacted_leads c
    -- INNER JOIN to ensure we only analyze leads that were actually created in the period
    INNER JOIN cleaned_leads cl ON cl.lead_id = c.lead_id
    GROUP BY 1, 2, 3
)

-- Final output
SELECT
    'Weekly' AS metric_type,
    CONCAT('Week ', wn.week_num, ' (', wn.year, '-', LPAD(wn.month, 2, '0'), ')') AS period,
    wn.week_start,
    wn.week_end,
    COALESCE(wl.leads_contacted, 0) AS leads_contacted,
    -- CORRECT CONVERSION RATE: (Leads Won) / (Leads Contacted in that week)
    COALESCE(
        ROUND((wl.leads_won * 100.0) / NULLIF(wl.leads_contacted, 0), 2),
        0.00
    ) AS conversion_rate,
    COALESCE(wl.total_net_premium, 0) AS total_net_premium
FROM week_numbers wn
LEFT JOIN weekly_leads wl
    ON wn.week_num = wl.week_num
    AND wn.month = wl.month
    AND wn.year = wl.year
ORDER BY wn.year, wn.month, wn.week_num;
            
				SET SP_STATUS = '200';
                SET MESSAGE = CONCAT('Admin Filter Fetched Renewal Dashboard Details');
            
            
                
            ELSE
                SET SP_STATUS = '400';
                SET MESSAGE = CONCAT('Invalid type: ', type);
            END IF;
   
   ELSEIF v_role_type = 'Dealer' THEN -- Manager

            IF type = 'renewalPipeLine' THEN
                
				SELECT ld.lead_id,ld.policy_id,ld.dealer_code,ld.dealer,insurance_company,ld.insured_name,
				ld.policy_no,ld.policy_effective_date,ld.policy_expiry_date,ld.vin,ld.cluster_id,ld.assigned_agent
                FROM mmi_lead_details ld 
				left join mmi_user_reporting mur on ld.assigned_agent = mur.user_id
				left join mmi_user_dealer_mapping udm on mur.user_id = udm.user_id AND ld.dealer_code = udm.dealer_id
				WHERE ld.lead_type IN ('Hot', 'Warm') 
				AND mur.supervisor_id =v_userId and ld.dealer_code = v_dealerId;

