				ld.policy_no,ld.policy_effective_date,ld.policy_expiry_date,ld.vin,ld.cluster_id,ld.assigned_agent 
                FROM mmi_lead_details ld 
				LEFT JOIN mmi_call_disposition_history cdh ON ld.lead_id = cdh.lead_id  and  ld.assigned_agent = cdh.agent_code 
				AND cdh.dealer_id = ld.dealer_code
				left join mmi_user_reporting mur on ld.assigned_agent = mur.user_id
				left join mmi_user_dealer_mapping udm on mur.user_id = udm.user_id 
				AND ld.dealer_code = udm.dealer_id  AND cdh.dealer_id = udm.dealer_id
				WHERE cdh.lead_id IS NULL
				AND mur.supervisor_id =v_userId and ld.dealer_code = v_dealerId;

                SET SP_STATUS = '200';
                SET MESSAGE = CONCAT('Fetched ', type, ' list.');

            ELSEIF type = 'promiseToPayTracker' THEN
              
			SELECT ld.lead_id,ld.policy_id,ld.dealer_code,ld.dealer,insurance_company,ld.insured_name,
			ld.policy_no,ld.policy_effective_date,ld.policy_expiry_date,ld.vin,ld.cluster_id,ld.assigned_agent
            FROM mmi_call_disposition_history cdh 
			LEFT JOIN mmi_lead_details ld ON cdh.lead_id = ld.lead_id and ld.dealer_code = cdh.dealer_id
			LEFT JOIN mmi_agent_disposition_field_response adfr ON adfr.response_id = cdh.id 
			left join mmi_user_reporting mur on ld.assigned_agent = mur.user_id
			left join mmi_user_dealer_mapping udm on mur.user_id = udm.user_id AND ld.dealer_code = udm.dealer_id
			WHERE mur.supervisor_id =v_userId 
			AND udm.dealer_id =v_dealerId
			AND adfr.field_label = 'Sub Disposition' 
			AND adfr.field_value = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.fieldValue'));
            

                SET SP_STATUS = '200';
                SET MESSAGE = CONCAT('Fetched ', type, ' list.');
        ELSEIF TYPE = 'fetchDashboard' THEN 
            -- Fetching Renewal Dashboard Counts

-- Recursive CTE to get all users under a supervisor
WITH RECURSIVE user_hierarchy AS (
    SELECT v_userId AS user_id
    UNION ALL
    SELECT mur.user_id
    FROM mmi_user_reporting mur
    JOIN user_hierarchy uh ON mur.supervisor_id = uh.user_id
),

-- Combined totals (Assigned + Base Leads)
CombinedTotals AS (
    SELECT 
        COUNT(DISTINCT CASE WHEN assigned_agent IS NOT NULL THEN lead_id END) AS AssignedCount,
        COUNT(*) AS TotalBaseCount
    FROM mmi_lead_details
    WHERE assigned_agent IN (SELECT user_id FROM user_hierarchy)
      AND dealer_code = v_dealerId

    UNION ALL

    SELECT 
        COUNT(DISTINCT CASE WHEN assigned_agent IS NOT NULL THEN lead_id END) AS AssignedCount,
        COUNT(*) AS TotalBaseCount
    FROM mmi_lead_archive_details
    WHERE assigned_agent IN (SELECT user_id FROM user_hierarchy)
      AND dealer_code = v_dealerId
)

-- Final UNION query block
SELECT
    'Total Assigned Leads' AS Name,
    SUM(AssignedCount) AS count,
    COALESCE(ROUND(SUM(AssignedCount) * 100.0 / NULLIF(SUM(TotalBaseCount), 0), 0), 0) AS percentage
FROM CombinedTotals

UNION ALL

-- Leads Contacted
SELECT 
    'Leads Contacted' AS Name,
    COALESCE(count, 0) AS count,
    CONCAT(ROUND(COALESCE(percentage, 0), 2)) AS percentage
FROM (
    WITH latest_dispositions AS (
        SELECT
            cdh.lead_id,
            cdh.dealer_disposition_id,
            adf.field_value AS sub_disposition_value
        FROM mmi_call_disposition_history cdh
        LEFT JOIN mmi_agent_disposition_field_response adf
            ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
        INNER JOIN (
            SELECT lead_id, MAX(created_date) AS max_created_date
            FROM mmi_call_disposition_history
            GROUP BY lead_id
        ) latest ON cdh.lead_id = latest.lead_id AND cdh.created_date = latest.max_created_date
        JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
        WHERE led.lead_type IN ('Hot', 'Warm', 'Cold')
          AND led.assigned_agent IN (SELECT user_id FROM user_hierarchy)
          AND led.dealer_code = v_dealerId
    )
    SELECT 
        'Contacted' AS leadStatus, 
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) / 
        NULLIF(
            (SELECT COUNT(DISTINCT lead_id) 
             FROM mmi_lead_details 
             WHERE lead_type IN ('Hot', 'Warm', 'Cold') 
               AND assigned_agent IN (SELECT user_id FROM user_hierarchy)
               AND dealer_code = v_dealerId), 
        0) AS percentage
    FROM mmi_call_disposition_history ld
    LEFT JOIN mmi_lead_details mld ON mld.lead_id = ld.lead_id
    WHERE mld.assigned_agent IN (SELECT user_id FROM user_hierarchy)
      AND mld.dealer_code = v_dealerId
) AS lead_summary

UNION ALL

-- Policy Renewed
SELECT 
    'Policy Renewed' AS Name, 
    COUNT(DISTINCT CASE WHEN lead_status = 'Won' AND converted_flag = 'CRM Renewal'  THEN lead_id END) AS count,
    COALESCE(ROUND(
        COUNT(DISTINCT CASE WHEN lead_status = 'Won' THEN lead_id END) * 100.0 / NULLIF(COUNT(*), 0), 
    0), 0) AS percentage
FROM mmi_lead_archive_details 
WHERE lead_source_type = 'Renewal'
  AND assigned_agent IN (SELECT user_id FROM user_hierarchy)
  AND dealer_code = v_dealerId

UNION ALL

-- Renewal Retention
SELECT 
    'Renewal Retention' AS Name,
    ROUND((COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(total_leads.count, 0), 2) AS count,
    ROUND((COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(total_leads.count, 0), 2) AS percentage
FROM 
    (SELECT SUM(AssignedCount) AS count FROM CombinedTotals) AS total_leads,
    (
        SELECT COUNT(DISTINCT CASE WHEN lead_status = 'Won' THEN lead_id END) AS count
        FROM mmi_lead_archive_details
        WHERE lead_source_type = 'Renewal' 
          AND assigned_agent IN (SELECT user_id FROM user_hierarchy)
          AND dealer_code = v_dealerId
    ) AS policy_renewed

UNION ALL

