    CONCAT('₹ ', FORMAT(ROUND(SUM(CASE WHEN archive.lead_status = 'Won' THEN mmd.net_premium ELSE 0 END), 0), 0)) AS count,
    COALESCE(
        ROUND(
            SUM(CASE WHEN archive.lead_status = 'Won' THEN mmd.net_premium END) * 100.0 
