    ON archive.policy_no = mmd.previous_policy_no
WHERE archive.assigned_agent IN (SELECT user_id FROM user_hierarchy)
  AND archive.dealer_code = v_dealerId

UNION ALL

-- Conversion Rate
SELECT 
    'Conversion Rate' AS Name,
    COALESCE(ROUND(ps.count * 100.0 / NULLIF(lc.count, 0), 2), 0) AS count,
    COALESCE(ROUND(ps.count * 100.0 / NULLIF(lc.count, 0), 2), 0) AS percentage
FROM 
    (
        SELECT COUNT(DISTINCT lead_id) AS count 
        FROM mmi_lead_archive_details 
        WHERE lead_status = 'Won' AND converted_flag = 'CRM Renewal' 
          AND assigned_agent IN (SELECT user_id FROM user_hierarchy)
          AND dealer_code = v_dealerId
    ) ps,
    (
        SELECT COUNT(DISTINCT cdh.lead_id) AS count 
        FROM mmi_call_disposition_history cdh
        JOIN mmi_lead_details ld ON cdh.lead_id = ld.lead_id
        WHERE ld.assigned_agent IN (SELECT user_id FROM user_hierarchy)
          AND ld.dealer_code = v_dealerId
    ) lc;

                
             -- Recursive CTE to get all users under v_userId
WITH RECURSIVE user_hierarchy AS (
    SELECT v_userId AS user_id
    UNION ALL
    SELECT mur.user_id
    FROM mmi_user_reporting mur
    JOIN user_hierarchy uh ON mur.supervisor_id = uh.user_id
),

-- Total assigned leads (active + archived)
CombinedTotals AS (
    SELECT 
        DATE_FORMAT(created_date, '%M') AS month_name, 
        COUNT(ld.lead_id) AS total_leads
    FROM mmi_lead_details ld
    WHERE ld.assigned_agent IS NOT NULL
      AND ld.dealer_code = v_dealerId
      AND ld.assigned_agent IN (SELECT user_id FROM user_hierarchy)
    GROUP BY DATE_FORMAT(created_date, '%M')
    
    UNION ALL

    SELECT 
        DATE_FORMAT(created_date, '%M') AS month_name, 
        COUNT(lad.lead_id) AS total_leads
    FROM mmi_lead_archive_details lad
    WHERE lad.assigned_agent IS NOT NULL
      AND lad.dealer_code = v_dealerId
      AND lad.assigned_agent IN (SELECT user_id FROM user_hierarchy)
    GROUP BY DATE_FORMAT(created_date, '%M')
),

-- Leads marked as 'Won'
RenewedLeads AS (
    SELECT 
        DATE_FORMAT(created_date, '%M') AS month_name, 
        COUNT(lead_id) AS renewed_leads
    FROM mmi_lead_archive_details
    WHERE lead_status = 'Won'
      AND dealer_code = v_dealerId
      AND assigned_agent IN (SELECT user_id FROM user_hierarchy)
    GROUP BY DATE_FORMAT(created_date, '%M')
)

-- Final SELECT joining the above data with dashboard month table
SELECT 
    LEFT(mrdh.month_name, 3) AS month,
    COALESCE(ld.total_leads, 0) AS leadCount,
    COALESCE(
        ROUND((rl.renewed_leads * 100.0) / NULLIF(lc.contacted_leads, 0), 2),
        0
    ) AS renewalConversionPercentage
    -- COALESCE(rl.renewed_leads, 0) AS renewalConversionPercentage
    -- If you want actual percentage calculation, uncomment this instead:
    -- COALESCE(ROUND((rl.renewed_leads * 100.0) / NULLIF(ld.total_leads, 0), 2), 0) AS renewalConversionPercentage

FROM mmi_mast_renewal_dashboard_month mrdh

LEFT JOIN (
    SELECT month_name, SUM(total_leads) AS total_leads
    FROM CombinedTotals
    GROUP BY month_name
) ld ON mrdh.month_name = ld.month_name
LEFT JOIN (
    SELECT 
        DATE_FORMAT(first_contact_date, '%M') AS month_name,
        COUNT(*) AS contacted_leads
    FROM (
        SELECT 
            lead_id,
            MIN(created_date) AS first_contact_date
        FROM mmi_call_disposition_history
        GROUP BY lead_id
    ) AS first_calls
    GROUP BY DATE_FORMAT(first_contact_date, '%M')
) lc ON mrdh.month_name = lc.month_name 
LEFT JOIN RenewedLeads rl ON mrdh.month_name = rl.month_name

WHERE mrdh.status = '1'
ORDER BY MONTH(STR_TO_DATE(mrdh.month_name, '%M'));

 -- Week count for previous month (Unchanged)
WITH RECURSIVE user_hierarchy AS (
    SELECT v_userId AS user_id
    UNION ALL
    SELECT mur.user_id
    FROM mmi_user_reporting mur
    JOIN user_hierarchy uh ON mur.supervisor_id = uh.user_id
),
prev_month_info AS (
    SELECT
        MONTH(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH)) AS month,
        YEAR(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH)) AS year,
        CEIL((DAY(LAST_DAY(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH)))
             + (DAYOFWEEK(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH) - INTERVAL 1 DAY) - 1)) / 7) AS total_weeks
),

-- Week count for current month (Unchanged)
curr_month_info AS (
    SELECT
        MONTH(CURRENT_DATE) AS month,
        YEAR(CURRENT_DATE) AS year,
        CEIL((DAY(LAST_DAY(CURRENT_DATE))
             + (DAYOFWEEK(CURRENT_DATE - INTERVAL 1 DAY) - 1)) / 7) AS total_weeks
),

-- Recursive weeks for previous month (Unchanged)
prev_month_weeks AS (
    SELECT
        1 AS week_num,
        p.month,
        p.year,
        p.total_weeks
    FROM prev_month_info p
    UNION ALL
    SELECT
        week_num + 1,
        month,
        year,
        total_weeks
    FROM prev_month_weeks
    WHERE week_num + 1 <= total_weeks
),

-- Recursive weeks for current month (Unchanged)
curr_month_weeks AS (
    SELECT
        1 AS week_num,
        c.month,
        c.year,
        c.total_weeks
    FROM curr_month_info c
    UNION ALL
    SELECT
        week_num + 1,
        month,
        year,
        total_weeks
    FROM curr_month_weeks
    WHERE week_num + 1 <= total_weeks
),

-- Combine both + add week start and end date (Unchanged)
week_numbers AS (
    SELECT
        week_num,
        month,
        year,
        DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 DAY) AS week_start,
        LEAST(
            DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 + 6 DAY),
            LAST_DAY(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')))
        ) AS week_end
    FROM prev_month_weeks

    UNION ALL

    SELECT
        week_num,
        month,
        year,
        DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 DAY),
        LEAST(
            DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 + 6 DAY),
            LAST_DAY(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')))
        )
    FROM curr_month_weeks
),

-- Cleaned leads (all leads created in the period and filtered by hierarchy/dealer)
cleaned_leads AS (
    SELECT DISTINCT
        ld.lead_id,
        ld.lead_status,
        ld.net_premium,
        ld.dealer_code, -- Added for clarity/consistency
        ld.assigned_agent, -- Added for clarity/consistency
        NULL AS converted_flag 
    FROM mmi_lead_details ld
    WHERE ld.created_date >= DATE_FORMAT(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH), '%Y-%m-01')
    AND ld.dealer_code = v_dealerId
      AND ld.assigned_agent IN (SELECT user_id FROM user_hierarchy)

    UNION ALL

    SELECT DISTINCT
        la.lead_id,
        la.lead_status,
        la.net_premium,
        la.dealer_code, -- Added for clarity/consistency
        la.assigned_agent, -- Added for clarity/consistency
        la.converted_flag
    FROM mmi_lead_archive_details la
    WHERE la.created_date >= DATE_FORMAT(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH), '%Y-%m-01')
    AND la.dealer_code = v_dealerId
      AND la.assigned_agent IN (SELECT user_id FROM user_hierarchy)
),

-- Contacted leads: NOW ONLY LOOKS UP DISPO HISTORY FOR FILTERED LEADS
contacted_leads AS (
    -- Get the first contact date for each lead that matches the dealer/user filter
    SELECT
        cdh.lead_id,
        DATE(MIN(cdh.created_date)) AS first_contact_date
    FROM mmi_call_disposition_history cdh
    -- CRITICAL FIX: Ensure contact history belongs to leads we care about
    INNER JOIN cleaned_leads cl ON cdh.lead_id = cl.lead_id
    WHERE cdh.created_date >= DATE_FORMAT(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH), '%Y-%m-01')
    AND cl.dealer_code = v_dealerId
      AND cl.assigned_agent IN (SELECT user_id FROM user_hierarchy)
    GROUP BY cdh.lead_id
),

-- Weekly aggregates (GROUPED BY CONTACT WEEK)
weekly_leads AS (
    SELECT
        YEAR(c.first_contact_date) AS year,
        MONTH(c.first_contact_date) AS month,
        -- Calculate the week number based on the CONTACT date
        FLOOR((DAYOFMONTH(c.first_contact_date) - 1) / 7) + 1 AS week_num,

        -- Leads contacted in this week (Denominator for CR)
        COUNT(DISTINCT c.lead_id) AS leads_contacted,

        -- Leads won in this week (Numerator for CR)
        COUNT(DISTINCT
            CASE
                -- A lead is counted as 'won' in the week it was FIRST CONTACTED
                WHEN cl.lead_status = 'Won' AND cl.converted_flag = 'CRM Renewal' THEN cl.lead_id
            END
        ) AS leads_won,

        -- Total Net Premium for leads WON that were FIRST CONTACTED this week
        SUM(CASE WHEN cl.lead_status = 'Won' AND cl.converted_flag = 'CRM Renewal'  THEN cl.net_premium ELSE 0 END) AS total_net_premium
    -- Start from contacted leads and link them to their lead status/premium
    FROM contacted_leads c
    -- INNER JOIN to ensure we only analyze leads that were actually created in the period
    INNER JOIN cleaned_leads cl ON cl.lead_id = c.lead_id
    GROUP BY 1, 2, 3
)
-- Final output
SELECT
    'Weekly' AS metric_type,
    CONCAT('Week ', wn.week_num, ' (', wn.year, '-', LPAD(wn.month, 2, '0'), ')') AS period,
    wn.week_start,
    wn.week_end,
    -- Contacted Rate and Total Net Premium are now sourced from wl
    COALESCE(wl.leads_contacted, 0) AS leads_contacted,
    COALESCE(wl.leads_won, 0) AS leads_converted,
    -- CONVERSION RATE: (Leads Won) / (Leads Contacted in that week)
    COALESCE(
        ROUND((wl.leads_won * 100.0) / NULLIF(wl.leads_contacted, 0), 2),
        0.00
    ) AS conversion_rate,
    COALESCE(wl.total_net_premium, 0) AS total_net_premium
FROM week_numbers wn
LEFT JOIN weekly_leads wl
    ON wn.week_num = wl.week_num
    AND wn.month = wl.month
    AND wn.year = wl.year
ORDER BY wn.year, wn.month, wn.week_num;
                
			
				SET SP_STATUS = '200';
                SET MESSAGE = CONCAT('Fetched Renewal Dashboard Details'); 



			        ELSEIF TYPE = 'filterfetchDashboard' THEN 

/*WITH RECURSIVE user_hierarchy AS (
