AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(mmi_lead_archive_details.vehicle_class), v_segment))
AND (
    (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
    OR
    (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
     AND (mmi_lead_archive_details.created_date BETWEEN v_startDate AND v_endDate
          OR mmi_lead_archive_details.modified_date BETWEEN v_startDate AND v_endDate))
)
UNION ALL

-- Conversion Rate
SELECT 
    'Conversion Rate' AS Name,
    COALESCE(ROUND(ps.count * 100.0 / NULLIF(lc.count, 0), 2), 0) AS count,
    COALESCE(ROUND(ps.count * 100.0 / NULLIF(lc.count, 0), 2), 0) AS percentage
FROM 
    (
        SELECT COUNT(DISTINCT lead_id) AS count 
        FROM mmi_lead_archive_details 
        LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = mmi_lead_archive_details.dealer_code
        LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
        WHERE mmi_lead_archive_details.lead_status = 'Won'
          AND mmi_lead_archive_details.assigned_agent IN (SELECT user_id FROM user_hierarchy)
          AND mmi_lead_archive_details.dealer_code = v_dealerId
        AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
        AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
        AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
        AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(mmi_lead_archive_details.vehicle_class), v_segment))
        AND (
            (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
            OR
            (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
             AND (mmi_lead_archive_details.created_date BETWEEN v_startDate AND v_endDate
                  OR mmi_lead_archive_details.modified_date BETWEEN v_startDate AND v_endDate))
        )
    ) ps,
    (
        SELECT COUNT(DISTINCT cdh.lead_id) AS count 
        FROM mmi_call_disposition_history cdh
        JOIN mmi_lead_details ld ON cdh.lead_id = ld.lead_id
        LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = ld.dealer_code
        LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
        LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
        WHERE ld.assigned_agent IN (SELECT user_id FROM user_hierarchy)
          AND ld.dealer_code = v_dealerId
        AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
        AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
        AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
        AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
        AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
        AND (
            (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
            OR
            (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
             AND (ld.created_date BETWEEN v_startDate AND v_endDate
                  OR ld.modified_date BETWEEN v_startDate AND v_endDate))
        )
    ) lc;

			-- Total Leads Assigned
                
             -- Recursive CTE to get all users under v_userId
WITH RECURSIVE user_hierarchy AS (
    SELECT v_userId AS user_id
    UNION ALL
    SELECT mur.user_id
    FROM mmi_user_reporting mur
    JOIN user_hierarchy uh ON mur.supervisor_id = uh.user_id
),

-- Total assigned leads (active + archived)
CombinedTotals AS (
    SELECT 
        DATE_FORMAT(ld.created_date, '%M') AS month_name, 
        COUNT(ld.lead_id) AS total_leads
    FROM mmi_lead_details ld
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = ld.dealer_code
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
    WHERE ld.assigned_agent IS NOT NULL
      AND ld.dealer_code = v_dealerId
      AND ld.assigned_agent IN (SELECT user_id FROM user_hierarchy)
      AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
      AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
      AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
      AND (
          (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
          OR
          (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
           AND (ld.created_date BETWEEN v_startDate AND v_endDate
                OR ld.modified_date BETWEEN v_startDate AND v_endDate))
      )
    GROUP BY DATE_FORMAT(ld.created_date, '%M')
    
    UNION ALL

    SELECT 
        DATE_FORMAT(lad.created_date, '%M') AS month_name, 
        COUNT(lad.lead_id) AS total_leads
    FROM mmi_lead_archive_details lad
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = lad.dealer_code
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
    WHERE lad.assigned_agent IS NOT NULL
      AND lad.dealer_code = v_dealerId
      AND lad.assigned_agent IN (SELECT user_id FROM user_hierarchy)
      AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
      AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
      AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(lad.vehicle_class), v_segment))
      AND (
          (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
          OR
          (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
           AND (lad.created_date BETWEEN v_startDate AND v_endDate
                OR lad.modified_date BETWEEN v_startDate AND v_endDate))
      )
    GROUP BY DATE_FORMAT(lad.created_date, '%M')
),

-- Leads marked as 'Won'
RenewedLeads AS (
    SELECT 
        DATE_FORMAT(mmi_lead_archive_details.created_date, '%M') AS month_name, 
        COUNT(lead_id) AS renewed_leads
    FROM mmi_lead_archive_details
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = mmi_lead_archive_details.dealer_code
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
    WHERE mmi_lead_archive_details.lead_status = 'Won'
      AND mmi_lead_archive_details.dealer_code = v_dealerId
      AND mmi_lead_archive_details.assigned_agent IN (SELECT user_id FROM user_hierarchy)
      AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
      AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
      AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(mmi_lead_archive_details.vehicle_class), v_segment))
      AND (
          (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
          OR
          (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
           AND (mmi_lead_archive_details.created_date BETWEEN v_startDate AND v_endDate
                OR mmi_lead_archive_details.modified_date BETWEEN v_startDate AND v_endDate))
      )
    GROUP BY DATE_FORMAT(mmi_lead_archive_details.created_date, '%M')
)

-- Final SELECT joining the above data with dashboard month table
SELECT 
    LEFT(mrdh.month_name, 3) AS month,
    COALESCE(ld.total_leads, 0) AS leadCount,
    COALESCE(
        ROUND((rl.renewed_leads * 100.0) / NULLIF(lc.contacted_leads, 0), 2),
        0
    ) AS renewalConversionPercentage
FROM mmi_mast_renewal_dashboard_month mrdh

LEFT JOIN (
    SELECT month_name, SUM(total_leads) AS total_leads
    FROM CombinedTotals
    GROUP BY month_name
) ld ON mrdh.month_name = ld.month_name
LEFT JOIN (
    SELECT 
        DATE_FORMAT(first_contact_date, '%M') AS month_name,
        COUNT(*) AS contacted_leads
    FROM (
        SELECT 
            lead_id,
            MIN(created_date) AS first_contact_date
        FROM mmi_call_disposition_history
        GROUP BY lead_id
    ) AS first_calls
    GROUP BY DATE_FORMAT(first_contact_date, '%M')
) lc ON mrdh.month_name = lc.month_name 
LEFT JOIN RenewedLeads rl ON mrdh.month_name = rl.month_name

WHERE mrdh.status = '1'
ORDER BY MONTH(STR_TO_DATE(mrdh.month_name, '%M'));

                
                -- Recursive CTE to get all users under a supervisor
WITH RECURSIVE user_hierarchy AS (
    SELECT v_userId AS user_id
    UNION ALL
    SELECT mur.user_id
    FROM mmi_user_reporting mur
    JOIN user_hierarchy uh ON mur.supervisor_id = uh.user_id
),

prev_month_info AS (
    SELECT
        MONTH(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH)) AS month,
        YEAR(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH)) AS year,
        CEIL((DAY(LAST_DAY(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH)))
             + (DAYOFWEEK(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH) - INTERVAL 1 DAY) - 1)) / 7) AS total_weeks
),

curr_month_info AS (
    SELECT
        MONTH(CURRENT_DATE) AS month,
        YEAR(CURRENT_DATE) AS year,
        CEIL((DAY(LAST_DAY(CURRENT_DATE))
             + (DAYOFWEEK(CURRENT_DATE - INTERVAL 1 DAY) - 1)) / 7) AS total_weeks
),

prev_month_weeks AS (
    SELECT
        1 AS week_num,
        p.month,
        p.year,
        p.total_weeks
    FROM prev_month_info p
    UNION ALL
    SELECT
        week_num + 1,
        month,
        year,
        total_weeks
    FROM prev_month_weeks
    WHERE week_num + 1 <= total_weeks
),

curr_month_weeks AS (
    SELECT
        1 AS week_num,
        c.month,
        c.year,
        c.total_weeks
    FROM curr_month_info c
    UNION ALL
    SELECT
        week_num + 1,
        month,
        year,
        total_weeks
    FROM curr_month_weeks
    WHERE week_num + 1 <= total_weeks
),

week_numbers AS (
    SELECT
        week_num,
        month,
        year,
        DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 DAY) AS week_start,
        LEAST(
            DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 + 6 DAY),
            LAST_DAY(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')))
        ) AS week_end
    FROM prev_month_weeks

    UNION ALL

    SELECT
        week_num,
        month,
        year,
        DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 DAY),
        LEAST(
            DATE_ADD(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')), INTERVAL (week_num - 1) * 7 + 6 DAY),
            LAST_DAY(DATE(CONCAT(year, '-', LPAD(month, 2, '0'), '-01')))
        )
    FROM curr_month_weeks
),

cleaned_leads AS (
    SELECT DISTINCT
        ld.lead_id,
        ld.lead_status,
        ld.net_premium,
        ld.dealer_code,
        ld.assigned_agent,
        ld.vehicle_class
    FROM mmi_lead_details ld
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = ld.dealer_code
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
    WHERE ld.created_date >= DATE_FORMAT(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH), '%Y-%m-01')
      AND ld.dealer_code = v_dealerId
      AND ld.assigned_agent IN (SELECT user_id FROM user_hierarchy)
      AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
      AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
      AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(ld.vehicle_class), v_segment))
      AND (
          (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
          OR
          (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
           AND (ld.created_date BETWEEN v_startDate AND v_endDate
                OR ld.modified_date BETWEEN v_startDate AND v_endDate))
      )

    UNION ALL

    SELECT DISTINCT
        la.lead_id,
        la.lead_status,
        la.net_premium,
        la.dealer_code,
        la.assigned_agent,
        la.vehicle_class
    FROM mmi_lead_archive_details la
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = la.dealer_code
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
    WHERE la.created_date >= DATE_FORMAT(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH), '%Y-%m-01')
      AND la.dealer_code = v_dealerId
      AND la.assigned_agent IN (SELECT user_id FROM user_hierarchy)
      AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
      AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
      AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(la.vehicle_class), v_segment))
      AND (
          (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
          OR
          (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
           AND (la.created_date BETWEEN v_startDate AND v_endDate
                OR la.modified_date BETWEEN v_startDate AND v_endDate))
      )
),

contacted_leads AS (
    SELECT
        cdh.lead_id,
        DATE(MIN(cdh.created_date)) AS first_contact_date
    FROM mmi_call_disposition_history cdh
    INNER JOIN cleaned_leads cl ON cdh.lead_id = cl.lead_id
    LEFT JOIN mmi_dealer_details mdl ON mdl.dealer_id = cl.dealer_code
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.parent_code = mdl.parent_code
    LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code
    WHERE cdh.created_date >= DATE_FORMAT(DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH), '%Y-%m-01')
      AND cl.dealer_code = v_dealerId
      AND cl.assigned_agent IN (SELECT user_id FROM user_hierarchy)
      AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
      AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
      AND (v_dealerId IS NULL OR v_dealerId = '' OR FIND_IN_SET(TRIM(mdl.parent_code), v_dealerId))
      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
      AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(cl.vehicle_class), v_segment))
      AND (
          (v_startDate IS NULL OR v_startDate = '') AND (v_endDate IS NULL OR v_endDate = '')
          OR
          (v_startDate IS NOT NULL AND v_startDate != '' AND v_endDate IS NOT NULL AND v_endDate != '' 
           AND (cdh.created_date BETWEEN v_startDate AND v_endDate
                OR cdh.modified_date BETWEEN v_startDate AND v_endDate))
      )
    GROUP BY cdh.lead_id
),

weekly_leads AS (
    SELECT
        YEAR(c.first_contact_date) AS year,
        MONTH(c.first_contact_date) AS month,
        FLOOR((DAYOFMONTH(c.first_contact_date) - 1) / 7) + 1 AS week_num,
        COUNT(DISTINCT c.lead_id) AS leads_contacted,
        COUNT(DISTINCT
            CASE
                WHEN cl.lead_status = 'Won' THEN cl.lead_id
            END
        ) AS leads_won,
        SUM(CASE WHEN cl.lead_status = 'Won' THEN cl.net_premium ELSE 0 END) AS total_net_premium
    FROM contacted_leads c
    INNER JOIN cleaned_leads cl ON cl.lead_id = c.lead_id
    GROUP BY 1, 2, 3
)

SELECT
    'Weekly' AS metric_type,
    CONCAT('Week ', wn.week_num, ' (', wn.year, '-', LPAD(wn.month, 2, '0'), ')') AS period,
    wn.week_start,
    wn.week_end,
    COALESCE(wl.leads_contacted, 0) AS leads_contacted,
    COALESCE(wl.leads_won, 0) AS leads_converted,
    COALESCE(
        ROUND((wl.leads_won * 100.0) / NULLIF(wl.leads_contacted, 0), 2),
        0.00
    ) AS conversion_rate,
    COALESCE(wl.total_net_premium, 0) AS total_net_premium
FROM week_numbers wn
LEFT JOIN weekly_leads wl
    ON wn.week_num = wl.week_num
    AND wn.month = wl.month
    AND wn.year = wl.year
ORDER BY wn.year, wn.month, wn.week_num;*/


/*WITH RECURSIVE user_hierarchy AS (
    SELECT v_userId AS user_id
    UNION ALL
    SELECT mur.user_id
    FROM mmi_user_reporting mur
    JOIN user_hierarchy uh ON mur.supervisor_id = uh.user_id
),*/

WITH RECURSIVE team_hierarchy AS (
    -- manager
    SELECT v_userId AS user_id

    UNION ALL

    -- all team members
    SELECT ur.user_id
    FROM mmi_user_reporting ur
    INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
dealer_team_members AS (
    SELECT tu.user_id
    FROM team_hierarchy tu
    JOIN mmi_user_dealer_mapping udm ON tu.user_id = udm.user_id
    WHERE udm.dealer_id = v_dealerId
),

-- Combined totals (Assigned + Base Leads)
CombinedTotals AS (
    SELECT 
        COUNT(DISTINCT CASE WHEN l.assigned_agent IS NOT NULL THEN l.lead_id END) AS AssignedCount,
        COUNT(*) AS TotalBaseCount
    FROM mmi_lead_details l
    LEFT JOIN mmi_user_dealer_mapping udm ON l.assigned_agent = udm.user_id
	WHERE udm.dealer_id = v_dealerId
	  AND l.assigned_agent IN (SELECT user_id FROM team_hierarchy)
	  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
	  AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(l.assigned_agent), v_teamMemberId))
	  AND (
			(v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
			OR
			(
				(DATE(l.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
				OR
				(DATE(l.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
			)
		  )
    -- WHERE assigned_agent IN (SELECT user_id FROM user_hierarchy)
      -- AND dealer_code = v_dealerId

    UNION ALL

    SELECT 
        COUNT(DISTINCT CASE WHEN assigned_agent IS NOT NULL THEN lead_id END) AS AssignedCount,
        COUNT(*) AS TotalBaseCount
    FROM mmi_lead_archive_details l
    LEFT JOIN mmi_user_dealer_mapping udm ON l.assigned_agent = udm.user_id
	WHERE udm.dealer_id = v_dealerId
	  AND l.assigned_agent IN (SELECT user_id FROM team_hierarchy)
	  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(l.vehicle_class), v_segment))
	  AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(l.assigned_agent), v_teamMemberId))
	  AND (
			(v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
			OR
			(
				(DATE(l.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
				OR
				(DATE(l.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
			)
		  )
    -- WHERE assigned_agent IN (SELECT user_id FROM user_hierarchy)
     -- AND dealer_code = v_dealerId
)

-- Final UNION query block
SELECT
    'Total Assigned Leads' AS Name,
    SUM(AssignedCount) AS count,
    COALESCE(ROUND(SUM(AssignedCount) * 100.0 / NULLIF(SUM(TotalBaseCount), 0), 0), 0) AS percentage
FROM CombinedTotals

UNION ALL

-- Leads Contacted
SELECT 
    'Leads Contacted' AS Name,
    COALESCE(count, 0) AS count,
    CONCAT(ROUND(COALESCE(percentage, 0), 2)) AS percentage
FROM (
    WITH latest_dispositions AS (
        SELECT
            cdh.lead_id,
            cdh.dealer_disposition_id,
            adf.field_value AS sub_disposition_value
        FROM mmi_call_disposition_history cdh
        LEFT JOIN mmi_agent_disposition_field_response adf
            ON adf.response_id = cdh.id AND adf.field_label = 'Sub Disposition'
        INNER JOIN (
            SELECT lead_id, MAX(created_date) AS max_created_date
            FROM mmi_call_disposition_history
            GROUP BY lead_id
        ) latest ON cdh.lead_id = latest.lead_id AND cdh.created_date = latest.max_created_date
        JOIN mmi_lead_details led ON cdh.lead_id = led.lead_id
        LEFT JOIN mmi_user_dealer_mapping udm ON led.assigned_agent = udm.user_id
        WHERE led.lead_type IN ('Hot', 'Warm', 'Cold')
          AND led.assigned_agent IN (SELECT user_id FROM team_hierarchy)
		  AND udm.dealer_id = v_dealerId
		  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(led.vehicle_class), v_segment))
		  AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(led.assigned_agent), v_teamMemberId))
		  AND (
				(v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR
				(
					(DATE(led.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
					OR
					(DATE(led.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
				)
			  )
    )
    SELECT 
        'Contacted' AS leadStatus, 
        COUNT(DISTINCT ld.lead_id) AS count,
        (COUNT(DISTINCT ld.lead_id) * 100.0) / 
        NULLIF(
            (SELECT COUNT(DISTINCT lead_id) 
             FROM mmi_lead_details 
             WHERE lead_type IN ('Hot', 'Warm', 'Cold') 
               AND assigned_agent IN (SELECT user_id FROM team_hierarchy)
               AND dealer_code = v_dealerId), 
        0) AS percentage
    FROM mmi_call_disposition_history ld
    LEFT JOIN mmi_lead_details mld ON mld.lead_id = ld.lead_id
    -- WHERE mld.assigned_agent IN (SELECT user_id FROM user_hierarchy)
      -- AND mld.dealer_code = v_dealerId
    LEFT JOIN mmi_user_dealer_mapping udm ON mld.assigned_agent = udm.user_id
        WHERE mld.assigned_agent IN (SELECT user_id FROM team_hierarchy)
		  AND udm.dealer_id = v_dealerId
		  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
		  AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(mld.assigned_agent), v_teamMemberId))
		  AND (
				(v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR
				(
					(DATE(mld.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
					OR
					(DATE(mld.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
				)
			  )  
) AS lead_summary

UNION ALL

-- Policy Renewed
SELECT 
    'Policy Renewed' AS Name, 
    COUNT(DISTINCT CASE WHEN mld.lead_status = 'Won' THEN mld.lead_id END) AS count,
    COALESCE(ROUND(
        COUNT(DISTINCT CASE WHEN mld.lead_status = 'Won' THEN mld.lead_id END) * 100.0 / NULLIF(COUNT(*), 0), 
    0), 0) AS percentage
FROM mmi_lead_archive_details mld
-- WHERE lead_source_type = 'Renewal'
  -- AND assigned_agent IN (SELECT user_id FROM user_hierarchy)
  -- AND dealer_code = v_dealerId
	LEFT JOIN mmi_user_dealer_mapping udm ON mld.assigned_agent = udm.user_id
        WHERE lead_source_type = 'Renewal' AND mld.assigned_agent IN (SELECT user_id FROM team_hierarchy)
		  AND udm.dealer_id = v_dealerId
		  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
		  AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(mld.assigned_agent), v_teamMemberId))
		  AND (
				(v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR
				(
					(DATE(mld.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
					OR
					(DATE(mld.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
				)
			  )    

UNION ALL

-- Renewal Retention
SELECT 
    'Renewal Retention' AS Name,
    ROUND((COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(total_leads.count, 0), 2) AS count,
    ROUND((COALESCE(policy_renewed.count, 0) * 100.0) / NULLIF(total_leads.count, 0), 2) AS percentage
FROM 
    (SELECT SUM(AssignedCount) AS count FROM CombinedTotals) AS total_leads,
    (
        SELECT COUNT(DISTINCT CASE WHEN mld.lead_status = 'Won' THEN mld.lead_id END) AS count
        FROM mmi_lead_archive_details mld
        -- WHERE lead_source_type = 'Renewal'
          -- AND assigned_agent IN (SELECT user_id FROM user_hierarchy)
          -- AND dealer_code = v_dealerId
       LEFT JOIN mmi_user_dealer_mapping udm ON mld.assigned_agent = udm.user_id
        WHERE lead_source_type = 'Renewal' AND mld.assigned_agent IN (SELECT user_id FROM team_hierarchy)
		  AND udm.dealer_id = v_dealerId
		  AND (v_segment IS NULL OR v_segment = '' OR FIND_IN_SET(TRIM(mld.vehicle_class), v_segment))
		  AND (v_teamMemberId IS NULL OR v_teamMemberId = '' OR FIND_IN_SET(TRIM(mld.assigned_agent), v_teamMemberId))
		  AND (
				(v_startDate IS NULL OR v_startDate = '' OR v_endDate IS NULL OR v_endDate = '')
				OR
				(
					(DATE(mld.created_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
					OR
					(DATE(mld.modified_date) BETWEEN STR_TO_DATE(v_startDate, '%Y-%m-%d') AND STR_TO_DATE(v_endDate, '%Y-%m-%d'))
				)
			  )     
    ) AS policy_renewed

UNION ALL

