CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_reopen_lost_lead`(
    IN p_json_data JSON,
    OUT p_status_code VARCHAR(50),
    OUT p_status_message VARCHAR(50)
)
BEGIN
    DECLARE v_role_name VARCHAR(100);
    DECLARE v_dealer_id VARCHAR(50);
    DECLARE v_created_user_id VARCHAR(50);
    DECLARE v_lead_id BIGINT; 
    DECLARE v_customer_id VARCHAR(50);
    DECLARE v_agent_code VARCHAR(50);
    DECLARE v_rows_inserted INT;

    DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(250);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_reopen_lost_lead', 'ReopenLead', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    SET v_role_name   = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.roleName'));
    SET v_dealer_id   = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerCode'));
    SET v_created_user_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.userId'));

    START TRANSACTION;

    -- Insert into mmi_lead_details table
    INSERT INTO mmi_lead_details (
        lead_id, policy_id, dealer_code, dealer, insurance_company, policy_no, policy_tenure, policy_type,
        insured_name, yom, ncb_percentage, vehicle_class, vehicle_sub_class, carrier_type, policy_effective_date,
        policy_expiry_date, make, model, vehicle_body_type, fuel_type, variant, vin, engine_no, payment_mode,
        od_discount_percentage, total_idv, addon_premium_amount, net_od_premium_amount, third_party_liability,
        pa_cover, legal_liability, net_liability, net_premium, imt_23, gross_premium, rto_display_name, previous_policy_no,
        previous_insurance_company, podc_start, podc_end, plc_start, plc_end, third_party_liability_bifuel_kit,
        trailer_imt30, imt_34tp, pa_cover_unnamed_persons_imt16, geographical_areas_extention_imt1,
        tpgeographical_areas_extention_imt1, legal_liability_nfpp_imt37, pa_cover_owner_driver, oem_code, proposal_no,
        plan_type, ebm_calls, zd, bundle_product, invoice_date, cancellation_flag, reg_no, i_date, m_date,
        cluster_id, registration_date, assigned_agent, lead_source, lead_status, expiry_days, renewal_category, lead_type, created_by
    )
    SELECT
        mld.lead_id, mld.policy_id, mld.dealer_code, mld.dealer, mld.insurance_company, mld.policy_no, mld.policy_tenure, mld.policy_type,
        mld.insured_name, mld.yom, mld.ncb_percentage, mld.vehicle_class, mld.vehicle_sub_class, mld.carrier_type, mld.policy_effective_date,
        mld.policy_expiry_date, mld.make, mld.model, mld.vehicle_body_type, mld.fuel_type, mld.variant, mld.vin, mld.engine_no, mld.payment_mode,
        mld.od_discount_percentage, mld.total_idv, mld.addon_premium_amount, mld.net_od_premium_amount, mld.third_party_liability,
        mld.pa_cover, mld.legal_liability, mld.net_liability, mld.net_premium, mld.imt_23, mld.gross_premium, mld.rto_display_name, mld.previous_policy_no,
        mld.previous_insurance_company, mld.podc_start, mld.podc_end, mld.plc_start, mld.plc_end, mld.third_party_liability_bifuel_kit,
        mld.trailer_imt30, mld.imt_34tp, mld.pa_cover_unnamed_persons_imt16, mld.geographical_areas_extention_imt1,
        mld.tpgeographical_areas_extention_imt1, mld.legal_liability_nfpp_imt37, mld.pa_cover_owner_driver, mld.oem_code, mld.proposal_no,
        mld.plan_type, mld.ebm_calls, mld.zd, mld.bundle_product, mld.invoice_date, mld.cancellation_flag, mld.reg_no, mld.i_date, mld.m_date,
        mld.cluster_id, mld.registration_date, null, mld.lead_source, mld.lead_status, mld.expiry_days, mld.renewal_category, mld.lead_type, v_created_user_id
    FROM JSON_TABLE(
        p_json_data,
        '$.lead_ids[*]' COLUMNS (lead_id BIGINT PATH '$', rn FOR ORDINALITY)
    ) AS jt_leads
    JOIN JSON_TABLE(
        p_json_data,
        '$.customer_ids[*]' COLUMNS (customer_id VARCHAR(50) PATH '$', rn FOR ORDINALITY)
    ) AS jt_customers
    ON jt_leads.rn = jt_customers.rn
    JOIN mmi_lead_archive_details mld
        ON mld.lead_id = jt_leads.lead_id
        AND mld.cluster_id = jt_customers.customer_id;

    -- Capture the number of rows inserted
    SET v_rows_inserted = ROW_COUNT();
    
    -- If rows were inserted, perform the delete operation
    IF v_rows_inserted > 0 THEN
        DELETE FROM mmi_lead_archive_details 
        WHERE lead_id IN (SELECT lead_id FROM JSON_TABLE(p_json_data, '$.lead_ids[*]' COLUMNS (lead_id BIGINT PATH '$')) AS jt_leads)
        AND cluster_id IN (SELECT customer_id FROM JSON_TABLE(p_json_data, '$.customer_ids[*]' COLUMNS (customer_id VARCHAR(50) PATH '$')) AS jt_customers)
        ;-- AND assigned_agent = v_agent_code;
    END IF;

    -- Log the insert operation
    INSERT INTO mmi_insert_log_details
        (service_name, user_id, log_payload, service_type, created_by, created_date)
    VALUES
        ('mmi_proc_reopen_lost_lead', v_created_user_id, p_json_data, 'UPDATE', v_created_user_id, CURRENT_TIMESTAMP(3));

    COMMIT;

    -- Set status codes and messages
    SET p_status_code = '200';
    SET p_status_message = 'Lead(s) reopened successfully';
END ;;
DELIMITER ;
