CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_rollover_lost_leads`()
BEGIN
    DECLARE v_inserted_count INT DEFAULT 0;
    DECLARE v_deleted_count INT DEFAULT 0;
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    -- Error handler for SQL exceptions
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_rollover_lost_leads', 'ROLLOVER_LOST_LEADS', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    START TRANSACTION;

    -- Insert eligible leads based on rollover_count
    INSERT INTO mmi_lead_details (
        lead_id, policy_id, dealer_code, dealer, insurance_company, policy_no, policy_tenure, policy_type,
        insured_name, yom, ncb_percentage, vehicle_class, vehicle_sub_class, carrier_type, policy_effective_date,
        policy_expiry_date, make, model, vehicle_body_type, fuel_type, variant, vin, engine_no, payment_mode,
        od_discount_percentage, total_idv, addon_premium_amount, net_od_premium_amount, third_party_liability,
        pa_cover, legal_liability, net_liability, net_premium, imt_23, gross_premium, group_product, rto_display_name,
        previous_policy_no, previous_insurance_company, podc_start, podc_end, plc_start, plc_end,
        third_party_liability_bifuel_kit, trailer_imt30, imt_34tp, pa_cover_unnamed_persons_imt16,
        geographical_areas_extention_imt1, tpgeographical_areas_extention_imt1, legal_liability_nfpp_imt37,
        pa_cover_owner_driver, oem_code, proposal_no, plan_type, ebm_calls, zd, bundle_product, invoice_date,
        cancellation_flag, reg_no, i_date, m_date, cluster_id, registration_date, lead_source,
        lead_source_type, renewal_category, lead_type, lead_type_score, rollover_count,
        customer_landline, customer_type, m_user, service_tax, sub_oem_name, version, created_by
    )
    SELECT
        lead_id, policy_id, dealer_code, dealer, insurance_company, policy_no, policy_tenure, policy_type,
        insured_name, yom, ncb_percentage, vehicle_class, vehicle_sub_class, carrier_type, policy_effective_date,
        policy_expiry_date, make, model, vehicle_body_type, fuel_type, variant, vin, engine_no, payment_mode,
        od_discount_percentage, total_idv, addon_premium_amount, net_od_premium_amount, third_party_liability,
        pa_cover, legal_liability, net_liability, net_premium, imt_23, gross_premium, group_product, rto_display_name,
        previous_policy_no, previous_insurance_company, podc_start, podc_end, plc_start, plc_end,
        third_party_liability_bifuel_kit, trailer_imt30, imt_34tp, pa_cover_unnamed_persons_imt16,
        geographical_areas_extention_imt1, tpgeographical_areas_extention_imt1, legal_liability_nfpp_imt37,
        pa_cover_owner_driver, oem_code, proposal_no, plan_type, ebm_calls, zd, bundle_product, invoice_date,
        cancellation_flag, reg_no, i_date, m_date, cluster_id, registration_date, lead_source,
        'Rollover', 'Rollover', lead_type,lead_type_score, COALESCE(rollover_count, 0) + 1,
        customer_landline, customer_type, m_user, service_tax, sub_oem_name, version, 'SYSTEM'
    FROM mmi_lead_archive_details
    WHERE lead_status = 'Lost'
      AND (
            (COALESCE(rollover_count, 0) = 0
             AND DATEDIFF(DATE_ADD(policy_expiry_date, INTERVAL 1 YEAR), CURDATE()) BETWEEN 0 AND 60
            )
         OR (COALESCE(rollover_count, 0) = 1
             AND DATEDIFF(DATE_ADD(policy_expiry_date, INTERVAL 2 YEAR), CURDATE()) BETWEEN 0 AND 60
            )
         OR (COALESCE(rollover_count, 0) = 2
             AND DATEDIFF(DATE_ADD(policy_expiry_date, INTERVAL 3 YEAR), CURDATE()) BETWEEN 0 AND 60
            )
      );

    SET v_inserted_count = ROW_COUNT();

    -- Delete same leads from archive using same logic
    DELETE FROM mmi_lead_archive_details
    WHERE lead_status = 'Lost'
      AND (
            (COALESCE(rollover_count, 0) = 0
             AND DATEDIFF(DATE_ADD(policy_expiry_date, INTERVAL 1 YEAR), CURDATE()) BETWEEN 0 AND 60
            )
         OR (COALESCE(rollover_count, 0) = 1
             AND DATEDIFF(DATE_ADD(policy_expiry_date, INTERVAL 2 YEAR), CURDATE()) BETWEEN 0 AND 60
            )
         OR (COALESCE(rollover_count, 0) = 2
             AND DATEDIFF(DATE_ADD(policy_expiry_date, INTERVAL 3 YEAR), CURDATE()) BETWEEN 0 AND 60
            )
      );

    SET v_deleted_count = ROW_COUNT();

    COMMIT;

    -- Log outcome
    INSERT INTO mmi_mast_procedure_error (
        error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
    ) VALUES (
        0,
        CONCAT('Rollover Inserted: ', v_inserted_count, ', Deleted: ', v_deleted_count),
        'mmi_proc_rollover_lost_leads', 'ROLLOVER_LOST_LEADS', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
    );
END ;;
