CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_save_bucket_creation_values`(
    IN p_json_data JSON,
    OUT p_status_code VARCHAR(500),
    OUT p_status_message VARCHAR(500)
)
BEGIN
	proc_end: BEGIN
    DECLARE v_bucketName VARCHAR(50);
    DECLARE v_dealerCode VARCHAR(50);
    DECLARE v_bucketId INT; 
    DECLARE v_existing_bucket_name VARCHAR(50);
    
    DECLARE v_icCodes JSON;
    DECLARE v_renewalCategoryIds JSON;
    DECLARE v_segmentIds JSON;
    DECLARE v_dataPullIds JSON;
    DECLARE v_addonIds JSON;
    DECLARE v_location VARCHAR(500);
    DECLARE v_created_user_id VARCHAR(50);
    DECLARE v_parent_code VARCHAR(50);
	DECLARE v_role_type VARCHAR(50);
    
    DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(500);
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        ROLLBACK;
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_save_bucket_creation_values', 'InsertBucketValue', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    START TRANSACTION;

    SET v_bucketName = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.bucketName'));
    SET v_dealerCode = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealerCode'));
    SET v_icCodes = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.icCodes'));
    SET v_renewalCategoryIds = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.renewalCategoryIds'));
    SET v_segmentIds = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.segmentIds'));
	SET v_dataPullIds = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dataPullIds'));
    SET v_addonIds = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.addonIds'));
    SET v_location = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.location'));
    SET v_created_user_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.userId'));
    -- SET v_location = JSON_EXTRACT(p_json_data, '$.location');
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode'));
	SET v_role_type = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.roleType'));

    IF v_bucketName IS NULL OR v_bucketName = '' THEN
        SET p_status_code = '300';
        SET p_status_message = 'Bucket name cannot be empty or null';
	ELSE
    
   IF v_role_type = 'MIBL' THEN
		SELECT dl.dealer_id INTO v_dealerCode 
		FROM mmi_dealer_location_mapping dlm
        LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = dlm.mapping_dealer_code and dl.parent_code = dlm.parent_code
		-- LEFT JOIN mmi_mast_dealer md ON md.parent_code = dl.parent_code
        LEFT JOIN mmi_mast_dealer_location mdl ON dlm.location_code = mdl.loc_code
		LEFT JOIN JSON_TABLE(
			v_location,
			"$[*]" COLUMNS (loc_name VARCHAR(100) PATH "$")
		) AS locs ON mdl.loc_name = locs.loc_name
		WHERE dlm.parent_code = v_parent_code
		LIMIT 1;
	END IF;

    IF v_dealerCode IS NULL OR v_dealerCode = '' THEN
		SET p_status_code = '400';
		SET p_status_message = 'Dealer code could not be resolved from location and parent code';
		ROLLBACK;
		LEAVE proc_end;
	END IF;

    SELECT id, bucket_name INTO v_bucketId, v_existing_bucket_name
    FROM mmi_mast_bucket
    WHERE bucket_name = v_bucketName AND dealer_code = v_dealerCode;

    IF v_existing_bucket_name IS NULL OR v_existing_bucket_name = '' THEN
        INSERT INTO mmi_mast_bucket (bucket_name, dealer_code, bucket_location, status, created_by)
        VALUES (v_bucketName, v_dealerCode, v_location, '1', v_created_user_id);
        SET v_bucketId = LAST_INSERT_ID();

    IF v_icCodes IS NOT NULL THEN
        INSERT INTO mmi_call_user_preference_insurance (status,bucket_id, ic_code, created_by)
        SELECT '1',v_bucketId, value, v_created_user_id
        FROM JSON_TABLE(v_icCodes, "$[*]" COLUMNS (value VARCHAR(50) PATH "$")) AS jt;
    END IF;

    IF v_renewalCategoryIds IS NOT NULL THEN
        INSERT INTO mmi_call_user_preference_renewal (status,bucket_id, renewal_category_id, created_by)
        SELECT '1',v_bucketId, value, v_created_user_id
        FROM JSON_TABLE(v_renewalCategoryIds, "$[*]" COLUMNS (value VARCHAR(50) PATH "$")) AS jt;
    END IF;

    IF v_segmentIds IS NOT NULL THEN
        INSERT INTO mmi_call_user_preference_segment (status,bucket_id, segment_id, created_by)
        SELECT '1',v_bucketId, value, v_created_user_id
        FROM JSON_TABLE(v_segmentIds, "$[*]" COLUMNS (value VARCHAR(50) PATH "$")) AS jt;
    END IF;

    -- Insert Data Pull as separate rows (without loops or cursors)
    -- IF v_icCodes IS NOT NULL THEN
       --  INSERT INTO mmi_call_user_preference_datapull (bucket_id, ic_code)
       -- SELECT v_bucketId, value
       -- FROM JSON_TABLE(v_icCodes, "$[*]" COLUMNS (value VARCHAR(50) PATH "$")) AS jt;
    -- END IF;
    
    IF v_dataPullIds IS NOT NULL THEN
		INSERT INTO mmi_call_user_preference_datapull (status,bucket_id, datapull_id, created_by)
        SELECT '1',v_bucketId, value, v_created_user_id
        FROM JSON_TABLE(v_dataPullIds, "$[*]" COLUMNS (value VARCHAR(50) PATH "$")) AS jt;
    END IF;    

    -- Insert Add-Ons as separate rows (without loops or cursors)
    IF v_addonIds IS NOT NULL THEN
        INSERT INTO mmi_call_user_preference_addon (status,bucket_id, addon_id, created_by)
        SELECT '1',v_bucketId, value, v_created_user_id
        FROM JSON_TABLE(v_addonIds, "$[*]" COLUMNS (value VARCHAR(50) PATH "$")) AS jt;
    END IF;
		INSERT INTO mmi_insert_log_details (service_name,user_id,log_payload,
		service_type,created_by,created_date) 
		VALUES ('mmi_proc_save_bucket_creation_values',v_created_user_id,
		p_json_data,'INSERT',v_created_user_id,CURRENT_TIMESTAMP(3));
    
		SET p_status_code = '200';
		SET p_status_message = 'Records Inserted Successfully';
    ELSE
        SET p_status_code = '300';
        SET p_status_message = 'Bucket Name Already Present';
    END IF;
    
    IF p_status_code = '200' THEN
        COMMIT;
    ELSE
        ROLLBACK;
    END IF;
    
END IF; 
END proc_end;   
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_save_column_mapping` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
