/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_save_column_mapping`(
	IN Json_data JSON,
    IN type VARCHAR(45),
    IN in_excel_blob LONGBLOB,
    OUT SP_STATUS VARCHAR(10),
    OUT MESSAGE VARCHAR(255)
)
BEGIN
 
    DECLARE pageId VARCHAR(45); 
    DECLARE roleId VARCHAR(45);
    DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 0;
    DECLARE calculated INT DEFAULT 0;
    DECLARE dealerId VARCHAR(45);
    DECLARE columnindex INT DEFAULT 0;
    DECLARE crossIndex INT DEFAULT 0;
    DECLARE map VARCHAR(45);
    DECLARE dealerLoc VARCHAR(45);
    DECLARE dbTableName VARCHAR(45);
    DECLARE dbColName VARCHAR(45);
    DECLARE excelColName VARCHAR(45);
    DECLARE parentId VARCHAR(100);
    DECLARE i INT DEFAULT 0;
    DECLARE hasError BOOLEAN DEFAULT false;
    DECLARE customId INT DEFAULT 0;
	DECLARE existId INT DEFAULT NULL;
    DECLARE existDealerCustomId VARCHAR(100) DEFAULT NULL;
    DECLARE dealerLocCode VARCHAR(100);
   --  DECLARE existCustomId VARCHAR(100);
    DECLARE dealerTablecustomId VARCHAR(100);
    DECLARE custom_type VARCHAR(45);
    DECLARE mappingDealerCode VARCHAR(45);
	DECLARE old_mappingupload_data JSON;
	DECLARE new_mappingupload_data JSON;
	DECLARE old_upload_data JSON;
	DECLARE new_upload_data JSON;  
	DECLARE errno INT DEFAULT 0;
	DECLARE errmsg TEXT;
    DECLARE userId VARCHAR(45);

	DECLARE EXIT HANDLER FOR SQLEXCEPTION 
	BEGIN
			GET DIAGNOSTICS CONDITION 1 
			@sqlstate = RETURNED_SQLSTATE,
			errno = MYSQL_ERRNO,
			errmsg = MESSAGE_TEXT;

        SET SP_STATUS = 407;
        SET MESSAGE = 'Something Went Worng';
		INSERT INTO mmi_mast_procedure_error (error_code, error_meaage, procedure_name,procedure_type,ERROR_TIMING,created_by,created_date) 
        VALUES (errno, CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg), 'mmi_saveOutletDetails', type ,CURRENT_TIMESTAMP(),'SYSTEM',NOW());

	ROLLBACK;
	END;
    
    IF type = 'savecolumnmap' THEN
         SET columnindex = JSON_LENGTH(JSON_EXTRACT(Json_data, '$.mappingColumns'));
		 SET dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'));
         SET parentId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'));
         SET dealerLocCode = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerLocCode'));
         SET custom_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype'));
         SET mappingDealerCode = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.mapping_dealer_code'));
		 SET userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));	
		
	IF dealerId IS NULL OR dealerId = '' 
		OR parentId IS NULL OR parentId = ''
        OR custom_type IS NULL OR custom_type = ''
		OR userId IS NULL OR userId = ''
        THEN
		SET SP_STATUS = '400';

		SET MESSAGE = CASE
		WHEN dealerId IS NULL OR dealerId = '' THEN 'dealerId is missing'
		WHEN parentId IS NULL OR parentId = '' THEN 'parent id is missing'
		WHEN custom_type IS NULL OR custom_type = '' THEN 'custom type is missing'
        WHEN userId IS NULL OR userId = '' THEN 'User Id is missing'
        END;
		ELSE
        
	START TRANSACTION;
    
    SELECT JSON_ARRAYAGG(
    JSON_OBJECT(
        'id', IFNULL(id, ''),
        'custom_id', IFNULL(custom_id, ''),
        'dealer_id', IFNULL(dealer_id, ''),
        'parent_id', IFNULL(parent_id, ''),
        'loc_code', IFNULL(loc_code, ''),
        'mapping_dealer_code', IFNULL(mapping_dealer_code, ''),
        'customtype', IFNULL(customtype, ''),
        'created_by', IFNULL(created_by, ''),
        'created_date', IFNULL(created_date, ''),
        'modified_by', IFNULL(modified_by, ''),
        'modified_date', IFNULL(modified_date, '')
    )
)
INTO  old_mappingupload_data FROM mmi_excel_column_mapping;

SELECT JSON_ARRAYAGG(
    JSON_OBJECT(
        'id', IFNULL(id, ''),
        'excel_column_name', IFNULL(excel_column_name, ''),
        'db_column_name', IFNULL(db_column_name, ''),
        'db_table_name', IFNULL(db_table_name, ''),
        'custom_id', IFNULL(custom_id, ''),
        'status', IFNULL(status, ''),
        'created_by', IFNULL(created_by, ''),
        'created_date', IFNULL(created_date, ''),
        'modified_by', IFNULL(modified_by, ''),
        'modified_date', IFNULL(modified_date, '')
    )
) INTO old_upload_data
FROM mmi_mast_excel_column_mapping;

        
   SELECT IFNULL(MAX(custom_id), 0) + 1 INTO customId FROM mmi_mast_excel_column_mapping;     
			WHILE i < columnindex DO
            
				SET excelColName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, CONCAT('$.mappingColumns[', i, '].excelColumnName')));
				SET dbColName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, CONCAT('$.mappingColumns[', i, '].dbColumnName')));
				SET dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'));
				SET dbTableName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, CONCAT('$.mappingColumns[', i, '].dbTableName')));
                
            
                IF excelColName IS NULL OR excelColName = '' OR dbColName IS NULL OR dbColName = '' OR
					dbTableName IS NULL OR dbTableName = '' OR dealerId IS NULL OR dealerId = '' THEN
					SET SP_STATUS = '1101';
                    SET MESSAGE = CONCAT('Missing fields in row ', i + 1);
					SET hasError = TRUE;
					SET i = columnindex;  
            ELSE
                SET i = i + 1;
            END IF;
            END WHILE;
            
	IF hasError = FALSE THEN

	SET dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'));
	SET dbTableName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.mappingColumns[0].dbTableName'));

		-- Set all previous mappings to inactive
			UPDATE mmi_mast_excel_column_mapping
			SET status = 0
			WHERE custom_id IN (
			SELECT custom_id FROM mmi_excel_column_mapping
			WHERE dealer_id = dealerId
			AND parent_id = parentId
			AND customtype = custom_type
            AND mapping_dealer_code = dealerId
			);
			
            -- Insert new mappings
            SET i = 0;
            WHILE i < columnindex DO
                SET excelColName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, CONCAT('$.mappingColumns[', i, '].excelColumnName')));
                SET dbColName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, CONCAT('$.mappingColumns[', i, '].dbColumnName')));
                SET dbTableName = JSON_UNQUOTE(JSON_EXTRACT(Json_data, CONCAT('$.mappingColumns[', i, '].dbTableName')));
        
	SET existId = NULL;
-- 	SET existDealerCustomId = NULL;
		SELECT 
		mec.id  INTO existId
		FROM mmi_mast_excel_column_mapping mec
		left JOIN mmi_excel_column_mapping ecm ON mec.custom_id = ecm.custom_id
		WHERE
		mec.db_column_name = dbColName
		AND mec.db_table_name = dbTableName 
		AND ecm.dealer_id = dealerId
		AND ecm.parent_id = parentId
		AND ecm.customtype = custom_type
        AND ecm.mapping_dealer_code = dealerId;
  
IF existId <> '' THEN

		UPDATE mmi_mast_excel_column_mapping
            SET status = 1,
                excel_column_name = excelColName,
                modified_by = userId,
                modified_date = NOW()
            WHERE id = existId;
                
ELSE

-- check dealer Table custom id exist or not 
SET dealerTablecustomId = (
					SELECT mec.custom_id FROM mmi_mast_excel_column_mapping  mec 
					join mmi_excel_column_mapping ecm on mec.custom_id = ecm.custom_id 
					WHERE 
                    mec.db_table_name = dbTableName 
					AND ecm.dealer_id = dealerId
					and ecm.parent_id = parentId
					AND ecm.customtype = custom_type
                    AND ecm.mapping_dealer_code = dealerId
					LIMIT 1
                    );
      
      IF dealerTablecustomId is null then
      
       INSERT INTO mmi_mast_excel_column_mapping (
                    excel_column_name,
                    db_column_name,
                    db_table_name,
                    custom_id,
                    status,
                    created_by
                ) VALUES (
                    excelColName,
                    dbColName,
                    dbTableName,
                    customId, -- new custom Id
                    1,
                    userId
                );
    ELSE
    
    
    INSERT INTO mmi_mast_excel_column_mapping (
                    excel_column_name,
                    db_column_name,
                    db_table_name,
                    custom_id,
                    status,
                    created_by
                ) VALUES (
                    excelColName,
                    dbColName,
                    dbTableName,
                    dealerTablecustomId, -- exist custom Id 
                    1,
                    userId
                );
   END if; 
     END IF;           
SET i = i + 1;
END WHILE;           
                      
-- created template Radio Button
IF columnindex IS NULL OR columnindex = '' THEN   
      
  
SELECT COUNT(*) AS cnt, MAX(custom_id) AS customId
INTO @recordExists, existDealerCustomId
FROM mmi_excel_column_mapping 
WHERE dealer_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'))
AND  mapping_dealer_code = mappingDealerCode
AND parent_id = parentId AND customtype = custom_type;

  
IF @recordExists > 0 THEN
	
    -- UPDATE existing record(s)
    UPDATE mmi_excel_column_mapping
    SET -- loc_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerLocCode')),
		custom_id = existDealerCustomId,
        modified_by = userId, modified_date = NOW()
    WHERE
        parent_id =  parentId
        AND dealer_id =JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'))
        AND customtype = custom_type;
ELSE

DELETE FROM mmi_excel_column_mapping
WHERE dealer_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'))
AND parent_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'))
AND customtype = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype'));


    
   INSERT INTO mmi_excel_column_mapping (
    custom_id,
    dealer_id,
    parent_id,
    loc_code,
    customtype,
    column_mapping_excel,
    created_by,
    mapping_dealer_code,
    column_mapping_file_name
)
SELECT *
FROM (
    SELECT
        custom_id,
        JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId')) AS dealer_id,
        parent_id,
        loc_code,
        customtype,
        column_mapping_excel,
        userId,
        mapping_dealer_code,
        column_mapping_file_name	
    FROM mmi_excel_column_mapping
    WHERE
        TRIM(LOWER(parent_id)) = TRIM(LOWER(parentId)) AND
        TRIM(LOWER(dealer_id)) = TRIM(LOWER(mappingDealerCode)) AND
        TRIM(LOWER(customtype)) = TRIM(LOWER(custom_type))
    ORDER BY custom_id DESC
    LIMIT 1
) AS sub;


END IF;

  ELSE
-- ********** custom template column Mapping Table   *******************

-- SELECT COUNT(*) INTO @recordExists
SELECT COUNT(*) AS cnt, 
MAX(custom_id) AS customId
INTO @recordExists, existDealerCustomId
FROM mmi_excel_column_mapping
WHERE dealer_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'))
AND parent_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'))
AND customtype = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype'))
AND mapping_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.mapping_dealer_code'));

-- Step 3: Insert or Update
IF @recordExists > 0 THEN
      
      IF in_excel_blob IS NOT NULL AND LENGTH(TRIM(in_excel_blob)) > 0 THEN
    -- If in_excel_blob has data, update with blob and file name
    UPDATE mmi_excel_column_mapping
    SET 
        custom_id = existDealerCustomId,
        modified_by = userId,
        modified_date = NOW(),
        column_mapping_excel = in_excel_blob,
        column_mapping_file_name = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.fileName'))
    WHERE dealer_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'))
      AND parent_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'))
      AND customtype = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype'));

ELSE
    -- If in_excel_blob is null or empty, update without blob
    UPDATE mmi_excel_column_mapping
    SET 
        custom_id = existDealerCustomId,
        modified_by = userId,
        modified_date = NOW()
    WHERE dealer_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'))
      AND parent_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'))
      AND customtype = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype'));
END IF;


ELSE

-- deleteing exising mapping row
DELETE FROM mmi_excel_column_mapping
WHERE dealer_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'))
AND parent_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'))
AND customtype = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype'));


    -- Insert new record
    INSERT INTO mmi_excel_column_mapping
						 (
						 `custom_id`,
						 `dealer_id`,
						 `parent_id`,
						 `loc_code`,
						 `customtype`,
                         `created_by`,
                         `column_mapping_excel`,
                         `mapping_dealer_code`,
                         `column_mapping_file_name`
                         )
						 VALUES (
						 customId,
						 JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId')),
						 JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId')),
						 JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerLocCode')),
						 JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype')),
                         userId,
                         in_excel_blob,
                         JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.mapping_dealer_code')),
                         JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.fileName'))
						 );
					END IF;                         
				END IF; 	-- columnindex end 
       
		-- After updating custom or created column mapping custom value update in dealer Details
		UPDATE mmi_dealer_details dd
		LEFT JOIN mmi_excel_column_mapping ecm
		ON dd.dealer_id = ecm.dealer_id
		AND dd.parent_code = ecm.parent_id
		SET 
		dd.policy_flag  = IF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype')) = 'policy',  JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.template')), dd.policy_flag),
		dd.claim_flag   = IF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype')) = 'claim',   JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.template')), dd.claim_flag),
		dd.sales_flag   = IF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype')) = 'sales',   JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.template')), dd.sales_flag),
		dd.service_flag = IF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype')) = 'service', JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.template')), dd.service_flag),
		dd.addon_flag   = IF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype')) = 'addon',   JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.template')), dd.addon_flag)
		WHERE dd.dealer_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'))  
		AND ecm.customtype = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype'))
		AND dd.parent_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'));
        
      
       SELECT JSON_ARRAYAGG(
    JSON_OBJECT(
        'id', IFNULL(id, ''),
        'custom_id', IFNULL(custom_id, ''),
        'dealer_id', IFNULL(dealer_id, ''),
        'parent_id', IFNULL(parent_id, ''),
        'loc_code', IFNULL(loc_code, ''),
        'mapping_dealer_code', IFNULL(mapping_dealer_code, ''),
        'customtype', IFNULL(customtype, ''),
        'created_by', IFNULL(created_by, ''),
        'created_date', IFNULL(created_date, ''),
        'modified_by', IFNULL(modified_by, ''),
        'modified_date', IFNULL(modified_date, '')
    )
)
INTO new_mappingupload_data FROM mmi_excel_column_mapping;

SELECT JSON_ARRAYAGG(
    JSON_OBJECT(
        'id', IFNULL(id, ''),
        'excel_column_name', IFNULL(excel_column_name, ''),
        'db_column_name', IFNULL(db_column_name, ''),
        'db_table_name', IFNULL(db_table_name, ''),
        'custom_id', IFNULL(custom_id, ''),
        'status', IFNULL(status, ''),
        'created_by', IFNULL(created_by, ''),
        'created_date', IFNULL(created_date, ''),
        'modified_by', IFNULL(modified_by, ''),
        'modified_date', IFNULL(modified_date, '')
    )
) INTO new_upload_data
FROM mmi_mast_excel_column_mapping;



 INSERT INTO mmi_maintain_overwrite_logs (
    upload_type,name,
    old_upload_data, new_upload_data,
    created_by, created_date
    ) VALUES 
(
    'columnMapping', 'mmi_excel_column_mapping',
    old_mappingupload_data, new_mappingupload_data,
    JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')), NOW()
),(
    'Excel Columns', 'mmi_excel_column_mapping',
    old_upload_data, new_upload_data,
    JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')), NOW()
);

			COMMIT;
            
            SET SP_STATUS = '200';
            SET MESSAGE = 'Mapping saved and file uploaded successfully.';
        END IF;
    END IF;
END IF;
    

END ;;
DELIMITER ;
