CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_save_disposition_details`(
    IN p_json_data JSON,
    OUT SP_STATUS VARCHAR(10),
    OUT MESSAGE VARCHAR(255)
)
BEGIN
    main_block: BEGIN 
    
    DECLARE v_customer_id VARCHAR(50);
    DECLARE v_lead_id BIGINT;
    DECLARE v_agent_code VARCHAR(50);
    DECLARE v_dealer_id VARCHAR(50);
    DECLARE v_call_status VARCHAR(100);
    DECLARE v_next_call_datetime VARCHAR(50);
    DECLARE v_remarks TEXT;
    DECLARE v_response_id BIGINT;
    DECLARE v_dealer_disp_id INT;
    DECLARE v_field_label VARCHAR(255);
    DECLARE v_field_value VARCHAR(255);
    DECLARE v_send_notification VARCHAR(255);
    DECLARE v_communicationtype VARCHAR(100);
    DECLARE v_created_user_id VARCHAR(100);
    DECLARE v_disposition_status VARCHAR(100);
    DECLARE v_rows_inserted INT;
    
    DECLARE err_code INT;
	DECLARE err_msg TEXT;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1 
        err_code = MYSQL_ERRNO, 
        err_msg = MESSAGE_TEXT;
        
        SET SP_STATUS = '500';
		SET MESSAGE = 'Something Went Wrong';

        ROLLBACK;
        
        INSERT INTO mmi_mast_procedure_error (
           error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
         ) VALUES (
           err_code, err_msg, 'mmi_proc_save_disposition_details', 'DISPOSITION', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
         );

    END;

    SET v_customer_id        = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.customer_id'));
    SET v_lead_id            = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.lead_id')) AS SIGNED);
    SET v_agent_code         = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.user_id'));
    SET v_dealer_id          = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dealer_code'));
    SET v_call_status        = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.call_status'));
    SET v_next_call_datetime = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.next_call_datetime'));
    SET v_remarks            = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.remarks'));
	SET v_created_user_id 	 = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.userId'));
    SET v_disposition_status = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.dispositionStatus'));
    
    IF v_customer_id IS NULL OR v_customer_id = ''
       OR v_lead_id IS NULL OR v_lead_id = 0
       OR v_agent_code IS NULL OR v_agent_code = ''
       OR v_dealer_id IS NULL OR v_dealer_id = ''
       OR v_call_status IS NULL OR v_call_status = ''
    THEN
        SET SP_STATUS = '400';
        SET MESSAGE = 'Required fields missing';
        -- ROLLBACK;
        LEAVE main_block;
    END IF;
	
     
     SELECT jt.field_label,jt.field_value INTO v_field_label,v_field_value
		FROM JSON_TABLE(
			p_json_data->"$.fieldDetails",
			'$[*]' COLUMNS (
				config_id INT PATH '$.configId',
				field_label VARCHAR(255) PATH '$.fieldLabel',
				field_type VARCHAR(50) PATH '$.fieldType',
				field_value VARCHAR(255) PATH '$.fieldValue'
			)
		) AS jt
		WHERE jt.field_label IS NOT NULL
		LIMIT 1;
    
     select disposition_id INTO v_dealer_disp_id 
     FROM mmi_mast_disposition WHERE
     disposition = v_call_status
     AND sub_disposition = v_field_value LIMIT 1;
     
    IF v_dealer_disp_id IS NULL THEN
        SET SP_STATUS = '404';
        SET MESSAGE = 'Disposition config not found';
        ROLLBACK;
        LEAVE main_block;
    END IF;

    START TRANSACTION;

    /*SELECT jt.field_label,jt.field_value INTO v_field_label,v_field_value
    FROM JSON_TABLE(
        p_json_data->"$.fieldDetails",
        '$[*]' COLUMNS (
            config_id INT PATH '$.configId',
            field_label VARCHAR(255) PATH '$.fieldLabel',
            field_type VARCHAR(50) PATH '$.fieldType',
            field_value VARCHAR(255) PATH '$.fieldValue'
        )
    ) AS jt
    WHERE jt.field_label IS NOT NULL
    LIMIT 1;*/
    
    -- SELECT disposition_id INTO v_dealer_disp_id
    -- FROM mmi_mast_call_disposition
    -- WHERE step1_input = v_call_status
     --  AND step2_input = v_field_label;
     /*select disposition_id INTO v_dealer_disp_id 
     FROM mmi_mast_disposition WHERE
     disposition = v_call_status
     AND sub_disposition = v_field_value LIMIT 1;
     
    IF v_dealer_disp_id IS NULL THEN
        SET SP_STATUS = '404';
        SET MESSAGE = 'Disposition config not found';
        ROLLBACK;
        LEAVE main_block;
    END IF;*/
    INSERT INTO mmi_call_disposition_history (
        customer_id, lead_id, agent_code, dealer_id,
        dealer_disposition_id, call_status, call_date,
        next_call_datetime, remarks, created_by
    ) VALUES (
        v_customer_id, v_lead_id, v_agent_code, v_dealer_id,
        v_dealer_disp_id, v_call_status, NOW(),
        v_next_call_datetime, v_remarks, v_created_user_id
    );

    SET v_response_id = LAST_INSERT_ID();
    select v_response_id;

    INSERT INTO mmi_agent_disposition_field_response (
        response_id, config_id, field_label, field_type,field_value, created_by
    )
    SELECT
        v_response_id, jt.config_id,jt.field_label,jt.field_type,jt.field_value, v_created_user_id
    FROM JSON_TABLE(
        p_json_data->"$.fieldDetails",
        '$[*]' COLUMNS (
            config_id INT PATH '$.configId',
            field_label VARCHAR(255) PATH '$.fieldLabel',
            field_type VARCHAR(50) PATH '$.fieldType',
            field_value VARCHAR(255) PATH '$.fieldValue'
        )
    ) AS jt;
    
     SET v_send_notification = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.type'));
     SET v_communicationtype = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.communicationtype'));
     
     IF v_send_notification IS NOT NULL THEN
     IF v_send_notification = 'sendnotification' THEN
        INSERT INTO mmi_customer_communication_history (
            customer_id,lead_id, agent_code, communication_mode,
            communication_date_time, communication_status, remarks, created_by
        ) VALUES (
            v_customer_id,v_lead_id, v_agent_code,v_communicationtype,
            NOW(), '1',v_remarks, v_created_user_id
            -- JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.remarks'))
        );
    END IF;
   END IF;
   COMMIT;
   
   /*IF v_disposition_status = 'Pending' THEN
		UPDATE mmi_lead_details SET lead_status = v_disposition_status 
        where lead_id = v_lead_id and cluster_id = v_customer_id and 
        assigned_agent = v_agent_code;
   ELSE 
		INSERT INTO mmi_lead_archive_details (
		   lead_id,policy_id,dealer_code,dealer,insurance_company,policy_no,policy_tenure,policy_type,
		   insured_name,yom,ncb_percentage,vehicle_class,vehicle_sub_class,carrier_type,policy_effective_date,
		   policy_expiry_date,make,model,vehicle_body_type,fuel_type,variant,vin,engine_no,payment_mode,
		   od_discount_percentage,total_idv,addon_premium_amount,net_od_premium_amount,third_party_liability,
		   pa_cover,legal_liability,net_liability,net_premium,imt_23,gross_premium,rto_display_name,previous_policy_no,
		   previous_insurance_company,podc_start,podc_end,plc_start,plc_end,third_party_liability_bifuel_kit,
		   trailer_imt30,imt_34tp,pa_cover_unnamed_persons_imt16,geographical_areas_extention_imt1,
		   tpgeographical_areas_extention_imt1,legal_liability_nfpp_imt37,pa_cover_owner_driver,oem_code,proposal_no,
		   plan_type,ebm_calls,zd,bundle_product,invoice_date,cancellation_flag,reg_no,i_date,m_date,
		   cluster_id,registration_date,assigned_agent,lead_source,lead_status,expiry_days,renewal_category,lead_type,
           reason_for_archiving
		  )select lead_id,policy_id,dealer_code,dealer,insurance_company,policy_no,policy_tenure,policy_type,
		   insured_name,yom,ncb_percentage,vehicle_class,vehicle_sub_class,carrier_type,policy_effective_date,
		   policy_expiry_date,make,model,vehicle_body_type,fuel_type,variant,vin,engine_no,payment_mode,
		   od_discount_percentage,total_idv,addon_premium_amount,net_od_premium_amount,third_party_liability,
		   pa_cover,legal_liability,net_liability,net_premium,imt_23,gross_premium,rto_display_name,previous_policy_no,
		   previous_insurance_company,podc_start,podc_end,plc_start,plc_end,third_party_liability_bifuel_kit,
		   trailer_imt30,imt_34tp,pa_cover_unnamed_persons_imt16,geographical_areas_extention_imt1,
		   tpgeographical_areas_extention_imt1,legal_liability_nfpp_imt37,pa_cover_owner_driver,oem_code,proposal_no,
		   plan_type,ebm_calls,zd,bundle_product,invoice_date,cancellation_flag,reg_no,i_date,m_date,
		   cluster_id,registration_date,assigned_agent,lead_source,lead_status,expiry_days,renewal_category,lead_type,
           'Disposition Done'
		   from mmi_lead_details WHERE lead_id = v_lead_id and 
		   cluster_id = v_customer_id and assigned_agent = v_agent_code;
           
		SET v_rows_inserted = ROW_COUNT();
        
	  IF v_rows_inserted > 0 THEN
			UPDATE mmi_lead_archive_details 
            SET created_by = v_agent_code ,lead_status = v_disposition_status 
            WHERE lead_id = v_lead_id AND cluster_id = v_customer_id; -- AND assigned_agent = v_agent_code;
			DELETE FROM mmi_lead_details 
            WHERE lead_id = v_lead_id AND cluster_id = v_customer_id AND assigned_agent = v_agent_code;
      END IF;
   END IF;*/
		INSERT INTO mmi_insert_log_details (service_name,user_id,log_payload,
		service_type,created_by,created_date) 
		VALUES ('mmi_proc_save_disposition_details',v_created_user_id,
		p_json_data,'INSERT',v_created_user_id,CURRENT_TIMESTAMP(3));

    -- COMMIT;
    SET SP_STATUS = '200';
    SET MESSAGE = 'Disposition and notification processed successfully';
  END main_block;  
END ;;
DELIMITER ;
