DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_send_tat_escalation_report`(In p_dealerCode varchar(200), In p_email varchar(200))
BEGIN

   WITH RECURSIVE user_hierarchy AS (
    SELECT
        id AS user_id
    FROM mmi_mast_user_registration_detail
    WHERE email_id = p_email
    UNION ALL
    SELECT
        ur.user_id
    FROM mmi_user_reporting ur
    JOIN user_hierarchy uh
        ON ur.supervisor_id = uh.user_id
),
manager_cte AS (
    SELECT id AS manager_id
    FROM mmi_mast_user_registration_detail
    WHERE email_id = p_email
),
latest_leads AS (
    SELECT
        l.lead_id,
        r.first_name,
        r.last_name,
        l.cluster_id,
        l.assigned_agent,
        c.customer_name,
        d.next_call_datetime,
        d.call_status,
        d.call_date,
        l.renewal_category,
        ROW_NUMBER() OVER (
            PARTITION BY l.lead_id
            ORDER BY d.call_date DESC, d.next_call_datetime DESC
        ) AS row_num
    FROM mmi_lead_details l
    INNER JOIN mmi_mast_customer_details c
        ON l.cluster_id = c.cluster_id
    INNER JOIN mmi_call_disposition_history d
        ON l.lead_id = d.lead_id
    INNER JOIN mmi_mast_user_registration_detail r
        ON l.assigned_agent = r.id
    INNER JOIN mmi_lead_breached lb
        ON lb.lead_id = l.lead_id
    WHERE
        l.dealer_code = p_dealerCode
        AND lb.breached_datetime IS NOT NULL
        AND TIMESTAMPDIFF(HOUR, lb.breached_datetime, NOW()) >= 1
)
SELECT
    lead_id AS LeadId,
    customer_name AS CustomerName,
    CONCAT(first_name, ' ', last_name) AS AgentName,
    assigned_agent AS AssignedAgentId,
    next_call_datetime AS ScheduledFollow_UpDate,
    call_status AS CurrentStatus,
    call_date AS LastCallDate,
    renewal_category AS LeadCategory,
    CASE
        WHEN NOW() > next_call_datetime THEN DATEDIFF(NOW(), next_call_datetime)
        ELSE 0
    END AS delay_days
FROM latest_leads
WHERE
    row_num = 1
    AND assigned_agent IN (SELECT user_id FROM user_hierarchy)
    AND assigned_agent NOT IN (SELECT manager_id FROM manager_cte);

END ;;
DELIMITER ;
