DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_target_planning`(
    IN Json_data JSON,
    OUT SP_STATUS VARCHAR(20),
    OUT MESSAGE TEXT
)
proc_label: BEGIN
    DECLARE v_operation VARCHAR(50);
    DECLARE v_dealerCode VARCHAR(50);
    DECLARE v_userId INT;
    DECLARE v_roleType VARCHAR(20);
    DECLARE v_periodType VARCHAR(10);
    DECLARE v_year INT;
    DECLARE v_month INT;
    DECLARE v_agentId INT;
    DECLARE v_segmentId INT;
    DECLARE v_kpiId INT;
    DECLARE v_targetBucketId INT;
    DECLARE v_targetValue DECIMAL(18,2);
    DECLARE v_notes TEXT;
    DECLARE v_targetId INT;
    DECLARE v_pageNumber INT DEFAULT 1;
    DECLARE v_pageSize INT DEFAULT 20;
    DECLARE v_filterAgentId INT;
    DECLARE v_searchText VARCHAR(255);
    DECLARE v_tabFilter VARCHAR(10);
    DECLARE v_filterPeriodType VARCHAR(10);
    DECLARE v_offset INT;
    DECLARE v_exists INT;


    DECLARE v_agent_name VARCHAR(255);
    DECLARE v_segment_name VARCHAR(100);
    DECLARE v_kpi_name VARCHAR(100);
    DECLARE v_bucket_name VARCHAR(100);

    DECLARE v_kpi_name_1 VARCHAR(50) DEFAULT 'Net OD Premium (INR)';
    DECLARE v_kpi_name_2 VARCHAR(50) DEFAULT 'Conversion Ratio (%)';
    DECLARE v_bucket_name_1 VARCHAR(50) DEFAULT 'Total Renewal';

    DECLARE v_check_reporting_manager INT;
    DECLARE v_has_supervisor INT;
    DECLARE v_calling_access CHAR(1);

SET v_operation = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.operation'));
SET v_dealerCode = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
SET v_userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
SET v_roleType = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.roleType'));
SET v_periodType = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.periodType'));
SET v_year = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.year')), '');
SET v_month = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.month')), '');
SET v_agentId = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.agentId')), '');
SET v_segmentId = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.segmentId')), '');
SET v_kpiId = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.kpiId')), '');
SET v_targetBucketId = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.targetBucketId')), '');
SET v_targetValue = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.targetValue')), '');
SET v_notes = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.notes'));
SET v_targetId = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.targetId')), '');
SET v_pageNumber = IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.pageNumber')), ''), 1);
SET v_pageSize = IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.pageSize')), ''), 10);
SET v_filterAgentId = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.filterAgentId')), '');
SET v_searchText = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.searchText'));
IF v_searchText = '' THEN SET v_searchText = NULL; END IF;
SET v_tabFilter = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.tabFilter'));

    IF v_userId IS NULL OR v_userId = '' THEN
        SET SP_STATUS = '400';
        SET MESSAGE = 'User ID is required.';
        SELECT SP_STATUS, MESSAGE;
        LEAVE proc_label;
    END IF;

    SELECT calling_flag INTO v_calling_access FROM mmi_mast_user WHERE user_id = v_userId;
    SELECT COUNT(*) INTO v_check_reporting_manager FROM mmi_user_reporting WHERE supervisor_id = v_userId;
    SELECT COUNT(*) INTO v_has_supervisor FROM mmi_user_reporting WHERE user_id = v_userId;

    -- getInitData
    IF v_operation = 'getInitData' THEN
        SELECT 'Monthly' AS period_type UNION SELECT 'Yearly' AS period_type;

        SELECT 
            u.user_id AS id, 
            CONCAT(COALESCE(urd.first_name, ''), ' ', COALESCE(urd.last_name, '')) AS name
        FROM mmi_mast_user u
        INNER JOIN mmi_user_dealer_mapping udm ON u.user_id = udm.user_id
        LEFT JOIN mmi_mast_user_registration_detail urd ON u.user_id = urd.id
        WHERE udm.dealer_id = v_dealerCode AND u.status = '1'
        ORDER BY name;

        SELECT DISTINCT segment AS segment_name FROM mmi_mast_segment WHERE status = 1 AND segment IS NOT NULL AND segment != '' ORDER BY segment;

        SELECT 1 AS kpi_id, v_kpi_name_1 AS kpi_name, 'INR' AS unit
        UNION ALL
        SELECT 2, v_kpi_name_2, '%';

		-- Bucket
        -- SELECT 1 AS bucket_id, v_bucket_name_1 AS bucket_name;
        SELECT DISTINCT id AS bucket_id, renewal_year AS bucket_name FROM
		mmi_mast_renewal_category
        WHERE renewal_year IS NOT NULL AND renewal_year != ''
		ORDER BY id ASC;
        

        SET SP_STATUS = '200';
        SET MESSAGE = 'Init data loaded.';
        SELECT SP_STATUS, MESSAGE;

    -- saveTarget
    ELSEIF v_operation = 'saveTarget' THEN
        IF v_dealerCode IS NULL OR v_dealerCode = '' THEN
            SET SP_STATUS = '400';
            SET MESSAGE = 'Dealer code is required.';
            SELECT SP_STATUS, MESSAGE;
            LEAVE proc_label;
        END IF;
        IF v_agentId IS NULL OR v_kpiId IS NULL OR v_targetValue IS NULL OR v_year IS NULL THEN
            SET SP_STATUS = '400';
            SET MESSAGE = 'Agent, KPI, Target Value, and Year are required.';
            SELECT SP_STATUS, MESSAGE;
            LEAVE proc_label;
        END IF;
        IF v_periodType = 'Monthly' AND v_month IS NULL THEN
            SET SP_STATUS = '400';
            SET MESSAGE = 'Month is required when period type is Monthly.';
            SELECT SP_STATUS, MESSAGE;
            LEAVE proc_label;
        END IF;

        -- fetching agent name
        SELECT CONCAT(COALESCE(urd.first_name, ''), ' ', COALESCE(urd.last_name, '')) INTO v_agent_name
        FROM mmi_mast_user u
        LEFT JOIN mmi_mast_user_registration_detail urd ON u.user_id = urd.id
        WHERE u.user_id = v_agentId;

        SELECT segment INTO v_segment_name
        FROM mmi_mast_segment
        WHERE segment_id = v_segmentId AND status = 1;

        -- KPI
        IF v_kpiId = 1 THEN SET v_kpi_name = v_kpi_name_1;
        ELSEIF v_kpiId = 2 THEN SET v_kpi_name = v_kpi_name_2;
        ELSE SET v_kpi_name = 'Unknown';
        END IF;

        -- Bucket
        /* IF v_targetBucketId = 1 THEN SET v_bucket_name = v_bucket_name_1;
        ELSE SET v_bucket_name = 'Unknown';
        END IF; */
        
        SELECT renewal_year INTO v_bucket_name FROM mmi_mast_renewal_category WHERE id = v_targetBucketId
		LIMIT 1;

		IF v_bucket_name IS NULL THEN
		SET v_bucket_name = 'Unknown';
		END IF;

        -- dupCheck
        SELECT COUNT(*) INTO v_exists FROM mmi_user_targets
        WHERE dealer_code = v_dealerCode
          AND period_type = v_periodType
          AND year = v_year
          AND (month = v_month OR (v_periodType = 'Yearly' AND month IS NULL))
          AND agent_id = v_agentId
          AND segment_id = v_segmentId
          AND kpi_id = v_kpiId
          AND target_bucket_id = v_targetBucketId
          AND is_active = 1
          AND (v_targetId IS NULL OR target_id != v_targetId);

        IF v_exists > 0 THEN
            SET SP_STATUS = '400';
            SET MESSAGE = 'An active target with the same dealer, agent, segment, KPI, bucket, and period already exists.';
            SELECT SP_STATUS, MESSAGE;
            LEAVE proc_label;
        END IF;

        START TRANSACTION;
        IF v_targetId IS NULL THEN
            INSERT INTO mmi_user_targets (
                dealer_code, period_type, year, month,
                agent_id, agent_name,
                segment_id, segment_name,
                kpi_id, kpi_name,
                target_bucket_id, target_bucket_name,
                target_value, notes, assigned_by, created_by, created_date, is_active
            ) VALUES (
                v_dealerCode, v_periodType, v_year, v_month,
                v_agentId, v_agent_name,
                v_segmentId, v_segment_name,
                v_kpiId, v_kpi_name,
                v_targetBucketId, v_bucket_name,
                v_targetValue, v_notes, v_userId, v_userId, NOW(), 1
            );
            SET v_targetId = LAST_INSERT_ID();
        ELSE
            UPDATE mmi_user_targets SET
                dealer_code = v_dealerCode,
                period_type = v_periodType,
                year = v_year,
                month = v_month,
                agent_id = v_agentId,
                agent_name = v_agent_name,
                segment_id = v_segmentId,
                segment_name = v_segment_name,
                kpi_id = v_kpiId,
                kpi_name = v_kpi_name,
                target_bucket_id = v_targetBucketId,
                target_bucket_name = v_bucket_name,
                target_value = v_targetValue,
                notes = v_notes,
                modified_by = v_userId,
                modified_date = NOW(),
                is_active = 1
            WHERE target_id = v_targetId AND is_active = 1;
            IF ROW_COUNT() = 0 THEN
                SET SP_STATUS = '400';
                SET MESSAGE = 'Target not found or already deleted.';
                ROLLBACK;
                SELECT SP_STATUS, MESSAGE;
                LEAVE proc_label;
            END IF;
        END IF;
        COMMIT;

        SET SP_STATUS = '200';
        SET MESSAGE = 'Target saved successfully.';
        SELECT SP_STATUS, MESSAGE, v_targetId AS target_id;

    
    -- getPreview
    ELSEIF v_operation = 'getPreview' THEN
        IF v_dealerCode IS NULL OR v_dealerCode = '' THEN
            SET SP_STATUS = '400';
            SET MESSAGE = 'Dealer code is required.';
            SELECT SP_STATUS, MESSAGE;
            LEAVE proc_label;
        END IF;

        DROP TEMPORARY TABLE IF EXISTS tmp_dealer_agents;
        CREATE TEMPORARY TABLE tmp_dealer_agents AS
        SELECT u.user_id AS agent_id
        FROM mmi_mast_user u
        INNER JOIN mmi_user_dealer_mapping udm ON u.user_id = udm.user_id
        WHERE udm.dealer_id = v_dealerCode AND u.status = '1';

        IF v_tabFilter = 'monthly' THEN
            SET v_filterPeriodType = 'Monthly';
        ELSEIF v_tabFilter = 'yearly' THEN
            SET v_filterPeriodType = 'Yearly';
        ELSE
            SET v_filterPeriodType = NULL;
        END IF;

		-- offset
        SET v_offset = (v_pageNumber - 1) * v_pageSize;

        DROP TEMPORARY TABLE IF EXISTS tmp_filtered_targets;
        CREATE TEMPORARY TABLE tmp_filtered_targets AS
        SELECT
            t.target_id,
            t.period_type,
            t.year,
            t.month,
            t.agent_id AS user_id,
            t.agent_name,
            t.segment_name,
            t.kpi_name,
            t.target_bucket_name,
            t.target_value,
            t.notes,
            CASE
                WHEN t.year > YEAR(CURDATE()) THEN 1
                WHEN t.year = YEAR(CURDATE()) AND
                     (t.period_type = 'Yearly' OR
                      (t.period_type = 'Monthly' AND t.month >= MONTH(CURDATE()))) THEN 1
                ELSE 0
            END AS can_edit
        FROM mmi_user_targets t
        WHERE t.is_active = 1
          AND t.dealer_code = v_dealerCode
          AND t.agent_id IN (SELECT agent_id FROM tmp_dealer_agents)
          AND (v_filterPeriodType IS NULL OR t.period_type = v_filterPeriodType)
          AND (v_filterAgentId IS NULL OR t.agent_id = v_filterAgentId)
          AND (v_searchText IS NULL OR t.agent_name LIKE CONCAT('%', v_searchText, '%'));

        SELECT SUM(target_value) AS total_value, COUNT(DISTINCT agent_name) AS assignees_count
        FROM tmp_filtered_targets;

        SELECT *
        FROM tmp_filtered_targets
        ORDER BY year DESC, month DESC, agent_name
        LIMIT v_offset, v_pageSize;

        DROP TEMPORARY TABLE IF EXISTS tmp_dealer_agents;
        DROP TEMPORARY TABLE IF EXISTS tmp_filtered_targets;


        SET SP_STATUS = '200';
        SET MESSAGE = 'Preview data fetched.';
        SELECT SP_STATUS, MESSAGE;


    -- editTarget
    ELSEIF v_operation = 'editTarget' THEN
        SELECT
            t.target_id,
            t.period_type,
            t.year,
            t.month,
            t.agent_id AS user_id,
            t.agent_name,
            t.segment_id,
            t.segment_name,
            t.kpi_id,
            t.kpi_name,
            t.target_bucket_id,
            t.target_bucket_name,
            t.target_value,
            t.notes
        FROM mmi_user_targets t
        WHERE t.target_id = v_targetId AND t.is_active = 1;

        IF ROW_COUNT() = 0 THEN
            SET SP_STATUS = '400';
            SET MESSAGE = 'Target not found or already deleted.';
        ELSE
            SET SP_STATUS = '200';
            SET MESSAGE = 'Target details retrieved.';
        END IF;
        SELECT SP_STATUS, MESSAGE;


    -- deleteTarget
    ELSEIF v_operation = 'deleteTarget' THEN
        SELECT COUNT(*) INTO v_exists FROM mmi_user_targets
        WHERE target_id = v_targetId
          AND is_active = 1
          AND (year < YEAR(CURDATE()) OR (year = YEAR(CURDATE()) AND period_type = 'Monthly' AND month < MONTH(CURDATE())));


        IF v_exists > 0 THEN
            SET SP_STATUS = '400';
            SET MESSAGE = 'Cannot delete targets from past periods.';
            SELECT SP_STATUS, MESSAGE;
            LEAVE proc_label;
        END IF;


        UPDATE mmi_user_targets
        SET is_active = 0,
            modified_by = v_userId,
            modified_date = NOW()
        WHERE target_id = v_targetId AND is_active = 1;


        IF ROW_COUNT() = 0 THEN
            SET SP_STATUS = '400';
            SET MESSAGE = 'Target not found or already deleted.';
        ELSE
            SET SP_STATUS = '200';
            SET MESSAGE = 'Target deleted successfully.';
        END IF;
        SELECT SP_STATUS, MESSAGE;

    ELSE
        SET SP_STATUS = '400';
        SET MESSAGE = 'Invalid operation.';
        SELECT SP_STATUS, MESSAGE;
    END IF;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_target_planning_chart_report` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_target_planning_chart_report`(
    IN Json_data JSON,
    OUT p_status_code VARCHAR(500),
    OUT p_status_message VARCHAR(500)
)
BEGIN
	
    DECLARE v_dealer_code VARCHAR(450);
    DECLARE v_agent_id VARCHAR(200);
    DECLARE v_user_id VARCHAR(200);
    DECLARE v_type VARCHAR(200);
    DECLARE v_from_date DATE;
	DECLARE v_to_date DATE;
    DECLARE v_year VARCHAR(200);
    DECLARE v_month VARCHAR(200);
	DECLARE v_check_count INT;
    DECLARE v_check_type BOOLEAN DEFAULT FALSE; 
    
    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
        @sqlstate = RETURNED_SQLSTATE, errno = MYSQL_ERRNO, errmsg = MESSAGE_TEXT;
        SET p_status_code = 407;
        SET p_status_message = CONCAT('Something went wrong. Error: ', errno, ' - ', errmsg);

        INSERT INTO mmi_mast_procedure_error (error_code, error_message, procedure_name, procedure_type, ERROR_TIMING, created_by, created_date)
        VALUES (errno, CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg), 'mmi_proc_target_planning_chart_report', 'SELECT', CURRENT_TIMESTAMP(), 'SYSTEM', NOW());
    END;

    SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerCode'));
    SET v_agent_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.teamId'));
	SET v_user_id = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));
	SET v_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.type'));
    SET v_year = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.year'));
    SET v_month = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.month'));
    -- SET v_check_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.checkType'));

/*IF MONTH(CURDATE()) >= 4 THEN
    SET v_from_date = STR_TO_DATE(CONCAT(YEAR(CURDATE()) - 1, '-04-01'), '%Y-%m-%d');
    SET v_to_date   = STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-03-31'), '%Y-%m-%d');
ELSE
    SET v_from_date = STR_TO_DATE(CONCAT(YEAR(CURDATE()) - 1, '-04-01'), '%Y-%m-%d');
    SET v_to_date   = STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-03-31'), '%Y-%m-%d');
END IF;*/
IF MONTH(CURDATE()) >= 4 THEN
        SET v_from_date = STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-04-01'), '%Y-%m-%d');
        SET v_to_date   = STR_TO_DATE(CONCAT(YEAR(CURDATE()) + 1, '-03-31'), '%Y-%m-%d');
ELSE
        SET v_from_date = STR_TO_DATE(CONCAT(YEAR(CURDATE()) - 1, '-04-01'), '%Y-%m-%d');
        SET v_to_date   = STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-03-31'), '%Y-%m-%d');
END IF;

IF (v_month IS NOT NULL AND v_month <> '') THEN

	SET v_month = REPLACE(v_month, 'January', 'Jan');
	SET v_month = REPLACE(v_month, 'February', 'Feb');
	SET v_month = REPLACE(v_month, 'March', 'Mar');
	SET v_month = REPLACE(v_month, 'April', 'Apr');
	SET v_month = REPLACE(v_month, 'May', 'May');
	SET v_month = REPLACE(v_month, 'June', 'Jun');
	SET v_month = REPLACE(v_month, 'July', 'Jul');
	SET v_month = REPLACE(v_month, 'August', 'Aug');
	SET v_month = REPLACE(v_month, 'September', 'Sep');
	SET v_month = REPLACE(v_month, 'October', 'Oct');
	SET v_month = REPLACE(v_month, 'November', 'Nov');
	SET v_month = REPLACE(v_month, 'December', 'Dec');

END IF;

select count(distinct id) as checkCount INTO v_check_count from mmi_target_planning where team_member = v_user_id;

IF v_type IS NULL OR v_type = '' THEN
	SET v_check_type = TRUE;
END IF;

IF v_check_type = TRUE THEN

IF (v_year IS NOT NULL AND v_year <> '') THEN

WITH RECURSIVE team_hierarchy AS (
	SELECT v_user_id AS user_id
	UNION ALL
	SELECT ur.user_id
	FROM mmi_user_reporting ur
	INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
dealer_team_members AS (
	SELECT th.user_id
	FROM team_hierarchy th
	JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
	WHERE udm.dealer_id = v_dealer_code
),
lead_archive_stats AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        SUM(mld.net_premium) AS netPremium,
        SUM(mld.addon_premium_amount) AS addonPremiumAmount,
        SUM(mld.net_od_premium_amount) AS netOdPremiumAmount,
        COUNT(DISTINCT mld.lead_id) AS leadsAssigned
    FROM mmi_lead_archive_details mld
    WHERE mld.assigned_agent IS NOT NULL 
    AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_agent_id IS NULL OR v_agent_id='' 
           OR FIND_IN_SET(TRIM(mld.assigned_agent), v_agent_id))
    AND ((v_year IS NOT NULL AND v_year <> '' AND YEAR(mld.created_date) = v_year) 
    OR ((v_year IS NULL OR v_year = '') AND (((MONTH(CURDATE()) >= 4 AND 
    mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-04-01'), '%Y-%m-%d')
    AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE())+1, '-03-31'), '%Y-%m-%d'))
	OR (MONTH(CURDATE()) < 4 AND mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE())-1, '-04-01'), '%Y-%m-%d')
	AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-03-31'), '%Y-%m-%d'))))
	AND (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(MONTH(mld.created_date),2,'0'), v_month))))
    and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code, period
),
call_stats AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_details mld 
        ON mld.lead_id = cdh.lead_id
    WHERE mld.assigned_agent IS NOT NULL 
    AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_agent_id IS NULL OR v_agent_id='' 
           OR FIND_IN_SET(TRIM(mld.assigned_agent), v_agent_id)) 
    AND ((v_year IS NOT NULL AND v_year <> '' AND YEAR(mld.created_date) = v_year) 
    OR ((v_year IS NULL OR v_year = '') AND (((MONTH(CURDATE()) >= 4 AND 
    mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-04-01'), '%Y-%m-%d')
    AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE())+1, '-03-31'), '%Y-%m-%d'))
	OR (MONTH(CURDATE()) < 4 AND mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE())-1, '-04-01'), '%Y-%m-%d')
	AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-03-31'), '%Y-%m-%d'))))
	AND (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(MONTH(mld.created_date),3,'0'), v_month))))
    and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code, period
),
lead_archive_call AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_archive_details mld 
        ON mld.lead_id = cdh.lead_id
    WHERE mld.assigned_agent IS NOT NULL 
    AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_agent_id IS NULL OR v_agent_id='' 
           OR FIND_IN_SET(TRIM(mld.assigned_agent), v_agent_id))
	AND ((v_year IS NOT NULL AND v_year <> '' AND YEAR(mld.created_date) = v_year) 
    OR ((v_year IS NULL OR v_year = '') AND (((MONTH(CURDATE()) >= 4 AND 
    mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-04-01'), '%Y-%m-%d')
    AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE())+1, '-03-31'), '%Y-%m-%d'))
	OR (MONTH(CURDATE()) < 4 AND mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE())-1, '-04-01'), '%Y-%m-%d')
	AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-03-31'), '%Y-%m-%d'))))
	AND (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(MONTH(mld.created_date),3,'0'), v_month))))
    and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code, period
),
conversion_stats AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        COUNT(DISTINCT policy_no) AS policiesConverted,
        COUNT(DISTINCT CASE 
            WHEN lead_status='Won' 
             AND converted_flag='CRM Renewal'
            THEN lead_id END) AS conversionCount
    FROM mmi_lead_archive_details mld
    WHERE mld.assigned_agent IS NOT NULL 
    AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_agent_id IS NULL OR v_agent_id='' 
           OR FIND_IN_SET(TRIM(mld.assigned_agent), v_agent_id))
    AND ((v_year IS NOT NULL AND v_year <> '' AND YEAR(mld.created_date) = v_year) 
    OR ((v_year IS NULL OR v_year = '') AND (((MONTH(CURDATE()) >= 4 AND 
    mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-04-01'), '%Y-%m-%d')
    AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE())+1, '-03-31'), '%Y-%m-%d'))
	OR (MONTH(CURDATE()) < 4 AND mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE())-1, '-04-01'), '%Y-%m-%d')
	AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-03-31'), '%Y-%m-%d'))))
	AND (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(MONTH(mld.created_date),3,'0'), v_month))))
    and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code, period
),
agent_actuals AS (
    SELECT
        ls.dealer_code,
        ls.assigned_agent,
		ls.period,
        SUM(COALESCE(ls.netPremium,0)) AS netTotalPremium,
        SUM(COALESCE(ls.addonPremiumAmount,0)) AS netAddonPremium,
        SUM(COALESCE(ls.netOdPremiumAmount,0)) AS netOdPremium,
        SUM(COALESCE(conv.conversionCount,0)) AS totalConversions,
        SUM(COALESCE(conv.policiesConverted,0)) AS totalPolicies,
        GREATEST(SUM(COALESCE(cs.leadsContacted,0)),SUM(COALESCE(lac.leadsContacted,0))) AS totalContacted,
        SUM(COALESCE(ls.leadsAssigned,0)) AS totalAssigned
    FROM lead_archive_stats ls     
    LEFT JOIN call_stats cs 
        ON cs.assigned_agent = ls.assigned_agent
        AND cs.dealer_code = ls.dealer_code
    LEFT JOIN lead_archive_call lac 
        ON lac.assigned_agent = ls.assigned_agent
        AND lac.dealer_code = ls.dealer_code
    LEFT JOIN conversion_stats conv 
        ON conv.assigned_agent = ls.assigned_agent
        AND conv.dealer_code = ls.dealer_code
    GROUP BY ls.dealer_code, ls.assigned_agent,ls.period
),
dealer_actuals AS (
    SELECT
        dealer_code,
        period,
        SUM(netTotalPremium) AS netTotalPremium,
        SUM(netAddonPremium) AS netAddonPremium,
        SUM(netOdPremium) AS netOdPremium,
        SUM(totalConversions) AS totalConversions,
        SUM(totalPolicies) AS totalPolicies,
        SUM(totalContacted) AS totalContacted,
        SUM(totalAssigned) AS totalAssigned
    FROM agent_actuals
    GROUP BY dealer_code,period
),
dealer_targets AS (
    SELECT
        dealer_code,
        team_member,
		DATE_FORMAT(STR_TO_DATE(CONCAT(year, '-', TRIM(month), '-01'), '%Y-%M-%d'), '%Y-%m') AS period_match,
        /*SUM(CASE 
        WHEN kpi = 'Net Total Premium' AND period_type = 'YEAR' THEN target_value / 12
        WHEN kpi = 'Net Total Premium' THEN target_value
        ELSE 0 
		END) AS target_netTotalPremium,

		SUM(CASE 
			WHEN kpi = 'Net Add-on Premium' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Net Add-on Premium' THEN target_value
			ELSE 0 
		END) AS target_netAddonPremium,

		SUM(CASE 
			WHEN kpi = 'Net OD Premium' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Net OD Premium' THEN target_value
			ELSE 0 
		END) AS target_netOdPremium,

		SUM(CASE 
			WHEN kpi = 'Conversion Ratio %' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Conversion Ratio %' THEN target_value
			ELSE 0 
		END) AS target_conversionRatio,

		SUM(CASE 
			WHEN kpi = 'Retention Ratio %' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Retention Ratio %' THEN target_value
			ELSE 0 
		END) AS target_retentionRatio*/
        
        SUM(CASE WHEN kpi = 'Net Total Premium' AND v_month IS NOT NULL AND v_month <> '' AND 
        (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(month,3,'0'), v_month)) AND 
        period_type = 'month' THEN target_value
        WHEN kpi = 'Net Total Premium' AND v_year IS NOT NULL AND v_year <> '' AND year = v_year
        AND (v_month IS NULL OR v_month = '') AND period_type = 'YEAR' THEN target_value / 12
        ELSE 0 
		END) AS target_netTotalPremium,

        SUM(CASE WHEN kpi = 'Net Add-on Premium' AND v_month IS NOT NULL AND v_month <> '' AND 
        (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(month,3,'0'), v_month)) AND 
        period_type = 'month' THEN target_value
        WHEN kpi = 'Net Add-on Premium' AND v_year IS NOT NULL AND v_year <> '' AND year = v_year
        AND (v_month IS NULL OR v_month = '') AND period_type = 'YEAR' THEN target_value / 12
        ELSE 0 
		END) AS target_netAddonPremium,
		
        SUM(CASE WHEN kpi = 'Net OD Premium' AND v_month IS NOT NULL AND v_month <> '' AND 
        (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(month,3,'0'), v_month)) AND 
        period_type = 'month' THEN target_value
        WHEN kpi = 'Net OD Premium' AND v_year IS NOT NULL AND v_year <> '' AND year = v_year
        AND (v_month IS NULL OR v_month = '') AND period_type = 'YEAR' THEN target_value / 12
        ELSE 0 
		END) AS target_netOdPremium,
        
        SUM(CASE WHEN kpi = 'Conversion Ratio %' AND v_month IS NOT NULL AND v_month <> '' AND 
        (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(month,3,'0'), v_month)) AND 
        period_type = 'month' THEN target_value
        WHEN kpi = 'Conversion Ratio %' AND v_year IS NOT NULL AND v_year <> '' AND year = v_year
        AND (v_month IS NULL OR v_month = '') AND period_type = 'YEAR' THEN target_value / 12
        ELSE 0 
		END) AS target_conversionRatio,

		SUM(CASE WHEN kpi = 'Retention Ratio %' AND v_month IS NOT NULL AND v_month <> '' AND 
        (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(month,3,'0'), v_month)) AND 
        period_type = 'month' THEN target_value
        WHEN kpi = 'Retention Ratio %' AND v_year IS NOT NULL AND v_year <> '' AND year = v_year
        AND (v_month IS NULL OR v_month = '') AND period_type = 'YEAR' THEN target_value / 12
        ELSE 0 
		END) AS target_retentionRatio
        
        -- SUM(CASE WHEN kpi = 'Net Total Premium' THEN target_value END) AS target_netTotalPremium,
        -- SUM(CASE WHEN kpi = 'Net Add-on Premium' THEN target_value END) AS target_netAddonPremium,
        -- SUM(CASE WHEN kpi = 'Net OD Premium' THEN target_value END) AS target_netOdPremium,
        -- SUM(CASE WHEN kpi = 'Conversion Ratio %' THEN target_value END) AS target_conversionRatio,
        -- SUM(CASE WHEN kpi = 'Retention Ratio %' THEN target_value END) AS target_retentionRatio

    FROM mmi_target_planning
    WHERE (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(dealer_code), v_dealer_code))
    AND (v_agent_id IS NULL OR v_agent_id='' 
           OR FIND_IN_SET(TRIM(team_member), v_agent_id))
    AND ((v_year IS NOT NULL AND v_year <> '' AND mmi_target_planning.year = v_year)
    OR ((v_year IS NULL OR v_year = '')
        AND (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(month,3,'0'), v_month))
        AND mmi_target_planning.year = YEAR(CURDATE())))  
     and team_member IN (SELECT user_id FROM dealer_team_members)    
    GROUP BY dealer_code, team_member, year, month
),
agent_overall_actuals AS (
    SELECT
        dealer_code,
        assigned_agent,
        SUM(totalConversions) AS totalConversions,
        SUM(totalPolicies) AS totalPolicies,
        SUM(totalContacted) AS totalContacted,
        SUM(totalAssigned) AS totalAssigned
    FROM agent_actuals
    GROUP BY dealer_code, assigned_agent
),
agent_names AS (
    SELECT DISTINCT
        mu.user_id,
        CONCAT(mud.first_name,' ',mud.last_name) AS agent_name
    FROM mmi_mast_user mu
    JOIN mmi_mast_user_registration_detail mud 
        ON mu.user_id = mud.id
    LEFT JOIN mmi_user_dealer_mapping udm on udm.user_id = mud.id
    WHERE dealer_id = v_dealer_code
),
dealer_targets_final AS (
    SELECT
        dealer_code,
        team_member,        
        CASE 
            WHEN v_month IS NOT NULL AND v_month <> '' 
                THEN period_match
            ELSE 'YEAR'
        END AS join_key,

        SUM(target_netTotalPremium) AS target_netTotalPremium,
        SUM(target_netAddonPremium) AS target_netAddonPremium,
        SUM(target_netOdPremium) AS target_netOdPremium,
        SUM(target_conversionRatio) AS target_conversionRatio,
        SUM(target_retentionRatio) AS target_retentionRatio

    FROM dealer_targets
    GROUP BY dealer_code, team_member, join_key
)
SELECT
    -- aa.dealer_code,
    -- aa.period,
    -- aa.assigned_agent,
    an.agent_name,

    -- PREMIUMS
    aa.netTotalPremium        AS actual_net_total_premium,
    dt.target_netTotalPremium AS target_net_total_premium,

    aa.netAddonPremium        AS actual_net_addon_premium,
    dt.target_netAddonPremium AS target_net_addon_premium,

    aa.netOdPremium           AS actual_net_od_premium,
    dt.target_netOdPremium    AS target_net_od_premium,
    -- ROUND(aa.totalConversions / NULLIF(aa.totalContacted,0) * 100,2) 
       -- AS actual_conversion_ratio,
    LEAST(ROUND(aa.totalConversions / NULLIF(aa.totalContacted,0) * 100,2),100) AS actual_conversion_ratio,
    dt.target_conversionRatio AS target_conversion_ratio,

    -- ROUND(aa.totalPolicies / NULLIF(aa.totalAssigned,0) * 100,2) 
       -- AS actual_retention_ratio,
    LEAST(ROUND(aa.totalPolicies / NULLIF(aa.totalAssigned,0) * 100,2),100) AS actual_retention_ratio,
    dt.target_retentionRatio  AS target_retention_ratio

    -- COUNTS (optional but useful)
    -- aa.totalAssigned,
    -- aa.totalContacted,
    -- aa.totalConversions,
    -- aa.totalPolicies

FROM agent_actuals aa
/*LEFT JOIN dealer_targets dt 
    ON aa.dealer_code = dt.dealer_code
	AND aa.assigned_agent = dt.team_member
    AND aa.period = dt.period_match*/
LEFT JOIN dealer_targets_final dt 
    ON aa.dealer_code = dt.dealer_code
    AND aa.assigned_agent = dt.team_member
    AND (
        (v_month IS NOT NULL AND v_month <> '' AND aa.period = dt.join_key)
        OR
        (v_month IS NULL OR v_month = '') AND dt.join_key = 'YEAR'
)    
LEFT JOIN agent_names an
    ON aa.assigned_agent = an.user_id
WHERE (v_month IS NULL OR v_month = '' 
     OR aa.period = DATE_FORMAT(STR_TO_DATE(CONCAT(v_year, '-', v_month, '-01'), '%Y-%b-%d'), '%Y-%m'))    
ORDER BY aa.dealer_code, aa.period, an.agent_name;

ELSEIF v_check_count IS NOT NULL AND v_check_count <> 0 THEN

WITH RECURSIVE team_hierarchy AS (
	SELECT v_user_id AS user_id
),
dealer_team_members AS (
	SELECT th.user_id
	FROM team_hierarchy th
	JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
	WHERE udm.dealer_id = v_dealer_code
),	
lead_archive_stats AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        SUM(mld.net_premium) AS netPremium,
        SUM(mld.addon_premium_amount) AS addonPremiumAmount,
        SUM(mld.net_od_premium_amount) AS netOdPremiumAmount,
        COUNT(DISTINCT mld.lead_id) AS leadsAssigned
    FROM mmi_lead_archive_details mld
    WHERE mld.assigned_agent IS NOT NULL AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
           AND DATE(mld.created_date) BETWEEN v_from_date AND v_to_date
           and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code,period
),

call_stats AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_details mld 
        ON mld.lead_id = cdh.lead_id
    WHERE mld.assigned_agent IS NOT NULL AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
           AND DATE(mld.created_date) BETWEEN v_from_date AND v_to_date
           and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code,period
),

lead_archive_call AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_archive_details mld 
        ON mld.lead_id = cdh.lead_id
    WHERE mld.assigned_agent IS NOT NULL AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
           AND DATE(mld.created_date) BETWEEN v_from_date AND v_to_date
           and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code,period
),

conversion_stats AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        COUNT(DISTINCT policy_no) AS policiesConverted,
        COUNT(DISTINCT CASE 
            WHEN lead_status='Won' 
             AND converted_flag='CRM Renewal'
            THEN lead_id END) AS conversionCount
    FROM mmi_lead_archive_details mld
    WHERE mld.assigned_agent IS NOT NULL AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
           AND DATE(mld.created_date) BETWEEN v_from_date AND v_to_date
           and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code,period
),

agent_actuals AS (
    SELECT
        ls.dealer_code,
        ls.assigned_agent,
        ls.period,

        SUM(COALESCE(ls.netPremium,0)) AS netTotalPremium,
        SUM(COALESCE(ls.addonPremiumAmount,0)) AS netAddonPremium,
        SUM(COALESCE(ls.netOdPremiumAmount,0)) AS netOdPremium,

        SUM(COALESCE(conv.conversionCount,0)) AS totalConversions,
        SUM(COALESCE(conv.policiesConverted,0)) AS totalPolicies,

        GREATEST(SUM(COALESCE(cs.leadsContacted,0)),SUM(COALESCE(lac.leadsContacted,0))) AS totalContacted,
        SUM(COALESCE(ls.leadsAssigned,0)) AS totalAssigned

    FROM lead_archive_stats ls   
    LEFT JOIN call_stats cs 
        ON cs.assigned_agent = ls.assigned_agent
        AND cs.dealer_code = ls.dealer_code
    LEFT JOIN lead_archive_call lac 
        ON lac.assigned_agent = ls.assigned_agent
        AND lac.dealer_code = ls.dealer_code
    LEFT JOIN conversion_stats conv 
        ON conv.assigned_agent = ls.assigned_agent
        AND conv.dealer_code = ls.dealer_code
    GROUP BY ls.dealer_code, ls.assigned_agent, ls.period
),

dealer_actuals AS (
    SELECT
        dealer_code,
        period,
        SUM(netTotalPremium) AS netTotalPremium,
        SUM(netAddonPremium) AS netAddonPremium,
        SUM(netOdPremium) AS netOdPremium,
        SUM(totalConversions) AS totalConversions,
        SUM(totalPolicies) AS totalPolicies,
        SUM(totalContacted) AS totalContacted,
        SUM(totalAssigned) AS totalAssigned
    FROM agent_actuals
    GROUP BY dealer_code,period
),

dealer_targets AS (
    SELECT
        dealer_code,
        -- team_member,
        SUM(CASE 
        WHEN kpi = 'Net Total Premium' AND period_type = 'YEAR' THEN target_value / 12
        WHEN kpi = 'Net Total Premium' THEN target_value
        ELSE 0 
		END) AS target_netTotalPremium,

		SUM(CASE 
			WHEN kpi = 'Net Add-on Premium' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Net Add-on Premium' THEN target_value
			ELSE 0 
		END) AS target_netAddonPremium,

		SUM(CASE 
			WHEN kpi = 'Net OD Premium' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Net OD Premium' THEN target_value
			ELSE 0 
		END) AS target_netOdPremium,

		SUM(CASE 
			WHEN kpi = 'Conversion Ratio %' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Conversion Ratio %' THEN target_value
			ELSE 0 
		END) AS target_conversionRatio,

		SUM(CASE 
			WHEN kpi = 'Retention Ratio %' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Retention Ratio %' THEN target_value
			ELSE 0 
		END) AS target_retentionRatio
        -- SUM(CASE WHEN kpi = 'Net Total Premium' THEN target_value END) AS target_netTotalPremium,
        -- SUM(CASE WHEN kpi = 'Net Add-on Premium' THEN target_value END) AS target_netAddonPremium,
        -- SUM(CASE WHEN kpi = 'Net OD Premium' THEN target_value END) AS target_netOdPremium,
        -- SUM(CASE WHEN kpi = 'Conversion Ratio %' THEN target_value END) AS target_conversionRatio,
        -- SUM(CASE WHEN kpi = 'Retention Ratio %' THEN target_value END) AS target_retentionRatio

    FROM mmi_target_planning
    WHERE (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(dealer_code), v_dealer_code))
     AND ((year = YEAR(v_from_date) AND month >= 4)OR (year = YEAR(v_to_date) AND month <= 3))
     and team_member IN (SELECT user_id FROM dealer_team_members)
    GROUP BY dealer_code
),
overall_actuals AS (
    SELECT
        dealer_code,
        SUM(totalConversions) AS totalConversions,
        SUM(totalPolicies) AS totalPolicies,
        SUM(totalContacted) AS totalContacted,
        SUM(totalAssigned) AS totalAssigned
    FROM dealer_actuals
    GROUP BY dealer_code
),
agent_names AS (
    SELECT DISTINCT
        mu.user_id,
        CONCAT(mud.first_name,' ',mud.last_name) AS agent_name
    FROM mmi_mast_user mu
    JOIN mmi_mast_user_registration_detail mud 
        ON mu.user_id = mud.id
    LEFT JOIN mmi_user_dealer_mapping udm on udm.user_id = mud.id
    WHERE dealer_id = v_dealer_code    
)
SELECT
    -- aa.dealer_code,
    -- aa.period,
    -- aa.assigned_agent,
    an.agent_name,

    -- PREMIUMS
    aa.netTotalPremium        AS actual_net_total_premium,
    dt.target_netTotalPremium AS target_net_total_premium,

    aa.netAddonPremium        AS actual_net_addon_premium,
    dt.target_netAddonPremium AS target_net_addon_premium,

    aa.netOdPremium           AS actual_net_od_premium,
    dt.target_netOdPremium    AS target_net_od_premium,

    -- RATIOS
    -- ROUND(aa.totalConversions / NULLIF(aa.totalContacted,0) * 100,2) 
       -- AS actual_conversion_ratio,
	LEAST(ROUND(aa.totalConversions / NULLIF(aa.totalContacted,0) * 100,2),100) AS actual_conversion_ratio,   
    dt.target_conversionRatio AS target_conversion_ratio,

    -- ROUND(aa.totalPolicies / NULLIF(aa.totalAssigned,0) * 100,2) 
       -- AS actual_retention_ratio,
    LEAST(ROUND(aa.totalPolicies / NULLIF(aa.totalAssigned,0) * 100,2),100) AS actual_retention_ratio,
    dt.target_retentionRatio  AS target_retention_ratio

    -- COUNTS (optional but useful)
    -- aa.totalAssigned,
    -- aa.totalContacted,
    -- aa.totalConversions,
    -- aa.totalPolicies

FROM agent_actuals aa
LEFT JOIN dealer_targets dt 
    ON aa.dealer_code = dt.dealer_code
	-- AND aa.assigned_agent = dt.team_member
LEFT JOIN agent_names an
    ON aa.assigned_agent = an.user_id
ORDER BY aa.dealer_code, aa.period, an.agent_name;

END IF;
END IF;

IF v_type = 'onload' THEN
	WITH RECURSIVE team_hierarchy AS (
				SELECT ur.user_id
				FROM mmi_user_reporting ur
				WHERE ur.supervisor_id =v_user_id
				UNION ALL
				SELECT ur2.user_id
				FROM mmi_user_reporting ur2
				INNER JOIN team_hierarchy th ON ur2.supervisor_id = th.user_id
			)
			SELECT
				th.user_id as teamMemberId,
				CONCAT(COALESCE(mud.first_name, ''), ' ', COALESCE(mud.last_name, '')) AS teamMemberName
			FROM team_hierarchy th
			JOIN mmi_mast_user mu ON th.user_id = mu.user_id
			JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
			JOIN mmi_mast_user_registration_detail mud ON mu.user_id = mud.id
			WHERE udm.dealer_id = v_dealer_code
			ORDER BY mud.first_name, mud.last_name;
    
    IF (v_agent_id IS NOT NULL AND v_agent_id <> '') THEN
	IF (v_year IS NOT NULL AND v_year <> '') THEN
		select distinct month from mmi_target_planning where team_member = v_agent_id and year = v_year and month is not null and month <> '';
		select distinct year from mmi_target_planning where team_member = v_agent_id and year is not null and year <> '';
	ELSE
		select distinct year from mmi_target_planning where team_member = v_agent_id and year is not null and year <> '';
	END IF;

	ELSE

	IF (v_year IS NOT NULL AND v_year <> '') THEN
		select distinct month from mmi_target_planning where team_member = v_user_id and year = v_year and month is not null and month <> '';
		select distinct year from mmi_target_planning where team_member = v_user_id and year is not null and year <> '';
	ELSE
		select distinct year from mmi_target_planning where team_member = v_user_id and year is not null and year <> '';
	END IF;
	END IF;
    
END IF;
    
select count(distinct id) as checkCount INTO v_check_count from mmi_target_planning where team_member = v_user_id;

IF (v_year IS NOT NULL AND v_year <> '') THEN
WITH RECURSIVE team_hierarchy AS (
	SELECT v_user_id AS user_id
	UNION ALL
	SELECT ur.user_id
	FROM mmi_user_reporting ur
	INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
dealer_team_members AS (
	SELECT th.user_id
	FROM team_hierarchy th
	JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
	WHERE udm.dealer_id = v_dealer_code
),
lead_archive_stats AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        SUM(mld.net_premium) AS netPremium,
        SUM(mld.addon_premium_amount) AS addonPremiumAmount,
        SUM(mld.net_od_premium_amount) AS netOdPremiumAmount,
        COUNT(DISTINCT mld.lead_id) AS leadsAssigned
    FROM mmi_lead_archive_details mld
    WHERE mld.assigned_agent IS NOT NULL 
    AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_agent_id IS NULL OR v_agent_id='' 
           OR FIND_IN_SET(TRIM(mld.assigned_agent), v_agent_id))
    AND ((v_year IS NOT NULL AND v_year <> '' AND YEAR(mld.created_date) = v_year) 
    OR ((v_year IS NULL OR v_year = '') AND (((MONTH(CURDATE()) >= 4 AND 
    mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-04-01'), '%Y-%m-%d')
    AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE())+1, '-03-31'), '%Y-%m-%d'))
	OR (MONTH(CURDATE()) < 4 AND mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE())-1, '-04-01'), '%Y-%m-%d')
	AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-03-31'), '%Y-%m-%d'))))
	AND (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(MONTH(mld.created_date),3,'0'), v_month))))
    and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code, period
),
call_stats AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_details mld 
        ON mld.lead_id = cdh.lead_id
    WHERE mld.assigned_agent IS NOT NULL 
    AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_agent_id IS NULL OR v_agent_id='' 
           OR FIND_IN_SET(TRIM(mld.assigned_agent), v_agent_id)) 
    AND ((v_year IS NOT NULL AND v_year <> '' AND YEAR(mld.created_date) = v_year) 
    OR ((v_year IS NULL OR v_year = '') AND (((MONTH(CURDATE()) >= 4 AND 
    mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-04-01'), '%Y-%m-%d')
    AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE())+1, '-03-31'), '%Y-%m-%d'))
	OR (MONTH(CURDATE()) < 4 AND mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE())-1, '-04-01'), '%Y-%m-%d')
	AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-03-31'), '%Y-%m-%d'))))
	AND (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(MONTH(mld.created_date),3,'0'), v_month))))
    and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code, period
),
lead_archive_call AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_archive_details mld 
        ON mld.lead_id = cdh.lead_id
    WHERE mld.assigned_agent IS NOT NULL 
    AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_agent_id IS NULL OR v_agent_id='' 
           OR FIND_IN_SET(TRIM(mld.assigned_agent), v_agent_id))
	AND ((v_year IS NOT NULL AND v_year <> '' AND YEAR(mld.created_date) = v_year) 
    OR ((v_year IS NULL OR v_year = '') AND (((MONTH(CURDATE()) >= 4 AND 
    mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-04-01'), '%Y-%m-%d')
    AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE())+1, '-03-31'), '%Y-%m-%d'))
	OR (MONTH(CURDATE()) < 4 AND mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE())-1, '-04-01'), '%Y-%m-%d')
	AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-03-31'), '%Y-%m-%d'))))
	AND (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(MONTH(mld.created_date),3,'0'), v_month))))
    and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code, period
),
conversion_stats AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        COUNT(DISTINCT policy_no) AS policiesConverted,
        COUNT(DISTINCT CASE 
            WHEN lead_status='Won' 
             AND converted_flag='CRM Renewal'
            THEN lead_id END) AS conversionCount
    FROM mmi_lead_archive_details mld
    WHERE mld.assigned_agent IS NOT NULL 
    AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_agent_id IS NULL OR v_agent_id='' 
           OR FIND_IN_SET(TRIM(mld.assigned_agent), v_agent_id))
    AND ((v_year IS NOT NULL AND v_year <> '' AND YEAR(mld.created_date) = v_year) 
    OR ((v_year IS NULL OR v_year = '') AND (((MONTH(CURDATE()) >= 4 AND 
    mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-04-01'), '%Y-%m-%d')
    AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE())+1, '-03-31'), '%Y-%m-%d'))
	OR (MONTH(CURDATE()) < 4 AND mld.created_date >= STR_TO_DATE(CONCAT(YEAR(CURDATE())-1, '-04-01'), '%Y-%m-%d')
	AND mld.created_date <= STR_TO_DATE(CONCAT(YEAR(CURDATE()), '-03-31'), '%Y-%m-%d'))))
	AND (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(MONTH(mld.created_date),3,'0'), v_month))))
    and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code, period
),
agent_actuals AS (
    SELECT
        ls.dealer_code,
        ls.assigned_agent,
		ls.period,
        SUM(COALESCE(ls.netPremium,0)) AS netTotalPremium,
        SUM(COALESCE(ls.addonPremiumAmount,0)) AS netAddonPremium,
        SUM(COALESCE(ls.netOdPremiumAmount,0)) AS netOdPremium,
        SUM(COALESCE(conv.conversionCount,0)) AS totalConversions,
        SUM(COALESCE(conv.policiesConverted,0)) AS totalPolicies,
        GREATEST(SUM(COALESCE(cs.leadsContacted,0)),SUM(COALESCE(lac.leadsContacted,0))) AS totalContacted,
        SUM(COALESCE(ls.leadsAssigned,0)) AS totalAssigned
    FROM lead_archive_stats ls     
    LEFT JOIN call_stats cs 
        ON cs.assigned_agent = ls.assigned_agent
        AND cs.dealer_code = ls.dealer_code
    LEFT JOIN lead_archive_call lac 
        ON lac.assigned_agent = ls.assigned_agent
        AND lac.dealer_code = ls.dealer_code
    LEFT JOIN conversion_stats conv 
        ON conv.assigned_agent = ls.assigned_agent
        AND conv.dealer_code = ls.dealer_code
    GROUP BY ls.dealer_code, ls.assigned_agent,ls.period
),
dealer_actuals AS (
    SELECT
        dealer_code,
        period,
        SUM(netTotalPremium) AS netTotalPremium,
        SUM(netAddonPremium) AS netAddonPremium,
        SUM(netOdPremium) AS netOdPremium,
        SUM(totalConversions) AS totalConversions,
        SUM(totalPolicies) AS totalPolicies,
        SUM(totalContacted) AS totalContacted,
        SUM(totalAssigned) AS totalAssigned
    FROM agent_actuals
    GROUP BY dealer_code,period
),
dealer_targets AS (
    SELECT
        dealer_code,
        team_member,
        DATE_FORMAT(STR_TO_DATE(CONCAT(year, '-', TRIM(month), '-01'), '%Y-%M-%d'), '%Y-%m') AS period_match,
        /*SUM(CASE 
        WHEN kpi = 'Net Total Premium' AND period_type = 'YEAR' THEN target_value / 12
        WHEN kpi = 'Net Total Premium' THEN target_value
        ELSE 0 
		END) AS target_netTotalPremium,

		SUM(CASE 
			WHEN kpi = 'Net Add-on Premium' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Net Add-on Premium' THEN target_value
			ELSE 0 
		END) AS target_netAddonPremium,

		SUM(CASE 
			WHEN kpi = 'Net OD Premium' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Net OD Premium' THEN target_value
			ELSE 0 
		END) AS target_netOdPremium,

		SUM(CASE 
			WHEN kpi = 'Conversion Ratio %' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Conversion Ratio %' THEN target_value
			ELSE 0 
		END) AS target_conversionRatio,

		SUM(CASE 
			WHEN kpi = 'Retention Ratio %' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Retention Ratio %' THEN target_value
			ELSE 0 
		END) AS target_retentionRatio*/
        
        SUM(CASE WHEN kpi = 'Net Total Premium' AND v_month IS NOT NULL AND v_month <> '' AND 
        (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(month,3,'0'), v_month)) AND 
        period_type = 'month' THEN target_value
        WHEN kpi = 'Net Total Premium' AND v_year IS NOT NULL AND v_year <> '' AND year = v_year
        AND (v_month IS NULL OR v_month = '') AND period_type = 'YEAR' THEN target_value / 12
        ELSE 0 
		END) AS target_netTotalPremium,

        SUM(CASE WHEN kpi = 'Net Add-on Premium' AND v_month IS NOT NULL AND v_month <> '' AND 
        (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(month,3,'0'), v_month)) AND 
        period_type = 'month' THEN target_value
        WHEN kpi = 'Net Add-on Premium' AND v_year IS NOT NULL AND v_year <> '' AND year = v_year
        AND (v_month IS NULL OR v_month = '') AND period_type = 'YEAR' THEN target_value / 12
        ELSE 0 
		END) AS target_netAddonPremium,
		
        SUM(CASE WHEN kpi = 'Net OD Premium' AND v_month IS NOT NULL AND v_month <> '' AND 
        (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(month,3,'0'), v_month)) AND 
        period_type = 'month' THEN target_value
        WHEN kpi = 'Net OD Premium' AND v_year IS NOT NULL AND v_year <> '' AND year = v_year
        AND (v_month IS NULL OR v_month = '') AND period_type = 'YEAR' THEN target_value / 12
        ELSE 0 
		END) AS target_netOdPremium,
        
        SUM(CASE WHEN kpi = 'Conversion Ratio %' AND v_month IS NOT NULL AND v_month <> '' AND 
        (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(month,3,'0'), v_month)) AND 
        period_type = 'month' THEN target_value
        WHEN kpi = 'Conversion Ratio %' AND v_year IS NOT NULL AND v_year <> '' AND year = v_year
        AND (v_month IS NULL OR v_month = '') AND period_type = 'YEAR' THEN target_value / 12
        ELSE 0 
		END) AS target_conversionRatio,

		SUM(CASE WHEN kpi = 'Retention Ratio %' AND v_month IS NOT NULL AND v_month <> '' AND 
        (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(month,3,'0'), v_month)) AND 
        period_type = 'month' THEN target_value
        WHEN kpi = 'Retention Ratio %' AND v_year IS NOT NULL AND v_year <> '' AND year = v_year
        AND (v_month IS NULL OR v_month = '') AND period_type = 'YEAR' THEN target_value / 12
        ELSE 0 
		END) AS target_retentionRatio
        
        -- SUM(CASE WHEN kpi = 'Net Total Premium' THEN target_value END) AS target_netTotalPremium,
        -- SUM(CASE WHEN kpi = 'Net Add-on Premium' THEN target_value END) AS target_netAddonPremium,
        -- SUM(CASE WHEN kpi = 'Net OD Premium' THEN target_value END) AS target_netOdPremium,
        -- SUM(CASE WHEN kpi = 'Conversion Ratio %' THEN target_value END) AS target_conversionRatio,
        -- SUM(CASE WHEN kpi = 'Retention Ratio %' THEN target_value END) AS target_retentionRatio
    FROM mmi_target_planning
    WHERE (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(dealer_code), v_dealer_code))
    AND (v_agent_id IS NULL OR v_agent_id='' 
           OR FIND_IN_SET(TRIM(team_member), v_agent_id))
    AND ((v_year IS NOT NULL AND v_year <> '' AND mmi_target_planning.year = v_year)
    OR ((v_year IS NULL OR v_year = '')
        AND (v_month IS NULL OR v_month = '' OR FIND_IN_SET(LPAD(month,3,'0'), v_month))
        AND mmi_target_planning.year = YEAR(CURDATE())))  
     and team_member IN (SELECT user_id FROM dealer_team_members)    
    GROUP BY dealer_code, team_member, year, month
),
agent_overall_actuals AS (
    SELECT
        dealer_code,
        assigned_agent,
        period,
        SUM(totalConversions) AS totalConversions,
        SUM(totalPolicies) AS totalPolicies,
        SUM(totalContacted) AS totalContacted,
        SUM(totalAssigned) AS totalAssigned
    FROM agent_actuals
    GROUP BY dealer_code, assigned_agent, period
),
dealer_targets_final AS (
    SELECT
        dealer_code,
        team_member,        
        CASE 
            WHEN v_month IS NOT NULL AND v_month <> '' 
                THEN period_match
            ELSE 'YEAR'
        END AS join_key,

        SUM(target_netTotalPremium) AS target_netTotalPremium,
        SUM(target_netAddonPremium) AS target_netAddonPremium,
        SUM(target_netOdPremium) AS target_netOdPremium,
        SUM(target_conversionRatio) AS target_conversionRatio,
        SUM(target_retentionRatio) AS target_retentionRatio

    FROM dealer_targets
    GROUP BY dealer_code, team_member, join_key
)
SELECT
    'NET_TOTAL_PREMIUM' AS chart_type,
    aa.dealer_code,
    aa.period,
    aa.netTotalPremium AS actual_value,
    dt.target_netTotalPremium AS target_value
FROM agent_actuals aa
/*LEFT JOIN dealer_targets dt 
    ON aa.dealer_code = dt.dealer_code
    AND aa.period = dt.period_match*/
LEFT JOIN dealer_targets_final dt 
    ON aa.dealer_code = dt.dealer_code
    -- AND aa.assigned_agent = dt.team_member
    AND (
        (v_month IS NOT NULL AND v_month <> '' AND aa.period = dt.join_key)
        OR
        (v_month IS NULL OR v_month = '') AND dt.join_key = 'YEAR'
)    
WHERE (v_month IS NULL OR v_month = '' 
     OR aa.period = DATE_FORMAT(STR_TO_DATE(CONCAT(v_year, '-', v_month, '-01'), '%Y-%b-%d'), '%Y-%m'))    

UNION ALL

SELECT
    'NET_ADDON_PREMIUM' AS chart_type,
    aa.dealer_code,
    aa.period,
    aa.netAddonPremium AS actual_value,
    dt.target_netAddonPremium AS target_value
FROM agent_actuals aa
/*LEFT JOIN dealer_targets dt 
    ON aa.dealer_code = dt.dealer_code
    AND aa.period = dt.period_match*/
LEFT JOIN dealer_targets_final dt 
    ON aa.dealer_code = dt.dealer_code
    -- AND aa.assigned_agent = dt.team_member
    AND (
        (v_month IS NOT NULL AND v_month <> '' AND aa.period = dt.join_key)
        OR
        (v_month IS NULL OR v_month = '') AND dt.join_key = 'YEAR'
)    
WHERE (v_month IS NULL OR v_month = '' 
     OR aa.period = DATE_FORMAT(STR_TO_DATE(CONCAT(v_year, '-', v_month, '-01'), '%Y-%b-%d'), '%Y-%m'))    

UNION ALL

SELECT
    'NET_OD_PREMIUM' AS chart_type,
    aa.dealer_code,
    aa.period,
    aa.netOdPremium AS actual_value,
    dt.target_netOdPremium AS target_value
FROM agent_actuals aa
/*LEFT JOIN dealer_targets dt 
    ON aa.dealer_code = dt.dealer_code
    AND aa.period = dt.period_match*/
LEFT JOIN dealer_targets_final dt 
    ON aa.dealer_code = dt.dealer_code
    -- AND aa.assigned_agent = dt.team_member
    AND (
        (v_month IS NOT NULL AND v_month <> '' AND aa.period = dt.join_key)
        OR
        (v_month IS NULL OR v_month = '') AND dt.join_key = 'YEAR'
)    
WHERE (v_month IS NULL OR v_month = '' 
     OR aa.period = DATE_FORMAT(STR_TO_DATE(CONCAT(v_year, '-', v_month, '-01'), '%Y-%b-%d'), '%Y-%m'))    
   
UNION ALL

SELECT
    'CONVERSION RATIO' AS chart_type,
    aa.dealer_code,
    NULL AS period,
    -- ROUND(aa.totalConversions / NULLIF(aa.totalContacted,0) * 100,2) AS actual_value,
    LEAST(ROUND(aa.totalConversions / NULLIF(aa.totalContacted,0) * 100,2),100) AS actual_value,
    dt.target_conversionRatio AS target_value
FROM agent_overall_actuals aa
/*LEFT JOIN dealer_targets dt 
    ON aa.dealer_code = dt.dealer_code
    AND aa.period = dt.period_match*/
LEFT JOIN dealer_targets_final dt 
    ON aa.dealer_code = dt.dealer_code
    -- AND aa.assigned_agent = dt.team_member
    AND (
        (v_month IS NOT NULL AND v_month <> '' AND aa.period = dt.join_key)
        OR
        (v_month IS NULL OR v_month = '') AND dt.join_key = 'YEAR'
)    
WHERE (v_month IS NULL OR v_month = '' 
     OR aa.period = DATE_FORMAT(STR_TO_DATE(CONCAT(v_year, '-', v_month, '-01'), '%Y-%b-%d'), '%Y-%m'))    
   
UNION ALL

SELECT
    'RETENTION RATIO' AS chart_type,
    aa.dealer_code,
    NULL AS period,
    -- ROUND(aa.totalPolicies / NULLIF(aa.totalAssigned,0) * 100,2)AS actual_value,
    LEAST(ROUND(aa.totalPolicies / NULLIF(aa.totalAssigned,0) * 100,2),100) AS actual_value,
    dt.target_retentionRatio AS target_value
FROM agent_overall_actuals aa
/*LEFT JOIN dealer_targets dt 
    ON aa.dealer_code = dt.dealer_code
    AND aa.period = dt.period_match*/
LEFT JOIN dealer_targets_final dt 
    ON aa.dealer_code = dt.dealer_code
    -- AND aa.assigned_agent = dt.team_member
    AND (
        (v_month IS NOT NULL AND v_month <> '' AND aa.period = dt.join_key)
        OR
        (v_month IS NULL OR v_month = '') AND dt.join_key = 'YEAR'
)    
WHERE (v_month IS NULL OR v_month = '' 
     OR aa.period = DATE_FORMAT(STR_TO_DATE(CONCAT(v_year, '-', v_month, '-01'), '%Y-%b-%d'), '%Y-%m'));

ELSEIF v_check_count IS NOT NULL AND v_check_count <> 0 THEN

WITH RECURSIVE team_hierarchy AS (
	SELECT v_user_id AS user_id
),
dealer_team_members AS (
	SELECT th.user_id
	FROM team_hierarchy th
	JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
	WHERE udm.dealer_id = v_dealer_code
),	
lead_archive_stats AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        SUM(mld.net_premium) AS netPremium,
        SUM(mld.addon_premium_amount) AS addonPremiumAmount,
        SUM(mld.net_od_premium_amount) AS netOdPremiumAmount,
        COUNT(DISTINCT mld.lead_id) AS leadsAssigned
    FROM mmi_lead_archive_details mld
    WHERE mld.assigned_agent IS NOT NULL AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
           AND DATE(mld.created_date) BETWEEN v_from_date AND v_to_date
           and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code,period
),
call_stats AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_details mld 
        ON mld.lead_id = cdh.lead_id
    WHERE mld.assigned_agent IS NOT NULL AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
           AND DATE(mld.created_date) BETWEEN v_from_date AND v_to_date
           and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code,period
),
lead_archive_call AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        COUNT(DISTINCT cdh.lead_id) AS leadsContacted
    FROM mmi_call_disposition_history cdh
    JOIN mmi_lead_archive_details mld 
        ON mld.lead_id = cdh.lead_id
    WHERE mld.assigned_agent IS NOT NULL AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
           AND DATE(mld.created_date) BETWEEN v_from_date AND v_to_date
           and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code,period
),
conversion_stats AS (
    SELECT
        mld.assigned_agent,
        mld.dealer_code,
        DATE_FORMAT(mld.created_date, '%Y-%m') AS period,
        COUNT(DISTINCT policy_no) AS policiesConverted,
        COUNT(DISTINCT CASE 
            WHEN lead_status='Won' 
             AND converted_flag='CRM Renewal'
            THEN lead_id END) AS conversionCount
    FROM mmi_lead_archive_details mld
    WHERE mld.assigned_agent IS NOT NULL AND (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
           AND DATE(mld.created_date) BETWEEN v_from_date AND v_to_date
           and mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
    GROUP BY mld.assigned_agent, mld.dealer_code,period
),
agent_actuals AS (
    SELECT
        ls.dealer_code,
        ls.assigned_agent,
        ls.period,
        SUM(COALESCE(ls.netPremium,0)) AS netTotalPremium,
        SUM(COALESCE(ls.addonPremiumAmount,0)) AS netAddonPremium,
        SUM(COALESCE(ls.netOdPremiumAmount,0)) AS netOdPremium,
        SUM(COALESCE(conv.conversionCount,0)) AS totalConversions,
        SUM(COALESCE(conv.policiesConverted,0)) AS totalPolicies,
        GREATEST(SUM(COALESCE(cs.leadsContacted,0)),SUM(COALESCE(lac.leadsContacted,0))) AS totalContacted,
        SUM(COALESCE(ls.leadsAssigned,0)) AS totalAssigned
    FROM lead_archive_stats ls   
    LEFT JOIN call_stats cs 
        ON cs.assigned_agent = ls.assigned_agent
        AND cs.dealer_code = ls.dealer_code
    LEFT JOIN lead_archive_call lac 
        ON lac.assigned_agent = ls.assigned_agent
        AND lac.dealer_code = ls.dealer_code
    LEFT JOIN conversion_stats conv 
        ON conv.assigned_agent = ls.assigned_agent
        AND conv.dealer_code = ls.dealer_code
    GROUP BY ls.dealer_code, ls.assigned_agent, ls.period
),
dealer_actuals AS (
    SELECT
        dealer_code,
        period,
        SUM(netTotalPremium) AS netTotalPremium,
        SUM(netAddonPremium) AS netAddonPremium,
        SUM(netOdPremium) AS netOdPremium,
        SUM(totalConversions) AS totalConversions,
        SUM(totalPolicies) AS totalPolicies,
        SUM(totalContacted) AS totalContacted,
        SUM(totalAssigned) AS totalAssigned
    FROM agent_actuals
    GROUP BY dealer_code,period
),
dealer_targets AS (
    SELECT
        dealer_code,
        -- team_member,
        SUM(CASE 
        WHEN kpi = 'Net Total Premium' AND period_type = 'YEAR' THEN target_value / 12
        WHEN kpi = 'Net Total Premium' THEN target_value
        ELSE 0 
		END) AS target_netTotalPremium,

		SUM(CASE 
			WHEN kpi = 'Net Add-on Premium' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Net Add-on Premium' THEN target_value
			ELSE 0 
		END) AS target_netAddonPremium,

		SUM(CASE 
			WHEN kpi = 'Net OD Premium' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Net OD Premium' THEN target_value
			ELSE 0 
		END) AS target_netOdPremium,

		SUM(CASE 
			WHEN kpi = 'Conversion Ratio %' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Conversion Ratio %' THEN target_value
			ELSE 0 
		END) AS target_conversionRatio,

		SUM(CASE 
			WHEN kpi = 'Retention Ratio %' AND period_type = 'YEAR' THEN target_value / 12
			WHEN kpi = 'Retention Ratio %' THEN target_value
			ELSE 0 
		END) AS target_retentionRatio
        -- SUM(CASE WHEN kpi = 'Net Total Premium' THEN target_value END) AS target_netTotalPremium,
        -- SUM(CASE WHEN kpi = 'Net Add-on Premium' THEN target_value END) AS target_netAddonPremium,
        -- SUM(CASE WHEN kpi = 'Net OD Premium' THEN target_value END) AS target_netOdPremium,
        -- SUM(CASE WHEN kpi = 'Conversion Ratio %' THEN target_value END) AS target_conversionRatio,
        -- SUM(CASE WHEN kpi = 'Retention Ratio %' THEN target_value END) AS target_retentionRatio
    FROM mmi_target_planning
    WHERE (v_dealer_code IS NULL OR v_dealer_code='' 
           OR FIND_IN_SET(TRIM(dealer_code), v_dealer_code))
     AND ((year = YEAR(v_from_date) AND month >= 4)OR (year = YEAR(v_to_date) AND month <= 3))
     and team_member IN (SELECT user_id FROM dealer_team_members)
    GROUP BY dealer_code
),
overall_actuals AS (
    SELECT
        dealer_code,
        SUM(totalConversions) AS totalConversions,
        SUM(totalPolicies) AS totalPolicies,
        SUM(totalContacted) AS totalContacted,
        SUM(totalAssigned) AS totalAssigned
    FROM dealer_actuals
    GROUP BY dealer_code
)
SELECT DISTINCT
    'NET_TOTAL_PREMIUM' AS chart_type,
    aa.dealer_code,
    aa.period,
    aa.netTotalPremium AS actual_value,
    dt.target_netTotalPremium AS target_value
FROM dealer_actuals aa
LEFT JOIN dealer_targets dt 
    ON aa.dealer_code = dt.dealer_code

UNION ALL

SELECT DISTINCT
    'NET_ADDON_PREMIUM' AS chart_type,
    aa.dealer_code,
    aa.period,
    aa.netAddonPremium AS actual_value,
    dt.target_netAddonPremium AS target_value
FROM dealer_actuals aa
LEFT JOIN dealer_targets dt 
    ON aa.dealer_code = dt.dealer_code

UNION ALL

SELECT DISTINCT
    'NET_OD_PREMIUM' AS chart_type,
    aa.dealer_code,
    aa.period,
    aa.netOdPremium AS actual_value,
    dt.target_netOdPremium AS target_value
FROM dealer_actuals aa
LEFT JOIN dealer_targets dt 
    ON aa.dealer_code = dt.dealer_code
   
UNION ALL

SELECT DISTINCT
    'CONVERSION RATIO' AS chart_type,
    aa.dealer_code,
    NULL AS period, 
    -- ROUND(aa.totalConversions / NULLIF(aa.totalContacted,0) * 100,2) AS actual_value,
    LEAST(ROUND(aa.totalConversions / NULLIF(aa.totalContacted,0) * 100,2),100) AS actual_value,
    dt.target_conversionRatio AS target_value
FROM overall_actuals aa
LEFT JOIN dealer_targets dt 
    ON aa.dealer_code = dt.dealer_code
   
UNION ALL

SELECT DISTINCT
    'RETENTION RATIO' AS chart_type,
    aa.dealer_code,
    NULL AS period, 
    -- ROUND(aa.totalPolicies / NULLIF(aa.totalAssigned,0) * 100,2)AS actual_value,
    LEAST(ROUND(aa.totalPolicies / NULLIF(aa.totalAssigned,0) * 100,2),100) AS actual_value,
    dt.target_retentionRatio AS target_value
FROM overall_actuals aa
LEFT JOIN dealer_targets dt 
    ON aa.dealer_code = dt.dealer_code;

END IF;

	-- Select v_from_date, v_to_date;
    -- Select v_year,v_month;
	-- Select v_check_type;
	SET p_status_code = 200;
	SET p_status_message = 'SUCCESS';
    
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
