FROM mmi_lead_breached lb
LEFT JOIN tmp_all_leads mld on lb.lead_id = mld.lead_id 
LEFT JOIN mmi_mast_customer_details mcd 
       ON mcd.chassis_no = mld.vin
LEFT JOIN mmi_mast_user_registration_detail urd 
       ON urd.id = mld.assigned_agent
INNER JOIN mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = mld.dealer_code       
WHERE mld.lead_id IS NOT NULL AND mld.dealer_code = v_dealer_code
AND mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
AND (v_search_name IS NULL
	 OR v_search_name = ''
	 OR LOWER(TRIM(REPLACE(REPLACE(mcd.customer_name, '  ', ' '),'  ', ' '))) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')	 
     OR LOWER(TRIM(urd.first_name)) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')
     OR LOWER(TRIM(urd.last_name)) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')
     OR CONCAT(urd.first_name,' ',urd.last_name) LIKE CONCAT('%', v_search_name, '%')
	 OR mld.renewal_category LIKE CONCAT('%', v_search_name, '%')
	 OR mld.policy_expiry_date LIKE CONCAT('%', v_search_name, '%')
	 OR mld.expiry_days LIKE CONCAT('%', v_search_name, '%'));
END IF;

ELSE
IF v_check_type = 'dealerWise' THEN
SELECT 
    CONCAT(urd.first_name,' ',urd.last_name) AS agentName,
    CASE 
			WHEN ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2) = 0 
				THEN 0
		ELSE 
				100 - ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2)
		END AS followUpCompliancePercentage,
    COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END) AS totalLeadsAssigned,
    COUNT(DISTINCT lb.lead_id) AS totalLeadsBreached 

FROM mmi_mast_user_registration_detail urd
LEFT JOIN tmp_all_leads mld 
       ON mld.assigned_agent = urd.id
LEFT JOIN mmi_call_disposition_history cdh 
       ON cdh.lead_id = mld.lead_id
LEFT JOIN mmi_lead_breached lb 
       ON lb.lead_id = mld.lead_id
INNER JOIN mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = mld.dealer_code       
WHERE mld.dealer_code = v_dealer_code AND mld.assigned_agent = v_userId
AND (v_search_name IS NULL
	OR v_search_name = ''
	OR urd.first_name LIKE CONCAT('%', v_search_name, '%')
	OR urd.last_name LIKE CONCAT('%', v_search_name, '%')
	OR CONCAT(urd.first_name,' ',urd.last_name) LIKE CONCAT('%', v_search_name, '%'))
GROUP BY urd.first_name, urd.last_name ORDER BY followUpCompliancePercentage desc;

ELSEIF v_check_type = 'dealerWiseFollowUps' THEN
SELECT distinct 
    mcd.customer_name AS customerName,
    mld.lead_id AS leadId,
    CONCAT(urd.first_name,' ',urd.last_name) AS agentName,
    mld.renewal_category AS renewalCategory,
    DATE_FORMAT(mld.policy_expiry_date, '%d %b %Y') AS expiryDate,
    mld.expiry_days AS expiryDays,
    mld.lead_type AS leadType
FROM mmi_lead_breached lb
LEFT JOIN tmp_all_leads mld on lb.lead_id = mld.lead_id 
LEFT JOIN mmi_mast_customer_details mcd 
       ON mcd.chassis_no = mld.vin
LEFT JOIN mmi_mast_user_registration_detail urd 
       ON urd.id = mld.assigned_agent
INNER JOIN mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = mld.dealer_code
WHERE mld.lead_id IS NOT NULL AND mld.dealer_code = v_dealer_code AND mld.assigned_agent = v_userId
AND (v_search_name IS NULL
	 OR v_search_name = ''
	 OR LOWER(TRIM(REPLACE(REPLACE(mcd.customer_name, '  ', ' '),'  ', ' '))) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')	 
     OR LOWER(TRIM(urd.first_name)) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')
     OR LOWER(TRIM(urd.last_name)) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')
     OR CONCAT(urd.first_name,' ',urd.last_name) LIKE CONCAT('%', v_search_name, '%')
	 OR mld.renewal_category LIKE CONCAT('%', v_search_name, '%')
	 OR mld.policy_expiry_date LIKE CONCAT('%', v_search_name, '%')
	 OR mld.expiry_days LIKE CONCAT('%', v_search_name, '%'));
END IF;
END IF;
END IF;
END IF;

SET p_status_code = 200;
SET p_status_message = 'Success';

END ;;
