CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_tat_montoring_dashboard`(
	IN p_json JSON,
    OUT p_status_code INT,
    OUT p_status_message VARCHAR(255)
)
BEGIN
	
    DECLARE v_team_id VARCHAR(200); 
    DECLARE v_type VARCHAR(45);
    DECLARE v_renewal_category VARCHAR(500);
    DECLARE v_zone VARCHAR(45);
    DECLARE v_state VARCHAR(500);
    DECLARE v_dealer_code VARCHAR(2000);
    DECLARE v_dealerLocCode VARCHAR(450);
    DECLARE v_from_date  VARCHAR(450);
    DECLARE v_to_date  VARCHAR(450);
    DECLARE v_role_type VARCHAR(450);
	DECLARE v_userId VARCHAR(450);
    DECLARE v_check_count VARCHAR(450);
    
    DECLARE v_search_name VARCHAR(100);
	DECLARE v_dealerCode VARCHAR(450);
    
    DECLARE calculated INT DEFAULT 0;
    DECLARE limitVal INT DEFAULT 10;
    DECLARE offsetVal INT DEFAULT 0;
    
    DECLARE err_code INT;
    DECLARE err_msg TEXT;
    DECLARE sortField VARCHAR(45);
    DECLARE sortOrder VARCHAR(45);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
            
            SET p_status_code = 500;
			SET p_status_message = 'An error occurred. Please try again.';
			ROLLBACK;
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_tat_montoring_dashboard', 'TAT_MONITORING_DASHBOARD', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    
    -- SET v_team_id   = JSON_EXTRACT(p_json, '$.teamId');
    -- SET v_team_id = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json,'$.teamId')) AS UNSIGNED);
	SET v_team_id = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.teamId'));
    SET v_search_name = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.searchName'));
    
    SET v_type   = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.type'));
	SET v_renewal_category = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.renewalCategory'));
    SET v_zone = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.zone'));
	SET v_state = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.state'));
	SET v_dealer_code = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.dealerCode'));
	SET v_dealerLocCode = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.dealerLocCode'));
	-- SET v_from_date = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_json,'$.fromDate')), '');
	-- SET v_to_date   = NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_json,'$.toDate')), '');
    SET v_from_date = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.fromDate'));
    SET v_to_date   = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.toDate'));
    SET v_role_type  = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.roleType'));
    SET v_userId  = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.loginUserId'));
    
    SET sortField = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.sortField'));
    SET sortOrder = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.sortOrder'));
    
	SET limitVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.limit')) AS UNSIGNED), 10);
    SET offsetVal = IFNULL(CAST(JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.offset')) AS UNSIGNED), 0);
    SET calculated = (offsetVal - 1) * limitVal;
    
    IF sortField IS NULL OR sortField = '' THEN
        SET sortField = 'expiryDate';
    END IF;

    -- Set default sort order
    IF sortOrder IS NULL OR sortOrder = '' THEN
        SET sortOrder = 'asc'; 
    END IF;
    
DROP TEMPORARY TABLE IF EXISTS tmp_all_leads;    
CREATE TEMPORARY TABLE tmp_all_leads AS
SELECT 
    lead_id,
    assigned_agent,
    dealer_code,
    renewal_category,
    created_date,
    modified_date,
    policy_expiry_date,
    expiry_days,
    lead_type,
    dealer,
    vin
FROM mmi_lead_details

UNION ALL

SELECT 
    lead_id,
    assigned_agent,
    dealer_code,
    renewal_category,
    created_date,
    modified_date,
    policy_expiry_date,
    expiry_days,
    lead_type,
    dealer,
    vin
FROM mmi_lead_archive_details;
    
    IF v_role_type = 'MIBL' THEN
    IF v_type = 'tatDashboardfilter' THEN
		SELECT 
		'Follow Up Compliance' AS Name,
        CASE 
			WHEN ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2) = 0 
				THEN 0
		ELSE 
			GREATEST(
			0,
			LEAST(
				100,
				100 - ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					NULLIF(COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END), 0),
				2)
				)
			) 
				END AS FollowUpCompliance,
				LEAST(
			100,
			ROUND(
				COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
				NULLIF(COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END), 0),
			2)
		) AS FollowUpNonCompliance,
		-- COUNT(DISTINCT cdh.lead_id) AS totalLeadsContacted,
        COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END) AS totalLeadsContacted,
		COUNT(DISTINCT lb.lead_id) AS totalLeadsBreached
	FROM tmp_all_leads mld
	LEFT JOIN mmi_call_disposition_history cdh 
		   ON cdh.lead_id = mld.lead_id	
	LEFT JOIN mmi_lead_breached lb 
		   ON lb.lead_id = mld.lead_id
	INNER JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.mapping_dealer_code = mld.dealer_code
	LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code       
	WHERE 
	  (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
      AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
	  AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
      AND (v_dealer_code IS NULL OR v_dealer_code = '' OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
      AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)));

	SELECT 
		'Leads Breached' AS Name,
		COUNT(DISTINCT lb.lead_id) AS totalLeadsBreached,
		COUNT(DISTINCT CASE 
				WHEN DATE(lb.created_date) = CURDATE() 
				THEN lb.lead_id 
			END) AS totalLeadsBreachedToday
	FROM tmp_all_leads mld
	LEFT JOIN mmi_lead_breached lb 
		   ON lb.lead_id = mld.lead_id
	LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.mapping_dealer_code = mld.dealer_code
	LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code       
	WHERE 
	  (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
      AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
	  AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
      AND (v_dealer_code IS NULL OR v_dealer_code = '' OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
      AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)));

	SELECT 
		'Leads Breached by Category' AS Name,
		COUNT(DISTINCT CASE 
				WHEN mld.lead_type  = 'Hot' 
				THEN lb.lead_id 
			END) AS hotBreached,
		COUNT(DISTINCT CASE 
				WHEN mld.lead_type  = 'Warm' 
				THEN lb.lead_id 
			END) AS warmBreached
	FROM tmp_all_leads mld
	LEFT JOIN mmi_lead_breached lb 
		   ON lb.lead_id = mld.lead_id
	LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.mapping_dealer_code = mld.dealer_code
	LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code       
	WHERE 
	  (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
      AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
	  AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
      AND (v_dealer_code IS NULL OR v_dealer_code = '' OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
      AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)));
    
    /*select 'Level 1' as Name, count(distinct lte.lead_id) as leadCount from mmi_lead_tat_escalation lte
	left join tmp_all_leads mld on mld.lead_id = lte.lead_id
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.mapping_dealer_code = mld.dealer_code
	LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code       
	WHERE 
	  (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
      AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
	  AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
      AND (v_dealer_code IS NULL OR v_dealer_code = '' OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
      AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))
	AND escalation_level = 'Level 1' 
	union all
	select 'Level 2' as Name, count(distinct lte.lead_id) as leadCount from mmi_lead_tat_escalation lte
	left join tmp_all_leads mld on mld.lead_id = lte.lead_id
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.mapping_dealer_code = mld.dealer_code
	LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code       
	WHERE 
	  (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
      AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
	  AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
      AND (v_dealer_code IS NULL OR v_dealer_code = '' OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
      AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))
	AND escalation_level = 'Level 2' 
	union all 
	select 'Level 3' as Name, count(distinct lte.lead_id) as leadCount from mmi_lead_tat_escalation lte
	left join tmp_all_leads mld on mld.lead_id = lte.lead_id
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.mapping_dealer_code = mld.dealer_code
	LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code       
	WHERE 
	  (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
      AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
	  AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
      AND (v_dealer_code IS NULL OR v_dealer_code = '' OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
      AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))
	AND escalation_level = 'Level 3';*/
	
	
	SELECT 
		levels.Name,COUNT(DISTINCT lte.lead_id) AS leadCount
	FROM (
		SELECT 'Level 1' AS Name
		UNION ALL
		SELECT 'Level 2'
		UNION ALL
		SELECT 'Level 3'
	) levels
	LEFT JOIN mmi_lead_tat_escalation lte
		ON lte.escalation_level = levels.Name
	LEFT JOIN tmp_all_leads mld 
		ON mld.lead_id = lte.lead_id
	LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.mapping_dealer_code = mld.dealer_code
	LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code       
	WHERE 
	  (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
      AND (v_zone IS NULL OR v_zone = '' OR FIND_IN_SET(TRIM(dealLoc.zone), v_zone))
	  AND (v_state IS NULL OR v_state = '' OR FIND_IN_SET(TRIM(dloc.state), v_state))
      AND (v_dealer_code IS NULL OR v_dealer_code = '' OR FIND_IN_SET(TRIM(mld.dealer_code), v_dealer_code))
      AND (v_dealerLocCode IS NULL OR v_dealerLocCode = '' OR FIND_IN_SET(TRIM(dloc.loc_code), v_dealerLocCode))
      AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))	
	GROUP BY levels.Name
	ORDER BY levels.Name;
    
    SELECT 
        dealLoc.dealer_name AS agentName,
        CASE 
			WHEN ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2) = 0 
				THEN 0
		ELSE 
				100 - ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2)
		END AS percentage,

        -- COUNT(DISTINCT cdh.lead_id) AS totalLeadsContacted,
        COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END) AS totalLeadsContacted,
        COUNT(DISTINCT lb.lead_id) AS totalLeadsBreached 

    FROM mmi_mast_user_registration_detail urd
    LEFT JOIN tmp_all_leads mld 
           ON mld.assigned_agent = urd.id
    LEFT JOIN mmi_call_disposition_history cdh 
           ON cdh.lead_id = mld.lead_id
    LEFT JOIN mmi_lead_breached lb 
           ON lb.lead_id = mld.lead_id
    LEFT JOIN mmi_dealer_location_mapping dealLoc ON dealLoc.mapping_dealer_code = mld.dealer_code
	LEFT JOIN mmi_mast_dealer_location dloc ON dloc.loc_code = dealLoc.location_code       
	WHERE dealLoc.dealer_name is not null AND
	  (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
