					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2) = 0 
