    'Follow Up Compliance' AS Name,
    ROUND(COALESCE(follow_up.totalLeadsContacted,0) / NULLIF(total.totalLeads,0) * 100,2) AS FollowUpCompliance,
    ROUND(COALESCE(non_follow_up.totalLeadsBreached,0) / NULLIF(total.totalLeads,0) * 100,2) AS FollowUpNonCompliance,
    COALESCE(follow_up.totalLeadsContacted,0) AS totalLeadsContacted,
