SELECT 
    'Leads Breached' AS Name,
    COUNT(DISTINCT lb.lead_id) AS totalLeadsBreached,
    COUNT(DISTINCT CASE 
            WHEN DATE(lb.created_date) = CURDATE() 
            THEN lb.lead_id 
        END) AS totalLeadsBreachedToday
FROM tmp_all_leads mld
LEFT JOIN mmi_lead_breached lb 
       ON lb.lead_id = mld.lead_id
INNER JOIN mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = mld.dealer_code;

SELECT 
    'Leads Breached by Category' AS Name,
    COUNT(DISTINCT CASE 
            WHEN mld.lead_type  = 'Hot' 
            THEN lb.lead_id 
        END) AS hotBreached,
    COUNT(DISTINCT CASE 
            WHEN mld.lead_type  = 'Warm' 
            THEN lb.lead_id 
        END) AS warmBreached
FROM tmp_all_leads mld
LEFT JOIN mmi_lead_breached lb 
       ON lb.lead_id = mld.lead_id
INNER JOIN mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = mld.dealer_code;       


/*select 'Level 1' as Name, count(distinct lte.lead_id) as leadCount from mmi_lead_tat_escalation lte
left join tmp_all_leads mld on mld.lead_id = lte.lead_id
where escalation_level = 'Level 1'
union all
select 'Level 2' as Name, count(distinct lte.lead_id) as leadCount from mmi_lead_tat_escalation lte
left join tmp_all_leads mld on mld.lead_id = lte.lead_id
where escalation_level = 'Level 2'
union all 
select 'Level 3' as Name, count(distinct lte.lead_id) as leadCount from mmi_lead_tat_escalation lte
left join tmp_all_leads mld on mld.lead_id = lte.lead_id
where escalation_level = 'Level 3';*/

SELECT 
    levels.Name,COUNT(DISTINCT lte.lead_id) AS leadCount
FROM (
    SELECT 'Level 1' AS Name
    UNION ALL
    SELECT 'Level 2'
    UNION ALL
    SELECT 'Level 3'
) levels
LEFT JOIN mmi_lead_tat_escalation lte
    ON lte.escalation_level = levels.Name
LEFT JOIN tmp_all_leads mld 
    ON mld.lead_id = lte.lead_id
GROUP BY levels.Name
ORDER BY levels.Name;

SELECT 
    dlm.dealer_name AS agentName,

    CASE 
			WHEN ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2) = 0 
				THEN 0
		ELSE 
				100 - ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2)
		END AS percentage,

    -- COUNT(DISTINCT cdh.lead_id) AS totalLeadsContacted,
    COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END) AS totalLeadsContacted,
    COUNT(DISTINCT lb.lead_id) AS totalLeadsBreached 

FROM mmi_mast_user_registration_detail urd
LEFT JOIN tmp_all_leads mld 
       ON mld.assigned_agent = urd.id
LEFT JOIN mmi_call_disposition_history cdh 
       ON cdh.lead_id = mld.lead_id
LEFT JOIN mmi_lead_breached lb 
       ON lb.lead_id = mld.lead_id
LEFT JOIN mmi_dealer_location_mapping dlm
	   ON dlm.mapping_dealer_code = mld.dealer_code       
WHERE dlm.dealer_name is not null AND (v_search_name IS NULL
	OR v_search_name = ''
	-- OR urd.first_name LIKE CONCAT('%', v_search_name, '%')
	-- OR urd.last_name LIKE CONCAT('%', v_search_name, '%')
	OR dlm.dealer_name LIKE CONCAT('%', v_search_name, '%'))
GROUP BY dlm.dealer_name ORDER BY percentage desc
LIMIT limitVal OFFSET calculated;

SELECT count(*) as dealerWiseFollowUpCount from (
SELECT 
    dlm.dealer_name AS agentName,

    CASE 
			WHEN ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2) = 0 
				THEN 0
		ELSE 
				100 - ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2)
		END AS percentage,

    -- COUNT(DISTINCT cdh.lead_id) AS totalLeadsContacted,
    COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END) AS totalLeadsContacted,
    COUNT(DISTINCT lb.lead_id) AS totalLeadsBreached 

FROM mmi_mast_user_registration_detail urd
LEFT JOIN tmp_all_leads mld 
       ON mld.assigned_agent = urd.id
LEFT JOIN mmi_call_disposition_history cdh 
       ON cdh.lead_id = mld.lead_id
LEFT JOIN mmi_lead_breached lb 
       ON lb.lead_id = mld.lead_id
LEFT JOIN mmi_dealer_location_mapping dlm
	   ON dlm.mapping_dealer_code = mld.dealer_code       
WHERE dlm.dealer_name is not null AND (v_search_name IS NULL
	OR v_search_name = ''
	-- OR urd.first_name LIKE CONCAT('%', v_search_name, '%')
	-- OR urd.last_name LIKE CONCAT('%', v_search_name, '%')
	OR dlm.dealer_name LIKE CONCAT('%', v_search_name, '%'))
GROUP BY dlm.dealer_name ORDER BY percentage desc
) as dealerWiseFollowUpCount;

