     OR LOWER(TRIM(urd.last_name)) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')
     OR CONCAT(urd.first_name,' ',urd.last_name) LIKE CONCAT('%', v_search_name, '%')
	 OR mld.renewal_category LIKE CONCAT('%', v_search_name, '%')
	 OR mld.policy_expiry_date LIKE CONCAT('%', v_search_name, '%')
	 OR mld.expiry_days LIKE CONCAT('%', v_search_name, '%'))
     ORDER BY 
			CASE WHEN sortField = 'expiryDate' AND sortOrder = 'asc' THEN expiryDays END ASC,
			CASE WHEN sortField = 'expiryDate' AND sortOrder = 'desc' THEN expiryDays END DESC   
     LIMIT limitVal OFFSET calculated;
     
     
SELECT count(*) as teamLeadFollowUpCount from (
SELECT distinct 
    mcd.customer_name AS customerName,
    mld.lead_id AS leadId,
    CONCAT(urd.first_name,' ',urd.last_name) AS agentName,
    mld.dealer AS dealerName,
	mld.dealer_code AS dealerCode,
    mld.renewal_category AS renewalCategory,
