INNER JOIN mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = mld.dealer_code
WHERE mld.lead_id IS NOT NULL AND (v_search_name IS NULL
	 OR v_search_name = ''
	 OR LOWER(TRIM(REPLACE(REPLACE(mcd.customer_name, '  ', ' '),'  ', ' '))) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')	 OR LOWER(TRIM(urd.first_name)) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')
     OR LOWER(TRIM(urd.last_name)) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')
     OR CONCAT(urd.first_name,' ',urd.last_name) LIKE CONCAT('%', v_search_name, '%')
	 OR mld.renewal_category LIKE CONCAT('%', v_search_name, '%')
	 OR mld.policy_expiry_date LIKE CONCAT('%', v_search_name, '%')
	 OR mld.expiry_days LIKE CONCAT('%', v_search_name, '%'))) as teamLeadFollowUpCount;
     
     select distinct id, renewal_year from mmi_mast_renewal_category where renewal_year is not null and renewal_year !='' order by id asc;
     SELECT DISTINCT zone as Zone FROM mmi_dealer_location_mapping dlm
			INNER JOIN mmi_dealer_details dl on dlm.dealer_code = dl.dealer_id Where zone is not null and zone !='';
            -- SELECT DISTINCT state as State FROM mmi_mast_dealer_location Where state is not null and state !='';
            SELECT DISTINCT state as State FROM mmi_mast_dealer_location mdl
			INNER JOIN mmi_dealer_location_mapping dlm on dlm.location_code = mdl.loc_code 
			INNER JOIN mmi_dealer_details dl on dlm.dealer_code = dl.dealer_id
			Where state is not null and state !='';
            
     SELECT DISTINCT dealer_name ,mapping_dealer_code AS dealer_id FROM mmi_dealer_location_mapping;       
     
SET p_status_code = 200;
SET p_status_message = 'TAT Dashboard Details fetched';       
