					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2) = 0 
				THEN 0
		ELSE 
			GREATEST(
			0,
			LEAST(
				100,
				100 - ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					NULLIF(COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END), 0),
				2)
				)
			) 
				END AS FollowUpCompliance,
				LEAST(
			100,
			ROUND(
				COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
				NULLIF(COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END), 0),
			2)
		) AS FollowUpNonCompliance,
