SELECT count(*) as dealerWiseFollowUpCount from (
SELECT 
    CONCAT(urd.first_name,' ',urd.last_name) AS agentName,

    CASE 
			WHEN ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2) = 0 
				THEN 0
		ELSE 
				100 - ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2)
		END AS percentage,

    -- COUNT(DISTINCT cdh.lead_id) AS totalLeadsContacted,
    COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END) AS totalLeadsContacted,
    COUNT(DISTINCT lb.lead_id) AS totalLeadsBreached 

FROM mmi_mast_user_registration_detail urd
LEFT JOIN tmp_all_leads mld 
       ON mld.assigned_agent = urd.id
LEFT JOIN mmi_call_disposition_history cdh 
       ON cdh.lead_id = mld.lead_id
LEFT JOIN mmi_lead_breached lb 
       ON lb.lead_id = mld.lead_id
INNER JOIN mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = mld.dealer_code
WHERE mld.dealer_code = v_dealer_code AND mld.assigned_agent IN (SELECT user_id FROM dealer_team_members) -- AND DATE(mld.created_date) BETWEEN v_from_date AND v_to_date
      AND (v_team_id IS NULL OR v_team_id = '' OR FIND_IN_SET(TRIM(mld.assigned_agent), v_team_id))
      AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
      AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))
      AND (v_search_name IS NULL
		 OR v_search_name = ''
		 OR urd.first_name LIKE CONCAT('%', v_search_name, '%')
		 OR urd.last_name LIKE CONCAT('%', v_search_name, '%')
		 OR CONCAT(urd.first_name,' ',urd.last_name) LIKE CONCAT('%', v_search_name, '%'))
    GROUP BY urd.first_name, urd.last_name ORDER BY percentage desc
) as dealerWiseFollowUpCount;


WITH RECURSIVE team_hierarchy AS (

    -- manager

    SELECT v_userId AS user_id

    UNION ALL

    -- team members

    SELECT ur.user_id
    FROM mmi_user_reporting ur
    INNER JOIN team_hierarchy th ON ur.supervisor_id = th.user_id
),
dealer_team_members AS (
    SELECT th.user_id
    FROM team_hierarchy th
    JOIN mmi_user_dealer_mapping udm ON th.user_id = udm.user_id
    WHERE udm.dealer_id = v_dealer_code
)
    SELECT distinct 
        mcd.customer_name AS customerName,
        mld.lead_id AS leadId,
        CONCAT(urd.first_name,' ',urd.last_name) AS agentName,
        mld.renewal_category AS renewalCategory,
        DATE_FORMAT(mld.policy_expiry_date, '%d %b %Y') AS expiryDate,
        mld.expiry_days AS expiryDays,
        mld.lead_type AS leadType
    -- FROM tmp_all_leads mld
    FROM mmi_lead_breached lb
	LEFT JOIN tmp_all_leads mld on lb.lead_id = mld.lead_id 
    LEFT JOIN mmi_mast_customer_details mcd 
           ON mcd.chassis_no = mld.vin
    LEFT JOIN mmi_mast_user_registration_detail urd 
           ON urd.id = mld.assigned_agent
	INNER JOIN mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = mld.dealer_code
    WHERE mld.lead_id IS NOT NULL AND mld.dealer_code = v_dealer_code AND mld.assigned_agent IN (SELECT user_id FROM dealer_team_members) -- AND DATE(mld.created_date) BETWEEN v_from_date AND v_to_date
      AND (v_team_id IS NULL OR v_team_id = '' OR FIND_IN_SET(TRIM(mld.assigned_agent), v_team_id))
      AND (v_renewal_category IS NULL OR v_renewal_category = '' OR FIND_IN_SET(TRIM(mld.renewal_category), v_renewal_category))
      AND (((v_from_date IS NULL OR v_from_date = '') AND (v_to_date IS NULL OR v_to_date = ''))
        OR
        (v_from_date IS NOT NULL AND v_from_date != '' AND v_to_date IS NOT NULL AND v_to_date != '' 
         AND (mld.created_date BETWEEN v_from_date AND v_to_date
              OR mld.modified_date BETWEEN v_from_date AND v_to_date)))
      AND (v_search_name IS NULL
		 OR v_search_name = ''
		 OR LOWER(TRIM(REPLACE(REPLACE(mcd.customer_name, '  ', ' '),'  ', ' '))) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')		OR LOWER(TRIM(urd.first_name)) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')
		OR LOWER(TRIM(urd.last_name)) LIKE CONCAT('%', LOWER(TRIM(v_search_name)), '%')
		 OR CONCAT(urd.first_name,' ',urd.last_name) LIKE CONCAT('%', v_search_name, '%')
		 OR mld.renewal_category LIKE CONCAT('%', v_search_name, '%')
		 OR mld.policy_expiry_date LIKE CONCAT('%', v_search_name, '%')
		 OR mld.expiry_days LIKE CONCAT('%', v_search_name, '%'))
     ORDER BY 
			CASE WHEN sortField = 'expiryDate' AND sortOrder = 'asc' THEN expiryDays END ASC,
			CASE WHEN sortField = 'expiryDate' AND sortOrder = 'desc' THEN expiryDays END DESC       
         LIMIT limitVal OFFSET calculated;


