/*select 'Level 1' as Name, count(distinct lte.lead_id) as leadCount from mmi_lead_tat_escalation lte
left join tmp_all_leads mld on mld.lead_id = lte.lead_id
where escalation_level = 'Level 1' and mld.dealer_code = v_dealer_code
AND mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
union all
select 'Level 2' as Name, count(distinct lte.lead_id) as leadCount from mmi_lead_tat_escalation lte
left join tmp_all_leads mld on mld.lead_id = lte.lead_id
where escalation_level = 'Level 2' and mld.dealer_code = v_dealer_code
AND mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)
union all 
select 'Level 3' as Name, count(distinct lte.lead_id) as leadCount from mmi_lead_tat_escalation lte
left join tmp_all_leads mld on mld.lead_id = lte.lead_id
where escalation_level = 'Level 3' and mld.dealer_code = v_dealer_code
AND mld.assigned_agent IN (SELECT user_id FROM dealer_team_members);
*/

SELECT 
    levels.Name,COUNT(DISTINCT lte.lead_id) AS leadCount
FROM (
    SELECT 'Level 1' AS Name
    UNION ALL
    SELECT 'Level 2'
    UNION ALL
    SELECT 'Level 3'
) levels
LEFT JOIN mmi_lead_tat_escalation lte
    ON lte.escalation_level = levels.Name
LEFT JOIN tmp_all_leads mld 
    ON mld.lead_id = lte.lead_id
INNER JOIN mmi_dealer_location_mapping dlm on dlm.mapping_dealer_code = mld.dealer_code
WHERE mld.dealer_code = v_dealer_code
AND mld.assigned_agent IN (SELECT user_id FROM dealer_team_members)	
GROUP BY levels.Name
ORDER BY levels.Name;


