SELECT 
    'Follow Up Compliance' AS Name,
    /*100 - ROUND(
        COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) / 
        NULLIF(COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),0) * 100, 2
		) AS FollowUpCompliance,*/
    CASE 
			WHEN ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END),
				2) = 0 
				THEN 0
		ELSE 
			GREATEST(
			0,
			LEAST(
				100,
				100 - ROUND(
					COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
					NULLIF(COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END), 0),
				2)
				)
			) 
				END AS FollowUpCompliance,
				LEAST(
			100,
			ROUND(
				COUNT(DISTINCT CASE WHEN lb.lead_id IS NOT NULL THEN mld.lead_id END) * 100.0 /
				NULLIF(COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END), 0),
			2)
		) AS FollowUpNonCompliance,
    -- COUNT(DISTINCT cdh.lead_id) AS totalLeadsContacted,
    COUNT(DISTINCT CASE WHEN mld.assigned_agent IS NOT NULL THEN mld.lead_id END) AS totalLeadsContacted,
    COUNT(DISTINCT lb.lead_id) AS totalLeadsBreached
FROM tmp_all_leads mld
LEFT JOIN mmi_call_disposition_history cdh 
       ON cdh.lead_id = mld.lead_id
LEFT JOIN mmi_lead_breached lb 
