DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_all_preferences_by_ids`(
    IN in_bucket_id INT,
    IN in_insurance_ids TEXT,
    IN in_segment_ids TEXT,
    IN in_renewal_ids TEXT,
	IN in_datapull_ids TEXT,
    IN in_addon_ids TEXT,
    IN in_location TEXT,
    OUT statusCode VARCHAR(45),
    OUT statusMessage VARCHAR(200)
)
BEGIN

	DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(250);
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
        SET statusCode = '500';
        SET statusMessage = 'SQL Error occurred in procedure.';
        ROLLBACK;
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_update_all_preferences_by_ids', 'UpdatePreferences', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
	START TRANSACTION;
    -- ===== INSURANCE =====
    UPDATE mmi_call_user_preference_insurance
    SET status = 0
    WHERE bucket_id = in_bucket_id;

    IF in_insurance_ids IS NOT NULL AND in_insurance_ids != '' THEN
        -- Reactivate existing
        UPDATE mmi_call_user_preference_insurance
        SET status = 1
        WHERE bucket_id = in_bucket_id
          AND FIND_IN_SET(ic_code, in_insurance_ids);

        -- Insert new if not exists
        INSERT INTO mmi_call_user_preference_insurance (bucket_id, ic_code, status)
        SELECT in_bucket_id, new_id, 1
        FROM (
            SELECT TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(in_insurance_ids, ',', numbers.n), ',', -1)) AS new_id
            FROM (
                SELECT ROW_NUMBER() OVER () AS n
                FROM (
                    SELECT 0 UNION SELECT 1 UNION SELECT 2 UNION SELECT 3 UNION SELECT 4
                    UNION SELECT 5 UNION SELECT 6 UNION SELECT 7 UNION SELECT 8 UNION SELECT 9
                ) a, (
                    SELECT 0 UNION SELECT 1 UNION SELECT 2 UNION SELECT 3 UNION SELECT 4
                    UNION SELECT 5 UNION SELECT 6 UNION SELECT 7 UNION SELECT 8 UNION SELECT 9
                ) b
            ) numbers
            WHERE n <= 1 + LENGTH(in_insurance_ids) - LENGTH(REPLACE(in_insurance_ids, ',', ''))
        ) parsed
        WHERE new_id NOT IN (
            SELECT ic_code FROM mmi_call_user_preference_insurance
            WHERE bucket_id = in_bucket_id
        );
    END IF;

    -- ===== SEGMENT =====
    UPDATE mmi_call_user_preference_segment
    SET status = 0
    WHERE bucket_id = in_bucket_id;

    IF in_segment_ids IS NOT NULL AND in_segment_ids != '' THEN
        UPDATE mmi_call_user_preference_segment
        SET status = 1
        WHERE bucket_id = in_bucket_id
          AND FIND_IN_SET(segment_id, in_segment_ids);

        INSERT INTO mmi_call_user_preference_segment (bucket_id, segment_id, status)
        SELECT in_bucket_id, CAST(new_id AS UNSIGNED), 1
        FROM (
            SELECT TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(in_segment_ids, ',', numbers.n), ',', -1)) AS new_id
            FROM (
                SELECT ROW_NUMBER() OVER () AS n
                FROM (
                    SELECT 0 UNION SELECT 1 UNION SELECT 2 UNION SELECT 3 UNION SELECT 4
                    UNION SELECT 5 UNION SELECT 6 UNION SELECT 7 UNION SELECT 8 UNION SELECT 9
                ) a, (
                    SELECT 0 UNION SELECT 1 UNION SELECT 2 UNION SELECT 3 UNION SELECT 4
                    UNION SELECT 5 UNION SELECT 6 UNION SELECT 7 UNION SELECT 8 UNION SELECT 9
                ) b
            ) numbers
            WHERE n <= 1 + LENGTH(in_segment_ids) - LENGTH(REPLACE(in_segment_ids, ',', ''))
        ) parsed
        WHERE new_id NOT IN (
            SELECT segment_id FROM mmi_call_user_preference_segment
            WHERE bucket_id = in_bucket_id
        );
    END IF;

    -- ===== RENEWAL =====
    UPDATE mmi_call_user_preference_renewal
    SET status = 0
    WHERE bucket_id = in_bucket_id;

    IF in_renewal_ids IS NOT NULL AND in_renewal_ids != '' THEN
        UPDATE mmi_call_user_preference_renewal
        SET status = 1
        WHERE bucket_id = in_bucket_id
          AND FIND_IN_SET(renewal_category_id, in_renewal_ids);

        INSERT INTO mmi_call_user_preference_renewal (bucket_id, renewal_category_id, status)
        SELECT in_bucket_id, CAST(new_id AS UNSIGNED), 1
        FROM (
            SELECT TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(in_renewal_ids, ',', numbers.n), ',', -1)) AS new_id
            FROM (
                SELECT ROW_NUMBER() OVER () AS n
                FROM (
                    SELECT 0 UNION SELECT 1 UNION SELECT 2 UNION SELECT 3 UNION SELECT 4
                    UNION SELECT 5 UNION SELECT 6 UNION SELECT 7 UNION SELECT 8 UNION SELECT 9
                ) a, (
                    SELECT 0 UNION SELECT 1 UNION SELECT 2 UNION SELECT 3 UNION SELECT 4
                    UNION SELECT 5 UNION SELECT 6 UNION SELECT 7 UNION SELECT 8 UNION SELECT 9
                ) b
            ) numbers
            WHERE n <= 1 + LENGTH(in_renewal_ids) - LENGTH(REPLACE(in_renewal_ids, ',', ''))
        ) parsed
        WHERE new_id NOT IN (
            SELECT renewal_category_id FROM mmi_call_user_preference_renewal
            WHERE bucket_id = in_bucket_id
        );
    END IF;
    
    -- =================== Data pull =================
    
	UPDATE mmi_call_user_preference_datapull
    SET status = 0
    WHERE bucket_id = in_bucket_id;

    IF in_datapull_ids IS NOT NULL AND in_datapull_ids != '' THEN
        -- Reactivate existing
        UPDATE mmi_call_user_preference_datapull
        SET status = 1
        WHERE bucket_id = in_bucket_id
          AND FIND_IN_SET(datapull_id, in_datapull_ids);

        -- Insert new if not exists
        INSERT INTO mmi_call_user_preference_datapull (bucket_id, datapull_id, status)
        SELECT in_bucket_id, new_id, 1
        FROM (
            SELECT TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(in_datapull_ids, ',', numbers.n), ',', -1)) AS new_id
            FROM (
                SELECT ROW_NUMBER() OVER () AS n
                FROM (
                    SELECT 0 UNION SELECT 1 UNION SELECT 2 UNION SELECT 3 UNION SELECT 4
                    UNION SELECT 5 UNION SELECT 6 UNION SELECT 7 UNION SELECT 8 UNION SELECT 9
                ) a, (
                    SELECT 0 UNION SELECT 1 UNION SELECT 2 UNION SELECT 3 UNION SELECT 4
                    UNION SELECT 5 UNION SELECT 6 UNION SELECT 7 UNION SELECT 8 UNION SELECT 9
                ) b
            ) numbers
            WHERE n <= 1 + LENGTH(in_datapull_ids) - LENGTH(REPLACE(in_datapull_ids, ',', ''))
        ) parsed
        WHERE new_id NOT IN (
            SELECT datapull_id FROM mmi_call_user_preference_datapull
            WHERE bucket_id = in_bucket_id
        );
    END IF;
    

    -- ===== ADDON =====
    UPDATE mmi_call_user_preference_addon
    SET status = 0
    WHERE bucket_id = in_bucket_id;

    IF in_addon_ids IS NOT NULL AND in_addon_ids != '' THEN
        UPDATE mmi_call_user_preference_addon
        SET status = 1
        WHERE bucket_id = in_bucket_id
          AND FIND_IN_SET(addon_id, in_addon_ids);

        INSERT INTO mmi_call_user_preference_addon (bucket_id, addon_id, status)
        SELECT in_bucket_id, new_id, 1
        FROM (
            SELECT TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(in_addon_ids, ',', numbers.n), ',', -1)) AS new_id
            FROM (
                SELECT ROW_NUMBER() OVER () AS n
                FROM (
                    SELECT 0 UNION SELECT 1 UNION SELECT 2 UNION SELECT 3 UNION SELECT 4
                    UNION SELECT 5 UNION SELECT 6 UNION SELECT 7 UNION SELECT 8 UNION SELECT 9
                ) a, (
                    SELECT 0 UNION SELECT 1 UNION SELECT 2 UNION SELECT 3 UNION SELECT 4
                    UNION SELECT 5 UNION SELECT 6 UNION SELECT 7 UNION SELECT 8 UNION SELECT 9
                ) b
            ) numbers
            WHERE n <= 1 + LENGTH(in_addon_ids) - LENGTH(REPLACE(in_addon_ids, ',', ''))
        ) parsed
        WHERE new_id NOT IN (
            SELECT addon_id FROM mmi_call_user_preference_addon
            WHERE bucket_id = in_bucket_id
        );
    END IF;
    
    Update mmi_mast_bucket set bucket_location = in_location 
    where id = in_bucket_id;

    -- Final success
    SET statusCode = '200';
    SET statusMessage = 'Lead Pool Updated Successfully';
    
    IF statusCode = '200' THEN
        COMMIT;
    ELSE
        ROLLBACK;
    END IF;

END ;;
DELIMITER ;
