CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_crm_ebm_proposal_status`(
    IN  Json_data JSON,
    OUT p_status_code INT,
    OUT p_status_message VARCHAR(255)
)
proc_main: BEGIN

    DECLARE v_policy_no VARCHAR(200);
    DECLARE v_proposal_no VARCHAR(45);

    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        SET p_status_code = 500;
        SET p_status_message = 'Error while updating proposal details';

        INSERT INTO mmi_mast_procedure_error (
            error_code,
            error_message,
            procedure_name,
            procedure_type,
            error_timing,
            created_by,
            created_date
        ) VALUES (
            err_code,
            err_msg,
            'mmi_proc_update_crm_ebm_proposal_status',
            'UPDATE_PROPOSAL',
            CURRENT_TIMESTAMP(),
            'SYSTEM',
            NOW()
        );
    END;

    START TRANSACTION;

    SET v_policy_no   = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.policyNo'));
    SET v_proposal_no = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.proposalNo'));

    IF v_policy_no IS NULL OR v_proposal_no IS NULL THEN
        SET p_status_code = 400;
        SET p_status_message = 'policyNo and proposalNo are required';
        ROLLBACK;
        LEAVE proc_main;
    END IF;

    IF NOT EXISTS (
        SELECT 1
        FROM mmi_crm_ebm_transaction_details
        WHERE policy_no = v_policy_no
          AND proposal_no = v_proposal_no
    ) THEN
        SET p_status_code = 404;
        SET p_status_message = 'Proposal not found';
        ROLLBACK;
        LEAVE proc_main;
    END IF;

UPDATE mmi_crm_ebm_transaction_details 
SET 
    lead_id = IFNULL(JSON_EXTRACT(Json_data, '$.leadId'), lead_id),
    crm_transaction_token_no = IFNULL(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.crmTransactionTokenNo')), crm_transaction_token_no),
    proposal_status = IFNULL(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.proposalStatus')), proposal_status),
    renewal_link_modify = IFNULL(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalLinkModify')), renewal_link_modify),
    renewal_link_read_only = IFNULL(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.renewalLinkReadOnly')), renewal_link_read_only),
    proposal_timestamp = IFNULL(STR_TO_DATE(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.proposalTimestamp')), '%Y-%m-%d %H:%i:%s'), proposal_timestamp),
    ebm_user_id = IFNULL(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.ebmUserId')), ebm_user_id),
    crm_token = IFNULL(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.crmToken')), crm_token),
    created_by = IFNULL(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.createdBy')), created_by),
    created_date = IFNULL(STR_TO_DATE(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.createdDate')), '%Y-%m-%d %H:%i:%s'), created_date),
    modified_by = IFNULL(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.modifiedBy')), modified_by), modified_date = NOW(),
    ebm_transaction_token_no = IFNULL(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.ebmTransactionTokenNo')), ebm_transaction_token_no),
    ebm_token_expiry_time = IFNULL(STR_TO_DATE(JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.ebmTokenExpiryTime')), '%Y-%m-%d %H:%i:%s'), ebm_token_expiry_time)
WHERE
    policy_no = v_policy_no
        AND proposal_no = v_proposal_no;

    COMMIT;

    SET p_status_code = 200;
    SET p_status_message = 'Proposal updated successfully';

END ;;
DELIMITER ;
