CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_ebm_user_data`(
    IN p_ebm_user_id VARCHAR(50),
    IN p_mobile_no VARCHAR(50)
)
BEGIN
    DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;
    DECLARE v_mobile_no VARCHAR(50);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code,
            error_message,
            procedure_name,
            procedure_type,
            error_timing,	
            created_by,
            created_date
        ) VALUES (
            err_code,
            err_msg,
            'mmi_ebm_update_ebm_user_data',
            'EBM_USER_DATA_UPDATE',
            NOW(),
            'SYSTEM',
            NOW()
        );
    END;

    START TRANSACTION;

    -- Fetch lead_id
    SELECT mobile_no
    INTO v_mobile_no
    FROM mmi_mast_user_registration_detail
    WHERE mobile_no = p_mobile_no
    LIMIT 1;

    IF v_mobile_no IS NOT NULL AND v_mobile_no <> '' THEN
        
        UPDATE mmi_mast_user_registration_detail
        SET
            ebm_user_id        = p_ebm_user_id,
            modified_by            = 'EBM_SYSTEM',
            modified_date          = NOW()
        WHERE mobile_no = p_mobile_no;

    END IF;

    COMMIT;

END ;;
DELIMITER ;
