CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_feature_access`(
    IN p_json_data JSON,
    OUT p_status_code VARCHAR(50),
    OUT p_status_message VARCHAR(50)
)
BEGIN
	main_block: BEGIN
    DECLARE v_role_name VARCHAR(100);
    DECLARE v_parent_code VARCHAR(100);
    DECLARE v_role_id INT; 
    DECLARE v_total INT DEFAULT 0;
    DECLARE v_index INT DEFAULT 0;
    DECLARE v_created_user_id VARCHAR(50);
    DECLARE v_check_role_exists INT DEFAULT 0;
    DECLARE v_reporting_role_name VARCHAR(100);
    DECLARE v_reporting_role_id INT;

    DECLARE v_feature_id INT;
    DECLARE v_access_id INT;
    
    DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(250);
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        ROLLBACK;
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_update_feature_access', 'UpdateFeatureAccess', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
	START TRANSACTION;
    SET v_role_name = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.roleName'));
    SET v_role_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.roleId'));
    SET v_reporting_role_name = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.reportingRoleName'));
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.parentCode'));
    SET v_created_user_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.userId'));
	
    -- IF v_role_name IS NULL OR v_role_name = '' OR v_parent_code IS NULL OR v_parent_code = '' THEN
     IF v_role_id IS NULL OR v_role_id = 0 THEN
		SET p_status_code = '300';
        SET p_status_message = 'Required Fields Cannon be null or empty';
        LEAVE main_block;
	END IF;
    IF v_parent_code IS NOT NULL THEN
		SELECT COUNT(*) INTO v_check_role_exists
		FROM mmi_mast_role r
		LEFT JOIN mmi_mast_dealer_role_mapping drm ON drm.role_id = r.role_id
		-- LEFT JOIN mmi_mast_dealer d ON d.parent_code = drm.parent_code
        LEFT JOIN mmi_dealer_location_mapping d ON d.parent_code = drm.parent_code
        LEFT JOIN mmi_dealer_details dl ON dl.dealer_id = d.mapping_dealer_code
		WHERE LOWER(r.role) = LOWER(v_role_name)
		  AND d.parent_code = v_parent_code
          AND r.role_id <> v_role_id;
	ELSE
		SELECT COUNT(*) INTO v_check_role_exists
		FROM mmi_mast_role r
		WHERE LOWER(r.role) = LOWER(v_role_name) AND role_id <> v_role_id;
    END IF;
    IF v_check_role_exists > 0 THEN
		SET p_status_code = '404';
		SET p_status_message = 'Role Already Exists';
		LEAVE main_block;
	END IF;
    
    UPDATE mmi_mast_role SET role = v_role_name,
    modified_by = v_created_user_id, 
	modified_date = NOW()
    WHERE role_id = v_role_id;
    
    SELECT role_id INTO v_reporting_role_id from mmi_mast_role 
    WHERE role = v_reporting_role_name;
    
    IF v_reporting_role_id IS NOT NULL THEN
		IF v_parent_code IS NOT NULL THEN
			UPDATE mmi_mast_dealer_role_mapping SET reporting_role_id = v_reporting_role_id, 
            modified_by = v_created_user_id, 
            modified_date = NOW()
			where role_id = v_role_id AND parent_code = v_parent_code;
		ELSE
			UPDATE mmi_mast_dealer_role_mapping SET reporting_role_id = v_reporting_role_id, 
            modified_by = v_created_user_id, 
            modified_date = NOW()
			where role_id = v_role_id;
		END IF;
    END IF;
    -- Step 3: Deactivate ALL current mappings for this role
    UPDATE mmi_user_feature_access_mapping
    SET status = '0',
    modified_by = v_created_user_id, 
    modified_date = NOW()
    WHERE role_id = v_role_id;

    -- Step 4: Loop through incoming mappings and insert/update as status = '1'
    SET v_total = JSON_LENGTH(JSON_EXTRACT(p_json_data, '$.featureAccessMappings'));

    WHILE v_index < v_total DO
        SET v_feature_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, CONCAT('$.featureAccessMappings[', v_index, '].featureId')));
        SET v_access_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, CONCAT('$.featureAccessMappings[', v_index, '].accessId')));
		
        IF v_feature_id IS NULL OR v_access_id IS NULL OR v_feature_id <= 0 OR v_access_id <= 0 THEN
            SET p_status_code = '400';
            SET p_status_message = 'Invalid featureId or accessId.';
            LEAVE main_block;
        END IF;
        
        -- If record exists, update to status = '1'
        IF EXISTS (
            SELECT 1 FROM mmi_user_feature_access_mapping
            WHERE role_id = v_role_id AND feature_id = v_feature_id AND access_id = v_access_id
        ) THEN
            UPDATE mmi_user_feature_access_mapping
            SET status = '1',
            modified_by = v_created_user_id, 
            modified_date = NOW()
            WHERE role_id = v_role_id AND feature_id = v_feature_id AND access_id = v_access_id;
        ELSE
            INSERT INTO mmi_user_feature_access_mapping (
                role_id, feature_id, access_id, status , created_by
            ) VALUES (
                v_role_id, v_feature_id, v_access_id, '1', v_created_user_id
            );
        END IF;

        SET v_index = v_index + 1;
    END WHILE;
    
    INSERT INTO mmi_insert_log_details (service_name,user_id,log_payload,
     service_type,created_by,created_date) 
     VALUES ('mmi_proc_update_feature_access',v_created_user_id,
     p_json_data,'UPDATE',v_created_user_id,CURRENT_TIMESTAMP(3));
	
    SET p_status_code = '200';
	SET p_status_message = 'Feature access updated successfully';
	IF p_status_code = '200' THEN
		COMMIT; 
	ELSE
		ROLLBACK;
	END IF;
    END main_block;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
