CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_lead_expiry_and_category`()
BEGIN
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    -- Handler for exceptions
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
        ROLLBACK;
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_update_lead_expiry_and_category', 'UPDATE_LEAD_EXPIRY_AND_CATEGORY', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    START TRANSACTION;

    -- 1️⃣ Update expiry_days by removing time from policy_expiry_date safely
    UPDATE mmi_lead_details
    SET expiry_days = DATEDIFF(
        CAST(SUBSTRING_INDEX(policy_expiry_date, '.', 1) AS DATE),
        CURDATE()
    )
    WHERE policy_expiry_date IS NOT NULL
      AND CAST(SUBSTRING_INDEX(policy_expiry_date, '.', 1) AS DATE) IS NOT NULL;

    -- 2️⃣ Drop and create temporary table
    DROP TEMPORARY TABLE IF EXISTS tmp_renewal_ranges;
    CREATE TEMPORARY TABLE tmp_renewal_ranges (
        renewal_year VARCHAR(100),
        start_month INT,
        end_month INT
    );

    -- 3️⃣ Populate the temp table from renewal_month ranges
    INSERT INTO tmp_renewal_ranges (renewal_year, start_month, end_month)
    SELECT
        renewal_year,
        CAST(SUBSTRING_INDEX(renewal_month, '-', 1) AS UNSIGNED),
        IF(renewal_month LIKE '%-%',
            CAST(SUBSTRING_INDEX(renewal_month, '-', -1) AS UNSIGNED),
            999
        )
    FROM mmi_mast_renewal_category
    WHERE renewal_month IS NOT NULL AND TRIM(renewal_month) != '';

    -- 4️⃣ Update mmi_lead_details.renewal_category using safer date parsing
    UPDATE mmi_lead_details ld
    JOIN tmp_renewal_ranges cat
      ON TIMESTAMPDIFF(
            MONTH,
            STR_TO_DATE(SUBSTRING_INDEX(ld.policy_effective_date, '.', 1), '%Y-%m-%d %H:%i:%s'),
            STR_TO_DATE(TRIM(ld.invoice_date),
                IF(LEFT(TRIM(ld.invoice_date), 4) BETWEEN '1900' AND '2099', '%Y-%m-%d', '%d-%m-%Y')
            )
         ) BETWEEN cat.start_month AND cat.end_month
    SET ld.renewal_category = cat.renewal_year
    WHERE (ld.renewal_category IS NULL OR TRIM(ld.renewal_category) = '')
      AND ld.invoice_date IS NOT NULL
      AND ld.policy_effective_date IS NOT NULL
      AND STR_TO_DATE(SUBSTRING_INDEX(ld.policy_effective_date, '.', 1), '%Y-%m-%d %H:%i:%s') IS NOT NULL
      AND (
            (LEFT(TRIM(ld.invoice_date), 4) BETWEEN '1900' AND '2099' AND STR_TO_DATE(TRIM(ld.invoice_date), '%Y-%m-%d') IS NOT NULL)
            OR
            (LEFT(TRIM(ld.invoice_date), 4) NOT BETWEEN '1900' AND '2099' AND STR_TO_DATE(TRIM(ld.invoice_date), '%d-%m-%Y') IS NOT NULL)
          );

    -- 5️⃣ Log invalid invoice_date rows
    INSERT INTO mmi_mast_procedure_error (
        error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
    )
    SELECT
        1002,
        CONCAT('Invalid invoice date for lead_id=', ld.lead_id, ', invoice_date=', ld.invoice_date),
        'mmi_proc_update_lead_expiry_and_category',
        'DATA_VALIDATION',
        CURRENT_TIMESTAMP(),
        'SYSTEM',
        NOW()
    FROM mmi_lead_details ld
    WHERE ld.invoice_date IS NOT NULL
      AND (
            (LEFT(TRIM(ld.invoice_date), 4) BETWEEN '1900' AND '2099' AND STR_TO_DATE(TRIM(ld.invoice_date), '%Y-%m-%d') IS NULL)
            OR
            (LEFT(TRIM(ld.invoice_date), 4) NOT BETWEEN '1900' AND '2099' AND STR_TO_DATE(TRIM(ld.invoice_date), '%d-%m-%Y') IS NULL)
          );

    COMMIT;

END ;;
DELIMITER ;
