CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_lead_expiry_days`()
BEGIN
    DECLARE err_code INT;
    DECLARE err_msg TEXT;

    -- Error handling
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_update_lead_expiry_days', 'UPDATE_EXPIRY_DAYS', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );
    END;

    -- Start transaction
    START TRANSACTION;

    BEGIN
        -- Update expiry_days only where policy_expiry_date is valid
        UPDATE mmi_lead_details
        SET expiry_days = DATEDIFF(
            DATE(SUBSTRING_INDEX(policy_expiry_date, '.', 1)),  -- removes fractional seconds if any
            CURDATE()
        )
        WHERE policy_expiry_date IS NOT NULL;

        COMMIT;
    END;
END ;;
DELIMITER ;
