CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_lead_renewal_category`()
BEGIN
    DECLARE err_code INT DEFAULT 0;
    DECLARE err_msg TEXT DEFAULT '';
    DECLARE rows_affected INT DEFAULT 0;

    -- Error handler
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        -- Insert error log
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_update_lead_renewal_category', 'UPDATE_RENEWAL_CATEGORY', NOW(), 'SYSTEM', NOW()
        );

        -- Rollback main transaction
        ROLLBACK;
    END;

    -- Disable safe update mode for this session (to avoid error 1175)
    SET SESSION SQL_SAFE_UPDATES = 0;

    -- Drop and create temporary table OUTSIDE transaction to avoid warnings
    DROP TEMPORARY TABLE IF EXISTS tmp_renewal_ranges;

    CREATE TEMPORARY TABLE tmp_renewal_ranges (
        renewal_year VARCHAR(100),
        start_month INT,
        end_month INT
    );

    -- Start transaction
    START TRANSACTION;

    -- Populate temp table
    INSERT INTO tmp_renewal_ranges (renewal_year, start_month, end_month)
    SELECT
        renewal_year,
        CAST(SUBSTRING_INDEX(renewal_month, '-', 1) AS UNSIGNED),
        CAST(SUBSTRING_INDEX(renewal_month, '-', -1) AS UNSIGNED)
    FROM mmi_mast_renewal_category
    WHERE renewal_month IS NOT NULL AND TRIM(renewal_month) != '';

    -- Update renewal_category and get affected rows count
    UPDATE mmi_lead_details ld
    JOIN tmp_renewal_ranges cat
      ON TIMESTAMPDIFF(
             MONTH,
             LEAST(
                 STR_TO_DATE(SUBSTRING_INDEX(ld.policy_expiry_date, '.', 1), '%Y-%m-%d %H:%i:%s'),
                 STR_TO_DATE(
                     CASE
                         WHEN ld.invoice_date REGEXP '^[0-9]{2}-[0-9]{2}-[0-9]{4}$' THEN ld.invoice_date
                         WHEN ld.invoice_date REGEXP '^[0-9]{4}-[0-9]{2}-[0-9]{2}$' THEN ld.invoice_date
                     END,
                     CASE
                         WHEN ld.invoice_date REGEXP '^[0-9]{2}-[0-9]{2}-[0-9]{4}$' THEN '%d-%m-%Y'
                         WHEN ld.invoice_date REGEXP '^[0-9]{4}-[0-9]{2}-[0-9]{2}$' THEN '%Y-%m-%d'
                     END
                 )
             ),
             GREATEST(
                 STR_TO_DATE(SUBSTRING_INDEX(ld.policy_expiry_date, '.', 1), '%Y-%m-%d %H:%i:%s'),
                 STR_TO_DATE(
                     CASE
                         WHEN ld.invoice_date REGEXP '^[0-9]{2}-[0-9]{2}-[0-9]{4}$' THEN ld.invoice_date
                         WHEN ld.invoice_date REGEXP '^[0-9]{4}-[0-9]{2}-[0-9]{2}$' THEN ld.invoice_date
                     END,
                     CASE
                         WHEN ld.invoice_date REGEXP '^[0-9]{2}-[0-9]{2}-[0-9]{4}$' THEN '%d-%m-%Y'
                         WHEN ld.invoice_date REGEXP '^[0-9]{4}-[0-9]{2}-[0-9]{2}$' THEN '%Y-%m-%d'
                     END
                 )
             )
         ) BETWEEN cat.start_month AND cat.end_month
    SET ld.renewal_category = cat.renewal_year
    WHERE ld.invoice_date IS NOT NULL
      AND ld.policy_expiry_date IS NOT NULL
      AND ld.renewal_category NOT IN ('Rollover');

    -- Capture number of rows updated
    SET rows_affected = ROW_COUNT();

    -- Commit transaction
    COMMIT;

    -- Log rows affected (success log)
    INSERT INTO mmi_mast_procedure_error (
        error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
    ) VALUES (
        0, CONCAT('Rows updated: ', rows_affected), 'mmi_proc_update_lead_renewal_category', 'UPDATE_RENEWAL_CATEGORY', NOW(), 'SYSTEM', NOW()
    );

    -- Re-enable safe update mode
    SET SESSION SQL_SAFE_UPDATES = 1;

END ;;
DELIMITER ;
