        );
        COMMIT;

        -- Rollback main transaction
        ROLLBACK;
    END;

    -- Start main transaction
    START TRANSACTION;

    BEGIN
        -- Drop temp table if exists
        DROP TEMPORARY TABLE IF EXISTS tmp_renewal_ranges;

        -- Create temp table
        CREATE TEMPORARY TABLE tmp_renewal_ranges (
            renewal_year VARCHAR(100),
            start_month INT,
            end_month INT
        );

        -- Populate temp table
        INSERT INTO tmp_renewal_ranges (renewal_year, start_month, end_month)
        SELECT
            renewal_year,
            CAST(SUBSTRING_INDEX(renewal_month, '-', 1) AS UNSIGNED),
            IF(renewal_month LIKE '%-%',
                CAST(SUBSTRING_INDEX(renewal_month, '-', -1) AS UNSIGNED),
                999
            )
        FROM mmi_mast_renewal_category
        WHERE renewal_month IS NOT NULL AND TRIM(renewal_month) != '';

        -- Update renewal_category
        UPDATE mmi_lead_details ld
        JOIN tmp_renewal_ranges cat
          ON TIMESTAMPDIFF(
                 MONTH,
                 LEAST(
