                         CASE
                             WHEN ld.invoice_date REGEXP '^[0-9]{2}-[0-9]{2}-[0-9]{4}$' THEN ld.invoice_date
                             WHEN ld.invoice_date REGEXP '^[0-9]{4}-[0-9]{2}-[0-9]{2}$' THEN ld.invoice_date
