                             WHEN ld.invoice_date REGEXP '^[0-9]{4}-[0-9]{2}-[0-9]{2}$' THEN '%Y-%m-%d'
                         END
                     )
                 )
             ) BETWEEN cat.start_month AND cat.end_month
        SET ld.renewal_category = cat.renewal_year
