CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_otp_verification`(
	IN otpId VARCHAR(255), 
    IN otpVerifiedTime VARCHAR(255)
)
BEGIN

	DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(250);
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
            
            ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_update_otp_verification', 'UpdateOTPVerification', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    START TRANSACTION;

	IF otpId IS NOT NULL OR otpVerifiedTime IS NOT NULL THEN
		UPDATE mmi_otp_details
		SET otp_verified = 'Y', otp_verified_time = otpVerifiedTime
		WHERE otp_id = otpId;
        
        IF ROW_COUNT() > 0 THEN
            COMMIT;
        ELSE
            ROLLBACK;
        END IF;
    ELSE
        ROLLBACK;
    END IF;   
END ;;
DELIMITER ;
