CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_system_configuration_details`(
  IN p_json_data JSON,
  OUT p_status VARCHAR(20),
  OUT p_message VARCHAR(200)
)
BEGIN
  proc_block: BEGIN	
  DECLARE v_error_code INT DEFAULT 0;
  DECLARE v_error_msg VARCHAR(255);
  DECLARE PROCEDURE_TYPE VARCHAR(20) DEFAULT 'UPDATE';

  DECLARE v_created_user_id VARCHAR(50);
  DECLARE v_lead_capture_days VARCHAR(100);
  DECLARE v_inactive_days VARCHAR(100);
  DECLARE v_password_expiry_days VARCHAR(100);
  DECLARE v_lost_bucket_days VARCHAR(50);
  DECLARE v_lead_rollover_year VARCHAR(50);
  DECLARE v_status VARCHAR(10);
  DECLARE v_type VARCHAR(100);

  DECLARE v_insurance_company VARCHAR(100);
  DECLARE v_renewal_category VARCHAR(100);
  DECLARE v_renewal_month VARCHAR(50);
  DECLARE v_vehicle_name VARCHAR(100);
  DECLARE v_segment_name VARCHAR(100);
  DECLARE v_addon_name VARCHAR(100);
  DECLARE v_addon_code VARCHAR(100);
  DECLARE v_premium_amt DECIMAL(10,2);

  DECLARE EXIT HANDLER FOR SQLEXCEPTION
  BEGIN
    GET DIAGNOSTICS CONDITION 1
      v_error_code = MYSQL_ERRNO,
      v_error_msg = MESSAGE_TEXT;
    IF v_error_msg IS NULL THEN
      SET v_error_msg = 'Unexpected SQL Exception occurred.';
    END IF;
    ROLLBACK;
    INSERT INTO mmi_mast_procedure_error
      (error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date)
    VALUES (v_error_code, v_error_msg,
            'mmi_proc_update_system_configuration_details',
            PROCEDURE_TYPE, CURRENT_TIMESTAMP(), 'SYSTEM', NOW());
    SET p_status = '500';
    SET p_message = 'Something went wrong. Please contact admin.';
  END;

  START TRANSACTION;

  -- Extract base config values
  SET v_lead_capture_days     = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.leadCaptureDays'));
  SET v_inactive_days         = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.userInactivityDays'));
  SET v_password_expiry_days  = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.userPasswordExpiryDays'));
  SET v_created_user_id       = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.userId'));
  SET v_lost_bucket_days      = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.lostBucketDays'));
  SET v_lead_rollover_year    = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.leadRolloverYear'));
  SET v_status                = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.status'));

  -- Extract lead pool extra fields
  SET v_type           = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.leadPoolType'));
  SET v_insurance_company = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.insuranceCompany'));
  SET v_renewal_category  = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.renewalCategory'));
  SET v_renewal_month     = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.renewalMonth'));
  SET v_vehicle_name      = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.vehicleCode'));
  SET v_segment_name      = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.vehicleName'));
  SET v_addon_name        = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.addonName'));
  SET v_addon_code        = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.addonCode'));
  SET v_premium_amt       = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.premiumAmt'));

  -- Service configs updates
  IF v_lead_capture_days IS NOT NULL THEN
    UPDATE mmi_services_config
      SET services_value = v_lead_capture_days
    WHERE services_property = 'lead_capture_interval_days';
  END IF;
  IF v_inactive_days IS NOT NULL THEN
    UPDATE mmi_services_config
      SET services_value = v_inactive_days
    WHERE services_property = 'inactive_user_threshold_days';
  END IF;
  IF v_password_expiry_days IS NOT NULL THEN
    UPDATE mmi_services_config
      SET services_value = v_password_expiry_days
    WHERE services_property = 'password_expiry_days';
  END IF;
  IF v_lost_bucket_days IS NOT NULL THEN
    UPDATE mmi_services_config
      SET services_value = v_lost_bucket_days
    WHERE services_property = 'lost_bucket_threshold_days';
  END IF;
  IF v_lead_rollover_year IS NOT NULL THEN
    UPDATE mmi_services_config
      SET services_value = v_lead_rollover_year
    WHERE services_property = 'lead_rollover_threshold_year';
  END IF;

  -- (your JSON_TABLE, thresholds, dispo mappings, dropdown split logic unchanged...)

  -- Lead pool inserts
  IF v_type = 'leadPool' THEN
    -- Insurance
    IF v_insurance_company IS NOT NULL THEN
      IF NOT EXISTS (SELECT 1 FROM mmi_mast_insurancecompany WHERE ic_name = v_insurance_company) THEN
        INSERT INTO mmi_mast_insurancecompany (ic_name, status, created_by)
        VALUES (v_insurance_company, '1', v_created_user_id);
      ELSE 
        SET p_status = '300';
        SET p_message = 'Insurance Company Already Exists';
        ROLLBACK;
        LEAVE proc_block;
      END IF;
    END IF;

    -- Renewal
    IF v_renewal_category IS NOT NULL THEN
      IF NOT EXISTS (SELECT 1 FROM mmi_mast_renewal_category WHERE renewal_year = v_renewal_category) THEN
        INSERT INTO mmi_mast_renewal_category (renewal_year, renewal_month, status, created_by)
        VALUES (v_renewal_category, v_renewal_month, '1', v_created_user_id);
      ELSE 
        SET p_status = '300';
        SET p_message = 'Renewal Category Already Exists';
        ROLLBACK;
        LEAVE proc_block;
      END IF;
    END IF;

    -- Vehicle
    IF v_vehicle_name IS NOT NULL THEN
      IF NOT EXISTS (SELECT 1 FROM mmi_mast_segment WHERE segment = v_vehicle_name) THEN
        INSERT INTO mmi_mast_segment (segment, name, created_by) VALUES (v_vehicle_name, v_segment_name, v_created_user_id);
      ELSE 
        SET p_status = '300';
        SET p_message = 'Vehicle Name Already Exists';
        ROLLBACK;
        LEAVE proc_block;
      END IF;
    END IF;

    -- Addon
    IF v_addon_name IS NOT NULL THEN
      IF NOT EXISTS (SELECT 1 FROM mmi_mast_addon WHERE addon_code = v_addon_code) THEN
        INSERT INTO mmi_mast_addon (addon_description, addon_code, premium_amt, status, created_by) 
        VALUES (v_addon_name, v_addon_code, v_premium_amt, '1', v_created_user_id);
      ELSE 
        SET p_status = '300';
        SET p_message = 'Addon Already Exists';
        ROLLBACK;
        LEAVE proc_block;
      END IF;
    END IF;
  END IF;

  -- Log
  INSERT INTO mmi_insert_log_details
    (service_name, user_id, log_payload, service_type, created_by, created_date)
  VALUES
    ('mmi_proc_update_system_configuration_details', v_created_user_id, p_json_data, 'UPDATE', v_created_user_id, CURRENT_TIMESTAMP(3));

  COMMIT;

  SET p_status = '200';
  SET p_message = 'System configuration updated successfully';
  END proc_block;
END ;;
DELIMITER ;
