CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_target_planning`(
    IN p_json JSON,
    OUT p_status_code VARCHAR(50),
    OUT p_status_message VARCHAR(255)
)
BEGIN
    DECLARE err_code VARCHAR(500);
    DECLARE err_msg TEXT;
    
    DECLARE v_period_type VARCHAR(50);
    DECLARE v_year VARCHAR(50);
    DECLARE v_month VARCHAR(50);
    DECLARE v_team_member VARCHAR(50);
    DECLARE v_segment VARCHAR(50);
    DECLARE v_kpi VARCHAR(50);
    DECLARE v_target_bucket VARCHAR(50);
    DECLARE v_target_value VARCHAR(50);
    DECLARE v_notes VARCHAR(50);
    DECLARE v_id VARCHAR(50);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;

        SET p_status_code = '500';
        SET p_status_message = 'Error while updating record.';
        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error
        VALUES (err_code, err_msg, 'mmi_proc_update_target_planning', 'UPDATE', CURRENT_TIMESTAMP(), 'SYSTEM', NOW());
    END;
	
    SET v_period_type = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.periodType'));
    SET v_year = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.year'));
    SET v_month = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.month'));
    SET v_team_member = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.teamMember'));
    SET v_segment = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.segment'));
    SET v_kpi = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.kpi'));
    SET v_target_bucket = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.targetBucket'));
    SET v_target_value = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.targetValue'));
    SET v_notes = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.notes'));
    SET v_id = JSON_UNQUOTE(JSON_EXTRACT(p_json, '$.id'));
    
    START TRANSACTION;

    UPDATE mmi_target_planning
    SET
        team_member = v_team_member,
        segment = v_segment,
        kpi = v_kpi,
        target_bucket = v_target_bucket,
        target_value = v_target_value,
        notes = v_notes,
        period_type = v_period_type,
        year = v_year,
        month = v_month
    WHERE id = v_id;

    COMMIT;

    SET p_status_code = '200';
    SET p_status_message = 'Record updated successfully';

END ;;
DELIMITER ;
