CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_users_account`()
BEGIN
    DECLARE v_expiry_days INT DEFAULT 60;

    -- Error handling
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
    END;

    START TRANSACTION;

    -- Get expiry days dynamically from config
    SELECT CAST(services_value AS UNSIGNED)
    INTO v_expiry_days
    FROM mmi_services_config
    WHERE services_property = 'password_expiry_days'
    LIMIT 1;

    -- Update user lock status
    UPDATE mmi_mast_user
    SET is_lock = 'L'
    WHERE 
        status = '1'
        AND pass_set_date IS NOT NULL
        AND STR_TO_DATE(pass_set_date, '%Y-%m-%d %H:%i:%s.%f') <= NOW() - INTERVAL v_expiry_days DAY;

    COMMIT;
END ;;
DELIMITER ;
