CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_user_details`(
    IN p_user_data JSON,
    OUT p_status_code VARCHAR(50),
    OUT p_status_message VARCHAR(255)
)
BEGIN
    -- Declare variables to hold parsed values
	DECLARE v_user_id VARCHAR(100); 
    DECLARE v_firstname VARCHAR(100);
    DECLARE v_lastname VARCHAR(100);
    DECLARE v_contactinfo VARCHAR(15);
    DECLARE v_status VARCHAR(20);
    DECLARE v_dealerCode VARCHAR(50);
    DECLARE v_location VARCHAR(100); 
    DECLARE v_roleID INT; 
    DECLARE v_reportingManager_id INT;
    DECLARE v_callingFlag CHAR(1);
    DECLARE v_emailid VARCHAR(255);
    DECLARE v_update_flag BOOLEAN DEFAULT FALSE;
	DECLARE v_leadPool VARCHAR(1000);
    DECLARE v_leadsFlag VARCHAR(100);
    DECLARE v_bucket_id VARCHAR(100);
    DECLARE v_role VARCHAR(100);
    DECLARE v_reportingManager VARCHAR(100);
	DECLARE v_check_bucket_id VARCHAR(100);
	DECLARE v_team_email_flag VARCHAR(10);
    DECLARE v_reporting_userID VARCHAR(10);
    DECLARE v_ad_flag Varchar(10);
    DECLARE v_created_user_id Varchar(50); 
    DECLARE v_parent_code Varchar(50);
    DECLARE v_dealer_code Varchar(50);
    DECLARE v_sap_code VARCHAR(100);
    DECLARE v_group_email VARCHAR(100);
    DECLARE v_password VARCHAR(300);

    DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(250);
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
        SET p_status_code = '500';
        SET p_status_message = 'An error occurred. Please try again.';
        ROLLBACK;
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_update_user_details', 'UpdateUserDetails', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;

    -- Parse values from the JSON input
    SET v_firstname = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.firstname'));
    SET v_lastname = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.lastname'));
    SET v_contactinfo = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.contactinfo'));
    SET v_status = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.status'));
    SET v_dealerCode = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.dealerCode'));
    SET v_location = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.location'));
    -- SET v_roleID = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.roleID'));
    SET v_reportingManager = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.manager'));
    SET v_callingFlag = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.callingFlag'));
    SET v_emailid = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.emailid'));
    SET v_user_id = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.userId'));
	SET v_leadPool = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.leadPool'));
    SET v_leadsFlag = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.leadsFlag'));
    SET v_role = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.role'));
    SET v_team_email_flag = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.teamEmail'));
	SET v_ad_flag = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.adFlag'));
	SET v_created_user_id = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.createduserId'));
    SET v_parent_code = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.parentCode'));
    SET v_sap_code = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.sapCode'));
    SET v_group_email = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.isGroup'));
    SET v_password = JSON_UNQUOTE(JSON_EXTRACT(p_user_data, '$.encryptedPassword'));
    
    -- Check if the necessary fields are provided for update
    IF v_emailid IS NOT NULL THEN
        SET p_status_code = 400;
        SET p_status_message = 'Invalid email format.';
    END IF;
    
    IF v_firstname IS NULL OR v_lastname IS NULL OR v_contactinfo IS NULL OR v_status IS NULL THEN
        SET p_status_code = 400;  -- Bad Request
        SET p_status_message = 'Required fields are missing.';
    ELSE
	
    -- Start the transaction
    START TRANSACTION;
	
    IF v_role IS NOT NULL THEN
		select role_id into v_roleID from mmi_mast_role where role = v_role LIMIT 1;
    END  IF;
    
    -- Update mmi_mast_user_registration_detail, excluding dealerCode, location, and emailid
    
    IF v_parent_code IS NOT NULL AND v_parent_code !='' THEN
    IF v_firstname IS NOT NULL OR v_lastname IS NOT NULL OR v_contactinfo IS NOT NULL OR v_status IS NOT NULL THEN
        UPDATE mmi_mast_user_registration_detail
        SET 
            first_name = COALESCE(v_firstname, first_name),
            last_name = COALESCE(v_lastname, last_name),
            mobile_no = COALESCE(v_contactinfo, mobile_no),
            status = COALESCE(v_status, status),
            team_email_flag = COALESCE(v_team_email_flag, team_email_flag),
            is_group = COALESCE(v_group_email, is_group), -- v_group_email
            modified_by = COALESCE(v_created_user_id, modified_by),
            modified_date = NOW()
        WHERE id = v_user_id;

        IF ROW_COUNT() > 0 THEN
            SET v_update_flag = TRUE;  -- Flag to commit the transaction
        END IF;
    END IF;
    
    SELECT dlm.dealer_code INTO v_dealer_code -- FROM mmi_mast_dealer md 
	FROM mmi_dealer_location_mapping dlm -- ON md.parent_code = dlm.parent_code
	LEFT JOIN mmi_dealer_details dl on dl.dealer_id = dlm.mapping_dealer_code
	LEFT JOIN mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
	WHERE dlm.dealer_name = v_dealerCode and mdl.loc_name = v_location LIMIT 1;
    
    IF v_reportingManager IS NOT NULL THEN
        -- select id into v_reportingManager_id from mmi_mast_user_registration_detail where CONCAT(first_name , ' ', last_name) = v_reportingManager LIMIT 1;
		SELECT urd.id INTO v_reportingManager_Id FROM mmi_mast_user_registration_detail urd 
		LEFT JOIN mmi_user_dealer_mapping udm on udm.user_id = urd.id 
        WHERE CONCAT(first_name , ' ', last_name) = v_reportingManager 
        AND dealer_id = v_dealer_code LIMIT 1;
    END  IF;
    
	IF v_callingFlag IS NOT NULL THEN
	/*IF v_callingFlag = 'Y' then
    IF v_leadPool IS NOT NULL then
		select id into v_bucket_id from mmi_mast_bucket where bucket_name = v_leadPool limit 1;
		select bucket_id into v_check_bucket_id from mmi_bucket_user_mapping where bucket_id = v_bucket_id and user_id = v_user_id limit 1;
        IF v_check_bucket_id IS NOT NULL THEN
			UPDATE mmi_bucket_user_mapping
			SET 
				bucket_id = COALESCE(v_bucket_id, bucket_id)
				WHERE user_id = v_user_id;
         ELSE 
			INSERT INTO mmi_bucket_user_mapping(bucket_id,user_id)
			VALUES(v_bucket_id,v_userID);
		END IF;
      END IF;*/
      IF v_callingFlag = 'Y' THEN
      UPDATE mmi_mast_user
        SET 
			status = COALESCE(v_status, status),
            calling_flag = COALESCE(v_callingFlag, calling_flag),
            ad_flag = COALESCE(v_ad_flag, ad_flag),
            modified_by = COALESCE(v_created_user_id, modified_by),
            modified_date = NOW()
        WHERE user_id = v_user_id;
  IF v_leadPool IS NOT NULL THEN
    IF TRIM(v_leadPool) = '' THEN
      DELETE FROM mmi_bucket_user_mapping WHERE user_id = v_user_id;
      SET v_update_flag = TRUE;
    ELSE
      -- Lookup bucket
      /*SELECT id INTO v_bucket_id FROM mmi_mast_bucket WHERE bucket_name = v_leadPool LIMIT 1;

      IF v_bucket_id IS NOT NULL THEN
        SELECT bucket_id INTO v_check_bucket_id
        FROM mmi_bucket_user_mapping
        WHERE bucket_id = v_bucket_id AND user_id = v_user_id
        LIMIT 1;

        IF v_check_bucket_id IS NOT NULL THEN
          UPDATE mmi_bucket_user_mapping
            SET bucket_id = v_bucket_id
          WHERE user_id = v_user_id;
        ELSE
          INSERT INTO mmi_bucket_user_mapping(bucket_id, user_id)
          VALUES (v_bucket_id, v_user_id);
        END IF;
        SET v_update_flag = TRUE;
      END IF;*/
      IF v_leadPool IS NOT NULL OR v_leadPool != '' THEN
      DELETE FROM mmi_bucket_user_mapping where user_id = v_user_id;
      
      INSERT INTO mmi_bucket_user_mapping (bucket_id, user_id,modified_by,modified_date)
        SELECT b.id, v_user_id, v_created_user_id,NOW()
        FROM JSON_TABLE(
                v_leadPool, 
                '$[*]' COLUMNS (bucket_name VARCHAR(255) PATH '$')
            ) AS jt
        JOIN mmi_mast_bucket b ON b.bucket_name = jt.bucket_name and b.dealer_code = v_dealer_code;
        -- LEFT JOIN mmi_bucket_user_mapping bm ON bm.bucket_id = b.id AND bm.user_id = v_user_id
        -- WHERE bm.bucket_id IS NULL;  -- Only insert if the bucket is not already mapped
        -- ON DUPLICATE KEY UPDATE  
           -- bucket_id = b.id;  -- Update if mapping already exists

        -- Update existing mappings if bucket_id already exists for the user
        -- UPDATE mmi_bucket_user_mapping
        -- JOIN JSON_TABLE(
               -- v_leadPool, 
               -- '$[*]' COLUMNS (bucket_name VARCHAR(255) PATH '$')
            -- ) AS jt
        -- JOIN mmi_mast_bucket b ON b.bucket_name = jt.bucket_name
        -- SET mmi_bucket_user_mapping.bucket_id = b.id
        -- WHERE mmi_bucket_user_mapping.user_id = v_user_id
        -- AND mmi_bucket_user_mapping.bucket_id != b.id;  -- Only update if the bucket_id is different

        SET v_update_flag = TRUE;
        END IF;

    END IF;
  END IF;
	ELSEIF v_callingFlag = 'N' then        
        UPDATE mmi_mast_user
        SET 
			status = COALESCE(v_status, status),
            calling_flag = COALESCE(v_callingFlag, calling_flag),
            ad_flag = COALESCE(v_ad_flag, ad_flag),
            modified_by = COALESCE(v_created_user_id, modified_by),
            modified_date = NOW()
        WHERE user_id = v_user_id;
		DELETE FROM mmi_bucket_user_mapping WHERE user_id = v_user_id;

        IF ROW_COUNT() > 0 THEN
            SET v_update_flag = TRUE;  -- Flag to commit the transaction
        END IF;
        END IF;
    END IF;

    -- Update mmi_user_dealer_mapping excluding dealerCode and location
    -- IF v_roleID IS NOT NULL OR v_reportingManager IS NOT NULL THEN
       -- UPDATE mmi_user_dealer_mapping
       -- SET 
         --   role_id = COALESCE(v_roleID, role_id),
           -- supervisor_id = COALESCE(v_reportingManager, supervisor_id)
        -- WHERE user_id = v_user_id;

        -- IF ROW_COUNT() > 0 THEN
           -- SET v_update_flag = TRUE;  -- Flag to commit the transaction
        -- END IF;
    -- END IF;

    -- Update mmi_user_role_mapping excluding roleID
    IF v_roleID IS NOT NULL THEN
        UPDATE mmi_user_role_mapping
        SET 
            role_id = COALESCE(v_roleID, role_id),
            modified_by = COALESCE(v_created_user_id, modified_by),
            modified_date = NOW()
        WHERE user_id = v_user_id;

        IF ROW_COUNT() > 0 THEN
            SET v_update_flag = TRUE;  -- Flag to commit the transaction
        END IF;
    END IF;

    -- Update mmi_user_reporting excluding reportingManager
    IF v_reportingManager_id IS NOT NULL THEN
		select user_id into v_reporting_userID from mmi_user_reporting where user_id = v_user_id LIMIT 1;
        
        IF v_reporting_userID IS NOT NULL or v_reporting_userID !='' THEN
			UPDATE mmi_user_reporting
			SET 
				supervisor_id = COALESCE(v_reportingManager_id, supervisor_id),
                modified_by = COALESCE(v_created_user_id, modified_by),
				modified_date = NOW()
			WHERE user_id = v_user_id;
        ELSE 
			INSERT INTO mmi_user_reporting (user_id, supervisor_id,modified_by,modified_date)
			VALUES (v_user_id, v_reportingManager_id,v_created_user_id,NOW());
        END IF;
        IF ROW_COUNT() > 0 THEN
            SET v_update_flag = TRUE;  -- Flag to commit the transaction
        END IF;
    END IF;
    -- v_leadPool, 
    IF v_leadsFlag IS NOT NULL THEN
        UPDATE mmi_mast_user
        SET 
			status = COALESCE(v_status, status),
            lead_flag = COALESCE(v_leadsFlag, lead_flag),
            modified_by = COALESCE(v_created_user_id, modified_by),
            modified_date = NOW()
        WHERE user_id = v_user_id; 

        IF ROW_COUNT() > 0 THEN
            SET v_update_flag = TRUE;  -- Flag to commit the transaction
        END IF;
    END IF;
    
    /*IF v_leadPool IS NOT NULL THEN
		select id into v_bucket_id from mmi_mast_bucket where bucket_name = v_leadPool;
        IF v_bucket_id IS NOT NULL THEN 
        UPDATE mmi_bucket_user_mapping
        SET 
            bucket_id = COALESCE(v_bucket_id, bucket_id)
        WHERE user_id = v_user_id; 

        IF ROW_COUNT() > 0 THEN
            SET v_update_flag = TRUE;  -- Flag to commit the transaction
        END IF;
        END IF;
    END IF;*/

	ELSE 
		IF v_firstname IS NOT NULL OR v_lastname IS NOT NULL OR v_contactinfo IS NOT NULL OR v_status IS NOT NULL THEN
        UPDATE mmi_mast_user_registration_detail 
        SET 
            first_name = COALESCE(v_firstname, first_name),
            last_name = COALESCE(v_lastname, last_name),
            mobile_no = COALESCE(v_contactinfo, mobile_no),
            status = COALESCE(v_status, status),
            team_email_flag = COALESCE(v_team_email_flag, team_email_flag),
            sap_code = COALESCE(v_sap_code, sap_code),
            is_group = COALESCE(v_group_email, is_group),
            modified_by = COALESCE(v_created_user_id, modified_by),
            modified_date = NOW()
        WHERE id = v_user_id;

        IF ROW_COUNT() > 0 THEN
            SET v_update_flag = TRUE;  -- Flag to commit the transaction
        END IF;
    END IF;
		IF v_ad_flag = 'N' THEN
			UPDATE mmi_mast_user
			SET 
				status = COALESCE(v_status, status),
				ad_flag = COALESCE(v_ad_flag, ad_flag),
                password = COALESCE(v_password, password),
                last_login_date = NULL,
                modified_by = COALESCE(v_created_user_id, modified_by),
				modified_date = NOW()
			WHERE user_id = v_user_id;
        ELSE
			UPDATE mmi_mast_user
			SET 
				status = COALESCE(v_status, status),
				ad_flag = COALESCE(v_ad_flag, ad_flag),
                modified_by = COALESCE(v_created_user_id, modified_by),
				modified_date = NOW()
			WHERE user_id = v_user_id;
	END IF;
        IF ROW_COUNT() > 0 THEN
            SET v_update_flag = TRUE;  -- Flag to commit the transaction
        END IF;

    -- Update mmi_user_role_mapping excluding roleID
    IF v_roleID IS NOT NULL THEN
        UPDATE mmi_user_role_mapping
        SET 
            role_id = COALESCE(v_roleID, role_id),
            modified_by = COALESCE(v_created_user_id, modified_by),
            modified_date = NOW()
        WHERE user_id = v_user_id;

        IF ROW_COUNT() > 0 THEN
            SET v_update_flag = TRUE;  -- Flag to commit the transaction
        END IF;
    END IF;
	IF v_reportingManager IS NOT NULL THEN
        select id into v_reportingManager_id from mmi_mast_user_registration_detail where CONCAT(first_name , ' ', last_name) = v_reportingManager 
        and role_type_id = 1 LIMIT 1;
    END IF;
    -- Update mmi_user_reporting excluding reportingManager
    IF v_reportingManager_id IS NOT NULL THEN
		select user_id into v_reporting_userID from mmi_user_reporting where user_id = v_user_id LIMIT 1;
        
        IF v_reporting_userID IS NOT NULL or v_reporting_userID !='' THEN
			UPDATE mmi_user_reporting
			SET 
				supervisor_id = COALESCE(v_reportingManager_id, supervisor_id),
                modified_by = COALESCE(v_created_user_id, modified_by),
				modified_date = NOW()
			WHERE user_id = v_user_id;
        ELSE 
			INSERT INTO mmi_user_reporting (user_id, supervisor_id,modified_by,modified_date)
			VALUES (v_user_id, v_reportingManager_id,v_created_user_id,NOW());
        END IF;
        IF ROW_COUNT() > 0 THEN
            SET v_update_flag = TRUE;  -- Flag to commit the transaction
        END IF;
    END IF;
    END IF;
END IF;

	INSERT INTO mmi_insert_log_details (service_name,user_id,log_payload,
    service_type,created_by,created_date) 
    VALUES ('mmi_proc_update_user_details',v_created_user_id,
    p_user_data,'UPDATE',v_created_user_id,CURRENT_TIMESTAMP(3));
        
    -- Finalize the transaction
    IF v_update_flag THEN
        COMMIT;  -- Commit transaction if any update was successful
        SET p_status_code = 200;  -- Success
        SET p_status_message = 'User details updated successfully.';
    ELSE
        ROLLBACK;  -- Rollback transaction if no update was made
        SET p_status_code = 304;  -- Not Modified
        SET p_status_message = 'No fields were updated.';
    END IF;

END ;;
DELIMITER ;
