CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_user_loginDate`(
	IN lastLoginDate VARCHAR(255),
	IN emailId VARCHAR(255)
)
BEGIN

	DECLARE err_code VARCHAR(100);
    DECLARE err_msg VARCHAR(250);
    DECLARE v_update_flag BOOLEAN DEFAULT FALSE;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            err_code = MYSQL_ERRNO,
            err_msg = MESSAGE_TEXT;
		
        ROLLBACK;
        
        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            err_code, err_msg, 'mmi_proc_update_user_loginDate', 'updateUserLoginDate', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

    END;
    START TRANSACTION;
    IF lastLoginDate IS NOT NULL OR emailId IS NOT NULL THEN
		UPDATE mmi_mast_user
		SET last_login_date = lastLoginDate WHERE email_id = emailId;
        IF ROW_COUNT() > 0 THEN
            SET v_update_flag = TRUE;
        END IF;
        IF v_update_flag THEN
			COMMIT;
		ELSE
			ROLLBACK;
		END IF;
    END IF;
END ;;
