CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_user_password`(
    IN p_email_id VARCHAR(255),
    IN p_password VARCHAR(255),
    IN p_checkLoginType VARCHAR(255)
)
BEGIN
    main_block: BEGIN
        DECLARE err_code VARCHAR(100); 
        DECLARE err_msg VARCHAR(250); 
        DECLARE v_existing_password VARCHAR(255);
        DECLARE v_new_encrypted_password VARCHAR(255); 

        DECLARE EXIT HANDLER FOR SQLEXCEPTION
        BEGIN
            GET DIAGNOSTICS CONDITION 1
                err_code = MYSQL_ERRNO,
                err_msg = MESSAGE_TEXT;

            ROLLBACK;

            INSERT INTO mmi_mast_procedure_error (
                error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
            ) VALUES (
                err_code, err_msg, 'mmi_proc_update_user_password', 'UpdateUserPassword', CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
            );
        END; 

        START TRANSACTION;

        -- Validation
        IF p_email_id IS NULL OR p_email_id = '' OR p_password IS NULL OR p_password = '' THEN
            ROLLBACK;
			SELECT '400' AS status_code, 'Invalid email or password' AS status_message;
            LEAVE main_block;
        END IF;

        -- Encrypt the new password input for comparison (Ensure the same encryption method as Spring)
        SET v_new_encrypted_password = p_password;  -- Ensure this matches Spring's MD5 method

        -- Fetch existing encrypted password
        IF p_checkLoginType = 'Email' THEN 
            SELECT password INTO v_existing_password
            FROM mmi_mast_user
            -- WHERE user_id = p_email_id OR email_id = p_email_id LIMIT 1;
			WHERE 
				(p_email_id REGEXP '^[0-9]+$' AND user_id = CAST(p_email_id AS UNSIGNED))
				OR 
				(p_email_id NOT REGEXP '^[0-9]+$' AND email_id = p_email_id);
            
        ELSEIF p_checkLoginType = 'Mobile' THEN
           SELECT DISTINCT u.password INTO v_existing_password
           FROM mmi_mast_user u
           JOIN mmi_mast_user_registration_detail r ON u.user_id = r.id
           WHERE r.mobile_no = p_email_id OR u.user_id = p_email_id OR r.sap_code = p_email_id;

        END IF;

        -- Check if the new encrypted password matches the existing one
        IF v_existing_password = v_new_encrypted_password THEN
            -- Do not allow same password
            ROLLBACK;
            -- Optionally log or raise a message
            SELECT '300' AS status_code, 'Cannot set existing password again' AS status_message;
            LEAVE main_block;
        END IF;

        -- Update with new encrypted password
        IF p_checkLoginType = 'Email' THEN
            UPDATE mmi_mast_user
            SET password = v_new_encrypted_password,
                modified_date = NOW(),
                password_updated_flag = 'Y',
                last_login_date = CURRENT_TIMESTAMP()
            -- WHERE user_id = p_email_id OR email_id = p_email_id; 
            WHERE 
				(p_email_id REGEXP '^[0-9]+$' AND user_id = CAST(p_email_id AS UNSIGNED))
				OR 
				(p_email_id NOT REGEXP '^[0-9]+$' AND email_id = p_email_id);


        ELSEIF p_checkLoginType = 'Mobile' THEN
           UPDATE mmi_mast_user u
           JOIN mmi_mast_user_registration_detail r ON -- r.mobile_no = p_email_id OR r.id = p_email_id
            r.mobile_no = p_email_id
			OR (p_email_id REGEXP '^[0-9]+$' AND r.id = CAST(p_email_id AS UNSIGNED))
            OR r.sap_code = p_email_id
           SET u.password = v_new_encrypted_password,
               u.modified_date = NOW(),
               password_updated_flag = 'Y',
               last_login_date = CURRENT_TIMESTAMP()
           WHERE u.user_id = r.id;

        END IF;

        COMMIT;

        -- Optionally return success message
        SELECT '200' AS status_code, 'Password updated successfully' AS status_message;
    END main_block;
END ;;
DELIMITER ;
