CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_update_user_profile`(
    IN p_json_data JSON,
    OUT sp_status VARCHAR(10),
    OUT message VARCHAR(255)
)
BEGIN 
    DECLARE existing_user INT DEFAULT 0;
    DECLARE v_user_id VARCHAR(50);
    DECLARE v_first_name VARCHAR(50);
    DECLARE v_last_name VARCHAR(50);
    DECLARE v_mobile_no VARCHAR(50);
    DECLARE v_email_id VARCHAR(500);
    DECLARE v_created_user_id VARCHAR(50);

    DECLARE SP_ERROR_CODE INT DEFAULT 0;
    DECLARE ERROR_MESSAGE TEXT;
    DECLARE PROCEDURE_TYPE VARCHAR(50) DEFAULT 'update_user_profile';

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            SP_ERROR_CODE = MYSQL_ERRNO,
            ERROR_MESSAGE = MESSAGE_TEXT;

        ROLLBACK;

        INSERT INTO mmi_mast_procedure_error (
            error_code, error_message, procedure_name, procedure_type, error_timing, created_by, created_date
        ) VALUES (
            SP_ERROR_CODE, ERROR_MESSAGE, 'mmi_proc_update_user_profile', PROCEDURE_TYPE, CURRENT_TIMESTAMP(), 'SYSTEM', NOW()
        );

        SET sp_status = '500';
        SET message = 'Error occurred while updating profile';
    END;

    main_block: BEGIN

        SET v_user_id    = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.userId'));
        SET v_first_name = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.firstName'));
        SET v_last_name  = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.lastName'));
        SET v_mobile_no  = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.mobileNo'));
		SET v_created_user_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.createduserId'));
        SET v_email_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.emailId'));
        
        IF v_user_id IS NULL OR v_user_id = '' THEN
        -- OR v_user_id REGEXP '[^a-zA-Z0-9_@.-]' THEN
            SET sp_status = '400';
            SET message = 'Invalid user ID';
            LEAVE main_block;
        END IF;

        START TRANSACTION;

        SELECT COUNT(*) INTO existing_user
        FROM mmi_mast_user_registration_detail
        WHERE id = v_user_id;

        IF existing_user = 0 THEN
            SET sp_status = '404';
            SET message = 'User not found';
            ROLLBACK;
            LEAVE main_block;
        END IF;

        UPDATE mmi_mast_user_registration_detail
        SET 
            first_name = IF(v_first_name IS NOT NULL AND v_first_name != '', v_first_name, first_name),
            last_name  = IF(v_last_name IS NOT NULL AND v_last_name != '', v_last_name, last_name),
            mobile_no  = IF(v_mobile_no IS NOT NULL AND v_mobile_no != '', v_mobile_no, mobile_no),
            modified_by = IF(v_created_user_id IS NOT NULL AND v_created_user_id != '', v_created_user_id, modified_by),
            modified_date = NOW()
        WHERE id = v_user_id and email_id = v_email_id;
		
        INSERT INTO mmi_insert_log_details (service_name,user_id,log_payload,
		service_type,created_by,created_date) 
		VALUES ('mmi_proc_update_user_profile',v_created_user_id,
		p_json_data,'UPDATE',v_created_user_id,CURRENT_TIMESTAMP(3));
        
        COMMIT;
        SET sp_status = '200';
        SET message = 'Profile updated successfully';

    END main_block;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
