CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_upload_misp_excel_data`(
    IN Json_data JSON,
    IN type VARCHAR(45),
    OUT SP_STATUS VARCHAR(500), 
    OUT MESSAGE VARCHAR(500) 
)
BEGIN
    DECLARE dealerId VARCHAR(45);
    DECLARE parentId VARCHAR(45);
    DECLARE v_parentId VARCHAR(45);
    DECLARE custom_type VARCHAR(45);
    DECLARE userId VARCHAR(100);
    DECLARE rowJson JSON;
	DECLARE old_upload_data JSON;
	DECLARE new_upload_data JSON;

    DECLARE i INT DEFAULT 0;
    DECLARE total INT;
    DECLARE errno INT DEFAULT 0;
    DECLARE errmsg TEXT;
    
    DECLARE v_uuid_short BIGINT UNSIGNED;
    DECLARE v_numeric_part VARCHAR(15);
    DECLARE v_unique_id VARCHAR(20);
	DECLARE success_count INT DEFAULT 0;
    DECLARE failure_count INT DEFAULT 0;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        GET DIAGNOSTICS CONDITION 1 
            @sqlstate = RETURNED_SQLSTATE,
            errno = MYSQL_ERRNO,
            errmsg = MESSAGE_TEXT;
        SET SP_STATUS = 407;
        SET MESSAGE = 'Something Went Wrong.';
        
        ROLLBACK;
		INSERT INTO mmi_mast_procedure_error (error_code, error_message, procedure_name,procedure_type,ERROR_TIMING,created_by,created_date) 
        VALUES (errno, CONCAT('SQLSTATE: ', @sqlstate, ', Error: ', errmsg), 'mmi_proc_upload_misp_excel_data', type ,CURRENT_TIMESTAMP(),'SYSTEM',NOW());

        
    END;

IF type = 'fetchexcelColumns' THEN

        SET dealerId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId'));
        SET parentId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'));
        SET custom_type = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.customtype'));
        SET userId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId'));


	IF dealerId IS NULL OR dealerId = '' OR parentId IS NULL OR parentId = '' 
		OR userId IS NULL OR userId = '' OR custom_type IS NULL OR custom_type = '' 
		THEN
		SET SP_STATUS = '400';
		SET MESSAGE = CONCAT(
		CASE 
		WHEN dealerId IS NULL OR dealerId = '' THEN 'dealerId is missing'
		WHEN parentId IS NULL OR parentId = '' THEN 'parentId is missing'
		WHEN userId IS NULL OR userId = '' THEN 'userId is missing'
		WHEN custom_type IS NULL OR custom_type = '' THEN 'custom Type is missing'
		END
		);    
	ELSE
			SELECT 
			CASE 
			WHEN custom_type = 'claim' THEN claim_flag
			WHEN custom_type = 'policy' THEN policy_flag
			WHEN custom_type = 'sales' THEN sales_flag
			WHEN custom_type = 'service' THEN service_flag
			WHEN custom_type = 'addon' THEN addon_flag
			ELSE NULL
			END INTO @templateSource 
            FROM mmi_dealer_details WHERE dealer_id = dealerId AND parent_code = parentId LIMIT 1;

	IF @templateSource = CONCAT(custom_type, '_custom') or @templateSource = CONCAT(custom_type, '_created_custom') THEN

			SELECT DISTINCT 
			mecm.excel_column_name AS excelColumnName,
			mecm.db_column_name AS dbColumnName,
			mecm.db_table_name AS dbTableName,
			mcm.mandatory AS mandatory,
			CASE 
			WHEN mecm.db_table_name = 'mmi_ebm_policy_data' THEN 'policy'
			WHEN mecm.db_table_name = 'mmi_ebm_claim_data' THEN 'claim'
			WHEN mecm.db_table_name = 'mmi_ebm_sales_data' THEN 'sales'
			WHEN mecm.db_table_name = 'mmi_ebm_service_data' THEN 'service'
			WHEN mecm.db_table_name = 'mmi_poladdon_data' THEN 'addon'
			END AS customtype
			FROM mmi_mast_excel_column_mapping mecm  
			LEFT JOIN mmi_mast_columns_mandatory mcm ON mcm.columns_name = mecm.db_column_name
			LEFT JOIN mmi_excel_column_mapping ecm ON ecm.custom_id = mecm.custom_id
			WHERE ecm.dealer_id = dealerId AND ecm.parent_id = parentId AND customtype = custom_type;

			select dealer_name,map as dealerLocCode,  loc_name as dealerLocName
			from mmi_dealer_details dd left join mmi_mast_dealer_location mdl on dd.map = mdl.loc_code
			where parent_code = parentId and dealer_id = dealerId;


			ELSEIF @templateSource = CONCAT(custom_type, '_system') THEN
			SELECT 
            excel_column_name AS excelColumnName,
			db_table_name AS dbTableName,
			columns_name  AS dbColumnName,
			mandatory FROM mmi_mast_columns_mandatory
			WHERE db_table_name = 
			CASE 
			WHEN custom_type = 'claim' THEN 'mmi_ebm_claim_data'
			WHEN custom_type = 'policy' THEN 'mmi_ebm_policy_data'
			WHEN custom_type = 'sales' THEN 'mmi_ebm_sales_data'
			WHEN custom_type = 'service' THEN 'mmi_ebm_service_data'
			WHEN custom_type = 'addon' THEN 'mmi_poladdon_data'
			END;
            
			select dealer_name,map as dealerLocCode,  loc_name as dealerLocName
			from mmi_dealer_details dd left join mmi_mast_dealer_location mdl on dd.map = mdl.loc_code
			where parent_code = parentId and dealer_id = dealerId;
			
            END IF;

			SET SP_STATUS = '200';
			SET MESSAGE = 'Success';
        END IF; 

    -- 2. Bulk Upload Data to Respective Tables
ELSEIF type = 'bulkInsertData' THEN

