IF custom_type = 'sales' THEN

            -- 1. Capture old data for the specific dealer
            SELECT JSON_ARRAYAGG(
                JSON_OBJECT(
                    'id', IFNULL(id, ''),
                    'cluster_id', IFNULL(cluster_id, ''),
                    'invoice_number', IFNULL(invoice_number, ''),
