           -- Step 1: Update existing records
			UPDATE mmi_ebm_sales_data t
			JOIN (
				SELECT 
					jt.invoice_number,
					jt.invoice_date_time,
					jt.chassis_number,
					jt.engine_number,
					jt.dealer_parent_name,
					jt.dealer_location_code,
					jt.branch_name,
					jt.sc_name,
					parentId AS dealer_parent_code,
					JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')) AS modified_by,
					NOW() AS modified_date
				FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
					invoice_number VARCHAR(255) PATH '$.invoice_number',
					invoice_date_time VARCHAR(255) PATH '$.invoice_date_time',
					chassis_number VARCHAR(255) PATH '$.chassis_number',
					engine_number VARCHAR(255) PATH '$.engine_number',
					dealer_parent_name VARCHAR(255) PATH '$.dealer_parent_name',
					dealer_location_code VARCHAR(255) PATH '$.dealer_location_code',
					branch_name VARCHAR(255) PATH '$.branch_name',
					sc_name VARCHAR(255) PATH '$.sc_name'
				)) AS jt
			) AS src
			ON t.chassis_number = src.chassis_number
			   AND t.engine_number = src.engine_number
			   AND t.dealer_parent_name = src.dealer_parent_name
			   AND t.dealer_parent_code = src.dealer_parent_code
			SET 
				t.invoice_number = src.invoice_number,
				t.invoice_date_time = src.invoice_date_time,
				t.dealer_location_code = src.dealer_location_code,
				t.branch_name = src.branch_name,
				t.sc_name = src.sc_name,
				t.modified_by = src.modified_by,
				t.modified_date = src.modified_date
             WHERE 
				-- Validation conditions
				src.invoice_number IS NOT NULL 
				AND STR_TO_DATE(src.invoice_date_time, '%Y-%m-%d %H:%i:%s') IS NOT NULL
				AND LENGTH(src.chassis_number) >= 7 
				AND LENGTH(src.engine_number) >= 7 
				AND src.dealer_parent_name IS NOT NULL
				AND src.dealer_location_code IS NOT NULL
				AND src.branch_name IS NOT NULL;   
			
             SET success_count = ROW_COUNT(); 
            
            -- Step 2: Insert new records
			INSERT INTO mmi_ebm_sales_data (
				invoice_number, invoice_date_time, dealer_parent_code,
				chassis_number, engine_number, dealer_parent_name,
				dealer_location_code, branch_name, sc_name,
				created_by, modified_by, modified_date
			)
			SELECT 
				jt.invoice_number,
				jt.invoice_date_time,
				parentId,
				jt.chassis_number,
				jt.engine_number,
				jt.dealer_parent_name,
				jt.dealer_location_code,
				jt.branch_name,
				jt.sc_name,
				JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
				JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
				NOW()
			FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
				invoice_number VARCHAR(255) PATH '$.invoice_number',
				invoice_date_time VARCHAR(255) PATH '$.invoice_date_time',
				chassis_number VARCHAR(255) PATH '$.chassis_number',
				engine_number VARCHAR(255) PATH '$.engine_number',
				dealer_parent_name VARCHAR(255) PATH '$.dealer_parent_name',
				dealer_location_code VARCHAR(255) PATH '$.dealer_location_code',
				branch_name VARCHAR(255) PATH '$.branch_name',
				sc_name VARCHAR(255) PATH '$.sc_name'
			)) AS jt
			WHERE jt.invoice_number IS NOT NULL 
			AND STR_TO_DATE(jt.invoice_date_time, '%Y-%m-%d %H:%i:%s') IS NOT NULL
			AND LENGTH(jt.chassis_number) >= 7 
			AND LENGTH(jt.engine_number) >= 7 
			AND jt.dealer_parent_name IS NOT NULL
			AND jt.dealer_location_code IS NOT NULL
			AND jt.branch_name IS NOT NULL
            AND NOT EXISTS (
				SELECT 1
				FROM mmi_ebm_sales_data existing
				WHERE existing.chassis_number = jt.chassis_number
				  AND existing.engine_number = jt.engine_number
				  AND existing.dealer_parent_name = jt.dealer_parent_name
				  AND existing.dealer_parent_code = parentId
			);
            
			SET success_count = success_count + ROW_COUNT();  -- Update the success count
            
            INSERT INTO mmi_ebm_sales_data_error (
				invoice_number, invoice_date_time, chassis_number,
				engine_number, dealer_parent_name, dealer_location_code,
				branch_name, dealer_id, user_id,case_reference_id, validation_errors
			)
			SELECT 
				jt.invoice_number,
				jt.invoice_date_time,
				jt.chassis_number,
				jt.engine_number,
				jt.dealer_parent_name,
				jt.dealer_location_code,
				jt.branch_name,
                JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId')),
                JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
                v_unique_id,
				CASE
					WHEN jt.invoice_number IS NULL THEN 'Invoice number is blank'
					WHEN STR_TO_DATE(jt.invoice_date_time, '%Y-%m-%d %H:%i:%s') IS NULL THEN 'Invalid date format'
					WHEN LENGTH(jt.chassis_number) < 7 THEN 'Chassis number must be at least 7 digits'
					WHEN LENGTH(jt.engine_number) < 7 THEN 'Engine number must be at least 7 digits'
					WHEN jt.dealer_parent_name IS NULL THEN 'Dealer parent name is blank'
					WHEN jt.dealer_location_code IS NULL THEN 'Dealer location code is blank'
					WHEN jt.branch_name IS NULL THEN 'Branch name is blank'
					ELSE 'Unknown error'
				END AS validation_errors
			FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
				invoice_number VARCHAR(255) PATH '$.invoice_number',
				invoice_date_time VARCHAR(255) PATH '$.invoice_date_time',
				chassis_number VARCHAR(255) PATH '$.chassis_number',
				engine_number VARCHAR(255) PATH '$.engine_number',
				dealer_parent_name VARCHAR(255) PATH '$.dealer_parent_name',
				dealer_location_code VARCHAR(255) PATH '$.dealer_location_code',
				branch_name VARCHAR(255) PATH '$.branch_name',
				sc_name VARCHAR(255) PATH '$.sc_name'
			)) AS jt
			WHERE 
				jt.invoice_number IS NULL 
				OR STR_TO_DATE(jt.invoice_date_time, '%Y-%m-%d %H:%i:%s') IS NULL
				OR LENGTH(jt.chassis_number) < 7 
				OR LENGTH(jt.engine_number) < 7 
				OR jt.dealer_parent_name IS NULL
				OR jt.dealer_location_code IS NULL
				OR jt.branch_name IS NULL;
                
			SET failure_count = ROW_COUNT();  -- This will capture the number of rows affected by the INSERT into error table
            
            -- 3. Capture new data for the specific dealer
            SELECT JSON_ARRAYAGG(
                JSON_OBJECT(
                    'id', IFNULL(id, ''),
                    'cluster_id', IFNULL(cluster_id, ''),
                    'invoice_number', IFNULL(invoice_number, ''),
                    'invoice_date_time', IFNULL(invoice_date_time, ''),
                    'dealer_parent_code', IFNULL(dealer_parent_code, ''),
                    'chassis_number', IFNULL(chassis_number, ''),
                    'engine_number', IFNULL(engine_number, ''),
                    'dealer_parent_name', IFNULL(dealer_parent_name, ''),
                    'dealer_location_code', IFNULL(dealer_location_code, ''),
                    'branch_name', IFNULL(branch_name, ''),
                    'sc_code', IFNULL(sc_code, ''),
                    'sc_name', IFNULL(sc_name, ''),
                    'i_date', IFNULL(i_date, ''),
                    'm_date', IFNULL(m_date, ''),
                    'm_user', IFNULL(m_user, ''),
                    'version', IFNULL(version, '')
                )
            ) INTO new_upload_data
            FROM mmi_ebm_sales_data
            WHERE dealer_parent_code = parentId;

            -- 4. Insert into logs
            INSERT INTO mmi_maintain_overwrite_logs (
                upload_type, name, old_upload_data, new_upload_data, created_by, created_date
            )
            VALUES (
                custom_type,
                'mmi_ebm_sales_data',
                old_upload_data,
                new_upload_data,
                JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
                NOW()
            );

            -- Commit and set status
            COMMIT;
            -- SET SP_STATUS = '200';
            -- SET MESSAGE = 'Bulk Data Saved into SALES successfully';
			-- SET MESSAGE = CONCAT(success_count, ' records processed successfully, ', failure_count, ' records failed.');
            IF failure_count > 0 THEN
				Select v_unique_id;
				SET SP_STATUS = '400';
				SET MESSAGE = CONCAT(success_count, ' records processed successfully, ', failure_count, ' records failed.');
			ELSE 
				SET v_unique_id = '';
				Select v_unique_id;
				SET SP_STATUS = '200';
				SET MESSAGE = CONCAT(success_count, ' records processed successfully, ', failure_count, ' records failed.');
			END IF;  

