        podc_start DATE PATH '$.podc_start',
        policy_effective_date VARCHAR(50) PATH '$.policy_effective_date',
        policy_expiry_date VARCHAR(50) PATH '$.policy_expiry_date',
        policy_no VARCHAR(255) PATH '$.policy_no',
        policy_tenure INT PATH '$.policy_tenure',
        policy_type VARCHAR(50) PATH '$.policy_type',
        previous_insurance_company VARCHAR(255) PATH '$.previous_insurance_company',
        previous_policy_no VARCHAR(255) PATH '$.previous_policy_no',
        proposal_no VARCHAR(255) PATH '$.proposal_no',
        reg_no VARCHAR(50) PATH '$.reg_no',
        rto_display_name VARCHAR(255) PATH '$.rto_display_name',
        third_party_liability DECIMAL(15,2) PATH '$.third_party_liability',
        third_party_liability_bifuel_kit DECIMAL(15,2) PATH '$.third_party_liability_bifuel_kit',
        total_idv DECIMAL(15,2) PATH '$.total_idv',
        tpgeographical_areas_extention_imt1 VARCHAR(255) PATH '$.tpgeographical_areas_extention_imt1',
        trailer_imt30 DECIMAL(15,2) PATH '$.trailer_imt30',
        variant VARCHAR(255) PATH '$.variant',
        vehicle_body_type VARCHAR(50) PATH '$.vehicle_body_type',
        vehicle_class VARCHAR(50) PATH '$.vehicle_class',
        vehicle_reg_no VARCHAR(50) PATH '$.vehicle_reg_no',
        vehicle_sub_class VARCHAR(50) PATH '$.vehicle_sub_class',
        vin VARCHAR(255) PATH '$.vin',
        yom INT PATH '$.yom',
        dealer VARCHAR(255) PATH '$.dealer'
    )) AS jt
    ) AS src
    ON t.policy_no = src.policy_no
       AND t.vin = src.vin
       AND t.engine_no = src.engine_no
       AND t.dealer_code = src.dealerId
    SET
		t.addon_premium_amount = src.addon_premium_amount,
		t.bundle_product = src.bundle_product,
		t.cancellation_flag = src.cancellation_flag,
		t.carrier_type = src.carrier_type,
		t.customer_address = src.customer_address,
		t.customer_city = src.customer_city,
		t.customer_email = src.customer_email,
		t.customer_phone = src.customer_phone,
		t.customer_pincode = src.customer_pincode,
		t.customer_state = src.customer_state,
		t.engine_no = src.engine_no,
		t.fuel_type = src.fuel_type,
		t.geographical_areas_extention_imt1 = src.geographical_areas_extention_imt1,
		t.gross_premium = src.gross_premium,
		t.imt_23 = src.imt_23,
		t.imt_34tp = src.imt_34tp,
		t.insurance_company = src.insurance_company,
		t.insured_name = src.insured_name,
		t.legal_liability = src.legal_liability,
		t.legal_liability_nfpp_imt37 = src.legal_liability_nfpp_imt37,
		t.make = src.make,
		t.model = src.model,
		t.ncb_percentage = src.ncb_percentage,
		t.net_liability = src.net_liability,
		t.net_od_premium_amount = src.net_od_premium_amount,
		t.net_premium = src.net_premium,
		t.oem_code = src.oem_code,
		t.pa_cover = src.pa_cover,
		t.pa_cover_owner_driver = src.pa_cover_owner_driver,
		t.pa_cover_unnamed_persons_imt16 = src.pa_cover_unnamed_persons_imt16,
		t.payment_mode = src.payment_mode,
		t.plan_type = src.plan_type,
		t.plc_end = src.plc_end,
		t.plc_start = src.plc_start,
		t.podc_end = src.podc_end,
		t.podc_start = src.podc_start,
		t.policy_effective_date = src.policy_effective_date,
		t.policy_expiry_date = src.policy_expiry_date,
		t.policy_tenure = src.policy_tenure,
		t.policy_type = src.policy_type,
		t.previous_insurance_company = src.previous_insurance_company,
		t.previous_policy_no = src.previous_policy_no,
		t.proposal_no = src.proposal_no,
		t.reg_no = src.reg_no,
		t.rto_display_name = src.rto_display_name,
		t.third_party_liability = src.third_party_liability,
		t.third_party_liability_bifuel_kit = src.third_party_liability_bifuel_kit,
		t.total_idv = src.total_idv,
		t.tpgeographical_areas_extention_imt1 = src.tpgeographical_areas_extention_imt1,
		t.trailer_imt30 = src.trailer_imt30,
		t.variant = src.variant,
		t.vehicle_body_type = src.vehicle_body_type,
		t.vehicle_class = src.vehicle_class,
		t.vehicle_reg_no = src.vehicle_reg_no,
		t.vehicle_sub_class = src.vehicle_sub_class,
		t.vin = src.vin,
		t.yom = src.yom,
		t.dealer = src.dealer,
		t.modified_by = src.modified_by,
		t.modified_date = NOW()
    WHERE
        EXISTS (SELECT 1 FROM mmi_mast_insurancecompany mic WHERE mic.ic_name = src.insurance_company)
		-- AND EXISTS (SELECT 1 FROM master_policy_type mpt WHERE mpt.policy_type = jt.policy_type)
		-- AND EXISTS (SELECT 1 FROM master_customer_state mcs WHERE mcs.customer_state = jt.customer_state)
		AND EXISTS (SELECT 1 FROM mmi_mast_segment mvc WHERE mvc.segment = src.vehicle_class)
        
		AND src.policy_no REGEXP '^[0-9a-zA-Z,/-]+$'
		AND src.policy_tenure BETWEEN 1 AND 5
		AND src.insured_name IS NOT NULL AND src.insured_name != ''
		AND src.customer_address IS NOT NULL AND src.customer_address != ''
		AND src.customer_city IS NOT NULL AND src.customer_city != ''
		AND src.policy_type IS NOT NULL AND src.policy_type != ''
		AND src.plan_type IS NOT NULL AND src.plan_type != ''
		AND src.make IS NOT NULL AND src.make != ''
		AND src.model IS NOT NULL AND src.model != ''
		AND src.fuel_type IS NOT NULL AND src.fuel_type != ''
		AND src.variant IS NOT NULL AND src.variant != ''
		AND src.customer_email IS NOT NULL AND src.customer_email != '' AND src.customer_email LIKE '%_@__%.__%'
		AND (src.customer_pincode IS NULL OR (LENGTH(src.customer_pincode) = 6 AND src.customer_pincode REGEXP '^[0-9]{6}$'))
		AND (src.customer_phone IS NULL OR (LENGTH(src.customer_phone) = 10 AND src.customer_phone REGEXP '^[0-9]{10}$'))
		AND src.vin IS NOT NULL AND LENGTH(src.vin) >= 7
		AND src.engine_no IS NOT NULL AND LENGTH(src.engine_no) >= 7
		AND src.yom BETWEEN 1900 AND YEAR(CURDATE())
		AND src.policy_effective_date IS NOT NULL 
		AND src.policy_expiry_date IS NOT NULL
		AND src.policy_effective_date REGEXP '^[0-9]{4}-(0[1-9]|1[0-2])-(0[1-9]|[12][0-9]|3[01])$'
		AND src.policy_expiry_date REGEXP '^[0-9]{4}-(0[1-9]|1[0-2])-(0[1-9]|[12][0-9]|3[01])$';
		-- AND STR_TO_DATE(src.policy_expiry_date, '%Y-%m-%d') > STR_TO_DATE(src.policy_effective_date, '%Y-%m-%d');
		-- AND src.policy_expiry_date > src.policy_effective_date;    
    
    SET success_count = ROW_COUNT(); 
    
    INSERT INTO mmi_ebm_policy_data (
        addon_premium_amount, bundle_product, cancellation_flag, carrier_type,
        customer_address, customer_city, customer_email, customer_phone, customer_pincode, customer_state,
        engine_no, fuel_type, geographical_areas_extention_imt1, gross_premium, imt_23, imt_34tp,
        insurance_company, insured_name, legal_liability, legal_liability_nfpp_imt37,
        make, model, ncb_percentage, net_liability, net_od_premium_amount, net_premium,
        oem_code, pa_cover, pa_cover_owner_driver, pa_cover_unnamed_persons_imt16,
        payment_mode, plan_type, plc_end, plc_start, podc_end, podc_start,
        policy_effective_date, policy_expiry_date, policy_no, policy_tenure, policy_type,
        previous_insurance_company, previous_policy_no, proposal_no, reg_no,
        rto_display_name, third_party_liability, third_party_liability_bifuel_kit,
        total_idv, tpgeographical_areas_extention_imt1, trailer_imt30,
        variant, vehicle_body_type, vehicle_class, vehicle_reg_no, vehicle_sub_class,
        vin, yom, created_by, modified_by, modified_date, dealer_code, dealer
    )
    SELECT
        jt.addon_premium_amount,
        jt.bundle_product,
        jt.cancellation_flag,
        jt.carrier_type,
        jt.customer_address,
        jt.customer_city,
        jt.customer_email,
        jt.customer_phone,
        jt.customer_pincode,
        jt.customer_state,
        jt.engine_no,
        jt.fuel_type,
        jt.geographical_areas_extention_imt1,
        jt.gross_premium,
        jt.imt_23,
        jt.imt_34tp,
        jt.insurance_company,
        jt.insured_name,
        jt.legal_liability,
        jt.legal_liability_nfpp_imt37,
        jt.make,
        jt.model,
        jt.ncb_percentage,
        jt.net_liability,
        jt.net_od_premium_amount,
        jt.net_premium,
        jt.oem_code,
        jt.pa_cover,
        jt.pa_cover_owner_driver,
        jt.pa_cover_unnamed_persons_imt16,
        jt.payment_mode,
        jt.plan_type,
        jt.plc_end,
        jt.plc_start,
        jt.podc_end,
        jt.podc_start,
        jt.policy_effective_date,
        jt.policy_expiry_date,
        jt.policy_no,
        jt.policy_tenure,
        jt.policy_type,
        jt.previous_insurance_company,
        jt.previous_policy_no,
        jt.proposal_no,
        jt.reg_no,
        jt.rto_display_name,
        jt.third_party_liability,
        jt.third_party_liability_bifuel_kit,
        jt.total_idv,
        jt.tpgeographical_areas_extention_imt1,
        jt.trailer_imt30,
        jt.variant,
        jt.vehicle_body_type,
        jt.vehicle_class,
        jt.vehicle_reg_no,
        jt.vehicle_sub_class,
        jt.vin,
        jt.yom,
        JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')) AS created_by,
        JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')) AS modified_by,
        NOW(),
        dealerId,
        jt.dealer
    FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
        addon_premium_amount DECIMAL(15,2) PATH '$.addon_premium_amount',
        bundle_product VARCHAR(255) PATH '$.bundle_product',
        cancellation_flag VARCHAR(10) PATH '$.cancellation_flag',
