        fuel_type VARCHAR(50) PATH '$.fuel_type',
        geographical_areas_extention_imt1 VARCHAR(255) PATH '$.geographical_areas_extention_imt1',
        gross_premium DECIMAL(15,2) PATH '$.gross_premium',
