        net_premium DECIMAL(15,2) PATH '$.net_premium',
        oem_code VARCHAR(50) PATH '$.oem_code',
        pa_cover DECIMAL(15,2) PATH '$.pa_cover',
        pa_cover_owner_driver DECIMAL(15,2) PATH '$.pa_cover_owner_driver',
        pa_cover_unnamed_persons_imt16 DECIMAL(15,2) PATH '$.pa_cover_unnamed_persons_imt16',
        payment_mode VARCHAR(50) PATH '$.payment_mode',
        plan_type VARCHAR(50) PATH '$.plan_type',
        plc_end DATE PATH '$.plc_end',
        plc_start DATE PATH '$.plc_start',
        podc_end DATE PATH '$.podc_end',
        podc_start DATE PATH '$.podc_start',
        policy_effective_date VARCHAR(50) PATH '$.policy_effective_date',
        policy_expiry_date VARCHAR(50) PATH '$.policy_expiry_date',
        policy_no VARCHAR(255) PATH '$.policy_no',
        policy_tenure INT PATH '$.policy_tenure',
        policy_type VARCHAR(50) PATH '$.policy_type',
        previous_insurance_company VARCHAR(255) PATH '$.previous_insurance_company',
        previous_policy_no VARCHAR(255) PATH '$.previous_policy_no',
        proposal_no VARCHAR(255) PATH '$.proposal_no',
        reg_no VARCHAR(50) PATH '$.reg_no',
        rto_display_name VARCHAR(255) PATH '$.rto_display_name',
        third_party_liability DECIMAL(15,2) PATH '$.third_party_liability',
        third_party_liability_bifuel_kit DECIMAL(15,2) PATH '$.third_party_liability_bifuel_kit',
        total_idv DECIMAL(15,2) PATH '$.total_idv',
        tpgeographical_areas_extention_imt1 VARCHAR(255) PATH '$.tpgeographical_areas_extention_imt1',
        trailer_imt30 DECIMAL(15,2) PATH '$.trailer_imt30',
        variant VARCHAR(255) PATH '$.variant',
        vehicle_body_type VARCHAR(50) PATH '$.vehicle_body_type',
        vehicle_class VARCHAR(50) PATH '$.vehicle_class',
        vehicle_reg_no VARCHAR(50) PATH '$.vehicle_reg_no',
        vehicle_sub_class VARCHAR(50) PATH '$.vehicle_sub_class',
        vin VARCHAR(255) PATH '$.vin',
        yom INT PATH '$.yom',
        dealer VARCHAR(255) PATH '$.dealer'
    )) AS jt
    WHERE 
		EXISTS (SELECT 1 FROM mmi_mast_insurancecompany mic WHERE mic.ic_name = jt.insurance_company)
		-- AND EXISTS (SELECT 1 FROM master_policy_type mpt WHERE mpt.policy_type = jt.policy_type)
		-- AND EXISTS (SELECT 1 FROM master_customer_state mcs WHERE mcs.customer_state = jt.customer_state)
		AND EXISTS (SELECT 1 FROM mmi_mast_segment mvc WHERE mvc.segment = jt.vehicle_class)

		-- Other validations
		AND jt.policy_no REGEXP '^[0-9a-zA-Z,/-]+$'
		AND jt.policy_tenure BETWEEN 1 AND 5
		AND jt.insured_name IS NOT NULL AND jt.insured_name != ''
		AND jt.customer_address IS NOT NULL AND jt.customer_address != ''
		AND jt.customer_city IS NOT NULL AND jt.customer_city != ''
		AND jt.policy_type IS NOT NULL AND jt.policy_type != ''
		AND jt.plan_type IS NOT NULL AND jt.plan_type != ''
		AND jt.make IS NOT NULL AND jt.make != ''
		AND jt.model IS NOT NULL AND jt.model != ''
		AND jt.fuel_type IS NOT NULL AND jt.fuel_type != ''
		AND jt.variant IS NOT NULL AND jt.variant != ''
		AND jt.customer_email IS NOT NULL AND jt.customer_email != ''
		AND jt.customer_email LIKE '%_@__%.__%'
		AND (jt.customer_pincode IS NULL OR (LENGTH(jt.customer_pincode) = 6 AND jt.customer_pincode REGEXP '^[0-9]{6}$'))
		AND (jt.customer_phone IS NULL OR (LENGTH(jt.customer_phone) = 10 AND jt.customer_phone REGEXP '^[0-9]{10}$'))
		AND jt.vin IS NOT NULL AND LENGTH(jt.vin) >= 7
		AND jt.engine_no IS NOT NULL AND LENGTH(jt.engine_no) >= 7
		AND jt.yom BETWEEN 1900 AND YEAR(CURDATE())
		AND jt.policy_effective_date IS NOT NULL
		AND jt.policy_expiry_date IS NOT NULL
		AND jt.policy_effective_date REGEXP '^[0-9]{4}-(0[1-9]|1[0-2])-(0[1-9]|[12][0-9]|3[01])$'
		AND jt.policy_expiry_date REGEXP '^[0-9]{4}-(0[1-9]|1[0-2])-(0[1-9]|[12][0-9]|3[01])$'
		-- AND STR_TO_DATE(jt.policy_expiry_date, '%Y-%m-%d') > STR_TO_DATE(jt.policy_effective_date, '%Y-%m-%d')
		-- AND jt.policy_expiry_date > jt.policy_effective_date
		AND NOT EXISTS (
			SELECT 1
			FROM mmi_ebm_policy_data existing
			WHERE existing.policy_no = jt.policy_no
			  AND existing.vin = jt.vin
			  AND existing.engine_no = jt.engine_no
			  AND existing.dealer_code = dealerId
		);
        
        SET success_count = success_count + ROW_COUNT();
        
