    -- Capture new data for the specific dealer
    
		INSERT INTO mmi_ebm_policy_data_error_log (
			validation_errors,
			addon_premium_amount, bundle_product, cancellation_flag, carrier_type,
			customer_address, customer_city, customer_email, customer_phone, customer_pincode, customer_state,
			engine_no, fuel_type, geographical_areas_extention_imt1, gross_premium, imt_23, imt_34tp,
			insurance_company, insured_name, legal_liability, legal_liability_nfpp_imt37,
			make, model, ncb_percentage, net_liability, net_od_premium_amount, net_premium,
			oem_code, pa_cover, pa_cover_owner_driver, pa_cover_unnamed_persons_imt16,
			payment_mode, plan_type, plc_end, plc_start, podc_end, podc_start,
			policy_effective_date, policy_expiry_date, policy_no, policy_tenure, policy_type,
			previous_insurance_company, previous_policy_no, proposal_no, reg_no,
			rto_display_name, third_party_liability, third_party_liability_bifuel_kit,
			total_idv, tpgeographical_areas_extention_imt1, trailer_imt30,
			variant, vehicle_body_type, vehicle_class, vehicle_reg_no, vehicle_sub_class,
			vin, yom, created_by, modified_by, modified_date, dealer_code, dealer, dealer_id, user_id, case_reference_id
		)
		SELECT
			-- Compose an error message based on failed validations
			CONCAT(
				IF(NOT EXISTS (SELECT 1 FROM mmi_mast_insurancecompany mic WHERE mic.ic_name = jt.insurance_company), 'Invalid insurance_company; ', ''),
				-- IF(NOT EXISTS (SELECT 1 FROM master_policy_type mpt WHERE mpt.policy_type = jt.policy_type), 'Invalid policy_type; ', ''),
				-- IF(NOT EXISTS (SELECT 1 FROM master_customer_state mcs WHERE mcs.customer_state = jt.customer_state), 'Invalid customer_state; ', ''),
				IF(NOT EXISTS (SELECT 1 FROM mmi_mast_segment mvc WHERE mvc.segment = jt.vehicle_class), 'Invalid vehicle_class; ', ''),
				IF(jt.policy_no NOT REGEXP '^[0-9a-zA-Z,/-]+$', 'Invalid policy_no format; ', ''),
				IF(jt.policy_tenure NOT BETWEEN 1 AND 5, 'Invalid policy_tenure; ', ''),
				IF(jt.insured_name IS NULL OR jt.insured_name = '', 'Missing insured_name; ', ''),
				IF(jt.customer_address IS NULL OR jt.customer_address = '', 'Missing customer_address; ', ''),
				IF(jt.customer_city IS NULL OR jt.customer_city = '', 'Missing customer_city; ', ''),
				IF(jt.customer_email IS NULL OR jt.customer_email = '' OR jt.customer_email NOT LIKE '%_@__%.__%', 'Invalid customer_email; ', ''),
				IF(jt.customer_pincode IS NOT NULL AND (LENGTH(jt.customer_pincode) != 6 OR jt.customer_pincode NOT REGEXP '^[0-9]{6}$'), 'Invalid customer_pincode; ', ''),
				IF(jt.customer_phone IS NOT NULL AND (LENGTH(jt.customer_phone) != 10 OR jt.customer_phone NOT REGEXP '^[0-9]{10}$'), 'Invalid customer_phone; ', ''),
				IF(jt.vin IS NULL OR LENGTH(jt.vin) < 7, 'Invalid vin; ', ''),
				IF(jt.engine_no IS NULL OR LENGTH(jt.engine_no) < 7, 'Invalid engine_no; ', ''),
				IF(jt.yom NOT BETWEEN 1900 AND YEAR(CURDATE()), 'Invalid yom; ', ''),
				IF(jt.policy_effective_date IS NULL, 'Missing policy_effective_date; ', ''),
				IF(jt.policy_expiry_date IS NULL, 'Missing policy_expiry_date; ', ''),
				IF(jt.policy_effective_date NOT REGEXP '^[0-9]{4}-(0[1-9]|1[0-2])-(0[1-9]|[12][0-9]|3[01])$', 'Invalid policy effective date format; ', ''),
				IF(jt.policy_expiry_date NOT REGEXP '^[0-9]{4}-(0[1-9]|1[0-2])-(0[1-9]|[12][0-9]|3[01])$', 'Invalid policy expiry date format;; ', ''),
				IF(jt.policy_expiry_date <= jt.policy_effective_date, 'policy_expiry_date <= policy_effective_date; ', '')
				/*IF(EXISTS (
					SELECT 1 FROM mmi_ebm_policy_data existing
					WHERE existing.policy_no = jt.policy_no
					AND existing.vin = jt.vin
					AND existing.engine_no = jt.engine_no
