        'vehicleRegNo', IFNULL(vehicle_reg_no, ''),
        'carrierType', IFNULL(carrier_type, ''),
        'policyEffectiveDate', IFNULL(policy_effective_date, ''),
        'policyExpiryDate', IFNULL(policy_expiry_date, ''),
        'make', IFNULL(make, ''),
        'model', IFNULL(model, ''),
        'vehicleBodyType', IFNULL(vehicle_body_type, ''),
        'fuelType', IFNULL(fuel_type, ''),
        'variant', IFNULL(variant, ''),
