        'engineNo', IFNULL(engine_no, ''),
        'paymentMode', IFNULL(payment_mode, ''),
        'odDiscountPercentage', IFNULL(od_discount_percentage, ''),
        'totalIdv', IFNULL(total_idv, ''),
        'addonPremiumAmount', IFNULL(addon_premium_amount, ''),
        'netOdPremiumAmount', IFNULL(net_od_premium_amount, ''),
        'thirdPartyLiability', IFNULL(third_party_liability, ''),
        'paCover', IFNULL(pa_cover, ''),
        'legalLiability', IFNULL(legal_liability, ''),
        'netLiability', IFNULL(net_liability, ''),
        'netPremium', IFNULL(net_premium, ''),
        'imt23', IFNULL(imt_23, ''),
        'grossPremium', IFNULL(gross_premium, ''),
        'rtoDisplayName', IFNULL(rto_display_name, ''),
        'previousPolicyNo', IFNULL(previous_policy_no, ''),
        'previousInsuranceCompany', IFNULL(previous_insurance_company, ''),
        'podcStart', IFNULL(podc_start, ''),
        'podcEnd', IFNULL(podc_end, ''),
        'plcStart', IFNULL(plc_start, ''),
        'plcEnd', IFNULL(plc_end, ''),
        'thirdPartyLiabilityBiFuelKit', IFNULL(third_party_liability_bifuel_kit, ''),
        'trailerImt30', IFNULL(trailer_imt30, ''),
        'imt34Tp', IFNULL(imt_34tp, ''),
        'paCoverUnnamedPersonsImt16', IFNULL(pa_cover_unnamed_persons_imt16, ''),
        'geographicalAreasExtentionImt1', IFNULL(geographical_areas_extention_imt1, ''),
        'tpgeographicalAreasExtentionImt1', IFNULL(tpgeographical_areas_extention_imt1, ''),
        'legalLiabilityNfppImt37', IFNULL(legal_liability_nfpp_imt37, ''),
        'paCoverOwnerDriver', IFNULL(pa_cover_owner_driver, ''),
        'oemCode', IFNULL(oem_code, ''),
        'proposalNo', IFNULL(proposal_no, ''),
        'planType', IFNULL(plan_type, ''),
        'ebmCalls', IFNULL(ebm_calls, ''),
        'zd', IFNULL(zd, ''),
        'bundleProduct', IFNULL(bundle_product, ''),
        'invoiceDate', IFNULL(invoice_date, ''),
        'cancellationFlag', IFNULL(cancellation_flag, ''),
        'regNo', IFNULL(reg_no, ''),
        'iDate', IFNULL(i_date, ''),
        'mDate', IFNULL(m_date, ''),
        'mUser', IFNULL(m_user, ''),
        'version', IFNULL(version, ''),
        'clusterId', IFNULL(cluster_id, ''),
        'customerAddress', IFNULL(customer_address, ''),
        'customerState', IFNULL(customer_state, ''),
        'customerCity', IFNULL(customer_city, ''),
        'customerPincode', IFNULL(customer_pincode, ''),
        'customerPhone', IFNULL(customer_phone, ''),
        'customerEmail', IFNULL(customer_email, ''),
        'dealer_code', IFNULL(dealer_code, ''),
        'dealer', IFNULL(dealer, '')
      )
    ) INTO new_upload_data
    FROM mmi_ebm_policy_data
    WHERE dealer_code = dealerId;

    -- Insert into logs
    INSERT INTO mmi_maintain_overwrite_logs (
        upload_type, name, old_upload_data, new_upload_data, created_by, created_date
    )
    VALUES (
        custom_type,
        'mmi_ebm_policy_data',
        old_upload_data,
        new_upload_data,
        JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
        NOW()
    );

    -- Commit transaction
    COMMIT;
    
    -- SET MESSAGE = 'Bulk Data Saved into POLICY successfully';
	IF failure_count > 0 THEN
		Select v_unique_id;
		SET SP_STATUS = '400';
		SET MESSAGE = CONCAT(success_count, ' records processed successfully, ', failure_count, ' records failed.');
    ELSE 
		SET v_unique_id = '';
		Select v_unique_id;
		SET SP_STATUS = '200';
		SET MESSAGE = CONCAT(success_count, ' records processed successfully, ', failure_count, ' records failed.');
    END IF; 

	  
