			SET SP_STATUS = '200';
			SET MESSAGE = 'Bulk insert into ADDON successful';      
	*/
 
 ELSEIF custom_type = 'addon' THEN

    -- Capture old data for the specific dealer
    SELECT JSON_ARRAYAGG(
        JSON_OBJECT(
            'id', IFNULL(id, ''),
            'policy_no', IFNULL(policy_no, ''),
            'add_on_name', IFNULL(add_on_name, ''),
            'bundle_name', IFNULL(bundle_name, ''),
            'premium', IFNULL(premium, ''),
            'policy_expiry_date', IFNULL(policy_expiry_date, '')
        )
    ) INTO old_upload_data
    FROM mmi_poladdon_data
    WHERE policy_no IN (
        SELECT jt.policy_no FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
            policy_no VARCHAR(255) PATH '$.policy_no'
        )) AS jt
    );

    -- Upsert using JSON_TABLE
    /*INSERT INTO mmi_poladdon_data (
        policy_no, add_on_name, bundle_name, premium, created_by, modified_by, modified_date, policy_expiry_date
    )
    SELECT
        jt.policy_no,
        jt.add_on_name,
        jt.bundle_name,
        jt.premium,
        JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
        JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
        NOW(),
        jt.policy_expiry_date
    FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
        policy_no VARCHAR(255) PATH '$.policy_no',
        add_on_name VARCHAR(255) PATH '$.add_on_name',
        bundle_name VARCHAR(255) PATH '$.bundle_name',
        premium DECIMAL(15,2) PATH '$.premium',
        policy_expiry_date DATE PATH '$.policy_expiry_date'
    )) AS jt
    ON DUPLICATE KEY UPDATE
        add_on_name = VALUES(add_on_name),
        bundle_name = VALUES(bundle_name),
        premium = VALUES(premium),
        modified_by = VALUES(modified_by),
        modified_date = VALUES(modified_date);*/
        
    -- Step 1: UPDATE existing records
		UPDATE mmi_poladdon_data t
		JOIN (
			SELECT
				jt.policy_no,
				jt.add_on_name,
				jt.bundle_name,
				jt.premium,
				jt.policy_expiry_date,
				JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')) AS modified_by,
				NOW() AS modified_date
			FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
				policy_no VARCHAR(255) PATH '$.policy_no',
				add_on_name VARCHAR(255) PATH '$.add_on_name',
				bundle_name VARCHAR(255) PATH '$.bundle_name',
				premium DECIMAL(15,2) PATH '$.premium',
				policy_expiry_date VARCHAR(255) PATH '$.policy_expiry_date'
			)) AS jt
            WHERE
			jt.policy_no IS NOT NULL AND jt.policy_no != ''
			AND jt.policy_no NOT REGEXP '[^0-9a-zA-Z\\-/]'
			AND (jt.policy_expiry_date IS NULL OR STR_TO_DATE(jt.policy_expiry_date, '%Y-%m-%d') IS NOT NULL)
		) AS src
		ON t.policy_no = src.policy_no
		   AND t.add_on_name = src.add_on_name
		SET
			t.bundle_name = src.bundle_name,
			t.premium = src.premium,
			t.policy_expiry_date = src.policy_expiry_date,
			t.modified_by = src.modified_by,
			t.modified_date = src.modified_date;
		
        SET success_count = ROW_COUNT();
        
		-- Step 2: INSERT new records only
		INSERT INTO mmi_poladdon_data (
			policy_no,
			add_on_name,
			bundle_name,
			premium,
			created_by,
			modified_by,
			modified_date,
			policy_expiry_date
		)
		SELECT
			jt.policy_no,
			jt.add_on_name,
			jt.bundle_name,
			jt.premium,
			JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
			JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
			NOW(),
			jt.policy_expiry_date
		FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
			policy_no VARCHAR(255) PATH '$.policy_no',
			add_on_name VARCHAR(255) PATH '$.add_on_name',
			bundle_name VARCHAR(255) PATH '$.bundle_name',
			premium DECIMAL(15,2) PATH '$.premium',
			policy_expiry_date VARCHAR(255) PATH '$.policy_expiry_date'
		)) AS jt
		WHERE 
			jt.policy_no IS NOT NULL AND jt.policy_no != ''
		    AND jt.policy_no NOT REGEXP '[^0-9a-zA-Z\\-/]'
		    AND (jt.policy_expiry_date IS NULL OR STR_TO_DATE(jt.policy_expiry_date, '%Y-%m-%d') IS NOT NULL)
		    AND NOT EXISTS (
				SELECT 1
				FROM mmi_poladdon_data existing
				WHERE existing.policy_no = jt.policy_no
				  AND existing.add_on_name = jt.add_on_name
			);
            
        SET success_count = success_count + ROW_COUNT();    

		INSERT INTO mmi_poladdon_data_error (
		  policy_no, add_on_name, bundle_name, premium,
		  policy_expiry_date, created_by, created_date, dealer_id, user_id,case_reference_id, validation_errors
		)
		SELECT
		  jt.policy_no,
		  jt.add_on_name,
		  jt.bundle_name,
		  jt.premium,
		  jt.policy_expiry_date,
		  JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
		  NOW(),
		  JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId')),
		  JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
          v_unique_id,
		  CONCAT_WS(', ',
			IF(jt.policy_no IS NULL OR jt.policy_no = '', 'Policy No is blank', NULL),
			IF(jt.policy_no REGEXP '[^0-9a-zA-Z\\-/]', 'Policy No has invalid characters', NULL),
			IF(jt.policy_expiry_date IS NOT NULL AND STR_TO_DATE(jt.policy_expiry_date, '%Y-%m-%d') IS NULL,
			   'Policy Expiry Date is invalid format', NULL)
		  )
		FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
		  policy_no VARCHAR(255) PATH '$.policy_no',
		  add_on_name VARCHAR(255) PATH '$.add_on_name',
		  bundle_name VARCHAR(255) PATH '$.bundle_name',
		  premium DECIMAL(15,2) PATH '$.premium',
		  policy_expiry_date VARCHAR(255) PATH '$.policy_expiry_date'
		)) AS jt
