	-- Step 1: UPDATE existing records based on chassis_number and engine_number
		UPDATE mmi_ebm_service_data t
		JOIN (
			SELECT
				jt.repair_order_no,
				jt.ro_date,
				jt.service_category,
				jt.service_type,
				jt.registration_no,
				jt.chassis_number,
				jt.engine_number,
				jt.customer_mobile_no,
				jt.service_advisor,
				jt.ro_bill_date_time,
				jt.ro_status,
				JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')) AS modified_by,
				NOW() AS modified_date
			FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
				repair_order_no VARCHAR(255) PATH '$.repair_order_no',
				ro_date VARCHAR(255) PATH '$.ro_date',
				service_category VARCHAR(255) PATH '$.service_category',
				service_type VARCHAR(255) PATH '$.service_type',
				registration_no VARCHAR(50) PATH '$.registration_no',
				chassis_number VARCHAR(255) PATH '$.chassis_number',
				engine_number VARCHAR(255) PATH '$.engine_number',
				customer_mobile_no VARCHAR(50) PATH '$.customer_mobile_no',
				service_advisor VARCHAR(255) PATH '$.service_advisor',
				ro_bill_date_time VARCHAR(255) PATH '$.ro_bill_date_time',
				ro_status VARCHAR(50) PATH '$.ro_status'
			)) AS jt
		) AS src
		ON t.chassis_number = src.chassis_number
		AND t.engine_number = src.engine_number
		SET
			t.repair_order_no = src.repair_order_no,
			t.ro_date = src.ro_date,
			t.service_category = src.service_category,
			t.service_type = src.service_type,
			t.registration_no = src.registration_no,
			t.customer_mobile_no = src.customer_mobile_no,
			t.service_advisor = src.service_advisor,
			t.ro_bill_date_time = src.ro_bill_date_time,
			t.ro_status = src.ro_status,
			t.modified_by = src.modified_by,
			t.modified_date = src.modified_date
         WHERE
			  src.repair_order_no IS NOT NULL AND src.repair_order_no != ''
			  AND src.ro_date IS NOT NULL AND STR_TO_DATE(src.ro_date, '%Y-%m-%d') IS NOT NULL
			  AND src.service_category IS NOT NULL AND src.service_category != ''
			  AND src.service_type IS NOT NULL AND src.service_type != ''
			  AND src.chassis_number IS NOT NULL AND LENGTH(src.chassis_number) >= 7
			  AND src.engine_number IS NOT NULL AND LENGTH(src.engine_number) >= 7
			  AND (src.customer_mobile_no IS NULL OR 
				   (LENGTH(src.customer_mobile_no) = 10 AND src.customer_mobile_no REGEXP '^[0-9]{10}$'))
			  AND src.service_advisor IS NOT NULL AND src.service_advisor != '';  
              
        SET success_count = ROW_COUNT();      

		-- Step 2: INSERT new records if chassis_number and engine_number not present
		INSERT INTO mmi_ebm_service_data (
			repair_order_no,
			ro_date,
			service_category,
			service_type,
			registration_no,
			chassis_number,
			engine_number,
			customer_mobile_no,
			service_advisor,
			ro_bill_date_time,
			ro_status,
			created_by,
			modified_by,
			modified_date
		)
		SELECT
			jt.repair_order_no,
			jt.ro_date,
			jt.service_category,
			jt.service_type,
			jt.registration_no,
			jt.chassis_number,
			jt.engine_number,
			jt.customer_mobile_no,
