			JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
			NOW()
		FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
			repair_order_no VARCHAR(255) PATH '$.repair_order_no',
			ro_date VARCHAR(255) PATH '$.ro_date',
			service_category VARCHAR(255) PATH '$.service_category',
			service_type VARCHAR(255) PATH '$.service_type',
			registration_no VARCHAR(50) PATH '$.registration_no',
			chassis_number VARCHAR(255) PATH '$.chassis_number',
			engine_number VARCHAR(255) PATH '$.engine_number',
			customer_mobile_no VARCHAR(50) PATH '$.customer_mobile_no',
			service_advisor VARCHAR(255) PATH '$.service_advisor',
			ro_bill_date_time VARCHAR(255) PATH '$.ro_bill_date_time',
			ro_status VARCHAR(50) PATH '$.ro_status'
		)) AS jt
		WHERE 
			jt.repair_order_no IS NOT NULL AND jt.repair_order_no != ''
		    AND jt.ro_date IS NOT NULL AND STR_TO_DATE(jt.ro_date, '%Y-%m-%d') IS NOT NULL
		    AND jt.service_category IS NOT NULL AND jt.service_category != ''
		    AND jt.service_type IS NOT NULL AND jt.service_type != ''
		    AND jt.chassis_number IS NOT NULL AND LENGTH(jt.chassis_number) >= 7
		    AND jt.engine_number IS NOT NULL AND LENGTH(jt.engine_number) >= 7
		    AND (jt.customer_mobile_no IS NULL OR 
			   (LENGTH(jt.customer_mobile_no) = 10 AND jt.customer_mobile_no REGEXP '^[0-9]{10}$'))
		    AND jt.service_advisor IS NOT NULL AND jt.service_advisor != ''
			AND NOT EXISTS (
			SELECT 1
			FROM mmi_ebm_service_data existing
			WHERE existing.chassis_number = jt.chassis_number
			AND existing.engine_number = jt.engine_number
		);
        
        SET success_count = success_count + ROW_COUNT();

		INSERT INTO mmi_ebm_service_data_error (
