		  JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
          v_unique_id,
		  CONCAT_WS(', ',
			IF(jt.repair_order_no IS NULL OR jt.repair_order_no = '', 'Repair Order No blank', NULL),
			IF(jt.ro_date IS NULL OR STR_TO_DATE(jt.ro_date, '%Y-%m-%d') IS NULL, 'Invalid RO Date', NULL),
			IF(jt.service_category IS NULL OR jt.service_category = '', 'Service Category blank', NULL),
			IF(jt.service_type IS NULL OR jt.service_type = '', 'Service Type blank', NULL),
			IF(jt.chassis_number IS NULL OR LENGTH(jt.chassis_number) < 7, 'Invalid Chassis Number', NULL),
			IF(jt.engine_number IS NULL OR LENGTH(jt.engine_number) < 7, 'Invalid Engine Number', NULL),
			IF(jt.customer_mobile_no IS NOT NULL 
				 AND (LENGTH(jt.customer_mobile_no) != 10 OR jt.customer_mobile_no NOT REGEXP '^[0-9]{10}$'),
			   'Invalid Customer Mobile No', NULL),
			IF(jt.service_advisor IS NULL OR jt.service_advisor = '', 'Service Advisor blank', NULL)
		  )
		FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
		  repair_order_no VARCHAR(255) PATH '$.repair_order_no',
		  ro_date VARCHAR(255) PATH '$.ro_date',
		  service_category VARCHAR(255) PATH '$.service_category',
		  service_type VARCHAR(255) PATH '$.service_type',
		  registration_no VARCHAR(50) PATH '$.registration_no',
		  chassis_number VARCHAR(255) PATH '$.chassis_number',
		  engine_number VARCHAR(255) PATH '$.engine_number',
		  customer_mobile_no VARCHAR(50) PATH '$.customer_mobile_no',
		  service_advisor VARCHAR(255) PATH '$.service_advisor',
		  ro_bill_date_time VARCHAR(255) PATH '$.ro_bill_date_time',
		  ro_status VARCHAR(50) PATH '$.ro_status'
		)) AS jt
