		  NOT (
			-- all validations for valid row
			jt.repair_order_no IS NOT NULL AND jt.repair_order_no != ''
			AND jt.ro_date IS NOT NULL AND STR_TO_DATE(jt.ro_date, '%Y-%m-%d') IS NOT NULL
			AND jt.service_category IS NOT NULL AND jt.service_category != ''
			AND jt.service_type IS NOT NULL AND jt.service_type != ''
			AND jt.chassis_number IS NOT NULL AND LENGTH(jt.chassis_number) >= 7
			AND jt.engine_number IS NOT NULL AND LENGTH(jt.engine_number) >= 7
