				 (LENGTH(jt.customer_mobile_no) = 10 AND jt.customer_mobile_no REGEXP '^[0-9]{10}$'))
			AND jt.service_advisor IS NOT NULL AND jt.service_advisor != ''
		  );
	
		SET failure_count = ROW_COUNT();

    -- Capture new data for the specific dealer
    SELECT JSON_ARRAYAGG(
        JSON_OBJECT(
            'id', IFNULL(id, ''),
            'repair_order_no', IFNULL(repair_order_no, ''),
            'ro_date', IFNULL(ro_date, ''),
            'service_category', IFNULL(service_category, ''),
