        -- Step 1: UPDATE existing records based on policy_no, chassis_number, and engine_no
		UPDATE mmi_ebm_claim_data t
		JOIN (
			SELECT
				jt.policy_no,
				jt.claim_no,
				jt.claim_intimation_date_time,
				jt.accident_city,
				jt.nature_of_loss,
				jt.insurance_claim_no,
				jt.claim_status,
				jt.total_estimate_amount,
				jt.amount_paid,
				jt.workshop_name,
				jt.workshop_state,
				jt.workshop_city,
				jt.last_modified_date,
				jt.chassis_number,
				jt.engine_no,
				jt.veh_reg_no,
				jt.risk_start_date,
				JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')) AS modified_by,
				NOW() AS modified_date
			FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
				policy_no VARCHAR(255) PATH '$.policy_no',
				claim_no VARCHAR(255) PATH '$.claim_no',
				claim_intimation_date_time VARCHAR(255) PATH '$.claim_intimation_date_time',
				accident_city VARCHAR(255) PATH '$.accident_city',
				nature_of_loss VARCHAR(255) PATH '$.nature_of_loss',
				insurance_claim_no VARCHAR(255) PATH '$.insurance_claim_no',
				claim_status VARCHAR(50) PATH '$.claim_status',
				total_estimate_amount DECIMAL(15,2) PATH '$.total_estimate_amount',
				amount_paid DECIMAL(15,2) PATH '$.amount_paid',
				workshop_name VARCHAR(255) PATH '$.workshop_name',
				workshop_state VARCHAR(255) PATH '$.workshop_state',
				workshop_city VARCHAR(255) PATH '$.workshop_city',
				last_modified_date DATETIME PATH '$.last_modified_date',
				chassis_number VARCHAR(255) PATH '$.chassis_number',
				engine_no VARCHAR(255) PATH '$.engine_no',
				veh_reg_no VARCHAR(255) PATH '$.veh_reg_no',
				risk_start_date DATE PATH '$.risk_start_date'
			)) AS jt
		) AS src
		ON t.policy_no = src.policy_no
		AND t.chassis_number = src.chassis_number
		AND t.engine_no = src.engine_no
		SET
			t.claim_no = src.claim_no,
			t.claim_intimation_date_time = src.claim_intimation_date_time,
			t.accident_city = src.accident_city,
			t.nature_of_loss = src.nature_of_loss,
			t.insurance_claim_no = src.insurance_claim_no,
			t.claim_status = src.claim_status,
			t.total_estimate_amount = src.total_estimate_amount,
			t.amount_paid = src.amount_paid,
			t.workshop_name = src.workshop_name,
			t.workshop_state = src.workshop_state,
			t.workshop_city = src.workshop_city,
			t.last_modified_date = src.last_modified_date,
			t.veh_reg_no = src.veh_reg_no,
			t.risk_start_date = src.risk_start_date,
			t.modified_by = src.modified_by,
			t.modified_date = src.modified_date
       WHERE
			src.policy_no REGEXP '^[0-9a-zA-Z,/-]+$'
			AND src.claim_no IS NOT NULL AND src.claim_no != ''
			AND src.claim_intimation_date_time IS NOT NULL
			AND STR_TO_DATE(src.claim_intimation_date_time, '%d-%m-%Y %H:%i') IS NOT NULL
			AND src.accident_city IS NOT NULL AND src.accident_city != ''
			AND src.nature_of_loss IS NOT NULL AND src.nature_of_loss != ''
			AND src.nature_of_loss REGEXP '^[A-Za-z ]+$'
			AND src.insurance_claim_no IS NOT NULL AND src.insurance_claim_no != ''
			AND src.claim_status IS NOT NULL AND src.claim_status != ''
			AND src.claim_status REGEXP '^[A-Za-z ]+$'
			AND src.workshop_name IS NOT NULL AND src.workshop_name != ''
			AND src.workshop_state IS NOT NULL AND src.workshop_state != ''
			AND src.workshop_city IS NOT NULL AND src.workshop_city != ''
			AND src.chassis_number IS NOT NULL AND LENGTH(src.chassis_number) >= 7
			AND src.engine_no IS NOT NULL AND LENGTH(src.engine_no) >= 7
			AND (src.risk_start_date IS NULL OR src.risk_start_date IS NOT NULL);     

		SET success_count = ROW_COUNT(); 

		-- Step 2: INSERT new records if policy_no, chassis_number, and engine_no combination does not exist
		INSERT INTO mmi_ebm_claim_data (
			policy_no, claim_no, claim_intimation_date_time, accident_city,
			nature_of_loss, insurance_claim_no, claim_status, total_estimate_amount,
			amount_paid, workshop_name, workshop_state, workshop_city,
			last_modified_date, chassis_number, engine_no, veh_reg_no,
			risk_start_date, created_by, modified_by, modified_date
		)
		SELECT
			jt.policy_no,
			jt.claim_no,
			jt.claim_intimation_date_time,
			jt.accident_city,
			jt.nature_of_loss,
			jt.insurance_claim_no,
			jt.claim_status,
			jt.total_estimate_amount,
			jt.amount_paid,
			jt.workshop_name,
			jt.workshop_state,
			jt.workshop_city,
			jt.last_modified_date,
			jt.chassis_number,
			jt.engine_no,
			jt.veh_reg_no,
			jt.risk_start_date,
			JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
			JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
			NOW()
		FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
			policy_no VARCHAR(255) PATH '$.policy_no',
			claim_no VARCHAR(255) PATH '$.claim_no',
			claim_intimation_date_time VARCHAR(255) PATH '$.claim_intimation_date_time',
			accident_city VARCHAR(255) PATH '$.accident_city',
			nature_of_loss VARCHAR(255) PATH '$.nature_of_loss',
			insurance_claim_no VARCHAR(255) PATH '$.insurance_claim_no',
			claim_status VARCHAR(50) PATH '$.claim_status',
			total_estimate_amount DECIMAL(15,2) PATH '$.total_estimate_amount',
			amount_paid DECIMAL(15,2) PATH '$.amount_paid',
			workshop_name VARCHAR(255) PATH '$.workshop_name',
			workshop_state VARCHAR(255) PATH '$.workshop_state',
			workshop_city VARCHAR(255) PATH '$.workshop_city',
			last_modified_date DATETIME PATH '$.last_modified_date',
			chassis_number VARCHAR(255) PATH '$.chassis_number',
			engine_no VARCHAR(255) PATH '$.engine_no',
			veh_reg_no VARCHAR(255) PATH '$.veh_reg_no',
			risk_start_date DATE PATH '$.risk_start_date'
		)) AS jt
		WHERE 
			jt.policy_no REGEXP '^[0-9a-zA-Z,/-]+$'
			AND jt.claim_no IS NOT NULL AND jt.claim_no != ''
			AND jt.claim_intimation_date_time IS NOT NULL AND STR_TO_DATE(jt.claim_intimation_date_time, '%d-%m-%Y %H:%i') IS NOT NULL
			AND jt.accident_city IS NOT NULL AND jt.accident_city != ''
			AND jt.nature_of_loss IS NOT NULL AND jt.nature_of_loss REGEXP '^[A-Za-z ]+$'
			AND jt.insurance_claim_no IS NOT NULL AND jt.insurance_claim_no != ''
			AND jt.claim_status IS NOT NULL AND jt.claim_status REGEXP '^[A-Za-z ]+$'
			AND jt.workshop_name IS NOT NULL AND jt.workshop_name != ''
			AND jt.workshop_state IS NOT NULL AND jt.workshop_state != ''
			AND jt.workshop_city IS NOT NULL AND jt.workshop_city != ''
			AND jt.chassis_number IS NOT NULL AND LENGTH(jt.chassis_number) >= 7
			AND jt.engine_no IS NOT NULL AND LENGTH(jt.engine_no) >= 7
			AND (jt.risk_start_date IS NULL OR STR_TO_DATE(jt.risk_start_date, '%Y-%m-%d') IS NOT NULL)
			AND NOT EXISTS (
				SELECT 1 FROM mmi_ebm_claim_data existing
				WHERE existing.policy_no = jt.policy_no
				AND existing.chassis_number = jt.chassis_number
				AND existing.engine_no = jt.engine_no
			);
		
        SET success_count = success_count + ROW_COUNT();
        
		INSERT INTO mmi_ebm_claim_data_error (
			policy_no, claim_no, claim_intimation_date_time, accident_city,
			nature_of_loss, insurance_claim_no, claim_status,
			total_estimate_amount, amount_paid,
			workshop_name, workshop_state, workshop_city,
			last_modified_date, chassis_number, engine_no,
			veh_reg_no, risk_start_date,
			created_by, created_date, dealer_id, user_id,case_reference_id, validation_errors
		)
		SELECT
			jt.policy_no,
			jt.claim_no,
			jt.claim_intimation_date_time,
			jt.accident_city,
			jt.nature_of_loss,
			jt.insurance_claim_no,
			jt.claim_status,
			jt.total_estimate_amount,
			jt.amount_paid,
			jt.workshop_name,
			jt.workshop_state,
			jt.workshop_city,
			jt.last_modified_date,
			jt.chassis_number,
			jt.engine_no,
			jt.veh_reg_no,
			jt.risk_start_date,
			JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
			NOW(),
            JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.dealerId')),
			JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
            v_unique_id,
			CONCAT_WS(', ',
				IF(jt.policy_no IS NULL OR jt.policy_no NOT REGEXP '^[0-9a-zA-Z,/-]+$', 'Invalid Policy No', NULL),
				IF(jt.claim_no IS NULL OR jt.claim_no = '', 'Claim No is blank', NULL),
				IF(jt.claim_intimation_date_time IS NULL OR STR_TO_DATE(jt.claim_intimation_date_time, '%d-%m-%Y %H:%i') IS NULL, 'Invalid Claim Intimation Date/Time', NULL),
				IF(jt.accident_city IS NULL OR jt.accident_city = '', 'Accident City is blank', NULL),
				IF(jt.nature_of_loss IS NULL OR jt.nature_of_loss = '' OR jt.nature_of_loss NOT REGEXP '^[A-Za-z ]+$', 'Invalid Nature of Loss', NULL),
				IF(jt.insurance_claim_no IS NULL OR jt.insurance_claim_no = '', 'Insurance Claim No is blank', NULL),
				IF(jt.claim_status IS NULL OR jt.claim_status = '' OR jt.claim_status NOT REGEXP '^[A-Za-z ]+$', 'Invalid Claim Status', NULL),
				IF(jt.workshop_name IS NULL OR jt.workshop_name = '', 'Workshop Name is blank', NULL),
				IF(jt.workshop_state IS NULL OR jt.workshop_state = '', 'Workshop State is blank', NULL),
				IF(jt.workshop_city IS NULL OR jt.workshop_city = '', 'Workshop City is blank', NULL),
				IF(jt.chassis_number IS NULL OR LENGTH(jt.chassis_number) < 7, 'Chassis Number is invalid', NULL),
				IF(jt.engine_no IS NULL OR LENGTH(jt.engine_no) < 7, 'Engine No is invalid', NULL),
				IF(jt.risk_start_date IS NOT NULL AND STR_TO_DATE(jt.risk_start_date, '%Y-%m-%d') IS NULL, 'Invalid Risk Start Date', NULL)
			)
		FROM JSON_TABLE(Json_data, '$.uploadRows[*]'
			COLUMNS (
				policy_no VARCHAR(255) PATH '$.policy_no',
				claim_no VARCHAR(255) PATH '$.claim_no',
				claim_intimation_date_time VARCHAR(255) PATH '$.claim_intimation_date_time',
				accident_city VARCHAR(255) PATH '$.accident_city',
				nature_of_loss VARCHAR(255) PATH '$.nature_of_loss',
				insurance_claim_no VARCHAR(255) PATH '$.insurance_claim_no',
				claim_status VARCHAR(50) PATH '$.claim_status',
				total_estimate_amount DECIMAL(15,2) PATH '$.total_estimate_amount',
				amount_paid DECIMAL(15,2) PATH '$.amount_paid',
				workshop_name VARCHAR(255) PATH '$.workshop_name',
				workshop_state VARCHAR(255) PATH '$.workshop_state',
				workshop_city VARCHAR(255) PATH '$.workshop_city',
				last_modified_date DATETIME PATH '$.last_modified_date',
				chassis_number VARCHAR(255) PATH '$.chassis_number',
				engine_no VARCHAR(255) PATH '$.engine_no',
				veh_reg_no VARCHAR(255) PATH '$.veh_reg_no',
				risk_start_date DATE PATH '$.risk_start_date'
			)
		) AS jt
		WHERE
			-- Apply negative validations to capture only invalid records
			NOT (
				jt.policy_no REGEXP '^[0-9a-zA-Z,/-]+$'
				AND jt.claim_no IS NOT NULL AND jt.claim_no != ''
				AND jt.claim_intimation_date_time IS NOT NULL AND STR_TO_DATE(jt.claim_intimation_date_time, '%d-%m-%Y %H:%i') IS NOT NULL
				AND jt.accident_city IS NOT NULL AND jt.accident_city != ''
				AND jt.nature_of_loss IS NOT NULL AND jt.nature_of_loss != '' AND jt.nature_of_loss REGEXP '^[A-Za-z ]+$'
				AND jt.insurance_claim_no IS NOT NULL AND jt.insurance_claim_no != ''
				AND jt.claim_status IS NOT NULL AND jt.claim_status != '' AND jt.claim_status REGEXP '^[A-Za-z ]+$'
				AND jt.workshop_name IS NOT NULL AND jt.workshop_name != ''
				AND jt.workshop_state IS NOT NULL AND jt.workshop_state != ''
				AND jt.workshop_city IS NOT NULL AND jt.workshop_city != ''
				AND jt.chassis_number IS NOT NULL AND LENGTH(jt.chassis_number) >= 7
				AND jt.engine_no IS NOT NULL AND LENGTH(jt.engine_no) >= 7
				AND (jt.risk_start_date IS NULL OR STR_TO_DATE(jt.risk_start_date, '%Y-%m-%d') IS NOT NULL)
			);

		SET failure_count = ROW_COUNT();

    -- Capture new data for the records matching incoming data
    SELECT JSON_ARRAYAGG(
        JSON_OBJECT(
            'id', IFNULL(id, ''),
            'policy_no', IFNULL(policy_no, ''),
            'claim_no', IFNULL(claim_no, ''),
            'claim_intimation_date_time', IFNULL(claim_intimation_date_time, ''),
            'accident_city', IFNULL(accident_city, ''),
            'nature_of_loss', IFNULL(nature_of_loss, ''),
            'insurance_claim_no', IFNULL(insurance_claim_no, ''),
            'claim_status', IFNULL(claim_status, ''),
            'total_estimate_amount', IFNULL(total_estimate_amount, ''),
            'amount_paid', IFNULL(amount_paid, ''),
            'workshop_name', IFNULL(workshop_name, ''),
            'workshop_state', IFNULL(workshop_state, ''),
            'workshop_city', IFNULL(workshop_city, ''),
            'last_modified_date', IFNULL(last_modified_date, ''),
            'chassis_number', IFNULL(chassis_number, ''),
            'engine_no', IFNULL(engine_no, ''),
            'veh_reg_no', IFNULL(veh_reg_no, ''),
            'risk_start_date', IFNULL(risk_start_date, '')
        )
    ) INTO new_upload_data
    FROM mmi_ebm_claim_data
    WHERE CONCAT(policy_no, chassis_number) IN (
        SELECT CONCAT(jt.policy_no, jt.chassis_number)
        FROM JSON_TABLE(Json_data, '$.uploadRows[*]' COLUMNS (
            policy_no VARCHAR(255) PATH '$.policy_no',
            chassis_number VARCHAR(255) PATH '$.chassis_number'
        )) AS jt
    );

    -- Insert into logs
    INSERT INTO mmi_maintain_overwrite_logs (
        upload_type, name, old_upload_data, new_upload_data, created_by, created_date
    )
    VALUES (
        custom_type,
        'mmi_ebm_claim_data',
        old_upload_data,
        new_upload_data,
        JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.userId')),
        NOW()
    );

    -- Commit transaction
     COMMIT;
    -- SET SP_STATUS = '200';
    -- SET MESSAGE = 'Bulk Data Saved into CLAIM successfully';
    IF failure_count > 0 THEN
		Select v_unique_id;
		SET SP_STATUS = '400';
		SET MESSAGE = CONCAT(success_count, ' records processed successfully, ', failure_count, ' records failed.');
    ELSE 
		SET v_unique_id = '';
		Select v_unique_id;
		SET SP_STATUS = '200';
		SET MESSAGE = CONCAT(success_count, ' records processed successfully, ', failure_count, ' records failed.');
    END IF;    
	ELSE
		SET SP_STATUS = '400';
		SET MESSAGE = CONCAT(custom_type,' Does not Exist.');
	END IF;
	END IF;
    
ELSEIF type = 'fetchDataUpload' THEN

	/*select distinct mdd.dealer_name as dealerName,mdd.parent_code as parentCode from mmi_mast_dealer md
	left join mmi_dealer_details mdd on mdd.parent_code = md.parent_code
	where mdd.dealer_id is not null and mdd.parent_code is not null
	AND md.is_active =1;*/
    
    select distinct mdd.dealer_name as dealerName,mdd.parent_code as parentCode 
	-- from mmi_mast_dealer 
    from mmi_dealer_location_mapping md
	left join mmi_dealer_details mdd on mdd.dealer_id = md.mapping_dealer_code
	where mdd.dealer_id is not null and mdd.parent_code is not null
	AND md.is_active =1;
		
    SET SP_STATUS = '200';
    SET MESSAGE = 'Fetched Dealer List successfully';
    
 ELSEIF type = 'fetchLocation' THEN

	SET v_parentId = JSON_UNQUOTE(JSON_EXTRACT(Json_data, '$.parentId'));
    
    IF v_parentId IS NULL OR v_parentId = '' 
		THEN
		SET SP_STATUS = '400';
		SET MESSAGE = CONCAT( CASE WHEN parentId IS NULL OR parentId = '' THEN 'parentId is missing' END);    
	ELSE

	select distinct mdl.loc_name as dealerLocName,mdd.dealer_id as dealerId,mdl.comm_address as dealerAddress from mmi_dealer_location_mapping dlm 
	left join mmi_dealer_details mdd on dlm.dealer_code = mdd.dealer_id and dlm.parent_code = mdd.parent_code
	left join mmi_mast_dealer_location mdl on mdl.loc_code = dlm.location_code
	where mdd.dealer_id is not null and mdd.parent_code = v_parentId;
		
    SET SP_STATUS = '200';
    SET MESSAGE = 'Fetched Location List successfully';
    
    END IF;
       

	ELSE
		SET SP_STATUS = '400';
		SET MESSAGE = CONCAT('Invalid type: ', type);
	END IF;
END ;;
DELIMITER ;
