CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_validate_crm_user_and_generateToken`(
    IN p_json_data JSON,
    OUT p_status_code VARCHAR(50),
    OUT p_status_message VARCHAR(255)
)
BEGIN
proc_end: BEGIN
    DECLARE v_user_id VARCHAR(100);
    DECLARE v_password VARCHAR(100);
    DECLARE v_active BOOLEAN;
    DECLARE v_token_type VARCHAR(100);
    DECLARE v_expiry_seconds INT;
    DECLARE v_expiry_time DATETIME;
    DECLARE v_token_value VARCHAR(255);
    DECLARE v_user_count INT DEFAULT 0;

    SET v_active = TRUE;
    SET v_token_type = 'CRM_AUTH';

    SET v_user_id = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.userId'));
    SET v_password = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.password'));

    SELECT value
    INTO v_expiry_seconds
    FROM mmi_property_config
    WHERE property = 'CRM_EBM_TOKEN_EXPIRY_TIME'
    LIMIT 1;

    SELECT COUNT(1)
    INTO v_user_count
    FROM mmi_crm_ebm_users
    WHERE user_id = v_user_id
      AND hash_password = v_password
      AND is_active = v_active;

    IF v_user_count = 0 THEN
        SET p_status_code = '401';
        SET p_status_message = 'Invalid user credentials';
        LEAVE proc_end;
    END IF;

    SET v_token_value = UUID();
    SET v_expiry_time = DATE_ADD(NOW(), INTERVAL v_expiry_seconds SECOND);

    INSERT INTO mmi_crm_ebm_tokens (
        token_type,
        token_value,
        user_id,
        expiry_time,
        created_by,
        created_date
    ) VALUES (
        v_token_type,
        v_token_value,
        v_user_id,
        v_expiry_time,
        v_user_id,
        NOW()
    );
	
    
    SET p_status_code = '200';
    SET p_status_message = CONCAT('Token generated successfully: ');
    Select v_token_value,v_expiry_time;

	END;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `mmi_proc_validate_ebm_transaction_token` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `mmi_proc_validate_ebm_transaction_token`(
    IN p_json_data JSON,
    OUT p_status_code     VARCHAR(20),
    OUT p_status_message  VARCHAR(255)
)
BEGIN
proc_end: BEGIN 
    DECLARE v_req_policy_no   VARCHAR(100);
    DECLARE v_token_policy_no VARCHAR(100);
    DECLARE v_crm_auth_token       VARCHAR(100);
    DECLARE v_crm_txn_token       VARCHAR(100);
    DECLARE v_is_valid        BOOLEAN;
    DECLARE v_remaining_secs BIGINT;
    DECLARE v_expiry_time     DATETIME;

    SET v_is_valid = FALSE;
    SET v_remaining_secs = 0;

    SET v_req_policy_no = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.policyNo'));
    SET v_crm_auth_token     = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.crmAuthToken'));
    SET v_crm_txn_token = JSON_UNQUOTE(JSON_EXTRACT(p_json_data, '$.crmTransactionToken'));

    IF NOT EXISTS (
        SELECT 1
        FROM mmi_crm_ebm_tokens
        WHERE token_value = v_crm_auth_token
          AND token_type = 'CRM_AUTH'
    ) THEN
        SET p_status_code = '401';
        SET p_status_message = 'Invalid CRM Auth Token';
        LEAVE proc_end;
    END IF;
    
    IF NOT EXISTS (
        SELECT 1
        FROM mmi_crm_ebm_transaction_details
        WHERE crm_transaction_token_no = v_crm_txn_token
          AND policy_no = v_req_policy_no
    ) THEN
        SET p_status_code = '401';
        SET p_status_message = 'Invalid CRM Transaction Token';
        LEAVE proc_end;
    END IF;

    SELECT policy_no, expiry_time
    INTO v_token_policy_no, v_expiry_time
    FROM mmi_crm_ebm_tokens
    WHERE token_value = v_crm_auth_token
      AND token_type = 'CRM_AUTH'
    LIMIT 1;

    IF v_req_policy_no IS NOT NULL
       AND v_token_policy_no IS NOT NULL
       AND v_req_policy_no <> v_token_policy_no THEN
        SET p_status_code = '401';
        SET p_status_message = 'Policy mismatch for transaction token';
        LEAVE proc_end;
    END IF;

    IF v_expiry_time < NOW() THEN
        SET p_status_code = '401';
        SET p_status_message = 'CRM Auth Token expired';
        LEAVE proc_end;
    END IF;

    SET v_remaining_secs = TIMESTAMPDIFF(SECOND, NOW(), v_expiry_time);
    SET v_is_valid = TRUE;
    
    Select v_remaining_secs as remainingSecond,v_is_valid as crmTokenValidity;
    
    SET p_status_code = '200';
    SET p_status_message = 'Transaction token is valid';

    END;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
