/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `rfq_sp_get_client_list`(
    IN p_input_json LONGTEXT, -- CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
    OUT p_response LONGTEXT
)
proc_main: BEGIN
    -- Control Variables
    DECLARE v_userid BIGINT;
    DECLARE v_offset INT DEFAULT 0;
    DECLARE v_limit INT DEFAULT 20;
    DECLARE v_total_records INT DEFAULT 0;
    
    -- Filter Strings
    DECLARE v_filter_name VARCHAR(255) DEFAULT NULL;
    DECLARE v_filter_type VARCHAR(30) DEFAULT NULL;
    DECLARE v_final_array JSON;

    -- System Error Capture Variables
    DECLARE v_sql_state VARCHAR(5) DEFAULT '00000';
    DECLARE v_error_msg TEXT;

    -- =========================================================================
    -- THE "CATCH" BLOCK (Global Exception Handler)
    -- =========================================================================
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1 
            v_sql_state = RETURNED_SQLSTATE, 
            v_error_msg = MESSAGE_TEXT;

        SET p_response = JSON_OBJECT(
            'status', 500,
            'message', CONCAT('Database Fetch Error: ', v_error_msg),
            'payload', JSON_OBJECT('sql_state', v_sql_state)
        );
    END;

    -- =========================================================================
    -- THE "TRY" BLOCK (Core Business Logic)
    -- =========================================================================
    
    -- 1. Extract structural routing parameters from JSON input
    SET v_userid = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_input_json, '$.userid')) AS UNSIGNED);
    
    -- Extract pagination parameters if supplied safely
    IF JSON_CONTAINS_PATH(p_input_json, 'one', '$.offset') = 1 THEN
        SET v_offset = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_input_json, '$.offset')) AS UNSIGNED);
    END IF;
    IF JSON_CONTAINS_PATH(p_input_json, 'one', '$.limit') = 1 THEN
        SET v_limit = CAST(JSON_UNQUOTE(JSON_EXTRACT(p_input_json, '$.limit')) AS UNSIGNED);
    END IF;

    -- 2. Extract searching filter criteria blocks
    IF JSON_CONTAINS_PATH(p_input_json, 'one', '$.filters.client_name') = 1 THEN
        SET v_filter_name = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, '$.filters.client_name'));
        IF v_filter_name = '' THEN 
            SET v_filter_name = NULL; 
        ELSE 
            SET v_filter_name = CONCAT('%', v_filter_name, '%'); 
        END IF;
    END IF;

    IF JSON_CONTAINS_PATH(p_input_json, 'one', '$.filters.client_type_code') = 1 THEN
        SET v_filter_type = JSON_UNQUOTE(JSON_EXTRACT(p_input_json, '$.filters.client_type_code'));
        IF v_filter_type = '' THEN SET v_filter_type = NULL; END IF;
    END IF;

	-- 3. Optimization Step: Fetch Total Matching Count first (Bypassing LIMIT/OFFSET)
    SELECT COUNT(1) INTO v_total_records
    FROM rfq_clients c
    WHERE (v_filter_name IS NULL OR c.client_name LIKE v_filter_name)
      AND (v_filter_type IS NULL OR c.client_type_code = v_filter_type);

	-- 4. User Filter

    -- 5. Execute Core Paginated Aggregation Query
    SELECT JSON_ARRAYAGG(
                JSON_OBJECT(
                    -- 'client_id', main.client_id,
                    'client_UUID', main.client_UUID,
                    'client_name', main.client_name,
                    'client_type_code', main.client_type_code,
                    'client_vertical_code', main.client_vertical_code,
                    'client_status_code',main.client_status_code,
                    'client_owner',main.client_owner,
                    'client_status',main.client_status,
                    'client_vertical',main.client_vertical,
                    'client_city',main.client_city,
                    'client_type',main.client_type
                    -- ,'client_data', main.client_payload
                )
           ) INTO v_final_array
    FROM (
        SELECT 
            -- c.client_id,
            c.client_UUID,
            c.client_name,
            c.client_type_code,
            c.client_vertical_code,
            c.client_status_code,
            'Pankaj Sahu' as client_owner,
            'Mumbai' as client_city,
            kstatus.key_value as  client_status,
            kvertical.key_value as  client_vertical,
            ktype.key_value as  client_type
           --  ,(SELECT cd.client_payload 
--              FROM client_data cd 
--              WHERE cd.client_id = c.client_id AND cd.active = TRUE 
--              ORDER BY cd.client_data_id DESC LIMIT 1) AS client_payload
        FROM rfq_clients c
        inner join rfq_kds kstatus on c.client_status_code = kstatus.key_code and kstatus.key_name = 'status' and kstatus.key_source = 'approval'
        inner join rfq_kds kvertical on c.client_vertical_code = kvertical.key_code and kvertical.key_name = 'vertical' and kvertical.key_source = 'vertical'
        inner join rfq_kds ktype on c.client_type_code = ktype.key_code and ktype.key_name = 'type' and ktype.key_source = 'type'
        WHERE (v_filter_name IS NULL OR c.client_name LIKE v_filter_name)
         AND (v_filter_type IS NULL OR c.client_type_code = v_filter_type)
        ORDER BY c.client_id DESC
        LIMIT v_limit OFFSET v_offset
    ) main;

    -- 4. Construct response wrapper structure 
    SET p_response = JSON_OBJECT(
        'status', 200,
        'message', 'Client Record Found',
        'payload', JSON_OBJECT(
            'total_records', v_total_records,
            'clients', COALESCE(v_final_array, JSON_ARRAY())
        )
    );

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `rfq_sp_get_user_hierarchy` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `rfq_sp_get_user_hierarchy`(
    IN p_user_id BIGINT,
    OUT p_hierarchy JSON
)
BEGIN

    WITH RECURSIVE

    up_hierarchy AS (
        SELECT user_id, supervisor_id
        FROM mmi_user_reporting
        WHERE user_id = p_user_id

        UNION ALL

        SELECT m.user_id, m.supervisor_id
        FROM mmi_user_reporting m
        JOIN up_hierarchy u
            ON m.user_id = u.supervisor_id
    ),

    down_hierarchy AS (
        SELECT user_id, supervisor_id
        FROM mmi_user_reporting
        WHERE user_id = p_user_id

        UNION ALL

        SELECT m.user_id, m.supervisor_id
        FROM mmi_user_reporting m
        JOIN down_hierarchy d
            ON m.supervisor_id = d.user_id
    )

    SELECT JSON_ARRAYAGG(user_id)
    INTO p_hierarchy
    FROM (
        SELECT DISTINCT user_id
        FROM (
            SELECT user_id FROM up_hierarchy
            UNION
            SELECT user_id FROM down_hierarchy
        ) x
    ) y;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
