CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_client_list`(
    IN p_input_json LONGTEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
    OUT p_response LONGTEXT
)
proc_main: BEGIN
    -- Control Pagination Variables
    DECLARE v_userid BIGINT UNSIGNED;
    DECLARE v_offset INT DEFAULT 0;
    DECLARE v_limit INT DEFAULT 20;
    DECLARE v_total_records INT DEFAULT 0;
    
    -- Filter Mapping Strings
    DECLARE v_filter_name VARCHAR(255) DEFAULT NULL;
    DECLARE v_filter_type VARCHAR(30) DEFAULT NULL;
    DECLARE v_filter_vertical VARCHAR(30) DEFAULT NULL;
    DECLARE v_filter_status VARCHAR(30) DEFAULT NULL;
    DECLARE v_final_array JSON;

    -- System Diagnostic Capture Variables
    DECLARE v_sql_state VARCHAR(5) DEFAULT '00000';
    DECLARE v_error_msg TEXT;

    -- =========================================================================
    -- THE "CATCH" BLOCK (Global Exception Trap)
    -- =========================================================================
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1 
            v_sql_state = RETURNED_SQLSTATE, 
            v_error_msg = MESSAGE_TEXT;

        SET p_response = JSON_OBJECT(
            'status', 500,
            'message', CONCAT('Database Fetch Error: ', v_error_msg),
            'payload', JSON_OBJECT('sql_state', v_sql_state)
        );
    END;

    -- =========================================================================
    -- THE "TRY" BLOCK (Core Extractor Engine)
    -- =========================================================================
    
    -- 1. Streamline Parameter Extractions (Bypassing heavy PATH contains loops)
    SET v_userid = CAST(p_input_json->>'$.userid' AS UNSIGNED);
    SET v_offset = CAST(COALESCE(p_input_json->>'$.offset', 0) AS UNSIGNED);
    SET v_limit  = CAST(COALESCE(p_input_json->>'$.limit', 20) AS UNSIGNED);

    -- 2. Extract and Formulate Search Critera Targets
    SET v_filter_name     = NULLIF(TRIM(p_input_json->>'$.filters.client_name'), '');
    SET v_filter_type     = NULLIF(TRIM(p_input_json->>'$.filters.client_type_code'), '');
    SET v_filter_vertical = NULLIF(TRIM(p_input_json->>'$.filters.client_vertical_code'), '');
    SET v_filter_status   = NULLIF(TRIM(p_input_json->>'$.filters.client_status_code'), '');

    -- Format wildcard tracking vector only if search string exists
    IF v_filter_name IS NOT NULL THEN
        SET v_filter_name = CONCAT('%', v_filter_name, '%');
    END IF;

    -- 3. Fetch Total Matching Count across synchronized View structure
    SELECT COUNT(1) INTO v_total_records
    FROM v_rfq_clients c
    WHERE (v_filter_name     IS NULL OR c.client_name LIKE v_filter_name)
      AND (v_filter_type     IS NULL OR c.client_type_code = v_filter_type)
      AND (v_filter_vertical IS NULL OR c.client_vertical_code = v_filter_vertical)
      AND (v_filter_status   IS NULL OR c.client_status_code = v_filter_status);

    -- 4. Execute Highly Optimized Paginated Extraction Array
    SELECT 
        JSON_ARRAYAGG(
            JSON_OBJECT(
                'client_code',          main.client_code,
                'client_UUID',          main.client_UUID,
                'client_name',          main.client_name,
                'client_type_code',     main.client_type_code,
                'client_vertical_code', main.client_vertical_code,
                'client_status_code',   main.client_status_code,
                'client_type',          main.client_type,
                'client_vertical',      main.client_vertical,
                'client_status',        main.client_status,
                'pincode',              main.pincode,
                'city_name',            main.city_name,
                'state_name',           main.state_name,
                'created_on',           DATE_FORMAT(main.created_on, '%Y-%m-%d %H:%i:%s'),
                'approve_by',           main.approve_by,
                'approval_on',          DATE_FORMAT(main.approval_on, '%Y-%m-%d %H:%i:%s'),
                'client_owner',         main.client_owner,
                'active',               main.active
            )
        ) INTO v_final_array
    FROM (
        SELECT 
            c.client_code, c.client_UUID, c.client_name, c.client_type_code,
            c.client_vertical_code, c.client_status_code, c.client_type,
            c.client_vertical, c.client_status, c.pincode, c.city_name,
            c.state_name, c.created_on, c.approve_by, c.approval_on,
            c.client_owner, c.active
        FROM v_rfq_clients c
        WHERE (v_filter_name     IS NULL OR c.client_name LIKE v_filter_name)
          AND (v_filter_type     IS NULL OR c.client_type_code = v_filter_type)
          AND (v_filter_vertical IS NULL OR c.client_vertical_code = v_filter_vertical)
          AND (v_filter_status   IS NULL OR c.client_status_code = v_filter_status)
        ORDER BY c.client_id DESC
        LIMIT v_limit OFFSET v_offset
    ) main;

    -- 5. Return Complete JSON Output Envelope
    SET p_response = JSON_OBJECT(
        'status', 200,
        'message', 'Client Record Found',
        'payload', JSON_OBJECT(
            'total_records', v_total_records,
            'clients', COALESCE(v_final_array, JSON_ARRAY())
        )
    );

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `ZPopulateDummyClients` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = '' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `ZPopulateDummyClients`()
BEGIN
    DECLARE i INT DEFAULT 1;
    DECLARE current_user_id INT;
    DECLARE random_uuid VARCHAR(36);
    DECLARE random_pan VARCHAR(10);
    DECLARE random_gstin VARCHAR(15);
    DECLARE client_type VARCHAR(4);
    DECLARE vertical VARCHAR(4);
	DECLARE status VARCHAR(4);
	DECLARE created_id VARCHAR(4);
    DECLARE biz_type VARCHAR(30);

    WHILE i <= 500 DO
        SET current_user_id = IF(i % 2 = 0, 2, 1);
        SET random_uuid = REPLACE(REPLACE(UUID(),'-', 'Q') , 'f','1'); -- REPLACE(text, '-', 'Q'):
        SET random_pan = CONCAT('ABCDE', FLOOR(1000 + (RAND() * 8999)), 'F');
        SET random_gstin = CONCAT('27', random_pan, '1Z', FLOOR(RAND() * 9));
        
        SET client_type = ELT((i % 2) + 1, 'cttc', 'cttd');
        SET vertical = ELT((i % 3) + 1, 'cvva', 'coos', 'cooi');
		SET status = ELT((i % 3) + 1, 'casa', 'casp', 'casr');
        SET biz_type = ELT((i % 4) + 1, 'Manufacturing', 'Retail Logistics', 'Pharmaceuticals', 'IT Services');
		SET created_id = ELT((i % 4) + 1, '1', '2', '3', '4');
        INSERT INTO `rfq_clients` 
        (`client_UUID`, `client_name`, `client_type_code`, `client_vertical_code`, `created_id`, `client_status_code`)
        VALUES 
        (
            rfq_f_generate_sequential_uuid(),
			(SELECT CONCAT(title) FROM sakila.film where film_id = i LIMIT 1), 
            client_type, 
            vertical, 
            created_id,
			status
        );

        INSERT INTO `rfq_clients_data` 
        (`client_id`, `client_payload`, `version`, `updated_id`)
        VALUES
        (
            LAST_INSERT_ID(),
            CONCAT('{
                "client": {
                    "pancard": "', random_pan, '",
                    "cin_number": "L', FLOOR(10000 + (RAND() * 89999)), 'MH2026PLC', FLOOR(100000 + (RAND() * 899999)), '",
                    "tin_number": "9876543', FLOOR(1000 + (RAND() * 8999)), '",
                    "gstin": "', random_gstin, '",
                    "biz_type": "', biz_type, '"
                },
                "address": {
                    "address_line1": "Building ', FLOOR(1 + (RAND() * 500)), ', Industrial Zone",
                    "address_line2": "Phase ', ELT((i % 3) + 1, 'I', 'II', 'III'), '",
                    "cityid": ', FLOOR(400000 + (RAND() * 99999)), ',
                    "stateid": ', FLOOR(1 + (RAND() * 36)), ',
                    "pincode": "4000', FLOOR(10 + (RAND() * 89)), '"
                },
                "portfolio": {
                    "biz_type": "', ELT((i % 3) + 1, 'CGS', 'SME', 'EM'), '",
                    "lob": "', ELT((i % 3) + 1, 'BGR', 'Burglary', 'CPM'), '",
                    "product": "', ELT((i % 3) + 1, 'Property', 'Liberty', 'Marine'), '",
                    "sub_product": "Standard Subcategory Plan",
                    "sum_insured": ', ROUND(5000000 + (RAND() * 45000000), 0), ',
                    "expected_premium": ', ROUND(20000 + (RAND() * 180000), 0), ',
                    "brokerage": ', ROUND(5.0 + (RAND() * 10.0), 2), ',
                    "renewal_date": "', DATE_ADD(CURRENT_DATE, INTERVAL FLOOR(RAND() * 365) DAY), '"
                }
            }'),
            1,
            current_user_id
        );

        SET i = i + 1;
    END WHILE;
END ;;
DELIMITER ;
